def _build_guard_specs(
    args: argparse.Namespace, argv: Sequence[str], parser: argparse.ArgumentParser
) -> list[dict]:
    static_specs = launcher_guards.load_static_guard_specs("train_bc")
    specs = launcher_guards.merge_dynamic_args(
        static_specs, {"cli_flag_lint": {"argv": list(argv), "parser": parser}}
    )
    # VAL-ONLY-never-trains (b): best-effort discovery of the seed range(s) this
    # corpus was generated from, from any reachable generation manifest.json --
    # refuses a training launch whose corpus overlaps the reserved VAL-ONLY band.
    for seed_range in launcher_guards.discover_generation_seed_ranges(args.data):
        specs.append(
            {
                "name": "val_only_never_trains",
                "args": {"seed_range": seed_range, "purpose": "train"},
            }
        )
    # masked-regime (c): only meaningful when continuing from a checkpoint --
    # a fresh --arch entity_graph run has no prior regime to contradict.
    if args.init_checkpoint:
        specs.append(
            {
                "name": "masked_regime",
                "args": {
                    "checkpoint_path": args.init_checkpoint,
                    "expected_masked": bool(args.mask_hidden_info),
                },
            }
        )
    return specs


def _resolve_value_objective_weights(args) -> tuple[float, float]:
    """Return ``(scalar_mse_weight, categorical_ce_weight)``.

    ``--value-loss-weight`` is the primary-value budget shared by the matched
    scalar and HL-Gauss arms.  Historically the HL-Gauss path applied that
    budget to scalar MSE *and* again to categorical CE, so the purported
    one-variable tournament doubled its value gradient and validation only
    reported the scalar half.  Keep the default MSE path byte-for-byte, but
    make the opt-in HL-Gauss mode categorical-primary and require any hybrid
    scalar auxiliary to be explicit.
    """

    mode = str(getattr(args, "value_head_type", "mse"))
    # ``scalar`` was used by pre-parser unit fixtures and early config JSONs;
    # accept it as the exact historical alias for the CLI spelling ``mse``.
    if mode == "scalar":
        mode = "mse"
    primary = float(getattr(args, "value_loss_weight", 0.10))
    categorical_override = float(
        getattr(args, "value_categorical_loss_weight", 0.0)
    )
    scalar_aux = float(getattr(args, "hlgauss_scalar_aux_loss_weight", 0.0))
    weights = {
        "value_loss_weight": primary,
        "value_categorical_loss_weight": categorical_override,
        "hlgauss_scalar_aux_loss_weight": scalar_aux,
    }
    if any(value < 0.0 for value in weights.values()):
        raise SystemExit(
            "value objective weights must be non-negative: "
            + ", ".join(f"{key}={value}" for key, value in weights.items())
        )
    value_target_lambda = float(getattr(args, "value_target_lambda", 1.0))
    if not 0.0 <= value_target_lambda <= 1.0:
        raise SystemExit(
            "--value-target-lambda must be in [0, 1]; values outside the convex "
            "range create invalid categorical probability mass and extrapolated "
            f"scalar targets (got {value_target_lambda})"
        )
    sigma_ratio = float(getattr(args, "value_hlgauss_sigma_ratio", 0.75))
    if sigma_ratio <= 0.0:
        raise SystemExit(
            "--value-hlgauss-sigma-ratio must be > 0 so the HL-Gauss target is "
            f"well-defined (got {sigma_ratio})"
        )
    if mode == "mse":
        if categorical_override != 0.0:
            raise SystemExit(
                "--value-categorical-loss-weight is nonzero while "
                "--value-head-type=mse; select --value-head-type=hlgauss instead"
            )
        if scalar_aux != 0.0:
            raise SystemExit(
                "--hlgauss-scalar-aux-loss-weight is only valid with "
                "--value-head-type=hlgauss"
            )
        return primary, 0.0
    if mode == "hlgauss":
        categorical = categorical_override if categorical_override != 0.0 else primary
        if categorical <= 0.0:
            raise SystemExit(
                "--value-head-type=hlgauss requires a positive categorical primary "
                "weight via --value-loss-weight or --value-categorical-loss-weight"
            )
        return scalar_aux, categorical
    raise SystemExit(f"unknown --value-head-type={mode!r}")


def _scalar_value_loss_contract(args) -> dict[str, object]:
    objective = str(getattr(args, "scalar_value_objective", "mse"))
    mode = str(getattr(args, "scalar_value_loss_readout", "raw"))
    scale = float(getattr(args, "scalar_value_loss_scale", 1.0))
    if objective not in {"mse", "binary_win_bce"}:
        raise SystemExit(f"unknown scalar value objective: {objective!r}")
    if mode not in {"raw", "deployed_tanh"}:
        raise SystemExit(f"unknown scalar value loss readout: {mode!r}")
    if not math.isfinite(scale) or scale <= 0.0:
        raise SystemExit("--scalar-value-loss-scale must be finite and > 0")
    if objective == "binary_win_bce":
        if mode != "deployed_tanh":
            raise SystemExit(
                "--scalar-value-objective=binary_win_bce requires "
                "--scalar-value-loss-readout=deployed_tanh so the Bernoulli "
                "probability and deployed scalar value are the same readout"
            )
        return {
            "schema_version": "scalar-value-objective-v2",
            "objective": objective,
            "readout": mode,
            "scale": scale,
            "target_formula": "(z + 1) / 2",
            "logit_formula": "2 * scale * raw",
            "deployed_value_formula": "tanh(raw * scale)",
            "matches_scalar_mcts_when_value_squash_tanh": True,
        }
    # Preserve the exact historical contract at the default. Existing sealed
    # MSE recipes and checkpoint receipts must not drift merely because the
    # experimental objective became available.
    return {
        "schema_version": "scalar-value-loss-readout-v1",
        "readout": mode,
        "scale": scale,
        "formula": "raw" if mode == "raw" else "tanh(raw * scale)",
        "matches_scalar_mcts_when_value_squash_tanh": mode == "deployed_tanh",
    }


def _scalar_value_loss_prediction(raw_value, *, readout: str, scale: float):
    """Return the scalar function whose error the optimizer should minimize."""

    mode = str(readout)
    if mode == "raw":
        return raw_value
    if mode == "deployed_tanh":
        import torch

        if not math.isfinite(float(scale)) or float(scale) <= 0.0:
            raise ValueError("deployed scalar value scale must be finite and > 0")
        # Compute the squash in float32 even under bf16 autocast. Search applies
        # the same function after converting the network output to a host float.
        return torch.tanh(raw_value.float() * float(scale))
    raise ValueError(f"unknown scalar value loss readout: {mode!r}")


def _scalar_value_objective_errors(
    raw_value,
    outcome_targets,
    *,
    objective: str,
    readout: str,
    scale: float,
):
    """Return ``(objective_error, deployed_mse_error, value_prediction)``.

    Binary win BCE uses the exact logistic parameterization corresponding to
    the deployed tanh value:

    ``2 * sigmoid(2*x) - 1 == tanh(x)``.

    The MSE diagnostic is intentionally computed separately from the selected
    training objective so BCE runs remain comparable to historical scalar
    validation without mislabelling BCE as MSE.
    """

    import torch
    from torch import nn

    mode = str(objective)
    value_prediction = _scalar_value_loss_prediction(
        raw_value,
        readout=readout,
        scale=scale,
    )
    mse_error = nn.functional.mse_loss(
        value_prediction,
        outcome_targets,
        reduction="none",
    )
    if mode == "mse":
        return mse_error, mse_error, value_prediction
    if mode != "binary_win_bce":
        raise ValueError(f"unknown scalar value objective: {mode!r}")
    if str(readout) != "deployed_tanh":
        raise ValueError(
            "binary_win_bce requires the deployed_tanh scalar value readout"
        )
    target = outcome_targets.float()
    if not bool(torch.isfinite(target).all()):
        raise ValueError("binary_win_bce received non-finite value targets")
    if bool(((target < -1.0) | (target > 1.0)).any()):
        raise ValueError("binary_win_bce value targets must lie in [-1, 1]")
    binary_target = (target + 1.0) * 0.5
    binary_logit = raw_value.float() * (2.0 * float(scale))
    objective_error = nn.functional.binary_cross_entropy_with_logits(
        binary_logit,
        binary_target,
        reduction="none",
    )
    return objective_error, mse_error, value_prediction


def _scalar_value_primary_loss_kind(objective: str) -> str:
    mode = str(objective)
    if mode == "mse":
        return "scalar_mse"
    if mode == "binary_win_bce":
        return "binary_win_bce"
    raise ValueError(f"unknown scalar value objective: {mode!r}")


def _value_trunk_gradient_routing(
    args,
    *,
    scalar_weight: float,
    categorical_weight: float = 0.0,
    final_vp_weight: float | None = None,
    model=None,
) -> dict[str, object]:
    """Validate and describe value-family gradient routing at the trunk boundary.

    This is deliberately narrower than ``--trunk-lr-mult``.  The latter scales
    the optimizer update produced by *all* objectives in trunk parameters.  This
    intervention leaves the policy gradient, forward outputs, optimizer groups,
    and value-readout parameter gradients untouched and changes only the
    derivatives from the scalar value readout into its shared trunk inputs.
    """

    scale = float(getattr(args, "value_trunk_grad_scale", 1.0))
    if not math.isfinite(scale) or not 0.0 <= scale <= 1.0:
        raise SystemExit("--value-trunk-grad-scale must be finite and in [0, 1]")
    active = scale != 1.0
    if active and str(getattr(args, "arch", "")) != "entity_graph":
        raise SystemExit(
            "--value-trunk-grad-scale != 1 requires --arch entity_graph"
        )
    resolved_final_vp_weight = float(
        getattr(args, "final_vp_loss_weight", 0.0)
        if final_vp_weight is None
        else final_vp_weight
    )
    scalar_value_objective = str(
        getattr(args, "scalar_value_objective", "mse")
    )
    scalar_primary_loss_kind = _scalar_value_primary_loss_kind(
        scalar_value_objective
    )
    active_value_objectives = {
        scalar_primary_loss_kind: float(scalar_weight),
        "categorical_ce": float(categorical_weight),
        "final_vp": resolved_final_vp_weight,
    }
    if active and not any(weight > 0.0 for weight in active_value_objectives.values()):
        raise SystemExit(
            "--value-trunk-grad-scale != 1 requires at least one active value-family "
            "objective (scalar MSE, categorical CE, or final-VP)"
        )
    value_attention_pool = bool(
        model is not None and getattr(model, "value_attention_pool", False)
    )
    value_tower_split_layers = int(
        getattr(model, "value_tower_split_layers", 0) or 0
        if model is not None
        else 0
    )
    legal_action_value_residual = bool(
        model is not None
        and getattr(model, "legal_action_value_residual_enabled", False)
    )
    legal_action_value_set_statistics = bool(
        legal_action_value_residual
        and getattr(model, "legal_action_value_set_statistics_enabled", False)
    )
    meaningful_public_history = bool(
        model is not None
        and getattr(model, "meaningful_public_history_enabled", False)
    )
    shared_input_paths = (
        ["value_tower_shared_prefix_tokens"]
        if value_tower_split_layers > 0
        else ["cls_state"]
    )
    if value_tower_split_layers > 0 and meaningful_public_history:
        # The split value branch receives the bounded history residual outside
        # value_tower_shared_prefix_tokens. score_actions applies the same
        # gradient boundary to it explicitly, so provenance must name it.
        shared_input_paths.append("meaningful_public_history_residual")
    if legal_action_value_residual:
        # Preserve the durable v1 name for the mean-pooled encoded-action path.
        shared_input_paths.append("legal_action_encoded_affordance")
        if legal_action_value_set_statistics:
            shared_input_paths.append("legal_action_max_affordance")
    if value_attention_pool:
        shared_input_paths.extend(
            ["attention_pool_state", "attention_pool_tokens"]
        )
    return {
        "schema_version": "scalar-value-trunk-gradient-routing-v1",
        "scalar_value_trunk_grad_scale": scale,
        "active": active,
        "forward_value_identity": True,
        "value_head_parameter_gradient_scale": 1.0,
        "shared_state_upstream_gradient_scale": scale,
        "scope": "value_family_readouts_all_shared_inputs",
        "legacy_scope_alias": "scalar_value_head_state_input_only",
        "scalar_value_objective": scalar_value_objective,
        "scalar_value_primary_loss_kind": scalar_primary_loss_kind,
        "active_value_objectives": active_value_objectives,
        "shared_input_paths": shared_input_paths,
        "value_attention_pool_enabled": value_attention_pool,
        "value_tower_split_layers": value_tower_split_layers,
        "legal_action_value_residual_enabled": legal_action_value_residual,
        "legal_action_value_set_statistics_enabled": (
            legal_action_value_set_statistics
        ),
        "shared_action_representation_upstream_gradient_scale": (
            scale if legal_action_value_residual else None
        ),
        "private_value_tower_parameter_gradient_scale": 1.0,
        "all_scalar_value_shared_inputs_scaled": True,
        "all_value_family_shared_inputs_scaled": True,
        "final_vp_shared_state_scaled": True,
        "categorical_value_shared_state_scaled": True,
        "policy_gradient_unchanged": True,
        "optimizer_parameter_groups_unchanged": True,
        "ddp_semantics": (
            "rank_local_boundary_scale_before_standard_ddp_gradient_allreduce"
        ),
    }


def _value_training_metadata(
    args,
    *,
    scalar_weight: float,
    categorical_weight: float,
    categorical_bins: int,
    optimizer_steps: int,
    completed_epochs: int,
    scalar_training_weight_sum: float,
    categorical_training_weight_sum: float,
) -> dict[str, object]:
    """Build durable checkpoint provenance for value readouts trained here.

    Merely adding a categorical module to a checkpoint does not train it.  The
    explicit readout list lets search fail closed on config-only upgrades while
    remaining backwards compatible with legacy scalar checkpoints.
    """

    mode = str(getattr(args, "value_head_type", "mse"))
    if mode == "scalar":
        mode = "mse"
    primary_readout = "categorical" if mode == "hlgauss" else "scalar"
    trained_readouts: list[str] = []
    # A bounded max-step run can have real optimizer updates before completing
    # an epoch.  Requiring completed_epochs > 0 made an otherwise valid
    # intermediate model claim that its value readout was untrained.  Optimizer
    # steps plus positive objective mass are the actual training evidence.
    has_updates = int(optimizer_steps) > 0
    if (
        has_updates
        and float(scalar_weight) > 0.0
        and float(scalar_training_weight_sum) > 0.0
    ):
        trained_readouts.append("scalar")
    if (
        has_updates
        and float(categorical_weight) > 0.0
        and float(categorical_training_weight_sum) > 0.0
    ):
        trained_readouts.append("categorical")
    value_gradient_routing = getattr(args, "value_gradient_routing", None)
    if value_gradient_routing is None:
        value_gradient_routing = _value_trunk_gradient_routing(
            args,
            scalar_weight=scalar_weight,
            categorical_weight=categorical_weight,
            final_vp_weight=float(getattr(args, "final_vp_loss_weight", 0.0)),
        )
    metadata = {
        "schema_version": "value-training-v1",
        "primary_readout": primary_readout,
        "trained_value_readouts": trained_readouts,
        "scalar_value_objective": str(
            getattr(args, "scalar_value_objective", "mse")
        ),
        "resolved_scalar_mse_weight": float(scalar_weight),
        "resolved_categorical_ce_weight": float(categorical_weight),
        "hlgauss_scalar_aux_loss_weight": float(
            getattr(args, "hlgauss_scalar_aux_loss_weight", 0.0)
        ),
        "hlgauss_bins": int(categorical_bins),
        "hlgauss_sigma_ratio": float(
            getattr(args, "value_hlgauss_sigma_ratio", 0.75)
        ),
        "value_target_lambda": float(getattr(args, "value_target_lambda", 1.0)),
        "value_root_blend_regime": _resolve_value_root_blend_regime(args),
        "value_root_blend_audit": getattr(args, "value_root_blend_audit", None),
        "scalar_value_loss_contract": getattr(
            args, "scalar_value_loss_contract", _scalar_value_loss_contract(args)
        ),
        "value_gradient_routing": value_gradient_routing,
        "truncated_vp_margin_value_weight": float(
            getattr(args, "truncated_vp_margin_value_weight", 0.0)
        ),
        "optimizer_steps": int(optimizer_steps),
        "completed_epochs": int(completed_epochs),
        "scalar_training_weight_sum": float(scalar_training_weight_sum),
        "categorical_training_weight_sum": float(
            categorical_training_weight_sum
        ),
        "checkout_runtime_binding": getattr(
            args, "checkout_runtime_binding", None
        ),
        **(
            {
                "a1_contract_sha256": args.a1_contract_sha256,
                "a1_selected_game_seed_set_sha256": (
                    getattr(args, "a1_selected_game_seed_set_sha256", None)
                ),
                "a1_training_game_seed_set_sha256": (
                    getattr(args, "a1_training_game_seed_set_sha256", None)
                ),
                "a1_learner_training_recipe_sha256": (
                    getattr(args, "a1_learner_training_recipe_sha256", None)
                ),
                "a1_memmap_payload_inventory_sha256": (
                    getattr(args, "a1_memmap_payload_inventory_sha256", None)
                ),
                "a1_learner_code_sha256": getattr(
                    args, "a1_learner_code_sha256", None
                ),
                "a1_runtime_code_tree_sha256": getattr(
                    args, "a1_runtime_code_tree_sha256", None
                ),
            }
            if getattr(args, "a1_contract_sha256", None)
            else {}
        ),
    }
    learner_ablation = getattr(args, "a1_learner_ablation", None)
    if learner_ablation is not None:
        metadata["learner_ablation"] = dict(learner_ablation)
    return metadata


def _initialization_reference_value_training(policy) -> dict[str, object] | None:
    """Preserve readout provenance on a function-preserving step-zero save.

    The initialization checkpoint is written before this learner applies an
    optimizer update.  Rebuilding ``value-training-v1`` with zero local steps
    erases the source checkpoint's already-trained scalar/categorical
    attestation, even though the readout weights are copied exactly.  Search
    then correctly rejects those inherited weights as untrained.

    Carry the source attestation forward and add an explicit current-trajectory
    marker.  Legacy checkpoints have no structured value provenance; returning
    ``None`` retains their legacy scalar compatibility instead of manufacturing
    a new zero-dose record.
    """

    inherited = getattr(policy, "value_training", None)
    if not isinstance(inherited, dict):
        return None
    durable = copy.deepcopy(inherited)
    durable["initialization_reference"] = {
        "schema_version": "value-training-initialization-reference-v1",
        "inherited_from_source_checkpoint": True,
        "optimizer_steps_in_current_trajectory": 0,
        "function_preserving_weights": True,
    }
    return durable


def _policy_training_signal_attestation(
    metrics: Sequence[dict[str, object]],
    *,
    policy_loss_weight: float,
    optimizer_steps: int,
    train_value_only: bool,
) -> dict[str, object]:
    """Attest that a configured policy objective actually reached the learner.

    A checkpoint step proves only that *some* configured objective advanced the
    optimizer.  In a joint policy/value learner, value rows can therefore make a
    run report thousands of successful steps even when the sampled policy mass
    is exactly zero.  Build the attestation from realized, DDP-reduced epoch
    sufficient statistics and fail closed before the final checkpoint is saved.
    """

    coefficient = _validate_policy_loss_weight(policy_loss_weight)
    base_active_rows = sum(
        int(metric.get("policy_base_active_rows", 0)) for metric in metrics
    )
    aux_active_rows = sum(
        int(metric.get("policy_aux_active_rows", 0)) for metric in metrics
    )
    base_draws = sum(int(metric.get("samples", 0)) for metric in metrics)
    total_draws = base_draws + aux_active_rows
    effective_weight_sum = sum(
        float(
            metric.get(
                "policy_objective_effective_weight_sum",
                (metric.get("loss_denominators") or {}).get(
                    "policy_loss", 0.0
                ),
            )
        )
        for metric in metrics
    )
    policy_enabled = coefficient > 0.0 and not bool(train_value_only)
    active_rows = sum(
        int(
            metric.get(
                "policy_objective_active_rows",
                int(metric.get("policy_base_active_rows", 0))
                + int(metric.get("policy_aux_active_rows", 0)),
            )
        )
        for metric in metrics
    )
    equivalent_active_rows = sum(
        float(
            metric.get(
                "policy_objective_equivalent_active_rows",
                metric.get(
                    "policy_objective_active_rows",
                    int(metric.get("policy_base_active_rows", 0))
                    + int(metric.get("policy_aux_active_rows", 0)),
                ),
            )
        )
        for metric in metrics
    )
    equivalent_effective_weight_sum = sum(
        float(
            metric["policy_objective_equivalent_effective_weight_sum"]
            if "policy_objective_equivalent_effective_weight_sum" in metric
            else (
                float(metric["policy_objective_effective_weight_sum"])
                / coefficient
                if (
                    coefficient > 0.0
                    and "policy_objective_effective_weight_sum" in metric
                )
                else (metric.get("loss_denominators") or {}).get(
                    "policy_loss", 0.0
                )
            )
        )
        for metric in metrics
    )
    policy_optimizer_updates = sum(
        int(metric.get("policy_objective_optimizer_updates", 0))
        for metric in metrics
    )
    equivalent_optimizer_updates = sum(
        float(
            metric.get(
                "policy_objective_equivalent_optimizer_updates",
                metric.get("policy_objective_optimizer_updates", 0),
            )
        )
        for metric in metrics
    )
    # Historical metrics predate objective-specific update accounting. They
    # used a constant nonzero policy coefficient, so a positive realized
    # denominator implies every applied update belonged to the policy dose.
    if (
        policy_optimizer_updates == 0
        and not any(
            "policy_objective_optimizer_updates" in metric for metric in metrics
        )
        and effective_weight_sum > 0.0
    ):
        policy_optimizer_updates = int(optimizer_steps)
        equivalent_optimizer_updates = float(optimizer_steps)
    trained = bool(
        policy_enabled
        and policy_optimizer_updates > 0
        and active_rows > 0
        and math.isfinite(equivalent_active_rows)
        and equivalent_active_rows > 0.0
        and math.isfinite(effective_weight_sum)
        and effective_weight_sum > 0.0
        and math.isfinite(equivalent_effective_weight_sum)
        and equivalent_effective_weight_sum > 0.0
    )
    attestation = {
        "schema_version": "policy-training-signal-v2",
        "policy_objective_enabled": policy_enabled,
        "policy_loss_weight": coefficient,
        "optimizer_steps": int(optimizer_steps),
        "policy_optimizer_updates": int(policy_optimizer_updates),
        "policy_equivalent_optimizer_updates": float(
            equivalent_optimizer_updates
        ),
        "base_sampler_draws": int(base_draws),
        "policy_aux_draws": int(aux_active_rows),
        "total_draws": int(total_draws),
        "policy_base_active_rows": int(base_active_rows),
        "policy_aux_active_rows": int(aux_active_rows),
        "policy_active_rows": int(active_rows),
        "policy_equivalent_active_rows": float(equivalent_active_rows),
        "policy_active_draw_fraction": (
            float(active_rows) / float(total_draws) if total_draws > 0 else None
        ),
        "policy_equivalent_active_draw_fraction": (
            float(equivalent_active_rows) / float(total_draws)
            if total_draws > 0
            else None
        ),
        "policy_effective_weight_sum": float(effective_weight_sum),
        "policy_equivalent_effective_weight_sum": float(
            equivalent_effective_weight_sum
        ),
        "trained_policy_objective": trained,
        "status": (
            "disabled_value_only"
            if bool(train_value_only)
            else "disabled_zero_coefficient"
            if coefficient <= 0.0
            else "trained"
            if trained
            else "missing_realized_signal"
        ),
    }
    if policy_enabled and not trained:
        raise RuntimeError(
            "policy objective was configured but no realized policy training "
            "signal reached an applied optimizer trajectory; refusing to save "
            "a checkpoint whose step count could be mistaken for policy "
            f"learning (steps={optimizer_steps}, "
            f"policy_updates={policy_optimizer_updates}, "
            f"active_rows={active_rows}, "
            f"equivalent_active_rows={equivalent_active_rows}, "
            f"effective_weight_sum={effective_weight_sum})"
        )
    return attestation


def _validate_policy_loss_weight(value: float) -> float:
    """Return a safe policy coefficient or reject anti-/undefined training."""

    value = float(value)
    if not math.isfinite(value) or value < 0.0:
        raise SystemExit(
            "--policy-loss-weight must be finite and non-negative; "
            f"got {value}"
        )
    return value


def _policy_weight_for_lr_area(
    base_weight: float,
    *,
    scheduled_base_lr: float,
    consumed_lr_area: float,
    target_lr_area: float,
    objective_multiplier: float = 1.0,
) -> float:
    """Meter policy imitation by integrated optimizer dose, not step count."""

    coefficient = _validate_policy_loss_weight(base_weight)
    learning_rate = float(scheduled_base_lr)
    consumed = float(consumed_lr_area)
    target = float(target_lr_area)
    multiplier = float(objective_multiplier)
    if not all(
        math.isfinite(value)
        for value in (learning_rate, consumed, target, multiplier)
    ):
        raise ValueError("policy LR-area inputs must be finite")
    if learning_rate < 0.0 or consumed < 0.0 or target < 0.0:
        raise ValueError("policy LR-area inputs must be non-negative")
    if multiplier <= 0.0:
        raise ValueError("policy objective multiplier must be positive")
    if target == 0.0 or coefficient == 0.0:
        return coefficient
    remaining = max(0.0, target - consumed)
    if remaining == 0.0:
        return 0.0
    if learning_rate == 0.0:
        return coefficient
    return min(coefficient, remaining / (learning_rate * multiplier))


def _policy_microbatch_weight_for_lr_area(
    base_weight: float,
    *,
    scheduled_base_lr: float,
    consumed_lr_area: float,
    target_lr_area: float,
    pending_group_lr_area_weight: float,
    globally_base_objective_mass: float,
    globally_aux_objective_mass: float,
    policy_aux_loss_weight: float,
    accumulation_group_size: int,
) -> float:
    """Resolve an exact boundary coefficient for one accumulated microbatch.

    Base and AUX policy means are independently normalized, and every
    microbatch is divided by the actual accumulation-group size.  Boundary
    metering must therefore use the streams that will really contribute to
    this microbatch and subtract dose already pending in the same optimizer
    group.  Using merely the presence of an AUX batch undercharges base-only
    and AUX-only boundaries; ignoring pending gradients can overshoot them.
    """

    coefficient = _validate_policy_loss_weight(base_weight)
    learning_rate = float(scheduled_base_lr)
    pending_weight = float(pending_group_lr_area_weight)
    base_mass = float(globally_base_objective_mass)
    aux_mass = float(globally_aux_objective_mass)
    aux_weight = float(policy_aux_loss_weight)
    group_size = int(accumulation_group_size)
    if not math.isfinite(pending_weight) or pending_weight < 0.0:
        raise ValueError(
            "pending policy LR-area weight must be finite and non-negative"
        )
    if not math.isfinite(aux_weight) or aux_weight < 0.0:
        raise ValueError("policy AUX objective weight must be finite and non-negative")
    if (
        not math.isfinite(base_mass)
        or base_mass < 0.0
        or not math.isfinite(aux_mass)
        or aux_mass < 0.0
    ):
        raise ValueError("policy objective masses must be finite and non-negative")
    if group_size < 1:
        raise ValueError("policy accumulation group size must be positive")
    pending_area = learning_rate * pending_weight
    effective_consumed = float(consumed_lr_area) + pending_area
    stream_multiplier = base_mass + aux_weight * aux_mass
    # An objective-empty microbatch spends no policy dose. Keep the configured
    # coefficient while the boundary remains open so value-only work cannot
    # trigger post-dose representation freezing.
    if stream_multiplier == 0.0:
        return _policy_weight_for_lr_area(
            coefficient,
            scheduled_base_lr=learning_rate,
            consumed_lr_area=effective_consumed,
            target_lr_area=target_lr_area,
        )
    return _policy_weight_for_lr_area(
        coefficient,
        scheduled_base_lr=learning_rate,
        consumed_lr_area=effective_consumed,
        target_lr_area=target_lr_area,
        objective_multiplier=stream_multiplier / group_size,
    )


def _policy_objective_fraction(
    policy_loss_weight: float, configured_policy_loss_weight: float
) -> float:
    """Return the full-dose-equivalent fraction for one learner batch."""

    configured = _validate_policy_loss_weight(configured_policy_loss_weight)
    realized = _validate_policy_loss_weight(policy_loss_weight)
    if configured == 0.0:
        if realized != 0.0:
            raise ValueError(
                "realized policy coefficient is nonzero while configured "
                "policy coefficient is zero"
            )
        return 0.0
    fraction = realized / configured
    if fraction > 1.0 + 1.0e-12:
        raise ValueError(
            "realized policy coefficient exceeds its configured full dose"
        )
    return min(1.0, fraction)


def _global_policy_objective_presence(
    *,
    local_base_active_rows: int,
    local_aux_active_rows: int,
    ddp: Mapping[str, int | bool],
) -> bool:
    """Return whether any rank supplied real policy rows to this microbatch.

    Policy-loss denominators are not an admissible signal here: coverage-mode
    normalizers can stay positive on a rank whose microbatch contains no policy
    rows. Dose ownership follows realized rows, reduced across the complete DDP
    worker set.
    """

    base_present, aux_present = _global_policy_stream_presence(
        local_base_active_rows=local_base_active_rows,
        local_aux_active_rows=local_aux_active_rows,
        ddp=ddp,
    )
    return base_present or aux_present


def _global_policy_stream_presence(
    *,
    local_base_active_rows: int,
    local_aux_active_rows: int,
    ddp: Mapping[str, int | bool],
) -> tuple[bool, bool]:
    """Return DDP-global presence for each independently normalized policy stream."""

    base_rows = int(local_base_active_rows)
    aux_rows = int(local_aux_active_rows)
    if base_rows < 0 or aux_rows < 0:
        raise ValueError("policy active-row counts must be non-negative")
    present = (base_rows > 0, aux_rows > 0)
    if not bool(ddp.get("enabled", False)):
        return present

    import torch
    import torch.distributed as dist

    device = (
        f"cuda:{int(ddp.get('local_rank', 0))}"
        if torch.cuda.is_available()
        else "cpu"
    )
    global_presence = torch.tensor(
        [int(present[0]), int(present[1])],
        dtype=torch.int32,
        device=device,
    )
    dist.all_reduce(global_presence, op=dist.ReduceOp.MAX)
    return bool(global_presence[0].item()), bool(global_presence[1].item())


def _base_policy_weights_for_training_batch(
    policy_sample_weights: np.ndarray,
    batch: np.ndarray,
) -> np.ndarray:
    """Select only the base rows whose policy objective is about to run.

    The synchronous iterator passes corpus-wide weights with global batch
    indices. Threaded prefetch instead passes weights materialized for the base
    rows followed by any policy-AUX rows, with local base indices. Indexing by
    ``batch`` is the common contract shared by both paths and matches the
    selection performed by the loss itself.
    """

    weights = np.asarray(policy_sample_weights)
    indices = np.asarray(batch)
    if weights.ndim != 1:
        raise ValueError("policy sample weights must be one-dimensional")
    if indices.ndim != 1 or not np.issubdtype(indices.dtype, np.integer):
        raise ValueError("training batch indices must be one-dimensional integers")
    if np.any(indices < 0) or np.any(indices >= len(weights)):
        raise IndexError("training batch indices exceed policy sample weights")
    return weights[indices]


def _global_policy_stream_objective_masses(
    *,
    local_base_effective_weight_sum: float,
    local_base_fixed_denominator: float | None,
    local_aux_active_rows: int,
    ddp: Mapping[str, int | bool],
) -> tuple[float, float]:
    """Return the exact normalized base/AUX policy mass applied by DDP.

    Ordinary base and AUX losses normalize by their realized global weight
    sums, so any positive stream contributes one full independently normalized
    objective. Coverage importance instead uses a fixed population
    denominator. Its base objective mass is therefore
    ``global_effective_weight_sum / global_fixed_denominator``; reducing it to
    a boolean would overstate sparse batches and make the LR-area ledger diverge
    from the coefficient actually multiplying the gradient.
    """

    base_weight_sum = float(local_base_effective_weight_sum)
    aux_rows = int(local_aux_active_rows)
    fixed = (
        None
        if local_base_fixed_denominator is None
        else float(local_base_fixed_denominator)
    )
    if not math.isfinite(base_weight_sum) or base_weight_sum < 0.0:
        raise ValueError(
            "base policy effective weight sum must be finite and non-negative"
        )
    if aux_rows < 0:
        raise ValueError("policy AUX active rows must be non-negative")
    if fixed is not None and (not math.isfinite(fixed) or fixed <= 0.0):
        raise ValueError(
            "fixed base policy denominator must be finite and positive"
        )

    totals = [base_weight_sum, 0.0 if fixed is None else fixed, float(aux_rows)]
    if bool(ddp.get("enabled", False)):
        import torch
        import torch.distributed as dist

        device = (
            f"cuda:{int(ddp.get('local_rank', 0))}"
            if torch.cuda.is_available()
            else "cpu"
        )
        tensor = torch.tensor(totals, dtype=torch.float64, device=device)
        dist.all_reduce(tensor, op=dist.ReduceOp.SUM)
        totals = [float(value) for value in tensor.cpu().tolist()]
    global_base_weight, global_fixed_denominator, global_aux_rows = totals
    base_mass = (
        global_base_weight / global_fixed_denominator
        if fixed is not None
        else float(global_base_weight > 0.0)
    )
    aux_mass = float(global_aux_rows > 0.0)
    if not math.isfinite(base_mass) or base_mass < 0.0:
        raise RuntimeError("global base policy objective mass is invalid")
    return base_mass, aux_mass


def _realized_policy_microbatch_dose(
    *,
    policy_loss_weight: float,
    policy_objective_fraction: float,
    globally_base_objective_mass: float,
    globally_aux_objective_mass: float,
    policy_aux_loss_weight: float,
    accumulation_group_size: int,
) -> tuple[float, float]:
    """Return this microbatch's contribution to one optimizer-group dose.

    The learner divides every microbatch objective by the actual accumulation
    group size, including a short trailing group. Policy LR-area and equivalent
    optimizer updates must use the same divisor and the same realized
    base/AUX objective masses. The base mass is normally one for its
    independently normalized mean, but coverage importance can contribute a
    fractional or super-unit population-denominator mass in one microbatch.
    Collapsing that mass to presence silently spends the wrong dose.
    """

    weight = _validate_policy_loss_weight(policy_loss_weight)
    fraction = float(policy_objective_fraction)
    base_mass = float(globally_base_objective_mass)
    aux_mass = float(globally_aux_objective_mass)
    aux_weight = float(policy_aux_loss_weight)
    group_size = int(accumulation_group_size)
    if not math.isfinite(fraction) or not 0.0 <= fraction <= 1.0:
        raise ValueError("policy objective fraction must be finite and in [0, 1]")
    if not math.isfinite(aux_weight) or aux_weight < 0.0:
        raise ValueError("policy AUX objective weight must be finite and non-negative")
    if (
        not math.isfinite(base_mass)
        or base_mass < 0.0
        or not math.isfinite(aux_mass)
        or aux_mass < 0.0
    ):
        raise ValueError("policy objective masses must be finite and non-negative")
    if group_size < 1:
        raise ValueError("policy accumulation group size must be positive")
    objective_multiplier = base_mass + aux_weight * aux_mass
    if objective_multiplier == 0.0:
        return 0.0, 0.0
    return (
        weight * objective_multiplier / group_size,
        fraction * objective_multiplier / group_size,
    )


def _validate_policy_dose_topology(
    *,
    target_lr_area: float,
    reference_global_batch_size: int,
    local_batch_size: int,
    grad_accum_steps: int,
    world_size: int,
) -> int:
    """Bind an LR-area dose to the optimizer topology that produced its evidence."""

    target = float(target_lr_area)
    reference = int(reference_global_batch_size)
    global_batch_size = (
        int(local_batch_size) * int(grad_accum_steps) * int(world_size)
    )
    if not math.isfinite(target) or target < 0.0:
        raise SystemExit("--policy-dose-lr-area must be finite and >= 0")
    if global_batch_size <= 0:
        raise SystemExit("policy dose requires a positive global optimizer batch")
    if target == 0.0:
        if reference != 0:
            raise SystemExit(
                "--policy-dose-reference-global-batch-size is inert unless "
                "--policy-dose-lr-area is positive"
            )
        return global_batch_size
    if reference <= 0:
        raise SystemExit(
            "positive --policy-dose-lr-area requires "
            "--policy-dose-reference-global-batch-size"
        )
    if reference != global_batch_size:
        raise SystemExit(
            "policy LR-area evidence cannot cross optimizer topology: "
            f"reference_global_batch={reference} "
            f"current_global_batch={global_batch_size}"
        )
    return global_batch_size


def _post_policy_dose_value_trunk_routing(
    *,
    base_scale: float,
    post_scale: float,
    target_lr_area: float,
    realized_policy_loss_weight: float,
    pending_policy_lr_area_weight: float = 0.0,
) -> dict[str, object]:
    """Resolve the per-batch value boundary without redefining a zero-dose run."""

    base = float(base_scale)
    post = float(post_scale)
    target = float(target_lr_area)
    policy_weight = float(realized_policy_loss_weight)
    pending_weight = float(pending_policy_lr_area_weight)
    for name, value in (
        ("--value-trunk-grad-scale", base),
        ("--post-policy-dose-value-trunk-grad-scale", post),
    ):
        if not math.isfinite(value) or not 0.0 <= value <= 1.0:
            raise SystemExit(f"{name} must be finite and in [0, 1]")
    if not math.isfinite(target) or target < 0.0:
        raise SystemExit("--policy-dose-lr-area must be finite and >= 0")
    if not math.isfinite(pending_weight) or pending_weight < 0.0:
        raise ValueError(
            "pending policy LR-area weight must be finite and non-negative"
        )
    if target == 0.0:
        phase = "dormant_no_positive_policy_dose"
        effective = base
    elif policy_weight > 0.0 or pending_weight > 0.0:
        phase = "pre_or_boundary_policy_dose"
        effective = base
    else:
        phase = "post_policy_dose"
        effective = post
    return {
        "schema_version": "post-policy-dose-value-routing-v1",
        "phase": phase,
        "effective_value_trunk_grad_scale": effective,
        "base_value_trunk_grad_scale": base,
        "post_policy_dose_value_trunk_grad_scale": post,
        "pending_policy_lr_area_weight": pending_weight,
        "positive_policy_dose_enabled": target > 0.0,
        "shared_policy_representation_frozen": (
            phase == "post_policy_dose" and effective == 0.0
        ),
    }


def _optimizer_lr_dose_attestation(
    *,
    applied_updates: int,
    schedule_multiplier_sum: float,
    lr_area_by_group: Sequence[float],
    optimizer,
) -> dict[str, object]:
    """Describe the exact LR integral over updates applied in this invocation."""

    updates = int(applied_updates)
    if updates < 0 or len(lr_area_by_group) != len(optimizer.param_groups):
        raise ValueError("invalid optimizer LR-dose accounting")
    groups = []
    for index, (area, group) in enumerate(
        zip(lr_area_by_group, optimizer.param_groups, strict=True)
    ):
        area = float(area)
        if not math.isfinite(area) or area < 0.0:
            raise ValueError("optimizer LR area must be finite and non-negative")
        groups.append(
            {
                "group_index": int(index),
                "base_lr": float(group.get("base_lr", group["lr"])),
                "integrated_lr_area": area,
                "mean_applied_lr": area / updates if updates > 0 else None,
            }
        )
    multiplier_sum = float(schedule_multiplier_sum)
    if not math.isfinite(multiplier_sum) or multiplier_sum < 0.0:
        raise ValueError("schedule multiplier area must be finite and non-negative")
    return {
        "schema_version": "optimizer-lr-dose-v1",
        "scope": "updates_applied_in_this_process_invocation",
        "applied_updates": updates,
        "integrated_schedule_multiplier_area": multiplier_sum,
        "mean_schedule_multiplier": (
            multiplier_sum / updates if updates > 0 else None
        ),
        "parameter_groups": groups,
    }


def _assert_value_heads_present_for_losses(model, args) -> None:
    """Fail LOUD (SystemExit) when a value-head objective was requested on the
    CLI but the constructed/loaded model lacks the head that objective needs --
    instead of silently training with that loss term stuck at 0.0 for the whole
    (multi-hundred-GPU-hour) run. Mirrors the --value-lr-mult SystemExit guard:
    a requested-but-inert head is a misconfiguration, not a no-op.

    (1) --value-head-type hlgauss needs a categorical value head
        (value_categorical_bins >= 2). CAT-39's weight resolution makes the CE
        weight nonzero in hlgauss mode, but the loss term is still gated on
        "value_categorical_logits" in the model outputs; a scalar model never
        emits them, so the HL-Gauss objective is silently inert.
    (2) --value-uncertainty-loss-weight != 0 needs the value_uncertainty_head
        submodule; without it "value_uncertainty" is never in outputs and the
        loss stays 0.0.
    """
    _resolve_value_objective_weights(args)
    if str(getattr(args, "value_head_type", "mse")) == "hlgauss":
        bins = int(getattr(model, "value_categorical_bins", 0) or 0)
        if bins < 2:
            raise SystemExit(
                "--value-head-type hlgauss requires a categorical value head "
                "(EntityGraphNetConfig.value_categorical_bins >= 2; see "
                "f69_upgrade_checkpoint_config catbins:N), but the constructed/"
                f"loaded model has value_categorical_bins={bins}. Without it the "
                "HL-Gauss objective is silently inert and the run trains scalar-MSE "
                "only. Build/upgrade a catbins head (for a fresh model pass "
                "--value-categorical-bins >=2) or pass "
                "--value-head-type scalar."
            )
    if float(getattr(args, "value_uncertainty_loss_weight", 0.0) or 0.0) != 0.0:
        if getattr(model, "value_uncertainty_head", None) is None:
            raise SystemExit(
                "--value-uncertainty-loss-weight != 0 requires the model to carry a "
                "value_uncertainty_head (build a fresh model with "
                "--value-uncertainty-head, or resume a checkpoint that already has "
                "it), but the constructed/loaded model has none. Without it the "
                "uncertainty loss is silently inert; pass "
                "--value-uncertainty-loss-weight 0 or add the head."
            )
    if float(getattr(args, "final_vp_loss_weight", 0.0) or 0.0) != 0.0:
        if getattr(model, "final_vp_head", None) is None:
            raise SystemExit(
                "--final-vp-loss-weight != 0 requires a named final_vp_head; "
                "without it the requested objective is silently inert"
            )
    if float(getattr(args, "aux_subgoal_loss_weight", 0.0) or 0.0) != 0.0:
        settlement_pointer = bool(
            getattr(model, "aux_settlement_pointer_head_enabled", False)
        )
        required_aux_heads = (
            "aux_longest_road_head",
            "aux_largest_army_head",
            "aux_vp_in_n_head",
            (
                "aux_next_settlement_pointer_head"
                if settlement_pointer
                else "aux_next_settlement_head"
            ),
            "aux_robber_target_head",
        )
        missing = [
            name for name in required_aux_heads if getattr(model, name, None) is None
        ]
        if missing:
            raise SystemExit(
                "--aux-subgoal-loss-weight != 0 requires the complete auxiliary "
                "head set; missing: " + ", ".join(missing)
            )
    if float(getattr(args, "belief_resource_loss_weight", 0.0) or 0.0) != 0.0:
        if getattr(model, "belief_resource_head", None) is None:
            raise SystemExit(
                "--belief-resource-loss-weight != 0 requires a named "
                "belief_resource_head; without it the requested objective is inert"
            )


_OPTIONAL_TRAINING_HEADS: tuple[tuple[str, str], ...] = (
    ("final_vp_head", "final_vp_loss_weight"),
    ("value_uncertainty_head", "value_uncertainty_loss_weight"),
    ("value_categorical_head", "value_categorical_loss_weight"),
    ("aux_longest_road_head", "aux_subgoal_loss_weight"),
    ("aux_largest_army_head", "aux_subgoal_loss_weight"),
    ("aux_vp_in_n_head", "aux_subgoal_loss_weight"),
    ("aux_next_settlement_head", "aux_subgoal_loss_weight"),
    ("aux_robber_target_head", "aux_subgoal_loss_weight"),
    ("aux_next_settlement_pointer_head", "aux_subgoal_loss_weight"),
    ("belief_resource_head", "belief_resource_loss_weight"),
    # The latent-deliberation halt readout is emitted by the model, but the BC
    # learner has no halt target or loss.  Leaving it trainable creates an
    # unused-parameter surface under DDP and lets AdamW decay an untrained head.
    ("deliberation_halt_head", "<no_bc_objective>"),
)


def _freeze_inactive_training_heads(
    model,
    *,
    final_vp_loss_weight: float,
    value_uncertainty_loss_weight: float,
    value_categorical_loss_weight: float,
    aux_subgoal_loss_weight: float,
    belief_resource_loss_weight: float,
) -> dict[str, object]:
    """Exclude zero-objective auxiliary heads before DDP/optimizer creation.

    A zero coefficient is not a freeze under AdamW: a parameter reached by the
    graph can receive a zero gradient and still undergo decoupled decay.  Heads
    with no learner objective can also become DDP-unused parameters.  This
    helper makes the actual trainable surface agree with the configured loss
    surface while leaving every active head unchanged.  It also records the
    inactive modules on the model itself.  EntityGraphNet consumes that
    trainer-only gate to skip their forwards: merely freezing parameters is
    insufficient when an inactive head contains dropout, because executing it
    would still advance the global torch RNG and change later trunk masks.
    """

    module = getattr(model, "module", model)
    weights = {
        "final_vp_loss_weight": float(final_vp_loss_weight),
        "value_uncertainty_loss_weight": float(value_uncertainty_loss_weight),
        "value_categorical_loss_weight": float(value_categorical_loss_weight),
        "aux_subgoal_loss_weight": float(aux_subgoal_loss_weight),
        "belief_resource_loss_weight": float(belief_resource_loss_weight),
        "<no_bc_objective>": 0.0,
    }
    frozen_names: list[str] = []
    frozen_parameters = 0
    active_names: list[str] = []
    for module_name, objective_name in _OPTIONAL_TRAINING_HEADS:
        head = getattr(module, module_name, None)
        if head is None:
            continue
        if weights[objective_name] != 0.0:
            active_names.append(module_name)
            continue
        parameters = list(head.parameters()) if hasattr(head, "parameters") else [head]
        for parameter in parameters:
            if parameter.requires_grad:
                parameter.requires_grad = False
                frozen_parameters += int(parameter.numel())
        frozen_names.append(module_name)
    # A plain Python attribute is intentional: it follows the live module
    # through DDP wrapping and repeated ``model.train()`` calls, but is not a
    # parameter/buffer and therefore cannot leak a training-only output policy
    # into checkpoint state_dicts or normal inference loads.
    module._inactive_training_head_modules = frozenset(frozen_names)
    return {
        "schema_version": "inactive-training-head-freeze-v2",
        "frozen_submodules": sorted(frozen_names),
        "active_optional_submodules": sorted(active_names),
        "frozen_parameters": int(frozen_parameters),
        "zero_weight_is_optimizer_exclusion": True,
        "zero_weight_skips_forward": True,
        "latent_deliberation_halt_has_bc_objective": False,
    }


def _checkpoint_value_categorical_bins(checkpoint_path: str) -> int:
    """Read the categorical support width from a policy checkpoint config."""

    import torch

    from catan_zero.rl.config_serialization import config_attr_view

    checkpoint = torch.load(checkpoint_path, map_location="cpu", weights_only=False)
    if not isinstance(checkpoint, dict) or "config" not in checkpoint:
        raise SystemExit(
            f"{checkpoint_path} is not a policy checkpoint with a config; cannot "
            "resolve --value-categorical-bins"
        )
    config = config_attr_view(checkpoint["config"])
    bins = int(getattr(config, "value_categorical_bins", 0) or 0)
    if bins == 1 or bins < 0:
        raise SystemExit(
            f"{checkpoint_path} records invalid value_categorical_bins={bins}; "
            "expected 0 (disabled) or >=2"
        )
    return bins


