def _sha256_existing_file(path: str | Path) -> str:
    resolved = Path(path)
    if not resolved.is_file():
        return ""
    digest = hashlib.sha256()
    with open(resolved, "rb") as handle:
        for block in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(block)
    return f"sha256:{digest.hexdigest()}"


def _stable_canonical_regular_file(
    value: str | Path, *, where: str
) -> tuple[Path, str, bytes]:
    """Stable-read one canonical regular file without symlink ambiguity.

    Hashing and parsing separate opens leaves a small but real authority race:
    the path can be replaced after its digest is checked but before its JSON is
    consumed.  Read through one descriptor, then prove that both the descriptor
    and the path still name the same inode before returning the authenticated
    bytes.
    """

    lexical = Path(value).expanduser()
    try:
        resolved = lexical.resolve(strict=True)
        lexical_absolute = lexical.absolute()
        before = resolved.stat()
    except OSError as error:
        raise SystemExit(f"cannot inspect {where}: {error}") from error
    if (
        str(resolved) != str(value)
        or lexical_absolute != resolved
        or lexical.is_symlink()
        or not stat.S_ISREG(before.st_mode)
    ):
        raise SystemExit(f"{where} must be one canonical regular-file path")
    flags = os.O_RDONLY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    descriptor = os.open(resolved, flags)
    try:
        opened_before = os.fstat(descriptor)
        chunks: list[bytes] = []
        while True:
            chunk = os.read(descriptor, 1 << 20)
            if not chunk:
                break
            chunks.append(chunk)
        opened_after = os.fstat(descriptor)
    finally:
        os.close(descriptor)
    payload = b"".join(chunks)
    after = resolved.stat()
    before_identity = (
        before.st_dev,
        before.st_ino,
        before.st_size,
        before.st_mtime_ns,
        before.st_ctime_ns,
    )
    after_identity = (
        after.st_dev,
        after.st_ino,
        after.st_size,
        after.st_mtime_ns,
        after.st_ctime_ns,
    )
    opened_before_identity = (
        opened_before.st_dev,
        opened_before.st_ino,
        opened_before.st_size,
        opened_before.st_mtime_ns,
        opened_before.st_ctime_ns,
    )
    opened_after_identity = (
        opened_after.st_dev,
        opened_after.st_ino,
        opened_after.st_size,
        opened_after.st_mtime_ns,
        opened_after.st_ctime_ns,
    )
    if (
        before_identity != after_identity
        or before_identity != opened_before_identity
        or opened_before_identity != opened_after_identity
    ):
        raise SystemExit(f"{where} changed while it was authenticated")
    return resolved, f"sha256:{hashlib.sha256(payload).hexdigest()}", payload


def _canonical_json_sha256(value: object) -> str:
    payload = json.dumps(
        value, sort_keys=True, separators=(",", ":"), ensure_ascii=True
    ).encode("utf-8")
    return f"sha256:{hashlib.sha256(payload).hexdigest()}"


def _a1_sample_binding_projection(sample: dict[str, object]) -> dict[str, object]:
    fields = (
        "state_sha256",
        "descriptor_sha256",
        "payload_inventory_sha256",
        "category_semantics",
        "category_semantics_sha256",
        "source_authority",
        "sampler_identity_sha256",
        "sample_order_sha256",
        "row_set_sha256",
        "unique_row_count",
        "rows_file_sha256",
        "sample_dose",
        "sampler_seed",
        "prior_rows_file_sha256",
        "prior_row_set_sha256",
        "kl_eligible_rows",
        "kl_eligible_mass_decimal",
        "kl_ordered_evidence_sha256",
        "kl_eligible_evidence_sha256",
    )
    result = {
        "schema_version": "a1-central-sample-binding-v2",
        "sample_receipt_state_sha256": sample.get("state_sha256"),
    }
    result.update({field: sample.get(field) for field in fields[1:]})
    return result


def _validate_a1_published_executor_authority(
    args: argparse.Namespace, central: dict[str, object]
) -> dict[str, object]:
    """Replay the coordinator DAG; inline JSON is only a derived projection."""

    path_value = str(getattr(args, "a1_central_executor_authority", "") or "")
    expected_file_sha = str(
        getattr(args, "a1_central_executor_authority_sha256", "") or ""
    )
    if not path_value or not _is_sha256(expected_file_sha):
        raise SystemExit(
            "central learner requires canonical executor-authority path and SHA"
        )
    authority_path, file_sha, authority_bytes = _stable_canonical_regular_file(
        path_value, where="A1 central executor authority"
    )
    if (
        file_sha != expected_file_sha
        or str(authority_path) != central.get("executor_authority_path")
        or file_sha != central.get("executor_authority_file_sha256")
    ):
        raise SystemExit("A1 central executor authority path/file digest drift")
    try:
        stable_authority = json.loads(authority_bytes.decode("utf-8"))
    except (UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(
            f"cannot parse A1 central executor authority: {error}"
        ) from error
    try:
        from tools import a1_aux_pair_coordinator as coordinator
    except ImportError as error:
        raise SystemExit(
            f"cannot import A1 central coordinator verifier: {error}"
        ) from error
    try:
        published = coordinator.verify_published_executor_authority(authority_path)
    except coordinator.CoordinatorError as error:
        raise SystemExit(
            f"A1 central executor authority replay refused: {error}"
        ) from error
    authority = published.get("authority")
    if (
        published.get("path") != str(authority_path)
        or published.get("file_sha256") != file_sha
        or authority != stable_authority
        or not isinstance(authority, dict)
        or authority.get("schema_version") != central.get("central_authority_schema")
        or authority.get("authority_sha256")
        != central.get("central_authority_sha256")
        or authority.get("state_sha256")
        != central.get("executor_authority_state_sha256")
    ):
        raise SystemExit("A1 central executor authority replay/projection drift")

    stage = central.get("stage")
    selected_aux = central.get("selected_aux_decision")
    try:
        if stage == "P1":
            authority_recipe = authority["arm"]["effective_recipe"]
            authority_sample = authority["p1_sample_evidence_receipt"]
            authority_initializer = authority["current_parent_authority"][
                "checkpoint_sha256"
            ]
            authority_selected_aux = None
        elif stage in {"AUX0", "AUXT"}:
            pair = authority["aux_pair_contract"]
            p1 = pair["portable_science_identity"]["p1_recipe_data_authority"]
            authority_recipe = copy.deepcopy(pair["joint"]["effective_recipe"])
            authority_recipe["aux_subgoal_loss_weight"] = authority["arm"][
                "aux_subgoal_loss_weight"
            ]
            authority_sample = p1["p1_sample_evidence_receipt"]
            authority_initializer = pair["joint"]["initializer_sha256"]
            authority_selected_aux = authority["arm"]["arm_id"]
        elif stage == "FINAL":
            final = authority["final_replication_authority"]
            authority_recipe = {
                key: value
                for key, value in final["effective_recipe"].items()
                if key not in {"aux_subgoal_heads", "aux_settlement_pointer_head"}
            }
            authority_sample = final["sampling_receipt"]
            authority_selected_aux = final["selected_aux_decision"]
            initializer_authority = final["initializer_authority"]
            raw_parent = initializer_authority[
                "exact_current_parent_authority"
            ]
            transition = coordinator.verify_public_award_transition_authority(
                initializer_authority["public_award_transition_authority"],
                expected_parent=raw_parent,
            )
            if authority_selected_aux == "AUXT":
                pointer = coordinator.verify_pointer_upgrade_authority(
                    initializer_authority["pointer_upgrade_authority"],
                    expected_parent_sha256=transition[
                        "transitioned_checkpoint"
                    ]["sha256"],
                )
                warmup = initializer_authority[
                    "reference_warmup_terminal"
                ]
                if (
                    warmup["result"]["input_initializer_sha256"]
                    != pointer["upgraded_initializer_sha256"]
                    or warmup["result"]["optimizer_sidecar_discarded_for_joint"]
                    is not True
                ):
                    raise SystemExit(
                        "A1 FINAL AUXT warmup does not continue the exact "
                        "transition/pointer initializer chain"
                    )
                authority_initializer = initializer_authority[
                    "reference_warmup_terminal"
                ]["result"]["warmed_checkpoint_sha256"]
            else:
                if (
                    initializer_authority.get("pointer_upgrade_authority") is not None
                    or initializer_authority.get("reference_warmup_terminal")
                    is not None
                ):
                    raise SystemExit(
                        "A1 FINAL AUX0 must use only the public-award transition"
                    )
                authority_initializer = transition["transitioned_checkpoint"][
                    "sha256"
                ]
        else:
            raise KeyError("stage")
    except (KeyError, TypeError, coordinator.CoordinatorError) as error:
        raise SystemExit(
            f"A1 central executor authority lacks canonical projection: {error}"
        ) from error
    if (
        authority_recipe != central.get("effective_recipe")
        or _a1_sample_binding_projection(authority_sample)
        != central.get("sample_binding")
        or authority_initializer != central.get("initializer_sha256")
        or authority_selected_aux != selected_aux
    ):
        raise SystemExit("A1 central inline projection differs from coordinator DAG")
    return published


def _validate_a1_aux_stage_authority(
    args: argparse.Namespace,
    *,
    composite_meta: Mapping[str, object] | None,
    ddp: Mapping[str, int | bool],
) -> dict[str, object] | None:
    """Replay the WARMUP/GEOMETRY authority before optimizer construction."""

    raw = str(getattr(args, "a1_aux_stage_binding_json", "") or "")
    authority_value = str(
        getattr(args, "a1_aux_stage_executor_authority", "") or ""
    )
    authority_sha = str(
        getattr(args, "a1_aux_stage_executor_authority_sha256", "") or ""
    )
    if not any((raw, authority_value, authority_sha)):
        return None
    if not all((raw, authority_value, authority_sha)) or not _is_sha256(authority_sha):
        raise SystemExit(
            "A1 AUX stage binding and executor-authority path/SHA are inseparable"
        )
    try:
        binding = json.loads(raw)
    except json.JSONDecodeError as error:
        raise SystemExit(f"cannot parse A1 AUX stage binding: {error}") from error
    expected_fields = {
        "schema_version",
        "stage",
        "experiment_id",
        "executor_authority_path",
        "executor_authority_file_sha256",
        "executor_authority_state_sha256",
        "descriptor_path",
        "descriptor_sha256",
        "payload_inventory_sha256",
        "initializer_path",
        "initializer_sha256",
        "output_report",
        "output_checkpoint",
        "probe_manifest",
    }
    if (
        not isinstance(binding, dict)
        or set(binding) != expected_fields
        or binding.get("schema_version") != "a1-aux-stage-training-binding-v1"
        or binding.get("stage") not in {"WARMUP", "GEOMETRY"}
    ):
        raise SystemExit("A1 AUX stage training binding shape drift")
    authority_path, file_sha, raw_authority = _stable_canonical_regular_file(
        authority_value, where="A1 AUX stage executor authority"
    )
    if (
        str(authority_path) != binding["executor_authority_path"]
        or file_sha != authority_sha
        or file_sha != binding["executor_authority_file_sha256"]
    ):
        raise SystemExit("A1 AUX stage executor authority path/file drift")
    try:
        stable_authority = json.loads(raw_authority.decode("utf-8"))
        from tools import a1_aux_pair_coordinator as coordinator

        published = coordinator.verify_published_executor_authority(authority_path)
    except (UnicodeError, json.JSONDecodeError, ImportError) as error:
        raise SystemExit(f"cannot replay A1 AUX stage authority: {error}") from error
    except coordinator.CoordinatorError as error:
        raise SystemExit(f"A1 AUX stage authority replay refused: {error}") from error
    authority = published.get("authority")
    stage = binding["stage"]
    expected_schema = f"a1-aux-{str(stage).lower()}-executor-authority-v1"
    if (
        authority != stable_authority
        or not isinstance(authority, dict)
        or authority.get("schema_version") != expected_schema
        or authority.get("stage") != stage
        or authority.get("experiment_id") != binding["experiment_id"]
        or authority.get("state_sha256")
        != binding["executor_authority_state_sha256"]
    ):
        raise SystemExit("A1 AUX stage authority projection drift")
    if composite_meta is None or composite_meta.get("schema_version") != "memmap_composite_v2":
        raise SystemExit("A1 AUX stage requires the authenticated production composite")
    science = authority.get("portable_science_identity")
    composite = science.get("composite") if isinstance(science, dict) else None
    if not isinstance(composite, dict):
        raise SystemExit("A1 AUX stage authority lacks typed composite")
    if (
        binding["descriptor_path"] != str(Path(args.data).expanduser().resolve(strict=True))
        or binding["descriptor_sha256"] != composite_meta.get("descriptor_file_sha256")
        or binding["descriptor_sha256"] != composite.get("descriptor_sha256")
        or binding["payload_inventory_sha256"]
        != composite_meta.get("payload_inventory_sha256")
        or binding["payload_inventory_sha256"]
        != composite.get("payload_inventory_sha256")
        or binding["initializer_path"]
        != str(Path(args.init_checkpoint).expanduser().resolve(strict=True))
        or binding["initializer_sha256"] != _sha256_existing_file(args.init_checkpoint)
        or binding["output_report"]
        != str(Path(args.report).expanduser().resolve(strict=False))
        or binding["output_checkpoint"]
        != str(Path(args.checkpoint).expanduser().resolve(strict=False))
        or int(ddp.get("world_size", 0)) != 8
        or int(args.batch_size) != 512
        or int(args.grad_accum_steps) != 1
        or str(args.arch) != "entity_graph"
        or str(args.amp) != "none"
        or not bool(args.training_rng_rank_offset)
        or bool(args.symmetry_augment)
        or not bool(args.mask_hidden_info)
        or not bool(args.aux_subgoal_heads)
        or not bool(args.aux_settlement_pointer_head)
    ):
        raise SystemExit("A1 AUX stage data/model/topology binding drift")
    effective = _effective_a1_learner_training_recipe(args, dict(ddp))
    if stage == "WARMUP":
        warmup = science.get("warmup_recipe")
        pointer = science.get("pointer_upgrade_authority")
        if not isinstance(warmup, dict) or not isinstance(pointer, dict):
            raise SystemExit("A1 AUX WARMUP authority is incomplete")
        exact_cli = {
            "max_steps": warmup["max_steps"],
            "lr": warmup["lr"],
            "lr_warmup_steps": warmup["lr_warmup_steps"],
            "lr_schedule": warmup["lr_schedule"],
            "weight_decay": warmup["weight_decay"],
            "seed": warmup["seed"],
            "sampler_seed": warmup["sampler_seed"],
            "aux_subgoal_loss_weight": warmup["aux_subgoal_loss_weight"],
            **warmup["main_objective_coefficients"],
        }
        if (
            binding["initializer_sha256"]
            != pointer.get("upgraded_initializer_sha256")
            or binding["probe_manifest"] is not None
            or int(args.epochs) != 1
            or str(args.optimizer) != "adam"
            or bool(args.resume_optimizer)
            or bool(args.fused_optimizer)
            or float(args.max_grad_norm) != float(warmup["max_grad_norm"])
            or _parse_prefixes(args.require_only_trainable_prefixes)
            != tuple(warmup["trainable_prefixes"])
            or any(effective.get(key) != value for key, value in exact_cli.items())
        ):
            raise SystemExit("A1 AUX WARMUP recipe/initializer drift")
    else:
        rule = science.get("selector_rule")
        warmup_terminal = authority.get("warmup_terminal")
        expected_recipe = copy.deepcopy(science.get("effective_recipe"))
        if not isinstance(rule, dict) or not isinstance(warmup_terminal, dict) or not isinstance(expected_recipe, dict):
            raise SystemExit("A1 AUX GEOMETRY authority is incomplete")
        expected_recipe["aux_subgoal_loss_weight"] = 1.0
        if (
            binding["initializer_sha256"]
            != warmup_terminal.get("result", {}).get("warmed_checkpoint_sha256")
            or not isinstance(binding["probe_manifest"], dict)
            or any(effective.get(key) != value for key, value in expected_recipe.items())
        ):
            raise SystemExit("A1 AUX GEOMETRY recipe/initializer drift")
    result = copy.deepcopy(binding)
    result["authority"] = copy.deepcopy(authority)
    result["published_executor_authority"] = copy.deepcopy(published)
    return result


def _training_data_fingerprint(path: str, data_format: str) -> str:
    """Return a durable corpus identity when the format exposes a manifest.

    A memmap metadata file describes the payload layout but, by itself, does
    not identify the flat-file bytes.  New corpora bind the metadata digest and
    the content-addressed payload inventory into one training fingerprint.
    Legacy non-A1 corpora without an inventory retain their historical metadata
    fingerprint for compatibility.
    """

    root = Path(path)
    if str(data_format) == "memmap" and root.is_file():
        try:
            descriptor = json.loads(root.read_text(encoding="utf-8"))
        except (OSError, UnicodeError, json.JSONDecodeError):
            return _sha256_existing_file(root)
        if (
            isinstance(descriptor, dict)
            and descriptor.get("schema_version") in {
                "memmap_composite_v1", "memmap_composite_v2"
            }
        ):
            return _canonical_json_sha256(descriptor)
    candidates = (
        (root / "corpus_meta.json", root / "manifest.json")
        if str(data_format) == "memmap"
        else (root / "manifest.json", root / "corpus_meta.json")
    )
    for candidate in candidates:
        digest = _sha256_existing_file(candidate)
        if not digest:
            continue
        if str(data_format) == "memmap" and candidate.name == "corpus_meta.json":
            try:
                meta = json.loads(candidate.read_text(encoding="utf-8"))
            except (OSError, UnicodeError, json.JSONDecodeError):
                return digest
            inventory_sha = (
                meta.get("payload_inventory_sha256")
                if isinstance(meta, dict)
                else None
            )
            if _is_sha256(inventory_sha):
                return _canonical_json_sha256(
                    {
                        "corpus_meta_file_sha256": digest,
                        "payload_inventory_sha256": inventory_sha,
                    }
                )
        return digest
    return ""


_FLYWHEEL_FRESH_CATEGORY_IDS = (
    "current_producer",
    "recent_history",
    "hard_negative",
)


def _validate_flywheel_category_semantics(
    raw: object, *, where: str
) -> dict[str, object]:
    """Validate scheduler-lane meaning without renaming the lanes.

    The recovery contract deliberately keeps the historical scheduler key
    ``recent_history`` even when the checkpoint is only an unproven safety
    reference.  Every downstream artifact must therefore copy this object
    byte-for-byte; reducing it to a locally invented role map would permit the
    exact lineage laundering this field exists to prevent.
    """

    if not isinstance(raw, dict) or set(raw) != set(_FLYWHEEL_FRESH_CATEGORY_IDS):
        raise SystemExit(f"{where} category semantics fields drift")
    result = {key: dict(raw[key]) for key in _FLYWHEEL_FRESH_CATEGORY_IDS}
    fixed = {
        "current_producer": ("current_producer", "self_play"),
        "hard_negative": ("hard_negative", "sealed_hard_negative_selection"),
    }
    for category, value in result.items():
        if not isinstance(raw[category], dict):
            raise SystemExit(f"{where} category semantic {category} is malformed")
        checkpoint = value.get("checkpoint")
        if (
            not isinstance(checkpoint, dict)
            or set(checkpoint) != {"id", "path", "sha256", "version"}
            or not isinstance(checkpoint.get("id"), str)
            or not isinstance(checkpoint.get("path"), str)
            or not Path(str(checkpoint["path"])).is_absolute()
            or not _is_sha256(checkpoint.get("sha256"))
            or isinstance(checkpoint.get("version"), bool)
            or not isinstance(checkpoint.get("version"), int)
            or value.get("scheduler_category") != category
        ):
            raise SystemExit(f"{where} category semantic {category} checkpoint drift")
        if category in fixed:
            semantic, relation = fixed[category]
            if (
                set(value) != {"scheduler_category", "semantic", "relation", "checkpoint"}
                or value.get("semantic") != semantic
                or value.get("relation") != relation
            ):
                raise SystemExit(f"{where} category semantic {category} relation drift")
    recent = result["recent_history"]
    recovery_fields = {
        "scheduler_category",
        "semantic",
        "relation",
        "causal_parent_proven",
        "promotion_proof_recreated",
        "checkpoint",
        "recovery_lineage_id",
    }
    promoted_fields = {
        "scheduler_category",
        "semantic",
        "relation",
        "causal_parent_proven",
        "checkpoint",
    }
    is_recovery = set(recent) == recovery_fields
    is_promoted_history = set(recent) == promoted_fields
    if is_recovery:
        valid_recent = (
            recent.get("semantic") == "recovery_reference"
            and recent.get("relation") == "safety_reference_unproven_predecessor"
            and recent.get("causal_parent_proven") is False
            and recent.get("promotion_proof_recreated") is False
            and isinstance(recent.get("recovery_lineage_id"), str)
            and bool(recent.get("recovery_lineage_id"))
        )
    else:
        valid_recent = (
            is_promoted_history
            and recent.get("semantic") == "recent_history"
            and recent.get("relation") == "immediate_displaced_incumbent"
            and recent.get("causal_parent_proven") is True
        )
    if not valid_recent:
        raise SystemExit(f"{where} recent-history semantic relation drift")
    return result


def _require_exact_flywheel_category_semantics(
    *,
    authority: Mapping[str, object],
    contract: Mapping[str, object],
    selected: Mapping[str, object],
    audit: Mapping[str, object],
) -> dict[str, object] | None:
    """Join all semantic surfaces, preserving absence for old contracts."""

    selected_semantics = selected.get("category_semantics")
    selected_records = selected.get("records")
    if selected_semantics is None and isinstance(selected_records, list):
        # The sealed post-wave selector binds the semantic object on every game
        # record instead of duplicating it at the top level.  Reconstruct the
        # redundant surface only when the record schema actually carries it.
        # Older sealed manifests carry no category-semantic field at all and
        # must preserve that historical absence.  A partial population is
        # ambiguous and remains fail-closed.
        record_semantics = [
            record.get("category_semantic") if isinstance(record, dict) else None
            for record in selected_records
        ]
        if any(value is not None for value in record_semantics):
            if any(value is None for value in record_semantics):
                raise SystemExit(
                    "selected-game category semantics are only partially populated"
                )
            derived: dict[str, object] = {}
            for index, (record, semantic) in enumerate(
                zip(selected_records, record_semantics, strict=True)
            ):
                category = (
                    record.get("category") if isinstance(record, dict) else None
                )
                if category not in _FLYWHEEL_FRESH_CATEGORY_IDS or not isinstance(
                    semantic, dict
                ):
                    raise SystemExit(
                        f"selected-game record {index} category semantic was stripped or swapped"
                    )
                previous = derived.setdefault(str(category), semantic)
                if previous != semantic:
                    raise SystemExit(
                        f"selected-game record {index} category semantic was stripped or swapped"
                    )
            selected_semantics = derived

    surfaces = {
        "source authority": authority.get("category_semantics"),
        "current contract": contract.get("category_semantics"),
        "selected-game manifest": selected_semantics,
        "post-wave audit": audit.get("category_semantics"),
    }
    if all(value is None for value in surfaces.values()):
        return None
    if any(value is None for value in surfaces.values()):
        raise SystemExit("flywheel category semantics were stripped from one authority surface")
    canonical: dict[str, object] | None = None
    for where, value in surfaces.items():
        checked = _validate_flywheel_category_semantics(value, where=where)
        if canonical is None:
            canonical = checked
        elif checked != canonical:
            raise SystemExit("flywheel category semantics differ across authority surfaces")
    assert canonical is not None
    if not isinstance(selected_records, list) or not selected_records:
        raise SystemExit("selected-game manifest has no semantic record evidence")
    for index, record in enumerate(selected_records):
        category = record.get("category") if isinstance(record, dict) else None
        if (
            category not in canonical
            or record.get("category_semantic") != canonical[category]
        ):
            raise SystemExit(
                f"selected-game record {index} category semantic was stripped or swapped"
            )
    source_provenance = audit.get("source_provenance")
    if not isinstance(source_provenance, dict):
        raise SystemExit("post-wave audit has no category semantic provenance")
    for category, semantic in canonical.items():
        record = source_provenance.get(category)
        if not isinstance(record, dict) or record.get("category_semantic") != semantic:
            raise SystemExit(
                f"post-wave audit category semantic was stripped or swapped: {category}"
            )
    return canonical


def _validate_flywheel_source_authority(
    path: Path,
    *,
    authenticated_payload: Mapping[str, object] | None = None,
) -> dict[str, object]:
    """Validate the portable pre-descriptor wave authority.

    Large raw shards are authenticated while the composite is built and remain
    represented by immutable source-id preimages.  Training intentionally does
    not require those original paths: all small semantic evidence needed to
    interpret the preimages is copied into the composite authority bundle.
    """

    if authenticated_payload is None:
        try:
            _, _, raw_payload = _stable_canonical_regular_file(
                path,
                where="flywheel source authority",
            )
            payload = json.loads(raw_payload.decode("utf-8"))
        except (UnicodeError, json.JSONDecodeError) as error:
            raise SystemExit(
                f"cannot load flywheel source authority {path}: {error}"
            ) from error
    else:
        payload = dict(authenticated_payload)
    expected = {
        "schema_version",
        "canonical_composite_root",
        "current_contract",
        "selected_game_manifest",
        "post_wave_audit",
        "fresh_source_bindings",
        "fresh_source_bindings_sha256",
        "fresh_generation_manifests",
        "fresh_generation_manifests_sha256",
        "authority_sha256",
    }
    source_authority_schema = (
        payload.get("schema_version") if isinstance(payload, dict) else None
    )
    if source_authority_schema in {
        "a1-post-wave-composite-source-authority-v2",
        "a1-post-wave-composite-source-authority-v3",
    }:
        expected.add("lock_verifier_authorities")
    if source_authority_schema == "a1-post-wave-composite-source-authority-v3":
        expected.add("fresh_target_activation")
    if source_authority_schema == "a1-post-wave-composite-source-authority-v4":
        expected.update({"lock_verifier_authorities", "fresh_target_activation"})
    else:
        expected.add("historical_replay")
    if isinstance(payload, dict) and "category_semantics" in payload:
        expected.add("category_semantics")
    if (
        not isinstance(payload, dict)
        or set(payload) != expected
        or source_authority_schema
        not in {
            "a1-post-wave-composite-source-authority-v1",
            "a1-post-wave-composite-source-authority-v2",
            "a1-post-wave-composite-source-authority-v3",
            "a1-post-wave-composite-source-authority-v4",
        }
    ):
        raise SystemExit("flywheel source authority fields/schema drift")
    try:
        canonical_root = Path(
            str(payload["canonical_composite_root"])
        ).expanduser().resolve(strict=True)
    except OSError as error:
        raise SystemExit(f"flywheel canonical composite root is missing: {error}") from error
    if (
        not canonical_root.is_dir()
        or str(canonical_root) != payload["canonical_composite_root"]
        or path.resolve(strict=True).parent != canonical_root
    ):
        raise SystemExit("flywheel authority is not at its canonical install root")
    unhashed = dict(payload)
    declared = unhashed.pop("authority_sha256", None)
    if declared != _canonical_json_sha256(unhashed):
        raise SystemExit("flywheel source authority digest mismatch")

    def verified_json_ref(
        raw: object, *, fields: set[str], kind: str
    ) -> tuple[Path, dict[str, object]]:
        if not isinstance(raw, dict) or set(raw) != fields:
            raise SystemExit("flywheel source authority artifact fields drift")
        try:
            artifact, artifact_sha256, artifact_bytes = (
                _stable_canonical_regular_file(
                    str(raw["path"]),
                    where="flywheel source authority artifact",
                )
            )
            value = json.loads(artifact_bytes.decode("utf-8"))
        except (UnicodeError, json.JSONDecodeError) as error:
            raise SystemExit(
                f"cannot load flywheel source authority artifact: {error}"
            ) from error
        if (
            not isinstance(value, dict)
            or str(artifact) != raw["path"]
            or artifact_sha256 != raw["file_sha256"]
        ):
            raise SystemExit("flywheel source authority artifact byte binding drift")
        if kind == "contract":
            semantic = dict(value)
            stated = semantic.pop("contract_sha256", None)
            actual = _canonical_json_sha256(semantic)
            referenced = raw.get("contract_sha256")
        elif kind == "audit":
            semantic = {key: item for key, item in value.items() if key != "audit_sha256"}
            stated = value.get("audit_sha256")
            actual = _canonical_json_sha256(semantic)
            referenced = raw.get("audit_sha256")
        else:
            stated = value.get("records_sha256")
            actual = _canonical_json_sha256(value.get("records"))
            referenced = raw.get("records_sha256")
        if stated != actual or referenced != actual:
            raise SystemExit("flywheel source authority semantic digest drift")
        if kind == "selected" and (
            raw.get("manifest_sha256") != _canonical_json_sha256(value)
            or raw.get("selected_game_seed_set_sha256")
            != value.get("selected_game_seed_set_sha256")
        ):
            raise SystemExit("flywheel selected-game authority digest drift")
        if kind == "audit" and raw.get("shard_inventory_sha256") != value.get(
            "shard_inventory_sha256"
        ):
            raise SystemExit("flywheel post-wave shard inventory drift")
        return artifact, value

    contract_fields = {"path", "file_sha256", "contract_sha256"}
    selected_fields = {
        "path",
        "file_sha256",
        "manifest_sha256",
        "records_sha256",
        "selected_game_seed_set_sha256",
    }
    audit_fields = {
        "path",
        "file_sha256",
        "audit_sha256",
        "shard_inventory_sha256",
    }
    current_audit_fields = set(audit_fields)
    if source_authority_schema in {
        "a1-post-wave-composite-source-authority-v3",
        "a1-post-wave-composite-source-authority-v4",
    }:
        current_audit_fields.add("target_activation_sha256")
    _contract_path, current_contract = verified_json_ref(
        payload["current_contract"],
        fields=contract_fields,
        kind="contract",
    )
    _selected_path, selected = verified_json_ref(
        payload["selected_game_manifest"],
        fields=selected_fields,
        kind="selected",
    )
    _audit_path, audit = verified_json_ref(
        payload["post_wave_audit"],
        fields=current_audit_fields,
        kind="audit",
    )
    if (
        selected.get("a1_contract_sha256")
        != current_contract.get("contract_sha256")
        or audit.get("contract_sha256") != current_contract.get("contract_sha256")
        or payload["selected_game_manifest"].get("manifest_sha256")
        != _canonical_json_sha256(selected)
        or payload["selected_game_manifest"].get("selected_game_seed_set_sha256")
        != selected.get("selected_game_seed_set_sha256")
        or payload["post_wave_audit"].get("shard_inventory_sha256")
        != audit.get("shard_inventory_sha256")
    ):
        raise SystemExit("flywheel current wave authority chain drift")

    target_activation_chunks: dict[tuple[str, str], dict[str, object]] = {}
    if source_authority_schema in {
        "a1-post-wave-composite-source-authority-v3",
        "a1-post-wave-composite-source-authority-v4",
    }:
        target_activation = payload.get("fresh_target_activation")
        if (
            not isinstance(target_activation, dict)
            or target_activation != audit.get("target_activation")
            or target_activation.get("schema_version")
            not in {
                "a1-selected-target-activation-v1",
                "a1-selected-target-activation-v3",
            }
            or target_activation.get("passed") is not True
            or payload["post_wave_audit"].get("target_activation_sha256")
            != target_activation.get("target_activation_sha256")
        ):
            raise SystemExit("flywheel fresh target-activation authority drift")
        if target_activation.get("schema_version") == (
            "a1-selected-target-activation-v3"
        ):
            if (
                target_activation.get("policy_target_completeness_rule")
                != (
                    "every policy-active row has finite nonnegative normalized "
                    "target_policy and target_policy_mask == "
                    "(legal_action_ids >= 0)"
                )
                or any(
                    int(category.get("counts", {}).get(
                        "policy_target_complete_rows", -1
                    ))
                    != int(category.get("counts", {}).get(
                        "policy_active_rows", -2
                    ))
                    or int(category.get("counts", {}).get(
                        "policy_target_incomplete_rows", -1
                    ))
                    != 0
                    for category in target_activation.get(
                        "categories", {}
                    ).values()
                    if isinstance(category, dict)
                )
            ):
                raise SystemExit(
                    "flywheel policy-target completeness authority drift"
                )
        unhashed_activation = dict(target_activation)
        declared_activation = unhashed_activation.pop(
            "target_activation_sha256", None
        )
        categories = target_activation.get("categories")
        if (
            declared_activation != _canonical_json_sha256(unhashed_activation)
            or not isinstance(categories, dict)
            or target_activation.get("categories_sha256")
            != _canonical_json_sha256(categories)
        ):
            raise SystemExit("flywheel fresh target-activation digest drift")
        for category, category_report in categories.items():
            if not isinstance(category_report, dict):
                raise SystemExit("flywheel target-activation category is malformed")
            unhashed_category = dict(category_report)
            declared_category = unhashed_category.pop("activation_sha256", None)
            chunks = category_report.get("chunks")
            counts = category_report.get("counts")
            if (
                declared_category != _canonical_json_sha256(unhashed_category)
                or not isinstance(chunks, list)
                or category_report.get("chunks_sha256")
                != _canonical_json_sha256(chunks)
                or not isinstance(counts, dict)
                or category_report.get("counts_sha256")
                != _canonical_json_sha256(counts)
                or category_report.get("full_search_rate_passed") is not True
            ):
                raise SystemExit("flywheel target-activation category digest drift")
            for chunk in chunks:
                if not isinstance(chunk, dict):
                    raise SystemExit("flywheel target-activation chunk is malformed")
                unhashed_chunk = dict(chunk)
                declared_chunk = unhashed_chunk.pop("chunk_sha256", None)
                identity = (
                    str(chunk.get("job_id", "")),
                    str(chunk.get("source_sha256", "")),
                )
                if (
                    identity in target_activation_chunks
                    or str(category) == ""
                    or declared_chunk != _canonical_json_sha256(unhashed_chunk)
                    or chunk.get("counts_sha256")
                    != _canonical_json_sha256(chunk.get("counts"))
                ):
                    raise SystemExit("flywheel target-activation chunk digest drift")
                target_activation_chunks[identity] = chunk

    category_semantics = _require_exact_flywheel_category_semantics(
        authority=payload,
        contract=current_contract,
        selected=selected,
        audit=audit,
    )

    binding_fields = {
        "source_id",
        "contract_sha256",
        "audit_file_sha256",
        "audit_sha256",
        "selected_manifest_file_sha256",
        "selected_records_sha256",
        "job_id",
        "category",
        "source_path",
        "source_sha256",
        "generation_manifest_path",
        "generation_manifest_sha256",
    }

    manifest_fields = {
        "job_id",
        "category",
        "original_path",
        "original_file_sha256",
        "artifact",
    }

    def verified_manifests(
        raw: object, *, digest: object
    ) -> dict[tuple[str, str, str], dict[str, object]]:
        if not isinstance(raw, list) or not raw or digest != _canonical_json_sha256(raw):
            raise SystemExit("flywheel generation-manifest inventory digest drift")
        verified: dict[tuple[str, str, str], dict[str, object]] = {}
        for index, record in enumerate(raw):
            if not isinstance(record, dict) or set(record) != manifest_fields:
                raise SystemExit(
                    f"flywheel staged generation manifest {index} fields drift"
                )
            artifact = record["artifact"]
            if not isinstance(artifact, dict) or set(artifact) != {
                "path",
                "file_sha256",
            }:
                raise SystemExit("flywheel staged generation-manifest ref drift")
            try:
                artifact_path = Path(str(artifact["path"])).expanduser().resolve(
                    strict=True
                )
            except OSError as error:
                raise SystemExit(
                    f"flywheel staged generation manifest is missing: {error}"
                ) from error
            identity = (
                str(record["job_id"]),
                str(record["original_path"]),
                str(record["original_file_sha256"]),
            )
            if (
                identity in verified
                or not artifact_path.is_file()
                or str(artifact_path) != artifact["path"]
                or _sha256_existing_file(artifact_path) != artifact["file_sha256"]
                or artifact["file_sha256"] != record["original_file_sha256"]
            ):
                raise SystemExit("flywheel staged generation-manifest bytes drift")
            verified[identity] = record
        return verified

    def verified_bindings(
        raw: object,
        *,
        digest: object,
        contract_sha256: object,
        selected_ref: dict[str, object],
        audit_ref: dict[str, object],
        audit_payload: dict[str, object],
        manifests: dict[tuple[str, str, str], dict[str, object]],
        category_semantics: dict[str, object] | None,
        require_target_activation: bool = False,
    ) -> tuple[list[dict[str, object]], set[str]]:
        if not isinstance(raw, list) or not raw or digest != _canonical_json_sha256(raw):
            raise SystemExit("flywheel source-binding inventory digest drift")
        seen: set[str] = set()
        normalized: list[dict[str, object]] = []
        raw_audit_records = audit_payload.get("shards")
        if not isinstance(raw_audit_records, list):
            raise SystemExit("flywheel staged audit has no shard inventory")
        audited_sources = {
            (
                str(value.get("job_id", "")),
                str(value.get("category", "")),
                str(value.get("path", "")),
                str(value.get("sha256", "")),
            ): value
            for value in raw_audit_records
            if isinstance(value, dict) and value.get("kind") == "data_shard"
        }
        audited_manifests = {
            (
                str(value.get("job_id", "")),
                str(value.get("category", "")),
                str(value.get("path", "")),
                str(value.get("sha256", "")),
            )
            for value in raw_audit_records
            if isinstance(value, dict)
            and value.get("kind") == "generation_manifest"
        }
        if not audited_sources or not audited_manifests:
            raise SystemExit("flywheel staged audit omits source/manifest evidence")
        for index, record in enumerate(raw):
            category = record.get("category") if isinstance(record, dict) else None
            expected_binding_fields = set(binding_fields)
            if require_target_activation:
                expected_binding_fields.update(
                    {
                        "target_activation_chunk_sha256",
                        "target_activation_counts_sha256",
                    }
                )
            if category_semantics is not None and category in category_semantics:
                expected_binding_fields.add("category_semantic")
            if not isinstance(record, dict) or set(record) != expected_binding_fields:
                raise SystemExit(f"flywheel source binding {index} fields drift")
            preimage = dict(record)
            source_id = preimage.pop("source_id")
            source_identity = (
                str(record["job_id"]),
                str(record["category"]),
                str(record["source_path"]),
                str(record["source_sha256"]),
            )
            if (
                not isinstance(source_id, str)
                or source_id in seen
                or source_id != _canonical_json_sha256(preimage)
                or record.get("contract_sha256") != contract_sha256
                or record.get("selected_manifest_file_sha256")
                != selected_ref.get("file_sha256")
                or record.get("selected_records_sha256")
                != selected_ref.get("records_sha256")
                or record.get("audit_file_sha256") != audit_ref.get("file_sha256")
                or record.get("audit_sha256") != audit_ref.get("audit_sha256")
                or (
                    record.get("category_semantic")
                    != category_semantics.get(str(record.get("category")))
                    if category_semantics is not None
                    else "category_semantic" in record
                )
            ):
                raise SystemExit(f"flywheel source binding {index} identity drift")
            if (
                not Path(str(record["source_path"])).is_absolute()
                or not Path(str(record["generation_manifest_path"])).is_absolute()
                or not _is_sha256(record["source_sha256"])
                or (
                    str(record["job_id"]),
                    str(record["generation_manifest_path"]),
                    str(record["generation_manifest_sha256"]),
                )
                not in manifests
                or source_identity not in audited_sources
                or (
                    str(record["job_id"]),
                    str(record["category"]),
                    str(record["generation_manifest_path"]),
                    str(record["generation_manifest_sha256"]),
                )
                not in audited_manifests
            ):
                raise SystemExit(f"flywheel source binding {index} evidence drift")
            if require_target_activation:
                chunk = target_activation_chunks.get(
                    (str(record["job_id"]), str(record["source_sha256"]))
                )
                audited_activation = audited_sources[source_identity].get(
                    "target_activation"
                )
                if (
                    chunk is None
                    or not isinstance(audited_activation, dict)
                    or record.get("target_activation_chunk_sha256")
                    != chunk.get("chunk_sha256")
                    or record.get("target_activation_counts_sha256")
                    != chunk.get("counts_sha256")
                    or audited_activation.get("chunk_sha256")
                    != chunk.get("chunk_sha256")
                    or audited_activation.get("counts_sha256")
                    != chunk.get("counts_sha256")
                    or audited_activation.get("row_activation_sha256")
                    != chunk.get("row_activation_sha256")
                    or audited_activation.get("counts") != chunk.get("counts")
                ):
                    raise SystemExit(
                        f"flywheel source binding {index} target activation drift"
                    )
            seen.add(source_id)
            normalized.append(record)
        return normalized, seen

    fresh_manifests = verified_manifests(
        payload["fresh_generation_manifests"],
        digest=payload["fresh_generation_manifests_sha256"],
    )
    fresh_bindings, fresh_ids = verified_bindings(
        payload["fresh_source_bindings"],
        digest=payload["fresh_source_bindings_sha256"],
        contract_sha256=current_contract["contract_sha256"],
        selected_ref=payload["selected_game_manifest"],
        audit_ref=payload["post_wave_audit"],
        audit_payload=audit,
        manifests=fresh_manifests,
        category_semantics=category_semantics,
        require_target_activation=(
            source_authority_schema
            in {
                "a1-post-wave-composite-source-authority-v3",
                "a1-post-wave-composite-source-authority-v4",
            }
        ),
    )

    if source_authority_schema == "a1-post-wave-composite-source-authority-v4":
        verifier_authorities = payload.get("lock_verifier_authorities")
        verifier_fields = {
            "schema_version",
            "lock",
            "lock_file_sha256",
            "contract_sha256",
            "frozen_repo",
            "verifier",
            "verifier_sha256",
            "require_all_job_claims",
            "verified_lock_sha256",
            "authority_sha256",
        }
        current_verifier = (
            verifier_authorities.get("current_wave")
            if isinstance(verifier_authorities, dict)
            and set(verifier_authorities) == {"current_wave"}
            else None
        )
        if not isinstance(current_verifier, dict) or set(current_verifier) != verifier_fields:
            raise SystemExit("flywheel lock-verifier authority roles drift")
        verifier_unhashed = dict(current_verifier)
        verifier_declared = verifier_unhashed.pop("authority_sha256", None)
        if (
            current_verifier.get("schema_version")
            != "a1-frozen-lock-verifier-authority-v1"
            or verifier_declared != _canonical_json_sha256(verifier_unhashed)
            or current_verifier.get("require_all_job_claims") is not True
            or current_verifier.get("lock_file_sha256")
            != payload["current_contract"].get("file_sha256")
            or current_verifier.get("contract_sha256")
            != payload["current_contract"].get("contract_sha256")
            or current_verifier.get("verified_lock_sha256")
            != _canonical_json_sha256(current_contract)
            or not Path(str(current_verifier.get("lock", ""))).is_absolute()
            or not Path(str(current_verifier.get("frozen_repo", ""))).is_absolute()
            or not Path(str(current_verifier.get("verifier", ""))).is_absolute()
            or not _is_sha256(current_verifier.get("verifier_sha256"))
        ):
            raise SystemExit("flywheel lock-verifier authority binding drift")
        return {
            **payload,
            "fresh_source_bindings": fresh_bindings,
            "fresh_source_ids": sorted(fresh_ids),
            "historical_source_bindings": [],
            "historical_source_ids": [],
            "category_semantics": category_semantics,
        }

    historical_authority = payload["historical_replay"]
    historical_fields = {
        "schema_version",
        "source_contract",
        "selected_game_manifest",
        "post_wave_audit",
        "source_bindings",
        "source_bindings_sha256",
        "generation_manifests",
        "generation_manifests_sha256",
        "component_provenance_sha256",
        "component_payload_inventory_sha256",
        "authority_sha256",
    }
    if (
        not isinstance(historical_authority, dict)
        or set(historical_authority) != historical_fields
        or historical_authority.get("schema_version")
        != "a1-historical-replay-authority-v1"
    ):
        raise SystemExit("historical replay authority reference fields drift")
    historical_unhashed = dict(historical_authority)
    historical_declared = historical_unhashed.pop("authority_sha256", None)
    if (
        historical_declared != _canonical_json_sha256(historical_unhashed)
    ):
        raise SystemExit("historical replay authority digest drift")
    _prior_path, prior_contract = verified_json_ref(
        historical_authority.get("source_contract"),
        fields=contract_fields,
        kind="contract",
    )
    _prior_selected_path, prior_selected = verified_json_ref(
        historical_authority.get("selected_game_manifest"),
        fields=selected_fields,
        kind="selected",
    )
    _prior_audit_path, prior_audit = verified_json_ref(
        historical_authority.get("post_wave_audit"),
        fields=audit_fields,
        kind="audit",
    )
    if (
        prior_selected.get("a1_contract_sha256")
        != prior_contract.get("contract_sha256")
        or prior_audit.get("contract_sha256") != prior_contract.get("contract_sha256")
    ):
        raise SystemExit("historical replay prior authority chain drift")
    historical_manifests = verified_manifests(
        historical_authority.get("generation_manifests"),
        digest=historical_authority.get("generation_manifests_sha256"),
    )
    prior_semantic_surfaces = (
        prior_contract.get("category_semantics"),
        prior_selected.get("category_semantics"),
        prior_audit.get("category_semantics"),
    )
    if all(value is None for value in prior_semantic_surfaces):
        prior_category_semantics = None
    elif any(value is None for value in prior_semantic_surfaces):
        raise SystemExit("historical replay category semantics were stripped")
    else:
        checked_prior = [
            _validate_flywheel_category_semantics(value, where="historical replay")
            for value in prior_semantic_surfaces
        ]
        if checked_prior[1:] != checked_prior[:-1]:
            raise SystemExit("historical replay category semantics differ")
        prior_category_semantics = checked_prior[0]
    historical_bindings, historical_ids = verified_bindings(
        historical_authority.get("source_bindings"),
        digest=historical_authority.get("source_bindings_sha256"),
        contract_sha256=prior_contract["contract_sha256"],
        selected_ref=historical_authority["selected_game_manifest"],
        audit_ref=historical_authority["post_wave_audit"],
        audit_payload=prior_audit,
        manifests=historical_manifests,
        category_semantics=prior_category_semantics,
    )
    if source_authority_schema in {
        "a1-post-wave-composite-source-authority-v2",
        "a1-post-wave-composite-source-authority-v3",
    }:
        verifier_authorities = payload.get("lock_verifier_authorities")
        if not isinstance(verifier_authorities, dict) or set(
            verifier_authorities
        ) != {"current_wave", "historical_replay"}:
            raise SystemExit("flywheel lock-verifier authority roles drift")

        verifier_fields = {
            "schema_version",
            "lock",
            "lock_file_sha256",
            "contract_sha256",
            "frozen_repo",
            "verifier",
            "verifier_sha256",
            "require_all_job_claims",
            "verified_lock_sha256",
            "authority_sha256",
        }

        def verified_verifier_authority(
            raw: object,
            *,
            contract_ref: dict[str, object],
            contract_payload: dict[str, object],
            require_all_job_claims: bool,
        ) -> None:
            if (
                not isinstance(raw, dict)
                or set(raw) != verifier_fields
                or raw.get("schema_version")
                != "a1-frozen-lock-verifier-authority-v1"
            ):
                raise SystemExit("flywheel lock-verifier authority fields drift")
            unhashed = dict(raw)
            declared = unhashed.pop("authority_sha256", None)
            if declared != _canonical_json_sha256(unhashed):
                raise SystemExit("flywheel lock-verifier authority digest drift")
            if (
                raw.get("require_all_job_claims") is not require_all_job_claims
                or raw.get("lock_file_sha256") != contract_ref.get("file_sha256")
                or raw.get("contract_sha256")
                != contract_ref.get("contract_sha256")
                or raw.get("verified_lock_sha256")
                != _canonical_json_sha256(contract_payload)
                or not Path(str(raw.get("lock", ""))).is_absolute()
                or not Path(str(raw.get("frozen_repo", ""))).is_absolute()
                or not Path(str(raw.get("verifier", ""))).is_absolute()
                or not _is_sha256(raw.get("verifier_sha256"))
            ):
                raise SystemExit("flywheel lock-verifier authority binding drift")

        verified_verifier_authority(
            verifier_authorities["current_wave"],
            contract_ref=payload["current_contract"],
            contract_payload=current_contract,
            require_all_job_claims=True,
        )
        verified_verifier_authority(
            verifier_authorities["historical_replay"],
            contract_ref=historical_authority["source_contract"],
            contract_payload=prior_contract,
            require_all_job_claims=False,
        )
    return {
        **payload,
        "fresh_source_bindings": fresh_bindings,
        # This enriched authority crosses the single-node DDP rendezvous as
        # JSON.  Keep the deterministic source-id collections JSON-native;
        # returning the verifier's working sets here made rank 0 finish the
        # expensive payload authentication and then fail before the first
        # optimizer step with ``Object of type set is not JSON serializable``.
        "fresh_source_ids": sorted(fresh_ids),
        "historical_source_bindings": historical_bindings,
        "historical_source_ids": sorted(historical_ids),
        "category_semantics": category_semantics,
    }


def _validate_flywheel_component_provenance(
    path: Path,
    *,
    component_id: str,
    corpus_dir: Path,
    corpus_meta: dict[str, object],
    authenticated_payload: Mapping[str, object] | None = None,
    authenticated_corpus_files: Mapping[str, BinaryIO] | None = None,
    source_authority_ref: dict[str, str] | None = None,
    allowed_source_ids: set[str] | None = None,
) -> dict[str, object]:
    """Authenticate the exact shards and producer checkpoints in one replay arm."""

    if authenticated_payload is None:
        try:
            _, _, raw_payload = _stable_canonical_regular_file(
                path,
                where="flywheel component provenance",
            )
            payload = json.loads(raw_payload.decode("utf-8"))
        except (UnicodeError, json.JSONDecodeError) as error:
            raise SystemExit(
                f"cannot load flywheel component provenance {path}: {error}"
            ) from error
    else:
        payload = dict(authenticated_payload)
    expected = {
        "schema_version",
        "component_id",
        "source_category",
        "role",
        "current_checkpoint_version",
        "checkpoint_versions",
        "producer_checkpoints",
        "row_count",
        "shards",
        "shard_inventory_sha256",
        "component_mass",
    }
    schema_version = payload.get("schema_version") if isinstance(payload, dict) else None
    if schema_version == "flywheel-replay-component-v2":
        expected.add("source_authority_manifest")
        if corpus_meta.get("policy_target_identity_sha256") is not None:
            expected.update(
                {
                    "policy_target_identity",
                    "policy_target_identity_sha256",
                }
            )
        if corpus_meta.get("policy_target_completeness") is not None:
            expected.add("policy_target_completeness")
    if not isinstance(payload, dict) or set(payload) != expected:
        raise SystemExit("flywheel component provenance fields differ from schema")
    if "policy_target_identity_sha256" in expected:
        identity = payload.get("policy_target_identity_sha256")
        identity_payload = payload.get("policy_target_identity")
        identity_hash_payload = identity_payload
        if (
            isinstance(identity_payload, dict)
            and identity_payload.get("schema_version")
            == "policy-target-manifest-operator-identity-v1-legacy-partial"
        ):
            # Historical inventories predate the full identity envelope and
            # intentionally fingerprint only their explicit operator projection.
            identity_hash_payload = identity_payload.get("operator")
        if (
            not _is_sha256(identity)
            or identity != corpus_meta.get("policy_target_identity_sha256")
            or not isinstance(identity_payload, dict)
            or identity_payload != corpus_meta.get("policy_target_identity")
            or not isinstance(identity_hash_payload, dict)
            or _canonical_json_sha256(identity_hash_payload) != identity
        ):
            raise SystemExit(
                "flywheel component policy-target identity provenance drift"
            )
    if "policy_target_completeness" in expected:
        completeness = payload.get("policy_target_completeness")
        if (
            not isinstance(completeness, dict)
            or completeness != corpus_meta.get("policy_target_completeness")
            or int(completeness.get("counts", {}).get(
                "policy_target_complete_rows", -1
            ))
            != int(completeness.get("counts", {}).get(
                "policy_active_rows", -2
            ))
            or int(completeness.get("counts", {}).get(
                "policy_target_incomplete_rows", -1
            ))
            != 0
        ):
            raise SystemExit(
                "flywheel component policy-target completeness provenance drift"
            )
    if schema_version not in {
        "flywheel-replay-component-v1",
        "flywheel-replay-component-v2",
    }:
        raise SystemExit("flywheel component provenance schema is unsupported")
    if payload.get("component_id") != component_id:
        raise SystemExit("flywheel component provenance id differs from descriptor")
    role = payload.get("role")
    if role not in {"fresh", "replay"}:
        raise SystemExit("flywheel component provenance role is invalid")
    current_version = payload.get("current_checkpoint_version")
    if isinstance(current_version, bool) or not isinstance(current_version, int):
        raise SystemExit("flywheel current checkpoint version is invalid")
    versions = payload.get("checkpoint_versions")
    if (
        not isinstance(versions, list)
        or not versions
        or any(isinstance(value, bool) or not isinstance(value, int) for value in versions)
        or versions != sorted(set(versions))
    ):
        raise SystemExit("flywheel component checkpoint versions are invalid")
    source_category = payload.get("source_category")
    if source_category not in {
        *FRESH_SOURCE_GAME_RATIOS,
        HISTORICAL_REPLAY_CATEGORY,
    }:
        raise SystemExit("flywheel component source category is invalid")
    if role == "fresh" and (
        versions != [current_version]
        or source_category not in FRESH_SOURCE_GAME_RATIOS
        or schema_version != "flywheel-replay-component-v2"
        or payload.get("source_authority_manifest") != source_authority_ref
    ):
        raise SystemExit("flywheel fresh component must bind the initializer version/source")
    if role == "replay" and source_category != HISTORICAL_REPLAY_CATEGORY:
        raise SystemExit("flywheel replay component source category is invalid")
    if role == "replay" and any(value >= current_version for value in versions):
        raise SystemExit("flywheel replay must come from a strictly older checkpoint generation")
    producers = payload.get("producer_checkpoints")
    if not isinstance(producers, list) or len(producers) != len(versions):
        raise SystemExit("flywheel producer checkpoint inventory is invalid")
    producer_by_version: dict[int, dict[str, object]] = {}
    for record in producers:
        if not isinstance(record, dict) or set(record) != {"version", "path", "sha256"}:
            raise SystemExit("flywheel producer checkpoint record is malformed")
        version = record["version"]
        checkpoint_path = Path(str(record["path"])).expanduser()
        if (
            isinstance(version, bool)
            or not isinstance(version, int)
            or version in producer_by_version
            or version not in versions
            or not checkpoint_path.is_absolute()
            or not _is_sha256(record["sha256"])
        ):
            raise SystemExit("flywheel producer checkpoint record is invalid")
        # Historical checkpoint files may be archived after generation; their
        # immutable digest remains authoritative. If the path still exists,
        # verify it has not drifted.
        if checkpoint_path.exists() and _sha256_existing_file(checkpoint_path) != record["sha256"]:
            raise SystemExit("flywheel producer checkpoint bytes changed")
        producer_by_version[int(version)] = record
    shards = payload.get("shards")
    shard_fields = {
        "path",
        "rows",
        "order",
        "size_bytes",
        "sha256",
        "checkpoint_version",
        "producer_checkpoint_path",
        "producer_checkpoint_sha256",
        "source_id",
        "source_category",
    }
    if not isinstance(shards, list) or not shards:
        raise SystemExit("flywheel component has no authenticated shards")
    canonical_inventory: list[dict[str, object]] = []
    seen_paths: set[str] = set()
    seen_source_ids: set[str] = set()
    rows = 0
    for record in shards:
        if not isinstance(record, dict) or set(record) != shard_fields:
            raise SystemExit("flywheel shard provenance record is malformed")
        shard_path = Path(str(record["path"])).expanduser()
        version = record["checkpoint_version"]
        if (
            not shard_path.is_absolute()
            or str(shard_path) in seen_paths
            or isinstance(record["rows"], bool)
            or not isinstance(record["rows"], int)
            or int(record["rows"]) <= 0
            or isinstance(record["order"], bool)
            or not isinstance(record["order"], int)
            or isinstance(version, bool)
            or not isinstance(version, int)
            or version not in producer_by_version
            or not isinstance(record["source_id"], str)
            or not record["source_id"]
            or isinstance(record["size_bytes"], bool)
            or not isinstance(record["size_bytes"], int)
            or int(record["size_bytes"]) <= 0
            or not _is_sha256(record["sha256"])
            or record["source_category"] not in FRESH_SOURCE_GAME_RATIOS
            or (
                role == "fresh"
                and record["source_category"] != source_category
            )
        ):
            raise SystemExit("flywheel shard provenance record is invalid")
        producer = producer_by_version[int(version)]
        if (
            record["producer_checkpoint_path"] != producer["path"]
            or record["producer_checkpoint_sha256"] != producer["sha256"]
        ):
            raise SystemExit("flywheel shard/checkpoint provenance binding drift")
        # Fresh filtered shards are the learner input and must always be present.
        # Replay raw shards were fully verified by the historical sealer; after
        # transfer only their authenticated preimages and the replay memmap are
        # required.  If an archived raw shard is present, still reject byte drift.
        if role == "fresh":
            try:
                resolved_shard = shard_path.resolve(strict=True)
            except OSError as error:
                raise SystemExit(
                    f"flywheel fresh shard is missing: {record.get('path')}"
                ) from error
            if (
                str(resolved_shard) != record["path"]
                or record["size_bytes"] != resolved_shard.stat().st_size
                or record["sha256"] != _sha256_existing_file(resolved_shard)
            ):
                raise SystemExit("flywheel fresh shard bytes drift")
        elif shard_path.exists() and (
            record["size_bytes"] != shard_path.stat().st_size
            or record["sha256"] != _sha256_existing_file(shard_path)
        ):
            raise SystemExit("flywheel archived replay shard bytes drift")
        seen_paths.add(str(shard_path))
        seen_source_ids.add(str(record["source_id"]))
        rows += int(record["rows"])
        canonical_inventory.append(record)
    if payload.get("shard_inventory_sha256") != _canonical_json_sha256(canonical_inventory):
        raise SystemExit("flywheel shard inventory digest mismatch")
    if (
        payload.get("row_count") != rows
        or int(corpus_meta.get("row_count", -1)) != rows
    ):
        raise SystemExit("flywheel component row count differs from authenticated shards")
    try:
        actual_mass = measure_memmap_component(
            corpus_dir,
            corpus_meta,
            authenticated_files=authenticated_corpus_files,
        )
    except ValueError as error:
        raise SystemExit(f"cannot measure flywheel component sampler mass: {error}") from error
    if payload.get("component_mass") != actual_mass:
        raise SystemExit("flywheel component game/row/policy-active mass drift")
    if (
        allowed_source_ids is None
        or not seen_source_ids
        or not seen_source_ids.issubset(allowed_source_ids)
    ):
        raise SystemExit("flywheel component shards lack authenticated source preimages")
    return payload


FLYWHEEL_DIAGNOSTIC_DERIVATION_SCHEMA = (
    "flywheel-diagnostic-descriptor-derivation-v1"
)


def _preflight_flywheel_diagnostic_derivative(
    descriptor_path: Path,
    descriptor: dict[str, object],
) -> dict[str, object] | None:
    """Authenticate one narrow diagnostic projection of a production composite.

    The production descriptor remains immutable and retains its strict recipe.
    A diagnostic learner may change only one of the explicitly enumerated
    treatments below: the proven policy-game weighting treatment, the explicit
    forced-action-type value weighting treatment, the exact A/B/C/D LR-dose
    campaign profile, and/or removal of historical replay from an objective.
    Components, sampling, source authority, and every other byte are inherited
    unchanged from the fully replayed production descriptor.
    """

    authority = descriptor.get("diagnostic_derivation_authority")
    if authority is None:
        return None
    expected_authority_keys = {
        "schema_version",
        "base_descriptor",
        "semantic_delta",
        "semantic_delta_sha256",
        "diagnostic_only",
        "promotion_eligible",
    }
    base_ref = authority.get("base_descriptor") if isinstance(authority, dict) else None
    semantic_delta = authority.get("semantic_delta") if isinstance(authority, dict) else None
    if (
        not isinstance(authority, dict)
        or set(authority) != expected_authority_keys
        or authority.get("schema_version")
        != FLYWHEEL_DIAGNOSTIC_DERIVATION_SCHEMA
        or authority.get("diagnostic_only") is not True
        or authority.get("promotion_eligible") is not False
        or not isinstance(base_ref, dict)
        or set(base_ref) != {"path", "file_sha256", "fingerprint"}
        or not isinstance(semantic_delta, dict)
        or not semantic_delta
        or set(semantic_delta)
        - {
            "learner_recipe_overrides",
            "policy_distillation_component_ids",
            "value_training_component_ids",
        }
        or authority.get("semantic_delta_sha256")
        != _canonical_json_sha256(semantic_delta)
    ):
        raise SystemExit("flywheel diagnostic derivation authority is malformed")
    try:
        base_path = Path(str(base_ref["path"])).expanduser().resolve(strict=True)
    except OSError as error:
        raise SystemExit(
            f"cannot resolve flywheel diagnostic base descriptor: {error}"
        ) from error
    if (
        str(base_path) != base_ref["path"]
        or base_path == descriptor_path
        or _sha256_existing_file(base_path) != base_ref["file_sha256"]
    ):
        raise SystemExit("flywheel diagnostic base descriptor byte binding drift")
    try:
        base_descriptor = json.loads(base_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(
            f"cannot read flywheel diagnostic base descriptor: {error}"
        ) from error
    if (
        not isinstance(base_descriptor, dict)
        or _canonical_json_sha256(base_descriptor) != base_ref["fingerprint"]
        or base_descriptor.get("diagnostic_derivation_authority") is not None
    ):
        raise SystemExit("flywheel diagnostic base descriptor semantic binding drift")
    # Recursively replay the ordinary production contract. The absence of a
    # derivation authority on the base makes this recursion one level deep.
    base_meta = _preflight_memmap_composite_descriptor(base_path)
    if (
        base_meta.get("diagnostic_only") is not False
        or base_meta.get("promotion_eligible") is not True
        or base_meta.get("descriptor_file_sha256") != base_ref["file_sha256"]
        or base_meta.get("descriptor_fingerprint") != base_ref["fingerprint"]
    ):
        raise SystemExit("flywheel diagnostic base is not production eligible")

    expected = copy.deepcopy(base_descriptor)
    expected["diagnostic_only"] = True
    expected["promotion_eligible"] = False
    if "learner_recipe_overrides" in semantic_delta:
        delta = semantic_delta["learner_recipe_overrides"]
        if (
            not isinstance(delta, dict)
            or set(delta) != {"base", "effective"}
            or delta.get("base") != base_descriptor.get("learner_recipe_overrides")
            or not isinstance(delta.get("effective"), dict)
        ):
            raise SystemExit("flywheel diagnostic learner-override delta is malformed")
        base_overrides = delta["base"]
        effective_overrides = delta["effective"]
        changed = {
            key
            for key in set(base_overrides) | set(effective_overrides)
            if base_overrides.get(key) != effective_overrides.get(key)
        }
        typed_key = "forced_row_value_action_type_weights"
        public_card_key = "public_card_lr_mult"
        surprise_key = "per_game_policy_surprise_weighting"
        lr_dose_keys = {
            "epochs",
            "max_steps",
            "lr",
            "lr_warmup_steps",
            "lr_schedule",
        }
        optional_lr_dose_keys = {
            "policy_aux_active_batch_size",
            "policy_aux_loss_weight",
        }
        science_profile_keys = {public_card_key, surprise_key}
        allowed_additions = {
            typed_key,
            *science_profile_keys,
            *lr_dose_keys,
            *optional_lr_dose_keys,
        }
        science_profile_present = bool(changed & science_profile_keys)
        science_profile_valid = True
        if science_profile_present:
            # Existing authenticated corpora may use the canonical card-only
            # learner treatment, but not the meaningful-history architecture
            # whose event payloads are absent from these shards.  Bind the
            # three coupled learner semantics as one exact profile.
            science_profile_valid = (
                effective_overrides.get(public_card_key) == 4.0
                and effective_overrides.get(surprise_key) is True
                and effective_overrides.get(typed_key)
                == "END_TURN=0.1,ROLL=0.25"
            )
        lr_dose_present = bool(changed & (lr_dose_keys | optional_lr_dose_keys))
        lr_dose_valid = True
        if lr_dose_present:
            # A campaign descriptor carries the complete optimizer profile so
            # LR/warmup/dose can never be authenticated piecemeal.  Values are
            # the preregistered four short arms plus the selected 256-step
            # replay; this is not a generic recipe-override escape hatch.
            lr_dose_valid = (
                lr_dose_keys.issubset(effective_overrides)
                and not (lr_dose_keys | optional_lr_dose_keys).intersection(
                    base_overrides
                )
                and type(effective_overrides.get("epochs")) is int
                and effective_overrides.get("epochs") == 1
                and type(effective_overrides.get("max_steps")) is int
                and effective_overrides.get("max_steps") in {128, 256}
                and type(effective_overrides.get("lr")) is float
                and effective_overrides.get("lr") in {3e-5, 6e-5, 1.2e-4}
                and type(effective_overrides.get("lr_warmup_steps")) is int
                and effective_overrides.get("lr_warmup_steps") in {16, 100}
                and effective_overrides.get("lr_schedule") == "flat"
                and (
                    effective_overrides.get("lr") == 3e-5
                    or effective_overrides.get("lr_warmup_steps") == 16
                )
            )
            if "policy_aux_active_batch_size" in effective_overrides:
                policy_aux = effective_overrides["policy_aux_active_batch_size"]
                lr_dose_valid = (
                    lr_dose_valid
                    and type(policy_aux) is int
                    and 1 <= policy_aux <= 512
                )
                policy_aux_loss_weight = effective_overrides.get(
                    "policy_aux_loss_weight"
                )
                lr_dose_valid = (
                    lr_dose_valid
                    and type(policy_aux_loss_weight) is float
                    and 0.0 < policy_aux_loss_weight <= 4.0
                )
        if (
            set(base_overrides) - set(effective_overrides)
            or set(effective_overrides) - set(base_overrides) - allowed_additions
            or not changed
            or changed
            - {
                "per_game_policy_weight",
                typed_key,
                *science_profile_keys,
                *lr_dose_keys,
                *optional_lr_dose_keys,
            }
            or (
                "per_game_policy_weight" in changed
                and (
                    base_overrides.get("per_game_policy_weight") is not True
                    or effective_overrides.get("per_game_policy_weight") is not False
                )
            )
            or (
                typed_key in changed
                and (
                    typed_key in base_overrides
                    or not isinstance(effective_overrides.get(typed_key), str)
                    or not _parse_forced_row_value_action_type_weights(
                        effective_overrides.get(typed_key, "")
                    )
                    or effective_overrides.get(typed_key)
                    != _canonical_forced_row_value_action_type_weights(
                        _parse_forced_row_value_action_type_weights(
                            effective_overrides.get(typed_key, "")
                        )
                    )
                )
            )
            or not science_profile_valid
            or not lr_dose_valid
        ):
            raise SystemExit(
                "flywheel diagnostic recipe may only disable per-game policy "
                "weighting, add a canonical forced-action-type value map, "
                "use the exact existing-corpus card/surprise learner profile, "
                "and/or use the exact authenticated A/B/C/D LR-dose profile"
            )
        expected["learner_recipe_overrides"] = copy.deepcopy(effective_overrides)
        expected["learner_recipe_overrides_sha256"] = _canonical_json_sha256(
            effective_overrides
        )
    expected_base_component_ids = [
        "current_producer",
        "recent_history",
        "hard_negative",
        "historical_replay",
    ]
    expected_fresh_component_ids = expected_base_component_ids[:3]
    if "policy_distillation_component_ids" in semantic_delta:
        delta = semantic_delta["policy_distillation_component_ids"]
        if delta != {
            "base": expected_base_component_ids,
            "effective": expected_fresh_component_ids,
        }:
            raise SystemExit("flywheel diagnostic policy scope delta is unsupported")
        expected["policy_distillation_component_ids"] = (
            expected_fresh_component_ids
        )
    if "value_training_component_ids" in semantic_delta:
        delta = semantic_delta["value_training_component_ids"]
        if delta != {
            "base": expected_base_component_ids,
            "effective": expected_fresh_component_ids,
        }:
            raise SystemExit("flywheel diagnostic value scope delta is unsupported")
        expected["value_training_component_ids"] = expected_fresh_component_ids
    expected["diagnostic_derivation_authority"] = copy.deepcopy(authority)
    if descriptor != expected:
        raise SystemExit(
            "flywheel diagnostic descriptor differs beyond its authenticated delta"
        )

    result = copy.deepcopy(base_meta)
    result.update(
        {
            "diagnostic_only": True,
            "promotion_eligible": False,
            "descriptor_path": str(descriptor_path),
            "descriptor_file_sha256": _sha256_existing_file(descriptor_path),
            "descriptor_fingerprint": _canonical_json_sha256(descriptor),
            "learner_recipe_overrides": copy.deepcopy(
                expected["learner_recipe_overrides"]
            ),
            "learner_recipe_overrides_sha256": expected[
                "learner_recipe_overrides_sha256"
            ],
            "policy_distillation_component_ids": copy.deepcopy(
                expected["policy_distillation_component_ids"]
            ),
            "policy_distillation_scope_explicit": True,
            "value_training_component_ids": copy.deepcopy(
                expected["value_training_component_ids"]
            ),
            "value_training_scope_explicit": True,
            "diagnostic_derivation_authority": copy.deepcopy(authority),
            "flywheel_diagnostic_derivative": True,
        }
    )
    return result


def _preflight_memmap_composite_descriptor(
    path: str | Path,
    *,
    expected_descriptor_file_sha256: str | None = None,
    production_authority_preflight_completed: bool = True,
) -> dict[str, object]:
    """Authenticate an ordered diagnostic-only no-copy descriptor.

    V1 remains the exact historical two-component format. V2 admits two or
    more components and binds a game-uniform sampling ratio for each one, plus
    the components whose recorded priors are allowed to enter the behavioral
    anchor. This prevents a current but regressed producer from silently
    becoming the policy that a recovery run preserves.
    """
    descriptor_path, descriptor_file_sha256, raw_descriptor = (
        _stable_canonical_regular_file(
            path,
            where="memmap composite descriptor",
        )
    )
    if (
        expected_descriptor_file_sha256 is not None
        and descriptor_file_sha256 != expected_descriptor_file_sha256
    ):
        raise SystemExit(
            "memmap composite descriptor changed after authority preflight"
        )
    try:
        descriptor = json.loads(raw_descriptor.decode("utf-8"))
    except (UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load memmap composite descriptor {path}: {error}") from error
    if not isinstance(descriptor, dict):
        raise SystemExit("memmap composite descriptor is not an object")
    diagnostic_derivative = _preflight_flywheel_diagnostic_derivative(
        descriptor_path, descriptor
    )
    if diagnostic_derivative is not None:
        return diagnostic_derivative
    schema_version = descriptor.get("schema_version")
    common_fields = {
        "schema_version", "diagnostic_only", "promotion_eligible", "components",
        "learner_recipe_overrides", "learner_recipe_overrides_sha256",
    }
    is_flywheel_production = (
        schema_version == "memmap_composite_v2"
        and descriptor.get("diagnostic_only") is False
        and descriptor.get("promotion_eligible") is True
    )
    if is_flywheel_production and not production_authority_preflight_completed:
        raise SystemExit(
            "promotion composite appeared after the authority front-door preflight"
        )
    if schema_version == "memmap_composite_v1":
        fields_valid = set(descriptor) == common_fields
    else:
        required_v2_fields = common_fields | {"policy_kl_anchor_component_ids"}
        optional_v2_fields = {
            "category_semantics",
            "policy_distillation_component_ids",
            "policy_aux_phase_sampling_weights",
            "stored_policy_component_temperatures",
            "entity_feature_adapter_component_versions",
            "value_training_component_ids",
            "aux_subgoal_component_ids",
            "flywheel_replay_contract",
            "source_authority_manifest",
            "source_authority_manifest_sha256",
            "source_authority_sha256",
        }
        # Optional for backward compatibility: absence preserves the historical
        # all-components objective scopes. Presence is authenticated by the
        # descriptor fingerprint and can make replay anchor-only rather than
        # treating an old-policy Monte-Carlo outcome as an f7 value label.
        fields_valid = (
            required_v2_fields.issubset(descriptor)
            and set(descriptor).issubset(required_v2_fields | optional_v2_fields)
        )
    if schema_version not in {"memmap_composite_v1", "memmap_composite_v2"} or not fields_valid:
        raise SystemExit("memmap composite descriptor fields differ from its schema")
    if schema_version == "memmap_composite_v1" and (
        descriptor.get("diagnostic_only") is not True
        or descriptor.get("promotion_eligible") is not False
    ):
        raise SystemExit(
            "memmap composite v1 is diagnostic-only and must declare "
            "diagnostic_only=true, promotion_eligible=false"
        )
    if schema_version == "memmap_composite_v2" and not (
        (
            descriptor.get("diagnostic_only") is True
            and descriptor.get("promotion_eligible") is False
        )
        or is_flywheel_production
    ):
        raise SystemExit(
            "memmap composite v2 must be diagnostic-only or carry the exact "
            "promotion-eligible flywheel replay contract"
        )
    if is_flywheel_production and "flywheel_replay_contract" not in descriptor:
        raise SystemExit("promotion-eligible composite lacks flywheel replay contract")
    if not is_flywheel_production and "flywheel_replay_contract" in descriptor:
        raise SystemExit("diagnostic composite may not claim flywheel replay provenance")
    source_authority: dict[str, object] | None = None
    source_authority_ref: dict[str, str] | None = None
    authority_fields = {
        "source_authority_manifest",
        "source_authority_manifest_sha256",
        "source_authority_sha256",
    }
    if is_flywheel_production:
        if not authority_fields.issubset(descriptor):
            raise SystemExit("promotion-eligible composite lacks source authority")
        try:
            source_authority_path = Path(
                str(descriptor["source_authority_manifest"])
            ).expanduser().resolve(strict=True)
        except OSError as error:
            raise SystemExit(f"cannot resolve flywheel source authority: {error}") from error
        (
            source_authority_path,
            source_authority_file_sha256,
            source_authority_bytes,
        ) = _stable_canonical_regular_file(
            source_authority_path,
            where="flywheel source authority",
        )
        if (
            str(source_authority_path) != descriptor["source_authority_manifest"]
            or source_authority_file_sha256
            != descriptor["source_authority_manifest_sha256"]
        ):
            raise SystemExit("flywheel source-authority byte binding drift")
        try:
            source_authority_payload = json.loads(
                source_authority_bytes.decode("utf-8")
            )
        except (UnicodeError, json.JSONDecodeError) as error:
            raise SystemExit(
                f"cannot load flywheel source authority "
                f"{source_authority_path}: {error}"
            ) from error
        if not isinstance(source_authority_payload, dict):
            raise SystemExit("flywheel source authority is not an object")
        source_authority = _validate_flywheel_source_authority(
            source_authority_path,
            authenticated_payload=source_authority_payload,
        )
        if source_authority.get("authority_sha256") != descriptor[
            "source_authority_sha256"
        ]:
            raise SystemExit("flywheel source-authority semantic binding drift")
        source_authority_ref = {
            "path": str(source_authority_path),
            "file_sha256": str(descriptor["source_authority_manifest_sha256"]),
            "authority_sha256": str(descriptor["source_authority_sha256"]),
        }
        descriptor_semantics = descriptor.get("category_semantics")
        authority_semantics = source_authority.get("category_semantics")
        if (descriptor_semantics is None) != (authority_semantics is None):
            raise SystemExit(
                "flywheel category semantics were stripped from descriptor or authority"
            )
        if descriptor_semantics is not None:
            checked_descriptor_semantics = _validate_flywheel_category_semantics(
                descriptor_semantics, where="memmap composite descriptor"
            )
            if checked_descriptor_semantics != authority_semantics:
                raise SystemExit(
                    "flywheel descriptor category semantics differ from source authority"
                )
    elif authority_fields.intersection(descriptor):
        raise SystemExit("diagnostic composite may not claim source authority")
    elif "category_semantics" in descriptor:
        raise SystemExit(
            "diagnostic composite may not claim unauthenticated category semantics"
        )
    raw_components = descriptor.get("components")
    if not isinstance(raw_components, list) or (
        len(raw_components) != 2
        if schema_version == "memmap_composite_v1"
        else len(raw_components) < 2
    ):
        requirement = "exactly two" if schema_version == "memmap_composite_v1" else "at least two"
        raise SystemExit(f"{schema_version} requires {requirement} ordered components")
    overrides = descriptor.get("learner_recipe_overrides")
    required_override_fields = {
        "per_game_policy_weight", "per_game_policy_weight_mode",
    }
    allowed_override_fields = {
        *required_override_fields,
        "forced_action_weight", "forced_row_value_weight",
        "forced_row_value_action_type_weights",
        "hlgauss_scalar_aux_loss_weight", "loser_sample_weight",
        "lr", "per_game_value_weight", "per_game_value_weight_mode",
        "value_player_outcome_balance_mode",
        "policy_loss_weight",
        "policy_kl_anchor_direction", "policy_kl_anchor_weight",
        "policy_kl_target", "policy_kl_dual_lr", "policy_kl_max_weight",
        "policy_target_blend_semantics", "q_loss_weight", "soft_target_source",
        "soft_target_temperature", "soft_target_weight",
        "scalar_value_objective", "scalar_value_loss_readout",
        "scalar_value_loss_scale",
        "truncated_vp_margin_value_weight",
        "value_target_lambda",
        "value_categorical_bins", "value_categorical_loss_weight",
        "value_head_type", "value_hlgauss_sigma_ratio", "value_loss_weight",
    }
    if (
        not isinstance(overrides, dict)
        or not required_override_fields.issubset(overrides)
        or not set(overrides).issubset(allowed_override_fields)
    ):
        raise SystemExit(
            "memmap composite learner_recipe_overrides must bind per-game policy "
            "weighting and may contain only supported diagnostic recipe fields"
        )
    if not isinstance(overrides["per_game_policy_weight"], bool) or overrides[
        "per_game_policy_weight_mode"
    ] not in {"equal", "sqrt"}:
        raise SystemExit("memmap composite per-game policy recipe override is invalid")
    if overrides.get("value_player_outcome_balance_mode", "none") not in {
        "none",
        "sampler_balanced_v1",
    }:
        raise SystemExit(
            "memmap composite value player/outcome balance override is invalid"
        )
    typed_forced_spec = overrides.get("forced_row_value_action_type_weights")
    if typed_forced_spec is not None:
        if not isinstance(typed_forced_spec, str):
            raise SystemExit(
                "memmap composite forced action-type value map must be a string"
            )
        parsed_typed_forced = _parse_forced_row_value_action_type_weights(
            typed_forced_spec
        )
        if (
            not parsed_typed_forced
            or typed_forced_spec
            != _canonical_forced_row_value_action_type_weights(parsed_typed_forced)
        ):
            raise SystemExit(
                "memmap composite forced action-type value map must be nonempty "
                "and canonical"
            )
    if descriptor.get("learner_recipe_overrides_sha256") != _canonical_json_sha256(overrides):
        raise SystemExit("memmap composite learner recipe override digest mismatch")
    components: list[dict[str, object]] = []
    inventory_bindings: list[dict[str, object]] = []
    seen_dirs: set[str] = set()
    expected_v1 = {
        "corpus_dir", "corpus_meta_sha256", "payload_inventory_sha256",
        "validation_manifest", "validation_manifest_sha256",
    }
    expected = (
        expected_v1
        if schema_version == "memmap_composite_v1"
        else {
            "corpus_dir",
            "corpus_meta_sha256",
            "payload_inventory_sha256",
            "component_id",
            "game_sampling_ratio",
            *(
                {"provenance_manifest", "provenance_manifest_sha256"}
                if is_flywheel_production
                else {"validation_manifest", "validation_manifest_sha256"}
            ),
            *(
                {"source_category", "component_mass"}
                if is_flywheel_production
                else set()
            ),
            *(
                {
                    "source_authority_manifest",
                    "source_authority_manifest_sha256",
                }
                if is_flywheel_production
                else set()
            ),
        }
    )
    component_ids: list[str] = []
    component_ratios: list[float] = []
    for index, raw in enumerate(raw_components):
        if not isinstance(raw, dict) or set(raw) != expected:
            raise SystemExit(f"memmap composite component {index} fields differ from schema")
        if schema_version == "memmap_composite_v2":
            component_id = raw["component_id"]
            ratio = raw["game_sampling_ratio"]
            if (
                not isinstance(component_id, str)
                or re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._-]{0,79}", component_id) is None
                or component_id in component_ids
            ):
                raise SystemExit(f"memmap composite component {index} has invalid/duplicate id")
            if isinstance(ratio, bool) or not isinstance(ratio, (int, float)) or not math.isfinite(
                float(ratio)
            ) or float(ratio) <= 0.0:
                raise SystemExit(f"memmap composite component {index} has invalid sampling ratio")
            component_ids.append(component_id)
            component_ratios.append(float(ratio))
        try:
            corpus_dir = Path(str(raw["corpus_dir"])).expanduser().resolve(strict=True)
            evidence_path = Path(
                str(
                    raw[
                        "provenance_manifest"
                        if is_flywheel_production
                        else "validation_manifest"
                    ]
                )
            ).expanduser().resolve(strict=True)
        except OSError as error:
            raise SystemExit(f"cannot resolve memmap composite component {index}: {error}") from error
        if not corpus_dir.is_dir() or str(corpus_dir) != str(raw["corpus_dir"]):
            raise SystemExit(f"memmap composite component {index} corpus_dir is not canonical")
        evidence_field = (
            "provenance_manifest" if is_flywheel_production else "validation_manifest"
        )
        if str(evidence_path) != str(raw[evidence_field]):
            raise SystemExit(
                f"memmap composite component {index} {evidence_field} is not canonical"
            )
        if str(corpus_dir) in seen_dirs:
            raise SystemExit("memmap composite component corpus directories must be unique")
        seen_dirs.add(str(corpus_dir))
        meta_path = corpus_dir / "corpus_meta.json"
        _, actual_meta_sha, raw_meta = _stable_canonical_regular_file(
            meta_path,
            where=f"memmap composite component {index} metadata",
        )
        if not _is_sha256(raw["corpus_meta_sha256"]) or raw["corpus_meta_sha256"] != actual_meta_sha:
            raise SystemExit(f"memmap composite component {index} corpus metadata hash mismatch")
        try:
            corpus_meta = json.loads(raw_meta.decode("utf-8"))
        except (UnicodeError, json.JSONDecodeError) as error:
            raise SystemExit(f"cannot load component {index} corpus metadata {meta_path}: {error}") from error
        if not isinstance(corpus_meta, dict):
            raise SystemExit(f"memmap composite component {index} metadata is not an object")
        if is_flywheel_production:
            if corpus_meta.get("game_seed_present") is not True:
                raise SystemExit(
                    f"flywheel composite component {index} lacks game_seed"
                )
            bound_provenance = corpus_meta.get("flywheel_component_provenance")
            is_historical_replay = (
                raw.get("component_id") == HISTORICAL_REPLAY_CATEGORY
            )
            if (
                not is_historical_replay
                and not isinstance(bound_provenance, dict)
            ) or (
                is_historical_replay
                and bound_provenance is not None
                and not isinstance(bound_provenance, dict)
            ):
                raise SystemExit(
                    f"flywheel composite component {index} lacks bound provenance"
                )
        elif not isinstance(
            corpus_meta.get("selected_game_seed_manifest"), dict
        ) or not isinstance(corpus_meta.get("a1_post_wave_audit"), dict):
            raise SystemExit(f"memmap composite component {index} is not an authenticated A1 corpus")
        (
            actual_inventory_sha,
            authenticated_payload_identities,
        ) = _validate_memmap_payload_inventory(
            corpus_dir,
            corpus_meta,
            return_identities=True,
        )
        if not _is_sha256(raw["payload_inventory_sha256"]) or raw[
            "payload_inventory_sha256"
        ] != actual_inventory_sha:
            raise SystemExit(f"memmap composite component {index} payload inventory hash mismatch")
        payload_runtime_binding = _memmap_payload_runtime_binding(
            corpus_dir,
            corpus_meta,
            authenticated_identities=authenticated_payload_identities,
        )
        evidence_sha_field = (
            "provenance_manifest_sha256"
            if is_flywheel_production
            else "validation_manifest_sha256"
        )
        _, actual_evidence_sha, raw_evidence = _stable_canonical_regular_file(
            evidence_path,
            where=f"memmap composite component {index} {evidence_field}",
        )
        if not _is_sha256(raw[evidence_sha_field]) or raw[
            evidence_sha_field
        ] != actual_evidence_sha:
            raise SystemExit(
                f"memmap composite component {index} "
                f"{evidence_field.replace('_', ' ')} hash mismatch"
            )
        if is_flywheel_production:
            try:
                evidence_payload = json.loads(raw_evidence.decode("utf-8"))
            except (UnicodeError, json.JSONDecodeError) as error:
                raise SystemExit(
                    f"cannot load flywheel component provenance "
                    f"{evidence_path}: {error}"
                ) from error
            if not isinstance(evidence_payload, dict):
                raise SystemExit(
                    "flywheel component provenance is not an object"
                )
            if (
                raw["source_authority_manifest"]
                != descriptor["source_authority_manifest"]
                or raw["source_authority_manifest_sha256"]
                != descriptor["source_authority_manifest_sha256"]
            ):
                raise SystemExit(
                    f"flywheel composite component {index} source authority drift"
                )
            expected_bound_provenance = {
                "path": str(evidence_path),
                "file_sha256": actual_evidence_sha,
            }
            if (
                raw["component_id"] != HISTORICAL_REPLAY_CATEGORY
                and bound_provenance != expected_bound_provenance
            ) or (
                raw["component_id"] == HISTORICAL_REPLAY_CATEGORY
                and bound_provenance is not None
                and bound_provenance != expected_bound_provenance
            ):
                raise SystemExit(
                    f"flywheel composite component {index} corpus provenance binding drift"
                )
            mass_filenames = {
                "game_seed.dat",
                "policy_weight_multiplier.dat",
            }
            mass_binding = {
                **payload_runtime_binding,
                "files": {
                    name: identity
                    for name, identity in payload_runtime_binding["files"].items()
                    if name in mass_filenames
                },
            }
            authenticated_mass_files = _open_authenticated_memmap_payloads(
                mass_binding,
                require_read_only=True,
            )
            try:
                provenance = _validate_flywheel_component_provenance(
                    evidence_path,
                    component_id=str(raw["component_id"]),
                    corpus_dir=corpus_dir,
                    corpus_meta=corpus_meta,
                    authenticated_payload=evidence_payload,
                    authenticated_corpus_files=authenticated_mass_files,
                    source_authority_ref=source_authority_ref,
                    allowed_source_ids=(
                        set(source_authority["fresh_source_ids"])
                        if raw["component_id"] in FRESH_SOURCE_GAME_RATIOS
                        else set(source_authority["historical_source_ids"])
                    ),
                )
            finally:
                for handle in authenticated_mass_files.values():
                    handle.close()
            if (
                raw["source_category"] != provenance["source_category"]
                or raw["component_mass"] != provenance["component_mass"]
            ):
                raise SystemExit(
                    f"flywheel composite component {index} sampler provenance drift"
                )
        else:
            provenance = None
        components.append({
            **raw, "corpus_dir": str(corpus_dir),
            evidence_field: str(evidence_path),
            "corpus_meta": corpus_meta,
            "flywheel_provenance": provenance,
            "payload_runtime_binding": payload_runtime_binding,
        })
        inventory_bindings.append({
            "corpus_meta_sha256": actual_meta_sha,
            "payload_inventory_sha256": actual_inventory_sha,
        })
    anchor_component_ids: list[str] = []
    distillation_component_ids: list[str] = []
    distillation_scope_explicit = False
    policy_aux_phase_sampling_weights: dict[str, float] | None = None
    stored_policy_component_temperatures: dict[str, float] | None = None
    entity_feature_adapter_component_versions: dict[str, str] | None = None
    value_training_component_ids: list[str] = []
    value_training_scope_explicit = False
    aux_subgoal_component_ids: list[str] = []
    aux_subgoal_scope_explicit = False
    if schema_version == "memmap_composite_v2":
        if not math.isclose(sum(component_ratios), 1.0, rel_tol=0.0, abs_tol=1e-9):
            raise SystemExit("memmap composite v2 game sampling ratios must sum to 1")
        raw_anchor_ids = descriptor["policy_kl_anchor_component_ids"]
        if (
            not isinstance(raw_anchor_ids, list)
            or any(not isinstance(value, str) for value in raw_anchor_ids)
            or len(set(raw_anchor_ids)) != len(raw_anchor_ids)
            or not set(raw_anchor_ids).issubset(component_ids)
        ):
            raise SystemExit("memmap composite v2 anchor component ids are invalid")
        anchor_component_ids = list(raw_anchor_ids)
        raw_distillation_ids = descriptor.get(
            "policy_distillation_component_ids", component_ids
        )
        if (
            not isinstance(raw_distillation_ids, list)
            or not raw_distillation_ids
            or any(not isinstance(value, str) for value in raw_distillation_ids)
            or len(set(raw_distillation_ids)) != len(raw_distillation_ids)
            or not set(raw_distillation_ids).issubset(component_ids)
        ):
            raise SystemExit(
                "memmap composite v2 policy distillation component ids are invalid"
            )
        # Canonical component order prevents a semantically-identical scope
        # from acquiring multiple authenticated identities.
        if raw_distillation_ids != [
            value for value in component_ids if value in set(raw_distillation_ids)
        ]:
            raise SystemExit(
                "memmap composite v2 policy distillation component ids must follow "
                "component order"
            )
        distillation_component_ids = list(raw_distillation_ids)
        distillation_scope_explicit = "policy_distillation_component_ids" in descriptor
        raw_aux_phase_weights = descriptor.get("policy_aux_phase_sampling_weights")
        if raw_aux_phase_weights is not None:
            if not distillation_scope_explicit:
                raise SystemExit(
                    "memmap composite v2 policy auxiliary phase sampling requires "
                    "an explicit policy distillation component scope"
                )
            if not isinstance(raw_aux_phase_weights, dict) or not raw_aux_phase_weights:
                raise SystemExit(
                    "memmap composite v2 policy auxiliary phase sampling weights "
                    "must be a non-empty object"
                )
            policy_aux_phase_sampling_weights = {}
            for phase, raw_weight in raw_aux_phase_weights.items():
                if (
                    not isinstance(phase, str)
                    or not phase
                    or "\0" in phase
                    or len(phase) > 160
                ):
                    raise SystemExit(
                        "memmap composite v2 policy auxiliary phase name is invalid"
                    )
                if (
                    isinstance(raw_weight, bool)
                    or not isinstance(raw_weight, (int, float))
                    or not math.isfinite(float(raw_weight))
                    or float(raw_weight) <= 0.0
                ):
                    raise SystemExit(
                        "memmap composite v2 policy auxiliary phase sampling "
                        f"weight is invalid for {phase!r}"
                    )
                policy_aux_phase_sampling_weights[phase] = float(raw_weight)
            if not math.isclose(
                sum(policy_aux_phase_sampling_weights.values()),
                1.0,
                rel_tol=0.0,
                abs_tol=1e-9,
            ):
                raise SystemExit(
                    "memmap composite v2 policy auxiliary phase sampling weights "
                    "must sum to 1"
                )
        raw_policy_temperatures = descriptor.get(
            "stored_policy_component_temperatures"
        )
        if raw_policy_temperatures is not None:
            if (
                not isinstance(raw_policy_temperatures, dict)
                or set(raw_policy_temperatures) != set(component_ids)
            ):
                raise SystemExit(
                    "memmap composite v2 stored-policy temperatures must bind "
                    "every component id exactly"
                )
            stored_policy_component_temperatures = {}
            for component_id in component_ids:
                raw_temperature = raw_policy_temperatures[component_id]
                if (
                    isinstance(raw_temperature, bool)
                    or not isinstance(raw_temperature, (int, float))
                    or not math.isfinite(float(raw_temperature))
                    or float(raw_temperature) <= 0.0
                ):
                    raise SystemExit(
                        "memmap composite v2 stored-policy temperature is invalid "
                        f"for {component_id!r}"
                    )
                stored_policy_component_temperatures[component_id] = float(
                    raw_temperature
                )
        raw_adapter_versions = descriptor.get(
            "entity_feature_adapter_component_versions"
        )
        if raw_adapter_versions is not None:
            if (
                not isinstance(raw_adapter_versions, dict)
                or set(raw_adapter_versions) != set(component_ids)
            ):
                raise SystemExit(
                    "memmap composite v2 entity-adapter versions must bind "
                    "every component id exactly"
                )
            entity_feature_adapter_component_versions = {}
            for component_id in component_ids:
                try:
                    version = require_known_entity_feature_adapter(
                        raw_adapter_versions[component_id]
                    )
                except ValueError as error:
                    raise SystemExit(
                        "memmap composite v2 entity-adapter version is invalid "
                        f"for {component_id!r}: {error}"
                    ) from error
                entity_feature_adapter_component_versions[component_id] = version
            if len(set(entity_feature_adapter_component_versions.values())) != 1:
                raise SystemExit(
                    "memmap composite v2 cannot mix entity feature adapter semantics"
                )
            for component_id, component in zip(
                component_ids, components, strict=True
            ):
                corpus_meta = component["corpus_meta"]
                assert isinstance(corpus_meta, dict)
                columns = corpus_meta.get("columns")
                stored_adapter = (
                    isinstance(columns, dict) and "adapter_version" in columns
                )
                version = entity_feature_adapter_component_versions[component_id]
                if (
                    not stored_adapter
                    and version != LEGACY_MISSING_CHECKPOINT_ADAPTER_VERSION
                ):
                    raise SystemExit(
                        "memmap composite v2 cannot backfill a current/future "
                        "entity-adapter version onto rows with no stored "
                        "adapter_version: "
                        f"component={component_id!r} descriptor={version!r}; only "
                        "the explicit legacy missing-metadata mapping "
                        f"{LEGACY_MISSING_CHECKPOINT_ADAPTER_VERSION!r} is allowed"
                    )
        raw_value_ids = descriptor.get("value_training_component_ids", component_ids)
        if (
            not isinstance(raw_value_ids, list)
            or not raw_value_ids
            or any(not isinstance(value, str) for value in raw_value_ids)
            or len(set(raw_value_ids)) != len(raw_value_ids)
            or not set(raw_value_ids).issubset(component_ids)
        ):
            raise SystemExit(
                "memmap composite v2 value training component ids are invalid"
            )
        if raw_value_ids != [
            value for value in component_ids if value in set(raw_value_ids)
        ]:
            raise SystemExit(
                "memmap composite v2 value training component ids must follow "
                "component order"
            )
        value_training_component_ids = list(raw_value_ids)
        value_training_scope_explicit = "value_training_component_ids" in descriptor
        raw_aux_subgoal_ids = descriptor.get("aux_subgoal_component_ids")
        if raw_aux_subgoal_ids is not None:
            if (
                not isinstance(raw_aux_subgoal_ids, list)
                or any(not isinstance(value, str) for value in raw_aux_subgoal_ids)
                or len(set(raw_aux_subgoal_ids)) != len(raw_aux_subgoal_ids)
                or not set(raw_aux_subgoal_ids).issubset(component_ids)
            ):
                raise SystemExit(
                    "memmap composite v2 aux-subgoal component ids are invalid"
                )
            if raw_aux_subgoal_ids != [
                value
                for value in component_ids
                if value in set(raw_aux_subgoal_ids)
            ]:
                raise SystemExit(
                    "memmap composite v2 aux-subgoal component ids must follow "
                    "component order"
                )
            aux_subgoal_component_ids = list(raw_aux_subgoal_ids)
            aux_subgoal_scope_explicit = True
    flywheel_replay_contract = None
    if is_flywheel_production:
        raw_contract = descriptor.get("flywheel_replay_contract")
        expected_contract_fields = {
            "schema_version",
            "current_checkpoint_version",
            "initializer_checkpoint_path",
            "initializer_checkpoint_sha256",
            "fresh_component_ids",
            "replay_component_ids",
            "fresh_source_game_ratios",
            "effective_component_sampling_ratios",
            "minimum_replay_ratio",
            "realized_replay_ratio",
            "checkpoint_versions",
            "component_provenance_sha256",
            "sampling_receipt",
            "sampling_receipt_sha256",
        }
        if not isinstance(raw_contract, dict) or set(raw_contract) != expected_contract_fields:
            raise SystemExit("flywheel replay contract fields differ from schema")
        contract_schema = raw_contract.get("schema_version")
        if contract_schema not in {
            "flywheel-replay-composite-v2",
            "flywheel-replay-composite-v3",
        }:
            raise SystemExit("flywheel replay contract schema is unsupported")
        fresh_ids = raw_contract.get("fresh_component_ids")
        replay_ids = raw_contract.get("replay_component_ids")
        expected_replay_ids = (
            [HISTORICAL_REPLAY_CATEGORY]
            if contract_schema == "flywheel-replay-composite-v2"
            else []
        )
        if (
            not isinstance(fresh_ids, list)
            or fresh_ids != list(FRESH_SOURCE_GAME_RATIOS)
            or not isinstance(replay_ids, list)
            or replay_ids != expected_replay_ids
            or component_ids != fresh_ids + replay_ids
        ):
            raise SystemExit("flywheel fresh/replay component identity is invalid")
        if raw_contract.get("fresh_source_game_ratios") != FRESH_SOURCE_GAME_RATIOS:
            raise SystemExit("flywheel fresh source game ratios drifted from 80/15/5")
        provenance_by_id = {
            str(component["component_id"]): component["flywheel_provenance"]
            for component in components
        }
        if any(
            provenance_by_id[value].get("role") != "fresh"
            or provenance_by_id[value].get("source_category") != value
            for value in fresh_ids
        ) or any(
            provenance_by_id[value].get("role") != "replay" for value in replay_ids
        ):
            raise SystemExit("flywheel component roles differ from replay contract")
        if source_authority is None or source_authority_ref is None:
            raise SystemExit("flywheel production composite has no verified authority")
        if replay_ids:
            replay_authority = source_authority.get("historical_replay")
            replay_component = components[
                component_ids.index(HISTORICAL_REPLAY_CATEGORY)
            ]
            if (
                not isinstance(replay_authority, dict)
                or replay_authority.get("component_provenance_sha256")
                != replay_component.get("provenance_manifest_sha256")
                or replay_authority.get("component_payload_inventory_sha256")
                != replay_component.get("payload_inventory_sha256")
            ):
                raise SystemExit(
                    "historical source authority differs from replay component"
                )
        current_version = raw_contract.get("current_checkpoint_version")
        if (
            isinstance(current_version, bool)
            or not isinstance(current_version, int)
            or any(
                provenance_by_id[value].get("current_checkpoint_version")
                != current_version
                for value in component_ids
            )
        ):
            raise SystemExit("flywheel current checkpoint generation binding drift")
        all_versions = sorted(
            {
                int(version)
                for provenance in provenance_by_id.values()
                for version in provenance["checkpoint_versions"]
            }
        )
        if raw_contract.get("checkpoint_versions") != all_versions or (
            replay_ids
            and not any(version < int(current_version) for version in all_versions)
        ):
            raise SystemExit("flywheel checkpoint-generation inventory drift")
        minimum_ratio = raw_contract.get("minimum_replay_ratio")
        realized_ratio = sum(
            component_ratios[component_ids.index(value)] for value in replay_ids
        )
        if (
            isinstance(minimum_ratio, bool)
            or not isinstance(minimum_ratio, (int, float))
            or not 0.0 <= float(minimum_ratio) < 1.0
            or not math.isclose(
                float(minimum_ratio),
                0.20 if replay_ids else 0.0,
                rel_tol=0.0,
                abs_tol=1e-12,
            )
            or not math.isclose(
                float(realized_ratio),
                0.20 if replay_ids else 0.0,
                rel_tol=0.0,
                abs_tol=1e-12,
            )
            or float(realized_ratio) + 1e-12 < float(minimum_ratio)
            or not math.isclose(
                float(raw_contract.get("realized_replay_ratio", -1.0)),
                float(realized_ratio),
                rel_tol=0.0,
                abs_tol=1e-12,
            )
        ):
            raise SystemExit("flywheel replay sampling ratio is below its bound minimum")
        effective_ratios = {
            component_id: component_ratios[index]
            for index, component_id in enumerate(component_ids)
        }
        if raw_contract.get("effective_component_sampling_ratios") != effective_ratios:
            raise SystemExit("flywheel effective source sampling ratios drifted")
        fresh_mass = 1.0 - realized_ratio
        for component_id, within_fresh_ratio in FRESH_SOURCE_GAME_RATIOS.items():
            if not math.isclose(
                effective_ratios[component_id],
                fresh_mass * within_fresh_ratio,
                rel_tol=0.0,
                abs_tol=1e-12,
            ):
                raise SystemExit(
                    "flywheel fresh 80/15/5 mixture was flattened or reweighted"
                )
        initializer_path = Path(
            str(raw_contract.get("initializer_checkpoint_path", ""))
        ).expanduser()
        initializer_sha = raw_contract.get("initializer_checkpoint_sha256")
        if (
            not _is_sha256(initializer_sha)
            or (
                initializer_path.exists()
                and _sha256_existing_file(initializer_path) != initializer_sha
            )
        ):
            raise SystemExit("flywheel initializer differs from current producer checkpoint")
        for component_id in fresh_ids:
            producers = provenance_by_id[component_id]["producer_checkpoints"]
            if (
                len(producers) != 1
                or producers[0].get("path") != str(initializer_path)
                or producers[0].get("sha256") != initializer_sha
            ):
                raise SystemExit(
                    "flywheel initializer differs from a fresh producer checkpoint"
                )
        provenance_binding = [
            {
                "component_id": component_id,
                "provenance_manifest_sha256": components[index][
                    "provenance_manifest_sha256"
                ],
            }
            for index, component_id in enumerate(component_ids)
        ]
        if raw_contract.get("component_provenance_sha256") != _canonical_json_sha256(
            provenance_binding
        ):
            raise SystemExit("flywheel component provenance digest mismatch")
        actual_sampling_receipt = build_sampling_receipt(
            [
                {
                    "component_id": component_id,
                    "source_category": components[index]["source_category"],
                    "game_sampling_ratio": component_ratios[index],
                    "component_mass": provenance_by_id[component_id]["component_mass"],
                }
                for index, component_id in enumerate(component_ids)
            ]
        )
        if (
            raw_contract.get("sampling_receipt") != actual_sampling_receipt
            or raw_contract.get("sampling_receipt_sha256")
            != _contract_sha256(actual_sampling_receipt)
        ):
            raise SystemExit("flywheel source/game/row/policy-active sampling receipt drift")
        if not (
            overrides.get("forced_action_weight") == 0.0
            and overrides.get("forced_row_value_weight") == 1.0
            and overrides.get("per_game_policy_weight") is True
            and overrides.get("per_game_policy_weight_mode") == "equal"
            and overrides.get("per_game_value_weight") is True
            and overrides.get("per_game_value_weight_mode") == "equal"
            and overrides.get("value_player_outcome_balance_mode") == "none"
            and overrides.get("loser_sample_weight") == 1.0
            and overrides.get("soft_target_temperature") == 0.7
            and overrides.get("soft_target_weight") == 1.0
            and overrides.get("policy_target_blend_semantics")
            == POLICY_TARGET_BLEND_FALLBACK_V2
            and overrides.get("soft_target_source") == "policy"
            and overrides.get("truncated_vp_margin_value_weight") == 0.25
            and overrides.get("value_target_lambda") == 1.0
            and overrides.get("q_loss_weight") == 0.0
        ):
            raise SystemExit(
                "promotion-eligible flywheel composite requires sampler-aware "
                "equal policy/value game weighting under the natural outcome prior"
            )
        flywheel_replay_contract = dict(raw_contract)
    return {
        "schema_version": schema_version,
        "diagnostic_only": bool(descriptor["diagnostic_only"]),
        "promotion_eligible": bool(descriptor["promotion_eligible"]),
        "descriptor_path": str(descriptor_path),
        "descriptor_file_sha256": _sha256_existing_file(descriptor_path),
        "descriptor_fingerprint": _canonical_json_sha256(descriptor),
        "payload_inventory_sha256": _canonical_json_sha256(inventory_bindings),
        "learner_recipe_overrides": overrides,
        "learner_recipe_overrides_sha256": descriptor[
            "learner_recipe_overrides_sha256"
        ],
        "components": components,
        "component_ids": component_ids,
        "component_game_sampling_ratios": component_ratios,
        "policy_kl_anchor_component_ids": anchor_component_ids,
        "policy_distillation_component_ids": distillation_component_ids,
        "policy_distillation_scope_explicit": distillation_scope_explicit,
        "policy_aux_phase_sampling_weights": policy_aux_phase_sampling_weights,
        "stored_policy_component_temperatures": (
            stored_policy_component_temperatures
        ),
        "entity_feature_adapter_component_versions": (
            entity_feature_adapter_component_versions
        ),
        "value_training_component_ids": value_training_component_ids,
        "value_training_scope_explicit": value_training_scope_explicit,
        "aux_subgoal_component_ids": aux_subgoal_component_ids,
        "aux_subgoal_scope_explicit": aux_subgoal_scope_explicit,
        "flywheel_replay_contract": flywheel_replay_contract,
        "production_mix_contract": flywheel_replay_contract,
        "source_authority": source_authority,
        "source_authority_ref": source_authority_ref,
        "category_semantics": (
            None
            if descriptor.get("category_semantics") is None
            else dict(descriptor["category_semantics"])
        ),
        "category_semantics_sha256": (
            None
            if descriptor.get("category_semantics") is None
            else _canonical_json_sha256(descriptor["category_semantics"])
        ),
        **_portable_composite_semantic_digests(
            components=components,
            component_ids=component_ids,
            aux_subgoal_component_ids=aux_subgoal_component_ids,
            source_authority=source_authority,
            learner_recipe_overrides_sha256=str(
                descriptor["learner_recipe_overrides_sha256"]
            ),
        ),
    }


def _portable_composite_semantic_digests(
    *,
    components: Sequence[Mapping[str, object]],
    component_ids: Sequence[str],
    aux_subgoal_component_ids: Sequence[str],
    source_authority: Mapping[str, object] | None,
    learner_recipe_overrides_sha256: str,
) -> dict[str, object]:
    """Bind path-independent learner semantics omitted by payload hashes.

    Payload inventories prove bytes, not what the learner is allowed to do
    with those bytes.  These explicit projections prevent a copied composite
    from retaining the same portable experiment identity after its objective
    scope, auxiliary-label contract, or legacy->authoritative feature
    transition changes.  Absolute staging paths and hashes whose preimages
    include those paths are deliberately excluded.
    """

    if not component_ids:
        # V1 predates explicit component ids. Keep its portable projection
        # ordered and nonempty with deterministic positional identities rather
        # than rejecting every legacy diagnostic descriptor or hashing no
        # component semantics at all.
        component_ids = tuple(
            f"component_{index}" for index in range(len(components))
        )
    elif list(component_ids) != [
        str(component.get("component_id", "")) for component in components
    ]:
        raise SystemExit("composite semantic projection component order drift")
    if not _is_sha256(learner_recipe_overrides_sha256):
        raise SystemExit("composite learner override semantic digest is malformed")

    aux_scope = set(aux_subgoal_component_ids)
    aux_components: list[dict[str, object]] = []
    award_components: list[dict[str, object]] = []
    for component_id, component in zip(component_ids, components, strict=True):
        meta = component.get("corpus_meta")
        if not isinstance(meta, Mapping):
            raise SystemExit(
                f"composite component {component_id!r} lacks authenticated metadata"
            )
        if component_id in aux_scope:
            contract = meta.get("aux_subgoal_target_contract")
            expected_counts = {
                str(AUX_SUBGOAL_TARGET_VERSION): int(meta.get("row_count", -1))
            }
            expected_contract_fields = {
                "version_key",
                "supported_version",
                "semantic",
                "version_zero_means_unversioned_ineligible",
                "realized_version_counts",
                "all_rows_semantically_eligible",
            }
            if (
                not isinstance(contract, Mapping)
                or set(contract) != expected_contract_fields
                or contract.get("version_key") != AUX_SUBGOAL_TARGET_VERSION_KEY
                or contract.get("supported_version") != AUX_SUBGOAL_TARGET_VERSION
                or contract.get("semantic") != AUX_SUBGOAL_TARGET_SEMANTIC
                or contract.get("version_zero_means_unversioned_ineligible") is not True
                or contract.get("realized_version_counts") != expected_counts
                or contract.get("all_rows_semantically_eligible") is not True
            ):
                raise SystemExit(
                    "aux-subgoal component scope names data without the exact "
                    f"strict-future target contract: {component_id}"
                )
            aux_components.append(
                {
                    "component_id": component_id,
                    "target_contract": copy.deepcopy(dict(contract)),
                }
            )

        provenance = meta.get("public_award_feature_provenance")
        if provenance is None:
            award_components.append(
                {
                    "component_id": component_id,
                    "contract": PUBLIC_AWARD_FEATURE_CONTRACT_LEGACY_ZERO,
                    "producer_semantics": [],
                }
            )
            continue
        if not isinstance(provenance, Mapping):
            raise SystemExit(
                f"component {component_id!r} public-award provenance is malformed"
            )
        contract = str(provenance.get("contract", ""))
        bindings = provenance.get("source_manifest_bindings")
        if contract not in {
            PUBLIC_AWARD_FEATURE_CONTRACT_LEGACY_ZERO,
            PUBLIC_AWARD_FEATURE_CONTRACT_AUTHORITATIVE,
            PUBLIC_AWARD_FEATURE_CONTRACT_MIXED,
        } or not isinstance(bindings, list):
            raise SystemExit(
                f"component {component_id!r} public-award semantic contract is invalid"
            )
        producer_semantics: list[dict[str, object]] = []
        for index, binding in enumerate(bindings):
            if not isinstance(binding, Mapping):
                raise SystemExit(
                    f"component {component_id!r} public-award binding {index} is invalid"
                )
            binding_contract = str(binding.get("contract", ""))
            producer = binding.get("producer_provenance")
            if binding_contract not in {
                PUBLIC_AWARD_FEATURE_CONTRACT_LEGACY_ZERO,
                PUBLIC_AWARD_FEATURE_CONTRACT_AUTHORITATIVE,
            } or (producer is not None and not isinstance(producer, Mapping)):
                raise SystemExit(
                    f"component {component_id!r} public-award producer semantics drift"
                )
            producer_semantics.append(
                {
                    "contract": binding_contract,
                    "producer_provenance": (
                        None if producer is None else copy.deepcopy(dict(producer))
                    ),
                }
            )
        award_components.append(
            {
                "component_id": component_id,
                "contract": contract,
                "producer_semantics": producer_semantics,
            }
        )

    aux_projection = {
        "schema_version": "a1-aux-subgoal-target-contract-projection-v1",
        "scope_component_ids": list(aux_subgoal_component_ids),
        "components": aux_components,
    }
    award_projection = {
        "schema_version": "a1-public-award-feature-transition-contract-v1",
        "components": award_components,
        "effective_checkpoint_contract": (
            PUBLIC_AWARD_FEATURE_CONTRACT_AUTHORITATIVE
        ),
        "mixed_row_routing_authority": (
            "authenticated_component_identity_not_feature_values"
        ),
        "legacy_initializer_transition": {
            "parameter_suffix": "player_encoder.0.weight",
            "input_column_index": PLAYER_LONGEST_ROAD_SLOT,
            "operation": "exact_zero_before_optimizer",
        },
    }

    source_projection = None
    if source_authority is not None:
        current = source_authority.get("current_contract")
        selected = source_authority.get("selected_game_manifest")
        audit = source_authority.get("post_wave_audit")
        historical = source_authority.get("historical_replay")
        if not all(isinstance(value, Mapping) for value in (current, selected, audit)):
            raise SystemExit("source authority semantic projection is incomplete")
        source_projection = {
            "schema_version": source_authority.get("schema_version"),
            "current_contract_sha256": current.get("contract_sha256"),
            "selected_records_sha256": selected.get("records_sha256"),
            "selected_game_seed_set_sha256": selected.get(
                "selected_game_seed_set_sha256"
            ),
            "post_wave_audit_sha256": audit.get("audit_sha256"),
            "post_wave_shard_inventory_sha256": audit.get(
                "shard_inventory_sha256"
            ),
            "fresh_source_bindings_sha256": source_authority.get(
                "fresh_source_bindings_sha256"
            ),
            "fresh_generation_manifests_sha256": source_authority.get(
                "fresh_generation_manifests_sha256"
            ),
            "category_semantics_sha256": _canonical_json_sha256(
                source_authority.get("category_semantics")
            ),
        }
        if historical is not None:
            if not isinstance(historical, Mapping):
                raise SystemExit("historical source authority projection is malformed")
            source_projection["historical_replay_authority_sha256"] = historical.get(
                "authority_sha256"
            )
        verifier_authorities = source_authority.get("lock_verifier_authorities")
        if verifier_authorities is not None:
            source_projection["lock_verifier_authorities_sha256"] = (
                _canonical_json_sha256(verifier_authorities)
            )
        if any(
            not _is_sha256(value)
            for key, value in source_projection.items()
            if key != "schema_version"
        ):
            raise SystemExit("source authority semantic digest field is malformed")

    return {
        "learner_recipe_overrides_sha256": learner_recipe_overrides_sha256,
        "aux_subgoal_target_contract_sha256": _canonical_json_sha256(
            aux_projection
        ),
        "public_award_feature_transition_contract_sha256": (
            _canonical_json_sha256(award_projection)
        ),
        "source_authority_semantic_sha256": (
            None
            if source_projection is None
            else _canonical_json_sha256(source_projection)
        ),
    }


def _validate_composite_learner_recipe_authorization(
    args: argparse.Namespace, composite_meta: dict[str, object]
) -> None:
    expected = composite_meta.get("learner_recipe_overrides")
    if not isinstance(expected, dict):
        raise SystemExit("memmap composite has no authenticated learner recipe override")
    converters = {
        "advantage_policy_weighting": str,
        "aux_subgoal_loss_weight": float,
        "epochs": int,
        "final_vp_loss_weight": float,
        "forced_action_weight": float,
        "forced_row_value_weight": float,
        "forced_row_value_action_type_weights": str,
        "hlgauss_scalar_aux_loss_weight": float,
        "loser_sample_weight": float,
        "lr": float,
        "lr_schedule": str,
        "lr_warmup_steps": int,
        "max_steps": int,
        "per_game_policy_surprise_weighting": bool,
        "target_reliability_confidence_weighting": bool,
        "target_reliability_confidence_floor": float,
        "per_game_policy_weight": bool,
        "per_game_policy_weight_mode": str,
        "policy_aux_sampling_mode": str,
        "per_game_value_weight": bool,
        "per_game_value_weight_mode": str,
        "value_player_outcome_balance_mode": str,
        "policy_aux_active_batch_size": int,
        "policy_aux_loss_weight": float,
        "policy_loss_weight": float,
        "policy_surprise_weight": float,
        "public_card_lr_mult": float,
        "shared_action_lr_mult": float,
        "policy_kl_anchor_direction": str,
        "policy_kl_anchor_weight": float,
        "policy_kl_target": float,
        "policy_kl_dual_lr": float,
        "policy_kl_max_weight": float,
        "policy_target_blend_semantics": str,
        "q_loss_weight": float,
        "soft_target_source": str,
        "soft_target_min_legal_coverage": float,
        "soft_target_temperature": float,
        "soft_target_weight": float,
        "scalar_value_objective": str,
        "scalar_value_loss_readout": str,
        "scalar_value_loss_scale": float,
        "truncated_vp_margin_value_weight": float,
        "value_target_lambda": float,
        "value_categorical_bins": int,
        "value_categorical_loss_weight": float,
        "value_head_type": str,
        "value_hlgauss_sigma_ratio": float,
        "value_loss_weight": float,
        "value_lr_mult": float,
        "value_trunk_grad_scale": float,
        "vp_margin_weight": float,
        "winner_sample_weight": float,
    }
    missing_converters = sorted(set(expected) - set(converters))
    if missing_converters:
        raise SystemExit(
            "memmap composite authenticated learner recipe contains fields "
            "without command converters: " + ", ".join(missing_converters)
        )
    actual = {
        key: converters[key](getattr(args, key))
        for key in expected
    }
    if expected != actual:
        raise SystemExit(
            "memmap composite command differs from its authenticated diagnostic "
            f"learner recipe override: descriptor={expected!r} command={actual!r}"
        )


def _expected_memmap_payload_filenames(
    corpus_meta: dict[str, object],
) -> set[str]:
    columns = corpus_meta.get("columns")
    if not isinstance(columns, dict) or not columns:
        raise SystemExit("A1 memmap metadata has no column schema")
    expected = {"row_offsets.dat"}
    for name, raw_schema in columns.items():
        if not isinstance(name, str) or not name or Path(name).name != name:
            raise SystemExit("A1 memmap column name is not a safe filename component")
        if not isinstance(raw_schema, dict):
            raise SystemExit(f"A1 memmap column {name!r} has malformed schema")
        kind = raw_schema.get("kind")
        if kind not in {
            "fixed",
            "ragged2d",
            "ragged3d",
            "row_offsets",
            "independent_ragged1d",
            "string",
            "implicit_constant",
        }:
            raise SystemExit(
                f"A1 memmap column {name!r} has unsupported kind {kind!r}"
            )
        if kind == "implicit_constant":
            continue
        expected.add(
            f"{name}.codes.dat" if kind == "string" else f"{name}.dat"
        )
    return expected


def _payload_auth_cache_root() -> Path:
    override = os.environ.get("TRAIN_BC_PAYLOAD_AUTH_CACHE_DIR")
    if override:
        return Path(override).expanduser()
    xdg = os.environ.get("XDG_CACHE_HOME")
    base = Path(xdg).expanduser() if xdg else Path.home() / ".cache"
    return base / "catan-zero" / "payload-auth"


def _payload_filesystem_identity(path: Path) -> dict[str, int | str]:
    """Return a fail-closed identity for one immutable payload path."""

    try:
        before = path.lstat()
    except OSError as error:
        raise SystemExit(f"cannot stat A1 memmap payload {path}: {error}") from error
    if stat.S_ISLNK(before.st_mode) or not stat.S_ISREG(before.st_mode):
        raise SystemExit(f"A1 memmap payload must be a non-symlink regular file: {path}")
    return _payload_stat_identity(path.name, before)


def _payload_stat_identity(
    filename: str, value: os.stat_result
) -> dict[str, int | str]:
    return {
        "filename": filename,
        "device": int(value.st_dev),
        "inode": int(value.st_ino),
        "size_bytes": int(value.st_size),
        "mtime_ns": int(value.st_mtime_ns),
        "ctime_ns": int(value.st_ctime_ns),
        "mode": int(stat.S_IMODE(value.st_mode)),
    }


def _memmap_payload_runtime_binding(
    corpus_dir: Path,
    corpus_meta: Mapping[str, object],
    *,
    authenticated_identities: Sequence[Mapping[str, object]] | None = None,
) -> dict[str, object]:
    """Capture the exact metadata/payload inodes that the loader must map."""

    records = corpus_meta.get("payload_inventory")
    if not isinstance(records, list):
        raise SystemExit("memmap corpus lacks its authenticated payload inventory")
    names = [
        str(record.get("filename", ""))
        for record in records
        if isinstance(record, Mapping)
    ]
    if len(names) != len(records) or not names or len(set(names)) != len(names):
        raise SystemExit("memmap payload runtime binding has malformed filenames")
    if authenticated_identities is None:
        identities = {
            name: _payload_filesystem_identity(corpus_dir / name)
            for name in sorted(names)
        }
    else:
        identities = {
            str(identity.get("filename", "")): dict(identity)
            for identity in authenticated_identities
        }
        if set(identities) != set(names):
            raise SystemExit(
                "authenticated memmap payload identity filenames drifted"
            )
    return {
        "corpus_dir": str(corpus_dir),
        "files": identities,
    }


def _validate_memmap_payload_runtime_binding(
    binding: Mapping[str, object],
    *,
    require_read_only: bool,
) -> None:
    """Refuse replacement or writable backing bytes around mmap creation."""

    corpus_dir = Path(str(binding.get("corpus_dir", "")))
    expected = binding.get("files")
    if not isinstance(expected, Mapping) or not expected:
        raise SystemExit("memmap payload runtime binding is malformed")
    for name, identity in expected.items():
        if not isinstance(name, str) or not isinstance(identity, Mapping):
            raise SystemExit("memmap payload runtime file binding is malformed")
        actual = _payload_filesystem_identity(corpus_dir / name)
        if actual != identity:
            raise SystemExit(
                f"authenticated memmap payload identity changed before use: {name}"
            )
        if (
            require_read_only
            and name != "corpus_meta.json"
            and int(actual["mode"]) & 0o222
        ):
            raise SystemExit(
                "promotion composite requires read-only authenticated memmap "
                f"backing bytes before training: {corpus_dir / name}"
            )


def _open_authenticated_memmap_payloads(
    binding: Mapping[str, object],
    *,
    require_read_only: bool,
) -> dict[str, Any]:
    """Open and pin the exact authenticated inodes used by NumPy memmaps."""

    corpus_dir = Path(str(binding.get("corpus_dir", "")))
    expected = binding.get("files")
    if not isinstance(expected, Mapping) or not expected:
        raise SystemExit("memmap payload runtime binding is malformed")
    opened: dict[str, Any] = {}
    flags = os.O_RDONLY | getattr(os, "O_CLOEXEC", 0) | getattr(os, "O_NOFOLLOW", 0)
    try:
        for name, identity in expected.items():
            if not isinstance(name, str) or not isinstance(identity, Mapping):
                raise SystemExit("memmap payload runtime file binding is malformed")
            fd = os.open(corpus_dir / name, flags)
            handle = os.fdopen(fd, "rb")
            actual = _payload_stat_identity(name, os.fstat(handle.fileno()))
            if actual != identity:
                handle.close()
                raise SystemExit(
                    f"authenticated memmap payload inode changed before open: {name}"
                )
            if (
                require_read_only
                and name != "corpus_meta.json"
                and int(actual["mode"]) & 0o222
            ):
                handle.close()
                raise SystemExit(
                    "promotion composite requires read-only authenticated memmap "
                    f"backing bytes before training: {corpus_dir / name}"
                )
            opened[name] = handle
    except BaseException:
        for handle in opened.values():
            handle.close()
        raise
    return opened


def _validate_open_authenticated_memmap_payloads(
    binding: Mapping[str, object],
    opened: Mapping[str, Any],
) -> None:
    """Prove mmap construction consumed handles for every expected inode."""

    expected = binding.get("files")
    if not isinstance(expected, Mapping) or set(opened) != set(expected):
        raise SystemExit("open authenticated memmap payload set drift")
    for name, identity in expected.items():
        handle = opened[name]
        actual = _payload_stat_identity(name, os.fstat(handle.fileno()))
        stable_fields = {
            "filename",
            "device",
            "inode",
            "size_bytes",
            "mtime_ns",
            "mode",
        }
        if any(actual[field] != identity.get(field) for field in stable_fields):
            raise SystemExit(
                f"authenticated memmap payload inode changed while mapping: {name}"
            )


def _sha256_stable_payload(
    path: Path, expected_identity: dict[str, int | str]
) -> str:
    """Hash one exact inode and reject mutation or pathname replacement."""

    flags = os.O_RDONLY | getattr(os, "O_CLOEXEC", 0) | getattr(os, "O_NOFOLLOW", 0)
    try:
        fd = os.open(path, flags)
    except OSError as error:
        raise SystemExit(f"cannot open A1 memmap payload {path}: {error}") from error
    digest = hashlib.sha256()
    try:
        with os.fdopen(fd, "rb") as handle:
            identity_before = _payload_stat_identity(path.name, os.fstat(handle.fileno()))
            if identity_before != expected_identity:
                raise SystemExit(
                    f"A1 memmap payload {path.name} identity changed before hashing"
                )
            for chunk in iter(lambda: handle.read(1024 * 1024), b""):
                digest.update(chunk)
            identity_after = _payload_stat_identity(path.name, os.fstat(handle.fileno()))
    except OSError as error:
        raise SystemExit(f"cannot hash A1 memmap payload {path}: {error}") from error
    if identity_after != expected_identity or _payload_filesystem_identity(path) != expected_identity:
        raise SystemExit(f"A1 memmap payload {path.name} changed while being authenticated")
    return f"sha256:{digest.hexdigest()}"


def _payload_auth_cache_binding(
    root: Path,
    corpus_meta: dict[str, object],
    inventory_sha: str,
    identities: list[dict[str, int | str]],
) -> dict[str, object]:
    meta_path = root / "corpus_meta.json"
    return {
        "schema_version": MEMMAP_PAYLOAD_AUTH_CACHE_SCHEMA,
        "validator_version": MEMMAP_PAYLOAD_AUTH_VALIDATOR_VERSION,
        "corpus_dir": str(root.resolve(strict=True)),
        "corpus_meta_file_sha256": _sha256_existing_file(meta_path),
        "corpus_descriptor_sha256": _canonical_json_sha256(corpus_meta),
        "payload_inventory_schema": corpus_meta.get("payload_inventory_schema"),
        "payload_inventory_sha256": inventory_sha,
        "payloads": identities,
    }


def _payload_auth_cache_path(binding: dict[str, object]) -> Path:
    digest = _canonical_json_sha256(binding).split(":", 1)[1]
    return _payload_auth_cache_root() / f"{digest}.json"


def _load_payload_auth_cache(
    binding: dict[str, object], *, total_bytes: int
) -> bool:
    path = _payload_auth_cache_path(binding)
    try:
        directory = path.parent
        directory_stat = directory.lstat()
        if (
            not stat.S_ISDIR(directory_stat.st_mode)
            or directory_stat.st_uid != os.geteuid()
            or stat.S_IMODE(directory_stat.st_mode) & 0o077
        ):
            return False
        cache_stat = path.lstat()
        if (
            not stat.S_ISREG(cache_stat.st_mode)
            or stat.S_ISLNK(cache_stat.st_mode)
            or cache_stat.st_uid != os.geteuid()
            or stat.S_IMODE(cache_stat.st_mode) & 0o077
        ):
            return False
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError):
        return False
    if not isinstance(payload, dict) or set(payload) != {
        "binding", "binding_sha256", "authenticated_bytes", "entry_sha256"
    }:
        return False
    unsigned = dict(payload)
    entry_sha = unsigned.pop("entry_sha256", None)
    return bool(
        payload.get("binding") == binding
        and payload.get("binding_sha256") == _canonical_json_sha256(binding)
        and payload.get("authenticated_bytes") == total_bytes
        and entry_sha == _canonical_json_sha256(unsigned)
    )


def _publish_payload_auth_cache(
    binding: dict[str, object], *, total_bytes: int
) -> None:
    """Best-effort publish; inability to cache never weakens verification."""

    path = _payload_auth_cache_path(binding)
    try:
        path.parent.mkdir(mode=0o700, parents=True, exist_ok=True)
        directory_stat = path.parent.lstat()
        if (
            not stat.S_ISDIR(directory_stat.st_mode)
            or directory_stat.st_uid != os.geteuid()
            or stat.S_IMODE(directory_stat.st_mode) != 0o700
        ):
            return
        unsigned = {
            "binding": binding,
            "binding_sha256": _canonical_json_sha256(binding),
            "authenticated_bytes": total_bytes,
        }
        payload = {**unsigned, "entry_sha256": _canonical_json_sha256(unsigned)}
        fd, temporary = tempfile.mkstemp(prefix=f".{path.name}.", dir=path.parent)
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as handle:
                json.dump(payload, handle, sort_keys=True, separators=(",", ":"))
                handle.flush()
                os.fsync(handle.fileno())
            os.chmod(temporary, 0o600)
            os.replace(temporary, path)
        finally:
            try:
                os.unlink(temporary)
            except FileNotFoundError:
                pass
    except OSError:
        return


def _validate_memmap_payload_inventory(
    data_path: str | Path,
    corpus_meta: dict[str, object],
    *,
    return_identities: bool = False,
) -> str | tuple[str, list[dict[str, int | str]]]:
    """Verify every A1 flat payload file against its immutable inventory."""

    if (
        corpus_meta.get("payload_inventory_schema")
        != MEMMAP_PAYLOAD_INVENTORY_SCHEMA
    ):
        raise SystemExit(
            "A1 memmap payload inventory schema is missing or unsupported"
        )
    inventory = corpus_meta.get("payload_inventory")
    if not isinstance(inventory, list) or not inventory:
        raise SystemExit("A1 memmap payload inventory is missing or empty")
    declared_inventory_sha = corpus_meta.get("payload_inventory_sha256")
    actual_inventory_sha = _canonical_json_sha256(inventory)
    if (
        not _is_sha256(declared_inventory_sha)
        or declared_inventory_sha != actual_inventory_sha
    ):
        raise SystemExit(
            "A1 memmap payload inventory semantic digest mismatch: "
            f"declared={declared_inventory_sha!r} actual={actual_inventory_sha!r}"
        )

    expected_names = _expected_memmap_payload_filenames(corpus_meta)
    records_by_name: dict[str, dict[str, object]] = {}
    prior_name: str | None = None
    for index, record in enumerate(inventory):
        if not isinstance(record, dict) or set(record) != {
            "filename",
            "size_bytes",
            "sha256",
        }:
            raise SystemExit(
                f"A1 memmap payload inventory record {index} has malformed fields"
            )
        filename = record["filename"]
        if (
            not isinstance(filename, str)
            or not filename
            or Path(filename).name != filename
        ):
            raise SystemExit(
                f"A1 memmap payload inventory record {index} has unsafe filename"
            )
        if prior_name is not None and filename <= prior_name:
            raise SystemExit(
                "A1 memmap payload inventory filenames must be strictly sorted"
            )
        prior_name = filename
        size_bytes = record["size_bytes"]
        if (
            isinstance(size_bytes, bool)
            or not isinstance(size_bytes, int)
            or size_bytes < 0
            or not _is_sha256(record["sha256"])
        ):
            raise SystemExit(
                f"A1 memmap payload inventory record {index} has invalid size/hash"
            )
        records_by_name[filename] = record
    if set(records_by_name) != expected_names:
        raise SystemExit(
            "A1 memmap payload inventory filenames differ from the column schema: "
            f"missing={sorted(expected_names - set(records_by_name))} "
            f"unexpected={sorted(set(records_by_name) - expected_names)}"
        )

    root = Path(data_path).expanduser()
    actual_names = {
        path.name
        for path in root.iterdir()
        if path.is_file()
        and (path.name.endswith(".dat") or path.name.endswith(".codes.dat"))
    }
    if actual_names != expected_names:
        raise SystemExit(
            "A1 memmap on-disk payload filenames differ from the authenticated "
            f"inventory: missing={sorted(expected_names - actual_names)} "
            f"unexpected={sorted(actual_names - expected_names)}"
        )
    identities = [
        _payload_filesystem_identity(root / filename)
        for filename in sorted(expected_names)
    ]
    total_bytes = sum(int(identity["size_bytes"]) for identity in identities)
    binding = _payload_auth_cache_binding(
        root, corpus_meta, actual_inventory_sha, identities
    )
    cache_eligible = all(
        int(identity["mode"]) & 0o222 == 0 for identity in identities
    )
    if cache_eligible and _load_payload_auth_cache(binding, total_bytes=total_bytes):
        print(json.dumps({
            "progress": "a1_payload_auth_cache",
            "status": "hit",
            "payload_count": len(identities),
            "authenticated_bytes": total_bytes,
            "bytes_avoided": total_bytes,
            "binding_sha256": _canonical_json_sha256(binding),
        }, sort_keys=True), flush=True)
        return (
            (actual_inventory_sha, identities)
            if return_identities
            else actual_inventory_sha
        )

    for filename in sorted(expected_names):
        record = records_by_name[filename]
        payload_path = root / filename
        identity_before = _payload_filesystem_identity(payload_path)
        actual_size = int(identity_before["size_bytes"])
        if actual_size != record["size_bytes"]:
            raise SystemExit(
                f"A1 memmap payload {filename} size mismatch: "
                f"declared={record['size_bytes']} actual={actual_size}"
            )
        actual_sha = _sha256_stable_payload(payload_path, identity_before)
        identity_after = _payload_filesystem_identity(payload_path)
        if identity_after != identity_before:
            raise SystemExit(
                f"A1 memmap payload {filename} changed while being authenticated"
            )
        if actual_sha != record["sha256"]:
            raise SystemExit(
                f"A1 memmap payload {filename} sha256 mismatch: "
                f"declared={record['sha256']!r} actual={actual_sha!r}"
            )
    # Recompute the complete binding after hashing. This also catches a sibling
    # payload changing while a different file was being read.
    final_identities = [
        _payload_filesystem_identity(root / filename)
        for filename in sorted(expected_names)
    ]
    if final_identities != identities:
        raise SystemExit("A1 memmap payload identity changed during authentication")
    if cache_eligible:
        _publish_payload_auth_cache(binding, total_bytes=total_bytes)
    print(json.dumps({
        "progress": "a1_payload_auth_cache",
        "status": "miss",
        "miss_reason": (
            "cache_absent_or_invalid"
            if cache_eligible
            else "payload_not_read_only"
        ),
        "payload_count": len(identities),
        "authenticated_bytes": total_bytes,
        "bytes_avoided": 0,
        "cache_eligible": cache_eligible,
        "binding_sha256": _canonical_json_sha256(binding),
    }, sort_keys=True), flush=True)
    return (
        (actual_inventory_sha, final_identities)
        if return_identities
        else actual_inventory_sha
    )


def _preflight_a1_memmap_metadata(
    data_path: str | Path,
    *,
    validation_manifest_path: str | Path | None,
    expected_descriptor_file_sha256: str | None = None,
    production_authority_preflight_completed: bool = True,
) -> dict[str, object] | None:
    """Auto-detect an A1 corpus and forbid bypassing its exact holdout path."""

    expanded = Path(data_path).expanduser()
    if expanded.is_file():
        if validation_manifest_path:
            raise SystemExit(
                "memmap composite descriptor binds each component validation manifest; "
                "do not also pass --validation-game-seed-manifest"
            )
        return _preflight_memmap_composite_descriptor(
            expanded,
            expected_descriptor_file_sha256=expected_descriptor_file_sha256,
            production_authority_preflight_completed=(
                production_authority_preflight_completed
            ),
        )
    meta_path = expanded / "corpus_meta.json"
    if not meta_path.is_file():
        return None
    try:
        payload = json.loads(meta_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load memmap corpus metadata {meta_path}: {error}") from error
    if not isinstance(payload, dict):
        raise SystemExit(f"{meta_path} must contain a JSON object")
    selected = payload.get("selected_game_seed_manifest")
    audit = payload.get("a1_post_wave_audit")
    is_a1 = selected is not None or audit is not None
    if not is_a1:
        return None
    if not isinstance(selected, dict) or not isinstance(audit, dict):
        raise SystemExit(
            "A1 memmap metadata must bind both selected_game_seed_manifest and "
            "a1_post_wave_audit"
        )
    if not validation_manifest_path:
        raise SystemExit(
            "A1 memmap corpus detected: --validation-game-seed-manifest is "
            "mandatory and cannot be replaced by a recomputed fraction/range split"
        )
    _validate_memmap_payload_inventory(data_path, payload)
    return payload


def _single_node_ddp_shared_storage_enabled(
    ddp: dict[str, int | bool],
) -> bool:
    """Return whether DDP topology proves all ranks share this node's storage.

    ``LOCAL_WORLD_SIZE`` is deliberately required.  If a non-torchrun launcher
    does not provide enough topology information, callers must retain per-rank
    verification/computation instead of assuming shared storage.  Multi-node
    launches likewise cannot treat equal path strings as proof that underlying
    files are equal across nodes.
    """

    raw_local_world_size = os.environ.get("LOCAL_WORLD_SIZE", "")
    try:
        local_world_size = int(raw_local_world_size or 0)
    except ValueError:
        return False
    world_size = int(ddp.get("world_size", 1))
    return (
        bool(ddp.get("enabled", False))
        and world_size > 1
        and local_world_size > 1
        and world_size == local_world_size
    )


def _single_node_ddp_preflight_enabled(ddp: dict[str, int | bool]) -> bool:
    """Backward-compatible name for the shared-storage topology contract."""

    return _single_node_ddp_shared_storage_enabled(ddp)


def _derived_array_cache_enabled(
    ddp: dict[str, int | bool], *, data_format: str
) -> bool:
    """Only share node-local derived arrays under proven single-node DDP."""

    return (
        data_format == "memmap"
        and _single_node_ddp_shared_storage_enabled(ddp)
    )


def _a1_preflight_store(
    ddp: dict[str, int | bool],
    *,
    data_path: str | Path,
    validation_manifest_path: str | Path | None,
) -> Any:
    """Connect to torchrun's CPU rendezvous store without initializing CUDA."""

    import torch.distributed as dist

    try:
        timeout_seconds = int(
            os.environ.get("TRAIN_BC_A1_PREFLIGHT_TIMEOUT_SECONDS", "21600")
        )
    except ValueError as error:
        raise SystemExit(
            "TRAIN_BC_A1_PREFLIGHT_TIMEOUT_SECONDS must be an integer"
        ) from error
    if timeout_seconds < 1:
        raise SystemExit("TRAIN_BC_A1_PREFLIGHT_TIMEOUT_SECONDS must be >= 1")
    master_addr = os.environ.get("MASTER_ADDR", "")
    master_port = os.environ.get("MASTER_PORT", "")
    if not master_addr or not master_port:
        raise SystemExit(
            "single-node DDP A1 preflight requires torchrun MASTER_ADDR/MASTER_PORT"
        )
    try:
        store = dist.TCPStore(
            master_addr,
            int(master_port),
            world_size=None,
            is_master=False,
            timeout=timedelta(seconds=timeout_seconds),
        )
    except Exception as error:
        raise SystemExit(
            "cannot connect to torchrun store for single-node A1 preflight: "
            f"{error}"
        ) from error
    identity = {
        "run_id": os.environ.get("TORCHELASTIC_RUN_ID", ""),
        "restart_count": os.environ.get("TORCHELASTIC_RESTART_COUNT", "0"),
        "world_size": int(ddp["world_size"]),
        "data": str(Path(data_path).expanduser().absolute()),
        "validation_manifest": (
            ""
            if validation_manifest_path is None
            else str(Path(validation_manifest_path).expanduser().absolute())
        ),
    }
    prefix = "train_bc/a1_preflight/" + _canonical_json_sha256(identity)[7:] + "/"
    return dist.PrefixStore(prefix, store)


A1_PREFLIGHT_STORE_CHUNK_BYTES = 4 * 1024 * 1024
A1_PREFLIGHT_STORE_MAX_PACKET_BYTES = 256 * 1024 * 1024
A1_PREFLIGHT_STORE_MAX_CHUNKS = (
    A1_PREFLIGHT_STORE_MAX_PACKET_BYTES // A1_PREFLIGHT_STORE_CHUNK_BYTES
)
A1_PREFLIGHT_STORE_PACKET_SCHEMA = "train-bc-a1-preflight-store-packet-v1"


def _publish_a1_preflight_packet(
    store: Any, result_key: str, packet: dict[str, object]
) -> None:
    """Publish one authenticated packet without exceeding TCPStore's 8 MiB cap.

    Chunks are written before the manifest.  Peers block on the manifest key,
    so they cannot mistake a partially published packet for a complete result.
    JSON's default ``ensure_ascii=True`` keeps every byte boundary safe to pass
    through the Store string API.
    """

    encoded = json.dumps(packet, sort_keys=True, separators=(",", ":")).encode("ascii")
    if len(encoded) > A1_PREFLIGHT_STORE_MAX_PACKET_BYTES:
        raise ValueError("A1 preflight packet exceeds the bounded Store transport size")
    chunks = [
        encoded[offset : offset + A1_PREFLIGHT_STORE_CHUNK_BYTES]
        for offset in range(0, len(encoded), A1_PREFLIGHT_STORE_CHUNK_BYTES)
    ]
    if not chunks:
        chunks = [b""]
    for index, chunk in enumerate(chunks):
        store.set(f"{result_key}/chunk/{index:08d}", chunk.decode("ascii"))
    manifest = {
        "schema_version": A1_PREFLIGHT_STORE_PACKET_SCHEMA,
        "chunk_bytes": A1_PREFLIGHT_STORE_CHUNK_BYTES,
        "chunk_count": len(chunks),
        "payload_size_bytes": len(encoded),
        "payload_sha256": f"sha256:{hashlib.sha256(encoded).hexdigest()}",
    }
    store.set(
        f"{result_key}/manifest",
        json.dumps(manifest, sort_keys=True, separators=(",", ":")),
    )


def _receive_a1_preflight_packet(
    store: Any, result_key: str
) -> dict[str, object]:
    """Receive, bound, and decode a chunked rank-0 preflight packet."""

    raw_manifest = store.get(f"{result_key}/manifest")
    if isinstance(raw_manifest, bytes):
        raw_manifest = raw_manifest.decode("utf-8")
    manifest = json.loads(raw_manifest)
    expected_fields = {
        "schema_version",
        "chunk_bytes",
        "chunk_count",
        "payload_size_bytes",
        "payload_sha256",
    }
    if not isinstance(manifest, dict) or set(manifest) != expected_fields:
        raise ValueError("A1 preflight packet manifest fields drifted")
    chunk_count = manifest.get("chunk_count")
    payload_size = manifest.get("payload_size_bytes")
    if (
        manifest.get("schema_version") != A1_PREFLIGHT_STORE_PACKET_SCHEMA
        or manifest.get("chunk_bytes") != A1_PREFLIGHT_STORE_CHUNK_BYTES
        or isinstance(chunk_count, bool)
        or not isinstance(chunk_count, int)
        or chunk_count < 1
        or chunk_count > A1_PREFLIGHT_STORE_MAX_CHUNKS
        or isinstance(payload_size, bool)
        or not isinstance(payload_size, int)
        or payload_size < 1
        or payload_size > A1_PREFLIGHT_STORE_MAX_PACKET_BYTES
        or chunk_count
        != (payload_size + A1_PREFLIGHT_STORE_CHUNK_BYTES - 1)
        // A1_PREFLIGHT_STORE_CHUNK_BYTES
        or not _is_sha256(manifest.get("payload_sha256"))
    ):
        raise ValueError("A1 preflight packet manifest is malformed")

    chunks: list[bytes] = []
    for index in range(chunk_count):
        raw_chunk = store.get(f"{result_key}/chunk/{index:08d}")
        if isinstance(raw_chunk, str):
            raw_chunk = raw_chunk.encode("utf-8")
        if not isinstance(raw_chunk, bytes):
            raise ValueError("A1 preflight packet chunk is not bytes")
        expected_size = (
            A1_PREFLIGHT_STORE_CHUNK_BYTES
            if index + 1 < chunk_count
            else payload_size - A1_PREFLIGHT_STORE_CHUNK_BYTES * (chunk_count - 1)
        )
        if len(raw_chunk) != expected_size:
            raise ValueError("A1 preflight packet chunk length drifted")
        chunks.append(raw_chunk)
    encoded = b"".join(chunks)
    if len(encoded) != payload_size:
        raise ValueError("A1 preflight packet total length drifted")
    actual_sha256 = f"sha256:{hashlib.sha256(encoded).hexdigest()}"
    if actual_sha256 != manifest["payload_sha256"]:
        raise ValueError("A1 preflight packet digest drifted")
    packet = json.loads(encoded.decode("utf-8"))
    if not isinstance(packet, dict):
        raise ValueError("A1 preflight packet is not an object")
    return packet


def _coordinated_a1_memmap_preflight(
    data_path: str | Path,
    *,
    validation_manifest_path: str | Path | None,
    ddp: dict[str, int | bool],
    expected_descriptor_file_sha256: str | None = None,
    production_authority_preflight_completed: bool = True,
    _store: Any | None = None,
) -> dict[str, object] | None:
    """Verify an A1 corpus once for single-node DDP and fail closed on all ranks.

    Rank 0 publishes a small authenticated-metadata result through torchrun's
    CPU rendezvous store.  Peers never touch the large payload files during
    this preflight.  A rank-0 verification error, malformed response, store
    failure, or timeout stops the peer before CUDA/process-group setup.
    """

    if not _single_node_ddp_preflight_enabled(ddp):
        preflight_kwargs: dict[str, object] = {
            "validation_manifest_path": validation_manifest_path,
        }
        if expected_descriptor_file_sha256 is not None:
            preflight_kwargs["expected_descriptor_file_sha256"] = (
                expected_descriptor_file_sha256
            )
        if not production_authority_preflight_completed:
            preflight_kwargs["production_authority_preflight_completed"] = False
        return _preflight_a1_memmap_metadata(data_path, **preflight_kwargs)

    store = (
        _store
        if _store is not None
        else _a1_preflight_store(
            ddp,
            data_path=data_path,
            validation_manifest_path=validation_manifest_path,
        )
    )
    result_key = "result"
    if int(ddp.get("rank", 0)) == 0:
        try:
            preflight_kwargs = {
                "validation_manifest_path": validation_manifest_path,
            }
            if expected_descriptor_file_sha256 is not None:
                preflight_kwargs["expected_descriptor_file_sha256"] = (
                    expected_descriptor_file_sha256
                )
            if not production_authority_preflight_completed:
                preflight_kwargs["production_authority_preflight_completed"] = False
            metadata = _preflight_a1_memmap_metadata(
                data_path,
                **preflight_kwargs,
            )
            packet = {"schema_version": 1, "ok": True, "metadata": metadata}
        except BaseException as error:
            packet = {
                "schema_version": 1,
                "ok": False,
                "error_type": type(error).__name__,
                "error": str(error),
            }
            try:
                _publish_a1_preflight_packet(store, result_key, packet)
            except Exception as publish_error:
                raise SystemExit(
                    "rank 0 A1 preflight failed and its failure could not be "
                    f"published to peers: {publish_error}; original error: {error}"
                ) from error
            raise
        try:
            _publish_a1_preflight_packet(store, result_key, packet)
        except Exception as error:
            raise SystemExit(
                f"rank 0 could not publish successful A1 preflight: {error}"
            ) from error
        return metadata

    try:
        packet = _receive_a1_preflight_packet(store, result_key)
    except Exception as error:
        raise SystemExit(
            f"rank {ddp.get('rank')} could not receive rank-0 A1 preflight: {error}"
        ) from error
    if not isinstance(packet, dict) or packet.get("schema_version") != 1:
        raise SystemExit("rank-0 A1 preflight returned a malformed response")
    if packet.get("ok") is not True:
        raise SystemExit(
            "rank-0 A1 preflight failed: "
            f"{packet.get('error_type', 'error')}: {packet.get('error', '')}"
        )
    metadata = packet.get("metadata")
    if metadata is not None and not isinstance(metadata, dict):
        raise SystemExit("rank-0 A1 preflight returned malformed metadata")
    return metadata


def _game_seed_set_sha256(seeds: np.ndarray) -> str:
    canonical = np.sort(np.unique(np.asarray(seeds, dtype=np.int64))).astype(
        "<i8", copy=False
    )
    return f"sha256:{hashlib.sha256(canonical.tobytes()).hexdigest()}"


def _validation_contract_config_identity(
    validation_seed_contract: dict[str, object] | None,
) -> dict[str, str]:
    """Return the holdout fields that must bind config/resume identity.

    A sentinel can narrow metric evaluation while the full authenticated
    holdout remains excluded from training.  Bind both sets, plus the source
    contract bytes, so Adam/RNG state cannot resume after either surface
    changes.
    """

    if validation_seed_contract is None:
        return {
            "validation_contract_file_sha256": "",
            "validation_game_seed_set_sha256": "",
            "training_excluded_game_seed_set_sha256": "",
        }
    validation_seeds = np.asarray(
        validation_seed_contract["game_seeds"], dtype=np.int64
    )
    excluded_seeds = np.asarray(
        validation_seed_contract.get("excluded_game_seeds", validation_seeds),
        dtype=np.int64,
    )
    return {
        "validation_contract_file_sha256": str(
            validation_seed_contract.get("file_sha256", "")
        ),
        "validation_game_seed_set_sha256": _game_seed_set_sha256(
            validation_seeds
        ),
        "training_excluded_game_seed_set_sha256": _game_seed_set_sha256(
            excluded_seeds
        ),
    }


def _is_sha256(value: object) -> bool:
    return (
        isinstance(value, str)
        and value.startswith("sha256:")
        and len(value) == 71
        and all(character in "0123456789abcdef" for character in value[7:])
    )


def _load_validation_game_seed_manifest_for_training(
    path: str | Path,
    *,
    validation_fraction: float,
    validation_seed: int,
    validation_max_samples: int,
    validation_game_seed_ranges: list[tuple[int, int]],
) -> dict[str, object]:
    """Validate the exact A1 holdout before any optimizer step can run.

    This input is deliberately stricter than the trainer's output manifest.
    It is the immutable sidecar emitted by ``a1_pre_wave_contract.py audit``
    and binds the exact validation games, their byte-level seed digest, and
    the A1 contract that selected the corpus.  Recomputing a nominally equal
    5% split and comparing only after training would detect drift too late.
    """

    try:
        manifest_path = Path(path).expanduser().resolve(strict=True)
        raw = manifest_path.read_bytes()
    except OSError as error:
        raise SystemExit(
            f"cannot read validation game-seed manifest {path}: {error}"
        ) from error
    try:
        payload = json.loads(raw)
    except (UnicodeDecodeError, json.JSONDecodeError) as error:
        raise SystemExit(
            f"cannot parse validation game-seed manifest {manifest_path}: {error}"
        ) from error
    if not isinstance(payload, dict):
        raise SystemExit("validation game-seed manifest must be a JSON object")
    expected_fields = {
        "schema_version",
        "a1_contract_sha256",
        "validation_fraction",
        "validation_seed",
        "validation_max_samples",
        "validation_game_seed_ranges",
        "validation_game_seed_count",
        "validation_row_count",
        "validation_game_seed_set_sha256",
        "game_seeds",
    }
    if set(payload) != expected_fields:
        raise SystemExit(
            "validation game-seed manifest fields differ from the exact "
            "train-validation-game-seeds-v1 schema; "
            f"missing={sorted(expected_fields - set(payload))} "
            f"extra={sorted(set(payload) - expected_fields)}"
        )
    if payload["schema_version"] != "train-validation-game-seeds-v1":
        raise SystemExit(
            "validation game-seed manifest schema must be "
            "'train-validation-game-seeds-v1'"
        )
    if not _is_sha256(payload["a1_contract_sha256"]):
        raise SystemExit("validation game-seed manifest has invalid a1_contract_sha256")

    manifest_fraction = payload["validation_fraction"]
    if isinstance(manifest_fraction, bool) or not isinstance(
        manifest_fraction, (int, float)
    ):
        raise SystemExit("validation game-seed manifest validation_fraction is invalid")
    if not math.isclose(
        float(manifest_fraction),
        float(validation_fraction),
        rel_tol=0.0,
        abs_tol=1e-12,
    ):
        raise SystemExit(
            "validation game-seed manifest fraction differs from CLI: "
            f"manifest={manifest_fraction} cli={validation_fraction}"
        )
    for field, cli_value in (
        ("validation_seed", validation_seed),
        ("validation_max_samples", validation_max_samples),
    ):
        value = payload[field]
        if isinstance(value, bool) or not isinstance(value, int):
            raise SystemExit(f"validation game-seed manifest {field} is invalid")
        if int(value) != int(cli_value):
            raise SystemExit(
                f"validation game-seed manifest {field} differs from CLI: "
                f"manifest={value} cli={cli_value}"
            )
    if int(validation_max_samples) != 0:
        raise SystemExit(
            "--validation-game-seed-manifest requires --validation-max-samples 0; "
            "row-capping an exact game holdout would change its semantics"
        )
    if validation_game_seed_ranges:
        raise SystemExit(
            "--validation-game-seed-manifest and --validation-game-seed-ranges "
            "are mutually exclusive"
        )
    if payload["validation_game_seed_ranges"] != []:
        raise SystemExit(
            "A1 validation game-seed manifest must declare no range override"
        )

    raw_seeds = payload["game_seeds"]
    if not isinstance(raw_seeds, list) or not raw_seeds:
        raise SystemExit("validation game-seed manifest has no game_seeds")
    if any(isinstance(seed, bool) or not isinstance(seed, int) for seed in raw_seeds):
        raise SystemExit("validation game-seed manifest game_seeds must be integers")
    try:
        seeds = np.asarray(raw_seeds, dtype=np.int64)
    except (OverflowError, TypeError, ValueError) as error:
        raise SystemExit(
            "validation game-seed manifest contains a seed outside int64"
        ) from error
    if not np.all(seeds[1:] > seeds[:-1]):
        raise SystemExit(
            "validation game-seed manifest game_seeds must be strictly sorted and unique"
        )
    count = payload["validation_game_seed_count"]
    if isinstance(count, bool) or not isinstance(count, int) or int(count) != len(seeds):
        raise SystemExit(
            "validation game-seed manifest validation_game_seed_count does not "
            f"match its seed list ({count!r} != {len(seeds)})"
        )
    row_count = payload["validation_row_count"]
    if isinstance(row_count, bool) or not isinstance(row_count, int) or row_count <= 0:
        raise SystemExit("validation game-seed manifest validation_row_count is invalid")
    actual_digest = _game_seed_set_sha256(seeds)
    if payload["validation_game_seed_set_sha256"] != actual_digest:
        raise SystemExit(
            "validation game-seed manifest seed digest mismatch: "
            f"declared={payload['validation_game_seed_set_sha256']!r} "
            f"actual={actual_digest!r}"
        )
    return {
        "path": manifest_path,
        "file_sha256": f"sha256:{hashlib.sha256(raw).hexdigest()}",
        "manifest_sha256": _canonical_json_sha256(payload),
        "a1_contract_sha256": payload["a1_contract_sha256"],
        "validation_game_seed_count": int(count),
        "validation_row_count": int(row_count),
        "validation_game_seed_set_sha256": actual_digest,
        "game_seeds": seeds,
    }


def _load_composite_validation_contract(
    composite_meta: dict[str, object],
    *,
    validation_fraction: float,
    validation_seed: int,
    validation_max_samples: int,
    validation_game_seed_ranges: list[tuple[int, int]],
) -> dict[str, object]:
    """Validate both bound holdouts and return their game-disjoint union."""
    raw_components = composite_meta.get("components")
    if not isinstance(raw_components, list) or len(raw_components) < 2:
        raise SystemExit("authenticated memmap composite metadata has invalid components")
    contracts: list[dict[str, object]] = []
    seen: set[int] = set()
    union: list[int] = []
    total_rows = 0
    bindings: list[dict[str, object]] = []
    for index, component in enumerate(raw_components):
        if not isinstance(component, dict):
            raise SystemExit(f"memmap composite component {index} metadata is malformed")
        contract = _load_validation_game_seed_manifest_for_training(
            component["validation_manifest"],
            validation_fraction=validation_fraction,
            validation_seed=validation_seed,
            validation_max_samples=validation_max_samples,
            validation_game_seed_ranges=validation_game_seed_ranges,
        )
        if contract["file_sha256"] != component["validation_manifest_sha256"]:
            raise SystemExit(f"memmap composite component {index} validation manifest binding drift")
        _validate_a1_validation_manifest_corpus_binding(component["corpus_meta"], contract)
        seeds = [int(seed) for seed in np.asarray(contract["game_seeds"], dtype=np.int64)]
        overlap = seen.intersection(seeds)
        if overlap:
            raise SystemExit(
                "memmap composite validation game seeds are not disjoint: "
                f"component={index} overlap_count={len(overlap)}"
            )
        seen.update(seeds)
        union.extend(seeds)
        total_rows += int(contract["validation_row_count"])
        contracts.append(contract)
        bindings.append({
            "a1_contract_sha256": contract["a1_contract_sha256"],
            "manifest_sha256": contract["manifest_sha256"],
            "validation_game_seed_set_sha256": contract["validation_game_seed_set_sha256"],
        })
    union_seeds = np.sort(np.asarray(union, dtype=np.int64))
    return {
        "path": Path(str(composite_meta["descriptor_path"])),
        "file_sha256": composite_meta["descriptor_file_sha256"],
        "manifest_sha256": _canonical_json_sha256(bindings),
        "a1_contract_sha256": _canonical_json_sha256(
            [binding["a1_contract_sha256"] for binding in bindings]
        ),
        "validation_row_count": total_rows,
        "validation_game_seed_set_sha256": _game_seed_set_sha256(union_seeds),
        "game_seeds": union_seeds,
        "component_contracts": contracts,
        "diagnostic_only": True,
        "promotion_eligible": False,
    }


def _load_composite_validation_sentinel_manifest(
    path: str | Path,
    *,
    composite_meta: dict[str, object],
    full_contract: dict[str, object],
) -> dict[str, object]:
    """Authenticate a whole-game subset of a composite's full holdout.

    The returned contract deliberately retains ``excluded_game_seeds`` as the
    complete authenticated holdout. Only ``game_seeds`` is narrowed for metric
    evaluation, so unused sentinel games can never leak back into training.
    """
    if int(full_contract.get("validation_row_count", 0)) <= 0:
        raise SystemExit("cannot derive a sentinel from an empty validation contract")
    try:
        manifest_path = Path(path).expanduser().resolve(strict=True)
        raw = manifest_path.read_bytes()
        payload = json.loads(raw)
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load validation sentinel manifest {path}: {error}") from error
    expected_fields = {
        "schema_version", "source_composite_descriptor_file_sha256",
        "source_composite_descriptor_fingerprint", "source_validation_bindings",
        "selection_seed", "target_row_count", "selected_row_count",
        "selected_game_seed_count", "selected_game_seed_set_sha256",
        "excluded_game_seed_count", "excluded_game_seed_set_sha256", "game_seeds",
    }
    if not isinstance(payload, dict) or set(payload) != expected_fields:
        raise SystemExit("validation sentinel manifest fields differ from its schema")
    if payload["schema_version"] != "train-validation-game-sentinel-v1":
        raise SystemExit("validation sentinel manifest schema is unsupported")
    for field in (
        "selection_seed", "target_row_count", "selected_row_count",
        "selected_game_seed_count", "excluded_game_seed_count",
    ):
        value = payload[field]
        if isinstance(value, bool) or not isinstance(value, int):
            raise SystemExit(f"validation sentinel manifest {field} is invalid")
    if payload["target_row_count"] <= 0 or payload["selected_row_count"] <= 0:
        raise SystemExit("validation sentinel row counts must be positive")
    if payload["source_composite_descriptor_file_sha256"] != composite_meta.get(
        "descriptor_file_sha256"
    ) or payload["source_composite_descriptor_fingerprint"] != composite_meta.get(
        "descriptor_fingerprint"
    ):
        raise SystemExit("validation sentinel source composite binding drift")

    contracts = full_contract.get("component_contracts")
    if not isinstance(contracts, list):
        raise SystemExit("validation sentinel source has no component contracts")
    expected_bindings = [
        {
            "component_index": index,
            "validation_manifest_file_sha256": contract["file_sha256"],
            "validation_manifest_sha256": contract["manifest_sha256"],
            "validation_game_seed_set_sha256": contract[
                "validation_game_seed_set_sha256"
            ],
        }
        for index, contract in enumerate(contracts)
    ]
    if payload["source_validation_bindings"] != expected_bindings:
        raise SystemExit("validation sentinel source manifest binding drift")

    raw_seeds = payload["game_seeds"]
    if (
        not isinstance(raw_seeds, list)
        or not raw_seeds
        or any(isinstance(seed, bool) or not isinstance(seed, int) for seed in raw_seeds)
    ):
        raise SystemExit("validation sentinel game_seeds must be non-empty integers")
    try:
        selected = np.asarray(raw_seeds, dtype=np.int64)
    except (OverflowError, TypeError, ValueError) as error:
        raise SystemExit("validation sentinel contains a seed outside int64") from error
    if not np.all(selected[1:] > selected[:-1]):
        raise SystemExit("validation sentinel game_seeds must be strictly sorted and unique")
    full = np.asarray(full_contract["game_seeds"], dtype=np.int64)
    if not set(map(int, selected)).issubset(set(map(int, full))):
        raise SystemExit("validation sentinel contains games outside the authenticated holdout")
    if payload["selected_game_seed_count"] != int(selected.size):
        raise SystemExit("validation sentinel selected game count mismatch")
    selected_digest = _game_seed_set_sha256(selected)
    if payload["selected_game_seed_set_sha256"] != selected_digest:
        raise SystemExit("validation sentinel selected seed digest mismatch")
    if (
        payload["excluded_game_seed_count"] != int(full.size)
        or payload["excluded_game_seed_set_sha256"]
        != full_contract["validation_game_seed_set_sha256"]
    ):
        raise SystemExit("validation sentinel full-holdout exclusion binding drift")

    return {
        **full_contract,
        "path": manifest_path,
        "file_sha256": f"sha256:{hashlib.sha256(raw).hexdigest()}",
        "manifest_sha256": _canonical_json_sha256(payload),
        "validation_row_count": int(payload["selected_row_count"]),
        "validation_game_seed_set_sha256": selected_digest,
        "game_seeds": selected,
        "excluded_game_seeds": full,
        "full_validation_row_count": int(full_contract["validation_row_count"]),
        "sentinel_target_row_count": int(payload["target_row_count"]),
        "sentinel_selection_seed": int(payload["selection_seed"]),
    }


def _validate_a1_validation_manifest_corpus_binding(
    corpus_meta: object, validation_seed_contract: dict[str, object]
) -> None:
    """Require the exact audited corpus selected by the holdout's A1 contract."""

    if not isinstance(corpus_meta, dict):
        raise SystemExit(
            "--validation-game-seed-manifest requires memmap corpus metadata"
        )
    selected_meta = corpus_meta.get("selected_game_seed_manifest")
    if not isinstance(selected_meta, dict):
        raise SystemExit(
            "the memmap corpus does not bind an audited A1 selected-game manifest"
        )
    expected_contract = str(validation_seed_contract["a1_contract_sha256"])
    if selected_meta.get("a1_contract_sha256") != expected_contract:
        raise SystemExit(
            "validation holdout and memmap corpus bind different A1 contracts: "
            f"holdout={expected_contract!r} "
            f"corpus={selected_meta.get('a1_contract_sha256')!r}"
        )
    audit_meta = corpus_meta.get("a1_post_wave_audit")
    if not isinstance(audit_meta, dict):
        raise SystemExit(
            "the memmap corpus does not bind a passing A1 post-wave audit"
        )
    if audit_meta.get("contract_sha256") != expected_contract:
        raise SystemExit(
            "A1 post-wave audit and validation holdout bind different contracts"
        )
    if not _is_sha256(audit_meta.get("file_sha256")) or not _is_sha256(
        audit_meta.get("audit_sha256")
    ):
        raise SystemExit("memmap A1 post-wave audit provenance is malformed")
    validation_meta = audit_meta.get("validation_holdout")
    if not isinstance(validation_meta, dict):
        raise SystemExit(
            "memmap A1 post-wave audit does not bind the validation sidecar"
        )
    expected_validation_binding = {
        "path": str(validation_seed_contract["path"]),
        "file_sha256": validation_seed_contract["file_sha256"],
        "manifest_sha256": validation_seed_contract["manifest_sha256"],
        "a1_contract_sha256": validation_seed_contract["a1_contract_sha256"],
        "validation_game_seed_count": int(
            np.asarray(validation_seed_contract["game_seeds"], dtype=np.int64).size
        ),
        "validation_row_count": int(validation_seed_contract["validation_row_count"]),
        "validation_game_seed_set_sha256": validation_seed_contract[
            "validation_game_seed_set_sha256"
        ],
    }
    if validation_meta != expected_validation_binding:
        raise SystemExit(
            "trainer validation sidecar differs from the exact file bound by the "
            "A1 post-wave audit"
        )
    dual_identity = (selected_meta.get("arm_id"), selected_meta.get("subset_id"))
    expected_selected_count = DUAL_ARM_SUBSET_COUNTS.get(dual_identity)
    if expected_selected_count is None:
        expected_selected_count = 12_000
        if any(value is not None for value in dual_identity):
            raise SystemExit("A1 memmap corpus has an invalid dual-arm identity")
    if selected_meta.get("selected_game_count") != expected_selected_count:
        raise SystemExit(
            "A1 memmap corpus selected-game count differs from its exact "
            f"contract ({selected_meta.get('selected_game_count')!r} != "
            f"{expected_selected_count})"
        )
    expected_validation_count = int(
        np.asarray(validation_seed_contract["game_seeds"], dtype=np.int64).size
    )
    if selected_meta.get("validation_game_count") != expected_validation_count:
        raise SystemExit(
            "validation holdout game count differs from the selected-game manifest "
            "bound into corpus_meta.json"
        )
    selected_validation_digest = selected_meta.get(
        "validation_game_seed_set_sha256"
    )
    if selected_validation_digest != validation_seed_contract[
        "validation_game_seed_set_sha256"
    ]:
        raise SystemExit(
            "validation holdout seed digest differs from the selected-game "
            "manifest bound into corpus_meta.json"
        )


def _read_sha256_bound_json(
    path_value: object, expected_file_sha256: object, *, label: str
) -> tuple[Path, dict[str, object], str]:
    try:
        path = Path(str(path_value)).expanduser().resolve(strict=True)
        raw = path.read_bytes()
        payload = json.loads(raw)
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot read bound {label} {path_value}: {error}") from error
    actual_file_sha256 = f"sha256:{hashlib.sha256(raw).hexdigest()}"
    if actual_file_sha256 != expected_file_sha256:
        raise SystemExit(
            f"bound {label} file SHA-256 drift: "
            f"expected={expected_file_sha256!r} actual={actual_file_sha256!r}"
        )
    if not isinstance(payload, dict):
        raise SystemExit(f"bound {label} must be a JSON object")
    return path, payload, actual_file_sha256


def _validate_dual_arm_corpus_artifacts_and_seeds(
    corpus_meta: dict[str, object],
    validation_seed_contract: dict[str, object],
    game_seed_column: np.ndarray,
) -> dict[str, object]:
    """Replay the dual-arm selection/audit chain before optimizer creation.

    This is deliberately separate from the historical 12k validator below:
    accepting a typed dual-arm corpus must not relax one byte of the frozen
    A1 path.
    """

    selected_meta = corpus_meta["selected_game_seed_manifest"]
    audit_meta = corpus_meta["a1_post_wave_audit"]
    assert isinstance(selected_meta, dict) and isinstance(audit_meta, dict)
    identity = (selected_meta.get("arm_id"), selected_meta.get("subset_id"))
    expected_count = DUAL_ARM_SUBSET_COUNTS.get(identity)
    if expected_count is None:
        raise SystemExit("dual-arm corpus has an unauthorized arm/subset identity")

    selected_path, selected_payload, _ = _read_sha256_bound_json(
        selected_meta.get("path"),
        selected_meta.get("file_sha256"),
        label="dual-arm selected-game manifest",
    )
    if selected_payload.get("schema_version") != DUAL_ARM_SELECTED_GAMES_SCHEMA:
        raise SystemExit("dual-arm selected-game manifest schema drift")
    expected_selected_fields = {
        "schema_version",
        "arm_id",
        "subset_id",
        "a1_contract_sha256",
        "selection_rule",
        "selected_game_count",
        "selected_game_seed_set_sha256",
        "category_game_counts",
        "training_game_count",
        "training_game_seed_set_sha256",
        "validation_game_count",
        "validation_game_seed_set_sha256",
        "records_sha256",
        "records",
        "parent_manifest_sha256",
    }
    if set(selected_payload) != expected_selected_fields:
        raise SystemExit("dual-arm selected-game manifest fields drift")
    if (selected_payload.get("arm_id"), selected_payload.get("subset_id")) != identity:
        raise SystemExit("dual-arm selected-game manifest identity drift")
    expected_categories = DUAL_ARM_SUBSET_CATEGORY_COUNTS.get(identity)
    if selected_payload.get("category_game_counts") != expected_categories:
        raise SystemExit("dual-arm selected-game category quotas drift")
    parent_manifest_sha = selected_payload.get("parent_manifest_sha256")
    is_full = identity[1] in {"full-56k", "full-140k"}
    if (is_full and parent_manifest_sha is not None) or (
        not is_full and not _is_sha256(parent_manifest_sha)
    ):
        raise SystemExit("dual-arm selected-game parent provenance drift")
    records = selected_payload.get("records")
    if not isinstance(records, list) or len(records) != expected_count:
        raise SystemExit(
            f"dual-arm selected-game manifest must contain exactly {expected_count} records"
        )
    if selected_payload.get("records_sha256") != _canonical_json_sha256(records):
        raise SystemExit("dual-arm selected-game records_sha256 mismatch")

    all_seeds: list[int] = []
    train_seeds: list[int] = []
    validation_seeds: list[int] = []
    producer_shas: set[str] = set()
    category_counts = {category: 0 for category in expected_categories or {}}
    previous: tuple[int, str] | None = None
    for index, record in enumerate(records):
        if not isinstance(record, dict) or record.get("arm_id") != identity[0]:
            raise SystemExit(f"dual-arm selected-game record {index} identity drift")
        seed, job_id, split = (
            record.get("game_seed"),
            record.get("job_id"),
            record.get("split"),
        )
        if (
            isinstance(seed, bool)
            or not isinstance(seed, int)
            or not isinstance(job_id, str)
            or not job_id
            or split not in {"train", "validation"}
        ):
            raise SystemExit(f"dual-arm selected-game record {index} is malformed")
        key = (int(seed), job_id)
        if previous is not None and key <= previous:
            raise SystemExit("dual-arm selected-game records are not strictly sorted")
        previous = key
        producer_sha = record.get("producer_checkpoint_sha256")
        if not _is_sha256(producer_sha):
            raise SystemExit(f"dual-arm selected-game record {index} producer drift")
        producer_shas.add(str(producer_sha))
        category = record.get("category")
        if category not in category_counts:
            raise SystemExit(f"dual-arm selected-game record {index} category drift")
        category_counts[str(category)] += 1
        all_seeds.append(int(seed))
        (train_seeds if split == "train" else validation_seeds).append(int(seed))
    if len(set(all_seeds)) != len(all_seeds) or len(producer_shas) != 1:
        raise SystemExit("dual-arm selected-game seed or producer identity drift")
    if category_counts != expected_categories:
        raise SystemExit("dual-arm selected-game record category quotas drift")

    digest_fields = {
        "selected_game_count": len(all_seeds),
        "selected_game_seed_set_sha256": _game_seed_set_sha256(
            np.asarray(all_seeds, dtype=np.int64)
        ),
        "training_game_count": len(train_seeds),
        "training_game_seed_set_sha256": _game_seed_set_sha256(
            np.asarray(train_seeds, dtype=np.int64)
        ),
        "validation_game_count": len(validation_seeds),
        "validation_game_seed_set_sha256": _game_seed_set_sha256(
            np.asarray(validation_seeds, dtype=np.int64)
        ),
        "records_sha256": _canonical_json_sha256(records),
    }
    for field, actual in digest_fields.items():
        if selected_payload.get(field) != actual or selected_meta.get(field) != actual:
            raise SystemExit(f"dual-arm selected-game {field} drift")
    if not np.array_equal(
        np.asarray(validation_seeds, dtype=np.int64),
        np.asarray(validation_seed_contract["game_seeds"], dtype=np.int64),
    ):
        raise SystemExit("dual-arm selected validation split differs from holdout")

    observed = np.asarray(game_seed_column, dtype=np.int64).reshape(-1)
    if observed.size == 0 or not np.array_equal(
        np.sort(np.unique(observed)), np.asarray(all_seeds, dtype=np.int64)
    ):
        raise SystemExit("dual-arm memmap game-seed set differs from its selection")
    run_starts = np.concatenate(
        (np.asarray([0]), np.flatnonzero(observed[1:] != observed[:-1]) + 1)
    )
    if np.unique(observed[run_starts]).size != run_starts.size:
        raise SystemExit("dual-arm memmap repeats a non-contiguous game seed run")

    audit_path, audit_payload, _ = _read_sha256_bound_json(
        audit_meta.get("path"), audit_meta.get("file_sha256"), label="dual-arm audit"
    )
    audit_schema = audit_payload.get("schema_version")
    if (
        audit_schema not in DUAL_ARM_AUDIT_SCHEMAS
        or audit_payload.get("passed") is not True
        or audit_payload.get("errors") != []
        or (audit_payload.get("arm_id"), audit_payload.get("subset_id")) != identity
    ):
        raise SystemExit("dual-arm audit is not a clean matching authorization")
    actual_audit_sha = _canonical_json_sha256(
        {key: value for key, value in audit_payload.items() if key != "audit_sha256"}
    )
    if (
        audit_payload.get("audit_sha256") != actual_audit_sha
        or audit_meta.get("audit_sha256") != actual_audit_sha
    ):
        raise SystemExit("dual-arm audit semantic digest drift")
    if audit_schema == "a1-dual-arm-derived-post-wave-audit-v1":
        parent_binding = audit_payload.get("parent_audit")
        if not isinstance(parent_binding, dict) or set(parent_binding) != {
            "path",
            "file_sha256",
            "audit_sha256",
            "selected_manifest_file_sha256",
            "shard_inventory_sha256",
        }:
            raise SystemExit("derived dual-arm audit parent binding drift")
        parent_path, parent_payload, _ = _read_sha256_bound_json(
            parent_binding.get("path"),
            parent_binding.get("file_sha256"),
            label="parent dual-arm audit",
        )
        parent_audit_sha = _canonical_json_sha256(
            {key: value for key, value in parent_payload.items() if key != "audit_sha256"}
        )
        parent_selected = parent_payload.get("selected_training_games")
        if (
            parent_payload.get("schema_version") != "a1-dual-arm-post-wave-audit-v1"
            or parent_payload.get("passed") is not True
            or parent_payload.get("errors") != []
            or parent_payload.get("audit_sha256") != parent_audit_sha
            or parent_binding.get("audit_sha256") != parent_audit_sha
            or parent_payload.get("arm_id") != identity[0]
            or parent_payload.get("contract_sha256")
            != audit_payload.get("contract_sha256")
            or parent_payload.get("shard_inventory_sha256")
            != parent_binding.get("shard_inventory_sha256")
            or audit_payload.get("shard_inventory_sha256")
            != parent_binding.get("shard_inventory_sha256")
            or not isinstance(parent_selected, dict)
            or parent_selected.get("manifest_file_sha256")
            != parent_binding.get("selected_manifest_file_sha256")
            or parent_manifest_sha
            != parent_binding.get("selected_manifest_file_sha256")
            or not parent_path.is_file()
        ):
            raise SystemExit("derived dual-arm audit parent authorization drift")
    contract_sha = validation_seed_contract["a1_contract_sha256"]
    if (
        audit_payload.get("contract_sha256") != contract_sha
        or audit_meta.get("contract_sha256") != contract_sha
        or selected_payload.get("a1_contract_sha256") != contract_sha
    ):
        raise SystemExit("dual-arm audit/selection/holdout contract mismatch")
    validation_row_count = int(validation_seed_contract["validation_row_count"])
    if (
        audit_payload.get("rows") != int(observed.size)
        or corpus_meta.get("row_count") != int(observed.size)
        or audit_meta.get("selected_row_count") != int(observed.size)
        or audit_meta.get("training_row_count")
        != int(observed.size) - validation_row_count
    ):
        raise SystemExit("dual-arm memmap row exposure differs from its audit")
    expected_selected_binding = {
        "manifest": str(selected_path),
        "manifest_sha256": _canonical_json_sha256(selected_payload),
        "manifest_file_sha256": selected_meta["file_sha256"],
        "selected_game_count": expected_count,
        "selected_game_seed_set_sha256": digest_fields[
            "selected_game_seed_set_sha256"
        ],
        "records_sha256": digest_fields["records_sha256"],
    }
    if audit_payload.get("selected_training_games") != expected_selected_binding:
        raise SystemExit("dual-arm audit selected-game binding drift")
    expected_validation_binding = {
        "manifest": str(validation_seed_contract["path"]),
        "manifest_sha256": validation_seed_contract["manifest_sha256"],
        "manifest_file_sha256": validation_seed_contract["file_sha256"],
        "validation_game_seed_count": len(validation_seeds),
        "validation_game_seed_set_sha256": digest_fields[
            "validation_game_seed_set_sha256"
        ],
    }
    if audit_payload.get("validation_holdout") != expected_validation_binding:
        raise SystemExit("dual-arm audit validation binding drift")

    # The dual learner keeps the proven A1 objective/optimizer recipe while
    # changing only topology: 8 ranks x 512 local = the same global batch 4096.
    # ``train_bc.py`` is launched by torchrun as a file path, so sys.path[0]
    # is ``tools/`` rather than the repository root.  Import the sibling
    # through the tools-directory bootstrap above; a ``tools.*`` import only
    # works accidentally when callers inject the repository into PYTHONPATH.
    from a1_pre_wave_contract import EXPECTED_LEARNER_TRAINING_RECIPE

    recipe = dict(EXPECTED_LEARNER_TRAINING_RECIPE)
    recipe.update({"batch_size": 512, "world_size": 8, "global_batch_size": 4096})
    repo = Path(__file__).resolve().parents[1]
    learner_snapshot = [
        {"path": suffix, "sha256": _sha256_existing_file(repo / suffix)}
        for suffix in sorted(A1_REQUIRED_LEARNER_CODE_SUFFIXES)
    ]
    runtime_snapshot = [
        {"path": suffix, "sha256": _sha256_existing_file(repo / suffix)}
        for suffix in sorted(A1_REQUIRED_RUNTIME_CODE_SUFFIXES)
    ]
    return {
        "dual_arm": True,
        "arm_id": identity[0],
        "subset_id": identity[1],
        "learner_value_objective": {"objective": "mse", "value_readout": "scalar"},
        "learner_training_recipe": recipe,
        "learner_training_recipe_sha256": _canonical_json_sha256(recipe),
        "learner_code_sha256": _canonical_json_sha256(learner_snapshot),
        "runtime_code_tree_sha256": _canonical_json_sha256(runtime_snapshot),
        "producer_checkpoint_sha256": next(iter(producer_shas)),
        "selected_game_seed_set_sha256": digest_fields[
            "selected_game_seed_set_sha256"
        ],
        "training_game_seed_set_sha256": digest_fields[
            "training_game_seed_set_sha256"
        ],
        "audit_file_sha256": _sha256_existing_file(audit_path),
    }


COHERENT_DIRECT_CORPUS_BINDING_SCHEMA = (
    "a1-coherent-direct-memmap-learner-binding-v1"
)
COHERENT_DIRECT_UPGRADE_MODULE = (
    "entity_graph.static_action_residual+legal_action_value_residual+"
    "public_card_count_features+meaningful_public_history.v3"
)


def _validate_coherent_direct_corpus_binding(
    raw_binding: str,
    *,
    data_path: str | Path,
    corpus_meta: dict[str, object],
    validation_seed_contract: dict[str, object],
    game_seed_column: np.ndarray,
) -> dict[str, object]:
    """Replay the typed 8,192-game coherent-corpus binding.

    The historical A1 path intentionally remains frozen at its 12,000-game
    selected/audit schema.  This diagnostic-only path admits the new coherent
    public-belief corpus without pretending it is legacy A1 data.  The caller
    must supply a binding emitted by the sealed one-dose executor; this
    function independently checks the memmap bytes, exact seed population,
    holdout, recipe, and non-promotion role before optimizer construction.
    """

    try:
        binding = json.loads(raw_binding)
    except json.JSONDecodeError as error:
        raise SystemExit(f"invalid coherent corpus binding JSON: {error}") from error
    expected_fields = {
        "schema_version",
        "diagnostic_only",
        "promotion_eligible",
        "corpus_admission",
        "target_contract_sha256",
        "producer_checkpoint_sha256",
        "learner_initializer",
        "corpus",
        "validation",
        "learner",
        "binding_sha256",
    }
    if not isinstance(binding, dict) or set(binding) != expected_fields:
        raise SystemExit("coherent corpus binding fields/schema drift")
    unsigned = dict(binding)
    stated = unsigned.pop("binding_sha256", None)
    if (
        binding.get("schema_version") != COHERENT_DIRECT_CORPUS_BINDING_SCHEMA
        or binding.get("diagnostic_only") is not True
        or binding.get("promotion_eligible") is not False
        or stated != _canonical_json_sha256(unsigned)
    ):
        raise SystemExit("coherent corpus binding digest/role drift")

    corpus = binding.get("corpus")
    validation = binding.get("validation")
    learner = binding.get("learner")
    learner_initializer = binding.get("learner_initializer")
    if not all(
        isinstance(value, dict)
        for value in (corpus, validation, learner, learner_initializer)
    ):
        raise SystemExit("coherent corpus binding sections are malformed")
    expected_initializer_fields = {
        "role",
        "parent_checkpoint_sha256",
        "initializer_checkpoint_sha256",
        "upgrade_module",
        "upgrade_receipt_file_sha256",
        "upgrade_receipt_sha256",
        "independent_parent_authority_sha256",
    }
    if (
        set(learner_initializer) != expected_initializer_fields
        or learner_initializer.get("role") != "diagnostic_independent_parent"
        or learner_initializer.get("upgrade_module")
        != COHERENT_DIRECT_UPGRADE_MODULE
        or any(
            not _is_sha256(learner_initializer.get(field))
            for field in expected_initializer_fields - {"role", "upgrade_module"}
        )
        or learner_initializer.get("parent_checkpoint_sha256")
        == binding.get("producer_checkpoint_sha256")
    ):
        raise SystemExit("coherent learner parent/initializer authority drift")
    root = Path(data_path).expanduser().resolve(strict=True)
    meta_path = root / "corpus_meta.json"
    if (
        corpus.get("path") != str(root)
        or corpus.get("corpus_meta_file_sha256") != _sha256_existing_file(meta_path)
        or corpus.get("payload_inventory_sha256")
        != corpus_meta.get("payload_inventory_sha256")
    ):
        raise SystemExit("coherent corpus binding differs from loaded memmap bytes")
    _validate_memmap_payload_inventory(root, corpus_meta)

    target_contract_sha = binding.get("target_contract_sha256")
    if (
        not _is_sha256(target_contract_sha)
        or validation_seed_contract.get("a1_contract_sha256")
        != target_contract_sha
        or validation.get("path") != str(validation_seed_contract["path"])
        or validation.get("file_sha256")
        != validation_seed_contract["file_sha256"]
        or validation.get("game_count")
        != validation_seed_contract["validation_game_seed_count"]
        or validation.get("game_seed_set_sha256")
        != validation_seed_contract["validation_game_seed_set_sha256"]
        or validation.get("row_count")
        != validation_seed_contract["validation_row_count"]
    ):
        raise SystemExit("coherent corpus binding differs from exact whole-game holdout")

    observed = np.asarray(game_seed_column, dtype=np.int64).reshape(-1)
    if observed.size == 0:
        raise SystemExit("coherent memmap corpus has no game_seed rows")
    run_starts = np.concatenate(
        (np.asarray([0], dtype=np.int64), np.flatnonzero(observed[1:] != observed[:-1]) + 1)
    )
    run_values = observed[run_starts]
    if np.unique(run_values).size != run_values.size:
        raise SystemExit("coherent memmap contains non-contiguous duplicate game runs")
    selected = np.sort(np.unique(observed))
    expected_games = int(corpus.get("selected_game_count", -1))
    if (
        expected_games <= 0
        or selected.size != expected_games
        or corpus.get("selected_game_seed_set_sha256")
        != _game_seed_set_sha256(selected)
    ):
        raise SystemExit("coherent memmap seed population differs from its sealed seed set")

    validation_seeds = np.asarray(
        validation_seed_contract["game_seeds"], dtype=np.int64
    )
    if not np.isin(validation_seeds, selected).all():
        raise SystemExit("coherent validation holdout contains a seed outside the corpus")
    training_seeds = selected[~np.isin(selected, validation_seeds)]
    if (
        corpus.get("training_game_count") != int(training_seeds.size)
        or corpus.get("training_game_seed_set_sha256")
        != _game_seed_set_sha256(training_seeds)
        or int(np.count_nonzero(np.isin(observed, validation_seeds)))
        != int(validation_seed_contract["validation_row_count"])
    ):
        raise SystemExit("coherent corpus training/validation split binding drift")

    recipe = learner.get("training_recipe")
    objective = learner.get("value_objective")
    topology = learner.get("topology")
    expected_topology = {
        "name": "b200-8gpu-ddp",
        "world_size": 8,
        "local_batch_size": 512,
        "grad_accum_steps": 1,
        "global_batch_size": 4096,
    }
    if (
        not isinstance(recipe, dict)
        or learner.get("training_recipe_sha256")
        != _canonical_json_sha256(recipe)
        or objective
        != {
            "objective": "mse",
            "value_readout": "scalar",
            "value_categorical_bins": None,
            "hlgauss_sigma_ratio": None,
        }
        or topology != expected_topology
        or not _is_sha256(binding.get("producer_checkpoint_sha256"))
    ):
        raise SystemExit("coherent corpus learner recipe/objective binding drift")
    repo = Path(__file__).resolve().parents[1]
    learner_snapshot = [
        {"path": suffix, "sha256": _sha256_existing_file(repo / suffix)}
        for suffix in sorted(A1_REQUIRED_LEARNER_CODE_SUFFIXES)
    ]
    runtime_snapshot = [
        {"path": suffix, "sha256": _sha256_existing_file(repo / suffix)}
        for suffix in sorted(A1_REQUIRED_RUNTIME_CODE_SUFFIXES)
    ]
    return {
        "coherent_direct_corpus": True,
        "diagnostic_only": True,
        "promotion_eligible": False,
        "learner_value_objective": objective,
        "learner_training_recipe": recipe,
        "learner_training_recipe_sha256": _canonical_json_sha256(recipe),
        "learner_code_sha256": _canonical_json_sha256(learner_snapshot),
        "runtime_code_tree_sha256": _canonical_json_sha256(runtime_snapshot),
        "producer_checkpoint_sha256": binding["producer_checkpoint_sha256"],
        "learner_parent_checkpoint_sha256": learner_initializer[
            "parent_checkpoint_sha256"
        ],
        "learner_initializer_sha256": learner_initializer[
            "initializer_checkpoint_sha256"
        ],
        "selected_game_seed_set_sha256": corpus[
            "selected_game_seed_set_sha256"
        ],
        "training_game_seed_set_sha256": corpus[
            "training_game_seed_set_sha256"
        ],
        "coherent_corpus_binding_sha256": stated,
        "coherent_topology": expected_topology,
    }


def _validate_parent_policy_kl_authority(
    args: argparse.Namespace,
    training_binding: dict[str, object] | None,
) -> dict[str, object] | None:
    """Refuse an adaptive *parent* KL target backed by another producer.

    ``prior_policy`` is a row payload, not an online evaluation of the
    initializer.  A projected-dual controller can regulate KL to the stored
    producer while KL to the actual parent keeps growing, so calling that
    configuration a parent-policy trust region is false unless those
    authorities are identical.

    Bindings that expose both identities are checked regardless of their
    corpus schema. Older formats that do not expose both identities retain
    their existing optimization behavior, but the report labels the metric as
    stored-prior-only and diagnostic rather than silently claiming parent KL.
    """

    if getattr(args, "policy_kl_target", None) is None:
        return None
    producer = (
        training_binding.get("producer_checkpoint_sha256")
        if isinstance(training_binding, dict)
        else None
    )
    parent = (
        training_binding.get("learner_parent_checkpoint_sha256")
        if isinstance(training_binding, dict)
        else None
    ) or getattr(args, "init_checkpoint_sha256", None)
    initializer = (
        training_binding.get("learner_initializer_sha256")
        if isinstance(training_binding, dict)
        else None
    ) or getattr(args, "init_checkpoint_sha256", None)
    if producer is None or parent is None:
        return {
            "schema_version": "train-bc-parent-policy-kl-authority-v1",
            "status": "stored_prior_not_verified_as_parent",
            "metric_semantics": "stored_prior_policy_kl_not_parent_policy_kl",
            "diagnostic_only": True,
            "stored_prior_checkpoint_sha256": (
                producer if _is_sha256(producer) else None
            ),
            "parent_checkpoint_sha256": parent if _is_sha256(parent) else None,
            "initializer_checkpoint_sha256": (
                initializer if _is_sha256(initializer) else None
            ),
        }
    if not all(_is_sha256(value) for value in (producer, parent, initializer)):
        raise SystemExit(
            "adaptive parent-policy KL authority contains a malformed checkpoint identity"
        )
    if producer != parent:
        raise SystemExit(
            "--policy-kl-target cannot enforce a parent-policy trust region: "
            f"stored prior_policy rows come from corpus producer {producer}, "
            f"but the learner's exact parent is {parent} (initializer "
            f"{initializer}). Regenerate prior_policy from the exact parent or "
            "omit --policy-kl-target; a producer-policy KL target must not be "
            "reported as parent KL."
        )
    return {
        "schema_version": "train-bc-parent-policy-kl-authority-v1",
        "status": "verified_exact_parent",
        "identity_comparison": (
            "stored_prior_producer_vs_declared_causal_parent"
        ),
        "stored_prior_checkpoint_sha256": producer,
        "parent_checkpoint_sha256": parent,
        "initializer_checkpoint_sha256": initializer,
        "initializer_identity_differs_from_parent": initializer != parent,
    }


def _validate_a1_corpus_artifacts_and_seeds(
    corpus_meta: dict[str, object],
    validation_seed_contract: dict[str, object],
    game_seed_column: np.ndarray,
) -> dict[str, object]:
    """Replay the selected/audit/lock chain against the actual memmap seeds."""

    selected_meta = corpus_meta["selected_game_seed_manifest"]
    audit_meta = corpus_meta["a1_post_wave_audit"]
    assert isinstance(selected_meta, dict)
    assert isinstance(audit_meta, dict)

    if selected_meta.get("arm_id") is not None:
        return _validate_dual_arm_corpus_artifacts_and_seeds(
            corpus_meta, validation_seed_contract, game_seed_column
        )

    selected_path, selected_payload, _ = _read_sha256_bound_json(
        selected_meta.get("path"),
        selected_meta.get("file_sha256"),
        label="A1 selected-game manifest",
    )
    if str(selected_path) != str(selected_meta.get("path")):
        raise SystemExit("A1 selected-game manifest path is not canonical")
    if selected_payload.get("schema_version") != "a1-selected-training-games-v1":
        raise SystemExit("A1 selected-game manifest schema drift")
    if (
        selected_payload.get("a1_contract_sha256")
        != validation_seed_contract["a1_contract_sha256"]
    ):
        raise SystemExit("A1 selected-game manifest contract hash drift")
    records = selected_payload.get("records")
    if not isinstance(records, list) or len(records) != 12_000:
        raise SystemExit("A1 selected-game manifest must contain exactly 12,000 records")
    if selected_payload.get("records_sha256") != _canonical_json_sha256(records):
        raise SystemExit("A1 selected-game manifest records_sha256 mismatch")

    all_seeds: list[int] = []
    train_seeds: list[int] = []
    validation_seeds: list[int] = []
    previous_seed: int | None = None
    for index, record in enumerate(records):
        if not isinstance(record, dict):
            raise SystemExit(f"A1 selected-game record {index} is not an object")
        seed = record.get("game_seed")
        split = record.get("split")
        if isinstance(seed, bool) or not isinstance(seed, int):
            raise SystemExit(f"A1 selected-game record {index} has invalid game_seed")
        if previous_seed is not None and int(seed) <= previous_seed:
            raise SystemExit("A1 selected-game records are not strictly seed-sorted")
        previous_seed = int(seed)
        if split not in {"train", "validation"}:
            raise SystemExit(f"A1 selected-game record {index} has invalid split")
        all_seeds.append(int(seed))
        (train_seeds if split == "train" else validation_seeds).append(int(seed))

    digest_fields = {
        "selected_game_count": len(all_seeds),
        "selected_game_seed_set_sha256": _game_seed_set_sha256(
            np.asarray(all_seeds, dtype=np.int64)
        ),
        "training_game_count": len(train_seeds),
        "training_game_seed_set_sha256": _game_seed_set_sha256(
            np.asarray(train_seeds, dtype=np.int64)
        ),
        "validation_game_count": len(validation_seeds),
        "validation_game_seed_set_sha256": _game_seed_set_sha256(
            np.asarray(validation_seeds, dtype=np.int64)
        ),
        "records_sha256": _canonical_json_sha256(records),
    }
    for field, actual in digest_fields.items():
        if selected_payload.get(field) != actual or selected_meta.get(field) != actual:
            raise SystemExit(f"A1 selected-game {field} drift")
    if not np.array_equal(
        np.asarray(validation_seeds, dtype=np.int64),
        np.asarray(validation_seed_contract["game_seeds"], dtype=np.int64),
    ):
        raise SystemExit(
            "A1 selected-game validation split differs from the exact holdout sidecar"
        )

    observed = np.asarray(game_seed_column, dtype=np.int64).reshape(-1)
    if observed.size == 0:
        raise SystemExit("A1 memmap corpus has no game_seed rows")
    run_starts = np.concatenate(
        (
            np.asarray([0], dtype=np.int64),
            np.flatnonzero(observed[1:] != observed[:-1]) + 1,
        )
    )
    run_values = observed[run_starts]
    if np.unique(run_values).size != run_values.size:
        raise SystemExit(
            "A1 memmap game_seed starts more than one non-contiguous run"
        )
    observed_unique = np.sort(np.unique(observed))
    if not np.array_equal(observed_unique, np.asarray(all_seeds, dtype=np.int64)):
        expected = set(all_seeds)
        actual = set(map(int, observed_unique.tolist()))
        raise SystemExit(
            "A1 memmap actual game-seed set differs from its selected manifest: "
            f"missing={len(expected - actual)} unexpected={len(actual - expected)}"
        )

    audit_path, audit_payload, _ = _read_sha256_bound_json(
        audit_meta.get("path"),
        audit_meta.get("file_sha256"),
        label="A1 post-wave audit",
    )
    if str(audit_path) != str(audit_meta.get("path")):
        raise SystemExit("A1 post-wave audit path is not canonical")
    if (
        audit_payload.get("schema_version") != "a1-post-wave-audit-v2"
        or audit_payload.get("passed") is not True
        or audit_payload.get("errors") != []
    ):
        raise SystemExit("A1 post-wave audit is not a clean passing artifact")
    actual_audit_sha = _canonical_json_sha256(
        {key: value for key, value in audit_payload.items() if key != "audit_sha256"}
    )
    if (
        audit_payload.get("audit_sha256") != actual_audit_sha
        or audit_meta.get("audit_sha256") != actual_audit_sha
    ):
        raise SystemExit("A1 post-wave audit semantic digest drift")
    contract_sha = validation_seed_contract["a1_contract_sha256"]
    if (
        audit_payload.get("contract_sha256") != contract_sha
        or audit_meta.get("contract_sha256") != contract_sha
    ):
        raise SystemExit("A1 post-wave audit contract hash drift")
    selected_row_count = audit_payload.get("rows")
    validation_row_count = int(validation_seed_contract["validation_row_count"])
    if (
        isinstance(selected_row_count, bool)
        or not isinstance(selected_row_count, int)
        or selected_row_count != int(observed.size)
        or corpus_meta.get("row_count") != selected_row_count
        or audit_meta.get("selected_row_count") != selected_row_count
        or audit_meta.get("training_row_count")
        != selected_row_count - validation_row_count
    ):
        raise SystemExit(
            "A1 memmap row exposure differs from the passing audit: "
            f"observed={observed.size} audit={selected_row_count!r} "
            f"meta_selected={audit_meta.get('selected_row_count')!r} "
            f"meta_training={audit_meta.get('training_row_count')!r}"
        )
    selected_binding = audit_payload.get("selected_training_games")
    if not isinstance(selected_binding, dict) or selected_binding != {
        "manifest": str(selected_path),
        "manifest_sha256": _canonical_json_sha256(selected_payload),
        "manifest_file_sha256": selected_meta["file_sha256"],
        "selected_game_count": 12_000,
        "selected_game_seed_set_sha256": digest_fields[
            "selected_game_seed_set_sha256"
        ],
        "records_sha256": digest_fields["records_sha256"],
    }:
        raise SystemExit("A1 post-wave audit selected-game binding drift")
    validation_binding = audit_payload.get("validation_holdout")
    expected_validation_binding = {
        "manifest": str(validation_seed_contract["path"]),
        "manifest_sha256": validation_seed_contract["manifest_sha256"],
        "manifest_file_sha256": validation_seed_contract["file_sha256"],
        "validation_game_seed_count": len(validation_seeds),
        "validation_game_seed_set_sha256": digest_fields[
            "validation_game_seed_set_sha256"
        ],
    }
    if validation_binding != expected_validation_binding:
        raise SystemExit("A1 post-wave audit validation binding drift")

    contract_path_value = audit_payload.get("contract_path")
    lock_path, lock_payload, _ = _read_sha256_bound_json(
        contract_path_value,
        _sha256_existing_file(str(contract_path_value)),
        label="A1 contract lock",
    )
    if str(lock_path) != str(contract_path_value):
        raise SystemExit("A1 contract lock path is not canonical")
    lock_schema = lock_payload.get("schema_version")
    if lock_schema not in {
        "a1-pre-wave-contract-lock-v2",
        "a1-pre-wave-contract-lock-v3",
    }:
        raise SystemExit("A1 contract lock schema drift")
    promotion_handoff = lock_payload.get("promotion_handoff")
    if lock_schema == "a1-pre-wave-contract-lock-v3":
        if (
            not isinstance(promotion_handoff, dict)
            or promotion_handoff.get("mode") != "post_promotion"
        ):
            raise SystemExit("A1 v3 contract lacks its post-promotion producer handoff")
    elif promotion_handoff is not None:
        # v2 locks created after the boundary carry an explicit historical
        # marker.  Markerless v2 remains readable only here for already-audited
        # pre-boundary corpora; a1_pre_wave_contract can no longer seal one.
        if (
            not isinstance(promotion_handoff, dict)
            or set(promotion_handoff) != {"mode", "reason"}
            or promotion_handoff.get("mode") != "historical_pre_promotion"
            or not isinstance(promotion_handoff.get("reason"), str)
            or not promotion_handoff["reason"].strip()
        ):
            raise SystemExit("A1 v2 historical promotion marker drift")
    lock_digest = _canonical_json_sha256(
        {key: value for key, value in lock_payload.items() if key != "contract_sha256"}
    )
    if lock_payload.get("contract_sha256") != contract_sha or lock_digest != contract_sha:
        raise SystemExit("A1 contract lock semantic digest drift")
    provenance = lock_payload.get("provenance")
    if not isinstance(provenance, dict):
        raise SystemExit("A1 contract lock has no provenance section")
    learner_code = provenance.get("learner_code")
    if not isinstance(learner_code, list) or not learner_code:
        raise SystemExit("A1 contract lock does not bind learner implementation files")
    learner_code_sha256 = _canonical_json_sha256(learner_code)
    if provenance.get("learner_code_sha256") != learner_code_sha256:
        raise SystemExit("A1 learner-code provenance digest drift")
    learner_paths: list[str] = []
    for index, record in enumerate(learner_code):
        if not isinstance(record, dict) or set(record) != {"kind", "path", "sha256"}:
            raise SystemExit(
                f"A1 learner-code record {index} has malformed fields"
            )
        if record.get("kind") != "learner_code" or not _is_sha256(
            record.get("sha256")
        ):
            raise SystemExit(f"A1 learner-code record {index} is malformed")
        try:
            code_path = Path(str(record["path"])).expanduser().resolve(strict=True)
        except OSError as error:
            raise SystemExit(
                f"cannot resolve A1 learner-code file {record.get('path')}: {error}"
            ) from error
        if str(code_path) != str(record["path"]):
            raise SystemExit(
                f"A1 learner-code path is not canonical: {record['path']}"
            )
        actual_code_sha = _sha256_existing_file(code_path)
        if actual_code_sha != record["sha256"]:
            raise SystemExit(
                "A1 learner implementation drift before optimizer construction: "
                f"{code_path} declared={record['sha256']!r} actual={actual_code_sha!r}"
            )
        learner_paths.append(code_path.as_posix())
    missing_learner_code = {
        suffix
        for suffix in A1_REQUIRED_LEARNER_CODE_SUFFIXES
        if not any(path.endswith(suffix) for path in learner_paths)
    }
    if missing_learner_code:
        raise SystemExit(
            "A1 contract omits required learner implementation files: "
            f"{sorted(missing_learner_code)}"
        )
    runtime_code_tree = provenance.get("runtime_code_tree")
    if not isinstance(runtime_code_tree, list) or not runtime_code_tree:
        raise SystemExit("A1 contract lock does not bind the transitive runtime tree")
    runtime_code_tree_sha256 = _canonical_json_sha256(runtime_code_tree)
    if provenance.get("runtime_code_tree_sha256") != runtime_code_tree_sha256:
        raise SystemExit("A1 runtime-code-tree provenance digest drift")
    runtime_paths: list[str] = []
    for index, record in enumerate(runtime_code_tree):
        if not isinstance(record, dict) or set(record) != {"kind", "path", "sha256"}:
            raise SystemExit(
                f"A1 runtime-code-tree record {index} has malformed fields"
            )
        if record.get("kind") != "runtime_code" or not _is_sha256(
            record.get("sha256")
        ):
            raise SystemExit(f"A1 runtime-code-tree record {index} is malformed")
        try:
            runtime_path = Path(str(record["path"])).expanduser().resolve(strict=True)
        except OSError as error:
            raise SystemExit(
                f"cannot resolve A1 runtime file {record.get('path')}: {error}"
            ) from error
        if str(runtime_path) != str(record["path"]):
            raise SystemExit(
                f"A1 runtime-code-tree path is not canonical: {record['path']}"
            )
        actual_runtime_sha = _sha256_existing_file(runtime_path)
        if actual_runtime_sha != record["sha256"]:
            raise SystemExit(
                "A1 transitive runtime drift before optimizer construction: "
                f"{runtime_path} declared={record['sha256']!r} "
                f"actual={actual_runtime_sha!r}"
            )
        runtime_paths.append(runtime_path.as_posix())
    missing_runtime_code = {
        suffix
        for suffix in A1_REQUIRED_RUNTIME_CODE_SUFFIXES
        if not any(path.endswith(suffix) for path in runtime_paths)
    }
    if missing_runtime_code:
        raise SystemExit(
            "A1 contract omits required transitive runtime files: "
            f"{sorted(missing_runtime_code)}"
        )
    science = lock_payload.get("science")
    if not isinstance(science, dict):
        raise SystemExit("A1 contract lock has no science section")
    learner_objective = science.get("learner_value_objective")
    if not isinstance(learner_objective, dict) or science.get(
        "learner_value_objective_sha256"
    ) != _canonical_json_sha256(learner_objective):
        raise SystemExit("A1 learner objective binding drift")
    learner_training_recipe = science.get("learner_training_recipe")
    if not isinstance(learner_training_recipe, dict) or science.get(
        "learner_training_recipe_sha256"
    ) != _canonical_json_sha256(learner_training_recipe):
        raise SystemExit("A1 learner training recipe binding drift")
    producer_sha = next(
        (
            record.get("sha256")
            for record in lock_payload.get("checkpoints", [])
            if isinstance(record, dict) and record.get("role") == "producer"
        ),
        None,
    )
    if not _is_sha256(producer_sha):
        raise SystemExit("A1 contract lock has no valid producer checkpoint")
    return {
        "learner_value_objective": learner_objective,
        "learner_training_recipe": learner_training_recipe,
        "learner_training_recipe_sha256": _canonical_json_sha256(
            learner_training_recipe
        ),
        "learner_code_sha256": learner_code_sha256,
        "runtime_code_tree_sha256": runtime_code_tree_sha256,
        "producer_checkpoint_sha256": producer_sha,
        "selected_game_seed_set_sha256": digest_fields[
            "selected_game_seed_set_sha256"
        ],
        "training_game_seed_set_sha256": digest_fields[
            "training_game_seed_set_sha256"
        ],
    }


def _validate_a1_learner_objective(
    args: argparse.Namespace, bound: dict[str, object]
) -> None:
    objective = bound["learner_value_objective"]
    assert isinstance(objective, dict)
    mode = str(getattr(args, "value_head_type", "mse"))
    if mode == "scalar":
        mode = "mse"
    if mode != objective.get("objective"):
        raise SystemExit(
            "A1 learner objective differs from the immutable contract: "
            f"contract={objective.get('objective')!r} cli={mode!r}"
        )
    expected_readout = "scalar" if mode == "mse" else "categorical"
    if objective.get("value_readout") != expected_readout:
        raise SystemExit("A1 learner readout differs from the immutable contract")
    expected_scalar_loss_readout = str(
        objective.get(
            "scalar_value_loss_readout",
            (
                bound.get("learner_training_recipe", {})
                if isinstance(bound.get("learner_training_recipe"), dict)
                else {}
            ).get("scalar_value_loss_readout", "raw"),
        )
    )
    if str(getattr(args, "scalar_value_loss_readout", "raw")) != expected_scalar_loss_readout:
        raise SystemExit(
            "A1 scalar value loss readout differs from the immutable contract"
        )
    expected_scalar_loss_scale = float(
        objective.get(
            "scalar_value_loss_scale",
            (
                bound.get("learner_training_recipe", {})
                if isinstance(bound.get("learner_training_recipe"), dict)
                else {}
            ).get("scalar_value_loss_scale", 1.0),
        )
    )
    if not math.isclose(
        float(getattr(args, "scalar_value_loss_scale", 1.0)),
        expected_scalar_loss_scale,
        rel_tol=0.0,
        abs_tol=1.0e-12,
    ):
        raise SystemExit(
            "A1 scalar value loss scale differs from the immutable contract"
        )
    expected_scalar_objective = str(
        objective.get(
            "scalar_value_objective",
            (
                bound.get("learner_training_recipe", {})
                if isinstance(bound.get("learner_training_recipe"), dict)
                else {}
            ).get("scalar_value_objective", "mse"),
        )
    )
    if (
        str(getattr(args, "scalar_value_objective", "mse"))
        != expected_scalar_objective
    ):
        raise SystemExit(
            "A1 scalar value objective differs from the immutable contract"
        )
    if mode == "mse":
        if int(getattr(args, "value_categorical_bins", 0)) != 0:
            raise SystemExit("A1 scalar learner cannot construct categorical bins")
        scalar_weight, categorical_weight = _resolve_value_objective_weights(args)
        if scalar_weight <= 0.0 or categorical_weight != 0.0:
            raise SystemExit("A1 scalar learner objective weights are contradictory")
    else:
        expected_bins = objective.get("value_categorical_bins")
        if int(getattr(args, "value_categorical_bins", 0)) != int(expected_bins):
            raise SystemExit("A1 categorical bin count differs from the contract")
        if not math.isclose(
            float(getattr(args, "value_hlgauss_sigma_ratio", 0.0)),
            float(objective.get("hlgauss_sigma_ratio")),
            rel_tol=0.0,
            abs_tol=1e-12,
        ):
            raise SystemExit("A1 HL-Gauss sigma differs from the contract")
    curriculum_parent = _validate_a1_curriculum_parent(args, bound)
    expected_initializer_sha256 = bound.get(
        "learner_initializer_sha256", bound["producer_checkpoint_sha256"]
    )
    if (
        getattr(args, "init_checkpoint_sha256", None)
        != expected_initializer_sha256
        and curriculum_parent is None
    ):
        raise SystemExit(
            "A1 warm-start checkpoint differs from its bound learner initializer"
        )
    args.a1_curriculum_parent = curriculum_parent


def _validate_a1_curriculum_parent(
    args: argparse.Namespace, bound: dict[str, object]
) -> dict[str, object] | None:
    """Authenticate the completed first dose used by a one-off two-arm curriculum.

    Generation remains bound to its original producer.  This narrow path only
    permits the learner warm start to advance to the exact output of a completed
    sealed n256 dose, so n128 can be the second half of an all-games curriculum.
    Ordinary A1 and production runs retain the historical producer-equality rule.
    """

    raw = str(getattr(args, "a1_curriculum_parent_receipt", "") or "")
    if not raw:
        return None
    path = Path(raw).expanduser().resolve(strict=True)
    try:
        receipt = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load A1 curriculum parent receipt: {error}") from error
    if not isinstance(receipt, dict):
        raise SystemExit("A1 curriculum parent receipt must be a JSON object")
    unhashed = dict(receipt)
    stated = unhashed.pop("receipt_sha256", None)
    if (
        receipt.get("schema_version") != "a1-dual-arm-training-receipt-v1"
        or receipt.get("status") != "complete"
        or (receipt.get("arm_id"), receipt.get("subset_id"))
        != ("n256", "full-56k")
        or (bound.get("arm_id"), bound.get("subset_id"))
        != ("n128", "full-140k")
        or stated != _canonical_json_sha256(unhashed)
    ):
        raise SystemExit("A1 curriculum parent receipt schema/status/digest drift")
    inputs = receipt.get("inputs")
    outputs = receipt.get("outputs")
    lineage_dose = receipt.get("lineage_dose")
    producer = inputs.get("producer") if isinstance(inputs, dict) else None
    checkpoint = outputs.get("checkpoint") if isinstance(outputs, dict) else None
    if (
        not isinstance(lineage_dose, dict)
        or lineage_dose.get("schema_version") != "a1-lineage-dose-v1"
        or lineage_dose.get("mode") != "direct_from_declared_producer"
        or lineage_dose.get("optimizer_state_continuity")
        != "fresh_optimizer_per_dose"
        or lineage_dose.get("declared_producer_sha256")
        != bound.get("producer_checkpoint_sha256")
        or lineage_dose.get("init_checkpoint_sha256")
        != bound.get("producer_checkpoint_sha256")
        or isinstance(lineage_dose.get("cumulative_sampled_rows"), bool)
        or not isinstance(lineage_dose.get("cumulative_sampled_rows"), int)
        or lineage_dose["cumulative_sampled_rows"] <= 0
        or isinstance(lineage_dose.get("cumulative_optimizer_steps"), bool)
        or not isinstance(lineage_dose.get("cumulative_optimizer_steps"), int)
        or lineage_dose["cumulative_optimizer_steps"] <= 0
    ):
        raise SystemExit(
            "A1 curriculum parent lacks a typed direct-producer cumulative dose"
        )
    if (
        not isinstance(producer, dict)
        or producer.get("sha256") != bound.get("producer_checkpoint_sha256")
        or not isinstance(checkpoint, dict)
        or set(checkpoint) != {"path", "sha256"}
        or checkpoint.get("sha256") != getattr(args, "init_checkpoint_sha256", None)
        or str(Path(str(checkpoint.get("path"))).expanduser().resolve(strict=True))
        != str(Path(str(args.init_checkpoint)).expanduser().resolve(strict=True))
        or _sha256_existing_file(str(checkpoint.get("path"))) != checkpoint.get("sha256")
    ):
        raise SystemExit("A1 curriculum parent does not bind producer/init checkpoint")
    return {
        "schema_version": "a1-curriculum-parent-binding-v1",
        "receipt_path": str(path),
        "receipt_sha256": _sha256_existing_file(path),
        "parent_arm_id": "n256",
        "parent_subset_id": "full-56k",
        "parent_checkpoint": checkpoint,
        "generation_producer_sha256": producer["sha256"],
    }


def _effective_a1_learner_training_recipe(
    args: argparse.Namespace, ddp: dict[str, int | bool]
) -> dict[str, object]:
    bound_fields = (
        "track",
        "vps_to_win",
        "graph_history_features",
        "seed",
        "epochs",
        "max_steps",
        "batch_size",
        "grad_accum_steps",
        "optimizer",
        "resume_optimizer",
        "lr",
        "lr_warmup_steps",
        "lr_schedule",
        "weight_decay",
        "fused_optimizer",
        "value_lr_mult",
        "action_module_lr_mult",
        "trunk_lr_mult",
        "policy_loss_weight",
        "soft_target_source",
        "soft_target_weight",
        "soft_target_temperature",
        "soft_target_min_legal_coverage",
        "value_loss_weight",
        "value_target_lambda",
        "value_categorical_loss_weight",
        "hlgauss_scalar_aux_loss_weight",
        "final_vp_loss_weight",
        "q_loss_weight",
        "policy_kl_anchor_weight",
        "value_uncertainty_loss_weight",
        "aux_subgoal_loss_weight",
        "train_value_only",
        "freeze_modules",
        "policy_surprise_weight",
        "advantage_policy_weighting",
        "per_game_value_weight",
        "vp_margin_weight",
        "truncated_vp_margin_value_weight",
        "amp",
        "mask_hidden_info",
        "symmetry_augment",
        "forced_action_weight",
        "forced_row_value_weight",
        "winner_sample_weight",
        "loser_sample_weight",
        "teacher_weights",
        "phase_weights",
        "value_phase_weights",
        "ddp_shard_data",
    )
    effective = {field: getattr(args, field) for field in bound_fields}
    min_35m_params = int(getattr(args, "min_35m_params", 30_000_000))
    max_35m_params = int(getattr(args, "max_35m_params", 40_000_000))
    if (min_35m_params, max_35m_params) != (30_000_000, 40_000_000):
        # The V6 parent update intentionally grows the commissioned topology
        # beyond the legacy 35M envelope.  Bind non-default architecture bounds
        # into the effective recipe so the sealed child cannot inherit parser
        # defaults or silently widen its accepted checkpoint shape.
        effective["min_35m_params"] = min_35m_params
        effective["max_35m_params"] = max_35m_params
    if bool(getattr(args, "symmetry_augment", False)):
        # Event/action ids and event target ids are part of the spatial input.
        # A symmetry-enabled recipe must bind whether that history is relabelled;
        # relying on the parser default can silently create contradictory rows.
        effective["symmetry_augment_events"] = bool(
            getattr(args, "symmetry_augment_events", True)
        )
    policy_target_blend_semantics = str(
        getattr(
            args,
            "policy_target_blend_semantics",
            POLICY_TARGET_BLEND_LEGACY_V1,
        )
    )
    # Always report the actual loss operator.  Historical authorities that
    # predate this field are normalized below by
    # _validate_a1_learner_training_recipe only when they request the exact
    # legacy default.  Current authorities must bind it explicitly so command
    # construction and recipe replay cannot disagree.
    effective["policy_target_blend_semantics"] = policy_target_blend_semantics
    scalar_value_loss_readout = str(
        getattr(args, "scalar_value_loss_readout", "raw")
    )
    scalar_value_loss_scale = float(
        getattr(args, "scalar_value_loss_scale", 1.0)
    )
    scalar_value_objective = str(
        getattr(args, "scalar_value_objective", "mse")
    )
    if scalar_value_objective != "mse":
        # Experimental scalar objectives are science-critical and must be
        # represented explicitly in every sealed recipe. The historical MSE
        # default remains omitted so old recipe hashes stay byte-identical.
        effective["scalar_value_objective"] = scalar_value_objective
    if scalar_value_loss_readout != "raw" or scalar_value_loss_scale != 1.0:
        # Historical scalar recipes optimize the raw head and omit these
        # additive fields. New recipes bind the exact deployed search operator.
        effective["scalar_value_loss_readout"] = scalar_value_loss_readout
        effective["scalar_value_loss_scale"] = scalar_value_loss_scale
    forced_type_weights = _parse_forced_row_value_action_type_weights(
        str(getattr(args, "forced_row_value_action_type_weights", "") or "")
    )
    if forced_type_weights:
        # Additive opt-in objective. Historical recipes omit the field at the
        # empty default, while an active type map is canonicalized and becomes
        # part of the sealed effective recipe.
        effective["forced_row_value_action_type_weights"] = (
            _canonical_forced_row_value_action_type_weights(forced_type_weights)
        )
    maximum_forced_value_mass = getattr(
        args,
        "maximum_nominal_forced_scalar_value_mass_fraction",
        None,
    )
    if maximum_forced_value_mass is not None:
        effective["maximum_nominal_forced_scalar_value_mass_fraction"] = float(
            maximum_forced_value_mass
        )
    if getattr(args, "sampler_seed", None) is not None:
        # Historical A1 recipes keep their exact shape when this additive flag
        # is omitted. An explicit independent sampler stream changes the
        # trajectory and must therefore be centrally authorized.
        effective["sampler_seed"] = int(args.sampler_seed)
    if bool(getattr(args, "per_game_policy_weight", False)) or str(
        getattr(args, "per_game_policy_weight_mode", "equal")
    ) != "equal":
        # The post-promotion v3 learner makes game-uniform policy mass part of
        # its sealed objective. Historical v2 recipes omit both fields at the
        # backward-compatible false/equal defaults.
        effective["per_game_policy_weight"] = bool(args.per_game_policy_weight)
        effective["per_game_policy_weight_mode"] = str(
            args.per_game_policy_weight_mode
        )
    if (
        bool(getattr(args, "static_action_residual", False))
        or bool(getattr(args, "legal_action_value_residual", False))
        or bool(getattr(args, "legal_action_value_set_statistics", False))
    ):
        # Additive checkpoint architecture. Historical recipes retain their
        # exact seal while an enabled repair cannot disappear from recipe
        # admission or be confused with the legacy blind topology.
        effective["static_action_residual"] = bool(args.static_action_residual)
        effective["legal_action_value_residual"] = bool(
            args.legal_action_value_residual
        )
        if bool(getattr(args, "legal_action_value_set_statistics", False)):
            effective["legal_action_value_set_statistics"] = True
    if int(getattr(args, "value_tower_split_layers", 0) or 0) > 0:
        effective["value_tower_split_layers"] = int(
            args.value_tower_split_layers
        )
    if bool(getattr(args, "public_rule_state_features", False)):
        effective["public_rule_state_features"] = True
    # Additive opt-in objective: historical sealed recipes and old Namespace
    # fixtures predate this field and must remain byte-for-byte exact when it is
    # absent/off. A nonzero value is trajectory-changing and therefore enters
    # the effective recipe so an old seal rejects it rather than weakening.
    belief_resource_loss_weight = float(
        getattr(args, "belief_resource_loss_weight", 0.0)
    )
    if belief_resource_loss_weight > 0.0:
        effective["belief_resource_loss_weight"] = belief_resource_loss_weight
    generic_a1_ablation = bool(
        str(getattr(args, "a1_learner_ablation_id", "") or "")
    )
    value_routing_ablation = str(
        getattr(args, "a1_learner_ablation_id", "") or ""
    ).startswith("scratch-value-routing-")
    # Additive diagnostic axis. Historical contracts predate it and retain an
    # identical recipe shape at the default. Generic ablations must record even
    # the unit value, however: a current authority whose baseline is 0.25 needs
    # an unambiguous, shape-complete V100 treatment rather than silently
    # omitting the only causal axis.
    value_trunk_grad_scale = float(
        getattr(args, "value_trunk_grad_scale", 1.0)
    )
    if value_trunk_grad_scale != 1.0 or value_routing_ablation:
        effective["value_trunk_grad_scale"] = value_trunk_grad_scale
    # These axes were added after the historical A1 seal. Keep ordinary old
    # recipes byte-for-byte unchanged at their exact legacy defaults. Generic
    # diagnostic ablations, however, are produced by a1_one_dose_train with
    # both defaults expanded into the declared effective recipe. Expand them
    # here for every such ablation as well, so train_bc compares one canonical
    # recipe shape instead of rejecting a valid intervention merely because
    # the immutable parent recipe predates the fields.
    policy_aux_sampling_mode = str(
        getattr(
            args,
            "policy_aux_sampling_mode",
            POLICY_AUX_SAMPLING_LEGACY_REPLACEMENT_V1,
        )
    )
    if (
        policy_aux_sampling_mode
        != POLICY_AUX_SAMPLING_LEGACY_REPLACEMENT_V1
    ):
        effective["policy_aux_sampling_mode"] = policy_aux_sampling_mode
    public_card_lr_mult = float(getattr(args, "public_card_lr_mult", 1.0))
    if public_card_lr_mult != 1.0 or generic_a1_ablation:
        effective["public_card_lr_mult"] = public_card_lr_mult
    shared_action_lr_mult = float(
        getattr(args, "shared_action_lr_mult", 1.0)
    )
    if shared_action_lr_mult != 1.0 or generic_a1_ablation:
        effective["shared_action_lr_mult"] = shared_action_lr_mult
    per_game_policy_surprise_weighting = bool(
        getattr(args, "per_game_policy_surprise_weighting", False)
    )
    target_reliability_confidence_weighting = bool(
        getattr(args, "target_reliability_confidence_weighting", False)
    )
    # The current production reliability contract deliberately binds surprise
    # weighting OFF. Preserve that negative decision in the effective recipe
    # whenever reliability weighting identifies the new contract; otherwise a
    # launched coherent run cannot reconstruct its sealed recipe even though
    # the CLI is correct. Historical recipes still omit both default-off fields.
    if (
        per_game_policy_surprise_weighting
        or target_reliability_confidence_weighting
        or generic_a1_ablation
    ):
        effective["per_game_policy_surprise_weighting"] = (
            per_game_policy_surprise_weighting
        )
    target_reliability_confidence_floor = float(
        getattr(args, "target_reliability_confidence_floor", 0.25)
    )
    if (
        per_game_policy_surprise_weighting
        or target_reliability_confidence_weighting
        or generic_a1_ablation
    ):
        # Reliability weighting and surprise weighting are competing ways to
        # redistribute policy mass. The current sealed recipe enables the
        # former and explicitly disables the latter, so that false value is
        # trajectory-critical rather than an omitted legacy default.
        effective["per_game_policy_surprise_weighting"] = (
            per_game_policy_surprise_weighting
        )
    if target_reliability_confidence_weighting or generic_a1_ablation:
        effective["target_reliability_confidence_weighting"] = (
            target_reliability_confidence_weighting
        )
        effective["target_reliability_confidence_floor"] = (
            target_reliability_confidence_floor
        )
    if target_reliability_confidence_weighting:
        # The current reliability-weighted contract explicitly seals the
        # default shared-trunk scale. Historical recipes predate this field and
        # must keep omitting the unit default; non-unit interventions were
        # already added above.
        effective["value_trunk_grad_scale"] = value_trunk_grad_scale
    if getattr(args, "policy_kl_target", None) is not None:
        # The fixed anchor's historical recipe shape remains untouched.  An
        # adaptive trust region is trajectory-changing and must be explicitly
        # present in any sealed learner authority.
        effective["policy_kl_target"] = float(args.policy_kl_target)
        effective["policy_kl_dual_lr"] = float(args.policy_kl_dual_lr)
        effective["policy_kl_max_weight"] = float(args.policy_kl_max_weight)
        effective["policy_kl_anchor_direction"] = str(
            args.policy_kl_anchor_direction
        )
    world_size = int(ddp["world_size"])
    effective["world_size"] = world_size
    effective["global_batch_size"] = (
        int(args.batch_size) * int(args.grad_accum_steps) * world_size
    )
    if int(getattr(args, "policy_aux_active_batch_size", 0)) > 0:
        effective["policy_aux_active_batch_size"] = int(args.policy_aux_active_batch_size)
        effective["policy_aux_loss_weight"] = float(args.policy_aux_loss_weight)
    # Additive provenance: old authenticated recipes remain byte-for-byte valid
    # when the backward-compatible flag is off, while future rank-offset runs
    # bind the trajectory-changing opt-in explicitly.
    if bool(getattr(args, "training_rng_rank_offset", False)):
        effective["training_rng_rank_offset"] = True
    if (
        str(getattr(args, "base_sampler", BASE_SAMPLER_WEIGHTED_REPLACEMENT_V1))
        != BASE_SAMPLER_WEIGHTED_REPLACEMENT_V1
    ):
        effective["base_sampler"] = str(args.base_sampler)
    policy_signal_floor = float(
        getattr(args, "minimum_policy_effective_rows_per_global_batch", 0.0)
    )
    if policy_signal_floor > 0.0:
        effective["minimum_policy_effective_rows_per_global_batch"] = (
            policy_signal_floor
        )
    moe_balance_loss_weight = float(
        getattr(args, "moe_balance_loss_weight", 0.01)
    )
    if moe_balance_loss_weight != 0.01 or generic_a1_ablation:
        effective["moe_balance_loss_weight"] = moe_balance_loss_weight
    train_diagnostic_cadence = int(
        getattr(args, "train_diagnostics_every_batches", 0)
    )
    objective_gradient_cadence = int(
        getattr(args, "objective_gradient_interference_every_batches", 0)
    )
    required_feature_modules = str(
        getattr(args, "require_feature_learning_signal_modules", "") or ""
    )
    minimum_feature_observations = int(
        getattr(args, "minimum_feature_learning_signal_observations", 0)
    )
    if (
        train_diagnostic_cadence
        or objective_gradient_cadence
        or required_feature_modules
        or minimum_feature_observations
    ):
        effective["train_diagnostics_every_batches"] = (
            train_diagnostic_cadence
        )
        effective["objective_gradient_interference_every_batches"] = (
            objective_gradient_cadence
        )
        effective["require_feature_learning_signal_modules"] = (
            required_feature_modules
        )
        effective["minimum_feature_learning_signal_observations"] = (
            minimum_feature_observations
        )
    return effective


def _bind_late_a1_recipe_fields(
    effective: dict[str, object],
    args: argparse.Namespace,
    expected: Mapping[str, object],
) -> None:
    """Project post-v1 fields only when the immutable authority binds them."""

    late_bound_values = {
        "checkpoint_steps": str(getattr(args, "checkpoint_steps", "") or ""),
        "max_grad_norm": float(getattr(args, "max_grad_norm", 1.0)),
        "post_policy_dose_value_trunk_grad_scale": float(
            getattr(args, "post_policy_dose_value_trunk_grad_scale", 1.0)
        ),
        "value_player_outcome_balance_mode": str(
            getattr(args, "value_player_outcome_balance_mode", "none")
        ),
        "value_root_blend_phases": str(
            getattr(args, "value_root_blend_phases", "") or ""
        ),
        "value_root_blend_global_compat": bool(
            getattr(args, "value_root_blend_global_compat", False)
        ),
    }
    for key, value in late_bound_values.items():
        if key in expected:
            effective[key] = value


def _effective_a1_scratch_training_recipe(
    args: argparse.Namespace,
    ddp: dict[str, int | bool],
    expected: Mapping[str, object],
) -> dict[str, object]:
    """Reconstruct scratch recipe fields after model projection is checked."""

    effective = _effective_a1_learner_training_recipe(args, ddp)
    _bind_late_a1_recipe_fields(effective, args, expected)
    for field in (
        "static_action_residual",
        "legal_action_value_residual",
        "legal_action_value_set_statistics",
        "value_tower_split_layers",
        "public_rule_state_features",
    ):
        effective.pop(field, None)
    return effective


def _validate_a1_decisive_training_semantics(
    args: argparse.Namespace,
    ddp: dict[str, int | bool],
    bound: dict[str, object],
) -> dict[str, object]:
    """Fail closed on learner operators that are not promotion-safe yet.

    The generic trainer keeps these knobs available for explicitly diagnostic
    research.  A sealed A1 run without diagnostic authority is decisive,
    however, and must not silently change its mathematical objective:

    * gradient accumulation currently averages already-normalized microbatch
      means, not the exact union-weighted numerator/denominator;
    * distributed symmetry augmentation consumes one logical global NumPy
      stream and gives each rank its ``rank::world_size`` slice; the underlying
      stream state remains equal across ranks and is checked before every
      resumable checkpoint; and
    * outcome-value advantage weighting was historically rank-local under DDP.
      Its new global normalization still needs a fresh, explicitly reviewed A1
      seal before it can affect a promotable candidate.
    """

    diagnostic_authority = bool(
        getattr(args, "a1_batch_probe_plan", "")
        or getattr(args, "a1_batch_probe_run_id", "")
        or getattr(args, "a1_learner_ablation_id", "")
        or getattr(args, "a1_dual_learner_lock", "")
        or bound.get("dual_arm") is True
    )
    world_size = int(ddp.get("world_size", 1))
    grad_accum_steps = int(getattr(args, "grad_accum_steps", 1))
    symmetry_augment = bool(getattr(args, "symmetry_augment", False))
    advantage_mode = str(getattr(args, "advantage_policy_weighting", "none"))
    contract: dict[str, object] = {
        "schema_version": "a1-decisive-training-semantics-v1",
        "decisive": not diagnostic_authority,
        "diagnostic_authority_present": diagnostic_authority,
        "world_size": world_size,
        "grad_accum_steps": grad_accum_steps,
        "gradient_accumulation_contract": (
            "single_microbatch_exact"
            if grad_accum_steps == 1
            else "diagnostic_approximate_microbatch_means"
        ),
        "symmetry_augmentation": symmetry_augment,
        "distributed_symmetry_contract": (
            "not_applicable"
            if not symmetry_augment or world_size == 1
            else "global_rank_strided_stream_exact_v2"
        ),
        "advantage_policy_weighting": advantage_mode,
        "distributed_advantage_contract": (
            "not_applicable"
            if advantage_mode == "none" or world_size == 1
            else "global_normalization_unsealed_for_a1"
        ),
    }
    if diagnostic_authority:
        return contract
    if grad_accum_steps != 1:
        raise SystemExit(
            "decisive A1 training requires --grad-accum-steps 1 until exact "
            "union-weighted gradient accumulation is implemented and sealed"
        )
    # Non-sharded DDP rank-strides one padded global order into equally sized
    # local batches. Symmetry augmentation mirrors that topology: every rank
    # advances an identical copy of the generator by one *global* batch, then
    # retains only its rank-strided draw positions. The shared generator state
    # therefore remains checkpointable once while no two ranks replay the same
    # local draw positions. Sharded DDP pads every local order to the distributed
    # maximum batch multiple and has the same equal-consumption invariant.
    if world_size > 1 and advantage_mode != "none":
        raise SystemExit(
            "decisive distributed A1 training rejects advantage policy weighting "
            "until its global DDP normalization has a reviewed A1 production seal"
        )
    return contract


def _a1_report_eligibility_from_training_semantics(
    semantics: Mapping[str, object] | None,
    *,
    diagnostic_only: bool,
    promotion_eligible: bool,
) -> tuple[bool, bool]:
    """Demote any A1 report whose gradient accumulation is approximate.

    Diagnostic authority permits bounded experiments with unsealed operators;
    it must never turn those operators into a promotion path.  In particular,
    the current ``grad_accum_steps > 1`` implementation averages already-
    normalized conditional microbatch means.  It is not equivalent to the
    union-weighted objective represented by one effective global batch.

    Treat missing or malformed declared semantics as non-promotable too.  The
    promotion transaction performs a stricter structural verification; this
    projection makes the trainer's own report truthful at creation time.
    """

    if semantics is None:
        return bool(diagnostic_only), bool(promotion_eligible)
    exact = (
        semantics.get("schema_version")
        == "a1-decisive-training-semantics-v1"
        and semantics.get("gradient_accumulation_contract")
        == "single_microbatch_exact"
        and type(semantics.get("grad_accum_steps")) is int
        and semantics.get("grad_accum_steps") == 1
    )
    if not exact:
        return True, False
    return bool(diagnostic_only), bool(promotion_eligible)


def _validate_a1_batch_probe_authorization(
    args: argparse.Namespace,
    effective: dict[str, object],
) -> dict[str, object] | None:
    """Authenticate the narrow, non-promotable B200 batch-probe recipe."""
    plan_value = str(getattr(args, "a1_batch_probe_plan", "") or "")
    run_id = str(getattr(args, "a1_batch_probe_run_id", "") or "")
    if not plan_value and not run_id:
        return None
    if not plan_value or not run_id:
        raise SystemExit("A1 batch probe requires both plan and run id")
    plan_path = Path(plan_value).expanduser().resolve(strict=True)
    try:
        plan = json.loads(plan_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load A1 batch-probe plan: {error}") from error
    if not isinstance(plan, dict):
        raise SystemExit("A1 batch-probe plan is not a JSON object")
    stated = plan.get("plan_sha256")
    replay = _canonical_json_sha256(
        {key: value for key, value in plan.items() if key != "plan_sha256"}
    )
    if (
        plan.get("schema_version") != "a1-b200-batch-probe-plan-v1"
        or plan.get("diagnostic_only") is not True
        or plan.get("promotion_eligible") is not False
        or stated != replay
    ):
        raise SystemExit("A1 batch-probe plan schema/digest/authority drift")
    matches = [row for row in plan.get("runs", []) if row.get("run_id") == run_id]
    if len(matches) != 1:
        raise SystemExit("A1 batch-probe run id is absent or duplicated")
    run = matches[0]
    command = run.get("command")
    if not isinstance(command, list):
        raise SystemExit("A1 batch-probe command is malformed")
    trainer_indices = [
        index for index, value in enumerate(command) if Path(str(value)).name == "train_bc.py"
    ]
    actual_argv = [str(Path(__file__).resolve()), *sys.argv[1:]]
    if len(trainer_indices) != 1 or command[trainer_indices[0] :] != actual_argv:
        raise SystemExit("A1 batch-probe plan does not bind the executing argv")
    runtime = plan.get("runtime", {})
    if (
        runtime.get("trainer") != str(Path(__file__).resolve())
        or runtime.get("trainer_sha256") != _sha256_existing_file(__file__)
    ):
        raise SystemExit("A1 batch-probe trainer runtime drift")
    receipt_ref = plan.get("midpoint_receipt", {})
    receipt_path = Path(str(receipt_ref.get("path", ""))).expanduser().resolve(strict=True)
    if receipt_ref.get("sha256") != _sha256_existing_file(receipt_path):
        raise SystemExit("A1 batch-probe midpoint receipt file drift")
    try:
        receipt = json.loads(receipt_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load A1 batch-probe receipt: {error}") from error
    receipt_unhashed = dict(receipt)
    receipt_stated = receipt_unhashed.pop("receipt_sha256", None)
    if receipt.get("status") != "complete" or receipt_stated != _canonical_json_sha256(
        receipt_unhashed
    ):
        raise SystemExit("A1 batch-probe midpoint receipt digest/status drift")
    authorization = plan.get("batch_probe_authorization", {})
    baseline = receipt.get("inputs", {}).get("learner_ablation", {}).get(
        "effective_recipe"
    )
    # The probe deliberately enables per-batch learner telemetry.  These four
    # fields became part of the effective recipe when diagnostic provenance
    # was made explicit; authenticate that exact monitoring delta instead of
    # treating it as an unexplained recipe-shape change.
    allowed = {
        "batch_size",
        "global_batch_size",
        "max_steps",
        "minimum_feature_learning_signal_observations",
        "objective_gradient_interference_every_batches",
        "require_feature_learning_signal_modules",
        "train_diagnostics_every_batches",
    }
    if (
        not isinstance(baseline, dict)
        or authorization.get("baseline_effective_recipe") != baseline
        or authorization.get("baseline_effective_recipe_sha256")
        != _canonical_json_sha256(baseline)
        or set(authorization.get("allowed_recipe_drift", [])) != allowed
    ):
        raise SystemExit("A1 batch-probe baseline recipe authorization drift")
    actual = dict(effective)
    actual["per_game_value_weight_mode"] = str(args.per_game_value_weight_mode)
    if str(args.value_player_outcome_balance_mode) != "none":
        actual["value_player_outcome_balance_mode"] = str(
            args.value_player_outcome_balance_mode
        )
    diagnostic_defaults: dict[str, object] = {
        "minimum_feature_learning_signal_observations": 0,
        "objective_gradient_interference_every_batches": 0,
        "require_feature_learning_signal_modules": "",
        "train_diagnostics_every_batches": 0,
    }
    shape_drift = set(actual) ^ set(baseline)
    if shape_drift - set(diagnostic_defaults):
        raise SystemExit("A1 batch-probe effective recipe shape drift")
    comparison_baseline = dict(baseline)
    for key in set(actual) - set(baseline):
        comparison_baseline[key] = diagnostic_defaults[key]
    comparison_actual = dict(actual)
    for key in set(baseline) - set(actual):
        comparison_actual[key] = diagnostic_defaults[key]
    drift = {
        key: {
            "baseline": comparison_baseline[key],
            "effective": comparison_actual[key],
        }
        for key in comparison_baseline
        if comparison_baseline[key] != comparison_actual[key]
    }
    if not drift or set(drift) - allowed:
        raise SystemExit(
            "A1 batch-probe recipe exceeds its allowed drift: "
            f"drift={sorted(drift)} allowed={sorted(allowed)}"
        )
    return {
        "schema_version": "a1-b200-batch-probe-authorization-v1",
        "diagnostic_only": True,
        "promotion_eligible": False,
        "plan": str(plan_path),
        "plan_sha256": stated,
        "run_id": run_id,
        "baseline_effective_recipe_sha256": _canonical_json_sha256(baseline),
        "effective_recipe": actual,
        "effective_recipe_sha256": _canonical_json_sha256(actual),
        "recipe_drift": drift,
    }


def _validate_a1_aux_regularization_binding(
    args: argparse.Namespace,
    *,
    recipe_drift: dict[str, dict[str, object]] | None,
) -> dict[str, object] | None:
    """Authenticate the centrally commissioned pointer AUX0/AUXT experiment.

    The outer one-dose executor replays the full function-preserving upgrade.
    The trainer independently binds the immutable receipt and initializer bytes
    it was handed, and rejects every recipe delta except activation at the
    geometry-selected coefficient. AUX0 is the sole reviewed no-op arm: its
    purpose is to keep the identical auxiliary architecture present but frozen.
    """

    raw = str(getattr(args, "a1_aux_regularization_binding_json", "") or "")
    if not raw:
        if recipe_drift is not None and "aux_subgoal_loss_weight" in recipe_drift:
            raise SystemExit(
                "aux_subgoal_loss_weight drift requires the matched aux "
                "regularization receipt/initializer binding"
            )
        return None
    try:
        binding = json.loads(raw)
    except json.JSONDecodeError as error:
        raise SystemExit(
            f"invalid A1 aux regularization binding JSON: {error}"
        ) from error
    required = {
        "schema_version",
        "arm_id",
        "aux_subgoal_loss_weight",
        "selected_aux_coefficient_decimal",
        "upgrade_module",
        "upgrade_receipt",
        "upgrade_receipt_file_sha256",
        "upgrade_receipt_digest",
        "upgrade_initializer",
        "upgrade_initializer_sha256",
        "initializer",
        "initializer_sha256",
        "aux_pair_authority_sha256",
        "shared_identity",
        "shared_identity_sha256",
    }
    if not isinstance(binding, dict) or set(binding) != required:
        raise SystemExit("A1 aux regularization binding shape drift")
    if (
        binding.get("schema_version") != "a1-matched-aux-pointer-arm-v1"
        or binding.get("upgrade_module")
        != "entity_graph.aux_subgoal_pointer_heads.v1"
        or not _is_sha256(binding.get("upgrade_receipt_file_sha256"))
        or not _is_sha256(binding.get("upgrade_receipt_digest"))
        or not _is_sha256(binding.get("upgrade_initializer_sha256"))
        or not _is_sha256(binding.get("initializer_sha256"))
        or not _is_sha256(binding.get("aux_pair_authority_sha256"))
        or not _is_sha256(binding.get("shared_identity_sha256"))
        or not isinstance(binding.get("shared_identity"), dict)
        or _canonical_json_sha256(binding["shared_identity"])
        != binding["shared_identity_sha256"]
    ):
        raise SystemExit("A1 aux regularization binding schema/digest drift")
    weight = binding.get("aux_subgoal_loss_weight")
    if isinstance(weight, bool) or not isinstance(weight, (int, float)):
        raise SystemExit("A1 aux regularization weight is not numeric")
    shared = binding["shared_identity"]
    selected_decimal = binding.get("selected_aux_coefficient_decimal")
    try:
        selected = float(selected_decimal)
    except (TypeError, ValueError) as error:
        raise SystemExit("A1 aux selected coefficient is not canonical numeric") from error
    expected_arm = (
        "AUX0"
        if float(weight) == 0.0
        else "AUXT"
        if float(weight) == selected and 0.001 <= selected <= 0.05
        else None
    )
    if (
        expected_arm is None
        or binding.get("arm_id") != expected_arm
        or float(getattr(args, "aux_subgoal_loss_weight", -1.0)) != float(weight)
        or not bool(getattr(args, "aux_subgoal_heads", False))
        or not bool(getattr(args, "aux_settlement_pointer_head", False))
        or shared.get("selected_aux_coefficient_decimal") != selected_decimal
    ):
        raise SystemExit("A1 aux regularization arm/weight/architecture drift")
    receipt_path, receipt_file_sha, receipt_bytes = (
        _stable_canonical_regular_file(
            str(binding["upgrade_receipt"]),
            where="A1 aux upgrade receipt",
        )
    )
    upgrade_initializer_path, upgrade_initializer_sha, _ = (
        _stable_canonical_regular_file(
            str(binding["upgrade_initializer"]),
            where="A1 aux upgrade initializer",
        )
    )
    initializer_path, initializer_sha, _ = _stable_canonical_regular_file(
        str(binding["initializer"]),
        where="A1 aux training initializer",
    )
    if (
        receipt_file_sha != binding["upgrade_receipt_file_sha256"]
        or upgrade_initializer_sha != binding["upgrade_initializer_sha256"]
        or initializer_sha != binding["initializer_sha256"]
        or str(args.init_checkpoint) != str(initializer_path)
        or getattr(args, "init_checkpoint_sha256", "")
        != binding["initializer_sha256"]
    ):
        raise SystemExit("A1 aux regularization receipt/initializer byte drift")
    try:
        receipt = json.loads(receipt_bytes.decode("utf-8"))
    except (UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot load A1 aux upgrade receipt: {error}") from error
    if not isinstance(receipt, dict):
        raise SystemExit("A1 aux upgrade receipt is not an object")
    unsigned_receipt = dict(receipt)
    receipt_digest = unsigned_receipt.pop("receipt_sha256", None)
    if (
        receipt.get("schema_version")
        != "a1-function-preserving-architecture-upgrade-v1"
        or receipt.get("module")
        != "entity_graph.aux_subgoal_pointer_heads.v1"
        or receipt_digest != binding["upgrade_receipt_digest"]
        or _canonical_json_sha256(unsigned_receipt) != receipt_digest
        or receipt.get("upgraded_initializer")
        != {
            "path": str(upgrade_initializer_path),
            "sha256": binding["upgrade_initializer_sha256"],
        }
    ):
        raise SystemExit("A1 aux upgrade receipt semantic drift")
    if (
        shared.get("upgrade_module") != binding["upgrade_module"]
        or shared.get("upgrade_receipt_file_sha256")
        != binding["upgrade_receipt_file_sha256"]
        or shared.get("upgrade_receipt_digest")
        != binding["upgrade_receipt_digest"]
        or shared.get("initializer_sha256") != binding["initializer_sha256"]
        or not _is_sha256(shared.get("pair_contract_state_sha256"))
        or not _is_sha256(shared.get("p1_selection_authority_sha256"))
        or not _is_sha256(shared.get("warmup_terminal_sha256"))
        or not _is_sha256(shared.get("gradient_geometry_terminal_sha256"))
        or not _is_sha256(shared.get("selector_rule_sha256"))
    ):
        raise SystemExit("A1 aux shared-pair identity drift")
    if recipe_drift is not None:
        expected_drift = (
            {}
            if expected_arm == "AUX0"
            else {
                "aux_subgoal_loss_weight": {
                    "contract": 0.0,
                    "effective": selected,
                }
            }
        )
        if recipe_drift != expected_drift:
            raise SystemExit(
                "matched aux arms may differ only by geometry-selected auxiliary loss"
            )
    return binding


def _validate_a1_scratch_runtime_projection(
    args: argparse.Namespace,
    ddp: Mapping[str, int | bool],
    model: Mapping[str, object],
    topology: Mapping[str, object],
    *,
    diagnostic_authority: Mapping[str, object] | None = None,
) -> None:
    """Fail closed unless argv constructs every field of sealed scratch science."""

    requested_adapter = getattr(args, "entity_feature_adapter_version", None)
    runtime_adapter = (
        require_known_entity_feature_adapter(requested_adapter)
        if requested_adapter
        else RUST_ENTITY_ADAPTER_V4
        if bool(args.public_rule_state_features)
        else CURRENT_RUST_ENTITY_ADAPTER_VERSION
    )
    expected_topology_residual = bool(
        diagnostic_authority.get(
            "topology_residual_adapter", model["topology_residual_adapter"]
        )
        if isinstance(diagnostic_authority, Mapping)
        else model["topology_residual_adapter"]
    )
    expected_max_parameter_count = int(
        diagnostic_authority.get(
            "max_parameter_count", model["max_parameter_count"]
        )
        if isinstance(diagnostic_authority, Mapping)
        else model["max_parameter_count"]
    )
    drift = {
        "fresh_initialization": bool(
            args.init_checkpoint or args.grow_from_checkpoint or args.resume_optimizer
        ),
        "arch": str(args.arch) != model["arch"],
        "hidden_size": int(args.hidden_size) != model["hidden_size"],
        "graph_tokens": model["graph_tokens"] is not None,
        "graph_layers": int(args.graph_layers) != model["graph_layers"],
        "attention_heads": int(args.attention_heads) != model["attention_heads"],
        "graph_dropout": float(args.graph_dropout) != model["graph_dropout"],
        "entity_state_trunk": str(args.entity_state_trunk)
        != model["entity_state_trunk"],
        "action_target_gather": bool(args.action_target_gather)
        != model["action_target_gather"],
        "action_cross_attention_layers": int(
            args.action_cross_attention_layers
        )
        != model["action_cross_attention_layers"],
        "topology_residual_adapter": bool(
            getattr(args, "topology_residual_adapter", False)
        )
        != expected_topology_residual,
        "static_action_residual": bool(args.static_action_residual)
        != model["static_action_residual"],
        "legal_action_value_residual": bool(args.legal_action_value_residual)
        != model["legal_action_value_residual"],
        "legal_action_value_set_statistics": bool(
            getattr(args, "legal_action_value_set_statistics", False)
        )
        != model["legal_action_value_set_statistics"],
        "value_tower_split_layers": int(args.value_tower_split_layers)
        != model["value_tower_split_layers"],
        "public_card_count_features": bool(args.public_card_count_features)
        != model["public_card_count_features"],
        "public_card_count_residual_bias": bool(
            args.public_card_count_residual_bias
        )
        != model["public_card_count_residual_bias"],
        "public_rule_state_features": bool(args.public_rule_state_features)
        != model["public_rule_state_features"],
        "public_rule_state_feature_schema": (
            PUBLIC_RULE_STATE_FEATURE_SCHEMA_VERSION
            != model["public_rule_state_feature_schema"]
        ),
        "entity_feature_adapter_version": runtime_adapter
        != model["entity_feature_adapter_version"],
        "meaningful_public_history": bool(args.meaningful_public_history)
        != model["meaningful_public_history"],
        "meaningful_public_history_pooling": str(
            args.meaningful_public_history_pooling
        )
        != model["meaningful_public_history_pooling"],
        "meaningful_public_history_target_gather": bool(
            args.meaningful_public_history_target_gather
        )
        != model["meaningful_public_history_target_gather"],
        "event_history_limit": int(args.event_history_limit)
        != model["event_history_limit"],
        "mask_hidden_info": bool(args.mask_hidden_info)
        != model["mask_hidden_info"],
        "require_35m_model": bool(args.require_35m_model)
        != model["require_35m_model"],
        "max_35m_params": int(args.max_35m_params)
        != expected_max_parameter_count,
        "topology_world_size": int(ddp.get("world_size", 0))
        != topology["world_size"],
        "topology_local_batch": int(args.batch_size)
        != topology["local_batch_size"],
        "topology_grad_accum": int(args.grad_accum_steps)
        != topology["grad_accum_steps"],
        "topology_global_batch": (
            int(ddp.get("world_size", 0))
            * int(args.batch_size)
            * int(args.grad_accum_steps)
            != topology["global_batch_size"]
        ),
        "ddp_shard_data": bool(args.ddp_shard_data)
        != topology["ddp_shard_data"],
        "training_rng_rank_offset": bool(args.training_rng_rank_offset)
        != topology["training_rng_rank_offset"],
    }
    failed = sorted(key for key, value in drift.items() if value)
    if failed:
        raise SystemExit(
            f"A1 native scratch runtime projection drift: {failed}"
        )


_A1_SCRATCH_DIAGNOSTIC_AUTHORITY_FIELDS = {
    "schema_version",
    "campaign_id",
    "arm_id",
    "diagnostic_only",
    "promotion_eligible",
    "exact_max_steps",
    "max_steps",
    "epochs",
    "checkpoint_steps",
    "value_trunk_grad_scale",
    "source_recipe_sha256",
    "source_execution_topology_sha256",
    "code_tree_sha256",
}
_A1_SCRATCH_VALUE_ROUTING_ARMS = {
    "V0": 0.0,
    "V25": 0.25,
    "V100": 1.0,
}
_A1_SCRATCH_TOPOLOGY_DIAGNOSTIC_FIELDS = (
    _A1_SCRATCH_DIAGNOSTIC_AUTHORITY_FIELDS
    | {
        "topology_residual_adapter",
        "max_parameter_count",
        "effective_recipe_sha256",
        "code_surface_sha256",
        "required_accelerator_family",
        "required_cuda_device_count",
    }
)
_A1_SCRATCH_TOPOLOGY_ARMS = {"C640": False, "T640": True}
_A1_SCRATCH_TOPOLOGY_CODE_SURFACE = (
    "tools/a1_h100_scratch_canary.py",
    "tools/a1_scratch_train.py",
    "tools/a1_current_science_contract.py",
    "tools/train_bc.py",
    "src/catan_zero/rl/entity_token_policy.py",
    "src/catan_zero/rl/relational_trunks.py",
)


def _a1_scratch_topology_expected_effective_recipe(
    *,
    source_recipe: Mapping[str, object],
    source_model: Mapping[str, object],
    source_topology: Mapping[str, object],
    max_steps: int,
) -> dict[str, object]:
    """Project current V25 science into the one allowed H100 diagnostic dose."""

    expected = copy.deepcopy(dict(source_recipe))
    expected.update(
        {
            "epochs": 1,
            "max_steps": int(max_steps),
            "world_size": int(source_topology["world_size"]),
            "batch_size": int(source_topology["local_batch_size"]),
            "grad_accum_steps": int(source_topology["grad_accum_steps"]),
            "global_batch_size": int(source_topology["global_batch_size"]),
        }
    )
    # These are authenticated separately because the generic effective-recipe
    # projection intentionally omits late-bound execution/reporting fields.
    for field in (
        "checkpoint_steps",
        "max_grad_norm",
        "post_policy_dose_value_trunk_grad_scale",
        "value_player_outcome_balance_mode",
    ):
        expected.pop(field, None)
    expected.update(
        {
            "per_game_value_weight_mode": "equal",
            "public_card_lr_mult": 1.0,
            "shared_action_lr_mult": 1.0,
            "per_game_policy_surprise_weighting": False,
            "target_reliability_confidence_weighting": False,
            "target_reliability_confidence_floor": 0.25,
            "public_rule_state_features": bool(
                source_model["public_rule_state_features"]
            ),
            "static_action_residual": bool(
                source_model["static_action_residual"]
            ),
            "legal_action_value_residual": bool(
                source_model["legal_action_value_residual"]
            ),
            "legal_action_value_set_statistics": bool(
                source_model["legal_action_value_set_statistics"]
            ),
            "value_tower_split_layers": int(
                source_model["value_tower_split_layers"]
            ),
        }
    )
    return expected


def _validate_a1_scratch_topology_code_binding(
    args: argparse.Namespace,
    *,
    expected_code_tree_sha256: str,
) -> None:
    """Require the exact reviewed runtime closure for the topology canary."""

    raw = str(getattr(args, "a1_ablation_code_binding_json", "") or "")
    try:
        binding = json.loads(raw)
    except json.JSONDecodeError as error:
        raise SystemExit(
            f"invalid A1 topology diagnostic code binding: {error}"
        ) from error
    if not isinstance(binding, dict) or set(binding) != {
        "schema_version",
        "records",
        "code_tree_sha256",
    }:
        raise SystemExit("A1 topology diagnostic code binding shape drift")
    unhashed = dict(binding)
    embedded_sha = unhashed.pop("code_tree_sha256", None)
    if (
        binding.get("schema_version")
        != "a1-scratch-topology-code-binding-v1"
        or embedded_sha != expected_code_tree_sha256
        or _canonical_json_sha256(unhashed) != expected_code_tree_sha256
    ):
        raise SystemExit("A1 topology diagnostic code binding digest drift")
    records = binding.get("records")
    if not isinstance(records, list) or [
        record.get("relative_path") if isinstance(record, dict) else None
        for record in records
    ] != list(_A1_SCRATCH_TOPOLOGY_CODE_SURFACE):
        raise SystemExit("A1 topology diagnostic code surface drift")
    for relative, record in zip(
        _A1_SCRATCH_TOPOLOGY_CODE_SURFACE, records, strict=True
    ):
        if not isinstance(record, dict) or set(record) != {
            "kind",
            "relative_path",
            "path",
            "sha256",
        }:
            raise SystemExit("A1 topology diagnostic code record is malformed")
        expected_path = (_REPO_ROOT / relative).resolve(strict=True)
        if (
            record["kind"] != "learner_code"
            or record["relative_path"] != relative
            or record["path"] != str(expected_path)
            or record["sha256"] != _sha256_existing_file(str(expected_path))
        ):
            raise SystemExit(
                f"A1 topology diagnostic code record drift: {relative}"
            )


def _require_a1_scratch_topology_h100_runtime(
    diagnostic: Mapping[str, object],
    ddp: Mapping[str, int | bool],
) -> list[dict[str, object]]:
    """Bind the trainer-side exception to eight CUDA-visible H100 devices."""

    if diagnostic.get("schema_version") != (
        "a1-scratch-topology-diagnostic-authority-v1"
    ):
        return []
    import torch

    required_count = int(diagnostic["required_cuda_device_count"])
    if not torch.cuda.is_available() or torch.cuda.device_count() != required_count:
        raise SystemExit(
            "A1 topology diagnostic requires exactly eight CUDA-visible H100 GPUs"
        )
    inventory: list[dict[str, object]] = []
    for index in range(required_count):
        properties = torch.cuda.get_device_properties(index)
        uuid = str(getattr(properties, "uuid", "") or "")
        record = {
            "index": index,
            "uuid": uuid,
            "name": str(properties.name),
            "total_memory_bytes": int(properties.total_memory),
            "compute_capability": [int(properties.major), int(properties.minor)],
        }
        inventory.append(record)
    if (
        any("H100" not in str(record["name"]).upper() for record in inventory)
        or any(not record["uuid"] for record in inventory)
        or len({str(record["uuid"]) for record in inventory}) != required_count
        or any(
            record["compute_capability"] != [9, 0] for record in inventory
        )
        or any(int(record["total_memory_bytes"]) <= 0 for record in inventory)
        or int(ddp.get("local_rank", -1)) not in range(required_count)
    ):
        raise SystemExit(
            "A1 topology diagnostic requires exactly eight unique CUDA-visible H100 GPUs"
        )
    return inventory


def _validate_a1_scratch_diagnostic_authority(
    raw: str,
    *,
    args: argparse.Namespace | None = None,
    science: Mapping[str, object] | None = None,
) -> dict[str, object] | None:
    """Validate one bounded, non-promotable scratch diagnostic override."""

    if not raw:
        return None
    try:
        authority = json.loads(raw)
    except json.JSONDecodeError as error:
        raise SystemExit(
            f"invalid A1 scratch diagnostic authority JSON: {error}"
        ) from error
    if not isinstance(authority, dict):
        raise SystemExit("A1 scratch diagnostic authority fields/schema drift")
    schema = authority.get("schema_version")
    campaign_id = authority.get("campaign_id")
    value_routing = (
        schema == "a1-scratch-bounded-diagnostic-authority-v1"
        and campaign_id == "scratch-value-routing-v0-v25-v100"
        and set(authority) == _A1_SCRATCH_DIAGNOSTIC_AUTHORITY_FIELDS
    )
    topology_campaign = (
        schema == "a1-scratch-topology-diagnostic-authority-v1"
        and campaign_id == "scratch-topology-c640-t640"
        and set(authority) == _A1_SCRATCH_TOPOLOGY_DIAGNOSTIC_FIELDS
    )
    if (
        not (value_routing or topology_campaign)
        or authority.get("diagnostic_only") is not True
        or authority.get("promotion_eligible") is not False
        or authority.get("exact_max_steps") is not True
    ):
        raise SystemExit("A1 scratch diagnostic authority fields/schema drift")
    arm_id = str(authority.get("arm_id", ""))
    expected_scale = (
        _A1_SCRATCH_VALUE_ROUTING_ARMS.get(arm_id)
        if value_routing
        else 0.25 if arm_id in _A1_SCRATCH_TOPOLOGY_ARMS else None
    )
    expected_topology_residual = (
        False
        if value_routing
        else _A1_SCRATCH_TOPOLOGY_ARMS.get(arm_id)
    )
    max_steps = authority.get("max_steps")
    epochs = authority.get("epochs")
    checkpoint_steps = authority.get("checkpoint_steps")
    scale = authority.get("value_trunk_grad_scale")
    if (
        expected_scale is None
        or isinstance(max_steps, bool)
        or not isinstance(max_steps, int)
        or not (128 <= max_steps <= 256 if topology_campaign else 1 <= max_steps <= 256)
        or isinstance(epochs, bool)
        or not isinstance(epochs, int)
        or epochs != 1
        or not isinstance(checkpoint_steps, list)
        or any(isinstance(step, bool) or not isinstance(step, int) for step in checkpoint_steps)
        or checkpoint_steps != sorted(set(checkpoint_steps))
        or any(step <= 0 or step >= max_steps for step in checkpoint_steps)
        or isinstance(scale, bool)
        or not isinstance(scale, (int, float))
        or float(scale) != expected_scale
        or (
            topology_campaign
            and authority.get("topology_residual_adapter")
            is not expected_topology_residual
        )
        or (
            topology_campaign
            and authority.get("max_parameter_count") != 43_000_000
        )
        or (
            topology_campaign
            and authority.get("required_accelerator_family") != "NVIDIA H100"
        )
        or (
            topology_campaign
            and authority.get("required_cuda_device_count") != 8
        )
        or (
            topology_campaign
            and authority.get("code_surface_sha256")
            != _canonical_json_sha256(list(_A1_SCRATCH_TOPOLOGY_CODE_SURFACE))
        )
        or any(
            not _is_sha256(authority.get(field))
            for field in (
                "source_recipe_sha256",
                "source_execution_topology_sha256",
                "code_tree_sha256",
                *(("effective_recipe_sha256",) if topology_campaign else ()),
            )
        )
    ):
        raise SystemExit("A1 scratch diagnostic authority value drift")
    if args is not None:
        try:
            parsed_steps = list(
                _parse_checkpoint_steps(
                    str(getattr(args, "checkpoint_steps", "") or ""),
                    max_steps=int(args.max_steps),
                )
            )
        except (AttributeError, TypeError, ValueError) as error:
            raise SystemExit(
                "A1 scratch diagnostic runtime fields are malformed"
            ) from error
        expected_ablation_id = (
            f"scratch-value-routing-{arm_id.lower()}"
            if value_routing
            else f"scratch-topology-{arm_id.lower()}"
        )
        if (
            int(args.max_steps) != max_steps
            or bool(args.exact_max_steps) is not True
            or int(args.epochs) != epochs
            or parsed_steps != checkpoint_steps
            or float(args.value_trunk_grad_scale) != expected_scale
            or bool(getattr(args, "topology_residual_adapter", False))
            is not bool(expected_topology_residual)
            or (
                topology_campaign
                and int(getattr(args, "max_35m_params", -1))
                != int(authority["max_parameter_count"])
            )
            or str(args.a1_learner_ablation_id or "") != expected_ablation_id
            or str(args.a1_ablation_code_tree_sha256 or "")
            != authority["code_tree_sha256"]
        ):
            raise SystemExit("A1 scratch diagnostic command/authority drift")
    if science is not None:
        source_recipe = science.get("learner_training_recipe")
        source_model = science.get("learner_model_construction")
        source_topology = science.get("learner_execution_topology")
        if (
            not isinstance(source_recipe, dict)
            or not isinstance(source_topology, dict)
            or (topology_campaign and not isinstance(source_model, dict))
            or authority["source_recipe_sha256"]
            != _canonical_json_sha256(source_recipe)
            or authority["source_execution_topology_sha256"]
            != _canonical_json_sha256(source_topology)
        ):
            raise SystemExit("A1 scratch diagnostic source authority drift")
        if topology_campaign:
            assert isinstance(source_model, dict)
            expected_checkpoints = list(
                step
                for step in _parse_checkpoint_steps(
                    str(source_recipe.get("checkpoint_steps", "") or ""),
                    max_steps=0,
                )
                if step < int(max_steps)
            )
            expected_effective = (
                _a1_scratch_topology_expected_effective_recipe(
                    source_recipe=source_recipe,
                    source_model=source_model,
                    source_topology=source_topology,
                    max_steps=int(max_steps),
                )
            )
            expected_effective_sha = _canonical_json_sha256(expected_effective)
            if (
                checkpoint_steps != expected_checkpoints
                or authority.get("effective_recipe_sha256")
                != expected_effective_sha
            ):
                raise SystemExit(
                    "A1 topology diagnostic matched V25 recipe drift"
                )
            if args is not None:
                actual_effective = _effective_a1_learner_training_recipe(
                    args,
                    {
                        "world_size": int(source_topology["world_size"]),
                        "rank": 0,
                        "local_rank": 0,
                        "enabled": True,
                    },
                )
                _bind_late_a1_recipe_fields(
                    actual_effective, args, expected_effective
                )
                actual_effective["per_game_value_weight_mode"] = str(
                    args.per_game_value_weight_mode
                )
                if str(args.value_player_outcome_balance_mode) != "none":
                    actual_effective["value_player_outcome_balance_mode"] = str(
                        args.value_player_outcome_balance_mode
                    )
                declared_raw = str(
                    getattr(args, "a1_effective_learner_recipe_json", "") or ""
                )
                declared_sha = str(
                    getattr(args, "a1_effective_learner_recipe_sha256", "") or ""
                )
                try:
                    declared_effective = json.loads(declared_raw)
                except json.JSONDecodeError as error:
                    raise SystemExit(
                        f"invalid A1 topology effective recipe JSON: {error}"
                    ) from error
                if (
                    actual_effective != expected_effective
                    or declared_effective != expected_effective
                    or declared_sha != expected_effective_sha
                    or _canonical_json_sha256(declared_effective)
                    != expected_effective_sha
                    or float(args.max_grad_norm)
                    != float(source_recipe["max_grad_norm"])
                    or float(args.post_policy_dose_value_trunk_grad_scale)
                    != float(
                        source_recipe[
                            "post_policy_dose_value_trunk_grad_scale"
                        ]
                    )
                    or str(args.value_player_outcome_balance_mode)
                    != str(source_recipe["value_player_outcome_balance_mode"])
                ):
                    raise SystemExit(
                        "A1 topology diagnostic command differs from exact V25 recipe"
                    )
                _validate_a1_scratch_topology_code_binding(
                    args,
                    expected_code_tree_sha256=str(authority["code_tree_sha256"]),
                )
    return authority


def _require_a1_scratch_execution_schedule(
    topology: Mapping[str, object],
    *,
    diagnostic_authority: Mapping[str, object] | None = None,
) -> None:
    """Require the exact commissioned from-scratch optimizer horizon."""

    if (
        topology.get("optimization_schedule_status")
        == "commissioned_scratch_update_horizon_v1"
        and topology.get("go_authorized") is True
        and topology.get("reviewed_optimizer_schedule_role")
        == "from_scratch_representation_learning_v1"
    ):
        return
    if (
        isinstance(diagnostic_authority, Mapping)
        and diagnostic_authority.get("diagnostic_only") is True
        and diagnostic_authority.get("promotion_eligible") is False
        and diagnostic_authority.get("exact_max_steps") is True
        and isinstance(diagnostic_authority.get("max_steps"), int)
        and 1 <= int(diagnostic_authority["max_steps"]) <= 256
        and diagnostic_authority.get("source_execution_topology_sha256")
        == _canonical_json_sha256(topology)
    ):
        return
    raise SystemExit(
        "A1 native scratch optimization schedule is unresolved; the sealed "
        "launcher may execute only the commissioned from-scratch update horizon "
        "or an authenticated bounded non-promotion diagnostic"
    )


def _preflight_a1_scratch_execution_authority(
    raw: str,
    diagnostic_raw: str = "",
    *,
    args: argparse.Namespace | None = None,
) -> None:
    """Authenticate the scratch marker before any corpus/model allocation."""

    if not raw:
        return
    try:
        authority = json.loads(raw)
    except json.JSONDecodeError as error:
        raise SystemExit(f"invalid A1 scratch authority JSON: {error}") from error
    if (
        not isinstance(authority, dict)
        or authority.get("schema_version")
        != "a1-coherent-scratch-plan-authority-v2"
    ):
        raise SystemExit("A1 scratch plan authority fields/schema drift")
    science = authority.get("science")
    topology = (
        science.get("learner_execution_topology")
        if isinstance(science, dict)
        else None
    )
    if not isinstance(topology, dict):
        raise SystemExit("A1 scratch authority has no execution topology")
    diagnostic = _validate_a1_scratch_diagnostic_authority(
        diagnostic_raw,
        args=args,
        science=science,
    )
    if diagnostic is None:
        _require_a1_scratch_execution_schedule(topology)
    else:
        _require_a1_scratch_execution_schedule(
            topology,
            diagnostic_authority=diagnostic,
        )


