class _IndexedValidationWeights:
    """Expose held-out row weights without allocating a corpus-sized vector."""

    def __init__(self, row_indices: np.ndarray, weights: np.ndarray) -> None:
        rows = np.asarray(row_indices, dtype=np.int64)
        values = np.asarray(weights, dtype=np.float64)
        if rows.ndim != 1 or values.shape != rows.shape:
            raise ValueError("indexed validation weight shape drift")
        order = np.argsort(rows, kind="stable")
        self._rows = rows[order]
        self._weights = values[order]
        if len(self._rows) and np.any(self._rows[1:] == self._rows[:-1]):
            raise ValueError("indexed validation rows must be unique")

    def __getitem__(self, row_indices: np.ndarray) -> np.ndarray:
        requested = np.asarray(row_indices, dtype=np.int64)
        if requested.size == 0:
            return np.empty(requested.shape, dtype=self._weights.dtype)
        if self._rows.size == 0:
            raise KeyError("validation requested a row from an empty weight measure")
        positions = np.searchsorted(self._rows, requested)
        if (
            np.any(positions >= len(self._rows))
            or np.any(self._rows[np.minimum(positions, len(self._rows) - 1)] != requested)
        ):
            raise KeyError("validation requested a row outside its weight measure")
        return self._weights[positions]


def _policy_aux_validation_objective_weights(
    sampling_weights: np.ndarray,
    policy_loss_weights: np.ndarray,
) -> np.ndarray:
    """Return the held-out density for the AUX policy CE objective.

    The auxiliary stream samples from ``q`` and applies row loss weight ``w``
    after sampling. Enumerating held-out rows must therefore use density
    ``q*w``. Conditioning ``q`` only on positive ``w`` is admission, not a
    replacement for the loss weight itself.
    """

    sampling = np.asarray(sampling_weights, dtype=np.float64)
    loss_weights = np.asarray(policy_loss_weights, dtype=np.float64)
    if sampling.ndim != 1 or loss_weights.shape != sampling.shape:
        raise ValueError("policy AUX validation objective weight shape drift")
    if (
        not np.isfinite(sampling).all()
        or not np.isfinite(loss_weights).all()
        or np.any(sampling < 0.0)
        or np.any(loss_weights < 0.0)
    ):
        raise ValueError("policy AUX validation objective weights are invalid")
    effective = sampling * loss_weights
    if float(effective.sum()) <= 0.0:
        raise ValueError("policy AUX validation objective has no positive mass")
    return effective


def _combine_policy_aux_validation_metrics(
    base_metrics: dict,
    aux_metrics: dict,
    *,
    policy_loss_weight: float,
    policy_aux_loss_weight: float,
    policy_kl_anchor_weight: float = 0.0,
) -> dict:
    """Reconstruct the exact two-stream policy objective used by training.

    The base and policy-AUX streams are normalized independently during the
    optimizer step.  Validation must therefore evaluate each held-out measure
    independently and combine their means with the configured AUX coefficient;
    concatenating rows or omitting AUX silently scores a different learner.
    """

    if not isinstance(base_metrics, dict) or not isinstance(aux_metrics, dict):
        raise ValueError("policy AUX validation metrics must be mappings")
    if "loss" not in base_metrics or "policy_loss" not in base_metrics:
        raise ValueError("base validation metrics are incomplete")
    if "policy_loss" not in aux_metrics:
        raise ValueError("policy AUX validation metrics are incomplete")
    coefficient = float(policy_aux_loss_weight)
    policy_coefficient = float(policy_loss_weight)
    anchor_coefficient = float(policy_kl_anchor_weight)
    if not math.isfinite(coefficient) or coefficient < 0.0:
        raise ValueError("policy AUX validation coefficient is invalid")
    if not math.isfinite(policy_coefficient) or policy_coefficient < 0.0:
        raise ValueError("policy validation coefficient is invalid")
    if not math.isfinite(anchor_coefficient) or anchor_coefficient < 0.0:
        raise ValueError("policy KL validation coefficient is invalid")

    base_policy = float(base_metrics["policy_loss"])
    aux_policy = float(aux_metrics["policy_loss"])
    base_anchor = float(base_metrics.get("policy_kl_anchor_loss", 0.0))
    aux_anchor = float(aux_metrics.get("policy_kl_anchor_loss", 0.0))
    combined_policy = base_policy + coefficient * aux_policy
    combined_anchor = base_anchor + coefficient * aux_anchor
    combined_loss = (
        float(base_metrics["loss"])
        + policy_coefficient * coefficient * aux_policy
        + anchor_coefficient * coefficient * aux_anchor
    )
    base_anchor_denominator = float(
        (base_metrics.get("loss_denominators") or {}).get(
            "policy_kl_anchor_loss", 0.0
        )
    )
    aux_anchor_denominator = float(
        (aux_metrics.get("loss_denominators") or {}).get(
            "policy_kl_anchor_loss", 0.0
        )
    )
    controller_denominator = (
        base_anchor_denominator + coefficient * aux_anchor_denominator
    )
    controller_anchor = (
        (
            base_anchor * base_anchor_denominator
            + coefficient * aux_anchor * aux_anchor_denominator
        )
        / controller_denominator
        if controller_denominator > 0.0
        else 0.0
    )
    combined = dict(base_metrics)
    base_target_metrics = base_metrics.get(
        "policy_target_distribution_metrics"
    )
    aux_target_metrics = aux_metrics.get(
        "policy_target_distribution_metrics"
    )
    combined.pop("policy_target_distribution_metrics", None)
    combined.pop(
        "policy_target_distribution_sufficient_statistics", None
    )
    combined.update(
        {
            "loss": combined_loss,
            "component_reconstructed_loss": combined_loss,
            "policy_loss": combined_policy,
            "policy_base_loss": base_policy,
            "policy_aux_loss": aux_policy,
            "policy_aux_loss_weight": coefficient,
            "policy_kl_anchor_loss": combined_anchor,
            "policy_kl_anchor_base_loss": base_anchor,
            "policy_kl_anchor_aux_loss": aux_anchor,
            "policy_kl_anchor_controller_measure": controller_anchor,
            "policy_kl_anchor_controller_weight_sum": controller_denominator,
            "policy_aux_validation_samples": int(aux_metrics.get("samples", 0)),
            "policy_aux_validation_effective_weight_sum": float(
                (aux_metrics.get("loss_denominators") or {}).get(
                    "policy_loss", 0.0
                )
            ),
            "base_raw_batch_mean_loss": float(
                base_metrics.get("raw_batch_mean_loss", base_metrics["loss"])
            ),
            "policy_base_target_distribution_metrics": (
                base_target_metrics
            ),
            "policy_aux_target_distribution_metrics": aux_target_metrics,
        }
    )
    return combined


def objective_matched_validation_evaluation_identity(
    *,
    model_state_sha256: str,
    runtime_binding: Mapping[str, object],
    epoch: int,
    optimizer_step: int,
) -> dict[str, object]:
    """Bind validation to the exact model state and runtime that produced it."""

    if not _is_sha256(model_state_sha256):
        raise ValueError("objective-matched validation model identity is malformed")
    if not isinstance(runtime_binding, Mapping) or not runtime_binding:
        raise ValueError("objective-matched validation runtime binding is malformed")
    if (
        isinstance(epoch, bool)
        or not isinstance(epoch, int)
        or epoch < 0
        or isinstance(optimizer_step, bool)
        or not isinstance(optimizer_step, int)
        or optimizer_step < 0
    ):
        raise ValueError("objective-matched validation step identity is malformed")
    runtime_sha256 = _canonical_json_sha256(dict(runtime_binding))
    checkpoint_identity = {
        "model_state_sha256": model_state_sha256,
        "runtime_binding_sha256": runtime_sha256,
        "epoch": epoch,
        "optimizer_step": optimizer_step,
    }
    return {
        "schema_version": COMPOSITE_VALIDATION_EVALUATION_SCHEMA,
        "evaluated_model_state_sha256": model_state_sha256,
        "evaluated_checkpoint_identity_sha256": _canonical_json_sha256(
            checkpoint_identity
        ),
        "evaluation_runtime_binding_sha256": runtime_sha256,
        "evaluation_epoch": epoch,
        "evaluation_optimizer_step": optimizer_step,
    }


def _objective_matched_promotion_metrics_binding(
    matched: Mapping[str, object],
) -> dict[str, object]:
    metrics = matched.get("metrics")
    components = matched.get("components")
    if not isinstance(metrics, dict) or not isinstance(components, dict):
        raise ValueError("objective-matched promotion metrics are malformed")
    component_metrics: dict[str, dict] = {}
    for component_id, report in components.items():
        values = report.get("metrics") if isinstance(report, dict) else None
        if not isinstance(component_id, str) or not isinstance(values, dict):
            raise ValueError("objective-matched component promotion metrics are malformed")
        component_metrics[component_id] = values
    binding = {
        "aggregate_metrics": metrics,
        "component_metrics": component_metrics,
    }
    if matched.get("schema_version") in {
        COMPOSITE_VALIDATION_MEASURE_SCHEMA_V3,
        POLICY_AUX_VALIDATION_MEASURE_SCHEMA,
    }:
        binding["validation_contract"] = {
            "schema_version": matched.get("schema_version"),
            "measure": matched.get("measure"),
            "objective_matched": matched.get("objective_matched"),
            "validation_key": matched.get("validation_key"),
            "objective_match": matched.get("objective_match"),
            "policy_aux": matched.get("policy_aux"),
        }
    return binding


def _reseal_objective_matched_validation_wrapper(
    matched: dict[str, object],
) -> dict[str, object]:
    """Rebind mutable aggregate/component metrics after objective composition."""

    provenance = matched.get("provenance")
    if not isinstance(provenance, dict):
        raise ValueError("objective-matched validation provenance is missing")
    provenance = dict(provenance)
    provenance["promotion_metrics_sha256"] = _canonical_json_sha256(
        _objective_matched_promotion_metrics_binding(matched)
    )
    matched["provenance"] = provenance
    matched["provenance_sha256"] = _canonical_json_sha256(provenance)
    return matched


def _validate_composite_validation_key_role(
    wrapper: Mapping[str, object], *, expected_key: str
) -> None:
    """Authenticate whether a composite wrapper is decision or natural evidence."""

    schema = wrapper.get("schema_version")
    if schema in {
        COMPOSITE_VALIDATION_MEASURE_SCHEMA,
        "policy-aux-validation-measure-v1",
    }:
        provenance = wrapper.get("provenance")
        if (
            expected_key != OBJECTIVE_MATCHED_VALIDATION_KEY
            or wrapper.get("objective_matched") is not True
            or wrapper.get("objective_match") is not None
            or wrapper.get("validation_key") is not None
            or (
                isinstance(provenance, Mapping)
                and provenance.get("schema_version")
                != COMPOSITE_VALIDATION_PROVENANCE_SCHEMA
            )
        ):
            raise ValueError("legacy composite validation has an invalid key role")
        return
    if schema not in {
        COMPOSITE_VALIDATION_MEASURE_SCHEMA_V3,
        POLICY_AUX_VALIDATION_MEASURE_SCHEMA,
    }:
        raise ValueError("composite validation schema is unsupported")
    objective_match = wrapper.get("objective_match")
    expected_fields = {
        "component_game_row_sampling_matched",
        "training_value_player_outcome_balance_mode",
        "validation_value_player_outcome_balance_mode",
        "value_player_outcome_balance_matched",
        "validation_outcome_measure",
    }
    if not isinstance(objective_match, dict) or set(objective_match) != expected_fields:
        raise ValueError("composite validation v3 declaration is malformed")
    outcome_matched = (
        objective_match["training_value_player_outcome_balance_mode"]
        == objective_match["validation_value_player_outcome_balance_mode"]
    )
    declared_key = (
        OBJECTIVE_MATCHED_VALIDATION_KEY
        if outcome_matched
        else NATURAL_COMPOSITE_VALIDATION_KEY
    )
    provenance = wrapper.get("provenance")
    if (
        objective_match.get("component_game_row_sampling_matched") is not True
        or objective_match.get("value_player_outcome_balance_matched")
        is not outcome_matched
        or wrapper.get("objective_matched") is not outcome_matched
        or wrapper.get("validation_key") != declared_key
        or expected_key != declared_key
        or not isinstance(provenance, dict)
        or provenance.get("schema_version")
        != COMPOSITE_VALIDATION_PROVENANCE_SCHEMA_V3
        or provenance.get("validation_key") != declared_key
        or provenance.get("objective_match_sha256")
        != _canonical_json_sha256(objective_match)
        or wrapper.get("provenance_sha256")
        != _canonical_json_sha256(provenance)
    ):
        raise ValueError("composite validation v3 key-role provenance is malformed")


def _validated_objective_matched_validation_wrapper(
    epoch_metrics: dict,
    *,
    require_matched: bool,
    require_provenance: bool,
) -> dict | None:
    """Validate the complete authenticated validation wrapper before use."""

    if (
        OBJECTIVE_MATCHED_VALIDATION_KEY in epoch_metrics
        and NATURAL_COMPOSITE_VALIDATION_KEY in epoch_metrics
    ):
        raise ValueError(
            "validation epoch declares both objective-matched and natural composite roles"
        )
    matched = epoch_metrics.get(OBJECTIVE_MATCHED_VALIDATION_KEY)
    if not isinstance(matched, dict):
        natural = epoch_metrics.get(NATURAL_COMPOSITE_VALIDATION_KEY)
        if isinstance(natural, dict):
            raise ValueError(
                "natural composite validation does not match the learner objective; "
                "objective-matched selection is unavailable"
            )
        if require_matched:
            raise ValueError(
                "authenticated composite adjudication requires objective-matched "
                "validation; raw concatenated-row fallback is not admissible"
            )
        return None
    schema = matched.get("schema_version")
    measure = matched.get("measure")
    current_schema = schema in {
        COMPOSITE_VALIDATION_MEASURE_SCHEMA_V3,
        POLICY_AUX_VALIDATION_MEASURE_SCHEMA,
    }
    allowed_measure = (
        measure == COMPOSITE_VALIDATION_MEASURE
        if schema
        in {
            COMPOSITE_VALIDATION_MEASURE_SCHEMA,
            COMPOSITE_VALIDATION_MEASURE_SCHEMA_V3,
        }
        else (
            schema
            in {
                "policy-aux-validation-measure-v1",
                POLICY_AUX_VALIDATION_MEASURE_SCHEMA,
            }
            and measure == f"{COMPOSITE_VALIDATION_MEASURE}+conditioned_policy_aux"
        )
    )
    metrics = matched.get("metrics")
    components = matched.get("components")
    ratios = matched.get("component_sampling_ratios")
    samples = matched.get("samples")
    games = matched.get("games")
    if (
        matched.get("objective_matched") is not True
        or not allowed_measure
        or not isinstance(metrics, dict)
        or not isinstance(components, dict)
        or len(components) < 2
        or not isinstance(ratios, dict)
        or set(components) != set(ratios)
        or isinstance(samples, bool)
        or not isinstance(samples, int)
        or samples <= 0
        or isinstance(games, bool)
        or not isinstance(games, int)
        or games <= 0
    ):
        if require_matched or matched:
            raise ValueError("objective-matched validation wrapper is malformed")
        return None
    _validate_composite_validation_key_role(
        matched, expected_key=OBJECTIVE_MATCHED_VALIDATION_KEY
    )
    objective_match = matched.get("objective_match")
    if current_schema and objective_match is None:
        raise ValueError(
            "objective-matched validation contract lacks its v3 declaration"
        )
    if objective_match is not None:
        expected_match_fields = {
            "component_game_row_sampling_matched",
            "training_value_player_outcome_balance_mode",
            "validation_value_player_outcome_balance_mode",
            "value_player_outcome_balance_matched",
            "validation_outcome_measure",
        }
        if (
            not isinstance(objective_match, dict)
            or set(objective_match) != expected_match_fields
            or objective_match.get("component_game_row_sampling_matched") is not True
            or objective_match.get("training_value_player_outcome_balance_mode")
            not in {"none", "sampler_balanced_v1"}
            or objective_match.get("validation_value_player_outcome_balance_mode")
            not in {"none", "sampler_balanced_v1"}
        ):
            raise ValueError("objective-matched validation contract is malformed")
        declared_outcome_match = (
            objective_match["training_value_player_outcome_balance_mode"]
            == objective_match["validation_value_player_outcome_balance_mode"]
        )
        expected_validation_measure = (
            "natural_holdout_v1"
            if objective_match["validation_value_player_outcome_balance_mode"]
            == "none"
            else objective_match["validation_value_player_outcome_balance_mode"]
        )
        if (
            objective_match.get("value_player_outcome_balance_matched")
            is not declared_outcome_match
            or objective_match.get("validation_outcome_measure")
            != expected_validation_measure
            or matched.get("objective_matched") is not declared_outcome_match
        ):
            raise ValueError("objective-matched validation contract is inconsistent")
    validation_key = matched.get("validation_key")
    if current_schema and validation_key != OBJECTIVE_MATCHED_VALIDATION_KEY:
        raise ValueError(
            "objective-matched validation contract has the wrong report-key role"
        )
    ratio_values = np.asarray(list(ratios.values()), dtype=np.float64)
    if (
        ratio_values.shape != (len(ratios),)
        or not np.isfinite(ratio_values).all()
        or np.any(ratio_values <= 0.0)
        or not math.isclose(
            float(ratio_values.sum()), 1.0, rel_tol=0.0, abs_tol=1e-9
        )
    ):
        raise ValueError("objective-matched component ratios are malformed")
    coverage: dict[str, dict[str, object]] = {}
    component_rows = 0
    component_games = 0
    component_indices: set[int] = set()
    for component_id, ratio in ratios.items():
        report = components.get(component_id)
        if not isinstance(component_id, str) or not component_id:
            raise ValueError("objective-matched component id is malformed")
        if not isinstance(report, dict):
            raise ValueError("objective-matched component coverage is malformed")
        index = report.get("component_index")
        rows = report.get("rows")
        component_game_count = report.get("games")
        min_rows = report.get("min_rows_per_game")
        max_rows = report.get("max_rows_per_game")
        component_metrics = report.get("metrics")
        if (
            isinstance(index, bool)
            or not isinstance(index, int)
            or index < 0
            or isinstance(rows, bool)
            or not isinstance(rows, int)
            or rows <= 0
            or isinstance(component_game_count, bool)
            or not isinstance(component_game_count, int)
            or component_game_count <= 0
            or isinstance(min_rows, bool)
            or not isinstance(min_rows, int)
            or min_rows <= 0
            or isinstance(max_rows, bool)
            or not isinstance(max_rows, int)
            or max_rows < min_rows
            or not component_game_count * min_rows
            <= rows
            <= component_game_count * max_rows
            or not isinstance(component_metrics, dict)
            or report.get("authenticated_sampling_ratio") != ratio
        ):
            raise ValueError(
                f"objective-matched component coverage is malformed: {component_id}"
            )
        component_indices.add(index)
        component_rows += rows
        component_games += component_game_count
        coverage[component_id] = {
            "component_index": index,
            "authenticated_sampling_ratio": ratio,
            "rows": rows,
            "games": component_game_count,
            "min_rows_per_game": min_rows,
            "max_rows_per_game": max_rows,
        }
    if (
        component_indices != set(range(len(components)))
        or component_rows != samples
        or component_games != games
    ):
        raise ValueError("objective-matched component coverage totals are malformed")
    provenance = matched.get("provenance")
    provenance_sha256 = matched.get("provenance_sha256")
    if (
        provenance is None
        and provenance_sha256 is None
        and not require_provenance
        and not current_schema
    ):
        return matched
    if (
        not isinstance(provenance, dict)
        or provenance.get("schema_version")
        != (
            COMPOSITE_VALIDATION_PROVENANCE_SCHEMA_V3
            if current_schema
            else COMPOSITE_VALIDATION_PROVENANCE_SCHEMA
        )
        or provenance.get("measure") != COMPOSITE_VALIDATION_MEASURE
        or not _is_sha256(provenance.get("descriptor_fingerprint"))
        or not _is_sha256(provenance.get("payload_inventory_sha256"))
        or not _is_sha256(provenance.get("validation_game_seed_set_sha256"))
        or not _is_sha256(provenance.get("promotion_metrics_sha256"))
        or provenance.get("component_coverage_sha256")
        != _canonical_json_sha256(coverage)
        or provenance.get("promotion_metrics_sha256")
        != _canonical_json_sha256(
            _objective_matched_promotion_metrics_binding(matched)
        )
        or provenance_sha256 != _canonical_json_sha256(provenance)
    ):
        raise ValueError("objective-matched validation provenance is malformed")
    if objective_match is not None:
        if (
            provenance.get("training_value_player_outcome_balance_mode")
            != objective_match["training_value_player_outcome_balance_mode"]
            or provenance.get("validation_value_player_outcome_balance_mode")
            != objective_match["validation_value_player_outcome_balance_mode"]
            or provenance.get("value_player_outcome_balance_matched")
            is not objective_match["value_player_outcome_balance_matched"]
        ):
            raise ValueError(
                "objective-matched validation provenance is inconsistent"
            )
        if current_schema and (
            provenance.get("validation_key") != validation_key
            or provenance.get("objective_match_sha256")
            != _canonical_json_sha256(objective_match)
        ):
            raise ValueError(
                "objective-matched validation v3 declaration provenance is malformed"
            )
    source_authority = provenance.get("source_authority_semantic_sha256")
    if source_authority is not None and not _is_sha256(source_authority):
        raise ValueError("objective-matched source authority is malformed")
    if (
        provenance.get("evaluation_schema_version")
        != COMPOSITE_VALIDATION_EVALUATION_SCHEMA
        or not _is_sha256(provenance.get("evaluated_model_state_sha256"))
        or not _is_sha256(
            provenance.get("evaluated_checkpoint_identity_sha256")
        )
        or not _is_sha256(provenance.get("evaluation_runtime_binding_sha256"))
        or isinstance(provenance.get("evaluation_epoch"), bool)
        or not isinstance(provenance.get("evaluation_epoch"), int)
        or int(provenance["evaluation_epoch"]) < 0
        or isinstance(provenance.get("evaluation_optimizer_step"), bool)
        or not isinstance(provenance.get("evaluation_optimizer_step"), int)
        or int(provenance["evaluation_optimizer_step"]) < 0
    ):
        raise ValueError("objective-matched evaluation identity is malformed")
    expected_checkpoint_identity = _canonical_json_sha256(
        {
            "model_state_sha256": provenance["evaluated_model_state_sha256"],
            "runtime_binding_sha256": provenance[
                "evaluation_runtime_binding_sha256"
            ],
            "epoch": provenance["evaluation_epoch"],
            "optimizer_step": provenance["evaluation_optimizer_step"],
        }
    )
    if (
        provenance["evaluated_checkpoint_identity_sha256"]
        != expected_checkpoint_identity
    ):
        raise ValueError("objective-matched checkpoint identity is malformed")
    return matched


def objective_matched_validation_metrics(
    epoch_metrics: dict,
    *,
    require_matched: bool = False,
    require_provenance: bool = False,
) -> dict:
    """Return promotion-facing validation means, with historical fallback.

    Composite reports wrap their authenticated aggregate with measure metadata;
    ordinary and historical reports only have the raw ``validation`` object.
    Centralizing this choice prevents downstream sweep/adjudication code from
    accidentally continuing to rank new composite candidates by raw row mix.
    """
    matched = _validated_objective_matched_validation_wrapper(
        epoch_metrics,
        require_matched=require_matched,
        require_provenance=require_provenance,
    )
    if matched is not None:
        return matched["metrics"]
    legacy = epoch_metrics.get("validation")
    return legacy if isinstance(legacy, dict) else {}


def objective_matched_validation_component_metrics(
    epoch_metrics: dict,
    *,
    require_matched: bool = False,
    require_provenance: bool = False,
) -> dict[str, dict]:
    """Return per-component metrics from an authenticated matched wrapper."""

    matched = _validated_objective_matched_validation_wrapper(
        epoch_metrics,
        require_matched=require_matched,
        require_provenance=require_provenance,
    )
    if matched is not None:
        components = matched.get("components")
        if isinstance(components, dict) and components:
            result = {}
            for component_id, report in components.items():
                metrics = report.get("metrics") if isinstance(report, dict) else None
                if not isinstance(component_id, str) or not isinstance(metrics, dict):
                    raise ValueError("objective-matched component metrics are malformed")
                result[component_id] = metrics
            return result
    return {}


def _weighted_validation_means(
    reports: list[dict], weights: np.ndarray
) -> dict[str, float]:
    """Combine mean-like validation fields under an explicit probability measure."""
    if not reports:
        raise SystemExit("cannot aggregate an empty validation report set")
    normalized = np.asarray(weights, dtype=np.float64)
    if normalized.shape != (len(reports),) or not np.isfinite(normalized).all():
        raise SystemExit("validation aggregation weights are malformed")
    total = float(normalized.sum())
    if total <= 0.0:
        raise SystemExit("validation aggregation weights have no mass")
    normalized = normalized / total
    result: dict[str, float] = {}
    for key in _OBJECTIVE_MATCHED_VALIDATION_MEANS:
        if all(key in report for report in reports):
            result[key] = float(
                np.dot(
                    normalized,
                    np.asarray([float(report[key]) for report in reports]),
                )
            )
    return result


_VALUE_VALIDATION_WIDTH_BUCKETS = (
    (1, 1, "1"),
    (2, 4, "2-4"),
    (5, 10, "5-10"),
    (11, 20, "11-20"),
    (21, None, "21+"),
)


def _value_validation_width_bucket(legal_width: int) -> str:
    width = int(legal_width)
    for lower, upper, label in _VALUE_VALIDATION_WIDTH_BUCKETS:
        if width >= lower and (upper is None or width <= upper):
            return label
    return "0"


def _value_validation_strata_parts(
    data: object,
    batch: np.ndarray,
    value_error,
    value_weights,
    value_active_mask,
    *,
    prediction=None,
    target=None,
    action_types_by_id: tuple[str, ...] | None = None,
) -> dict[str, dict[str, dict[str, float]]]:
    """Exact scalar-value MSE sufficient statistics by strategic row class.

    This diagnostic deliberately follows the *same* per-row error, confidence,
    sample weight, and eligibility mask as the scalar value objective.  It is
    therefore able to expose a strategically important regression that a
    corpus-wide mean hides without inventing a second validation measure.
    """

    errors = np.asarray(value_error.detach().float().cpu(), dtype=np.float64)
    weights = np.asarray(value_weights.detach().float().cpu(), dtype=np.float64)
    active = np.asarray(
        value_active_mask.detach().bool().cpu(), dtype=np.bool_
    )
    if (
        errors.shape != (len(batch),)
        or weights.shape != errors.shape
        or active.shape != errors.shape
    ):
        raise ValueError("value validation stratum input shape drift")
    effective = np.where(active, weights, 0.0)
    predictions = (
        np.asarray(prediction.detach().float().cpu(), dtype=np.float64)
        if prediction is not None
        else None
    )
    targets = (
        np.asarray(target.detach().float().cpu(), dtype=np.float64)
        if target is not None
        else None
    )
    if (predictions is None) != (targets is None):
        raise ValueError("value validation prediction/target must be provided together")
    if predictions is not None and (
        predictions.shape != errors.shape or targets.shape != errors.shape
    ):
        raise ValueError("value validation prediction/target shape drift")
    legal = np.asarray(data["legal_action_ids"][batch])
    if legal.ndim != 2 or legal.shape[0] != len(batch):
        raise ValueError("value validation requires rectangular legal actions")
    legal_widths = np.sum(legal >= 0, axis=1).astype(np.int64, copy=False)
    actions = np.asarray(data["action_taken"][batch], dtype=np.int64)
    phases = (
        np.asarray(data["phase"][batch]).astype(str)
        if "phase" in data
        else np.full(len(batch), "unknown")
    )

    result: dict[str, dict[str, dict[str, float]]] = {}

    def _add(axis: str, label: str, mask: np.ndarray) -> None:
        selected = np.asarray(mask, dtype=np.bool_) & active
        row_weights = effective[selected]
        axis_report = result.setdefault(axis, {})
        parts = {
            "weighted_sum": float(np.dot(errors[selected], row_weights)),
            "weight_sum": float(row_weights.sum()),
            "rows": float(np.count_nonzero(selected)),
        }
        if predictions is not None and targets is not None:
            selected_predictions = predictions[selected]
            selected_targets = targets[selected]
            parts.update(
                {
                    "weighted_residual_sum": float(
                        np.dot(
                            selected_predictions - selected_targets,
                            row_weights,
                        )
                    ),
                    "weighted_prediction_sum": float(
                        np.dot(selected_predictions, row_weights)
                    ),
                    "weighted_target_sum": float(
                        np.dot(selected_targets, row_weights)
                    ),
                    "weighted_prediction_sq_sum": float(
                        np.dot(selected_predictions**2, row_weights)
                    ),
                    "weighted_target_sq_sum": float(
                        np.dot(selected_targets**2, row_weights)
                    ),
                    "weighted_prediction_target_sum": float(
                        np.dot(
                            selected_predictions * selected_targets,
                            row_weights,
                        )
                    ),
                }
            )
        axis_report[str(label)] = parts

    forced = legal_widths == 1
    _add("decision_class", "forced", forced)
    _add("decision_class", "multi_action", legal_widths > 1)
    for _, _, label in _VALUE_VALIDATION_WIDTH_BUCKETS:
        _add(
            "legal_width",
            label,
            np.fromiter(
                (
                    _value_validation_width_bucket(width) == label
                    for width in legal_widths
                ),
                dtype=np.bool_,
                count=len(legal_widths),
            ),
        )
    for phase in sorted(set(phases.tolist())):
        _add("phase", phase, phases == phase)

    if action_types_by_id is not None:
        action_types = tuple(str(value).upper() for value in action_types_by_id)
        malformed = forced & (
            (actions < 0) | (actions >= len(action_types))
        )
        if bool(np.any(malformed)):
            raise ValueError(
                "forced value-validation row has an action outside the "
                "authoritative action catalog"
            )
        forced_labels = np.full(len(batch), "", dtype=object)
        forced_rows = np.flatnonzero(forced)
        forced_labels[forced_rows] = [
            action_types[int(actions[row])] for row in forced_rows
        ]
        for label in ("ROLL", "END_TURN"):
            _add("forced_action_type", label, forced & (forced_labels == label))
        _add(
            "forced_action_type",
            "OTHER",
            forced
            & (forced_labels != "ROLL")
            & (forced_labels != "END_TURN"),
        )
        _add("query_state", "turn_start_roll", forced & (forced_labels == "ROLL"))
        _add(
            "query_state",
            "turn_end_end_turn",
            forced & (forced_labels == "END_TURN"),
        )
        _add(
            "query_state",
            "other",
            ~(forced & ((forced_labels == "ROLL") | (forced_labels == "END_TURN"))),
        )
    return result


def _merge_value_validation_strata(
    target: dict[str, dict[str, dict[str, float]]],
    source: dict[str, dict[str, dict[str, float]]],
) -> None:
    for axis, strata in source.items():
        target_axis = target.setdefault(axis, {})
        for label, parts in strata.items():
            target_parts = target_axis.setdefault(label, {})
            for key, value in parts.items():
                target_parts[key] = target_parts.get(key, 0.0) + float(value)


def _reduce_value_validation_strata(
    strata: dict[str, dict[str, dict[str, float]]],
    ddp: dict[str, int | bool],
) -> dict[str, dict[str, dict[str, float]]]:
    flattened = {
        f"{axis}\0{label}\0{key}": float(value)
        for axis, labels in strata.items()
        for label, parts in labels.items()
        for key, value in parts.items()
    }
    # Phase/action strata are rank-local and sparse: one rank may legitimately
    # observe no rows for a label in its distributed validation slice.  A dense
    # NCCL vector built from local keys can therefore differ in both length and
    # ordering across ranks, causing a collective mismatch/hang.  Gather and
    # union the tiny telemetry maps instead.
    reduced = _reduce_sparse_named_sums(flattened, ddp)
    result: dict[str, dict[str, dict[str, float]]] = {}
    for name, value in reduced.items():
        axis, label, key = name.split("\0", 2)
        result.setdefault(axis, {}).setdefault(label, {})[key] = float(value)
    return result


def _finalize_value_validation_strata(
    strata: dict[str, dict[str, dict[str, float]]],
) -> dict[str, dict[str, dict[str, float | int]]]:
    def _one(parts: Mapping[str, float]) -> dict[str, float | int]:
        weight = float(parts.get("weight_sum", 0.0))
        mse = float(parts.get("weighted_sum", 0.0)) / weight if weight > 0.0 else 0.0
        result: dict[str, float | int] = {
            "mse": mse,
            "weighted_sum": float(parts.get("weighted_sum", 0.0)),
            "weight_sum": weight,
            "rows": int(round(float(parts.get("rows", 0.0)))),
        }
        if "weighted_residual_sum" not in parts:
            return result
        denominator = max(weight, 1.0e-30)
        prediction_mean = (
            float(parts.get("weighted_prediction_sum", 0.0)) / denominator
        )
        target_mean = float(parts.get("weighted_target_sum", 0.0)) / denominator
        prediction_variance = max(
            float(parts.get("weighted_prediction_sq_sum", 0.0)) / denominator
            - prediction_mean**2,
            0.0,
        )
        target_variance = max(
            float(parts.get("weighted_target_sq_sum", 0.0)) / denominator
            - target_mean**2,
            0.0,
        )
        covariance = (
            float(parts.get("weighted_prediction_target_sum", 0.0)) / denominator
            - prediction_mean * target_mean
        )
        correlation_denominator = math.sqrt(
            prediction_variance * target_variance
        )
        result.update(
            {
                "rmse": math.sqrt(max(mse, 0.0)),
                "bias": (
                    float(parts.get("weighted_residual_sum", 0.0)) / weight
                    if weight > 0.0
                    else 0.0
                ),
                "prediction_mean": prediction_mean if weight > 0.0 else 0.0,
                "target_mean": target_mean if weight > 0.0 else 0.0,
                "pearson": (
                    covariance / correlation_denominator
                    if correlation_denominator > 0.0
                    else 0.0
                ),
            }
        )
        return result

    return {
        axis: {label: _one(parts) for label, parts in labels.items()}
        for axis, labels in strata.items()
    }


_TRAINING_OBJECTIVE_METRIC_KEYS = (
    "policy_loss",
    "value_loss",
    # Diagnostic only (its coefficient is absent/zero), but it needs the same
    # exact component/game/row aggregation as the scalar objective so BCE
    # reports remain comparable to historical MSE.
    "scalar_value_mse_diagnostic",
    "final_vp_loss",
    "q_loss",
    "policy_kl_anchor_loss",
    "value_uncertainty_loss",
    "belief_resource_loss",
    "value_categorical_loss",
)


def _objective_measure_validation_aggregate(
    reports: list[dict], weights: np.ndarray
) -> tuple[dict[str, float], dict[str, object] | None]:
    """Aggregate validation under a row-sampling measure before normalization.

    A training loss is ``E_p[w * loss] / E_p[w]``. Averaging one normalized
    loss per game instead computes ``E_game[E_row[w*loss]/E_row[w]]`` and is
    different whenever active-policy or loser/value mass varies by game. The
    latter was incorrectly called objective-matched validation. Convert each
    game's sums to per-row densities, average those densities under the exact
    game/component draw probabilities, and divide only once.

    Historical/generic callbacks without sufficient statistics retain the old
    mean aggregation rather than fabricating exactness.
    """
    normalized = np.asarray(weights, dtype=np.float64)
    normalized = normalized / float(normalized.sum())
    metrics = _weighted_validation_means(reports, normalized)
    common_uniform_value = _aggregate_common_uniform_clean_outcome_scalar_mse(
        reports
    )
    if common_uniform_value is not None:
        # This metric intentionally answers a different, cross-recipe question
        # than the objective-matched aggregate below. Sum raw held-out row SSE
        # and count exactly once, independent of component/game sampling ratios
        # and every learner loss weight.
        metrics[COMMON_UNIFORM_CLEAN_OUTCOME_SCALAR_MSE_KEY] = (
            common_uniform_value
        )
    if all(
        isinstance(report.get("value_mse_strata_sufficient_statistics"), dict)
        and int(report.get("samples", 0)) > 0
        for report in reports
    ):
        axes = sorted(
            set().union(
                *(
                    set(report["value_mse_strata_sufficient_statistics"])
                    for report in reports
                )
            )
        )
        aggregate_strata: dict[str, dict[str, dict[str, float]]] = {}
        for axis in axes:
            labels = sorted(
                set().union(
                    *(
                        set(
                            report["value_mse_strata_sufficient_statistics"].get(
                                axis, {}
                            )
                        )
                        for report in reports
                    )
                )
            )
            for label in labels:
                density_parts: dict[str, float] = {}
                for probability, report in zip(normalized, reports, strict=True):
                    samples = float(report["samples"])
                    parts = (
                        report["value_mse_strata_sufficient_statistics"]
                        .get(axis, {})
                        .get(label, {})
                    )
                    for key, value in parts.items():
                        density_parts[key] = density_parts.get(key, 0.0) + (
                            float(probability) * float(value) / samples
                        )
                aggregate_strata.setdefault(axis, {})[label] = density_parts
        finalized_strata = _finalize_value_validation_strata(aggregate_strata)
        metrics["value_mse_strata"] = {}
        for axis, labels in finalized_strata.items():
            metrics["value_mse_strata"][axis] = {}
            for label, finalized in labels.items():
                density = aggregate_strata[axis][label]
                metrics["value_mse_strata"][axis][label] = {
                    key: value
                    for key, value in finalized.items()
                    if key not in {"weighted_sum", "weight_sum", "rows"}
                }
                metrics["value_mse_strata"][axis][label].update(
                    {
                        "weighted_numerator_per_sample": float(
                            density.get("weighted_sum", 0.0)
                        ),
                        "weight_per_sample": float(
                            density.get("weight_sum", 0.0)
                        ),
                        "row_probability": float(density.get("rows", 0.0)),
                    }
                )
        metrics["value_mse_strata_measure"] = (
            "objective_measure_weighted_density"
        )
    coefficient_rows = [report.get("objective_coefficients") for report in reports]
    has_objective_coefficients = bool(coefficient_rows) and all(
        isinstance(row, dict) and row == coefficient_rows[0]
        for row in coefficient_rows
    )
    if any(row is not None for row in coefficient_rows) and not has_objective_coefficients:
        raise SystemExit(
            "objective-matched validation reports have missing or inconsistent "
            "objective coefficients"
        )
    coefficients = coefficient_rows[0] if has_objective_coefficients else {}
    sufficient: dict[str, object] = {}
    for key in _TRAINING_OBJECTIVE_METRIC_KEYS:
        if not all(
            key in report
            and isinstance(report.get("loss_denominators"), dict)
            and key in report["loss_denominators"]
            and int(report.get("samples", 0)) > 0
            for report in reports
        ):
            continue
        numerator_density = 0.0
        denominator_density = 0.0
        for probability, report in zip(normalized, reports, strict=True):
            samples = float(report["samples"])
            denominator = float(report["loss_denominators"][key])
            numerator_density += (
                float(probability) * float(report[key]) * denominator / samples
            )
            denominator_density += float(probability) * denominator / samples
        metrics[key] = (
            numerator_density / denominator_density
            if denominator_density > 0.0
            else 0.0
        )
        sufficient[key] = {
            "weighted_numerator_per_sample": numerator_density,
            "weight_per_sample": denominator_density,
        }
    # Sampled-action agreement is conditional on policy-active rows, just like policy
    # cross-entropy.  In a scoped learner an excluded replay component reports
    # zero active rows and therefore zero agreement. Weighting that placeholder
    # zero by the component's sampling mass diluted fresh-policy agreement (for
    # the production .80/.20 split, .613 became .4904) even though replay never
    # entered the policy objective. Reconstruct both agreement means from their
    # explicit active-row denominator under the same component/game measure.
    for key in (
        "sampled_action_top1_accuracy",
        "sampled_action_top3_accuracy",
        "accuracy",
        "top3_accuracy",
    ):
        denominator_key = (
            "sampled_action_accuracy_active_count"
            if key.startswith("sampled_action_")
            else "accuracy_active_count"
        )
        if not all(
            key in report
            and denominator_key in report
            and int(report.get("samples", 0)) > 0
            for report in reports
        ):
            continue
        numerator_density = 0.0
        denominator_density = 0.0
        for probability, report in zip(normalized, reports, strict=True):
            samples = float(report["samples"])
            denominator = float(report[denominator_key])
            numerator_density += (
                float(probability) * float(report[key]) * denominator / samples
            )
            denominator_density += float(probability) * denominator / samples
        metrics[key] = (
            numerator_density / denominator_density
            if denominator_density > 0.0
            else 0.0
        )
        sufficient[key] = {
            "weighted_numerator_per_sample": numerator_density,
            "weight_per_sample": denominator_density,
        }
    if all(
        isinstance(
            report.get(
                "policy_target_distribution_sufficient_statistics"
            ),
            dict,
        )
        and int(report.get("samples", 0)) > 0
        for report in reports
    ):
        aggregate_target_stats: dict[str, object] = {}
        for probability, report in zip(normalized, reports, strict=True):
            samples = float(report["samples"])
            source = report[
                "policy_target_distribution_sufficient_statistics"
            ]
            scaled: dict[str, object] = {}
            _merge_policy_target_distribution_stats(scaled, source)
            for axis in ("overall", "phase", "opening_decision_index"):
                axis_value = scaled.get(axis)
                if axis == "overall" and isinstance(axis_value, dict):
                    for key in ("rows", *_POLICY_TARGET_METRIC_SUM_KEYS):
                        axis_value[key] = (
                            float(axis_value.get(key, 0.0))
                            * float(probability)
                            / samples
                        )
                elif isinstance(axis_value, dict):
                    for parts in axis_value.values():
                        if not isinstance(parts, dict):
                            continue
                        for key in (
                            "rows",
                            *_POLICY_TARGET_METRIC_SUM_KEYS,
                        ):
                            parts[key] = (
                                float(parts.get(key, 0.0))
                                * float(probability)
                                / samples
                            )
            _merge_policy_target_distribution_stats(
                aggregate_target_stats, scaled
            )
        metrics["policy_target_distribution_metrics"] = (
            _finalize_policy_target_distribution_stats(
                aggregate_target_stats,
                rows_are_density=True,
            )
        )
        sufficient["policy_target_distribution_metrics"] = (
            aggregate_target_stats
        )
    # CAT-100 is a sum of separately normalized masked-head objectives.  A
    # synthetic row denominator for their already-summed batch mean is not a
    # sufficient statistic: label density differs by head and by game.  Carry
    # and combine each head's numerator/denominator independently, then sum the
    # reconstructed conditional means exactly once.
    if all(
        isinstance(report.get("aux_subgoal_loss_parts"), dict)
        and int(report.get("samples", 0)) > 0
        for report in reports
    ):
        head_fields = sorted(
            set().union(
                *(
                    set(report["aux_subgoal_loss_parts"])
                    for report in reports
                )
            )
        )
        complete = all(
            all(
                isinstance(report["aux_subgoal_loss_parts"].get(field), dict)
                and "weighted_sum"
                in report["aux_subgoal_loss_parts"][field]
                and "weight_sum" in report["aux_subgoal_loss_parts"][field]
                for field in head_fields
            )
            for report in reports
        )
        if complete:
            aux_loss = 0.0
            aux_heads: dict[str, dict[str, float]] = {}
            for field in head_fields:
                numerator_density = 0.0
                denominator_density = 0.0
                for probability, report in zip(normalized, reports, strict=True):
                    samples = float(report["samples"])
                    parts = report["aux_subgoal_loss_parts"][field]
                    numerator_density += (
                        float(probability)
                        * float(parts["weighted_sum"])
                        / samples
                    )
                    denominator_density += (
                        float(probability)
                        * float(parts["weight_sum"])
                        / samples
                    )
                head_loss = (
                    numerator_density / denominator_density
                    if denominator_density > 0.0
                    else 0.0
                )
                aux_loss += head_loss
                aux_heads[field] = {
                    "weighted_numerator_per_sample": numerator_density,
                    "weight_per_sample": denominator_density,
                    "loss": head_loss,
                }
            metrics["aux_subgoal_loss"] = aux_loss
            sufficient["aux_subgoal_loss"] = {"heads": aux_heads}
    exact_zero_sets = [
        set(report.get("objective_exact_zero_terms", [])) for report in reports
    ]
    exact_zero_terms = (
        set.intersection(*exact_zero_sets) if exact_zero_sets else set()
    )
    for key in exact_zero_terms:
        metrics[key] = 0.0
        sufficient[key] = {"exact_zero": True}
    # These diagnostics are also conditional means.  In particular, averaging
    # per-game teacher-gap closure can Simpson-reverse an arm when games differ
    # in active-row density or target/prior gap. Reconstruct the KL densities
    # first, then form the ratio exactly once under the training measure.
    conditional_metrics = {
        "prior_kl_model_prior_mean": "prior_kl_rows",
        "prior_kl_prior_model_mean": "prior_kl_rows",
        "prior_kl_target_prior_mean": "prior_kl_rows",
        "active_policy_kl_target_model_mean": "active_policy_teacher_gap_weight_sum",
        "active_policy_kl_target_prior_mean": "active_policy_teacher_gap_weight_sum",
    }
    for key, denominator_key in conditional_metrics.items():
        if denominator_key == "active_policy_teacher_gap_weight_sum" and not all(
            denominator_key in report for report in reports
        ):
            # Historical validation artifacts predate explicit policy-measure
            # mass. Their closure was uniform over eligible rows; retain that
            # replay semantics while all new reports carry the exact weights.
            denominator_key = "active_policy_teacher_gap_rows"
        if not all(
            key in report
            and denominator_key in report
            and int(report.get("samples", 0)) > 0
            for report in reports
        ):
            continue
        numerator_density = 0.0
        denominator_density = 0.0
        for probability, report in zip(normalized, reports, strict=True):
            samples = float(report["samples"])
            denominator = float(report[denominator_key])
            numerator_density += (
                float(probability) * float(report[key]) * denominator / samples
            )
            denominator_density += float(probability) * denominator / samples
        metrics[key] = (
            numerator_density / denominator_density
            if denominator_density > 0.0
            else 0.0
        )
        sufficient[key] = {
            "weighted_numerator_per_sample": numerator_density,
            "weight_per_sample": denominator_density,
        }
    target_model = metrics.get("active_policy_kl_target_model_mean")
    target_prior = metrics.get("active_policy_kl_target_prior_mean")
    if target_model is not None and target_prior is not None:
        metrics["active_policy_teacher_gap_closure"] = (
            1.0 - target_model / target_prior if target_prior > 1.0e-8 else 0.0
        )
    model_prior = metrics.get("prior_kl_model_prior_mean")
    target_prior_legacy = metrics.get("prior_kl_target_prior_mean")
    if model_prior is not None and target_prior_legacy is not None:
        metrics["prior_kl_ratio"] = (
            model_prior / target_prior_legacy
            if target_prior_legacy > 1.0e-8
            else 0.0
        )
    if coefficients:
        categorical_active = float(
            coefficients.get("value_categorical_loss", 0.0)
        ) > 0.0
        primary_key = "value_categorical_loss" if categorical_active else "value_loss"
        if primary_key in metrics:
            metrics["primary_value_loss"] = metrics[primary_key]
    if coefficients:
        missing_exact = sorted(
            key
            for key, coefficient in coefficients.items()
            if float(coefficient) != 0.0 and key not in sufficient
        )
        if missing_exact:
            raise SystemExit(
                "objective-matched validation cannot reconstruct nonzero "
                "objective term(s) exactly: "
                + ", ".join(missing_exact)
            )
        exact_loss = sum(
            float(coefficient) * float(metrics.get(key, 0.0))
            for key, coefficient in coefficients.items()
        )
        # Promotion-facing loss is now the exact configured population objective.
        # Preserve the historical batch/game-normalized statistic under its honest
        # name for diagnostics and backwards comparisons.
        metrics["raw_batch_mean_loss"] = metrics.get("loss", exact_loss)
        metrics["component_reconstructed_loss"] = exact_loss
        metrics["loss"] = exact_loss
    return metrics, sufficient or None


def evaluate_composite_validation_measure(
    data,
    validation_indices: np.ndarray,
    evaluate_indices,
    *,
    evaluation_identity: Mapping[str, object],
    training_value_player_outcome_balance_mode: str = "none",
    validation_value_player_outcome_balance_mode: str = "none",
) -> dict[str, object]:
    """Evaluate a composite under its authenticated training distribution.

    The v2 learner samples ``component -> game -> row``. Concatenating holdout
    rows instead samples components and games in proportion to their row counts;
    on A1 that diluted the replay component by about 3.15x. Evaluate every game
    independently so rows are uniform *within* a game, average games uniformly
    inside each component, then apply the descriptor's authenticated component
    ratios. ``evaluate_indices`` performs all DDP reductions, and every rank
    traverses this deterministic component/game order, so collectives remain
    aligned even when a game has fewer rows than ranks.

    Outcome balancing is a separate part of the learner objective. In
    particular, ``sampler_balanced_v1`` is fitted on the training partition and
    is intentionally not fitted on validation labels. Report that distinction
    explicitly instead of calling a natural-outcome holdout objective-matched.
    """
    allowed_outcome_balance_modes = {"none", "sampler_balanced_v1"}
    training_outcome_balance_mode = str(
        training_value_player_outcome_balance_mode
    )
    validation_outcome_balance_mode = str(
        validation_value_player_outcome_balance_mode
    )
    if (
        training_outcome_balance_mode not in allowed_outcome_balance_modes
        or validation_outcome_balance_mode not in allowed_outcome_balance_modes
    ):
        raise SystemExit(
            "composite validation received an unknown value outcome-balance mode"
        )
    outcome_balance_matched = (
        training_outcome_balance_mode == validation_outcome_balance_mode
    )
    ratios = np.asarray(
        getattr(data, "component_game_sampling_ratios", tuple()), dtype=np.float64
    )
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    corpora = tuple(getattr(data, "corpora", tuple()))
    if (
        ratios.shape != (len(corpora),)
        or len(component_ids) != len(corpora)
        or len(corpora) < 2
        or not np.isfinite(ratios).all()
        or np.any(ratios <= 0.0)
        or not math.isclose(float(ratios.sum()), 1.0, rel_tol=0.0, abs_tol=1e-9)
    ):
        raise SystemExit(
            "objective-matched validation requires authenticated composite ids/ratios"
        )
    indices = np.asarray(validation_indices, dtype=np.int64)
    distillation_scope_authenticated = bool(
        getattr(data, "policy_distillation_scope_authenticated", False)
    )
    distillation_indices = set(
        int(value)
        for value in getattr(data, "policy_distillation_component_indices", tuple())
    )
    if distillation_scope_authenticated and (
        not distillation_indices
        or any(value < 0 or value >= len(component_ids) for value in distillation_indices)
    ):
        raise SystemExit(
            "objective-matched validation received invalid policy distillation scope"
        )
    components = np.asarray(data.component_indices_for_rows(indices), dtype=np.int64)
    seeds = np.asarray(data["game_seed"][indices], dtype=np.int64)
    metadata = getattr(data, "meta", None)
    if (
        not isinstance(metadata, dict)
        or metadata.get("schema") != "memmap_composite_v2"
        or not _is_sha256(metadata.get("descriptor_fingerprint"))
        or not _is_sha256(metadata.get("payload_inventory_sha256"))
    ):
        raise SystemExit(
            "objective-matched validation requires authenticated composite provenance"
        )
    component_reports: dict[str, dict[str, object]] = {}
    all_game_reports: list[dict] = []
    all_game_weights: list[float] = []
    for component, component_id in enumerate(component_ids):
        positions = np.flatnonzero(components == component)
        if positions.size == 0:
            raise SystemExit(
                f"authenticated validation component {component_id!r} has no rows"
            )
        component_indices = indices[positions]
        component_seeds = seeds[positions]
        games = np.unique(component_seeds)
        game_reports: list[dict] = []
        rows_per_game: list[int] = []
        for game_seed in games:
            game_indices = component_indices[component_seeds == game_seed]
            game_reports.append(evaluate_indices(game_indices))
            rows_per_game.append(int(game_indices.size))
        game_uniform, sufficient = _objective_measure_validation_aggregate(
            game_reports, np.ones(len(game_reports), dtype=np.float64)
        )
        all_game_reports.extend(game_reports)
        all_game_weights.extend(
            [float(ratios[component]) / len(game_reports)] * len(game_reports)
        )
        component_reports[str(component_id)] = {
            "component_index": int(component),
            "policy_distillation_enabled": bool(
                not distillation_scope_authenticated
                or component in distillation_indices
            ),
            "value_training_enabled": bool(
                not bool(getattr(data, "value_training_scope_authenticated", False))
                or component
                in set(getattr(data, "value_training_component_indices", tuple()))
            ),
            "authenticated_sampling_ratio": float(ratios[component]),
            "games": int(len(games)),
            "rows": int(positions.size),
            "min_rows_per_game": int(min(rows_per_game)),
            "max_rows_per_game": int(max(rows_per_game)),
            "metrics": game_uniform,
            **(
                {"objective_measure_sufficient_statistics": sufficient}
                if sufficient is not None
                else {}
            ),
        }
    aggregate, aggregate_sufficient = _objective_measure_validation_aggregate(
        all_game_reports, np.asarray(all_game_weights, dtype=np.float64)
    )
    coverage = {
        component_id: {
            key: component_reports[component_id][key]
            for key in (
                "component_index",
                "authenticated_sampling_ratio",
                "rows",
                "games",
                "min_rows_per_game",
                "max_rows_per_game",
            )
        }
        for component_id in component_reports
    }
    required_evaluation_fields = {
        "schema_version",
        "evaluated_model_state_sha256",
        "evaluated_checkpoint_identity_sha256",
        "evaluation_runtime_binding_sha256",
        "evaluation_epoch",
        "evaluation_optimizer_step",
    }
    if (
        not isinstance(evaluation_identity, Mapping)
        or set(evaluation_identity) != required_evaluation_fields
        or evaluation_identity.get("schema_version")
        != COMPOSITE_VALIDATION_EVALUATION_SCHEMA
    ):
        raise SystemExit(
            "objective-matched validation requires exact evaluation identity"
        )
    objective_match = {
        "component_game_row_sampling_matched": True,
        "training_value_player_outcome_balance_mode": (
            training_outcome_balance_mode
        ),
        "validation_value_player_outcome_balance_mode": (
            validation_outcome_balance_mode
        ),
        "value_player_outcome_balance_matched": outcome_balance_matched,
        "validation_outcome_measure": (
            "natural_holdout_v1"
            if validation_outcome_balance_mode == "none"
            else validation_outcome_balance_mode
        ),
    }
    validation_key = (
        OBJECTIVE_MATCHED_VALIDATION_KEY
        if outcome_balance_matched
        else NATURAL_COMPOSITE_VALIDATION_KEY
    )
    provenance = {
        "schema_version": COMPOSITE_VALIDATION_PROVENANCE_SCHEMA_V3,
        "measure": COMPOSITE_VALIDATION_MEASURE,
        "descriptor_fingerprint": metadata["descriptor_fingerprint"],
        "payload_inventory_sha256": metadata["payload_inventory_sha256"],
        "source_authority_semantic_sha256": metadata.get(
            "source_authority_semantic_sha256"
        ),
        "validation_game_seed_set_sha256": _game_seed_set_sha256(
            np.unique(seeds)
        ),
        "component_coverage_sha256": _canonical_json_sha256(coverage),
        "training_value_player_outcome_balance_mode": (
            training_outcome_balance_mode
        ),
        "validation_value_player_outcome_balance_mode": (
            validation_outcome_balance_mode
        ),
        "value_player_outcome_balance_matched": outcome_balance_matched,
        "validation_key": validation_key,
        "objective_match_sha256": _canonical_json_sha256(objective_match),
        "evaluation_schema_version": evaluation_identity["schema_version"],
        **{
            key: evaluation_identity[key]
            for key in required_evaluation_fields
            if key != "schema_version"
        },
    }
    result: dict[str, object] = {
        "schema_version": COMPOSITE_VALIDATION_MEASURE_SCHEMA_V3,
        "measure": COMPOSITE_VALIDATION_MEASURE,
        "objective_matched": outcome_balance_matched,
        "validation_key": validation_key,
        "objective_match": objective_match,
        "samples": int(indices.size),
        "games": int(
            sum(int(report["games"]) for report in component_reports.values())
        ),
        "component_sampling_ratios": {
            str(component_id): float(ratio)
            for component_id, ratio in zip(component_ids, ratios, strict=True)
        },
        "policy_distillation_component_ids": (
            [component_ids[index] for index in sorted(distillation_indices)]
            if distillation_scope_authenticated
            else list(component_ids)
        ),
        "metrics": aggregate,
        "components": component_reports,
        "provenance": provenance,
        **(
            {"objective_measure_sufficient_statistics": aggregate_sufficient}
            if aggregate_sufficient is not None
            else {}
        ),
    }
    return _reseal_objective_matched_validation_wrapper(result)


def evaluate_bc_batches(
    policy,
    data: dict,
    indices: np.ndarray,
    policy_sample_weights: np.ndarray,
    value_sample_weights: np.ndarray,
    batch_size: int,
    soft_target_temperature: float,
    soft_target_weight: float,
    soft_target_source: str,
    soft_target_min_legal_coverage: float,
    policy_loss_weight: float,
    value_loss_weight: float,
    final_vp_loss_weight: float,
    q_loss_weight: float,
    q_skip_teacher_prefixes: tuple[str, ...],
    vps_to_win: int,
    advantage_policy_weighting: str,
    advantage_temperature: float,
    advantage_weight_cap: float,
    advantage_weight_floor: float,
    ddp: dict[str, int | bool],
    amp: str = "none",
    *,
    policy_target_blend_semantics: str = POLICY_TARGET_BLEND_LEGACY_V1,
    data_sharded: bool = False,
    truncated_vp_margin_value_weight: float = 0.0,
    policy_kl_anchor_weight: float = 0.0,
    policy_kl_anchor_direction: str = "forward",
    policy_kl_use_policy_weights: bool = False,
    value_uncertainty_loss_weight: float = 0.0,
    aux_subgoal_loss_weight: float = 0.0,
    belief_resource_loss_weight: float = 0.0,
    moe_balance_loss_weight: float = 0.0,
    value_categorical_loss_weight: float = 0.0,
    value_hlgauss_sigma_ratio: float = 0.75,
    value_target_lambda: float = 1.0,
    value_root_blend_phases: tuple[str, ...] = (),
    value_root_blend_global_compat: bool = False,
    data_loader_workers: int = 0,
    data_loader_prefetch: int = 2,
    scalar_value_objective: str = "mse",
    scalar_value_loss_readout: str = "raw",
    scalar_value_loss_scale: float = 1.0,
    value_validation_action_types_by_id: tuple[str, ...] | None = None,
) -> dict:
    if len(indices) == 0:
        return {}
    eval_indices = np.asarray(indices, dtype=np.int64)
    if not data_sharded:
        eval_indices = _distributed_index_slice(eval_indices, ddp)
    ddp_model = None
    if bool(ddp.get("enabled", False)):
        import torch

        model = getattr(policy, "model", None)
        if isinstance(model, torch.nn.parallel.DistributedDataParallel):
            # Validation ranks may receive different numbers of rows (most
            # notably for the exact per-game composite measure).  DDP forward
            # broadcasts are collectives, so leaving the wrapper active makes
            # a shorter rank enter metric reduction while a peer is still in a
            # forward broadcast.  Inference needs no gradient synchronization;
            # unwrap only for the validation scope and retain the explicit
            # sufficient-statistic reductions below.
            ddp_model = model
            policy.model = model.module
    previous_modes = _set_policy_training(policy, False)
    try:
        loss_sum = 0.0
        extra_sums: dict[str, float] = {
            "policy_loss": 0.0,
            "value_loss": 0.0,
            "scalar_value_mse_diagnostic": 0.0,
            "final_vp_loss": 0.0,
            "q_loss": 0.0,
            "policy_kl_anchor_loss": 0.0,
            "value_uncertainty_loss": 0.0,
            "aux_subgoal_loss": 0.0,
            "belief_resource_loss": 0.0,
            "moe_balance_loss": 0.0,
            "value_categorical_loss": 0.0,
            "value_categorical_clean_loss": 0.0,
            "value_categorical_truncated_loss": 0.0,
            "q_score_rows_ge2": 0.0,
            "soft_distillation_rows": 0.0,
            "soft_distillation_active_rows": 0.0,
            "advantage_weight_rows": 0.0,
            "advantage_mean_sum": 0.0,
            "advantage_weight_mean_sum": 0.0,
            "prior_kl_rows": 0.0,
            "prior_kl_model_prior_sum": 0.0,
            "prior_kl_prior_model_sum": 0.0,
            "prior_kl_target_prior_sum": 0.0,
            "active_policy_teacher_gap_rows": 0.0,
            "active_policy_teacher_gap_weight_sum": 0.0,
            "active_policy_kl_target_model_sum": 0.0,
            "active_policy_kl_target_prior_sum": 0.0,
        }
        extra_denominators: dict[str, float] = {
            "policy_loss": 0.0,
            "value_loss": 0.0,
            "scalar_value_mse_diagnostic": 0.0,
            "final_vp_loss": 0.0,
            "q_loss": 0.0,
            "policy_kl_anchor_loss": 0.0,
            "value_uncertainty_loss": 0.0,
            "aux_subgoal_loss": 0.0,
            "belief_resource_loss": 0.0,
            "moe_balance_loss": 0.0,
            "value_categorical_loss": 0.0,
            "value_categorical_clean_loss": 0.0,
            "value_categorical_truncated_loss": 0.0,
        }
        aux_subgoal_sums = {field: 0.0 for field, _ in _AUX_SUBGOAL_SPECS}
        aux_subgoal_denominators = {
            field: 0.0 for field, _ in _AUX_SUBGOAL_SPECS
        }
        objective_exact_zero_terms = (
            {"moe_balance_loss"}
            if int(
                getattr(
                    getattr(policy, "config", None), "moe_routed_experts", 0
                )
            )
            <= 0
            else set()
        )
        acc_sum = 0.0
        top3_sum = 0.0
        count = 0.0
        active_count = 0.0
        phase_stats = _empty_phase_stats()
        phase_stats_unforced = _empty_phase_stats()
        teacher_stats = _empty_phase_stats()
        policy_target_distribution_stats: dict[str, object] = {}
        value_mse_strata_sufficient_statistics: dict[
            str, dict[str, dict[str, float]]
        ] = {}
        common_uniform_clean_outcome_squared_error_sum = 0.0
        common_uniform_clean_outcome_eligible_rows = 0
        eval_fn = _eval_entity_batch
        eval_fn_extra_kwargs: dict[str, object] = {
            "policy_kl_anchor_weight": float(policy_kl_anchor_weight),
            "policy_kl_anchor_direction": str(policy_kl_anchor_direction),
            "policy_kl_use_policy_weights": bool(policy_kl_use_policy_weights),
            "value_uncertainty_loss_weight": float(value_uncertainty_loss_weight),
            "aux_subgoal_loss_weight": float(aux_subgoal_loss_weight),
            "belief_resource_loss_weight": float(belief_resource_loss_weight),
            "moe_balance_loss_weight": float(moe_balance_loss_weight),
            "value_categorical_loss_weight": float(value_categorical_loss_weight),
            "value_hlgauss_sigma_ratio": float(value_hlgauss_sigma_ratio),
            "value_target_lambda": float(value_target_lambda),
            "value_root_blend_phases": tuple(value_root_blend_phases),
            "value_root_blend_global_compat": bool(value_root_blend_global_compat),
            "value_validation_action_types_by_id": (
                value_validation_action_types_by_id
            ),
        }
        # Validation used to bypass the streaming loader and synchronously
        # reconstruct every ragged memmap batch on the rank's main thread. On a
        # large validation sentinel that leaves the GPU idle while one CPU is
        # materialising the next batch. Reuse the exact training iterator: its
        # synchronous path preserves historical global indices, while its
        # threaded path materialises the same rows in deterministic order and
        # overlaps future CPU work with the current GPU forward pass.
        eval_order = np.arange(len(eval_indices), dtype=np.int64)
        for batch_data, batch, batch_policy_weights, batch_value_weights in (
            _iterate_training_batches(
                data,
                eval_order,
                eval_indices,
                batch_size,
                policy_sample_weights,
                value_sample_weights,
                num_workers=int(data_loader_workers),
                prefetch=int(data_loader_prefetch),
                materialize_keys=(
                    _entity_graph_prefetch_materialization_keys(data)
                    if getattr(policy, "policy_type", None) == "entity_graph"
                    else None
                ),
            )
        ):
            batch_metrics = eval_fn(
                policy,
                batch_data,
                batch,
                batch_policy_weights,
                batch_value_weights,
                soft_target_temperature,
                soft_target_weight,
                soft_target_source,
                soft_target_min_legal_coverage,
                policy_loss_weight,
                value_loss_weight,
                final_vp_loss_weight,
                q_loss_weight,
                q_skip_teacher_prefixes,
                vps_to_win,
                advantage_policy_weighting,
                advantage_temperature,
                advantage_weight_cap,
                advantage_weight_floor,
                amp,
                policy_target_blend_semantics=policy_target_blend_semantics,
                truncated_vp_margin_value_weight=truncated_vp_margin_value_weight,
                scalar_value_objective=scalar_value_objective,
                scalar_value_loss_readout=scalar_value_loss_readout,
                scalar_value_loss_scale=scalar_value_loss_scale,
                **eval_fn_extra_kwargs,
            )
            loss_sum += float(batch_metrics["loss"]) * len(batch)
            for key in (
                "policy_loss",
                "value_loss",
                "scalar_value_mse_diagnostic",
                "final_vp_loss",
                "q_loss",
                "policy_kl_anchor_loss",
                "value_uncertainty_loss",
                "aux_subgoal_loss",
                "belief_resource_loss",
                "moe_balance_loss",
                "value_categorical_loss",
                "value_categorical_clean_loss",
                "value_categorical_truncated_loss",
            ):
                weighted_sum_key = f"{key}_weighted_sum"
                weight_sum_key = f"{key}_weight_sum"
                if weighted_sum_key in batch_metrics and weight_sum_key in batch_metrics:
                    extra_sums[key] += float(batch_metrics[weighted_sum_key])
                    extra_denominators[key] += float(batch_metrics[weight_sum_key])
                else:
                    extra_sums[key] += float(batch_metrics.get(key, 0.0)) * len(batch)
                    extra_denominators[key] += float(len(batch))
            for field, parts in batch_metrics.get(
                "aux_subgoal_loss_parts", {}
            ).items():
                aux_subgoal_sums[field] += float(parts["weighted_sum"])
                aux_subgoal_denominators[field] += float(parts["weight_sum"])
            if "objective_exact_zero_terms" in batch_metrics:
                objective_exact_zero_terms.intersection_update(
                    batch_metrics["objective_exact_zero_terms"]
                )
            extra_sums["q_score_rows_ge2"] += float(batch_metrics.get("q_score_rows_ge2", 0.0))
            extra_sums["soft_distillation_rows"] += float(
                batch_metrics.get("soft_distillation_rows", 0.0)
            )
            extra_sums["soft_distillation_active_rows"] += float(
                batch_metrics.get("soft_distillation_active_rows", 0.0)
            )
            advantage_rows = float(batch_metrics.get("advantage_weight_rows", 0.0))
            extra_sums["advantage_weight_rows"] += advantage_rows
            extra_sums["advantage_mean_sum"] += (
                float(batch_metrics.get("advantage_mean", 0.0)) * advantage_rows
            )
            extra_sums["advantage_weight_mean_sum"] += (
                float(batch_metrics.get("advantage_weight_mean", 1.0)) * advantage_rows
            )
            extra_sums["prior_kl_rows"] += float(batch_metrics.get("prior_kl_rows", 0.0))
            extra_sums["prior_kl_model_prior_sum"] += float(
                batch_metrics.get("prior_kl_model_prior_sum", 0.0)
            )
            extra_sums["prior_kl_prior_model_sum"] += float(
                batch_metrics.get("prior_kl_prior_model_sum", 0.0)
            )
            extra_sums["prior_kl_target_prior_sum"] += float(
                batch_metrics.get("prior_kl_target_prior_sum", 0.0)
            )
            extra_sums["active_policy_teacher_gap_rows"] += float(
                batch_metrics.get("active_policy_teacher_gap_rows", 0.0)
            )
            extra_sums["active_policy_teacher_gap_weight_sum"] += float(
                batch_metrics.get("active_policy_teacher_gap_weight_sum", 0.0)
            )
            extra_sums["active_policy_kl_target_model_sum"] += float(
                batch_metrics.get("active_policy_kl_target_model_sum", 0.0)
            )
            extra_sums["active_policy_kl_target_prior_sum"] += float(
                batch_metrics.get("active_policy_kl_target_prior_sum", 0.0)
            )
            batch_active_count = float(batch_metrics.get("active_count", len(batch)))
            acc_sum += float(batch_metrics["accuracy"]) * batch_active_count
            top3_sum += float(batch_metrics["top3_accuracy"]) * batch_active_count
            count += float(len(batch))
            active_count += batch_active_count
            _merge_phase_stats(phase_stats, batch_metrics["phase_stats"])
            _merge_phase_stats(
                phase_stats_unforced,
                batch_metrics.get("phase_stats_unforced", {}),
            )
            _merge_phase_stats(teacher_stats, batch_metrics["teacher_stats"])
            _merge_policy_target_distribution_stats(
                policy_target_distribution_stats,
                batch_metrics.get("policy_target_distribution_stats", {}),
            )
            _merge_value_validation_strata(
                value_mse_strata_sufficient_statistics,
                batch_metrics.get(
                    "value_mse_strata_sufficient_statistics", {}
                ),
            )
            common_uniform_clean_outcome_squared_error_sum += float(
                batch_metrics[
                    "_common_uniform_clean_outcome_scalar_squared_error_sum"
                ]
            )
            common_uniform_clean_outcome_eligible_rows += int(
                batch_metrics[
                    "_common_uniform_clean_outcome_scalar_eligible_rows"
                ]
            )
        extra_sums = _reduce_named_sums(extra_sums, ddp)
        extra_denominators = _reduce_named_sums(extra_denominators, ddp)
        aux_subgoal_sums = _reduce_named_sums(aux_subgoal_sums, ddp)
        aux_subgoal_denominators = _reduce_named_sums(
            aux_subgoal_denominators, ddp
        )
        loss_sum, acc_sum, top3_sum, total_count = _reduce_epoch_metrics(
            loss_sum,
            acc_sum,
            top3_sum,
            count,
            ddp,
        )
        active_count_total = _reduce_scalar_sum(active_count, ddp)
        phase_stats = _reduce_nested_count_stats(phase_stats, ddp)
        phase_stats_unforced = _reduce_nested_count_stats(phase_stats_unforced, ddp)
        teacher_stats = _reduce_nested_count_stats(teacher_stats, ddp)
        policy_target_distribution_stats = (
            _reduce_policy_target_distribution_stats(
                policy_target_distribution_stats, ddp
            )
        )
        value_mse_strata_sufficient_statistics = (
            _reduce_value_validation_strata(
                value_mse_strata_sufficient_statistics, ddp
            )
        )
        common_uniform_clean_outcome_scalar_mse = (
            _reduce_common_uniform_clean_outcome_scalar_mse(
                common_uniform_clean_outcome_squared_error_sum,
                common_uniform_clean_outcome_eligible_rows,
                ddp,
                prediction_readout=scalar_value_loss_readout,
                prediction_scale=scalar_value_loss_scale,
            )
        )
        policy_loss_eval = _metric_from_sum_denominator(
            extra_sums["policy_loss"], extra_denominators["policy_loss"]
        )
        value_loss_eval = _metric_from_sum_denominator(
            extra_sums["value_loss"], extra_denominators["value_loss"]
        )
        scalar_value_mse_diagnostic_eval = _metric_from_sum_denominator(
            extra_sums["scalar_value_mse_diagnostic"],
            extra_denominators["scalar_value_mse_diagnostic"],
        )
        final_vp_loss_eval = _metric_from_sum_denominator(
            extra_sums["final_vp_loss"], extra_denominators["final_vp_loss"]
        )
        q_loss_eval = _metric_from_sum_denominator(
            extra_sums["q_loss"], extra_denominators["q_loss"]
        )
        auxiliary_loss_eval = {
            key: _metric_from_sum_denominator(
                extra_sums[key], extra_denominators[key]
            )
            for key in (
                "policy_kl_anchor_loss",
                "value_uncertainty_loss",
                "aux_subgoal_loss",
                "belief_resource_loss",
                "moe_balance_loss",
                "value_categorical_loss",
            )
        }
        auxiliary_loss_eval["aux_subgoal_loss"] = sum(
            _metric_from_sum_denominator(
                aux_subgoal_sums[field], aux_subgoal_denominators[field]
            )
            for field, _ in _AUX_SUBGOAL_SPECS
        )
        categorical_breakdown_eval = {
            key: _metric_from_sum_denominator(
                extra_sums[key], extra_denominators[key]
            )
            for key in (
                "value_categorical_clean_loss",
                "value_categorical_truncated_loss",
            )
        }
        loss_eval = loss_sum / max(total_count, 1.0)
        component_reconstructed_loss = (
            float(policy_loss_weight) * policy_loss_eval
            + float(value_loss_weight) * value_loss_eval
            + float(final_vp_loss_weight) * final_vp_loss_eval
            + float(q_loss_weight) * q_loss_eval
            + float(policy_kl_anchor_weight)
            * auxiliary_loss_eval["policy_kl_anchor_loss"]
            + float(value_uncertainty_loss_weight)
            * auxiliary_loss_eval["value_uncertainty_loss"]
            + float(aux_subgoal_loss_weight) * auxiliary_loss_eval["aux_subgoal_loss"]
            + float(belief_resource_loss_weight)
            * auxiliary_loss_eval["belief_resource_loss"]
            + float(moe_balance_loss_weight)
            * auxiliary_loss_eval["moe_balance_loss"]
            + float(value_categorical_loss_weight)
            * auxiliary_loss_eval["value_categorical_loss"]
        )
        return {
            "samples": int(total_count),
            # The configured objective is a sum of independently normalized
            # terms. Averaging each batch's already-normalized total silently
            # changes that objective when policy/value eligibility differs by
            # batch. Use the globally reconstructed objective for every corpus;
            # retain the historical batch statistic under its honest name.
            "loss": component_reconstructed_loss,
            "raw_batch_mean_loss": loss_eval,
            "component_reconstructed_loss": component_reconstructed_loss,
            "policy_loss": policy_loss_eval,
            "value_loss": value_loss_eval,
            "scalar_value_mse_diagnostic": scalar_value_mse_diagnostic_eval,
            COMMON_UNIFORM_CLEAN_OUTCOME_SCALAR_MSE_KEY: (
                common_uniform_clean_outcome_scalar_mse
            ),
            "value_mse_strata": _finalize_value_validation_strata(
                value_mse_strata_sufficient_statistics
            ),
            "value_mse_strata_sufficient_statistics": (
                value_mse_strata_sufficient_statistics
            ),
            "value_mse_strata_measure": "exact_weighted_rows",
            "final_vp_loss": final_vp_loss_eval,
            "q_loss": q_loss_eval,
            **auxiliary_loss_eval,
            **categorical_breakdown_eval,
            "primary_value_loss": (
                auxiliary_loss_eval["value_categorical_loss"]
                if float(value_categorical_loss_weight) > 0.0
                else value_loss_eval
            ),
            "primary_value_loss_kind": (
                "hlgauss_ce"
                if float(value_categorical_loss_weight) > 0.0
                else _scalar_value_primary_loss_kind(scalar_value_objective)
            ),
            "loss_denominators": {
                key: value
                for key, value in extra_denominators.items()
                if key not in {"aux_subgoal_loss", "moe_balance_loss"}
            },
            "aux_subgoal_loss_parts": {
                field: {
                    "weighted_sum": aux_subgoal_sums[field],
                    "weight_sum": aux_subgoal_denominators[field],
                }
                for field, _ in _AUX_SUBGOAL_SPECS
            },
            "objective_exact_zero_terms": sorted(objective_exact_zero_terms),
            "objective_coefficients": {
                "policy_loss": float(policy_loss_weight),
                "value_loss": float(value_loss_weight),
                "final_vp_loss": float(final_vp_loss_weight),
                "q_loss": float(q_loss_weight),
                "policy_kl_anchor_loss": float(policy_kl_anchor_weight),
                "value_uncertainty_loss": float(value_uncertainty_loss_weight),
                "aux_subgoal_loss": float(aux_subgoal_loss_weight),
                "belief_resource_loss": float(belief_resource_loss_weight),
                "moe_balance_loss": float(moe_balance_loss_weight),
                "value_categorical_loss": float(value_categorical_loss_weight),
            },
            "q_score_rows_ge2": int(round(extra_sums["q_score_rows_ge2"])),
            "q_score_rows_ge2_fraction": extra_sums["q_score_rows_ge2"] / max(total_count, 1.0),
            "soft_distillation_rows": int(round(extra_sums["soft_distillation_rows"])),
            "soft_distillation_fraction": extra_sums["soft_distillation_rows"] / max(total_count, 1.0),
            "soft_distillation_active_rows": int(
                round(extra_sums["soft_distillation_active_rows"])
            ),
            "soft_distillation_active_fraction": (
                extra_sums["soft_distillation_active_rows"] / max(active_count_total, 1.0)
            ),
            "advantage_weight_rows": int(round(extra_sums["advantage_weight_rows"])),
            "advantage_mean": (
                extra_sums["advantage_mean_sum"]
                / max(extra_sums["advantage_weight_rows"], 1.0)
            ),
            "advantage_weight_mean": (
                extra_sums["advantage_weight_mean_sum"]
                / max(extra_sums["advantage_weight_rows"], 1.0)
            ),
            "sampled_action_accuracy_active_count": int(
                round(active_count_total)
            ),
            "sampled_action_top1_accuracy": (
                acc_sum / max(active_count_total, 1.0)
            ),
            "sampled_action_top3_accuracy": (
                top3_sum / max(active_count_total, 1.0)
            ),
            "sampled_action_phase_accuracy": _finalize_phase_stats(
                phase_stats
            ),
            "sampled_action_phase_accuracy_excluding_forced": (
                _finalize_phase_stats(phase_stats_unforced)
            ),
            "sampled_action_teacher_group_accuracy": _finalize_phase_stats(
                teacher_stats
            ),
            "policy_target_distribution_metrics": (
                _finalize_policy_target_distribution_stats(
                    policy_target_distribution_stats
                )
            ),
            "policy_target_distribution_sufficient_statistics": (
                policy_target_distribution_stats
            ),
            # Explicitly named compatibility surface for historical report
            # consumers. These compare the model with the sampled trajectory
            # action, never with the soft MCTS target distribution.
            "legacy_sampled_action_compat": {
                "accuracy_active_count": int(round(active_count_total)),
                "accuracy": acc_sum / max(active_count_total, 1.0),
                "top3_accuracy": top3_sum / max(active_count_total, 1.0),
                "phase_accuracy": _finalize_phase_stats(phase_stats),
                "phase_accuracy_excluding_forced": (
                    _finalize_phase_stats(phase_stats_unforced)
                ),
                "teacher_accuracy": _finalize_phase_stats(teacher_stats),
            },
            "legacy_sampled_action_metric_semantics": {
                "deprecated": True,
                "replacement": "policy_target_distribution_metrics",
                "target": "temperature_sampled_action_taken",
                "not_teacher_imitation": True,
            },
            # Top-level aliases remain temporarily for existing executors and
            # dashboards. Their semantics are explicitly bound above.
            "accuracy_active_count": int(round(active_count_total)),
            "accuracy": acc_sum / max(active_count_total, 1.0),
            "top3_accuracy": top3_sum / max(active_count_total, 1.0),
            "phase_accuracy": _finalize_phase_stats(phase_stats),
            "phase_accuracy_excluding_forced": _finalize_phase_stats(
                phase_stats_unforced
            ),
            "teacher_accuracy": _finalize_phase_stats(teacher_stats),
            # Legacy drift telemetry. This reverse-KL ratio is retained for report
            # compatibility and anchor diagnostics, but is not a calibrated teacher
            # uptake fraction and must not be used as an LR or launch gate.
            "prior_kl_rows": int(round(extra_sums["prior_kl_rows"])),
            "prior_kl_model_prior_mean": (
                extra_sums["prior_kl_model_prior_sum"] / max(extra_sums["prior_kl_rows"], 1.0)
            ),
            "prior_kl_prior_model_mean": (
                extra_sums["prior_kl_prior_model_sum"] / max(extra_sums["prior_kl_rows"], 1.0)
            ),
            "prior_kl_target_prior_mean": (
                extra_sums["prior_kl_target_prior_sum"] / max(extra_sums["prior_kl_rows"], 1.0)
            ),
            "prior_kl_ratio": (
                extra_sums["prior_kl_model_prior_sum"]
                / max(extra_sums["prior_kl_target_prior_sum"], 1.0e-6)
                if extra_sums["prior_kl_rows"] > 0
                else 0.0
            ),
            # Objective-aligned teacher uptake. Unlike the legacy prior_kl_* fields,
            # these rows exactly match positive policy weight + a usable
            # multi-action soft target + a recorded prior.
            **_active_policy_teacher_gap_report(
                rows=extra_sums["active_policy_teacher_gap_rows"],
                weight_sum=extra_sums["active_policy_teacher_gap_weight_sum"],
                kl_target_model_sum=extra_sums[
                    "active_policy_kl_target_model_sum"
                ],
                kl_target_prior_sum=extra_sums[
                    "active_policy_kl_target_prior_sum"
                ],
            ),
        }
    finally:
        _restore_policy_training(policy, previous_modes)
        if ddp_model is not None:
            policy.model = ddp_model


def _run_teacher_quality_gate(
    data_path: Path,
    *,
    track: str,
    vps_to_win: int,
    strict: bool,
    production: bool,
    soft_target_min_legal_coverage: float,
    out_path: Path,
    ddp: dict[str, int | bool],
) -> None:
    if production:
        strict = True
    if not strict:
        return

    command = [
        sys.executable,
        "tools/report_teacher_data_quality.py",
        "--data",
        str(data_path),
        "--track",
        str(track),
        "--vps-to-win",
        str(int(vps_to_win)),
        "--out",
        str(out_path),
        "--soft-target-min-legal-coverage",
        str(float(soft_target_min_legal_coverage)),
    ]
    if production:
        command.append("--production-35m-teacher")
    else:
        command.append("--strict-35m-teacher")

    status = 0
    if int(ddp.get("rank", 0)) == 0:
        print(
            json.dumps(
                {
                    "progress": "teacher_quality_gate",
                    "command": command,
                    "production": bool(production),
                },
                sort_keys=True,
            ),
            flush=True,
        )
        result = subprocess.run(command, text=True, capture_output=True)
        if result.stdout:
            print(result.stdout, end="", flush=True)
        if result.stderr:
            print(result.stderr, end="", file=sys.stderr, flush=True)
        status = int(result.returncode)

    if ddp.get("enabled", False):
        import torch
        import torch.distributed as dist

        device = f"cuda:{int(ddp.get('local_rank', 0))}"
        status_tensor = torch.tensor([status], dtype=torch.int32, device=device)
        dist.broadcast(status_tensor, src=0)
        status = int(status_tensor.item())

    if status != 0:
        raise SystemExit(
            "teacher data quality gate failed; refusing to start BC training "
            f"on {data_path}"
        )




def _eval_entity_batch(
    policy,
    data: dict,
    batch: np.ndarray,
    policy_sample_weights: np.ndarray,
    value_sample_weights: np.ndarray,
    soft_target_temperature: float,
    soft_target_weight: float,
    soft_target_source: str,
    soft_target_min_legal_coverage: float,
    policy_loss_weight: float,
    value_loss_weight: float,
    final_vp_loss_weight: float,
    q_loss_weight: float,
    q_skip_teacher_prefixes: tuple[str, ...],
    vps_to_win: int,
    advantage_policy_weighting: str,
    advantage_temperature: float,
    advantage_weight_cap: float,
    advantage_weight_floor: float,
    amp: str = "none",
    *,
    policy_target_blend_semantics: str = POLICY_TARGET_BLEND_LEGACY_V1,
    truncated_vp_margin_value_weight: float = 0.0,
    policy_kl_anchor_weight: float = 0.0,
    policy_kl_anchor_direction: str = "forward",
    policy_kl_use_policy_weights: bool = False,
    value_uncertainty_loss_weight: float = 0.0,
    aux_subgoal_loss_weight: float = 0.0,
    belief_resource_loss_weight: float = 0.0,
    moe_balance_loss_weight: float = 0.0,
    value_categorical_loss_weight: float = 0.0,
    value_hlgauss_sigma_ratio: float = 0.75,
    value_target_lambda: float = 1.0,
    value_root_blend_phases: tuple[str, ...] = (),
    value_root_blend_global_compat: bool = False,
    scalar_value_objective: str = "mse",
    scalar_value_loss_readout: str = "raw",
    scalar_value_loss_scale: float = 1.0,
    value_validation_action_types_by_id: tuple[str, ...] | None = None,
) -> dict:
    import torch
    from torch import nn

    with torch.no_grad():
        legal_action_ids = data["legal_action_ids"][batch]
        actions_np = data["action_taken"][batch].astype(np.int64)
        target_columns = _target_columns(legal_action_ids, actions_np)
        target = torch.as_tensor(target_columns, dtype=torch.long, device=policy.device)
        policy_weights = torch.as_tensor(
            policy_sample_weights[batch],
            dtype=torch.float32,
            device=policy.device,
        )
        policy_kl_measure_weights = policy_weights
        value_weights = torch.as_tensor(
            value_sample_weights[batch],
            dtype=torch.float32,
            device=policy.device,
        )
        with _amp_context(policy.device, amp):
            outputs = _forward_legal_np_for_batch(
                policy,
                data,
                batch,
                legal_action_ids,
                return_q=float(q_loss_weight) != 0.0,
                return_aux_subgoals=float(aux_subgoal_loss_weight) != 0.0,
            )
            hard_loss = nn.functional.cross_entropy(outputs["logits"], target, reduction="none")
            soft_targets, has_soft, soft_support = _soft_targets_legal(
                data,
                batch,
                policy.device,
                soft_target_temperature,
                soft_target_source,
                soft_target_min_legal_coverage,
            )
            if soft_targets is not None:
                log_probs = _support_log_softmax(outputs["logits"], soft_support)
                soft_loss = -(soft_targets * log_probs).sum(dim=-1)
                per_sample_loss = _policy_target_per_sample_loss(
                    hard_loss,
                    soft_loss,
                    has_soft,
                    soft_target_weight=soft_target_weight,
                    blend_semantics=policy_target_blend_semantics,
                )
            else:
                per_sample_loss = hard_loss
            # Teacher-gap telemetry must follow the rows the POLICY objective can
            # actually update. The exact positive policy weights are also the
            # teacher-gap measure; reducing them to a boolean made weighted
            # learner recipes report an unrelated uniform-row closure.
            (
                outcome_targets,
                vp_targets,
                has_outcome,
                has_vp_target,
                value_outcome_targets,
                value_has_outcome,
                outcome_confidence,
            ) = _value_targets(
                data,
                batch,
                policy.device,
                vps_to_win,
                truncated_vp_margin_value_weight=truncated_vp_margin_value_weight,
            )
            truncated_mask = torch.as_tensor(
                np.asarray(
                    _batch_array_or_fill(
                        data,
                        "truncated",
                        batch,
                        False,
                        dtype=np.bool_,
                    ),
                    dtype=np.bool_,
                ),
                dtype=torch.bool,
                device=policy.device,
            )
            root_value, root_value_mask = _root_value_targets(
                data, batch, policy.device
            )
            if (
                float(value_target_lambda) != 1.0
                and value_outcome_targets is not None
                and root_value is not None
            ):
                lam = float(value_target_lambda)
                blend_rows = _value_root_blend_mask(
                    data,
                    batch,
                    policy.device,
                    root_value_mask,
                    value_has_outcome,
                    truncated_mask,
                    phases=value_root_blend_phases,
                    global_compat=value_root_blend_global_compat,
                )
                value_outcome_targets = torch.where(
                    blend_rows,
                    lam * value_outcome_targets + (1.0 - lam) * root_value,
                    value_outcome_targets,
                )
            # Advantage reweighting stays on the policy-safe (unfilled) outcome/has_outcome --
            # FIX F3 is scoped to the value head only, must not leak into POLICY weighting.
            advantage_outputs = outputs
            if "value" in outputs and scalar_value_loss_readout != "raw":
                advantage_outputs = {
                    **outputs,
                    "value": _scalar_value_loss_prediction(
                        outputs["value"],
                        readout=scalar_value_loss_readout,
                        scale=scalar_value_loss_scale,
                    ),
                }
            policy_weights, advantage_stats = _advantage_reweighted_policy_weights(
                policy_weights,
                advantage_outputs,
                outcome_targets,
                has_outcome,
                advantage_policy_weighting,
                advantage_temperature,
                advantage_weight_cap,
                advantage_weight_floor,
            )
            policy_loss_sum, policy_loss_denominator = _weighted_loss_parts(per_sample_loss, policy_weights)
            policy_loss = policy_loss_sum / torch.clamp(policy_loss_denominator, min=1e-6)
            value_loss = torch.tensor(0.0, dtype=torch.float32, device=policy.device)
            scalar_value_mse_diagnostic = torch.tensor(
                0.0, dtype=torch.float32, device=policy.device
            )
            value_mse_strata_sufficient_statistics = {}
            final_vp_loss = torch.tensor(0.0, dtype=torch.float32, device=policy.device)
            q_loss = torch.tensor(0.0, dtype=torch.float32, device=policy.device)
            if value_outcome_targets is not None and "value" in outputs:
                (
                    value_error,
                    scalar_value_mse_error,
                    scalar_value_prediction,
                ) = _scalar_value_objective_errors(
                    outputs["value"],
                    value_outcome_targets,
                    objective=scalar_value_objective,
                    readout=scalar_value_loss_readout,
                    scale=scalar_value_loss_scale,
                )
                value_loss_sum, value_loss_denominator = _weighted_loss_parts(
                    value_error,
                    value_weights * outcome_confidence,
                    mask=value_has_outcome,
                )
                value_loss = value_loss_sum / torch.clamp(value_loss_denominator, min=1e-6)
                (
                    scalar_value_mse_diagnostic_sum,
                    scalar_value_mse_diagnostic_denominator,
                ) = _weighted_loss_parts(
                    scalar_value_mse_error,
                    value_weights * outcome_confidence,
                    mask=value_has_outcome,
                )
                scalar_value_mse_diagnostic = (
                    scalar_value_mse_diagnostic_sum
                    / torch.clamp(
                        scalar_value_mse_diagnostic_denominator, min=1e-6
                    )
                )
                common_uniform_clean_outcome_error = (
                    scalar_value_prediction - outcome_targets
                ) ** 2
                (
                    common_uniform_clean_outcome_squared_error_sum,
                    common_uniform_clean_outcome_eligible_rows,
                ) = _weighted_loss_parts(
                    common_uniform_clean_outcome_error,
                    torch.ones_like(common_uniform_clean_outcome_error),
                    mask=has_outcome,
                )
                effective_value_weights = value_weights * outcome_confidence
                value_mse_strata_sufficient_statistics = (
                    _value_validation_strata_parts(
                        data,
                        batch,
                        scalar_value_mse_error,
                        effective_value_weights,
                        value_has_outcome & (effective_value_weights > 0.0),
                        prediction=scalar_value_prediction,
                        target=value_outcome_targets,
                        action_types_by_id=value_validation_action_types_by_id,
                    )
                )
            else:
                value_loss_sum, value_loss_denominator = _zero_loss_parts(policy.device)
                (
                    scalar_value_mse_diagnostic_sum,
                    scalar_value_mse_diagnostic_denominator,
                ) = _zero_loss_parts(policy.device)
                (
                    common_uniform_clean_outcome_squared_error_sum,
                    common_uniform_clean_outcome_eligible_rows,
                ) = _zero_loss_parts(policy.device)
            if vp_targets is not None and "final_vp" in outputs:
                vp_error = nn.functional.mse_loss(outputs["final_vp"], vp_targets, reduction="none")
                final_vp_loss_sum, final_vp_loss_denominator = _weighted_loss_parts(
                    vp_error,
                    value_weights,
                    mask=has_vp_target,
                )
                final_vp_loss = final_vp_loss_sum / torch.clamp(final_vp_loss_denominator, min=1e-6)
            else:
                final_vp_loss_sum, final_vp_loss_denominator = _zero_loss_parts(policy.device)
            q_loss_sum, q_loss_denominator = _zero_loss_parts(policy.device)
            if float(q_loss_weight) != 0.0 and "q_values" in outputs:
                q_loss, q_loss_sum, q_loss_denominator = _q_score_loss_parts(
                    outputs["q_values"],
                    data,
                    batch,
                    policy_weights,
                    policy.device,
                    q_skip_teacher_prefixes=q_skip_teacher_prefixes,
                )
            kl_anchor_loss = torch.tensor(
                0.0, dtype=torch.float32, device=policy.device
            )
            kl_anchor_loss_sum, kl_anchor_loss_denominator = _zero_loss_parts(
                policy.device
            )
            # Always measure the exact configured anchor direction and
            # authenticated replay scope during validation, including K0. A
            # zero coefficient still contributes nothing to the objective.
            anchor = _policy_kl_anchor_loss_parts(
                data,
                batch,
                outputs["logits"],
                policy.device,
                direction=policy_kl_anchor_direction,
                sample_weights=(
                    policy_kl_measure_weights
                    if policy_kl_use_policy_weights
                    else None
                ),
            )
            if anchor is not None:
                (
                    kl_anchor_loss,
                    kl_anchor_loss_sum,
                    kl_anchor_loss_denominator,
                ) = anchor
            value_uncertainty_loss = torch.tensor(
                0.0, dtype=torch.float32, device=policy.device
            )
            value_uncertainty_loss_sum, value_uncertainty_loss_denominator = (
                _zero_loss_parts(policy.device)
            )
            if (
                float(value_uncertainty_loss_weight) != 0.0
                and "value_uncertainty" in outputs
                and value_outcome_targets is not None
                and "value" in outputs
            ):
                uncertainty_value = _scalar_value_loss_prediction(
                    outputs["value"],
                    readout=scalar_value_loss_readout,
                    scale=scalar_value_loss_scale,
                )
                uncertainty_target = (
                    value_outcome_targets - uncertainty_value.detach()
                ) ** 2
                uncertainty_error = nn.functional.smooth_l1_loss(
                    outputs["value_uncertainty"],
                    uncertainty_target,
                    reduction="none",
                )
                (
                    value_uncertainty_loss_sum,
                    value_uncertainty_loss_denominator,
                ) = _weighted_loss_parts(
                    uncertainty_error,
                    value_weights * outcome_confidence,
                    mask=value_has_outcome,
                )
                value_uncertainty_loss = _weighted_mean_from_parts(
                    value_uncertainty_loss_sum,
                    value_uncertainty_loss_denominator,
                )
            value_categorical_loss = torch.tensor(
                0.0, dtype=torch.float32, device=policy.device
            )
            value_categorical_loss_sum, value_categorical_loss_denominator = (
                _zero_loss_parts(policy.device)
            )
            (
                value_categorical_clean_loss_sum,
                value_categorical_clean_loss_denominator,
            ) = _zero_loss_parts(policy.device)
            (
                value_categorical_truncated_loss_sum,
                value_categorical_truncated_loss_denominator,
            ) = _zero_loss_parts(policy.device)
            if (
                float(value_categorical_loss_weight) != 0.0
                and "value_categorical_logits" in outputs
                and outcome_targets is not None
            ):
                cat_logits = outputs["value_categorical_logits"].float()
                bins = _policy_value_categorical_bins(policy)
                has_trunc_class = int(cat_logits.shape[-1]) > bins
                cat_targets = _hl_gauss_value_targets(
                    outcome_targets,
                    bins,
                    sigma_ratio=value_hlgauss_sigma_ratio,
                    truncated=truncated_mask if has_trunc_class else None,
                    add_truncation_class=has_trunc_class,
                )
                if float(value_target_lambda) != 1.0 and root_value is not None:
                    lam = float(value_target_lambda)
                    root_targets = _hl_gauss_value_targets(
                        root_value,
                        bins,
                        sigma_ratio=value_hlgauss_sigma_ratio,
                        truncated=None,
                        add_truncation_class=has_trunc_class,
                    )
                    blend_rows = _value_root_blend_mask(
                        data,
                        batch,
                        policy.device,
                        root_value_mask,
                        has_outcome,
                        truncated_mask,
                        phases=value_root_blend_phases,
                        global_compat=value_root_blend_global_compat,
                    ).unsqueeze(-1)
                    cat_targets = torch.where(
                        blend_rows,
                        lam * cat_targets + (1.0 - lam) * root_targets,
                        cat_targets,
                    )
                cat_log_probs = torch.nn.functional.log_softmax(
                    cat_logits, dim=-1
                )
                cat_error = -(cat_targets * cat_log_probs).sum(dim=-1)
                cat_mask = (
                    has_outcome | truncated_mask
                    if has_trunc_class
                    else has_outcome
                )
                categorical_value_weights = value_weights * torch.where(
                    truncated_mask,
                    torch.full_like(
                        value_weights, float(truncated_vp_margin_value_weight)
                    ),
                    torch.ones_like(value_weights),
                )
                (
                    value_categorical_loss_sum,
                    value_categorical_loss_denominator,
                ) = _weighted_loss_parts(
                    cat_error, categorical_value_weights, mask=cat_mask
                )
                value_categorical_loss = value_categorical_loss_sum / torch.clamp(
                    value_categorical_loss_denominator, min=1e-6
                )
                (
                    value_categorical_clean_loss_sum,
                    value_categorical_clean_loss_denominator,
                ) = _weighted_loss_parts(
                    cat_error,
                    categorical_value_weights,
                    mask=has_outcome & ~truncated_mask,
                )
                if has_trunc_class:
                    (
                        value_categorical_truncated_loss_sum,
                        value_categorical_truncated_loss_denominator,
                    ) = _weighted_loss_parts(
                        cat_error,
                        categorical_value_weights,
                        mask=truncated_mask,
                    )
            aux_subgoal_loss = torch.tensor(
                0.0, dtype=torch.float32, device=policy.device
            )
            aux_subgoal_active_heads = 0
            aux_subgoal_loss_parts = {}
            if float(aux_subgoal_loss_weight) != 0.0:
                (
                    aux_subgoal_loss,
                    aux_subgoal_active_heads,
                    aux_subgoal_loss_parts,
                ) = _aux_subgoal_loss(
                    outputs,
                    data,
                    batch,
                    policy.device,
                    return_sufficient_statistics=True,
                )
            belief_resource_loss = torch.tensor(
                0.0, dtype=torch.float32, device=policy.device
            )
            belief_resource_active_players = 0
            belief_resource_loss_sum, belief_resource_loss_denominator = (
                _zero_loss_parts(policy.device)
            )
            if float(belief_resource_loss_weight) != 0.0:
                (
                    belief_resource_loss,
                    belief_resource_active_players,
                    belief_resource_loss_sum,
                    belief_resource_loss_denominator,
                ) = _belief_resource_loss(outputs, data, batch, policy.device)
            moe_balance_loss = outputs.get("moe_balance_metric")
            moe_balance_loss_exact_zero = (
                moe_balance_loss is None
                and int(
                    getattr(
                        getattr(policy, "config", None),
                        "moe_routed_experts",
                        0,
                    )
                )
                <= 0
            )
            if moe_balance_loss is None:
                moe_balance_loss = torch.tensor(
                    0.0, dtype=torch.float32, device=policy.device
                )
                if (
                    float(moe_balance_loss_weight) != 0.0
                    and int(getattr(policy.config, "moe_routed_experts", 0)) > 0
                ):
                    raise ValueError(
                        "MoE balance loss requested but the model emitted no routing metric"
                    )
            loss = (
                float(policy_loss_weight) * policy_loss
                + float(value_loss_weight) * value_loss
                + float(final_vp_loss_weight) * final_vp_loss
                + float(q_loss_weight) * q_loss
                + float(policy_kl_anchor_weight) * kl_anchor_loss
                + float(value_uncertainty_loss_weight)
                * value_uncertainty_loss
                + float(aux_subgoal_loss_weight) * aux_subgoal_loss
                + float(belief_resource_loss_weight) * belief_resource_loss
                + float(moe_balance_loss_weight) * moe_balance_loss
                + float(value_categorical_loss_weight)
                * value_categorical_loss
            )
        predictions = torch.argmax(outputs["logits"], dim=-1)
        active = policy_weights > 0.0
        active_count = int(active.sum().item())
        accuracy = _masked_metric_mean((predictions == target).float(), active)
        top3_accuracy = _topk_legal_accuracy(outputs["logits"], target, k=3, mask=active)
        predictions_np = predictions.detach().cpu().numpy()
        targets_np = target.detach().cpu().numpy()
        logits_np = outputs["logits"].float().detach().cpu().numpy()
        q_score_rows_ge2 = _q_score_rows_ge2(
            data,
            batch,
            q_skip_teacher_prefixes=q_skip_teacher_prefixes,
        )
        active_np = active.detach().cpu().numpy().astype(bool)
        policy_target_distribution_stats = (
            _policy_target_distribution_stats(
                data,
                batch,
                outputs["logits"],
                soft_targets,
                has_soft,
                active,
                soft_support,
            )
        )
        # Success telemetry (gen-1 recipe): KL(model||prior_policy) vs the
        # reference KL(target_policy||prior_policy) on a held-out gen slice.
        prior_kl = _prior_kl_telemetry(data, batch, outputs["logits"], policy.device)
        if prior_kl is not None:
            has_prior = prior_kl["has_prior"]
            prior_kl_rows = int(has_prior.sum().item())
            kl_model_prior_sum = float(prior_kl["kl_model_prior"][has_prior].sum().item())
            kl_prior_model_sum = float(prior_kl["kl_prior_model"][has_prior].sum().item())
            kl_target_prior_sum = float(prior_kl["kl_target_prior"][has_prior].sum().item())
        else:
            prior_kl_rows = 0
            kl_model_prior_sum = 0.0
            kl_prior_model_sum = 0.0
            kl_target_prior_sum = 0.0
        teacher_gap = _active_policy_teacher_gap_telemetry(
            data,
            batch,
            outputs["logits"],
            policy.device,
            soft_targets=soft_targets,
            has_soft=has_soft,
            policy_weights=policy_weights,
        )
        if teacher_gap is not None:
            teacher_gap_rows = int(teacher_gap["eligible"].sum().item())
            teacher_gap_weight_sum = float(
                teacher_gap["measure_weights"].sum().item()
            )
            teacher_kl_target_model_sum = float(
                (
                    teacher_gap["kl_target_model"]
                    * teacher_gap["measure_weights"]
                ).sum().item()
            )
            teacher_kl_target_prior_sum = float(
                (
                    teacher_gap["kl_target_prior"]
                    * teacher_gap["measure_weights"]
                ).sum().item()
            )
        else:
            teacher_gap_rows = 0
            teacher_gap_weight_sum = 0.0
            teacher_kl_target_model_sum = 0.0
            teacher_kl_target_prior_sum = 0.0
        return {
            "loss": float(loss.item()),
            "policy_loss": float(policy_loss.item()),
            "value_loss": float(value_loss.item()),
            "final_vp_loss": float(final_vp_loss.item()),
            "q_loss": float(q_loss.item()),
            "policy_kl_anchor_loss": float(kl_anchor_loss.item()),
            "policy_kl_anchor_loss_weighted_sum": float(
                kl_anchor_loss_sum.item()
            ),
            "policy_kl_anchor_loss_weight_sum": float(
                kl_anchor_loss_denominator.item()
            ),
            "policy_kl_anchor_eligible_rows": int(
                kl_anchor_loss_denominator.item()
            ),
            "value_uncertainty_loss": float(value_uncertainty_loss.item()),
            "value_uncertainty_loss_weighted_sum": float(
                value_uncertainty_loss_sum.item()
            ),
            "value_uncertainty_loss_weight_sum": float(
                value_uncertainty_loss_denominator.item()
            ),
            "aux_subgoal_loss": float(aux_subgoal_loss.item()),
            "aux_subgoal_loss_parts": {
                field: {
                    "weighted_sum": float(parts["weighted_sum"].item()),
                    "weight_sum": float(parts["weight_sum"].item()),
                }
                for field, parts in aux_subgoal_loss_parts.items()
            },
            "belief_resource_loss": float(belief_resource_loss.item()),
            "belief_resource_loss_weighted_sum": float(
                belief_resource_loss_sum.item()
            ),
            "belief_resource_loss_weight_sum": float(
                belief_resource_loss_denominator.item()
            ),
            "moe_balance_loss": float(moe_balance_loss.item()),
            "objective_exact_zero_terms": (
                ["moe_balance_loss"] if moe_balance_loss_exact_zero else []
            ),
            "aux_subgoal_active_heads": int(aux_subgoal_active_heads),
            "belief_resource_active_players": int(
                belief_resource_active_players
            ),
            "value_categorical_loss": float(value_categorical_loss.item()),
            "primary_value_loss": float(
                value_categorical_loss.item()
                if float(value_categorical_loss_weight) > 0.0
                else value_loss.item()
            ),
            "primary_value_loss_kind": (
                "hlgauss_ce"
                if float(value_categorical_loss_weight) > 0.0
                else _scalar_value_primary_loss_kind(scalar_value_objective)
            ),
            "scalar_value_mse_diagnostic": float(
                scalar_value_mse_diagnostic.item()
            ),
            "value_mse_strata_sufficient_statistics": (
                value_mse_strata_sufficient_statistics
            ),
            "policy_loss_weighted_sum": float(policy_loss_sum.item()),
            "policy_loss_weight_sum": float(policy_loss_denominator.item()),
            "value_loss_weighted_sum": float(value_loss_sum.item()),
            "value_loss_weight_sum": float(value_loss_denominator.item()),
            "scalar_value_mse_diagnostic_weighted_sum": float(
                scalar_value_mse_diagnostic_sum.item()
            ),
            "scalar_value_mse_diagnostic_weight_sum": float(
                scalar_value_mse_diagnostic_denominator.item()
            ),
            "_common_uniform_clean_outcome_scalar_squared_error_sum": float(
                common_uniform_clean_outcome_squared_error_sum.item()
            ),
            "_common_uniform_clean_outcome_scalar_eligible_rows": int(
                common_uniform_clean_outcome_eligible_rows.item()
            ),
            "final_vp_loss_weighted_sum": float(final_vp_loss_sum.item()),
            "final_vp_loss_weight_sum": float(final_vp_loss_denominator.item()),
            "q_loss_weighted_sum": float(q_loss_sum.item()),
            "q_loss_weight_sum": float(q_loss_denominator.item()),
            "value_categorical_loss_weighted_sum": float(
                value_categorical_loss_sum.item()
            ),
            "value_categorical_loss_weight_sum": float(
                value_categorical_loss_denominator.item()
            ),
            "value_categorical_clean_loss_weighted_sum": float(
                value_categorical_clean_loss_sum.item()
            ),
            "value_categorical_clean_loss_weight_sum": float(
                value_categorical_clean_loss_denominator.item()
            ),
            "value_categorical_truncated_loss_weighted_sum": float(
                value_categorical_truncated_loss_sum.item()
            ),
            "value_categorical_truncated_loss_weight_sum": float(
                value_categorical_truncated_loss_denominator.item()
            ),
            "q_score_rows_ge2": q_score_rows_ge2,
            **advantage_stats,
            "soft_distillation_rows": int(has_soft.sum().item()) if soft_targets is not None else 0,
            "soft_distillation_active_rows": (
                int((has_soft & active).sum().item()) if soft_targets is not None else 0
            ),
            "active_count": active_count,
            "sampled_action_top1_accuracy": float(accuracy.item()),
            "sampled_action_top3_accuracy": float(top3_accuracy.item()),
            "policy_target_distribution_stats": (
                policy_target_distribution_stats
            ),
            # Batch-local compatibility aliases. Serialized reports rename
            # these so sampled behavior cannot be mistaken for teacher fit.
            "accuracy": float(accuracy.item()),
            "top3_accuracy": float(top3_accuracy.item()),
            "phase_stats": _field_stats(
                data,
                batch[active_np],
                predictions_np[active_np],
                targets_np[active_np],
                logits_np[active_np],
                field="phase",
            ),
            "phase_stats_unforced": _field_stats_unforced(
                data,
                batch[active_np],
                predictions_np[active_np],
                targets_np[active_np],
                logits_np[active_np],
                field="phase",
            ),
            "teacher_stats": _field_stats(
                data,
                batch[active_np],
                predictions_np[active_np],
                targets_np[active_np],
                logits_np[active_np],
                field="teacher_name",
            ),
            "prior_kl_rows": prior_kl_rows,
            "prior_kl_model_prior_sum": kl_model_prior_sum,
            "prior_kl_prior_model_sum": kl_prior_model_sum,
            "prior_kl_target_prior_sum": kl_target_prior_sum,
            "active_policy_teacher_gap_rows": teacher_gap_rows,
            "active_policy_teacher_gap_weight_sum": teacher_gap_weight_sum,
            "active_policy_kl_target_model_sum": teacher_kl_target_model_sum,
            "active_policy_kl_target_prior_sum": teacher_kl_target_prior_sum,
        }


def load_teacher_data_memmap(
    path: Path, *, composite_meta: dict[str, object] | None = None
) -> MemmapCorpus | ConcatMemmapCorpus:
    if path.is_file():
        authenticated = (
            composite_meta
            if composite_meta is not None
            else _preflight_memmap_composite_descriptor(path)
        )
        if authenticated.get("schema_version") not in {
            "memmap_composite_v1", "memmap_composite_v2"
        }:
            raise SystemExit("memmap composite loader received invalid authenticated metadata")
        components = authenticated["components"]
        assert isinstance(components, list)
        dirs = [Path(str(component["corpus_dir"])) for component in components]
        runtime_bindings = [
            component.get("payload_runtime_binding")
            for component in components
        ]
        if any(not isinstance(binding, Mapping) for binding in runtime_bindings):
            raise SystemExit(
                "authenticated composite lacks payload runtime inode bindings"
            )
        production = bool(
            authenticated.get("schema_version") == "memmap_composite_v2"
            and authenticated.get("promotion_eligible") is True
        )
        opened_payloads: list[dict[str, Any]] = []
        try:
            for binding in runtime_bindings:
                assert isinstance(binding, Mapping)
                opened_payloads.append(
                    _open_authenticated_memmap_payloads(
                        binding,
                        require_read_only=production,
                    )
                )
        except BaseException:
            for opened in opened_payloads:
                for handle in opened.values():
                    handle.close()
            raise
        adapter_versions_by_component = authenticated.get(
            "entity_feature_adapter_component_versions"
        )
        try:
            corpus = ConcatMemmapCorpus(
                [
                    MemmapCorpus(
                        component_dir,
                        authenticated_files=opened,
                        authenticated_meta=component["corpus_meta"],
                    )
                    for component, component_dir, opened in zip(
                        components, dirs, opened_payloads, strict=True
                    )
                ],
                dirs=dirs,
                component_adapter_versions=(
                    None
                    if adapter_versions_by_component is None
                    else [
                        str(adapter_versions_by_component[component_id])
                        for component_id in authenticated["component_ids"]
                    ]
                ),
            )
        except BaseException:
            for opened in opened_payloads:
                for handle in opened.values():
                    handle.close()
            raise
        # Memmaps and parsed metadata came from these already-authenticated
        # handles, so directory/path replacement cannot switch the bytes.
        for binding, opened in zip(
            runtime_bindings, opened_payloads, strict=True
        ):
            assert isinstance(binding, Mapping)
            _validate_open_authenticated_memmap_payloads(
                binding,
                opened,
            )
        corpus.authenticated_payload_runtime_bindings = tuple(
            copy.deepcopy(dict(binding))
            for binding in runtime_bindings
            if isinstance(binding, Mapping)
        )
        if authenticated["schema_version"] == "memmap_composite_v2":
            corpus.component_ids = tuple(authenticated["component_ids"])
            corpus.component_game_sampling_ratios = tuple(
                float(value)
                for value in authenticated["component_game_sampling_ratios"]
            )
            anchor_ids = set(authenticated["policy_kl_anchor_component_ids"])
            corpus.policy_kl_anchor_component_indices = tuple(
                index
                for index, component_id in enumerate(corpus.component_ids)
                if component_id in anchor_ids
            )
            corpus.policy_kl_anchor_scope_authenticated = True
            distillation_ids = set(
                authenticated["policy_distillation_component_ids"]
            )
            corpus.policy_distillation_component_indices = tuple(
                index
                for index, component_id in enumerate(corpus.component_ids)
                if component_id in distillation_ids
            )
            corpus.policy_distillation_scope_authenticated = True
            raw_aux_phase_weights = authenticated.get(
                "policy_aux_phase_sampling_weights"
            )
            corpus.policy_aux_phase_sampling_weights = (
                None
                if raw_aux_phase_weights is None
                else {
                    str(phase): float(weight)
                    for phase, weight in raw_aux_phase_weights.items()
                }
            )
            corpus.policy_aux_phase_scope_authenticated = (
                raw_aux_phase_weights is not None
            )
            raw_policy_temperatures = authenticated.get(
                "stored_policy_component_temperatures"
            )
            corpus.stored_policy_component_temperatures = (
                None
                if raw_policy_temperatures is None
                else {
                    str(component_id): float(temperature)
                    for component_id, temperature in raw_policy_temperatures.items()
                }
            )
            value_ids = set(authenticated["value_training_component_ids"])
            corpus.value_training_component_indices = tuple(
                index
                for index, component_id in enumerate(corpus.component_ids)
                if component_id in value_ids
            )
            corpus.value_training_scope_authenticated = True
            aux_subgoal_ids = set(authenticated["aux_subgoal_component_ids"])
            corpus.aux_subgoal_component_indices = tuple(
                index
                for index, component_id in enumerate(corpus.component_ids)
                if component_id in aux_subgoal_ids
            )
            corpus.aux_subgoal_scope_authenticated = bool(
                authenticated["aux_subgoal_scope_explicit"]
            )
        corpus.meta.update({
            "schema": authenticated["schema_version"],
            "descriptor_path": authenticated["descriptor_path"],
            "descriptor_fingerprint": authenticated["descriptor_fingerprint"],
            "payload_inventory_sha256": authenticated["payload_inventory_sha256"],
            "source_authority_semantic_sha256": authenticated.get(
                "source_authority_semantic_sha256"
            ),
            "diagnostic_only": bool(authenticated["diagnostic_only"]),
            "promotion_eligible": bool(authenticated["promotion_eligible"]),
            "flywheel_replay_contract": authenticated.get(
                "flywheel_replay_contract"
            ),
            "aux_subgoal_component_ids": authenticated.get(
                "aux_subgoal_component_ids", []
            ),
        })
    else:
        corpus = MemmapCorpus(path)
    load_event = {
        "progress": "bc_memmap_load",
        "corpus_dir": str(path),
        "rows": corpus.row_count,
        "legal_width": corpus.legal_width,
        "shard_count": int(corpus.meta.get("shard_count", 0)),
    }
    if isinstance(corpus, ConcatMemmapCorpus):
        load_event.update({
            "progress": "bc_memmap_composite_load",
            "component_count": len(corpus.corpora),
            "component_ids": list(getattr(corpus, "component_ids", tuple())),
            "stored_policy_component_temperatures": getattr(
                corpus, "stored_policy_component_temperatures", None
            ),
            "entity_feature_adapter_component_versions": (
                None
                if getattr(corpus, "component_adapter_versions", None) is None
                else {
                    component_id: version
                    for component_id, version in zip(
                        corpus.component_ids,
                        corpus.component_adapter_versions,
                        strict=True,
                    )
                }
            ),
        })
    print(json.dumps(load_event, sort_keys=True), flush=True)
    return corpus


def _iterate_training_batches(
    data,
    order: np.ndarray,
    train_indices: np.ndarray,
    batch_size: int,
    policy_sample_weights: np.ndarray,
    value_sample_weights: np.ndarray,
    *,
    num_workers: int,
    prefetch: int,
    policy_aux_rows: np.ndarray | None = None,
    policy_aux_batch_size: int = 0,
    materialize_keys: tuple[str, ...] | None = None,
):
    """Yield ``(data, batch, policy_weights, value_weights)`` tuples for one epoch.

    Default path (npz dict, or num_workers<=0): yields the corpus and the GLOBAL
    batch indices unchanged, so train_fn indexes exactly as before -- zero
    behaviour change and identical batch order.

    Prefetch path (MemmapCorpus + num_workers>0): background threads materialise
    each batch's columns into a plain dict while the GPU trains the previous
    batch, overlapping the per-batch ragged reconstruction. If policy-auxiliary
    rows are supplied, their corresponding batch is gathered in the *same*
    materialisation. This removes the old synchronous second memmap gather from
    the rank main thread without changing either sampled row stream. train_fn
    then sees a materialised dict indexed by local positions, which is
    element-for-element identical to indexing the corpus with the global rows.
    Threads (not processes) share the read-only memmaps safely and avoid the
    fork-duplication pitfall of DataLoader workers.
    """
    # Do not eagerly construct one NumPy array per batch.  On a multi-million
    # row corpus that duplicated the complete epoch index stream and retained
    # tens of thousands of tiny arrays on every DDP rank before the first GPU
    # step.  Resolve only the bounded synchronous/current-prefetch window.
    batch_size = int(batch_size)
    if batch_size <= 0:
        raise ValueError("batch_size must be positive")
    num_batches = (len(order) + batch_size - 1) // batch_size

    def _batch_at(index: int) -> np.ndarray:
        start = index * batch_size
        stop = min(start + batch_size, len(order))
        return train_indices[order[start:stop]]

    if policy_aux_rows is not None:
        aux_rows = np.asarray(policy_aux_rows, dtype=np.int64)
        aux_size = int(policy_aux_batch_size)
        if aux_size <= 0 or aux_rows.ndim != 1:
            raise RuntimeError("policy auxiliary prefetch shape is invalid")
        expected = num_batches * aux_size
        if len(aux_rows) != expected:
            raise RuntimeError(
                "policy auxiliary draw dose drift: "
                f"rows={len(aux_rows)} expected={expected}"
            )

        def _aux_batch_at(index: int) -> np.ndarray:
            start = index * aux_size
            return aux_rows[start : start + aux_size]
    else:
        _aux_batch_at = None

    if num_workers <= 0 or not isinstance(data, (MemmapCorpus, ConcatMemmapCorpus)):
        for index in range(num_batches):
            batch = _batch_at(index)
            if _aux_batch_at is None:
                yield data, batch, policy_sample_weights, value_sample_weights
            else:
                aux_batch = _aux_batch_at(index)
                yield (
                    data,
                    batch,
                    policy_sample_weights,
                    value_sample_weights,
                    data,
                    aux_batch,
                    aux_batch,
                )
        return

    available_keys = tuple(data.keys())
    if materialize_keys is None:
        keys = available_keys
    else:
        keys = tuple(materialize_keys)
        if len(keys) != len(set(keys)):
            raise ValueError("prefetch materialization keys contain duplicates")
        missing = set(keys) - set(available_keys)
        if missing:
            raise ValueError(
                "prefetch materialization keys are absent from the corpus: "
                + ",".join(sorted(missing))
            )

    def _materialize(batch: np.ndarray, aux_batch: np.ndarray | None):
        rows = (
            batch
            if aux_batch is None
            else np.concatenate((batch, aux_batch))
        )
        materialized = {}
        for key in keys:
            if _CROP_AUTHENTICATED_EMPTY_EVENT_HISTORY and key in {
                "event_tokens",
                "event_target_ids",
                "event_mask",
            }:
                # The full-corpus mask was authenticated as empty before this
                # optimization is enabled. Preserve the exact decoded tensor
                # ABI while avoiding reads of the two largest all-zero payloads.
                column = data[key]
                materialized[key] = np.empty(
                    (len(rows), 0, *tuple(column.shape[2:])),
                    dtype=column.dtype,
                )
            else:
                materialized[key] = data[key][rows]
        # train_fn indexes a materialized batch with local ``0..N-1`` rows.
        # Preserve the immutable global source rows separately so post-loss
        # provenance (notably component dose) cannot reinterpret those local
        # positions as rows from component zero of the full composite.
        materialized["_source_global_row_indices"] = np.asarray(
            rows, dtype=np.int64
        ).copy()
        stored_policy_temperatures = _stored_policy_temperatures_for_batch(
            data, rows
        )
        if stored_policy_temperatures is not None:
            materialized["_stored_policy_temperature"] = (
                stored_policy_temperatures
            )
        policy_kl_anchor_eligible = _policy_kl_anchor_scope_mask(data, rows)
        if policy_kl_anchor_eligible is not None:
            # A materialised batch is a plain dict, so authenticated composite
            # attributes (and component_indices_for_rows) no longer exist by
            # the time the loss runs. Carry the resolved row mask explicitly;
            # otherwise threaded prefetch silently broadens a replay-only KL
            # anchor to every corpus component while the synchronous path stays
            # correctly scoped.
            materialized["_policy_kl_anchor_eligible"] = (
                policy_kl_anchor_eligible
            )
        aux_subgoal_eligible = _aux_subgoal_scope_mask(data, rows)
        if aux_subgoal_eligible is not None:
            # Preserve the authenticated component scope after global memmap
            # rows are materialized into a local plain dict.
            materialized["_aux_subgoal_eligible"] = aux_subgoal_eligible
        public_award_authoritative = _public_award_authoritative_row_mask(
            data, rows
        )
        if public_award_authoritative is not None:
            # Threaded prefetch replaces the authenticated composite object with
            # a local dict. Carry the already-resolved per-row contract so the
            # worker path cannot accidentally turn mixed routing into all-on or
            # all-zero slot12 behavior.
            materialized["_public_award_authoritative_row_mask"] = (
                public_award_authoritative
            )
        local = np.arange(len(batch), dtype=np.int64)
        local_policy_weights = policy_sample_weights[rows]
        local_value_weights = value_sample_weights[rows]
        if aux_batch is None:
            return (
                materialized,
                local,
                local_policy_weights,
                local_value_weights,
            )
        aux_local = np.arange(len(batch), len(rows), dtype=np.int64)
        return (
            materialized,
            local,
            local_policy_weights,
            local_value_weights,
            materialized,
            aux_local,
            aux_batch,
        )

    prefetch = max(1, int(prefetch))
    with ThreadPoolExecutor(max_workers=int(num_workers)) as executor:
        pending: deque = deque()
        next_index = 0
        while next_index < num_batches and len(pending) < prefetch:
            pending.append(
                executor.submit(
                    _materialize,
                    _batch_at(next_index),
                    None if _aux_batch_at is None else _aux_batch_at(next_index),
                )
            )
            next_index += 1
        while pending:
            future = pending.popleft()
            if next_index < num_batches:
                pending.append(
                    executor.submit(
                        _materialize,
                        _batch_at(next_index),
                        None if _aux_batch_at is None else _aux_batch_at(next_index),
                    )
                )
                next_index += 1
            yield future.result()


def _entity_graph_prefetch_materialization_keys(data) -> tuple[str, ...]:
    """Keep every entity-graph column except its unused legacy dense input."""
    return tuple(key for key in data.keys() if key != "obs")


def load_teacher_data(
    path: Path,
    *,
    ddp: dict[str, int | bool] | None = None,
    shard_data: bool = False,
    mask_hidden_info: bool = False,
    preserve_belief_resource_targets: bool = False,
    entity_feature_adapter_version: str = LEGACY_MISSING_CHECKPOINT_ADAPTER_VERSION,
) -> dict:
    files = _teacher_shard_files(path)
    if not files:
        raise SystemExit(f"no teacher shards found in {path}")
    total_files = len(files)
    if shard_data:
        if ddp is None or not bool(ddp.get("enabled", False)):
            raise SystemExit("--ddp-shard-data requires torchrun/DDP")
        world_size = int(ddp["world_size"])
        rank = int(ddp["rank"])
        files = files[rank::world_size]
        if not files:
            raise SystemExit(
                f"rank {rank} received no teacher shards from {path}; "
                f"total_shards={total_files}, world_size={world_size}"
            )
        print(
            json.dumps(
                {
                    "progress": "bc_data_shard_load",
                    "rank": rank,
                    "world_size": world_size,
                    "loaded_shards": len(files),
                    "total_shards": total_files,
                    "first_shard": str(files[0]),
                    "last_shard": str(files[-1]),
                },
                sort_keys=True,
            ),
            flush=True,
        )
    arrays: dict[str, list[np.ndarray]] = {}
    aux_targets_enabled = False
    prior_row_counts: list[int] = []
    keys = (
        "obs",
        "legal_action_ids",
        "legal_action_context",
        "action_taken",
        "target_policy",
        "prior_policy",
        "target_scores",
        "target_policy_mask",
        "target_scores_mask",
        "target_score_source",
        "target_information_regime",
        *TARGET_RELIABILITY_COLUMNS,
        "root_value",
        "root_value_mask",
        "root_prior_value",
        "root_prior_value_mask",
        "afterstate_target",
        "afterstate_target_mask",
        "simulations_used",
        "is_forced",
        "used_full_search",
        "game_seed",
        "teacher_name",
        "player",
        "seat",
        "phase",
        "decision_index",
        "action_mask_version",
        "adapter_version",
        "actor_resource_counts",
        "winner",
        "terminated",
        "truncated",
        "final_public_vps",
        "has_final_public_vps",
        "final_actual_vps",
        "has_final_actual_vps",
        "policy_weight_multiplier",
        "value_weight_multiplier",
        *RESTART_PROVENANCE_KEYS,
        *OPPONENT_PROVENANCE_KEYS,
        *TRAINING_SOURCE_PROVENANCE_KEYS,
        *AUX_TARGET_KEYS,
        AUX_SUBGOAL_TARGET_VERSION_KEY,
        "hex_tokens",
        "hex_vertex_ids",
        "hex_edge_ids",
        "vertex_tokens",
        "edge_tokens",
        "edge_vertex_ids",
        "player_tokens",
        "belief_resource_composition",
        "belief_resource_total",
        "belief_resource_valid",
        "global_tokens",
        "legal_action_tokens",
        "legal_action_target_ids",
        "event_tokens",
        "event_target_ids",
        "hex_mask",
        "vertex_mask",
        "edge_mask",
        "player_mask",
        "legal_action_mask",
        "event_mask",
    )
    if mask_hidden_info:
        from catan_zero.rl.entity_token_features import mask_player_tokens_public
    for file in files:
        raw = _load_npz(file)
        raw_has_aux_targets = any(key in raw for key in AUX_TARGET_KEYS)
        if raw_has_aux_targets and not aux_targets_enabled:
            # A replay window may intentionally mix legacy shards with newly
            # labeled CAT-100 shards. Backfill already-seen legacy rows with
            # ignore values when the first labeled shard appears so every
            # column remains aligned to action_taken.
            aux_targets_enabled = True
            for key in AUX_TARGET_KEYS:
                arrays[key] = [
                    _aux_subgoal_default_array(key, rows) for rows in prior_row_counts
                ]
            arrays[AUX_SUBGOAL_TARGET_VERSION_KEY] = [
                np.zeros(rows, dtype=np.uint8) for rows in prior_row_counts
            ]
        shard = _normalize_teacher_shard(
            raw,
            file,
            include_aux_defaults=aux_targets_enabled,
        )
        prior_row_counts.append(int(len(shard["action_taken"])))
        if mask_hidden_info and "player_tokens" in shard:
            if preserve_belief_resource_targets:
                from catan_zero.rl.belief_aux_targets import (
                    resource_belief_targets,
                )

                composition, total, valid = resource_belief_targets(
                    shard["player_tokens"],
                    entity_feature_adapter_version=entity_feature_adapter_version,
                )
                shard["belief_resource_composition"] = composition
                shard["belief_resource_total"] = total
                shard["belief_resource_valid"] = valid
            # f72 public-observation training: strip opponent hidden slots from the
            # banked (omniscient) tokens so this corpus trains a public-only model.
            shard["player_tokens"] = mask_player_tokens_public(shard["player_tokens"])
        for key in keys:
            if key in shard:
                arrays.setdefault(key, []).append(shard[key])
    expected_rows = int(sum(prior_row_counts))
    result: dict[str, np.ndarray] = {}
    for key, values in arrays.items():
        concatenated = _concat_padded(key, values)
        if int(concatenated.shape[0]) != expected_rows:
            raise SystemExit(
                f"teacher field {key!r} violates cross-shard row alignment: "
                f"rows={int(concatenated.shape[0])} expected={expected_rows}. "
                "Mixed optional schemas require a safe per-row default or must "
                "be rebuilt with one consistent schema."
            )
        result[key] = concatenated
    return result


def _policy_target_completeness_report(
    data,
    *,
    policy_loss_weight: float,
    train_value_only: bool,
    soft_target_source: str,
    soft_target_weight: float,
    policy_target_blend_semantics: str,
    soft_target_temperature: float,
    soft_target_min_legal_coverage: float,
    require_exact_public_policy: bool,
    chunk_rows: int = 262_144,
) -> dict[str, object]:
    """Replay which policy rows can reach hard ``action_taken`` fallback.

    Coherent-public production requires more than a non-empty distribution:
    every policy-active row must carry a finite normalized stored policy whose
    authenticated support is exactly the complete legal-action set.  This scan
    is chunked so the admission proof remains bounded for multi-million-row
    memmap composites.
    """

    rows = int(len(data["action_taken"]))
    active = np.ones(rows, dtype=np.bool_)
    if "policy_weight_multiplier" in data:
        multiplier = np.asarray(data["policy_weight_multiplier"])
        if multiplier.shape != (rows,):
            raise SystemExit(
                "policy_weight_multiplier shape drift during policy-target admission"
            )
        active = multiplier > 0.0
    policy_scope = _policy_distillation_scope_mask(
        data, np.arange(rows, dtype=np.int64)
    )
    if policy_scope is not None:
        active &= policy_scope
    policy_active_rows = int(np.count_nonzero(active))
    objective_active = bool(
        float(policy_loss_weight) > 0.0
        and not bool(train_value_only)
        and policy_active_rows > 0
    )
    fallback_semantics = bool(
        objective_active
        and str(policy_target_blend_semantics) == POLICY_TARGET_BLEND_FALLBACK_V2
        and float(soft_target_weight) == 1.0
    )
    usable_rows = 0
    exact_rows = 0
    fallback_rows = policy_active_rows if objective_active else 0
    incomplete_examples: list[int] = []
    digest = hashlib.sha256()
    digest.update(b"coherent-public-policy-target-completeness-v1\0")

    if objective_active and fallback_semantics:
        fallback_rows = 0
        for start in range(0, rows, max(1, int(chunk_rows))):
            stop = min(rows, start + max(1, int(chunk_rows)))
            local_active = active[start:stop]
            if not np.any(local_active):
                continue
            batch = np.arange(start, stop, dtype=np.int64)[local_active]
            soft = _soft_target_array(
                data,
                batch,
                float(soft_target_temperature),
                str(soft_target_source),
            )
            legal = np.asarray(data["legal_action_ids"][batch])
            if soft is None:
                usable = np.zeros(batch.size, dtype=np.bool_)
            else:
                target, support = soft
                usable = _has_distillation_distribution(
                    target,
                    support,
                    legal_action_ids=legal,
                    min_legal_coverage=float(soft_target_min_legal_coverage),
                )
            usable_rows += int(np.count_nonzero(usable))
            fallback_rows += int(np.count_nonzero(~usable))

            exact = np.zeros(batch.size, dtype=np.bool_)
            if (
                str(soft_target_source) == "policy"
                and "target_policy" in data
                and "target_policy_mask" in data
            ):
                raw_target = np.asarray(data["target_policy"][batch], dtype=np.float32)
                raw_support = np.asarray(
                    data["target_policy_mask"][batch], dtype=np.bool_
                )
                legal_support = legal >= 0
                if (
                    raw_target.shape == legal.shape
                    and raw_support.shape == legal.shape
                ):
                    finite_nonnegative = np.all(
                        (~legal_support)
                        | (np.isfinite(raw_target) & (raw_target >= 0.0)),
                        axis=1,
                    )
                    padded_clean = np.all(
                        legal_support
                        | (
                            ~raw_support
                            & np.isfinite(raw_target)
                            & (raw_target == 0.0)
                        ),
                        axis=1,
                    )
                    mass = np.sum(
                        np.where(legal_support, raw_target, 0.0),
                        axis=1,
                        dtype=np.float64,
                    )
                    exact = (
                        np.all(raw_support == legal_support, axis=1)
                        & finite_nonnegative
                        & padded_clean
                        & np.isclose(mass, 1.0, rtol=1.0e-6, atol=1.0e-6)
                    )
                    digest.update(
                        np.asarray(batch, dtype="<i8").tobytes(order="C")
                    )
                    digest.update(
                        np.asarray(legal, dtype="<i2").tobytes(order="C")
                    )
                    digest.update(
                        np.asarray(raw_support, dtype=np.uint8).tobytes(order="C")
                    )
                    digest.update(
                        np.asarray(raw_target, dtype="<f4").tobytes(order="C")
                    )
            exact_rows += int(np.count_nonzero(exact))
            rejected = batch[~exact]
            if rejected.size and len(incomplete_examples) < 16:
                incomplete_examples.extend(
                    map(int, rejected[: 16 - len(incomplete_examples)].tolist())
                )

    report: dict[str, object] = {
        "schema_version": "policy-target-completeness-admission-v1",
        "policy_active_rows": policy_active_rows,
        "policy_objective_active": objective_active,
        "soft_target_source": str(soft_target_source),
        "soft_target_weight": float(soft_target_weight),
        "policy_target_blend_semantics": str(policy_target_blend_semantics),
        "soft_target_min_legal_coverage": float(
            soft_target_min_legal_coverage
        ),
        "usable_soft_target_rows": usable_rows,
        "exact_complete_public_soft_target_rows": exact_rows,
        "hard_action_fallback_rows": fallback_rows,
        "require_exact_public_policy": bool(require_exact_public_policy),
        "incomplete_row_examples": incomplete_examples,
        "row_evidence_sha256": "sha256:" + digest.hexdigest(),
    }
    if bool(require_exact_public_policy) and objective_active:
        config_errors = []
        if str(soft_target_source) != "policy":
            config_errors.append("soft_target_source must equal 'policy'")
        if float(soft_target_weight) != 1.0:
            config_errors.append("soft_target_weight must equal 1.0")
        if str(policy_target_blend_semantics) != POLICY_TARGET_BLEND_FALLBACK_V2:
            config_errors.append(
                "policy_target_blend_semantics must equal policy_target_fallback_v2"
            )
        if float(soft_target_min_legal_coverage) != 1.0:
            config_errors.append("soft_target_min_legal_coverage must equal 1.0")
        if config_errors:
            raise SystemExit(
                "coherent-public policy-target completeness configuration drift: "
                + "; ".join(config_errors)
            )
        if exact_rows != policy_active_rows or fallback_rows:
            raise SystemExit(
                "coherent-public policy-target completeness failed: every "
                "policy-active row must have finite normalized target_policy with "
                "target_policy_mask exactly equal to all legal_action_ids; "
                f"complete={exact_rows}/{policy_active_rows}, "
                f"hard_fallback_rows={fallback_rows}, "
                f"examples={incomplete_examples}"
            )
    return report


def _validate_hard_action_target_admission(
    data,
    data_path: str | Path,
    *,
    mask_hidden_info: bool,
    policy_loss_weight: float,
    train_value_only: bool,
    production: bool,
    acknowledged_authoritative_targets: bool,
    policy_target_completeness: Mapping[str, object] | None = None,
) -> dict[str, object]:
    """Keep played-action provenance separate from search-target provenance.

    A public-masked student can only treat ``action_taken`` as a production label
    when the producing manifest authenticates a public information-set teacher.
    Older and authoritative corpora remain available for explicitly acknowledged
    diagnostics, but acknowledgment is never a production override.
    """

    rows = int(len(data["action_taken"]))
    potential_hard_action_rows = rows
    if policy_target_completeness is not None:
        potential_hard_action_rows = int(
            policy_target_completeness.get("hard_action_fallback_rows", rows)
        )
    elif "policy_weight_multiplier" in data:
        multiplier = np.asarray(data["policy_weight_multiplier"])
        if multiplier.shape != (rows,):
            raise SystemExit(
                "policy_weight_multiplier shape drift during hard-action admission"
            )
        potential_hard_action_rows = int(np.count_nonzero(multiplier > 0.0))
    hard_action_active = (
        bool(mask_hidden_info)
        and float(policy_loss_weight) > 0.0
        and not bool(train_value_only)
        and potential_hard_action_rows > 0
    )

    root = Path(data_path)
    manifest_path = root / (
        "corpus_meta.json" if (root / "corpus_meta.json").is_file() else "manifest.json"
    )
    manifest: dict[str, object] = {}
    if manifest_path.is_file():
        try:
            loaded = json.loads(manifest_path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError) as error:
            raise SystemExit(
                f"cannot read hard-action provenance manifest {manifest_path}: {error}"
            ) from error
        if not isinstance(loaded, dict):
            raise SystemExit(
                f"hard-action provenance manifest must be a JSON object: {manifest_path}"
            )
        manifest = loaded

    direct = manifest.get("hard_action_target_information")
    resolved = propagated_hard_action_target_information(manifest)
    direct_contract_present = isinstance(direct, dict)
    if direct_contract_present and direct != resolved:
        raise SystemExit(
            "hard-action target provenance conflicts with nested source lineage: "
            f"manifest={manifest_path}"
        )
    expected_fields = {
        "schema_version",
        "target_column",
        "information_scope",
        "public_information_authenticated",
        "producer",
    }
    shape_valid = (
        set(resolved) == expected_fields
        and resolved.get("schema_version") == HARD_ACTION_TARGET_INFORMATION_SCHEMA
        and resolved.get("target_column") == "action_taken"
        and isinstance(resolved.get("information_scope"), str)
        and isinstance(resolved.get("public_information_authenticated"), bool)
        and isinstance(resolved.get("producer"), str)
        and bool(resolved.get("producer"))
    )
    public_authenticated = bool(
        shape_valid
        and direct_contract_present
        and resolved.get("information_scope") == HARD_ACTION_SCOPE_PUBLIC
        and resolved.get("public_information_authenticated") is True
    )
    report: dict[str, object] = {
        "mask_hidden_info": bool(mask_hidden_info),
        # Conservative by construction: even soft_target_weight=1 uses
        # action_taken as fallback on rows without an admitted soft target.
        # The hard-label provenance contract must therefore cover every
        # policy-weight-positive row unless policy training is wholly disabled.
        "potential_hard_action_policy_active_rows": potential_hard_action_rows,
        "hard_action_objective_active": hard_action_active,
        "train_value_only": bool(train_value_only),
        "manifest": str(manifest_path),
        "direct_contract_present": direct_contract_present,
        "contract": resolved,
        "public_information_authenticated": public_authenticated,
        "diagnostic_acknowledgement": bool(acknowledged_authoritative_targets),
        "production": bool(production),
        "policy_target_completeness": (
            None
            if policy_target_completeness is None
            else dict(policy_target_completeness)
        ),
    }
    if not hard_action_active:
        return report
    if public_authenticated:
        return report
    if bool(production):
        raise SystemExit(
            "masked production training refused hard action targets that are not "
            "public-information authenticated: action_taken was selected under "
            f"scope={resolved.get('information_scope')!r}, producer="
            f"{resolved.get('producer')!r}, manifest={manifest_path}. Observation "
            "masking does not sanitize an authoritative teacher label. Generate "
            "labels with an authenticated public information-set teacher; the "
            "diagnostic acknowledgment flag cannot override production admission."
        )
    if not bool(acknowledged_authoritative_targets):
        raise SystemExit(
            "masked training refused unauthenticated hard action targets: "
            f"scope={resolved.get('information_scope')!r}, producer="
            f"{resolved.get('producer')!r}, manifest={manifest_path}. For a sealed "
            "historical/diagnostic replay only, pass "
            "--acknowledge-authoritative-hard-action-targets."
        )
    return report


def _validate_target_information_admission(
    data,
    *,
    mask_hidden_info: bool,
    soft_target_weight: float,
    policy_target_blend_semantics: str = POLICY_TARGET_BLEND_FALLBACK_V2,
    policy_loss_weight: float,
    q_loss_weight: float,
    value_target_lambda: float,
    policy_kl_anchor_weight: float,
    policy_surprise_weight: float,
    required_target_information_regime: str = (
        TARGET_INFORMATION_REGIME_PUBLIC_COHERENT
    ),
    policy_kl_target: float | None = None,
    per_game_policy_surprise_weighting: bool = False,
    soft_target_source: str = "policy",
    soft_target_temperature: float = 0.7,
    soft_target_min_legal_coverage: float = 0.5,
    policy_target_completeness: Mapping[str, object] | None = None,
) -> dict[str, object]:
    """Fail closed before public-information training consumes search targets.

    Observation masking and search-state safety are independent contracts.  A
    masked student may still use realised outcomes from legacy rows, but every
    row that is active for a search-derived objective must bind the one exact
    requested operator. Public PIMC and coherent-public search are both
    information-safe yet are not interchangeable policy-improvement teachers.
    """

    n = int(len(data["action_taken"]))
    regime_column = data.get("target_information_regime")
    if regime_column is None:
        counts = {TARGET_INFORMATION_REGIME_UNKNOWN: n}
    else:
        if tuple(getattr(regime_column, "shape", ())) != (n,):
            raise SystemExit(
                "target_information_regime must be a one-dimensional per-row column: "
                f"expected {(n,)}, got {getattr(regime_column, 'shape', None)}"
            )
        # Dictionary-encoded memmaps can count their compact integer codes
        # directly.  Decoding a 47.6M-row composite to a temporary Unicode
        # array here used hundreds of MiB and was repeated by every DDP rank.
        if isinstance(regime_column, _MemmapCategoricalColumn) or bool(
            getattr(regime_column, "supports_value_counts", False)
        ):
            counts = {
                str(value): int(count)
                for value, count in regime_column.value_counts().items()
            }
        else:
            regimes = np.asarray(regime_column).astype(str)
            counts = {
                str(value): int(count)
                for value, count in zip(*np.unique(regimes, return_counts=True))
            }
    if sum(counts.values()) != n:
        raise SystemExit(
            "target_information_regime counts do not cover the corpus: "
            f"counts={sum(counts.values())} rows={n}"
        )
    safe_count = sum(int(counts.get(regime, 0)) for regime in TARGET_INFORMATION_REGIMES_PUBLIC)
    unsafe_count = n - safe_count
    objectives: list[str] = []
    if (
        float(policy_loss_weight) != 0.0
        and float(soft_target_weight) > 0.0
        and ("target_policy" in data or "target_scores" in data)
    ):
        objectives.append("soft_policy")
    if float(q_loss_weight) != 0.0 and "target_scores" in data:
        objectives.append("q_target")
    if float(value_target_lambda) != 1.0 and "root_value" in data:
        objectives.append("root_value")
    if (
        float(policy_kl_anchor_weight) > 0.0 or policy_kl_target is not None
    ) and "prior_policy" in data:
        objectives.append("policy_kl_anchor")
    if float(policy_surprise_weight) > 0.0 and (
        "target_policy" in data or "prior_policy" in data
    ):
        objectives.append("policy_surprise_sampling")
    if bool(per_game_policy_surprise_weighting) and (
        "target_policy" in data or "prior_policy" in data
    ):
        objectives.append("per_game_capped_policy_surprise_sampling")

    required_regime = str(required_target_information_regime)
    if required_regime not in TARGET_INFORMATION_REGIMES_PUBLIC:
        raise SystemExit(
            "required_target_information_regime must name one exact supported "
            f"public search operator, got {required_regime!r}"
        )
    all_rows = np.arange(n, dtype=np.int64)
    policy_active = np.ones(n, dtype=np.bool_)
    if "policy_weight_multiplier" in data:
        policy_active = np.asarray(data["policy_weight_multiplier"]) > 0.0
        if policy_active.shape != (n,):
            raise SystemExit("policy_weight_multiplier shape drift during admission")
    policy_scope = _policy_distillation_scope_mask(data, all_rows)
    scoped_policy_active = policy_active.copy()
    if policy_scope is not None:
        scoped_policy_active &= policy_scope
    objective_active = np.zeros(n, dtype=np.bool_)
    if any(
        objective
        in {
            "soft_policy",
            "q_target",
            "policy_surprise_sampling",
            "per_game_capped_policy_surprise_sampling",
        }
        for objective in objectives
    ):
        objective_active |= scoped_policy_active
    if "policy_kl_anchor" in objectives:
        anchor_scope = _policy_kl_anchor_scope_mask(data, all_rows)
        objective_active |= (
            policy_active
            if anchor_scope is None
            else policy_active & anchor_scope
        )
    if "root_value" in objectives:
        if "root_value_mask" in data:
            root_active = np.asarray(data["root_value_mask"], dtype=np.bool_)
        else:
            root_active = np.isfinite(np.asarray(data["root_value"]))
        if root_active.shape != (n,):
            raise SystemExit("root-value activity mask shape drift during admission")
        value_scope = _value_training_scope_mask(data, all_rows)
        if value_scope is not None:
            root_active &= value_scope
        objective_active |= root_active
    active_indices = np.flatnonzero(objective_active)
    if regime_column is None:
        active_regime_counts = {
            TARGET_INFORMATION_REGIME_UNKNOWN: int(active_indices.size)
        }
    elif int(active_indices.size) == n:
        # Preserve the count-only categorical fast path when every row is
        # active. Some authenticated corpus columns intentionally expose
        # value_counts without materializing or supporting row indexing.
        active_regime_counts = dict(counts)
    elif isinstance(regime_column, _MemmapCategoricalColumn) or bool(
        getattr(regime_column, "supports_value_counts", False)
    ):
        active_regime_counts = {
            str(value): int(count)
            for value, count in regime_column.value_counts(
                index=active_indices
            ).items()
        }
    else:
        active_regimes = np.asarray(regime_column[active_indices]).astype(str)
        active_regime_counts = {
            str(value): int(count)
            for value, count in zip(
                *np.unique(active_regimes, return_counts=True), strict=True
            )
        }
    mismatched_target_rows = int(active_indices.size) - int(
        active_regime_counts.get(required_regime, 0)
    )
    report: dict[str, object] = {
        "mask_hidden_info": bool(mask_hidden_info),
        "target_information_regime_counts": counts,
        "required_target_information_regime": required_regime,
        "search_objective_active_rows": int(active_indices.size),
        "search_objective_target_information_regime_counts": active_regime_counts,
        "policy_target_blend_semantics": str(policy_target_blend_semantics),
        "mismatched_target_information_rows": mismatched_target_rows,
        "unsafe_or_unknown_rows": unsafe_count,
        "search_target_objectives": objectives,
    }
    if bool(mask_hidden_info) and objectives and mismatched_target_rows:
        raise SystemExit(
            "public-observation training refused mismatched search targets: "
            f"objectives={objectives}, required_target_information_regime="
            f"{required_regime!r}, mismatched_objective_rows="
            f"{mismatched_target_rows}/{int(active_indices.size)}, "
            f"unsafe_or_unknown_rows={unsafe_count}/{n}, "
            f"objective_target_information_regimes={active_regime_counts}, "
            f"corpus_target_information_regimes={counts}. Public PIMC and coherent-public "
            "single-tree targets are different policy-improvement operators and may "
            "not be silently combined or substituted. Reanalyse with the required "
            "operator, explicitly select the legacy regime for a sealed ablation, or "
            "disable every listed search-target objective and train only on hard "
            "actions/realised outcomes."
        )
    semantics = str(policy_target_blend_semantics)
    if semantics not in POLICY_TARGET_BLEND_SEMANTICS:
        raise SystemExit(
            "policy_target_blend_semantics must name one exact supported loss "
            f"contract, got {semantics!r}"
        )
    weight = float(soft_target_weight)
    if not math.isfinite(weight) or not 0.0 <= weight <= 1.0:
        raise SystemExit("soft_target_weight must be finite and in [0, 1]")
    if semantics == POLICY_TARGET_BLEND_FALLBACK_V2 and weight not in {0.0, 1.0}:
        raise SystemExit(
            "policy_target_fallback_v2 forbids intermediate soft_target_weight: "
            "use 1.0 for pure authenticated policy CE with hard fallback, 0.0 "
            "to disable soft targets, or explicitly select legacy_interpolate_v1 "
            "to replay a historical mixed-label report"
        )
    if (
        required_regime == TARGET_INFORMATION_REGIME_PUBLIC_COHERENT
        and "soft_policy" in objectives
        and (
            semantics != POLICY_TARGET_BLEND_FALLBACK_V2
            or weight != 1.0
        )
    ):
        raise SystemExit(
            "coherent-public search-policy distillation requires "
            "policy_target_fallback_v2 with soft_target_weight=1.0"
        )
    if (
        bool(mask_hidden_info)
        and required_regime == TARGET_INFORMATION_REGIME_PUBLIC_COHERENT
        and "soft_policy" in objectives
    ):
        completeness = (
            _policy_target_completeness_report(
                data,
                policy_loss_weight=float(policy_loss_weight),
                train_value_only=False,
                soft_target_source=str(soft_target_source),
                soft_target_weight=weight,
                policy_target_blend_semantics=semantics,
                soft_target_temperature=float(soft_target_temperature),
                soft_target_min_legal_coverage=float(
                    soft_target_min_legal_coverage
                ),
                require_exact_public_policy=True,
            )
            if policy_target_completeness is None
            else dict(policy_target_completeness)
        )
        if (
            completeness.get("require_exact_public_policy") is not True
            or int(completeness.get("hard_action_fallback_rows", -1)) != 0
            or int(
                completeness.get(
                    "exact_complete_public_soft_target_rows", -1
                )
            )
            != int(completeness.get("policy_active_rows", -2))
        ):
            raise SystemExit(
                "coherent-public target-information admission lacks an exact "
                "policy-target completeness proof"
            )
        report["policy_target_completeness"] = completeness
    report["played_action_mixed_into_usable_policy_target"] = bool(
        semantics == POLICY_TARGET_BLEND_LEGACY_V1 and 0.0 < weight < 1.0
    )
    return report


def _env_config_for_teacher_data(args, data: dict, ddp: dict[str, int | bool]):
    from catan_zero.rl.multiagent_env import ColonistMultiAgentEnv

    observed_width = int(data["obs"].shape[1])
    base_config = parse_track(
        args.track,
        vps_to_win=args.vps_to_win,
        use_graph_history_features=False,
    )
    graph_config = parse_track(
        args.track,
        vps_to_win=args.vps_to_win,
        use_graph_history_features=True,
    )

    def _obs_width(config) -> int:
        env = ColonistMultiAgentEnv(config)
        try:
            return int(env.observation_space.shape[0])
        finally:
            env.close()

    base_width = _obs_width(base_config)
    graph_width = _obs_width(graph_config)
    if bool(args.graph_history_features):
        selected = graph_config
        reason = "explicit"
    elif observed_width == graph_width and observed_width != base_width:
        selected = graph_config
        reason = "auto_detected_from_obs_width"
    elif observed_width == base_width:
        selected = base_config
        reason = "base_obs_width"
    else:
        raise SystemExit(
            "teacher observation width does not match a known train schema: "
            f"observed={observed_width}, base={base_width}, graph_history={graph_width}. "
            "Regenerate/curate the shards with the current env or pass the correct "
            "--graph-history-features setting if the schema changed intentionally."
        )
    _rank0_print(
        json.dumps(
            {
                "progress": "bc_env_schema",
                "track": args.track,
                "vps_to_win": int(args.vps_to_win),
                "observed_obs_width": observed_width,
                "base_obs_width": base_width,
                "graph_history_obs_width": graph_width,
                "graph_history_features": bool(
                    getattr(selected, "use_graph_history_features", False)
                ),
                "reason": reason,
            },
            sort_keys=True,
        ),
        ddp,
    )
    return selected


def _a1_training_event_history_contract(
    args,
    a1_preflight_meta: dict[str, object] | None,
    env_config,
) -> dict[str, object] | None:
    """Build the fail-closed entity-event contract for authenticated A1 data."""

    if a1_preflight_meta is None:
        # Backward compatibility: generic/legacy non-A1 corpora retain their
        # historical behavior. A1 and production paths are authenticated above.
        return None
    from audit_entity_graph_information_surface import (
        InformationSurfaceError,
        build_a1_training_event_history_contract,
    )

    if a1_preflight_meta.get("schema_version") in {
        "memmap_composite_v1",
        "memmap_composite_v2",
    }:
        components = {
            str(component["component_id"]): component["corpus_meta"]
            for component in a1_preflight_meta["components"]
        }
    else:
        components = {"a1": a1_preflight_meta}
    component_payload_scans = {
        component_id: metadata["event_history_payload_scan"]
        for component_id, metadata in components.items()
        if isinstance(metadata.get("event_history_payload_scan"), dict)
    }
    selected_adapter = getattr(args, "entity_feature_adapter_version", None)
    init_checkpoint = str(getattr(args, "init_checkpoint", "") or "")
    if selected_adapter is None and init_checkpoint:
        selected_adapter = _checkpoint_entity_feature_adapter_version(
            str(
                getattr(
                    args,
                    "authenticated_init_checkpoint_load_path",
                    init_checkpoint,
                )
            )
        )
    try:
        return build_a1_training_event_history_contract(
            components,
            graph_history_features=bool(
                getattr(env_config, "use_graph_history_features", False)
            ),
            event_history_consumer_enabled=str(args.arch) == "entity_graph",
            entity_feature_adapter_version=selected_adapter,
            empty_payload_inventory_acknowledgements=tuple(
                args.acknowledge_empty_event_history_payload_inventory_sha256
            ),
            component_payload_scans=component_payload_scans,
        )
    except InformationSurfaceError as error:
        raise SystemExit(f"A1 event-history contract refused training: {error}") from error


def _scan_empty_event_mask(data: dict, *, chunk_rows: int = 262_144) -> dict[str, object]:
    """Exactly prove the loaded immutable corpus exposes no live event rows."""

    if isinstance(chunk_rows, bool) or int(chunk_rows) < 1:
        raise ValueError("chunk_rows must be a positive integer")
    column = data["event_mask"]
    rows = int(column.shape[0])
    width = int(column.shape[1])
    nonzero = 0
    for start in range(0, rows, int(chunk_rows)):
        chunk = np.asarray(column[start : start + int(chunk_rows)], dtype=np.bool_)
        nonzero += int(np.count_nonzero(chunk))
        if nonzero:
            raise SystemExit(
                "--crop-authenticated-empty-event-history found a live event mask: "
                f"first_nonempty_chunk_start={start} nonzero_count_at_least={nonzero}"
            )
    scan = {
        "schema": "training-empty-event-mask-scan-v1",
        "row_count": rows,
        "padded_event_width": width,
        "nonzero_event_mask_count": 0,
    }
    scan["scan_sha256"] = _canonical_json_sha256(scan)
    return scan


def _teacher_shard_files(path: Path) -> list[Path]:
    manifest_path = path / "manifest.json"
    if manifest_path.exists():
        files = _manifest_shard_files(manifest_path)
        if files:
            return files

    if (path / "manifest.partial.json").exists() or (path / "parts").exists():
        raise SystemExit(
            f"{path} looks like a partial Modal/raw teacher root without a completed "
            "top-level manifest.json; refusing recursive shard glob. Curate or "
            "summarize the run first, or pass a completed leaf teacher_data directory."
        )

    files = sorted(path.glob("*.npz")) + sorted(path.glob("*.npz.zst"))
    if files:
        return files

    child_manifests = sorted(
        candidate
        for candidate in path.glob("**/manifest.json")
        if candidate.parent != path
    )
    if len(child_manifests) == 1:
        files = _manifest_shard_files(child_manifests[0])
        if files:
            return files
    if len(child_manifests) > 1:
        files = _modal_part_manifest_shards(path, child_manifests)
        if files:
            return files
        files = _entity_partition_manifest_shards(child_manifests)
        if files:
            return files
        previews = ", ".join(str(candidate.parent) for candidate in child_manifests[:5])
        raise SystemExit(
            f"{path} contains multiple nested teacher manifests; pass a single leaf "
            f"curated data directory instead of recursively mixing runs. Examples: {previews}"
        )

    return sorted(path.glob("**/*.npz")) + sorted(path.glob("**/*.npz.zst"))


def _modal_part_manifest_shards(path: Path, manifests: list[Path]) -> list[Path]:
    files: list[Path] = []
    for manifest in manifests:
        try:
            relative = manifest.relative_to(path)
        except ValueError:
            return []
        parts = relative.parts
        if len(parts) != 3 or parts[0] != "parts" or not parts[1].startswith("part_"):
            return []
        files.extend(_manifest_shard_files(manifest))
    return sorted(files)


def _entity_partition_manifest_shards(manifests: list[Path]) -> list[Path]:
    files: list[Path] = []
    signatures: set[tuple[str, int, bool]] = set()
    partition_pairs: set[tuple[int, int]] = set()
    partition_counts: set[int] = set()
    for manifest_path in manifests:
        try:
            manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
        except Exception:
            return []
        if manifest.get("schema") != "entity_tokens_v1":
            return []
        signatures.add(
            (
                str(manifest.get("track", "")),
                int(manifest.get("vps_to_win", -1)),
                bool(manifest.get("graph_history_features", False)),
            )
        )
        partition_count = int(manifest.get("partition_count", 1))
        partition_index = int(manifest.get("partition_index", 0))
        partition_counts.add(partition_count)
        partition_pairs.add((partition_count, partition_index))
        if manifest.get("mismatches"):
            raise SystemExit(f"{manifest_path} contains entity conversion mismatches")
        files.extend(_manifest_shard_files(manifest_path))
    if len(signatures) != 1:
        return []
    if len(partition_pairs) != len(manifests):
        raise SystemExit("duplicate entity conversion partition manifests detected")
    if len(partition_counts) != 1:
        raise SystemExit("inconsistent entity conversion partition counts detected")
    partition_count = next(iter(partition_counts))
    expected = {(partition_count, index) for index in range(partition_count)}
    missing = sorted(index for _, index in (expected - partition_pairs))
    extra = sorted(index for _, index in (partition_pairs - expected))
    if missing or extra:
        details = []
        if missing:
            details.append(f"missing partition indices {missing[:10]}")
        if extra:
            details.append(f"unexpected partition indices {extra[:10]}")
        raise SystemExit("incomplete entity conversion partition manifests: " + "; ".join(details))
    return sorted(files)


def _manifest_shard_files(manifest_path: Path) -> list[Path]:
    manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    if manifest.get("schema_version") == _POLICY_TARGET_REANALYSIS_SCHEMA:
        _validate_policy_target_reanalysis_manifest(manifest_path)
    files = []
    missing = []
    for value in manifest.get("shards", ()):
        raw = Path(value)
        candidates = [raw] if raw.is_absolute() else [raw, manifest_path.parent / raw]
        if raw.is_absolute():
            candidates.append(manifest_path.parent / raw.name)
        chosen = next((candidate for candidate in candidates if candidate.exists()), candidates[0])
        files.append(chosen)
        if not chosen.exists():
            missing.append(str(chosen))
    if missing:
        preview = ", ".join(missing[:5])
        raise SystemExit(
            f"{manifest_path} points to missing teacher shards. "
            f"First missing paths: {preview}"
        )
    return files


def _normalize_teacher_shard(
    shard,
    path: Path,
    *,
    include_aux_defaults: bool = False,
) -> dict[str, np.ndarray]:
    required = ("obs", "legal_action_ids", "legal_action_context", "action_taken")
    missing = [key for key in required if key not in shard]
    if missing:
        raise SystemExit(f"{path} is missing required teacher fields: {missing}")

    action_taken = np.asarray(shard["action_taken"], dtype=np.int16)
    n = int(len(action_taken))
    legal = np.asarray(shard["legal_action_ids"], dtype=np.int16)
    context = np.asarray(shard["legal_action_context"], dtype=np.float16)
    obs = np.asarray(shard["obs"], dtype=np.float16)
    if obs.shape[0] != n or legal.shape[0] != n or context.shape[0] != n:
        raise SystemExit(
            f"{path} has inconsistent row counts: "
            f"obs={obs.shape[0]} legal={legal.shape[0]} "
            f"context={context.shape[0]} action_taken={n}"
        )
    if legal.ndim != 2 or context.ndim != 3 or context.shape[1] != legal.shape[1]:
        raise SystemExit(
            f"{path} has invalid legal/context shapes: "
            f"legal={legal.shape} context={context.shape}"
        )

    legal_width = int(legal.shape[1])
    shard_has_final_public_vps = False
    shard_has_final_actual_vps = False
    target_policy = _field_or_default(
        shard,
        "target_policy",
        np.zeros((n, legal_width), dtype=np.float32),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.float32, copy=False)  # F4: fp32, not fp16 (see gumbel_self_play.py._build_decision_row)
    # Success telemetry: root prior (pre-search network policy), same legal_rust
    # ordering as target_policy -- only populated by Gumbel self-play rows
    # (gumbel_self_play.py._build_decision_row), defaults to all-zero for any
    # other teacher source. That default is exactly what scopes
    # _prior_kl_telemetry to a held-out GEN slice with no extra bookkeeping.
    prior_policy = _field_or_default(
        shard,
        "prior_policy",
        np.zeros((n, legal_width), dtype=np.float32),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.float32, copy=False)
    target_scores = _field_or_default(
        shard,
        "target_scores",
        np.full((n, legal_width), np.nan, dtype=np.float32),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.float32, copy=False)
    target_policy_mask = _field_or_default(
        shard,
        "target_policy_mask",
        (np.asarray(target_policy, dtype=np.float32) > 0.0),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.bool_, copy=False)
    target_scores_mask = _field_or_default(
        shard,
        "target_scores_mask",
        np.isfinite(target_scores),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.bool_, copy=False)

    # Keep the v6 admission witness exact.  Casting first would turn malformed
    # floating-point evidence such as ``1.9`` into an apparently valid integer
    # count and could let a corrupt shard authenticate itself accidentally.
    if "actor_resource_counts" in shard:
        raw_actor_resource_counts = np.asarray(shard["actor_resource_counts"])
        if raw_actor_resource_counts.shape != (n, 5):
            raise SystemExit(
                f"{path} has invalid actor_resource_counts shape: "
                f"{raw_actor_resource_counts.shape}; expected {(n, 5)}"
            )
        if raw_actor_resource_counts.dtype.kind not in {"i", "u"}:
            raise SystemExit(
                f"{path} actor_resource_counts must use an integral dtype, got "
                f"{raw_actor_resource_counts.dtype}"
            )
        if np.any(raw_actor_resource_counts < 0) or np.any(
            raw_actor_resource_counts > 19
        ):
            raise SystemExit(
                f"{path} actor_resource_counts must be physical counts in [0, 19]"
            )
        actor_resource_counts = raw_actor_resource_counts.astype(
            np.int16, copy=False
        )
    else:
        actor_resource_counts = np.full((n, 5), -1, dtype=np.int16)

    result: dict[str, np.ndarray] = {
        "obs": obs,
        "legal_action_ids": legal,
        "legal_action_context": context,
        "action_taken": action_taken,
        "target_policy": target_policy,
        "prior_policy": prior_policy,
        "target_scores": target_scores,
        "target_policy_mask": target_policy_mask,
        "target_scores_mask": target_scores_mask,
        "target_score_source": _field_or_default(
            shard,
            "target_score_source",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "target_information_regime": _field_or_default(
            shard,
            "target_information_regime",
            np.full(n, TARGET_INFORMATION_REGIME_UNKNOWN),
            path,
            leading=n,
        ).astype(str),
        "game_seed": _field_or_default(
            shard,
            "game_seed",
            np.zeros(n, dtype=np.int64),
            path,
            leading=n,
        ).astype(np.int64, copy=False),
        "teacher_name": _field_or_default(
            shard,
            "teacher_name",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "player": _field_or_default(
            shard,
            "player",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "seat": _field_or_default(
            shard,
            "seat",
            np.full(n, -1, dtype=np.int8),
            path,
            leading=n,
        ).astype(np.int8, copy=False),
        "phase": _field_or_default(
            shard,
            "phase",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        # Search/learner taxonomy is science provenance, not merely a
        # generation audit field.  Keeping it through normalization lets the
        # learner prove which semantic decision classes actually received its
        # finite optimizer dose.  Old corpora remain explicit rather than
        # guessed: they decode as ``legacy_unknown``.
        "decision_class": _field_or_default(
            shard,
            "decision_class",
            np.full(n, "legacy_unknown", dtype="<U14"),
            path,
            leading=n,
        ).astype(str),
        "decision_index": _field_or_default(
            shard,
            "decision_index",
            np.full(n, -1, dtype=np.int32),
            path,
            leading=n,
        ).astype(np.int32, copy=False),
        "action_mask_version": _field_or_default(
            shard,
            "action_mask_version",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "adapter_version": _field_or_default(
            shard,
            "adapter_version",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "actor_resource_counts": actor_resource_counts,
        "winner": _field_or_default(
            shard,
            "winner",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "terminated": _field_or_default(
            shard,
            "terminated",
            np.full(n, True, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "truncated": _field_or_default(
            shard,
            "truncated",
            np.full(n, False, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "final_public_vps": _field_or_default(
            shard,
            "final_public_vps",
            np.zeros((n, 4), dtype=np.int16),
            path,
            leading=n,
        ).astype(np.int16, copy=False),
        "has_final_public_vps": _field_or_default(
            shard,
            "has_final_public_vps",
            np.full(n, shard_has_final_public_vps, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "final_actual_vps": _field_or_default(
            shard,
            "final_actual_vps",
            np.zeros((n, 4), dtype=np.int16),
            path,
            leading=n,
        ).astype(np.int16, copy=False),
        "has_final_actual_vps": _field_or_default(
            shard,
            "has_final_actual_vps",
            np.full(n, shard_has_final_actual_vps, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "policy_weight_multiplier": _field_or_default(
            shard,
            "policy_weight_multiplier",
            np.ones(n, dtype=np.float32),
            path,
            leading=n,
        ).astype(np.float32, copy=False),
        "value_weight_multiplier": _field_or_default(
            shard,
            "value_weight_multiplier",
            np.ones(n, dtype=np.float32),
            path,
            leading=n,
        ).astype(np.float32, copy=False),
        "target_reliability_version": _field_or_default(
            shard,
            "target_reliability_version",
            np.zeros(n, dtype=np.uint8),
            path,
            leading=n,
        ).astype(np.uint8, copy=False),
        "target_reliability_audited": _field_or_default(
            shard,
            "target_reliability_audited",
            np.zeros(n, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "target_reliability_js_divergence": _field_or_default(
            shard,
            "target_reliability_js_divergence",
            np.full(n, np.nan, dtype=np.float32),
            path,
            leading=n,
        ).astype(np.float32, copy=False),
        "target_reliability_policy_top1_agreement": _field_or_default(
            shard,
            "target_reliability_policy_top1_agreement",
            np.zeros(n, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "target_reliability_q_top1_agreement": _field_or_default(
            shard,
            "target_reliability_q_top1_agreement",
            np.zeros(n, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "target_reliability_q_margin_primary": _field_or_default(
            shard,
            "target_reliability_q_margin_primary",
            np.full(n, np.nan, dtype=np.float32),
            path,
            leading=n,
        ).astype(np.float32, copy=False),
        "target_reliability_q_margin_duplicate": _field_or_default(
            shard,
            "target_reliability_q_margin_duplicate",
            np.full(n, np.nan, dtype=np.float32),
            path,
            leading=n,
        ).astype(np.float32, copy=False),
        "target_reliability_confidence": _field_or_default(
            shard,
            "target_reliability_confidence",
            np.ones(n, dtype=np.float32),
            path,
            leading=n,
        ).astype(np.float32, copy=False),
        "is_pool_game": _field_or_default(
            shard,
            "is_pool_game",
            np.zeros(n, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "opponent_version": _field_or_default(
            shard,
            "opponent_version",
            np.full(n, -1, dtype=np.int32),
            path,
            leading=n,
        ).astype(np.int32, copy=False),
        "opponent_tag": _field_or_default(
            shard,
            "opponent_tag",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "opponent_checkpoint_md5": _field_or_default(
            shard,
            "opponent_checkpoint_md5",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "opponent_type": _field_or_default(
            shard,
            "opponent_type",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        # An explicit presence bit distinguishes a recorded self-play/default
        # identity from legacy shards for which opponent identity is unknown.
        "opponent_provenance_present": _field_or_default(
            shard,
            "opponent_provenance_present",
            np.full(
                n,
                any(key in shard for key in OPPONENT_PROVENANCE_KEYS),
                dtype=np.bool_,
            ),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
        "training_source_category": _field_or_default(
            shard,
            "training_source_category",
            np.full(n, "", dtype="<U1"),
            path,
            leading=n,
        ).astype(str),
        "training_source_category_verified": _field_or_default(
            shard,
            "training_source_category_verified",
            np.zeros(n, dtype=np.bool_),
            path,
            leading=n,
        ).astype(np.bool_, copy=False),
    }
    for value_key, mask_key in (
        ("root_value", "root_value_mask"),
        ("root_prior_value", "root_prior_value_mask"),
        ("afterstate_target", "afterstate_target_mask"),
    ):
        if mask_key in shard and value_key not in shard:
            raise SystemExit(
                f"{path} field {mask_key} is present without {value_key}"
            )

    result["root_value"] = _field_or_default(
        shard,
        "root_value",
        np.full(n, np.nan, dtype=np.float32),
        path,
        leading=n,
    ).astype(np.float32, copy=False)
    result["root_value_mask"] = _field_or_default(
        shard,
        "root_value_mask",
        np.isfinite(result["root_value"]),
        path,
        leading=n,
    ).astype(np.bool_, copy=False)
    result["root_prior_value"] = _field_or_default(
        shard,
        "root_prior_value",
        np.full(n, np.nan, dtype=np.float32),
        path,
        leading=n,
    ).astype(np.float32, copy=False)
    result["root_prior_value_mask"] = _field_or_default(
        shard,
        "root_prior_value_mask",
        np.isfinite(result["root_prior_value"]),
        path,
        leading=n,
    ).astype(np.bool_, copy=False)
    result["afterstate_target"] = _field_or_default(
        shard,
        "afterstate_target",
        np.full((n, legal_width), np.nan, dtype=np.float32),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.float32, copy=False)
    result["afterstate_target_mask"] = _field_or_default(
        shard,
        "afterstate_target_mask",
        np.isfinite(result["afterstate_target"]),
        path,
        leading=n,
        width=legal_width,
    ).astype(np.bool_, copy=False)
    if "simulations_used" in shard:
        result["simulations_used"] = _field_or_default(
            shard,
            "simulations_used",
            np.zeros(n, dtype=np.int32),
            path,
            leading=n,
        ).astype(np.int32, copy=False)
    # Preserve optional self-play search provenance when present.  Besides
    # supporting shard audits, these columns make the root-value admission
    # mask independently checkable after normalization.
    for key in ("is_forced", "used_full_search"):
        if key in shard:
            result[key] = _field_or_default(
                shard,
                key,
                np.zeros(n, dtype=np.bool_),
                path,
                leading=n,
            ).astype(np.bool_, copy=False)
    # CAT-100 columns are optional for legacy/non-self-play corpora, but when
    # present they must survive normalization into the training dict. Numeric
    # heads use NaN as their per-row ignore mask; categorical heads use -1.
    for key, dtype in AUX_SUBGOAL_FIELD_DTYPES.items():
        if key not in shard:
            if not include_aux_defaults:
                continue
            value = _aux_subgoal_default_array(key, n)
        else:
            value = np.asarray(shard[key])
        if value.shape != (n,):
            raise SystemExit(
                f"{path} field {key} has shape {value.shape}, expected ({n},)"
            )
        result[key] = value.astype(dtype, copy=False)
    if include_aux_defaults or AUX_SUBGOAL_TARGET_VERSION_KEY in shard:
        version = np.asarray(
            shard[AUX_SUBGOAL_TARGET_VERSION_KEY]
            if AUX_SUBGOAL_TARGET_VERSION_KEY in shard
            else np.zeros(n, dtype=np.uint8)
        )
        if version.shape != (n,):
            raise SystemExit(
                f"{path} field {AUX_SUBGOAL_TARGET_VERSION_KEY} has shape "
                f"{version.shape}, expected ({n},)"
            )
        if version.dtype.kind not in {"i", "u"} or bool(
            np.any((version.astype(np.int64) < 0) | (version.astype(np.int64) > 255))
        ):
            raise SystemExit(
                f"{path} field {AUX_SUBGOAL_TARGET_VERSION_KEY} must be an "
                "integer version in [0, 255]"
            )
        result[AUX_SUBGOAL_TARGET_VERSION_KEY] = version.astype(
            np.uint8, copy=False
        )
    restart_present = set(RESTART_PROVENANCE_KEYS) & set(shard)
    if restart_present:
        missing = set(RESTART_PROVENANCE_KEYS) - restart_present
        if missing:
            raise SystemExit(
                f"{path} has incomplete restart provenance; "
                f"missing={sorted(missing)}"
            )
        for key in RESTART_STRING_KEYS:
            value = np.asarray(shard[key])
            if value.shape != (n,):
                raise SystemExit(
                    f"{path} field {key} has shape {value.shape}, expected ({n},)"
                )
            result[key] = value.astype(str)
        for key in RESTART_BOOL_KEYS:
            value = np.asarray(shard[key])
            if value.shape != (n,):
                raise SystemExit(
                    f"{path} field {key} has shape {value.shape}, expected ({n},)"
                )
            result[key] = value.astype(np.bool_, copy=False)
        for key in RESTART_INT64_KEYS:
            value = np.asarray(shard[key])
            if value.shape != (n,) or value.dtype.kind not in {"i", "u"}:
                raise SystemExit(
                    f"{path} field {key} must be an integral ({n},) column"
                )
            result[key] = value.astype(np.int64, copy=False)
        present = np.asarray(
            result["restart_provenance_present"], dtype=np.bool_
        )
        modes = np.asarray(result["start_mode"]).astype(str)
        buckets = np.asarray(result["start_bucket"]).astype(str)
        archived = present & (modes == "archived_public_state")
        normal = present & (modes == "normal")
        legacy = ~present
        if bool(np.any(present & ~(archived | normal))):
            raise SystemExit(f"{path} has unknown restart start_mode")
        if bool(
            np.any(
                present
                & (
                    np.asarray(result["restart_select_seed"], dtype=np.int64)
                    != np.asarray(result["game_seed"], dtype=np.int64)
                )
            )
        ):
            raise SystemExit(
                f"{path} restart trajectory game_seed differs from "
                "restart_select_seed"
            )
        archived_seeds = np.asarray(result["archived_game_seed"], dtype=np.int64)
        archived_decisions = np.asarray(
            result["archived_decision_index"], dtype=np.int64
        )
        restart_select_seeds = np.asarray(
            result["restart_select_seed"], dtype=np.int64
        )
        if bool(
            np.any(
                legacy
                & (
                    (modes != "legacy_unknown")
                    | (buckets != "")
                    | (restart_select_seeds != -1)
                    | (archived_seeds != -1)
                    | (archived_decisions != -1)
                )
            )
        ):
            raise SystemExit(f"{path} has invalid legacy restart provenance")
        if bool(
            np.any(
                archived
                & (
                    (archived_seeds < 0)
                    | (archived_decisions < 0)
                    | (buckets == "")
                    | (buckets == "normal")
                )
            )
        ):
            raise SystemExit(f"{path} has invalid archived restart provenance")
        if bool(
            np.any(
                normal
                & (
                    (archived_seeds != -1)
                    | (archived_decisions != -1)
                    | (buckets != "normal")
                )
            )
        ):
            raise SystemExit(f"{path} has invalid normal-start provenance")
    else:
        result["restart_provenance_present"] = np.zeros(n, dtype=np.bool_)
        result["start_mode"] = np.full(n, "legacy_unknown")
        result["start_bucket"] = np.full(n, "")
        for key in RESTART_INT64_KEYS:
            result[key] = np.full(n, -1, dtype=np.int64)
    for key, dtype in ENTITY_FIELD_DTYPES.items():
        if key not in shard:
            continue
        value = np.asarray(shard[key])
        if value.shape[0] != n:
            raise SystemExit(
                f"{path} field {key} has {value.shape[0]} rows, expected {n}"
            )
        result[key] = value.astype(dtype, copy=False)
    return result


def _aux_subgoal_default_array(key: str, rows: int) -> np.ndarray:
    """Per-head ignore fill used when mixing legacy and CAT-100 shards."""

    dtype = AUX_SUBGOAL_FIELD_DTYPES[key]
    fill = -1 if key in {"aux_next_settlement", "aux_robber_target"} else np.nan
    return np.full(int(rows), fill, dtype=dtype)


def _field_or_default(
    shard,
    key: str,
    default: np.ndarray,
    path: Path,
    *,
    leading: int,
    width: int | None = None,
) -> np.ndarray:
    if key not in shard:
        return default
    value = np.asarray(shard[key])
    if value.shape[0] != leading:
        raise SystemExit(
            f"{path} field {key} has {value.shape[0]} rows, expected {leading}"
        )
    if width is not None and (value.ndim < 2 or value.shape[1] != width):
        raise SystemExit(
            f"{path} field {key} has shape {value.shape}, expected width {width}"
        )
    return value


def teacher_provenance_quality(data, *, chunk_rows: int = 262_144) -> dict:
    """Summarize opponent/source provenance without decoding a whole memmap."""

    n = int(len(data["action_taken"]))
    opponent_rows = 0
    verified_rows = 0
    opponent_tags: Counter[str] = Counter()
    source_categories: Counter[str] = Counter()
    step = max(1, int(chunk_rows))
    for start in range(0, n, step):
        stop = min(start + step, n)
        index = np.arange(start, stop, dtype=np.int64)
        present = (
            np.asarray(data["opponent_provenance_present"][index], dtype=np.bool_)
            if "opponent_provenance_present" in data
            else np.zeros(stop - start, dtype=np.bool_)
        )
        verified = (
            np.asarray(
                data["training_source_category_verified"][index], dtype=np.bool_
            )
            if "training_source_category_verified" in data
            else np.zeros(stop - start, dtype=np.bool_)
        )
        tags = (
            np.asarray(data["opponent_tag"][index]).astype(str)
            if "opponent_tag" in data
            else np.full(stop - start, "")
        )
        categories = (
            np.asarray(data["training_source_category"][index]).astype(str)
            if "training_source_category" in data
            else np.full(stop - start, "")
        )
        for name, value in (
            ("opponent_provenance_present", present),
            ("training_source_category_verified", verified),
            ("opponent_tag", tags),
            ("training_source_category", categories),
        ):
            if value.shape != (stop - start,):
                raise SystemExit(
                    f"{name} must be a row-aligned scalar column; got "
                    f"{value.shape} for rows [{start}, {stop})"
                )
        opponent_rows += int(np.sum(present))
        verified_rows += int(np.sum(verified))
        opponent_tags.update(tags[tags != ""].tolist())
        source_categories.update(categories[verified & (categories != "")].tolist())
    return {
        "opponent_provenance_rows": opponent_rows,
        "opponent_provenance_fraction": opponent_rows / max(n, 1),
        "opponent_tag_counts": dict(sorted(opponent_tags.items())),
        "training_source_category_verified_rows": verified_rows,
        "training_source_category_verified_fraction": verified_rows / max(n, 1),
        "training_source_category_counts": dict(sorted(source_categories.items())),
    }


def teacher_data_quality(
    data: dict,
    *,
    q_skip_teacher_prefixes: tuple[str, ...] = ("catanatron_ab",),
    soft_target_temperature: float = 0.7,
    soft_target_source: str = "policy",
    soft_target_min_legal_coverage: float = 0.5,
) -> dict:
    n = int(len(data["action_taken"]))
    legal_action_ids = data["legal_action_ids"]
    legal_counts = _legal_action_counts(legal_action_ids)
    legal = np.asarray(legal_action_ids)
    target_policy = np.asarray(data.get("target_policy", np.zeros((n, 0))), dtype=np.float32)
    target_scores = np.asarray(data.get("target_scores", np.full((n, 0), np.nan)), dtype=np.float32)
    legal_mask = legal >= 0
    target_policy_mask = np.asarray(
        data.get("target_policy_mask", np.where(np.isfinite(target_policy), target_policy, 0.0) > 0.0),
        dtype=np.bool_,
    )
    target_scores_mask = np.asarray(
        data.get("target_scores_mask", np.isfinite(target_scores)),
        dtype=np.bool_,
    )
    finite_scores = legal_mask & target_scores_mask & np.isfinite(target_scores)
    positive_policy = legal_mask & target_policy_mask & (
        np.where(np.isfinite(target_policy), target_policy, 0.0) > 0.0
    )
    policy_rows = np.sum(positive_policy.any(axis=1))
    score_rows = np.sum(finite_scores.any(axis=1))
    legal_denominator = np.maximum(legal_counts, 1)
    score_coverage = np.sum(finite_scores, axis=1) / legal_denominator
    policy_coverage = np.sum(positive_policy, axis=1) / legal_denominator
    q_score_rows_ge2 = _q_score_rows_ge2(data, np.arange(n, dtype=np.int64))
    usable_q_score_rows_ge2 = _q_score_rows_ge2(
        data,
        np.arange(n, dtype=np.int64),
        q_skip_teacher_prefixes=q_skip_teacher_prefixes,
    )
    winners = np.asarray(data.get("winner", np.full(n, ""))).astype(str)
    truncated = np.asarray(data.get("truncated", np.zeros(n, dtype=np.bool_)), dtype=np.bool_)
    has_final_vps = np.asarray(
        data.get("has_final_public_vps", np.zeros(n, dtype=np.bool_)),
        dtype=np.bool_,
    )
    has_actual_vps = np.asarray(
        data.get("has_final_actual_vps", np.zeros(n, dtype=np.bool_)),
        dtype=np.bool_,
    )
    teachers = np.asarray(data.get("teacher_name", np.full(n, ""))).astype(str)
    phases = np.asarray(data.get("phase", np.full(n, ""))).astype(str)
    score_sources = np.asarray(data.get("target_score_source", np.full(n, ""))).astype(str)
    policy_multiplier = np.asarray(
        data.get("policy_weight_multiplier", np.ones(n, dtype=np.float32)),
        dtype=np.float32,
    )
    value_multiplier = np.asarray(
        data.get("value_weight_multiplier", np.ones(n, dtype=np.float32)),
        dtype=np.float32,
    )
    policy_active = policy_multiplier > 0.0
    value_active = value_multiplier > 0.0
    soft_payload = _soft_target_array(
        data,
        np.arange(n, dtype=np.int64),
        soft_target_temperature,
        soft_target_source,
    )
    if soft_payload is None:
        effective_soft_distillation = np.zeros(n, dtype=bool)
    else:
        effective_soft_distillation = _has_distillation_distribution(
            soft_payload[0],
            soft_payload[1],
            legal_action_ids=legal,
            min_legal_coverage=soft_target_min_legal_coverage,
        )
    unflagged_actual_vp_rows = _unflagged_vp_rows(data, "final_actual_vps", "has_final_actual_vps")
    unflagged_public_vp_rows = _unflagged_vp_rows(data, "final_public_vps", "has_final_public_vps")
    matches = legal == data["action_taken"][:, None]
    selected_action_has_score = np.any(matches & finite_scores, axis=1)
    soft_scores = np.any(finite_scores, axis=1)
    soft_policy = np.any(positive_policy, axis=1)
    ab_root_scores = (score_sources == "ab_root") & soft_scores
    invalid = int(np.sum(~np.any(matches, axis=1)))
    policy_active_count = int(np.sum(policy_active))
    value_active_count = int(np.sum(value_active))
    q_rows_ge2 = np.sum(finite_scores, axis=1) >= 2
    usable_finite_scores = finite_scores.copy()
    skip_rows = _q_skip_rows_for_arrays(
        teachers,
        score_sources,
        q_skip_teacher_prefixes,
    )
    if np.any(skip_rows):
        usable_finite_scores[skip_rows] = False
    usable_q_rows_ge2 = np.sum(usable_finite_scores, axis=1) >= 2
    q_score_rows_ge2 = int(np.sum(q_rows_ge2))
    usable_q_score_rows_ge2 = int(np.sum(usable_q_rows_ge2))
    return {
        "samples": n,
        **teacher_provenance_quality(data),
        "soft_policy_rows": int(policy_rows),
        "soft_policy_fraction": float(policy_rows / max(n, 1)),
        "soft_score_rows": int(score_rows),
        "soft_score_fraction": float(score_rows / max(n, 1)),
        "policy_active_soft_policy_fraction": (
            float(np.sum(policy_active & soft_policy) / max(policy_active_count, 1))
        ),
        "policy_active_soft_score_fraction": (
            float(np.sum(policy_active & soft_scores) / max(policy_active_count, 1))
        ),
        "soft_score_legal_coverage_mean": float(np.mean(score_coverage)) if n else 0.0,
        "soft_score_legal_coverage_p50": float(np.percentile(score_coverage, 50)) if n else 0.0,
        "soft_policy_legal_coverage_mean": float(np.mean(policy_coverage)) if n else 0.0,
        "soft_policy_legal_coverage_p50": float(np.percentile(policy_coverage, 50)) if n else 0.0,
        "effective_soft_distillation_rows": int(np.sum(effective_soft_distillation)),
        "effective_soft_distillation_fraction": (
            float(np.mean(effective_soft_distillation)) if n else 0.0
        ),
        "policy_active_effective_soft_distillation_rows": int(
            np.sum(policy_active & effective_soft_distillation)
        ),
        "policy_active_effective_soft_distillation_fraction": (
            float(np.sum(policy_active & effective_soft_distillation) / max(policy_active_count, 1))
        ),
        "soft_target_min_legal_coverage": float(soft_target_min_legal_coverage),
        "selected_action_score_fraction": (
            float(np.mean(selected_action_has_score)) if n else 0.0
        ),
        "q_score_rows_ge2": int(q_score_rows_ge2),
        "q_score_rows_ge2_fraction": float(q_score_rows_ge2 / max(n, 1)),
        "usable_q_score_rows_ge2": int(usable_q_score_rows_ge2),
        "usable_q_score_rows_ge2_fraction": float(usable_q_score_rows_ge2 / max(n, 1)),
        "q_score_rows_ge2_policy_active_fraction": (
            float(np.sum(policy_active & q_rows_ge2) / max(policy_active_count, 1))
        ),
        "usable_q_score_rows_ge2_policy_active_fraction": (
            float(np.sum(policy_active & usable_q_rows_ge2) / max(policy_active_count, 1))
        ),
        "q_skip_teacher_prefixes": list(q_skip_teacher_prefixes),
        "outcome_rows": int(np.sum(winners != "")),
        "outcome_fraction": float(np.mean(winners != "")) if n else 0.0,
        "clean_terminal_outcome_rows": int(np.sum((winners != "") & ~truncated)),
        "clean_terminal_outcome_fraction": (
            float(np.mean((winners != "") & ~truncated)) if n else 0.0
        ),
        "final_public_vp_rows": int(np.sum(has_final_vps)),
        "final_public_vp_fraction": float(np.mean(has_final_vps)) if n else 0.0,
        "final_actual_vp_rows": int(np.sum(has_actual_vps)),
        "final_actual_vp_fraction": float(np.mean(has_actual_vps)) if n else 0.0,
        "unflagged_final_actual_vp_rows": int(np.sum(unflagged_actual_vp_rows)),
        "unflagged_final_public_vp_rows": int(np.sum(unflagged_public_vp_rows)),
        "truncated_rows": int(np.sum(truncated)),
        "truncated_fraction": float(np.mean(truncated)) if n else 0.0,
        "forced_action_rows": int(np.sum(legal_counts == 1)),
        "forced_action_fraction": float(np.mean(legal_counts == 1)) if n else 0.0,
        "policy_weight_zero_rows": int(np.sum(policy_multiplier <= 0.0)),
        "policy_weight_zero_fraction": float(np.mean(policy_multiplier <= 0.0)) if n else 0.0,
        "value_weight_zero_rows": int(np.sum(value_multiplier <= 0.0)),
        "value_weight_zero_fraction": float(np.mean(value_multiplier <= 0.0)) if n else 0.0,
        "policy_active_rows": policy_active_count,
        "policy_active_fraction": float(policy_active_count / max(n, 1)),
        "value_active_rows": value_active_count,
        "value_active_fraction": float(value_active_count / max(n, 1)),
        "policy_effective_forced_action_fraction": (
            float(np.sum(policy_active & (legal_counts == 1))) / float(max(policy_active_count, 1))
        ),
        "policy_effective_roll_fraction": (
            float(np.sum(policy_active & (phases == "roll"))) / float(max(policy_active_count, 1))
        ),
        "invalid_teacher_actions": invalid,
        "legal_actions_mean": float(np.mean(legal_counts)) if n else 0.0,
        "legal_actions_p90": int(np.percentile(legal_counts, 90)) if n else 0,
        "legal_actions_max": int(np.max(legal_counts)) if n else 0,
        "teacher_counts": _string_counts(teachers),
        "phase_counts": _string_counts(phases),
        "target_score_source_counts": _string_counts(
            np.where(score_sources == "", "none", score_sources)
        ),
        "ab_root_score_rows": int(np.sum((score_sources == "ab_root") & np.isfinite(target_scores).any(axis=1))),
        "ab_root_score_fraction": float(
            np.mean((score_sources == "ab_root") & np.isfinite(target_scores).any(axis=1))
        )
        if n
        else 0.0,
        "policy_active_ab_root_score_fraction": (
            float(np.sum(policy_active & ab_root_scores) / max(policy_active_count, 1))
        ),
        "action_mask_version_counts": _string_column_counts(
            data.get("action_mask_version"), rows=n
        ),
        "adapter_version_counts": _string_column_counts(
            data.get("adapter_version"), rows=n
        ),
        "by_teacher": _quality_by_field(
            data,
            "teacher_name",
            q_skip_teacher_prefixes=q_skip_teacher_prefixes,
            soft_target_temperature=soft_target_temperature,
            soft_target_source=soft_target_source,
            soft_target_min_legal_coverage=soft_target_min_legal_coverage,
            effective_soft_distillation=effective_soft_distillation,
        ),
        "by_phase": _quality_by_field(
            data,
            "phase",
            q_skip_teacher_prefixes=q_skip_teacher_prefixes,
            soft_target_temperature=soft_target_temperature,
            soft_target_source=soft_target_source,
            soft_target_min_legal_coverage=soft_target_min_legal_coverage,
            effective_soft_distillation=effective_soft_distillation,
        ),
        "by_teacher_phase": _quality_by_fields(
            data,
            ("teacher_name", "phase"),
            q_skip_teacher_prefixes=q_skip_teacher_prefixes,
            soft_target_temperature=soft_target_temperature,
            soft_target_source=soft_target_source,
            soft_target_min_legal_coverage=soft_target_min_legal_coverage,
            effective_soft_distillation=effective_soft_distillation,
        ),
    }


def sample_weight_quality(data: dict, weights: np.ndarray) -> dict:
    weights = np.asarray(weights, dtype=np.float64)
    if weights.size == 0:
        return {
            "mean": 0.0,
            "min": 0.0,
            "max": 0.0,
            "effective_sample_size": 0.0,
            "effective_sample_fraction": 0.0,
            "positive_sample_count": 0,
            "positive_sample_fraction": 0.0,
            "positive_effective_sample_size": 0.0,
            "positive_effective_sample_fraction": 0.0,
            "by_teacher": {},
            "by_phase": {},
        }
    denom = float(np.sum(weights * weights))
    effective = float(np.sum(weights) ** 2 / denom) if denom > 0.0 else 0.0
    positive = weights[weights > 0.0]
    positive_denom = float(np.sum(positive * positive))
    positive_effective = (
        float(np.sum(positive) ** 2 / positive_denom) if positive_denom > 0.0 else 0.0
    )
    return {
        "mean": float(np.mean(weights)),
        "min": float(np.min(weights)),
        "max": float(np.max(weights)),
        "effective_sample_size": effective,
        "effective_sample_fraction": effective / float(len(weights)),
        # Sparse self-play policy supervision deliberately assigns zero weight to
        # forced and fast-search rows.  The all-row ESS fraction therefore mostly
        # measures target coverage, not variance among examples that actually
        # enter the loss.  Report both factors so an n128/n256 run cannot mistake
        # 12% policy coverage for a 12%-efficient importance-weighting scheme.
        "positive_sample_count": int(positive.size),
        "positive_sample_fraction": float(positive.size / len(weights)),
        "positive_effective_sample_size": positive_effective,
        "positive_effective_sample_fraction": (
            positive_effective / float(positive.size) if positive.size else 0.0
        ),
        "by_teacher": _weight_by_field(data, weights, "teacher_name"),
        "by_phase": _weight_by_field(data, weights, "phase"),
    }


def per_game_weight_quality(data: dict, weights: np.ndarray) -> dict:
    """Report raw and sampler-adjusted per-game loss-weight mass."""

    n = len(weights)
    if n == 0:
        return {
            "n_games": 0,
            "rows_per_game": {},
            "total_weight_per_game": {},
            "sampler_adjusted_weight_per_game": {},
        }
    seeds = np.asarray(data.get("game_seed", np.arange(n, dtype=np.int64)), dtype=np.int64)
    weight_array = np.asarray(weights)
    # Production memmaps are written game-by-game, so every game's rows form
    # one contiguous run.  Exploit that layout before falling back to the fully
    # general factorisation.  ``np.unique(..., return_inverse=True)`` allocates
    # an int64 inverse for every row (about 363 MiB at 47.6M rows) and sorts all
    # of those rows merely to produce four scalar diagnostics.  The run path
    # allocates one boundary per game and remains exact for arbitrary seed
    # ordering.  A repeated non-contiguous seed is detected and takes the old
    # path, so this is not an assumption hidden in the report.
    boundaries = np.flatnonzero(seeds[1:] != seeds[:-1]) + 1
    component_offsets = _validated_component_offsets(data, n)
    if component_offsets is not None:
        # A seed identifies a game only inside one composite component.  Different
        # generation arms may intentionally reuse the same numeric seed; treating
        # those rows as one game corrupts both this diagnostic and the normalization
        # performed by _normalize_weights_per_game.  Component boundaries are
        # already contiguous, so add them without materialising a per-row component
        # id array (hundreds of MiB at A1 scale).
        boundaries = np.union1d(boundaries, component_offsets[1:-1])
    starts = np.concatenate((np.asarray([0], dtype=np.int64), boundaries))
    run_seeds = seeds[starts]
    run_components = (
        np.searchsorted(component_offsets[1:], starts, side="right")
        if component_offsets is not None
        else np.zeros(len(starts), dtype=np.int64)
    )
    run_keys = np.rec.fromarrays((run_components, run_seeds), names=("component", "seed"))
    if len(np.unique(run_keys)) == len(run_keys):
        counts = np.diff(
            np.concatenate((starts, np.asarray([n], dtype=np.int64)))
        )
        # Accumulate as float64 without first materialising a float64 copy of
        # the whole row vector (another ~363 MiB at production scale).
        totals = np.add.reduceat(weight_array, starts, dtype=np.float64)
        unique_seed_count = len(run_seeds)
    else:
        counts_parts: list[np.ndarray] = []
        totals_parts: list[np.ndarray] = []
        for start, stop in _component_row_ranges(component_offsets, n):
            _unique, inverse, component_counts = np.unique(
                seeds[start:stop], return_inverse=True, return_counts=True
            )
            component_totals = np.zeros(len(_unique), dtype=np.float64)
            np.add.at(
                component_totals,
                inverse,
                np.asarray(weight_array[start:stop], dtype=np.float64),
            )
            counts_parts.append(component_counts)
            totals_parts.append(component_totals)
        counts = np.concatenate(counts_parts)
        totals = np.concatenate(totals_parts)
        unique_seed_count = len(counts)
    game_uniform_sampler = bool(
        tuple(getattr(data, "component_game_sampling_ratios", tuple()))
    )
    # With uniform-row sampling, summed weight is the game's objective mass.
    # Composite-v2 first samples a game and then a row, so mean in-game weight
    # is the corresponding mass. Reporting only totals previously made a
    # correct flag-off v2 run look length-biased and invited double correction.
    adjusted = totals / counts if game_uniform_sampler else totals
    return {
        "n_games": int(unique_seed_count),
        "sampling_measure": (
            "component_then_uniform_game_then_uniform_row"
            if game_uniform_sampler
            else "uniform_row"
        ),
        "rows_per_game": {
            "min": int(counts.min()),
            "max": int(counts.max()),
            "mean": float(counts.mean()),
        },
        "total_weight_per_game": {
            "min": float(totals.min()),
            "max": float(totals.max()),
            "mean": float(totals.mean()),
            "std": float(totals.std()),
        },
        "sampler_adjusted_weight_per_game": {
            "min": float(adjusted.min()),
            "max": float(adjusted.max()),
            "mean": float(adjusted.mean()),
            "std": float(adjusted.std()),
        },
    }


def validate_teacher_data_schema(policy, data: dict, data_quality: dict, env_config) -> None:
    config = getattr(policy, "config", None)
    action_size = int(getattr(policy, "action_size", getattr(config, "action_size", 0)))
    observation_size = int(getattr(config, "observation_size", 0))
    context_size = int(
        getattr(
            policy,
            "context_action_feature_size",
            getattr(config, "context_action_feature_size", 0),
        )
    )
    # obs / context / entity-token columns are checked for shape only, so read
    # them without np.asarray -- a MemmapCorpus streams these lazily and
    # materialising the full column here would defeat the streaming loader.
    obs = data["obs"]
    legal = np.asarray(data["legal_action_ids"])
    context = data["legal_action_context"]
    actions = np.asarray(data["action_taken"])
    problems: list[str] = []
    if observation_size and obs.ndim == 2 and int(obs.shape[1]) != observation_size:
        problems.append(
            f"obs width {obs.shape[1]} != checkpoint observation_size {observation_size}"
        )
    if legal.ndim != 2:
        problems.append(f"legal_action_ids must be rank 2, got {legal.shape}")
    else:
        duplicate_rows = _duplicate_legal_action_rows(legal)
        if duplicate_rows.size:
            preview = ", ".join(str(int(row)) for row in duplicate_rows[:5])
            problems.append(
                "duplicate legal action ids in rows "
                f"{preview}; each legal_action_ids row must be unique"
            )
    if context.ndim != 3:
        problems.append(f"legal_action_context must be rank 3, got {context.shape}")
    elif context_size and int(context.shape[2]) != context_size:
        problems.append(
            f"legal_action_context width {context.shape[2]} != checkpoint context size {context_size}"
        )
    if getattr(policy, "policy_type", "") == "entity_graph":
        missing_entity = [key for key in ENTITY_BATCH_KEYS if key not in data]
        if missing_entity:
            problems.append(
                "entity_graph requires converted entity-token fields; "
                f"missing {missing_entity[:8]}{'...' if len(missing_entity) > 8 else ''}"
            )
        else:
            entity_shapes = {
                "hex_tokens": (3, 19, HEX_FEATURE_SIZE),
                "vertex_tokens": (3, 54, VERTEX_FEATURE_SIZE),
                "edge_tokens": (3, 72, EDGE_FEATURE_SIZE),
                "player_tokens": (3, None, PLAYER_FEATURE_SIZE),
                "global_tokens": (3, 1, GLOBAL_FEATURE_SIZE),
                "legal_action_tokens": (3, legal.shape[1] if legal.ndim == 2 else None, None),
                "event_tokens": (3, None, EVENT_FEATURE_SIZE),
            }
            feature_sizes = {
                "legal_action_tokens": int(getattr(config, "legal_action_feature_size", 0) or 0),
            }
            for key, expected in entity_shapes.items():
                value = data[key]  # shape-only checks; keep lazy columns unmaterialised
                if value.ndim != expected[0]:
                    problems.append(f"{key} must be rank {expected[0]}, got {value.shape}")
                    continue
                if expected[1] is not None and int(value.shape[1]) != int(expected[1]):
                    problems.append(
                        f"{key} dim1 {value.shape[1]} != expected {expected[1]}"
                    )
                expected_width = feature_sizes.get(key)
                if expected_width is None:
                    expected_width = expected[2]
                if expected_width and int(value.shape[2]) != int(expected_width):
                    problems.append(
                        f"{key} width {value.shape[2]} != checkpoint width {expected_width}"
                    )
            for key in (
                "hex_mask",
                "vertex_mask",
                "edge_mask",
                "player_mask",
                "legal_action_mask",
                "event_mask",
            ):
                value = data[key]  # shape-only checks; keep lazy columns unmaterialised
                if value.ndim != 2 or value.shape[0] != len(actions):
                    problems.append(f"{key} must be rank 2 with {len(actions)} rows, got {value.shape}")
            if (
                legal.ndim == 2
                and "legal_action_tokens" in data
                and "legal_action_mask" in data
                and data["legal_action_tokens"].shape[1] != legal.shape[1]
            ):
                problems.append(
                    "legal_action_tokens candidate width must match legal_action_ids width"
                )
    if action_size:
        valid_legal = legal[legal >= 0]
        if valid_legal.size and int(np.max(valid_legal)) >= action_size:
            problems.append(
                f"legal action id max {int(np.max(valid_legal))} >= checkpoint action_size {action_size}"
            )
        if actions.size and (int(np.min(actions)) < 0 or int(np.max(actions)) >= action_size):
            problems.append(
                f"action_taken range [{int(np.min(actions))}, {int(np.max(actions))}] "
                f"is outside checkpoint action_size {action_size}"
            )
    if int(data_quality.get("invalid_teacher_actions", 0)) != 0:
        problems.append(
            f"invalid_teacher_actions={int(data_quality['invalid_teacher_actions'])}; "
            "teacher action must be present in legal_action_ids"
        )
    version_column = data.get("action_mask_version")
    present_versions = _string_column_present_values(
        version_column, rows=len(actions)
    )
    nonempty_versions = sorted(version for version in present_versions if version)
    has_empty_version = "" in present_versions
    if nonempty_versions and has_empty_version:
        problems.append(
            "mixed known and unknown action_mask_version values; regenerate or curate "
            "old shards instead of mixing empty-version rows with versioned rows"
        )
    if not nonempty_versions and len(actions) >= 1000:
        problems.append(
            "missing action_mask_version for a production-sized teacher dataset; "
            "regenerate or curate shards with current action catalog provenance"
        )
    if len(nonempty_versions) > 1:
        problems.append(f"mixed action_mask_version values: {nonempty_versions}")
    expected_version = _expected_action_mask_version(env_config)
    checkpoint_version = str(getattr(config, "action_mask_version", "") or "")
    if expected_version and checkpoint_version and checkpoint_version != expected_version:
        problems.append(
            f"checkpoint action_mask_version {checkpoint_version!r} does not match "
            f"current env action_mask_version {expected_version!r}"
        )
    if expected_version and nonempty_versions and nonempty_versions != [expected_version]:
        problems.append(
            f"teacher action_mask_version {nonempty_versions} does not match current "
            f"env action_mask_version {expected_version!r}"
        )
    adapter_versions = _string_column_present_values(
        data.get("adapter_version"), rows=len(actions)
    )
    nonempty_adapters = sorted(version for version in adapter_versions if version)
    has_empty_adapter = "" in adapter_versions
    if nonempty_adapters and has_empty_adapter:
        problems.append(
            "mixed known and unknown adapter_version values; regenerate or curate "
            "legacy shards instead of mixing feature semantics"
        )
    if len(nonempty_adapters) > 1:
        problems.append(f"mixed adapter_version values: {nonempty_adapters}")
    if nonempty_adapters == [RUST_ENTITY_ADAPTER_V6]:
        if "player_tokens" not in data:
            problems.append(
                "adapter-v6 dataset is missing player_tokens required for "
                "actor-resource admission"
            )
        elif "actor_resource_counts" not in data:
            problems.append(
                "adapter-v6 dataset is missing authoritative actor_resource_counts; "
                "regenerate current-v6 rows instead of trusting a circular feature-only check"
            )
        else:
            invalid_resource_rows, checked_resource_rows = (
                v6_actor_resource_identity_violations(
                    data["player_tokens"],
                    actor_resource_counts=data["actor_resource_counts"],
                )
            )
            if checked_resource_rows != len(actions):
                problems.append(
                    "adapter-v6 actor-resource admission could not inspect every row: "
                    f"checked={checked_resource_rows} expected={len(actions)}"
                )
            elif invalid_resource_rows:
                problems.append(
                    "adapter-v6 actor-resource identity failed after physical-scale "
                    "decoding: actor total slot 6 must equal sum slots 16:21 and "
                    "match authoritative actor_resource_counts; "
                    f"invalid_rows={invalid_resource_rows}/{checked_resource_rows}"
                )
    checkpoint_adapter_version = (
        policy_entity_feature_adapter_version(policy)
        if getattr(policy, "policy_type", "") == "entity_graph"
        else ""
    )
    if (
        checkpoint_adapter_version
        in {
            CURRENT_RUST_ENTITY_ADAPTER_VERSION,
            RUST_ENTITY_ADAPTER_V4,
            RUST_ENTITY_ADAPTER_V5,
            RUST_ENTITY_ADAPTER_V6,
        }
        and not nonempty_adapters
        and len(actions) >= 1000
    ):
        problems.append(
            "missing adapter_version for a production-sized teacher dataset while "
            f"the checkpoint uses current entity adapter {checkpoint_adapter_version!r}; "
            "regenerate current-adapter rows or curate/backfill authenticated adapter "
            "provenance instead of training current semantics on legacy-unknown features"
        )
    if (
        checkpoint_adapter_version
        and nonempty_adapters
        and nonempty_adapters != [checkpoint_adapter_version]
    ):
        problems.append(
            f"teacher adapter_version {nonempty_adapters} does not match checkpoint "
            f"entity adapter {checkpoint_adapter_version!r}"
        )
    expected_static_hash = _expected_static_action_features_sha256(env_config)
    checkpoint_static_hash = _policy_static_action_features_sha256(policy)
    if (
        expected_static_hash
        and checkpoint_static_hash
        and checkpoint_static_hash != expected_static_hash
    ):
        problems.append(
            "checkpoint static_action_features_sha256 does not match current "
            f"env action features: checkpoint={checkpoint_static_hash} "
            f"current={expected_static_hash}"
        )
    if problems:
        raise SystemExit("teacher data schema validation failed: " + "; ".join(problems))


def _expected_action_mask_version(env_config) -> str:
    from catan_zero.rl.multiagent_env import ColonistMultiAgentEnv

    env = ColonistMultiAgentEnv(env_config)
    try:
        _, info = env.reset(seed=0)
        return str(info.get("action_mask_version", ""))
    finally:
        env.close()


def _action_catalog_for_env_config(env_config):
    """Return the exact catalog used by the configured training environment."""

    from catan_zero.rl.multiagent_env import ColonistMultiAgentEnv

    env = ColonistMultiAgentEnv(env_config)
    try:
        return env.action_catalog
    finally:
        env.close()


def _expected_static_action_features_sha256(env_config) -> str:
    from catan_zero.rl.multiagent_env import ColonistMultiAgentEnv

    env = ColonistMultiAgentEnv(env_config)
    try:
        env.reset(seed=0)
        return _array_sha256(build_action_feature_table(env))
    finally:
        env.close()


def _policy_static_action_features_sha256(policy) -> str:
    static = getattr(policy, "static_action_features", None)
    if static is None:
        static = getattr(policy, "action_features", None)
    if static is None:
        return ""
    if hasattr(static, "detach"):
        static = static.detach().cpu().numpy()
    return _array_sha256(np.asarray(static, dtype=np.float32))


def _quality_by_field(
    data: dict,
    field: str,
    *,
    limit: int = 40,
    q_skip_teacher_prefixes: tuple[str, ...] = (),
    soft_target_temperature: float = 0.7,
    soft_target_source: str = "policy",
    soft_target_min_legal_coverage: float = 0.5,
    effective_soft_distillation: np.ndarray | None = None,
) -> dict[str, dict]:
    n = int(len(data["action_taken"]))
    values = np.asarray(data.get(field, np.full(n, ""))).astype(str)
    result = {}
    for key in _top_group_keys(values, limit=limit):
        mask = values == key
        result[str(key)] = _quality_for_mask(
            data,
            mask,
            q_skip_teacher_prefixes=q_skip_teacher_prefixes,
            soft_target_temperature=soft_target_temperature,
            soft_target_source=soft_target_source,
            soft_target_min_legal_coverage=soft_target_min_legal_coverage,
            effective_soft_distillation=effective_soft_distillation,
        )
    return result


def _quality_by_fields(
    data: dict,
    fields: tuple[str, ...],
    *,
    limit: int = 80,
    q_skip_teacher_prefixes: tuple[str, ...] = (),
    soft_target_temperature: float = 0.7,
    soft_target_source: str = "policy",
    soft_target_min_legal_coverage: float = 0.5,
    effective_soft_distillation: np.ndarray | None = None,
) -> dict[str, dict]:
    n = int(len(data["action_taken"]))
    columns = [
        np.asarray(data.get(field, np.full(n, ""))).astype(str)
        for field in fields
    ]
    keys = np.asarray(["|".join(parts) for parts in zip(*columns, strict=False)])
    result = {}
    for key in _top_group_keys(keys, limit=limit):
        mask = keys == key
        result[str(key)] = _quality_for_mask(
            data,
            mask,
            q_skip_teacher_prefixes=q_skip_teacher_prefixes,
            soft_target_temperature=soft_target_temperature,
            soft_target_source=soft_target_source,
            soft_target_min_legal_coverage=soft_target_min_legal_coverage,
            effective_soft_distillation=effective_soft_distillation,
        )
    return result


def _quality_for_mask(
    data: dict,
    mask: np.ndarray,
    *,
    q_skip_teacher_prefixes: tuple[str, ...] = (),
    soft_target_temperature: float = 0.7,
    soft_target_source: str = "policy",
    soft_target_min_legal_coverage: float = 0.5,
    effective_soft_distillation: np.ndarray | None = None,
) -> dict:
    mask = np.asarray(mask, dtype=bool)
    n = int(np.sum(mask))
    if n == 0:
        return {}
    legal = data["legal_action_ids"][mask]
    actions = data["action_taken"][mask]
    legal_counts = np.sum(legal >= 0, axis=1)
    target_policy = np.asarray(data.get("target_policy", np.zeros((len(data["action_taken"]), 0)))[mask], dtype=np.float32)
    target_scores = np.asarray(data.get("target_scores", np.full((len(data["action_taken"]), 0), np.nan))[mask], dtype=np.float32)
    teachers = np.asarray(data.get("teacher_name", np.full(len(data["action_taken"]), "")))[mask].astype(str)
    score_sources = np.asarray(
        data.get("target_score_source", np.full(len(data["action_taken"]), ""))
    )[mask].astype(str)
    winners = np.asarray(data.get("winner", np.full(len(data["action_taken"]), "")))[mask].astype(str)
    players = np.asarray(data.get("player", np.full(len(data["action_taken"]), "")))[mask].astype(str)
    truncated = np.asarray(data.get("truncated", np.zeros(len(data["action_taken"]), dtype=np.bool_)))[mask].astype(bool)
    phases = np.asarray(data.get("phase", np.full(len(data["action_taken"]), "")))[mask].astype(str)
    policy_multiplier = np.asarray(
        data.get("policy_weight_multiplier", np.ones(len(data["action_taken"]), dtype=np.float32))
    )[mask].astype(np.float32)
    value_multiplier = np.asarray(
        data.get("value_weight_multiplier", np.ones(len(data["action_taken"]), dtype=np.float32))
    )[mask].astype(np.float32)
    policy_active = policy_multiplier > 0.0
    value_active = value_multiplier > 0.0
    if effective_soft_distillation is not None:
        effective_soft_distillation_masked = np.asarray(
            effective_soft_distillation,
            dtype=bool,
        )[mask]
    else:
        batch = np.flatnonzero(mask).astype(np.int64)
        soft_payload = _soft_target_array(
            data,
            batch,
            soft_target_temperature,
            soft_target_source,
        )
        if soft_payload is None:
            effective_soft_distillation_masked = np.zeros(n, dtype=bool)
        else:
            effective_soft_distillation_masked = _has_distillation_distribution(
                soft_payload[0],
                soft_payload[1],
                legal_action_ids=legal,
                min_legal_coverage=soft_target_min_legal_coverage,
            )
    has_final_vps = np.asarray(
        data.get("has_final_public_vps", np.zeros(len(data["action_taken"]), dtype=np.bool_))
    )[mask].astype(bool)
    has_actual_vps = np.asarray(
        data.get("has_final_actual_vps", np.zeros(len(data["action_taken"]), dtype=np.bool_))
    )[mask].astype(bool)
    matches = legal == actions[:, None]
    target_policy_mask_all = np.asarray(
        data.get(
            "target_policy_mask",
            np.where(
                np.isfinite(data.get("target_policy", np.zeros((len(data["action_taken"]), 0)))),
                data.get("target_policy", np.zeros((len(data["action_taken"]), 0))),
                0.0,
            )
            > 0.0,
        ),
        dtype=np.bool_,
    )
    target_scores_all = data.get(
        "target_scores",
        np.full((len(data["action_taken"]), 0), np.nan),
    )
    target_scores_mask_all = np.asarray(
        data.get("target_scores_mask", np.isfinite(target_scores_all)),
        dtype=np.bool_,
    )
    target_policy_mask = np.asarray(
        target_policy_mask_all,
        dtype=np.bool_,
    )[mask]
    target_scores_mask = np.asarray(
        target_scores_mask_all,
        dtype=np.bool_,
    )[mask]
    finite_scores = (legal >= 0) & target_scores_mask & np.isfinite(target_scores)
    positive_policy = (legal >= 0) & target_policy_mask & (
        np.where(np.isfinite(target_policy), target_policy, 0.0) > 0.0
    )
    soft_policy = np.any(positive_policy, axis=1)
    soft_scores = np.any(finite_scores, axis=1)
    ab_root_scores = (score_sources == "ab_root") & soft_scores
    selected_action_has_score = np.any(matches & finite_scores, axis=1)
    legal_denominator = np.maximum(legal_counts, 1)
    score_coverage = np.sum(finite_scores, axis=1) / legal_denominator
    policy_coverage = np.sum(positive_policy, axis=1) / legal_denominator
    q_rows_ge2 = np.sum(finite_scores, axis=1) >= 2
    usable_finite_scores = finite_scores.copy()
    skip_rows = _q_skip_rows_for_arrays(
        teachers,
        score_sources,
        q_skip_teacher_prefixes,
    )
    if np.any(skip_rows):
        usable_finite_scores[skip_rows] = False
    usable_q_rows_ge2 = np.sum(usable_finite_scores, axis=1) >= 2
    clean_outcome = (winners != "") & ~truncated
    winner_rows = clean_outcome & (winners == players)
    policy_active_count = int(np.sum(policy_active))
    value_active_count = int(np.sum(value_active))
    return {
        "samples": n,
        "target_score_source_counts": _string_counts(
            np.where(score_sources == "", "none", score_sources)
        ),
        "ab_root_score_fraction": float(
            np.mean((score_sources == "ab_root") & soft_scores)
        ),
        "soft_policy_fraction": float(np.mean(soft_policy)),
        "soft_score_fraction": float(np.mean(soft_scores)),
        "policy_active_soft_policy_fraction": (
            float(np.sum(policy_active & soft_policy) / max(policy_active_count, 1))
        ),
        "policy_active_soft_score_fraction": (
            float(np.sum(policy_active & soft_scores) / max(policy_active_count, 1))
        ),
        "policy_active_ab_root_score_fraction": (
            float(np.sum(policy_active & ab_root_scores) / max(policy_active_count, 1))
        ),
        "soft_score_legal_coverage_mean": float(np.mean(score_coverage)),
        "soft_score_legal_coverage_p50": float(np.percentile(score_coverage, 50)),
        "soft_policy_legal_coverage_mean": float(np.mean(policy_coverage)),
        "soft_policy_legal_coverage_p50": float(np.percentile(policy_coverage, 50)),
        "effective_soft_distillation_fraction": float(np.mean(effective_soft_distillation_masked)),
        "policy_active_effective_soft_distillation_fraction": (
            float(np.sum(policy_active & effective_soft_distillation_masked) / max(policy_active_count, 1))
        ),
        "effective_soft_distillation_rows": int(np.sum(effective_soft_distillation_masked)),
        "policy_active_effective_soft_distillation_rows": int(
            np.sum(policy_active & effective_soft_distillation_masked)
        ),
        "selected_action_score_fraction": float(np.mean(selected_action_has_score)),
        "q_score_rows_ge2": int(np.sum(q_rows_ge2)),
        "q_score_rows_ge2_fraction": float(np.mean(q_rows_ge2)),
        "q_score_rows_ge2_policy_active_fraction": (
            float(np.sum(policy_active & q_rows_ge2) / max(policy_active_count, 1))
        ),
        "usable_q_score_rows_ge2": int(np.sum(usable_q_rows_ge2)),
        "usable_q_score_rows_ge2_fraction": float(np.mean(usable_q_rows_ge2)),
        "usable_q_score_rows_ge2_policy_active_fraction": (
            float(np.sum(policy_active & usable_q_rows_ge2) / max(policy_active_count, 1))
        ),
        "forced_action_fraction": float(np.mean(legal_counts == 1)),
        "policy_weight_zero_fraction": float(np.mean(policy_multiplier <= 0.0)),
        "value_weight_zero_fraction": float(np.mean(value_multiplier <= 0.0)),
        "policy_active_rows": policy_active_count,
        "policy_active_fraction": float(policy_active_count / max(n, 1)),
        "value_active_rows": value_active_count,
        "value_active_fraction": float(value_active_count / max(n, 1)),
        "policy_effective_forced_action_fraction": (
            float(np.sum(policy_active & (legal_counts == 1))) / float(max(policy_active_count, 1))
        ),
        "policy_effective_roll_fraction": (
            float(np.sum(policy_active & (phases == "roll"))) / float(max(policy_active_count, 1))
        ),
        "invalid_teacher_actions": int(np.sum(~np.any(matches, axis=1))),
        "truncated_fraction": float(np.mean(truncated)),
        "outcome_fraction": float(np.mean(winners != "")),
        "clean_terminal_outcome_fraction": float(np.mean(clean_outcome)),
        "final_public_vp_fraction": float(np.mean(has_final_vps)),
        "final_actual_vp_fraction": float(np.mean(has_actual_vps)),
        "winner_row_fraction": float(np.mean(winner_rows)) if np.any(clean_outcome) else 0.0,
        "legal_actions_mean": float(np.mean(legal_counts)),
        "legal_actions_p90": int(np.percentile(legal_counts, 90)),
    }


def _weight_by_field(
    data: dict,
    weights: np.ndarray,
    field: str,
    *,
    limit: int = 40,
) -> dict[str, dict]:
    n = int(len(data["action_taken"]))
    column = data.get(field)
    if isinstance(column, _MemmapCategoricalColumn) or bool(
        getattr(column, "supports_grouped_weights", False)
    ):
        return column.grouped_weights(weights, limit=limit)
    values = np.asarray(np.full(n, "") if column is None else column).astype(str)
    result = {}
    for key in _top_group_keys(values, limit=limit):
        mask = values == key
        raw_count = int(np.sum(mask))
        total = float(np.sum(weights[mask]))
        result[str(key)] = {
            "raw_samples": raw_count,
            "weight_sum": total,
            "mean_weight": total / max(raw_count, 1),
        }
    return result


def _top_group_keys(values: np.ndarray, *, limit: int) -> list[str]:
    if values.size == 0:
        return []
    unique, counts = np.unique(values.astype(str), return_counts=True)
    order = np.argsort(-counts)
    return [str(unique[index]) for index in order[:limit]]


def _string_counts(values: np.ndarray, *, limit: int = 20) -> dict[str, int]:
    if values.size == 0:
        return {}
    unique, counts = np.unique(values.astype(str), return_counts=True)
    order = np.argsort(-counts)
    return {
        str(unique[index]): int(counts[index])
        for index in order[:limit]
    }


def _string_column_counts(column, *, rows: int, limit: int = 20) -> dict[str, int]:
    """Count a string column without decoding a production memmap composite."""

    if column is None:
        return {"": int(rows)} if rows else {}
    value_counts = getattr(column, "value_counts", None)
    if callable(value_counts):
        counts = {
            str(value): int(count)
            for value, count in value_counts().items()
            if int(count) > 0
        }
        return dict(
            sorted(counts.items(), key=lambda item: (-item[1], item[0]))[:limit]
        )
    values = np.asarray(column).astype(str)
    if values.shape != (int(rows),):
        raise SystemExit(
            f"string provenance column must have shape ({int(rows)},), got {values.shape}"
        )
    return _string_counts(values, limit=limit)


def _string_column_present_values(column, *, rows: int) -> set[str]:
    """Return present labels while retaining lazy categorical memmap semantics."""

    if column is None:
        return {""} if rows else set()
    present_values = getattr(column, "present_values", None)
    if callable(present_values):
        return {str(value) for value in present_values()}
    value_counts = getattr(column, "value_counts", None)
    if callable(value_counts):
        return {
            str(value)
            for value, count in value_counts().items()
            if int(count) > 0
        }
    values = np.asarray(column).astype(str)
    if values.shape != (int(rows),):
        raise SystemExit(
            f"string provenance column must have shape ({int(rows)},), got {values.shape}"
        )
    return set(values.tolist())


def _load_npz(path: Path):
    if path.suffix == ".zst":
        try:
            import zstandard as zstd
        except ImportError as error:
            raise SystemExit("zstandard is required to read .npz.zst shards") from error
        data = zstd.ZstdDecompressor().decompress(path.read_bytes())
        return np.load(io.BytesIO(data), allow_pickle=False)
    return np.load(path, allow_pickle=False)






def _target_columns(legal_action_ids: np.ndarray, actions: np.ndarray) -> np.ndarray:
    duplicate_rows = _duplicate_legal_action_rows(legal_action_ids)
    if duplicate_rows.size:
        first = int(duplicate_rows[0])
        valid = legal_action_ids[first][legal_action_ids[first] >= 0]
        raise ValueError(
            "duplicate legal action ids in teacher row "
            f"{first}: {valid.astype(np.int64).tolist()}"
        )
    matches = legal_action_ids == actions[:, None]
    missing = ~np.any(matches, axis=1)
    if np.any(missing):
        first = int(np.flatnonzero(missing)[0])
        raise ValueError(
            f"teacher action {int(actions[first])} is not present in legal candidates"
        )
    return np.argmax(matches, axis=1).astype(np.int64, copy=False)


def _duplicate_legal_action_rows(legal_action_ids: np.ndarray) -> np.ndarray:
    """Vectorized (task #76 side-finding): the original per-row Python loop
    with a np.unique() call inside was O(n) Python-level overhead that got
    dramatically slower under real memory pressure on very large corpora
    (discovered as a multi-hour pre-training stall on a 14.4M-row corpus,
    task #65). Sort each row (padding sentinel -1 sorts first), then a
    duplicate is any adjacent-equal pair among the non-negative (real action
    id) entries -- two adjacent -1 padding slots are explicitly excluded, not
    real duplicates.
    """
    legal = np.asarray(legal_action_ids)
    if legal.ndim != 2 or legal.shape[1] < 2:
        return np.asarray([], dtype=np.int64)
    sorted_rows = np.sort(legal, axis=1)
    adjacent_equal = np.diff(sorted_rows, axis=1) == 0
    later_is_valid = sorted_rows[:, 1:] >= 0
    has_duplicate = np.any(adjacent_equal & later_is_valid, axis=1)
    return np.nonzero(has_duplicate)[0].astype(np.int64)


def _concat_padded(key: str, values: list[np.ndarray]) -> np.ndarray:
    if len(values) == 1:
        return values[0]
    if key in {
        "legal_action_ids",
        "target_policy",
        "prior_policy",
        "target_scores",
        "target_policy_mask",
        "target_scores_mask",
        "afterstate_target",
        "afterstate_target_mask",
        "legal_action_mask",
    }:
        if key == "legal_action_ids":
            fill = -1
        elif key in {"target_scores", "afterstate_target"}:
            fill = np.nan
        elif key in {
            "target_policy_mask",
            "target_scores_mask",
            "afterstate_target_mask",
            "legal_action_mask",
        }:
            fill = False
        else:
            fill = 0.0
        width = max(value.shape[1] for value in values)
        padded = []
        for value in values:
            if value.shape[1] == width:
                padded.append(value)
                continue
            out = np.full((value.shape[0], width), fill, dtype=value.dtype)
            out[:, : value.shape[1]] = value
            padded.append(out)
        return np.concatenate(padded, axis=0)
    if key == "legal_action_context":
        width = max(value.shape[1] for value in values)
        feature_size = max(value.shape[2] for value in values)
        padded = []
        for value in values:
            if value.shape[1] == width and value.shape[2] == feature_size:
                padded.append(value)
                continue
            out = np.zeros((value.shape[0], width, feature_size), dtype=value.dtype)
            out[:, : value.shape[1], : value.shape[2]] = value
            padded.append(out)
        return np.concatenate(padded, axis=0)
    if key in {"legal_action_tokens", "legal_action_target_ids"}:
        width = max(value.shape[1] for value in values)
        feature_size = max(value.shape[2] for value in values)
        fill = -1 if key == "legal_action_target_ids" else 0.0
        padded = []
        for value in values:
            if value.shape[1] == width and value.shape[2] == feature_size:
                padded.append(value)
                continue
            out = np.full((value.shape[0], width, feature_size), fill, dtype=value.dtype)
            out[:, : value.shape[1], : value.shape[2]] = value
            padded.append(out)
        return np.concatenate(padded, axis=0)
    return np.concatenate(values, axis=0)


def _soft_targets_legal(
    data: dict,
    batch: np.ndarray,
    device,
    temperature: float,
    source: str,
    min_legal_coverage: float = 0.0,
):
    import torch

    payload = _soft_target_array(data, batch, temperature, source)
    if payload is None:
        return None, None, None
    target, support = payload
    soft = torch.as_tensor(target, dtype=torch.float32, device=device)
    support_t = torch.as_tensor(support, dtype=torch.bool, device=device)
    has_soft = torch.as_tensor(
        _has_distillation_distribution(
            target,
            support,
            legal_action_ids=data["legal_action_ids"][batch],
            min_legal_coverage=min_legal_coverage,
        ),
        dtype=torch.bool,
        device=device,
    )
    return soft, has_soft, support_t


def _soft_targets_full(
    data: dict,
    batch: np.ndarray,
    action_size: int,
    device,
    temperature: float,
    source: str,
    min_legal_coverage: float = 0.0,
):
    import torch

    payload = _soft_target_array(data, batch, temperature, source)
    if payload is None:
        return None, None, None
    target, support = payload
    legal = data["legal_action_ids"][batch]
    has_soft_np = _has_distillation_distribution(
        target,
        support,
        legal_action_ids=legal,
        min_legal_coverage=min_legal_coverage,
    )
    dense = np.zeros((len(batch), action_size), dtype=np.float32)
    dense_support = np.zeros((len(batch), action_size), dtype=np.bool_)
    for row in range(len(batch)):
        keep = legal[row] >= 0
        dense[row, legal[row, keep].astype(np.int64)] = target[row, keep]
        dense_support[row, legal[row, keep].astype(np.int64)] = support[row, keep]
    soft = torch.as_tensor(dense, dtype=torch.float32, device=device)
    support_t = torch.as_tensor(dense_support, dtype=torch.bool, device=device)
    has_soft = torch.as_tensor(
        has_soft_np,
        dtype=torch.bool,
        device=device,
    )
    return soft, has_soft, support_t


def _batch_array_or_fill(
    data: dict,
    field: str,
    batch: np.ndarray,
    fill_value,
    *,
    dtype=None,
) -> np.ndarray:
    """Read one optional column without constructing a full-corpus default."""

    if field in data:
        return np.asarray(data[field][batch], dtype=dtype)
    return np.full(len(batch), fill_value, dtype=dtype)


def _stored_policy_temperatures_for_batch(
    data: object,
    batch: np.ndarray,
) -> np.ndarray | None:
    """Resolve authenticated per-component temperatures for stored policies.

    Component identity survives a no-copy memmap composite through
    ``component_indices_for_rows``.  Keeping calibration on that identity is
    important: n128, n256, and replay can all use the same ``teacher_name``
    while carrying materially different target entropies.  Ordinary corpora
    and v2 descriptors without this opt-in return ``None`` and preserve the
    historical path exactly.
    """

    if isinstance(data, dict) and "_stored_policy_temperature" in data:
        materialized = np.asarray(
            data["_stored_policy_temperature"][batch], dtype=np.float64
        )
        if materialized.shape != (len(batch),):
            raise ValueError("materialized stored-policy temperature shape drift")
        if not np.isfinite(materialized).all() or np.any(materialized <= 0.0):
            raise ValueError(
                "materialized stored-policy temperatures must be finite and > 0"
            )
        return materialized

    configured = getattr(data, "stored_policy_component_temperatures", None)
    if configured is None:
        return None
    component_ids = tuple(getattr(data, "component_ids", ()))
    component_lookup = getattr(data, "component_indices_for_rows", None)
    if (
        not component_ids
        or not callable(component_lookup)
        or not isinstance(configured, dict)
        or set(configured) != set(component_ids)
    ):
        raise ValueError("stored-policy component temperature binding is invalid")
    ordered = np.asarray(
        [float(configured[component_id]) for component_id in component_ids],
        dtype=np.float64,
    )
    if not np.isfinite(ordered).all() or np.any(ordered <= 0.0):
        raise ValueError("stored-policy component temperatures must be finite and > 0")
    components = np.asarray(component_lookup(batch), dtype=np.int64)
    if components.shape != (len(batch),) or np.any(components < 0) or np.any(
        components >= len(component_ids)
    ):
        raise ValueError("stored-policy component row identity is invalid")
    return ordered[components]


def _temperature_scale_stored_policy(
    policy: np.ndarray,
    support: np.ndarray,
    temperatures: np.ndarray | None,
) -> np.ndarray:
    """Temperature-scale normalized stored probabilities on their support.

    ``T > 1`` softens and ``T < 1`` sharpens. Unsupported and exact-zero
    entries stay exact zero.  ``temperatures is None`` and an all-ones vector
    are strict no-ops so legacy descriptors and explicit T=1 controls retain
    the already-normalized bytes produced by the historical path.
    """

    if temperatures is None:
        return policy
    values = np.asarray(policy, dtype=np.float32)
    mask = np.asarray(support, dtype=np.bool_)
    row_temperatures = np.asarray(temperatures, dtype=np.float64)
    if values.ndim != 2 or mask.shape != values.shape:
        raise ValueError("stored-policy value/support shape drift")
    if row_temperatures.shape != (values.shape[0],):
        raise ValueError("stored-policy temperature row shape drift")
    if not np.isfinite(row_temperatures).all() or np.any(row_temperatures <= 0.0):
        raise ValueError("stored-policy temperatures must be finite and > 0")
    if np.all(row_temperatures == 1.0):
        return policy

    calibrated = values.copy()
    for row in np.flatnonzero(row_temperatures != 1.0):
        active = mask[row] & np.isfinite(values[row]) & (values[row] > 0.0)
        if not np.any(active):
            continue
        logits = np.log(values[row, active].astype(np.float64)) / float(
            row_temperatures[row]
        )
        logits -= float(np.max(logits))
        weights = np.exp(logits)
        total = float(np.sum(weights))
        if not math.isfinite(total) or total <= 0.0:
            raise ValueError("stored-policy temperature normalization failed")
        calibrated[row] = 0.0
        calibrated[row, active] = (weights / total).astype(np.float32)
    return calibrated


def _soft_target_array(
    data: dict,
    batch: np.ndarray,
    temperature: float,
    source: str,
) -> tuple[np.ndarray, np.ndarray] | None:
    policy = np.zeros_like(data["legal_action_ids"][batch], dtype=np.float32)
    policy_support = np.zeros_like(policy, dtype=np.bool_)
    has_policy = np.zeros(policy.shape[0], dtype=bool)
    if "target_policy" in data and source in {"prefer_policy", "policy", "prefer_scores"}:
        policy = np.asarray(data["target_policy"][batch], dtype=np.float32)
        if "target_policy_mask" in data:
            policy_support = np.asarray(data["target_policy_mask"][batch], dtype=np.bool_)
        else:
            policy_support = np.where(np.isfinite(policy), policy, 0.0) > 0.0
        policy = np.where(np.isfinite(policy), np.maximum(policy, 0.0), 0.0)
        policy = np.where(policy_support, policy, 0.0)
        sums = np.sum(policy, axis=1, keepdims=True)
        has_policy = sums[:, 0] > 0.0
        if np.any(has_policy):
            policy[has_policy] = policy[has_policy] / sums[has_policy]
        policy = _temperature_scale_stored_policy(
            policy,
            policy_support,
            _stored_policy_temperatures_for_batch(data, batch),
        )
    score_target = np.zeros_like(policy, dtype=np.float32)
    score_support = np.zeros_like(policy, dtype=np.bool_)
    has_scores = np.zeros(policy.shape[0], dtype=bool)
    if "target_scores" in data and source in {"prefer_scores", "scores", "prefer_policy"}:
        scores = np.asarray(data["target_scores"][batch], dtype=np.float32)
        if "target_scores_mask" in data:
            score_support = np.asarray(data["target_scores_mask"][batch], dtype=np.bool_)
        else:
            score_support = np.isfinite(scores)
        score_target = _scores_to_policy(
            scores,
            data["legal_action_ids"][batch],
            temperature,
            score_support=score_support,
        )
        has_scores = np.sum(score_target, axis=1) > 0.0

    teacher_names = _batch_array_or_fill(data, "teacher_name", batch, "").astype(str)
    score_sources = _batch_array_or_fill(
        data,
        "target_score_source",
        batch,
        "",
    ).astype(str)
    prefer_policy_rows = _prefer_policy_over_scores_for_teachers(
        teacher_names,
        score_sources,
    )
    ab_root_blend_rows = (
        _ab_root_score_rows(teacher_names, score_sources) & has_policy & has_scores
    )

    if source == "policy":
        target = policy
        support = policy_support
    elif source == "scores":
        target = score_target
        support = score_support
    elif source == "prefer_scores":
        target = policy.copy()
        support = policy_support.copy()
        target[has_scores] = score_target[has_scores]
        support[has_scores] = score_support[has_scores]
        target[prefer_policy_rows & has_policy] = policy[prefer_policy_rows & has_policy]
        support[prefer_policy_rows & has_policy] = policy_support[prefer_policy_rows & has_policy]
        if np.any(ab_root_blend_rows):
            blended = _blend_soft_target_rows(
                policy,
                score_target,
                ab_root_blend_rows,
                policy_weight=0.30,
            )
            target[ab_root_blend_rows] = blended
            support[ab_root_blend_rows] = blended > 0.0
    else:
        target = policy.copy()
        support = policy_support.copy()
        target[~has_policy & has_scores] = score_target[~has_policy & has_scores]
        support[~has_policy & has_scores] = score_support[~has_policy & has_scores]
    if not np.any(np.sum(target, axis=1) > 0.0):
        return None
    # Support is provenance, not ``target > 0``.  In particular, an exact-zero
    # probability on a legal action is still part of a complete search target:
    # it proves that the teacher considered that action and assigned it no
    # mass.  Collapsing support to positive entries made a valid one-hot search
    # target look like an unusable sparse target and silently routed the row to
    # the historical hard ``action_taken`` label.
    support &= np.asarray(data["legal_action_ids"][batch]) >= 0
    target = np.where(support, target, 0.0)
    return target.astype(np.float32, copy=False), support.astype(np.bool_, copy=False)


def _has_distillation_distribution(
    target: np.ndarray,
    support: np.ndarray,
    *,
    legal_action_ids: np.ndarray | None = None,
    min_legal_coverage: float = 0.0,
) -> np.ndarray:
    """Return rows carrying a usable, sufficiently complete distribution.

    The loss denominator is the complete legal-action softmax, so a one-hot
    target with authenticated all-legal support is a valid distillation label
    (and is mathematically equivalent to hard CE on that selected action).
    Exact-zero probabilities therefore remain support rather than forcing a
    fallback to ``action_taken``.
    """

    target = np.asarray(target, dtype=np.float32)
    support = np.asarray(support, dtype=np.bool_)
    has_distribution = np.sum(
        np.where(support & np.isfinite(target) & (target > 0.0), target, 0.0),
        axis=1,
    ) > 0.0
    min_coverage = float(np.clip(min_legal_coverage, 0.0, 1.0))
    if min_coverage <= 0.0 or legal_action_ids is None:
        return has_distribution
    legal = np.asarray(legal_action_ids)
    legal_counts = np.maximum(np.sum(legal >= 0, axis=1), 1)
    coverage = np.sum(support & (legal >= 0), axis=1) / legal_counts
    return has_distribution & (coverage >= min_coverage)


def _require_stage_c_soft_targets(
    data,
    batch: np.ndarray,
    has_soft,
    *,
    source: str,
) -> None:
    """Fail closed for active Stage-C rows instead of using stale hard actions."""

    if source != "policy" or "teacher_name" not in data:
        return
    teachers = np.asarray(data["teacher_name"][batch]).astype(str)
    stage_c = teachers == "stage_c_coherent_n128_reanalysis"
    if "policy_weight_multiplier" in data:
        stage_c &= (
            np.asarray(data["policy_weight_multiplier"][batch], dtype=np.float32)
            > 0.0
        )
    if not np.any(stage_c):
        return
    usable = (
        np.zeros(len(batch), dtype=np.bool_)
        if has_soft is None
        else np.asarray(has_soft.detach().cpu(), dtype=np.bool_)
    )
    rejected = np.flatnonzero(stage_c & ~usable)
    if rejected.size:
        source_rows = np.asarray(batch, dtype=np.int64)[rejected]
        raise ValueError(
            "active Stage-C coherent target is unusable; refusing historical "
            f"action_taken fallback for corpus rows {source_rows[:16].tolist()}"
        )


def _scores_to_policy(
    scores: np.ndarray,
    legal_action_ids: np.ndarray,
    temperature: float,
    *,
    score_support: np.ndarray | None = None,
) -> np.ndarray:
    target = np.zeros(scores.shape, dtype=np.float32)
    temp = max(float(temperature), 1.0e-6)
    if score_support is None:
        score_support = np.isfinite(scores)
    valid = (legal_action_ids >= 0) & np.asarray(score_support, dtype=np.bool_) & np.isfinite(scores)
    for row in range(scores.shape[0]):
        keep = valid[row]
        if not np.any(keep):
            continue
        logits = scores[row, keep].astype(np.float32)
        logits = logits / temp
        logits = logits - float(np.max(logits))
        logits = np.clip(logits, -60.0, 0.0)
        probs = np.exp(logits)
        total = float(np.sum(probs))
        if total > 0.0:
            target[row, keep] = probs / total
    return target


def _support_log_softmax(logits, support):
    import torch

    if support is None:
        return torch.nn.functional.log_softmax(logits, dim=-1)
    support = support.to(device=logits.device, dtype=torch.bool)
    if support.shape != logits.shape:
        raise ValueError(
            f"soft target support shape {tuple(support.shape)} does not match "
            f"logits shape {tuple(logits.shape)}"
        )
    # The support mask is only a shape/provenance guard here. Candidate logits are
    # already masked to legal actions upstream, so the soft-label denominator must
    # include every legal candidate. Otherwise a high logit on an unscored legal
    # action gets no distillation penalty and can silently dominate evaluation.
    return torch.nn.functional.log_softmax(logits, dim=-1)


def _prior_kl_telemetry(
    data: dict,
    batch: np.ndarray,
    logits,
    device,
):
    """SUCCESS TELEMETRY (gen-1 recipe): KL(model_policy || prior_policy) on a
    held-out GEN slice, alongside the reference KL(target_policy || prior_policy)
    -- training "worked" once the former reaches 60-80% of the latter; if it's
    still under ~30% of it by the end of training, the run underfit (a retrain
    at a higher LR is cheaper than spending gate games finding that out).

    Scoped to rows with a recorded prior, with no extra bookkeeping: prior_policy
    is populated by the self-play data generators -- gumbel_self_play.py's
    _build_decision_row and raw_selfplay.py's _build_raw_decision_row (the latter
    stores the seed model's raw prior distribution, since there is no search to
    improve it) -- while any other teacher source defaults it to all-zero (see
    _normalize_teacher_shard), which this function's `has_prior` filter excludes
    automatically.

    The returned per-row `kl_model_prior`/`kl_target_prior` tensors are
    differentiable through `logits` (the caller detaches at `.item()` for
    telemetry); _policy_kl_anchor_loss reuses this same computation, un-detached,
    as the training-time policy-KL anchor so the anchor and the telemetry measure
    the identical quantity.

    `logits` must already be in the SAME per-row legal-action ordering as
    data["target_policy"]/data["prior_policy"] (true for _eval_entity_batch's
    outputs["logits"], which _soft_targets_legal already relies on for the
    same reason -- see _support_log_softmax above).
    """
    import torch

    if "prior_policy" not in data or "target_policy" not in data:
        return None
    prior_np = np.asarray(data["prior_policy"][batch], dtype=np.float32)
    target_np = np.asarray(data["target_policy"][batch], dtype=np.float32)
    legal_ids = np.asarray(data["legal_action_ids"][batch])
    valid_np = legal_ids >= 0
    has_prior_np = (prior_np * valid_np).sum(axis=1) > 1.0e-6
    if not has_prior_np.any():
        return None

    valid = torch.as_tensor(valid_np, dtype=torch.bool, device=device)
    has_prior = torch.as_tensor(has_prior_np, dtype=torch.bool, device=device)
    prior = torch.as_tensor(prior_np, dtype=torch.float32, device=device)
    target = torch.as_tensor(target_np, dtype=torch.float32, device=device)
    zeros = torch.zeros_like(prior)

    eps = 1.0e-8
    prior = torch.where(valid, prior, zeros)
    prior_norm = prior / torch.clamp(prior.sum(dim=-1, keepdim=True), min=eps)
    target = torch.where(valid, target, zeros)
    target_norm = target / torch.clamp(target.sum(dim=-1, keepdim=True), min=eps)

    model_log_probs = torch.nn.functional.log_softmax(logits, dim=-1)
    model_probs = torch.where(valid, model_log_probs.exp(), zeros)

    log_prior = torch.log(torch.clamp(prior_norm, min=eps))
    log_target = torch.log(torch.clamp(target_norm, min=eps))

    kl_model_prior = torch.where(valid, model_probs * (model_log_probs - log_prior), zeros).sum(
        dim=-1
    )
    kl_prior_model = torch.where(
        valid, prior_norm * (log_prior - model_log_probs), zeros
    ).sum(dim=-1)
    kl_target_prior = torch.where(valid, target_norm * (log_target - log_prior), zeros).sum(
        dim=-1
    )
    return {
        "has_prior": has_prior,
        "kl_model_prior": kl_model_prior,
        "kl_prior_model": kl_prior_model,
        "kl_target_prior": kl_target_prior,
    }


def _active_policy_teacher_gap_telemetry(
    data: dict,
    batch: np.ndarray,
    logits,
    device,
    *,
    soft_targets,
    has_soft,
    policy_weights,
):
    """Measure how much of the active soft-policy teacher gap was closed.

    This intentionally differs from the historical ``_prior_kl_telemetry``:

    * only rows with positive policy loss weight are eligible;
    * only usable multi-action soft targets are eligible; and
    * the primary distance is ``KL(target || model)``, the direction aligned
      with the soft cross-entropy objective.

    PCR shards retain improved policies for fast-search and forced rows even
    when their ``policy_weight_multiplier`` is zero.  Those rows are useful for
    provenance but are not optimization targets, so including them in a
    teacher-uptake denominator makes the resulting ratio structurally
    unattainable.  Rows without a recorded prior are also excluded because the
    baseline gap ``KL(target || prior)`` is undefined for them.
    """

    import torch

    if soft_targets is None or has_soft is None or "prior_policy" not in data:
        return None

    legal_np = np.asarray(data["legal_action_ids"][batch]) >= 0
    prior_np = np.asarray(data["prior_policy"][batch], dtype=np.float32)
    if prior_np.shape != legal_np.shape:
        return None

    valid = torch.as_tensor(legal_np, dtype=torch.bool, device=device)
    target = soft_targets.to(device=device, dtype=torch.float32)
    if target.shape != valid.shape or logits.shape != valid.shape:
        return None
    zeros = torch.zeros_like(target)
    eps = 1.0e-8

    target = torch.where(valid, torch.clamp(target, min=0.0), zeros)
    target = target / torch.clamp(target.sum(dim=-1, keepdim=True), min=eps)
    prior = torch.as_tensor(prior_np, dtype=torch.float32, device=device)
    prior = torch.where(valid, torch.clamp(prior, min=0.0), zeros)
    prior_mass = prior.sum(dim=-1)
    prior = prior / torch.clamp(prior_mass.unsqueeze(-1), min=eps)

    has_multi_action_target = ((target > 0.0) & valid).sum(dim=-1) > 1
    measure_weights = policy_weights.to(device=device, dtype=torch.float32)
    eligible = (
        (measure_weights > 0.0)
        & has_soft.to(device=device, dtype=torch.bool)
        & has_multi_action_target
        & (prior_mass > eps)
    )

    log_target = torch.log(torch.clamp(target, min=eps))
    log_prior = torch.log(torch.clamp(prior, min=eps))
    model_log_probs = torch.nn.functional.log_softmax(logits.float(), dim=-1)
    kl_target_model = torch.where(
        valid,
        target * (log_target - model_log_probs),
        zeros,
    ).sum(dim=-1).clamp_min(0.0)
    kl_target_prior = torch.where(
        valid,
        target * (log_target - log_prior),
        zeros,
    ).sum(dim=-1).clamp_min(0.0)
    return {
        "eligible": eligible,
        "measure_weights": torch.where(
            eligible, measure_weights, torch.zeros_like(measure_weights)
        ),
        "kl_target_model": kl_target_model,
        "kl_target_prior": kl_target_prior,
    }


def _active_policy_teacher_gap_report(
    *,
    rows: float,
    weight_sum: float | None = None,
    kl_target_model_sum: float,
    kl_target_prior_sum: float,
) -> dict[str, float | int]:
    """Reduce additive teacher-gap statistics into report-level metrics."""

    count = max(float(rows), 0.0)
    denominator = count if weight_sum is None else max(float(weight_sum), 0.0)
    target_model = float(kl_target_model_sum)
    target_prior = float(kl_target_prior_sum)
    return {
        "active_policy_teacher_gap_rows": int(round(count)),
        "active_policy_teacher_gap_weight_sum": denominator,
        "active_policy_kl_target_model_mean": target_model / max(denominator, 1.0e-12),
        "active_policy_kl_target_prior_mean": target_prior / max(denominator, 1.0e-12),
        "active_policy_teacher_gap_closure": (
            1.0 - target_model / target_prior
            if denominator > 0.0 and target_prior > 1.0e-8
            else 0.0
        ),
    }


def compute_policy_surprise_kl(
    data: dict, batch: np.ndarray | None = None
) -> tuple[np.ndarray, np.ndarray]:
    """Per-row "policy surprise" KL(target_policy || prior_policy) -- a pure,
    data-derived (no model/torch) NumPy port of ``_prior_kl_telemetry``'s
    ``kl_target_prior`` term, for use as a CAT-45 sample-frequency weighting
    signal rather than a training-time loss/telemetry term. Kept as a separate
    function (not a refactor of ``_prior_kl_telemetry``) so that function's
    existing tests/behaviour are untouched; the masking/eps/normalization
    conventions are intentionally identical so the two never silently drift
    apart.

    Returns ``(kl_target_prior, has_prior)`` over ``batch`` (or the whole
    corpus when ``batch`` is None), matching ``_prior_kl_telemetry``'s
    ``has_prior`` scoping: rows with no recorded ``prior_policy`` (any non-
    Gumbel-self-play teacher row, or any shard predating this column) get
    ``has_prior=False`` and ``kl_target_prior=0.0`` -- exactly the "old shards
    default to uniform weight" behaviour CAT-45 requires.
    """
    n = len(data["action_taken"]) if batch is None else len(batch)
    if "prior_policy" not in data or "target_policy" not in data:
        return np.zeros(n, dtype=np.float32), np.zeros(n, dtype=np.bool_)

    index = slice(None) if batch is None else batch
    prior = np.asarray(data["prior_policy"][index], dtype=np.float32)
    target = np.asarray(data["target_policy"][index], dtype=np.float32)
    legal_ids = np.asarray(data["legal_action_ids"][index])
    valid = legal_ids >= 0

    has_prior = (prior * valid).sum(axis=1) > 1.0e-6
    if not has_prior.any():
        return np.zeros(n, dtype=np.float32), has_prior

    eps = 1.0e-8
    prior = np.where(valid, prior, 0.0)
    prior_norm = prior / np.clip(prior.sum(axis=-1, keepdims=True), eps, None)
    target = np.where(valid, target, 0.0)
    target_norm = target / np.clip(target.sum(axis=-1, keepdims=True), eps, None)

    log_prior = np.log(np.clip(prior_norm, eps, None))
    log_target = np.log(np.clip(target_norm, eps, None))
    kl_target_prior = np.where(valid, target_norm * (log_target - log_prior), 0.0).sum(axis=-1)
    # Rows without a recorded prior have an undefined KL -- zero them explicitly
    # rather than trust the eps-clamped math above to land near zero.
    kl_target_prior = np.where(has_prior, kl_target_prior, 0.0)
    return kl_target_prior.astype(np.float32, copy=False), has_prior


def policy_surprise_sampling_weights(
    kl_target_prior: np.ndarray,
    has_prior: np.ndarray,
    *,
    weight_scale: float,
    cap: float,
) -> np.ndarray:
    """CAT-45 sample-frequency weight from per-row policy surprise.

    ``weight = 1.0 + weight_scale * min(kl_target_prior, cap)`` for rows with a
    recorded prior, ``weight = 1.0`` (uniform baseline) for everything else --
    rows with no recorded prior (pre-CAT-45 shards, non-Gumbel teacher rows) and
    ANY row whenever ``weight_scale <= 0.0`` (the default-off case). This is a
    strict *upweighting* of surprising states relative to a uniform floor of
    1.0, never a downweighting of agreeing ones -- consistent with "oversample
    high-KL states" (R8 / master plan Sec 4.5), not "starve low-KL states".

    This is deliberately NOT a literal reproduction of KataGo's own (unpublished
    here) sample-frequency constants -- it is "roughly KataGo-style" per the
    ticket's own framing ("half of KataGo's sample-frequency weighting scheme"),
    with an explicit, capped, documented formula of our own so the behaviour is
    auditable and testable independent of that precedent.
    """
    weight_scale = float(weight_scale)
    cap = float(cap)
    weights = np.ones_like(kl_target_prior, dtype=np.float64)
    if weight_scale > 0.0:
        weights[has_prior] = 1.0 + weight_scale * np.minimum(kl_target_prior[has_prior], cap)
    return weights.astype(np.float32, copy=False)


_PER_GAME_POLICY_SURPRISE_CAP = 2.0


def _component_game_identities(data, rows: np.ndarray) -> np.ndarray:
    """Return game identities namespaced by composite component."""

    indices = np.asarray(rows, dtype=np.int64)
    seeds = np.asarray(data["game_seed"][indices], dtype=np.int64)
    component_mapper = getattr(data, "component_indices_for_rows", None)
    components = (
        np.asarray(component_mapper(indices), dtype=np.int64)
        if callable(component_mapper)
        else np.zeros(indices.size, dtype=np.int64)
    )
    if components.shape != seeds.shape:
        raise ValueError("component/game identity alignment drift")
    return np.rec.fromarrays(
        (components, seeds),
        names=("component", "seed"),
    )


def per_game_capped_policy_surprise_sampling_weights(
    game_identities: np.ndarray,
    kl_target_prior: np.ndarray,
    policy_active: np.ndarray,
) -> np.ndarray:
    """Return exact mass-preserving surprise factors within each game.

    For the ``m`` policy-active roots in one game, the enabled formula is::

        0.5 + 0.5 * m * clip(KL(search || prior), 0, 2) / sum(clip(KL), 0, 2)

    When every active KL in a game is zero, every factor in that game is 1.
    Policy-inactive rows also remain exactly 1: their sample frequency is not
    starved, while their existing zero policy-loss weight remains authoritative.
    Consequently the factors sum to the original row count in every game, which
    lets callers multiply them into a component->game->row base measure without
    changing either the game or component sampling proportions.
    """

    identities = np.asarray(game_identities)
    surprise = np.asarray(kl_target_prior, dtype=np.float64)
    active = np.asarray(policy_active, dtype=np.bool_)
    if identities.ndim != 1 or surprise.ndim != 1 or active.ndim != 1:
        raise ValueError("per-game policy-surprise inputs must be one-dimensional")
    if identities.shape != surprise.shape or identities.shape != active.shape:
        raise ValueError("per-game policy-surprise input shape drift")
    if not np.isfinite(surprise).all():
        raise ValueError("per-game policy-surprise KL contains non-finite values")

    factors = np.ones(identities.shape[0], dtype=np.float64)
    active_positions = np.flatnonzero(active)
    if active_positions.size == 0:
        return factors

    _games, inverse = np.unique(
        identities[active_positions], return_inverse=True
    )
    active_counts = np.bincount(inverse).astype(np.float64, copy=False)
    clipped = np.clip(
        surprise[active_positions], 0.0, _PER_GAME_POLICY_SURPRISE_CAP
    )
    surprise_sums = np.bincount(inverse, weights=clipped)
    denominators = surprise_sums[inverse]
    positive = denominators > 0.0
    active_factors = np.ones(active_positions.size, dtype=np.float64)
    active_factors[positive] = 0.5 + (
        0.5
        * active_counts[inverse[positive]]
        * clipped[positive]
        / denominators[positive]
    )
    factors[active_positions] = active_factors

    realized_active_mass = np.bincount(inverse, weights=active_factors)
    if not np.allclose(
        realized_active_mass, active_counts, rtol=0.0, atol=1.0e-10
    ):
        raise RuntimeError("per-game policy-surprise active mass drift")
    return factors


def per_game_policy_surprise_sampling_report(
    game_identities: np.ndarray,
    sampling_factors: np.ndarray,
    policy_active: np.ndarray,
    *,
    enabled: bool,
    authenticated_component_sampling: bool,
) -> dict[str, object]:
    """Build the stable report schema for the exact within-game sampler."""

    identities = np.asarray(game_identities)
    factors = np.asarray(sampling_factors, dtype=np.float64)
    active = np.asarray(policy_active, dtype=np.bool_)
    if identities.shape != factors.shape or identities.shape != active.shape:
        raise ValueError("per-game policy-surprise report shape drift")
    active_positions = np.flatnonzero(active)
    max_active_mass_error = 0.0
    active_games = 0
    if active_positions.size:
        _games, inverse = np.unique(
            identities[active_positions], return_inverse=True
        )
        expected = np.bincount(inverse).astype(np.float64, copy=False)
        realized = np.bincount(inverse, weights=factors[active_positions])
        max_active_mass_error = float(np.max(np.abs(realized - expected)))
        active_games = int(expected.size)
    return {
        "schema_version": "train-policy-surprise-sampling-v2",
        "mode": "per_game_capped" if enabled else "off",
        "enabled": bool(enabled),
        "formula": (
            "0.5+0.5*m*clip(KL(search||prior),0,2)/sum(clip(KL),0,2)"
        ),
        "kl_cap": _PER_GAME_POLICY_SURPRISE_CAP,
        "uniform_mass_fraction": 0.5,
        "surprise_mass_fraction": 0.5,
        "all_zero_kl_fallback_weight": 1.0,
        "policy_active_rows": int(active_positions.size),
        "policy_inactive_rows": int(active.size - active_positions.size),
        "policy_active_games": active_games,
        "game_identity_namespace": (
            "component_id+game_seed"
            if identities.dtype.names == ("component", "seed")
            else "game_seed"
        ),
        "max_per_game_active_mass_error": max_active_mass_error,
        "policy_inactive_factor_is_one": bool(
            np.all(factors[~active] == 1.0) if np.any(~active) else True
        ),
        "application_order": (
            "authenticated_component_then_game_then_row_then_within_game_surprise"
            if authenticated_component_sampling
            else "legacy_row_measure_then_within_game_surprise"
        ),
        "authenticated_component_proportions_preserved": bool(
            authenticated_component_sampling and enabled
        ),
    }


def _combine_policy_kl_anchor_streams(
    base_mean,
    base_sum,
    base_denominator,
    aux_mean,
    aux_sum,
    aux_denominator,
    *,
    aux_coefficient: float,
):
    """Combine base/AUX trust-region objectives and controller evidence.

    Policy CE treats the base and high-surprise streams as independently
    normalized objectives, so the differentiable KL regularizer must do the
    same. The adaptive controller instead consumes one effective-mixture mean;
    returning its weighted sum/denominator preserves the existing target-KL
    interpretation without leaving AUX drift invisible.
    """

    coefficient = float(aux_coefficient)
    if not math.isfinite(coefficient) or coefficient < 0.0:
        raise ValueError("policy AUX KL coefficient must be finite and non-negative")
    objective = base_mean + coefficient * aux_mean
    controller_sum = base_sum + coefficient * aux_sum
    controller_denominator = base_denominator + coefficient * aux_denominator
    return objective, controller_sum, controller_denominator


def _policy_kl_anchor_loss(
    data: dict,
    batch: np.ndarray,
    logits,
    device,
    *,
    direction: str = "forward",
):
    """Differentiable behavior anchor over multi-action rows with a prior.

    ``forward`` is KL(prior_policy || pi_theta), the recovery/default old-policy
    distillation objective. ``reverse`` retains historical KL(pi_theta ||
    prior_policy) only as an explicit compatibility ablation.

    Reuses _prior_kl_telemetry's exact per-row computation (un-detached here).
    Its optimization mean then excludes forced rows, whose one-element policy
    simplex makes KL identically zero; raw prior-KL telemetry may still report
    those rows as coverage. The masked mean goes through _weighted_mean_loss so
    it inherits the same DDP-correct global-denominator reduction the
    value/policy losses use.

    Returns None when the batch has no prior rows (caller then adds nothing to
    the loss). MUST be called with grad enabled -- i.e. from the training path,
    not the no_grad eval path where the telemetry variant lives.
    """
    parts = _policy_kl_anchor_loss_parts(
        data, batch, logits, device, direction=direction
    )
    return None if parts is None else parts[0]


def _policy_kl_anchor_loss_parts(
    data: dict,
    batch: np.ndarray,
    logits,
    device,
    *,
    direction: str = "forward",
    sample_weights=None,
):
    """Return conditional anchor mean plus its eligible-row sum/denominator.

    The scalar objective is normalized over authenticated, multi-action rows
    that carry a prior. Returning the raw parts lets epoch/eval telemetry use
    that same denominator instead of silently diluting the reported metric by
    the full batch size.
    """
    import torch
    import torch.distributed as dist

    terms = _prior_kl_telemetry(data, batch, logits, device)
    # A locally empty anchor batch is not evidence that the GLOBAL DDP batch is
    # empty. The old local early-return let one rank skip the denominator
    # all-reduce while a peer with replay/prior rows entered it, deadlocking the
    # step (or yielding different objectives if collectives were mocked). Make
    # the presence decision collectively during gradient-enabled training.
    distributed_training = bool(
        torch.is_grad_enabled() and dist.is_available() and dist.is_initialized()
    )
    if distributed_training:
        global_has_terms = torch.tensor(
            int(terms is not None), dtype=torch.int64, device=device
        )
        dist.all_reduce(global_has_terms, op=dist.ReduceOp.MAX)
        if int(global_has_terms.item()) == 0:
            return None
        if terms is None:
            zero = logits.float().sum(dim=-1) * 0.0
            terms = {
                "has_prior": torch.zeros(
                    len(batch), dtype=torch.bool, device=device
                ),
                "kl_model_prior": zero,
                "kl_prior_model": zero,
            }
    elif terms is None:
        return None
    # A forced row has a one-element legal simplex, so its KL is identically
    # zero for every model.  Counting those rows in the denominator diluted the
    # configured anchor by roughly the corpus forced fraction (~51.5%) even
    # though they can never contribute an anchor gradient.
    legal = np.asarray(data["legal_action_ids"][batch])
    non_forced = torch.as_tensor(
        np.sum(legal >= 0, axis=1) > 1,
        dtype=torch.bool,
        device=device,
    )
    weights = (terms["has_prior"] & non_forced).to(torch.float32)
    if sample_weights is not None:
        external = torch.as_tensor(
            sample_weights,
            dtype=torch.float32,
            device=device,
        )
        if external.shape != weights.shape:
            raise ValueError("policy KL anchor sample-weight shape drift")
        if not bool(torch.isfinite(external).all().item()) or bool(
            (external < 0.0).any().item()
        ):
            raise ValueError("policy KL anchor sample weights are invalid")
        weights = weights * external
    scope_mask = _policy_kl_anchor_scope_mask(data, batch)
    if scope_mask is not None:
        eligible = torch.as_tensor(scope_mask, dtype=torch.bool, device=device)
        weights = weights * eligible.to(torch.float32)
    if not distributed_training and float(weights.sum().item()) <= 0.0:
        return None
    if direction == "forward":
        values = terms["kl_prior_model"]
    elif direction == "reverse":
        values = terms["kl_model_prior"]
    else:
        raise ValueError(f"unknown policy KL anchor direction {direction!r}")
    weighted_sum, denominator = _weighted_loss_parts(values, weights)
    return _weighted_mean_loss(values, weights), weighted_sum, denominator


def _policy_kl_anchor_scope_mask(
    data: object,
    batch: np.ndarray,
) -> np.ndarray | None:
    """Resolve the authenticated anchor-component mask for one batch.

    The private materialized column is produced only by
    :func:`_iterate_training_batches`; ordinary dictionaries retain the legacy
    unscoped behavior. Returning ``None`` therefore means "no authenticated
    scope", while an all-false array faithfully represents an authenticated
    scope with no eligible rows in this particular batch.
    """

    if isinstance(data, dict) and "_policy_kl_anchor_eligible" in data:
        eligible = np.asarray(
            data["_policy_kl_anchor_eligible"][batch], dtype=np.bool_
        )
        if eligible.shape != (len(batch),):
            raise ValueError("materialized policy-KL anchor scope shape drift")
        return eligible

    if not bool(getattr(data, "policy_kl_anchor_scope_authenticated", False)):
        return None
    component_lookup = getattr(data, "component_indices_for_rows", None)
    if not callable(component_lookup):
        raise ValueError(
            "authenticated policy-KL anchor scope has no component row lookup"
        )
    component_indices = np.asarray(component_lookup(batch), dtype=np.int64)
    if component_indices.shape != (len(batch),):
        raise ValueError("authenticated policy-KL anchor component shape drift")
    eligible_components = np.asarray(
        getattr(data, "policy_kl_anchor_component_indices", tuple()),
        dtype=np.int64,
    )
    return np.isin(component_indices, eligible_components)


def _aux_subgoal_scope_mask(
    data: object,
    batch: np.ndarray,
) -> np.ndarray | None:
    """Resolve the authenticated component mask for auxiliary supervision.

    ``None`` means an ordinary single corpus (all rows are in scope, subject to
    the per-row semantic version).  An authenticated composite always returns
    an explicit boolean mask, including all-false batches from historical
    replay.  This distinction prevents old replay labels from being silently
    re-enabled by threaded materialization.
    """

    if isinstance(data, dict) and "_aux_subgoal_eligible" in data:
        eligible = np.asarray(data["_aux_subgoal_eligible"][batch], dtype=np.bool_)
        if eligible.shape != (len(batch),):
            raise ValueError("materialized aux-subgoal scope shape drift")
        return eligible
    if not bool(getattr(data, "aux_subgoal_scope_authenticated", False)):
        return None
    component_lookup = getattr(data, "component_indices_for_rows", None)
    if not callable(component_lookup):
        raise ValueError(
            "authenticated aux-subgoal scope has no component row lookup"
        )
    components = np.asarray(component_lookup(batch), dtype=np.int64)
    if components.shape != (len(batch),):
        raise ValueError("authenticated aux-subgoal component shape drift")
    eligible_components = np.asarray(
        getattr(data, "aux_subgoal_component_indices", tuple()), dtype=np.int64
    )
    return np.isin(components, eligible_components)


def _validate_aux_subgoal_training_contract(
    data: object,
    train_indices: np.ndarray,
    *,
    loss_weight: float,
) -> dict[str, object]:
    """Validate semantic/version/scope before the first aux optimizer step.

    Version 0 (missing from historical shards) is deliberately valid storage
    but invalid auxiliary supervision.  Composite descriptors must explicitly
    authenticate the components allowed to supply version-1 targets; excluded
    components remain available to policy/value objectives.
    """

    weight = float(loss_weight)
    if weight == 0.0:
        return {
            "schema_version": "aux-subgoal-training-contract-v1",
            "enabled": False,
            "loss_weight": 0.0,
        }
    missing = [key for key in (*AUX_TARGET_KEYS, AUX_SUBGOAL_TARGET_VERSION_KEY) if key not in data]
    if missing:
        raise SystemExit(
            "nonzero aux-subgoal loss requires versioned target columns; missing="
            + ",".join(missing)
        )
    indices = np.asarray(train_indices, dtype=np.int64)
    if indices.ndim != 1 or indices.size == 0:
        raise SystemExit("nonzero aux-subgoal loss has no training rows")

    component_ids = tuple(getattr(data, "component_ids", tuple()))
    component_lookup = getattr(data, "component_indices_for_rows", None)
    is_composite = bool(component_ids)
    if is_composite:
        if not bool(getattr(data, "aux_subgoal_scope_authenticated", False)):
            raise SystemExit(
                "nonzero aux-subgoal loss on a composite requires an authenticated "
                "aux_subgoal_component_ids scope"
            )
        eligible_components = tuple(
            int(value)
            for value in getattr(data, "aux_subgoal_component_indices", tuple())
        )
        if (
            not callable(component_lookup)
            or not eligible_components
            or len(set(eligible_components)) != len(eligible_components)
            or any(value < 0 or value >= len(component_ids) for value in eligible_components)
        ):
            raise SystemExit(
                "nonzero aux-subgoal loss has an empty/invalid authenticated component scope"
            )
    else:
        component_ids = ("single_corpus",)
        eligible_components = (0,)

    coverage_floors = {
        "aux_longest_road": 0.999,
        "aux_largest_army": 0.999,
        "aux_vp_in_n": 0.999,
        "aux_next_settlement": 0.69,
        "aux_robber_target": 0.89,
    }
    target_domains = {
        "aux_longest_road": {"kind": "binary", "values": [0.0, 1.0]},
        "aux_largest_army": {"kind": "binary", "values": [0.0, 1.0]},
        # Buildings/development VPs cannot be lost; only the two 2-VP awards
        # can be lost (-4).  The physical maximum actual score is 18
        # (9 building + 4 awards + 5 development VPs).
        "aux_vp_in_n": {"kind": "scalar", "minimum": -4.0, "maximum": 18.0},
        "aux_next_settlement": {
            "kind": "categorical",
            "ignore_index": -1,
            "classes": 54,
        },
        "aux_robber_target": {
            "kind": "categorical",
            "ignore_index": -1,
            "classes": 19,
        },
    }
    report_components = {
        component_id: {
            "component_index": int(component),
            "aux_training_enabled": bool(component in eligible_components),
            "training_rows": 0,
            "version_counts": {},
            "valid_target_rows": {key: 0 for key in AUX_TARGET_KEYS},
            "valid_target_fraction": {key: 0.0 for key in AUX_TARGET_KEYS},
        }
        for component, component_id in enumerate(component_ids)
    }
    chunk_size = 1_000_000
    for start in range(0, int(indices.size), chunk_size):
        rows = indices[start : start + chunk_size]
        components = (
            np.asarray(component_lookup(rows), dtype=np.int64)
            if is_composite
            else np.zeros(rows.size, dtype=np.int64)
        )
        versions = np.asarray(data[AUX_SUBGOAL_TARGET_VERSION_KEY][rows])
        if versions.shape != (rows.size,) or versions.dtype.kind not in {"i", "u"}:
            raise SystemExit("aux-subgoal target version column shape/dtype drift")
        versions_i64 = versions.astype(np.int64, copy=False)
        for component in np.unique(components).tolist():
            if not 0 <= int(component) < len(component_ids):
                raise SystemExit("aux-subgoal component lookup returned an invalid index")
            selected = components == int(component)
            component_id = component_ids[int(component)]
            row = report_components[component_id]
            row["training_rows"] = int(row["training_rows"]) + int(selected.sum())
            unique_versions, version_counts = np.unique(
                versions_i64[selected], return_counts=True
            )
            counts = row["version_counts"]
            for version, count in zip(unique_versions.tolist(), version_counts.tolist()):
                key = str(int(version))
                counts[key] = int(counts.get(key, 0)) + int(count)
            if int(component) not in eligible_components:
                continue
            if bool(np.any(versions_i64[selected] != AUX_SUBGOAL_TARGET_VERSION)):
                raise SystemExit(
                    "aux-subgoal semantic version mismatch in authenticated component "
                    f"{component_id!r}: expected {AUX_SUBGOAL_TARGET_VERSION}, "
                    f"observed={sorted(map(int, unique_versions.tolist()))}"
                )
            selected_rows = rows[selected]
            valid_counts = row["valid_target_rows"]
            for key in AUX_TARGET_KEYS:
                target = np.asarray(data[key][selected_rows])
                domain = target_domains[key]
                if domain["kind"] == "categorical":
                    if target.dtype.kind not in {"i", "u"}:
                        raise SystemExit(
                            f"aux-subgoal categorical target {key} is not integer"
                        )
                    values = target.astype(np.int64, copy=False)
                    if bool(
                        np.any(
                            (values < int(domain["ignore_index"]))
                            | (values >= int(domain["classes"]))
                        )
                    ):
                        raise SystemExit(
                            f"aux-subgoal categorical target {key} is outside "
                            f"[-1,{int(domain['classes']) - 1}]"
                        )
                    valid = values >= 0
                else:
                    values = target.astype(np.float64, copy=False)
                    valid = np.isfinite(values)
                    finite_values = values[valid]
                    if domain["kind"] == "binary" and bool(
                        np.any((finite_values != 0.0) & (finite_values != 1.0))
                    ):
                        raise SystemExit(
                            f"aux-subgoal binary target {key} is not exactly 0/1"
                        )
                    if domain["kind"] == "scalar" and bool(
                        np.any(
                            (finite_values < float(domain["minimum"]))
                            | (finite_values > float(domain["maximum"]))
                        )
                    ):
                        raise SystemExit(
                            f"aux-subgoal scalar target {key} is outside "
                            f"[{domain['minimum']},{domain['maximum']}]"
                        )
                valid_counts[key] = int(valid_counts[key]) + int(np.count_nonzero(valid))

    eligible_ids = [component_ids[index] for index in eligible_components]
    for component_id in eligible_ids:
        row = report_components[component_id]
        if int(row["training_rows"]) <= 0:
            raise SystemExit(
                f"authenticated aux-subgoal component {component_id!r} has no training rows"
            )
        missing_labels = [
            key
            for key, count in row["valid_target_rows"].items()
            if int(count) <= 0
        ]
        if missing_labels:
            raise SystemExit(
                f"authenticated aux-subgoal component {component_id!r} has no valid "
                "training labels for " + ",".join(missing_labels)
            )
        training_rows = int(row["training_rows"])
        fractions = row["valid_target_fraction"]
        below_floor: list[str] = []
        for key, count in row["valid_target_rows"].items():
            fraction = float(int(count) / training_rows)
            fractions[key] = fraction
            if fraction < coverage_floors[key]:
                below_floor.append(
                    f"{key}={fraction:.9f}<{coverage_floors[key]:.9f}"
                )
        if below_floor:
            raise SystemExit(
                f"authenticated aux-subgoal component {component_id!r} is below "
                "declared coverage floors: " + ",".join(below_floor)
            )
    return {
        "schema_version": "aux-subgoal-training-contract-v1",
        "enabled": True,
        "loss_weight": weight,
        "target_version": AUX_SUBGOAL_TARGET_VERSION,
        "target_semantic": AUX_SUBGOAL_TARGET_SEMANTIC,
        "coverage_floors": coverage_floors,
        "target_domains": target_domains,
        "component_ids": eligible_ids,
        "components": report_components,
    }


def _weighted_mean_loss(
    values,
    weights,
    *,
    mask=None,
    fixed_weight_mean: float | None = None,
):
    numerator, denominator = _weighted_loss_parts(
        values,
        weights,
        mask=mask,
        fixed_weight_mean=fixed_weight_mean,
    )
    return _weighted_mean_from_parts(numerator, denominator)


def _policy_target_per_sample_loss(
    hard_loss,
    soft_loss,
    has_soft,
    *,
    soft_target_weight: float,
    blend_semantics: str,
):
    """Apply one explicit, versioned policy-label contract.

    ``policy_target_fallback_v2`` never mixes the played action into a usable
    search-policy row.  This matters when ``action_taken`` was sampled for
    self-play exploration: the sampled move advances the trajectory, while the
    authenticated untempered search distribution remains the teacher label.

    ``legacy_interpolate_v1`` preserves the historical alpha interpolation for
    exact report/checkpoint replay.  New coherent/A1 recipes must opt into v2.
    """

    import torch

    semantics = str(blend_semantics)
    weight = float(soft_target_weight)
    if semantics == POLICY_TARGET_BLEND_LEGACY_V1:
        alpha = float(np.clip(weight, 0.0, 1.0))
        return torch.where(
            has_soft,
            alpha * soft_loss + (1.0 - alpha) * hard_loss,
            hard_loss,
        )
    if semantics != POLICY_TARGET_BLEND_FALLBACK_V2:
        raise ValueError(f"unsupported policy-target blend semantics {semantics!r}")
    if weight == 0.0:
        return hard_loss
    if weight != 1.0:
        raise ValueError(
            "policy_target_fallback_v2 requires soft_target_weight 0.0 or 1.0"
        )
    return torch.where(has_soft, soft_loss, hard_loss)


def _weighted_mean_from_parts(numerator, denominator):
    """Form one DDP-correct mean after independently accumulated loss parts."""
    import torch

    if torch.is_grad_enabled():
        import torch.distributed as dist

        if dist.is_available() and dist.is_initialized():
            # Never fall back to the local denominator after a collective error.
            # That would silently make each rank optimize a different ratio while
            # DDP still averages their gradients -- exactly the biased mean-of-rank-
            # means estimator this collective exists to prevent.
            global_denominator = denominator.detach().clone()
            dist.all_reduce(global_denominator, op=dist.ReduceOp.SUM)
            return (
                numerator
                * float(dist.get_world_size())
                / torch.clamp(global_denominator, min=1.0e-6)
            )
    return numerator / torch.clamp(denominator, min=1.0e-6)


def _weighted_loss_parts(
    values,
    weights,
    *,
    mask=None,
    fixed_weight_mean: float | None = None,
):
    effective_weights = weights
    if mask is not None:
        effective_weights = effective_weights * mask.to(
            device=weights.device,
            dtype=weights.dtype,
        )
    numerator = (values * effective_weights).sum()
    if fixed_weight_mean is None:
        denominator = effective_weights.sum()
    else:
        import torch

        resolved = float(fixed_weight_mean)
        if not math.isfinite(resolved) or resolved < 0.0:
            raise ValueError("fixed loss weight mean must be finite and non-negative")
        denominator = torch.as_tensor(
            resolved * float(values.shape[0]),
            dtype=effective_weights.dtype,
            device=effective_weights.device,
        )
    return numerator, denominator


def _zero_loss_parts(device):
    import torch

    zero = torch.tensor(0.0, dtype=torch.float32, device=device)
    return zero, zero


def _metric_from_sum_denominator(weighted_sum: float, denominator: float) -> float:
    if float(denominator) <= 0.0:
        return 0.0
    return float(weighted_sum) / float(denominator)


def _policy_stream_epoch_metrics(
    weighted_sums: Mapping[str, float],
    denominators: Mapping[str, float],
    *,
    aux_enabled: bool,
    aux_coefficient: float,
) -> dict[str, float]:
    """Reconstruct the independently normalized policy-stream objective.

    When AUX is enabled, training optimizes ``base_mean + c * aux_mean``.
    Multiplying each batch's combined mean by the base denominator and pooling
    those products instead computes a different objective whenever either
    stream's denominator or loss changes across batches. Preserve and combine
    the two streams' sufficient statistics independently instead.
    """

    coefficient = float(aux_coefficient)
    if not math.isfinite(coefficient) or coefficient < 0.0:
        raise ValueError("policy AUX epoch coefficient must be finite and non-negative")

    if not aux_enabled:
        policy_loss = _metric_from_sum_denominator(
            weighted_sums["policy_loss"], denominators["policy_loss"]
        )
        return {
            "policy_loss": policy_loss,
            "policy_base_loss": policy_loss,
            "policy_aux_loss": 0.0,
        }

    required = ("policy_base_loss", "policy_aux_loss")
    missing = [
        key
        for key in required
        if key not in weighted_sums or key not in denominators
    ]
    if missing:
        raise ValueError(
            f"policy stream epoch sufficient statistics are incomplete: {missing}"
        )
    invalid = {
        key: {
            "weighted_sum": weighted_sums[key],
            "denominator": denominators[key],
        }
        for key in required
        if (
            not math.isfinite(float(weighted_sums[key]))
            or not math.isfinite(float(denominators[key]))
            or float(denominators[key]) < 0.0
        )
    }
    if invalid:
        raise ValueError(
            f"policy stream epoch sufficient statistics are invalid: {invalid}"
        )

    base_loss = _metric_from_sum_denominator(
        weighted_sums["policy_base_loss"],
        denominators["policy_base_loss"],
    )
    aux_loss = _metric_from_sum_denominator(
        weighted_sums["policy_aux_loss"],
        denominators["policy_aux_loss"],
    )
    return {
        "policy_loss": base_loss + coefficient * aux_loss,
        "policy_base_loss": base_loss,
        "policy_aux_loss": aux_loss,
    }


def _bounded_count_fraction(numerator: float, denominator: float, *, label: str) -> float:
    """Form a [0, 1] count fraction and reject mixed reduction scopes.

    This is intentionally stricter than a generic ratio.  DDP telemetry once
    all-reduced ``soft_distillation_active_rows`` but divided it by rank-local
    ``epoch_active_count``, producing an impossible 7.95 fraction on eight GPUs.
    Count fractions should fail closed if a future caller mixes global and local
    quantities again.
    """

    numerator = float(numerator)
    denominator = float(denominator)
    tolerance = 1.0e-6 * max(1.0, abs(denominator))
    if numerator < -tolerance or denominator < 0.0 or numerator > denominator + tolerance:
        raise RuntimeError(
            f"{label} has incompatible count scopes: numerator={numerator} "
            f"denominator={denominator}"
        )
    if denominator == 0.0:
        return 0.0
    return min(1.0, max(0.0, numerator / denominator))


def _q_score_loss_parts(
    q_values,
    data: dict,
    batch: np.ndarray,
    weights,
    device,
    *,
    q_skip_teacher_prefixes: tuple[str, ...],
):
    import torch

    scores = np.asarray(data.get("target_scores", np.empty((len(data["action_taken"]), 0)))[batch], dtype=np.float32)
    legal = np.asarray(data["legal_action_ids"][batch], dtype=np.int64)
    if scores.size == 0:
        zero = torch.tensor(0.0, dtype=torch.float32, device=device)
        return zero, zero, zero
    if "target_scores_mask" in data:
        score_mask = np.asarray(data["target_scores_mask"][batch], dtype=np.bool_)
    else:
        score_mask = np.isfinite(scores)
    finite_np = (legal >= 0) & score_mask & np.isfinite(scores)
    skip_rows = _q_skip_rows(data, batch, q_skip_teacher_prefixes)
    if np.any(skip_rows):
        finite_np[skip_rows] = False
    row_has_scores_np = np.sum(finite_np, axis=1) >= 2

    mask = torch.as_tensor(finite_np, dtype=torch.bool, device=device)
    row_has_scores = torch.as_tensor(row_has_scores_np, dtype=torch.float32, device=device)
    targets = torch.as_tensor(
        np.where(finite_np, scores, 0.0),
        dtype=torch.float32,
        device=device,
    )
    counts = mask.sum(dim=1, keepdim=True).clamp_min(1)
    target_mean = (targets * mask.float()).sum(dim=1, keepdim=True) / counts
    centered_targets = torch.where(mask, targets - target_mean, torch.zeros_like(targets))
    target_var = (centered_targets.pow(2) * mask.float()).sum(dim=1, keepdim=True) / counts
    target_std = target_var.sqrt().clamp_min(1.0e-4)
    normalized_targets = centered_targets / target_std

    q_safe = torch.where(mask, q_values, torch.zeros_like(q_values))
    per_row = ((q_safe - normalized_targets).pow(2) * mask.float()).sum(dim=1) / counts.squeeze(1)
    effective_weights = weights * row_has_scores
    loss = _weighted_mean_loss(per_row, effective_weights)
    weighted_sum, denominator = _weighted_loss_parts(per_row, effective_weights)
    return loss, weighted_sum, denominator


def _unflagged_vp_rows(data: dict, values_key: str, flags_key: str) -> np.ndarray:
    values = np.asarray(data.get(values_key, np.zeros((len(data["action_taken"]), 0))), dtype=np.float32)
    flags = np.asarray(
        data.get(flags_key, np.zeros(len(data["action_taken"]), dtype=np.bool_)),
        dtype=np.bool_,
    )
    if values.ndim != 2 or values.shape[0] != len(flags):
        return np.zeros(len(data["action_taken"]), dtype=bool)
    return (np.sum(np.abs(values), axis=1) > 0.0) & ~flags


def _q_score_rows_ge2(
    data: dict,
    batch: np.ndarray,
    *,
    q_skip_teacher_prefixes: tuple[str, ...] = (),
) -> int:
    scores_all = data.get("target_scores")
    if scores_all is None:
        return 0
    scores = np.asarray(scores_all[batch], dtype=np.float32)
    legal = np.asarray(data["legal_action_ids"][batch], dtype=np.int64)
    if scores.shape != legal.shape:
        return 0
    if "target_scores_mask" in data:
        score_mask = np.asarray(data["target_scores_mask"][batch], dtype=np.bool_)
    else:
        score_mask = np.isfinite(scores)
    finite = (legal >= 0) & score_mask & np.isfinite(scores)
    skip_rows = _q_skip_rows(data, batch, q_skip_teacher_prefixes)
    if np.any(skip_rows):
        finite[skip_rows] = False
    return int(np.sum(np.sum(finite, axis=1) >= 2))


def _truncated_vp_margin_outcome(
    data: dict,
    batch: np.ndarray,
    truncated: np.ndarray,
    vps_to_win: int,
    *,
    public_information_only: bool = False,
) -> tuple[np.ndarray, np.ndarray]:
    """FIX F3: derive a soft value label for TRUNCATED rows from the VP margin at the
    point of truncation. final_actual_vps/final_public_vps + seat are populated in every
    row regardless of whether the game actually ended -- only the has_final_*_vps flag is
    gated on termination (see gumbel_self_play.py's _game_outcome_fields, which always
    snapshots the live state). Without this, the value head only ever learns from the
    9-19% of games that finish naturally, starving it of signal from the majority.

    margin = clip((my_vp - opponent_vp) / vps_to_win, -1, 1). Since this is always a
    2-seated game, opponent_vp = sum(all 4 PLAYER_NAMES slots) - my_vp (the other two
    slots are unseated and always 0), avoiding any need to know which color is "the
    opponent" explicitly.
    """
    n = len(batch)
    mask = np.zeros(n, dtype=bool)
    outcome = np.zeros(n, dtype=np.float32)
    if "seat" not in data:
        return mask, outcome
    seats = np.asarray(data["seat"][batch], dtype=np.int64)
    rows = np.arange(n)
    # Opponents' actual VP includes hidden victory-point development cards.
    # A public-observation learner must never derive even a low-weight target
    # from that hidden truth.  Its own public score and every opponent's public
    # score are sufficient for the truncation proxy.
    vp_keys = (
        ("final_public_vps",)
        if public_information_only
        else ("final_actual_vps", "final_public_vps")
    )
    for vp_key in vp_keys:
        if vp_key not in data:
            continue
        remaining = truncated & ~mask & (seats >= 0)
        if not remaining.any():
            continue
        vps = np.asarray(data[vp_key][batch], dtype=np.float32)
        valid = remaining & (seats < vps.shape[1])
        if not valid.any():
            continue
        my_vp = vps[rows[valid], seats[valid]]
        opponent_vp = vps[valid].sum(axis=1) - my_vp
        margin = (my_vp - opponent_vp) / max(float(vps_to_win), 1.0)
        outcome[valid] = np.clip(margin, -1.0, 1.0)
        mask[valid] = True
    return mask, outcome


_KNOWN_VALUE_ROOT_BLEND_PHASES = frozenset(
    {
        "BUILD_INITIAL_SETTLEMENT",
        "BUILD_INITIAL_ROAD",
        "DISCARD",
        "MOVE_ROBBER",
        "DECIDE_TRADE",
        "DECIDE_ACCEPTEES",
        "PLAY_TURN",
    }
)


def _parse_value_root_blend_phases(value: str | tuple[str, ...]) -> tuple[str, ...]:
    raw = value if isinstance(value, tuple) else tuple(str(value).split(","))
    phases = tuple(dict.fromkeys(part.strip().upper() for part in raw if part.strip()))
    unknown = sorted(set(phases) - _KNOWN_VALUE_ROOT_BLEND_PHASES)
    if unknown:
        raise SystemExit(
            "unknown --value-root-blend-phases value(s): "
            + ", ".join(unknown)
            + "; known phases are "
            + ", ".join(sorted(_KNOWN_VALUE_ROOT_BLEND_PHASES))
        )
    return phases


def _resolve_value_root_blend_regime(args) -> dict[str, object]:
    """Keep root-target blending disabled until its authority is authenticated.

    ``lambda=1`` stays an exact no-op. Lower-level blend helpers remain in place
    for eventual authenticated admission and focused operator tests, but neither
    a phase name nor the legacy global flag is target provenance.
    """

    lam = float(getattr(args, "value_target_lambda", 1.0))
    phases = _parse_value_root_blend_phases(
        getattr(args, "value_root_blend_phases", "")
    )
    global_compat = bool(getattr(args, "value_root_blend_global_compat", False))
    if phases and global_compat:
        raise SystemExit(
            "--value-root-blend-phases and --value-root-blend-global-compat are "
            "mutually exclusive"
        )
    if lam != 1.0:
        raise SystemExit(
            "--value-target-lambda < 1 is disabled because authenticated "
            "root-target admission is not implemented; use "
            "--value-target-lambda 1.0 until every active target is bound to "
            "an authenticated producer, operator, payload, and per-row mask"
        )
    return {
        "schema_version": "value-root-blend-regime-v1",
        "mode": "phase_gated" if phases else ("global_compat" if global_compat else "disabled"),
        "lambda": lam,
        "phases": list(phases),
    }


def _value_root_phase_mask(
    data: dict,
    batch: np.ndarray,
    phases: tuple[str, ...],
    *,
    global_compat: bool,
) -> np.ndarray:
    if global_compat:
        return np.ones(len(batch), dtype=np.bool_)
    if not phases or "phase" not in data:
        return np.zeros(len(batch), dtype=np.bool_)
    observed = np.char.upper(np.asarray(data["phase"][batch]).astype(str))
    return np.isin(observed, np.asarray(phases, dtype=str))


def _value_root_blend_mask(
    data: dict,
    batch: np.ndarray,
    device,
    root_value_mask,
    value_has_outcome,
    truncated_mask,
    *,
    phases: tuple[str, ...] = (),
    global_compat: bool = False,
):
    import torch

    phase_mask = torch.as_tensor(
        _value_root_phase_mask(data, batch, phases, global_compat=global_compat),
        dtype=torch.bool,
        device=device,
    )
    # Truncated games and missing/invalid search roots retain pure z. This also
    # keeps scalar and categorical objectives on exactly the same row operator.
    return phase_mask & root_value_mask & value_has_outcome & ~truncated_mask


def _audit_value_root_blend_corpus(
    data: dict,
    value_sample_weights: np.ndarray,
    *,
    regime: dict[str, object],
    indices: np.ndarray | None = None,
) -> dict[str, object]:
    """Fail-closed corpus realization and durable target-operator telemetry."""

    total_rows = len(data["action_taken"])
    rows = (
        np.arange(total_rows, dtype=np.int64)
        if indices is None
        else np.asarray(indices, dtype=np.int64)
    )
    n = len(rows)
    lam = float(regime["lambda"])
    phases = tuple(str(value) for value in regime["phases"])
    mode = str(regime["mode"])
    report: dict[str, object] = {
        **regime,
        "rows": n,
        "eligible_rows": 0,
        "blended_rows": 0,
        "eligible_weighted_mass": 0.0,
        "blended_weighted_mass": 0.0,
        "per_phase": {},
        "mean_abs_root_minus_z": None,
        "root_value_finite": True,
        "root_value_in_range": True,
        "target_information_regime_counts": {},
        "public_target_information_only": None,
    }
    if "target_information_regime" in data:
        information_column = data["target_information_regime"]
        if bool(getattr(information_column, "supports_value_counts", False)) or isinstance(
            information_column, _MemmapCategoricalColumn
        ):
            report["target_information_regime_counts"] = (
                information_column.value_counts(rows)
            )
        else:
            values, counts = np.unique(
                np.asarray(information_column[rows]).astype(str),
                return_counts=True,
            )
            report["target_information_regime_counts"] = {
                str(value): int(count)
                for value, count in zip(values, counts, strict=True)
            }
        report["public_target_information_only"] = set(
            report["target_information_regime_counts"]
        ) == {"public_conservation_pimc_v1"}
    if lam == 1.0:
        return report
    # reanalyze_lite <=1.2 mislabeled a single network forward as a
    # post-search root backup. Quarantine those overlays by their durable
    # materialization schema before any blended target can reach the optimizer.
    components = getattr(data, "corpora", None) or (data,)
    for component in components:
        columns = getattr(component, "meta", {}).get("columns", {})
        materialization = columns.get("root_value", {}).get("materialization", {})
        if (
            isinstance(materialization, dict)
            and materialization.get("schema")
            == "catan_zero_root_value_materialization_v1"
        ):
            raise SystemExit(
                "requested root-value blend includes a legacy direct-forward "
                "root_value overlay; regenerate targets with a true sealed search "
                "reanalysis"
            )
    if "root_value" not in data:
        raise SystemExit("requested root-value blend but corpus has no root_value column")
    root = np.asarray(data["root_value"][rows], dtype=np.float32).reshape(n)
    mask = np.asarray(
        (
            data["root_value_mask"][rows]
            if "root_value_mask" in data
            else np.isfinite(root)
        ),
        dtype=np.bool_,
    ).reshape(n)
    masked_finite = np.isfinite(root[mask])
    masked_range = np.abs(root[mask]) <= 1.0
    report["root_value_finite"] = bool(np.all(masked_finite))
    report["root_value_in_range"] = bool(np.all(masked_range))
    if not report["root_value_finite"] or not report["root_value_in_range"]:
        raise SystemExit(
            "requested root-value blend contains masked non-finite or out-of-range "
            "root_value values; expected finite [-1, 1]"
        )
    phase_mask = _value_root_phase_mask(
        data, rows, phases, global_compat=(mode == "global_compat")
    )
    truncated = np.asarray(
        data["truncated"][rows] if "truncated" in data else np.zeros(n),
        dtype=np.bool_,
    )
    # Outcome existence is deliberately conservative and public: winner labels
    # are the realized z source. Rows without one retain pure z/no blend.
    winner = np.asarray(
        data["winner"][rows] if "winner" in data else np.full(n, "")
    ).astype(str)
    has_outcome = winner != ""
    eligible = phase_mask & mask & has_outcome & ~truncated
    weights = np.asarray(value_sample_weights[rows], dtype=np.float64)
    report["eligible_rows"] = int(np.sum(eligible))
    report["blended_rows"] = int(np.sum(eligible))
    report["eligible_weighted_mass"] = float(np.sum(weights[eligible]))
    report["blended_weighted_mass"] = float(np.sum(weights[eligible]))
    observed_phases = np.asarray(
        data["phase"][rows] if "phase" in data else np.full(n, "")
    ).astype(str)
    report["per_phase"] = {
        phase: {
            "eligible_rows": int(np.sum(eligible & (np.char.upper(observed_phases) == phase))),
            "weighted_mass": float(
                np.sum(weights[eligible & (np.char.upper(observed_phases) == phase)])
            ),
        }
        for phase in (phases or tuple(sorted(set(np.char.upper(observed_phases[eligible])))))
    }
    if not np.any(eligible) or float(report["blended_weighted_mass"]) <= 0.0:
        raise SystemExit(
            "requested root-value blend realized zero eligible rows or weighted mass "
            "after phase, outcome, truncation, root-value, and learner-weight masks"
        )
    if "player" in data:
        player = np.asarray(data["player"][rows]).astype(str)
        z = np.where(player == winner, 1.0, -1.0)
        report["mean_abs_root_minus_z"] = float(
            np.average(np.abs(root[eligible] - z[eligible]), weights=weights[eligible])
        )
    return report


def _root_value_targets(data: dict, batch: np.ndarray, device):
    """Read the stored search root value (`root_value` + `root_value_mask`) for
    the CAT-39 value-target lambda blend (MuZero/ReZero, arXiv:2404.16364).

    Returns (root_value[B], root_value_mask[B]) as torch tensors, or (None, None)
    when the shard has no root_value column (every current shard) so the blend is
    a pure no-op and inert -- a gen-1-onward lever. root_value is expected in the
    same [-1, 1] value scale as the outcome target; rows without a stored value
    are masked (NaNs treated as unset).
    """
    import torch

    if "root_value" not in data:
        return None, None
    n = len(batch)
    raw = np.asarray(data["root_value"][batch], dtype=np.float32).reshape(n)
    if "root_value_mask" in data:
        mask = np.asarray(data["root_value_mask"][batch], dtype=np.bool_).reshape(n)
    else:
        mask = np.isfinite(raw)
    mask = mask & np.isfinite(raw)
    values = np.where(mask, raw, 0.0).astype(np.float32)
    return (
        torch.as_tensor(values, dtype=torch.float32, device=device),
        torch.as_tensor(mask, dtype=torch.bool, device=device),
    )


def _hl_gauss_value_targets(
    targets,
    bins: int,
    *,
    sigma_ratio: float = 0.75,
    truncated=None,
    add_truncation_class: bool = True,
):
    """HL-Gauss projection (Farebrother et al. 2024, arXiv:2403.03950 "Stop
    Regressing") of scalar win-loss targets in [-1, 1] onto a uniform categorical
    support of `bins` atoms.

    Each scalar target y is smeared as a Gaussian of std ``sigma = sigma_ratio *
    bin_width`` and integrated over atom-centred cells via the Gaussian CDF
    (erf); the outer cells extend to +/-inf so tail mass beyond the support is
    captured rather than clipped. This is the regression-as-classification target
    that beats both plain two-hot (which underperforms MSE) and scalar MSE,
    especially under stochastic dynamics.

    Returns a row-stochastic ``[B, bins (+1 when add_truncation_class)]`` tensor.
    When ``truncated`` is given, those rows are routed ENTIRELY to the extra
    truncation class (one-hot) with zero mass on the win-loss bins -- the CAT-39
    R9 support (win/loss + truncation ONLY; VP-margin routes to a separate aux
    head), never a margin bump on the continuous axis. The support expectation
    over the win-loss atoms recovers the (clamped) scalar target to within the
    bin resolution, which is what the scalar readout consumes downstream.
    """
    import torch

    n = int(targets.shape[0])
    device = targets.device
    n_out = int(bins) + (1 if add_truncation_class else 0)
    out = torch.zeros((n, n_out), dtype=torch.float32, device=device)
    centers = torch.linspace(-1.0, 1.0, int(bins), device=device)
    bin_width = 2.0 / float(int(bins) - 1)
    sigma = max(float(sigma_ratio), 1.0e-6) * bin_width
    lower = centers - bin_width / 2.0
    upper = centers + bin_width / 2.0
    lower = lower.clone()
    upper = upper.clone()
    lower[0] = float("-inf")
    upper[-1] = float("inf")
    y = targets.detach().float().clamp(-1.0, 1.0).unsqueeze(-1)
    inv = 1.0 / (sigma * math.sqrt(2.0))
    cdf_hi = 0.5 * (1.0 + torch.erf((upper.unsqueeze(0) - y) * inv))
    cdf_lo = 0.5 * (1.0 + torch.erf((lower.unsqueeze(0) - y) * inv))
    probs = (cdf_hi - cdf_lo).clamp_min(0.0)
    probs = probs / probs.sum(dim=-1, keepdim=True).clamp_min(1.0e-8)
    out[:, : int(bins)] = probs
    if truncated is not None and add_truncation_class:
        tmask = truncated.to(device=device, dtype=torch.bool)
        if bool(tmask.any().item()):
            out[tmask] = 0.0
            out[tmask, int(bins)] = 1.0
    return out


def _policy_value_categorical_bins(policy: object) -> int:
    """Read categorical support width through optional DDP wrapping."""

    model = getattr(policy, "model", None)
    model = getattr(model, "module", model)
    try:
        bins = int(getattr(model, "value_categorical_bins"))
    except (AttributeError, TypeError, ValueError) as error:
        raise RuntimeError(
            "categorical value objective requires a model with an integer "
            "value_categorical_bins attribute"
        ) from error
    if bins < 2:
        raise RuntimeError(
            "categorical value objective requires value_categorical_bins >= 2"
        )
    return bins


def _scalar_value_outcome_targets_np(
    data: dict,
    batch: np.ndarray,
    vps_to_win: int,
    *,
    truncated_vp_margin_value_weight: float = 0.0,
    public_information_only: bool | None = None,
) -> tuple[
    np.ndarray,
    np.ndarray,
    np.ndarray,
    np.ndarray,
    np.ndarray,
    np.ndarray,
]:
    """Build the exact scalar-outcome target mask and confidence on CPU."""

    winners = np.asarray(data["winner"][batch]).astype(str)
    players = np.asarray(data["player"][batch]).astype(str)
    truncated = _batch_array_or_fill(
        data,
        "truncated",
        batch,
        False,
        dtype=np.bool_,
    )
    has_outcome = (winners != "") & ~truncated
    outcome = np.zeros(len(batch), dtype=np.float32)
    outcome[has_outcome & (winners == players)] = 1.0
    outcome[has_outcome & (winners != players)] = -1.0
    value_outcome = outcome.copy()
    value_has_outcome = has_outcome.copy()
    confidence = np.where(has_outcome, 1.0, 0.0).astype(np.float32)
    if float(truncated_vp_margin_value_weight) > 0.0 and truncated.any():
        if public_information_only is None:
            public_information_only = _MASK_HIDDEN_INFO_PLAYER_TOKENS
        soft_mask, soft_outcome = _truncated_vp_margin_outcome(
            data,
            batch,
            truncated,
            vps_to_win,
            public_information_only=bool(public_information_only),
        )
        fill = soft_mask & ~has_outcome
        value_outcome[fill] = soft_outcome[fill]
        value_has_outcome |= fill
        confidence[fill] = float(truncated_vp_margin_value_weight)
    return (
        outcome,
        has_outcome,
        value_outcome,
        value_has_outcome,
        confidence,
        truncated,
    )


def _scalar_value_outcome_confidence_for_rows(
    data: dict,
    rows: np.ndarray,
    vps_to_win: int,
    *,
    truncated_vp_margin_value_weight: float = 0.0,
    public_information_only: bool | None = None,
    chunk_rows: int = 1 << 20,
) -> np.ndarray:
    """Return exact scalar-value eligibility/confidence with bounded decoding."""

    indices = np.asarray(rows, dtype=np.int64)
    if indices.ndim != 1:
        raise ValueError("scalar value confidence rows must be one-dimensional")
    chunk_size = int(chunk_rows)
    if chunk_size <= 0:
        raise ValueError("scalar value confidence chunk size must be positive")
    confidence = np.empty(indices.shape[0], dtype=np.float32)
    for start in range(0, indices.shape[0], chunk_size):
        stop = min(start + chunk_size, indices.shape[0])
        (
            _outcome,
            _has_outcome,
            _value_outcome,
            _value_has_outcome,
            chunk_confidence,
            _truncated,
        ) = _scalar_value_outcome_targets_np(
            data,
            indices[start:stop],
            vps_to_win,
            truncated_vp_margin_value_weight=truncated_vp_margin_value_weight,
            public_information_only=public_information_only,
        )
        confidence[start:stop] = chunk_confidence
    return confidence


def _value_targets(
    data: dict,
    batch: np.ndarray,
    device,
    vps_to_win: int,
    *,
    truncated_vp_margin_value_weight: float = 0.0,
    public_information_only: bool | None = None,
):
    import torch

    if "winner" not in data or "player" not in data:
        return None, None, None, None, None, None, None
    # The policy advantage view (outcome/has_outcome_np) intentionally remains
    # separate from the scalar value-loss view, which may admit confidence-
    # weighted truncated VP-margin targets.
    (
        outcome,
        has_outcome_np,
        value_outcome,
        value_has_outcome_np,
        outcome_confidence,
        truncated,
    ) = _scalar_value_outcome_targets_np(
        data,
        batch,
        vps_to_win,
        truncated_vp_margin_value_weight=truncated_vp_margin_value_weight,
        public_information_only=public_information_only,
    )
    vp_target = np.zeros(len(batch), dtype=np.float32)
    has_vp_np = np.zeros(len(batch), dtype=bool)
    if "seat" in data and "final_actual_vps" in data:
        seats = np.asarray(data["seat"][batch], dtype=np.int64)
        rows = np.arange(len(batch))
        actual_vps = np.asarray(data["final_actual_vps"][batch], dtype=np.float32)
        has_actual = _batch_array_or_fill(
            data,
            "has_final_actual_vps",
            batch,
            False,
            dtype=np.bool_,
        )
        valid_actual = (
            (seats >= 0)
            & (seats < actual_vps.shape[1])
            & ~truncated
            & has_actual
        )
        vp_target[valid_actual] = actual_vps[rows[valid_actual], seats[valid_actual]]
        has_vp_np[valid_actual] = True
    if "seat" in data and "final_public_vps" in data:
        seats = np.asarray(data["seat"][batch], dtype=np.int64)
        rows = np.arange(len(batch))
        public_vps = np.asarray(data["final_public_vps"][batch], dtype=np.float32)
        has_public = _batch_array_or_fill(
            data,
            "has_final_public_vps",
            batch,
            False,
            dtype=np.bool_,
        )
        valid_public = (
            ~has_vp_np
            & (seats >= 0)
            & (seats < public_vps.shape[1])
            & ~truncated
            & has_public
        )
        vp_target[valid_public] = public_vps[rows[valid_public], seats[valid_public]]
        has_vp_np[valid_public] = True
    vp_target[has_vp_np] /= max(float(vps_to_win), 1.0)
    return (
        torch.as_tensor(outcome, dtype=torch.float32, device=device),
        torch.as_tensor(vp_target, dtype=torch.float32, device=device),
        torch.as_tensor(has_outcome_np, dtype=torch.bool, device=device),
        torch.as_tensor(has_vp_np, dtype=torch.bool, device=device),
        torch.as_tensor(value_outcome, dtype=torch.float32, device=device),
        torch.as_tensor(value_has_outcome_np, dtype=torch.bool, device=device),
        torch.as_tensor(outcome_confidence, dtype=torch.float32, device=device),
    )


def _validate_value_outcome_labels(
    data: Mapping[str, object],
    *,
    chunk_rows: int = 1 << 20,
) -> dict[str, object]:
    """Fail closed before a malformed winner becomes a universal ``-1`` label.

    ``_value_targets`` is intentionally simple: a clean row is positive when
    ``winner == player`` and negative otherwise. Without corpus admission, any
    non-empty typo, truncated fixed-width string, or winner from an unseated
    color silently turns every row in that game into a loss. Validate the
    actor/seat domain and accumulate per-game seated-player/winner masks in
    bounded chunks before the first optimizer step.
    """

    if "winner" not in data or "player" not in data:
        return {
            "schema_version": "value-outcome-label-admission-v1",
            "present": False,
            "rows": int(len(data.get("action_taken", ()))),
            "games": 0,
            "clean_outcome_games": 0,
        }
    n = int(len(data["player"]))
    if len(data["winner"]) != n:
        raise SystemExit("winner/player columns are not row-aligned")
    if chunk_rows <= 0:
        raise ValueError("chunk_rows must be positive")
    optional_columns = ("game_seed", "seat", "terminated", "truncated")
    malformed_lengths = {
        name: len(data[name])
        for name in optional_columns
        if name in data and len(data[name]) != n
    }
    if malformed_lengths:
        raise SystemExit(
            "value outcome columns are not row-aligned: "
            f"rows={n}, malformed={malformed_lengths}"
        )

    component_ids = tuple(
        str(value) for value in getattr(data, "component_ids", tuple())
    )
    component_mapper = getattr(data, "component_indices_for_rows", None)
    authenticated_composite = bool(component_ids)
    if authenticated_composite and (
        not callable(component_mapper)
        or "game_seed" not in data
        or any(not value for value in component_ids)
    ):
        raise SystemExit(
            "authenticated composite value outcomes lack component/game provenance"
        )
    if not authenticated_composite:
        component_ids = ("ordinary_corpus",)

    game_player_masks: dict[tuple[int, int], int] = {}
    game_winner_masks: dict[tuple[int, int], int] = {}
    clean_outcome_rows = 0
    for start in range(0, n, int(chunk_rows)):
        stop = min(start + int(chunk_rows), n)
        row_slice = slice(start, stop)
        players = np.asarray(data["player"][row_slice]).astype(str)
        winners = np.asarray(data["winner"][row_slice]).astype(str)
        player_codes = np.asarray(
            [_VALUE_PLAYER_INDEX.get(value, -1) for value in players],
            dtype=np.int8,
        )
        winner_codes = np.asarray(
            [
                -1 if value == "" else _VALUE_PLAYER_INDEX.get(value, -2)
                for value in winners
            ],
            dtype=np.int8,
        )
        invalid_players = np.flatnonzero(player_codes < 0)
        invalid_winners = np.flatnonzero(winner_codes == -2)
        if invalid_players.size or invalid_winners.size:
            examples = {
                "players": sorted(set(players[invalid_players].tolist()))[:8],
                "winners": sorted(set(winners[invalid_winners].tolist()))[:8],
            }
            raise SystemExit(
                "value outcome labels contain unknown player/winner values: "
                f"{examples}"
            )
        if "seat" in data:
            seats = np.asarray(data["seat"][row_slice], dtype=np.int64)
            bad_seats = seats != player_codes.astype(np.int64)
            if np.any(bad_seats):
                index = int(np.flatnonzero(bad_seats)[0])
                raise SystemExit(
                    "value outcome actor/seat perspective mismatch at row "
                    f"{start + index}: player={players[index]!r}, "
                    f"seat={int(seats[index])}, expected={int(player_codes[index])}"
                )
        nonempty = winner_codes >= 0
        clean_outcome_rows += int(np.count_nonzero(nonempty))
        if "truncated" in data:
            truncated = np.asarray(data["truncated"][row_slice], dtype=np.bool_)
            if np.any(nonempty & truncated):
                raise SystemExit("truncated rows carry a non-empty terminal winner")
        if "terminated" in data:
            terminated = np.asarray(data["terminated"][row_slice], dtype=np.bool_)
            if np.any(nonempty & ~terminated):
                raise SystemExit("non-terminal rows carry a non-empty winner")
            if np.any(terminated & ~nonempty):
                raise SystemExit("terminal rows are missing their winner label")

        if "game_seed" not in data:
            continue
        seeds = np.asarray(data["game_seed"][row_slice], dtype=np.int64)
        component_codes = (
            np.asarray(
                component_mapper(
                    np.arange(start, stop, dtype=np.int64)
                ),
                dtype=np.int64,
            )
            if authenticated_composite
            else np.zeros(stop - start, dtype=np.int64)
        )
        if (
            component_codes.shape != seeds.shape
            or np.any(component_codes < 0)
            or np.any(component_codes >= len(component_ids))
        ):
            raise SystemExit(
                "authenticated composite outcome component mapping is invalid"
            )
        unique_keys, inverse = np.unique(
            np.rec.fromarrays(
                (component_codes, seeds), names=("component", "seed")
            ),
            return_inverse=True,
        )
        player_masks = np.zeros(len(unique_keys), dtype=np.uint8)
        winner_masks = np.zeros(len(unique_keys), dtype=np.uint8)
        np.bitwise_or.at(
            player_masks,
            inverse,
            np.left_shift(np.uint8(1), player_codes.astype(np.uint8)),
        )
        if np.any(nonempty):
            np.bitwise_or.at(
                winner_masks,
                inverse[nonempty],
                np.left_shift(
                    np.uint8(1), winner_codes[nonempty].astype(np.uint8)
                ),
            )
        for key, player_mask, winner_mask in zip(
            unique_keys, player_masks, winner_masks, strict=True
        ):
            game_key = (int(key["component"]), int(key["seed"]))
            game_player_masks[game_key] = game_player_masks.get(game_key, 0) | int(
                player_mask
            )
            game_winner_masks[game_key] = game_winner_masks.get(game_key, 0) | int(
                winner_mask
            )

    malformed_games = []
    clean_outcome_games = 0
    bilateral_games = 0
    one_sided_games = 0
    one_sided_winner_unobserved_games = 0
    component_reports = {
        component_id: {
            "games": 0,
            "clean_outcome_games": 0,
            "bilateral_games": 0,
            "one_sided_games": 0,
            "one_sided_winner_unobserved_games": 0,
        }
        for component_id in component_ids
    }
    for (component_index, seed), player_mask in game_player_masks.items():
        winner_mask = game_winner_masks.get((component_index, seed), 0)
        component_id = component_ids[component_index]
        component_report = component_reports[component_id]
        component_report["games"] += 1
        observed_players = int(player_mask).bit_count()
        if winner_mask:
            clean_outcome_games += 1
            component_report["clean_outcome_games"] += 1
        if observed_players >= 2:
            bilateral_games += 1
            component_report["bilateral_games"] += 1
        elif observed_players == 1:
            one_sided_games += 1
            component_report["one_sided_games"] += 1
            if winner_mask and winner_mask & player_mask == 0:
                one_sided_winner_unobserved_games += 1
                component_report["one_sided_winner_unobserved_games"] += 1
        malformed_winner = bool(
            winner_mask
            and (
                (winner_mask & (winner_mask - 1)) != 0
                or (observed_players >= 2 and winner_mask & player_mask == 0)
            )
        )
        if observed_players == 0 or malformed_winner:
            malformed_games.append(
                {
                    "component_id": component_id,
                    "game_seed": seed,
                    "seated_player_mask": player_mask,
                    "winner_mask": winner_mask,
                    "observed_player_count": observed_players,
                }
            )
            if len(malformed_games) >= 8:
                break
    if malformed_games:
        raise SystemExit(
            "value outcome winner is inconsistent or not seated in its game: "
            f"{malformed_games}"
        )
    return {
        "schema_version": "value-outcome-label-admission-v1",
        "present": True,
        "rows": n,
        "games": len(game_player_masks),
        "clean_outcome_rows": clean_outcome_rows,
        "clean_outcome_games": clean_outcome_games,
        "bilateral_games": bilateral_games,
        "one_sided_games": one_sided_games,
        "one_sided_winner_unobserved_games": one_sided_winner_unobserved_games,
        "player_domain": list(_VALUE_PLAYER_NAMES),
        "actor_seat_perspective_verified": "seat" in data,
        "winner_seated_per_game_verified": "game_seed" in data,
        "bilateral_winner_seated_per_game_verified": "game_seed" in data,
        "game_identity_namespace": (
            "component_id+game_seed"
            if authenticated_composite
            else "game_seed"
            if "game_seed" in data
            else "none"
        ),
        "components": component_reports,
    }


def _masked_metric_mean(values, mask):
    import torch

    mask = mask.to(device=values.device, dtype=torch.bool)
    if not torch.any(mask):
        return torch.tensor(0.0, dtype=values.dtype, device=values.device)
    return values[mask].mean()


def _topk_legal_accuracy(logits, target, *, k: int, mask=None):
    import torch

    k = min(int(k), int(logits.shape[-1]))
    topk = torch.topk(logits, k=k, dim=-1).indices
    hits = (topk == target.unsqueeze(-1)).any(dim=-1).float()
    if mask is not None:
        return _masked_metric_mean(hits, mask)
    return hits.mean()


def _topk_full_accuracy(masked_logits, actions, *, k: int, mask=None):
    import torch

    k = min(int(k), int(masked_logits.shape[-1]))
    topk = torch.topk(masked_logits, k=k, dim=-1).indices
    hits = (topk == actions.unsqueeze(-1)).any(dim=-1).float()
    if mask is not None:
        return _masked_metric_mean(hits, mask)
    return hits.mean()


_POLICY_TARGET_METRIC_SUM_KEYS = (
    "teacher_argmax_top1_correct",
    "teacher_argmax_top3_correct",
    "cross_entropy_sum",
    "target_entropy_sum",
    "kl_target_model_sum",
    "excess_cross_entropy_sum",
    "model_top1_target_mass_sum",
    "model_top3_target_mass_sum",
)


def _empty_policy_target_metric_parts() -> dict[str, float]:
    return {
        "rows": 0.0,
        **{key: 0.0 for key in _POLICY_TARGET_METRIC_SUM_KEYS},
    }


def _policy_target_metric_parts(
    logits,
    soft_targets,
    has_soft,
    active,
    support,
) -> dict[str, np.ndarray]:
    """Return per-row teacher-distribution diagnostics without another forward.

    ``action_taken`` is a temperature sample from the search policy and is not
    the supervised target when soft distillation is active.  These diagnostics
    therefore compare the model with the complete stored teacher distribution.
    """

    import torch

    if soft_targets is None:
        return {}
    eligible = has_soft.to(dtype=torch.bool) & active.to(dtype=torch.bool)
    if not torch.any(eligible):
        return {}
    log_probs = _support_log_softmax(logits, support)
    targets = soft_targets.float()
    teacher_argmax = torch.argmax(targets, dim=-1)
    model_top3 = torch.topk(
        logits,
        k=min(3, int(logits.shape[-1])),
        dim=-1,
    ).indices
    cross_entropy = -(targets * log_probs).sum(dim=-1)
    target_entropy = -(
        targets
        * torch.where(
            targets > 0.0,
            torch.log(torch.clamp(targets, min=1.0e-30)),
            torch.zeros_like(targets),
        )
    ).sum(dim=-1)
    model_top1 = model_top3[:, 0]
    top1_mass = targets.gather(1, model_top1.unsqueeze(-1)).squeeze(-1)
    top3_mass = targets.gather(1, model_top3).sum(dim=-1)
    selected = eligible.detach().cpu().numpy().astype(np.bool_, copy=False)
    return {
        "eligible": selected,
        "teacher_argmax_top1_correct": (
            model_top1 == teacher_argmax
        ).detach().cpu().numpy().astype(np.float64, copy=False),
        "teacher_argmax_top3_correct": (
            model_top3 == teacher_argmax.unsqueeze(-1)
        ).any(dim=-1).detach().cpu().numpy().astype(np.float64, copy=False),
        "cross_entropy_sum": cross_entropy.detach().float().cpu().numpy(),
        "target_entropy_sum": target_entropy.detach().float().cpu().numpy(),
        "kl_target_model_sum": (
            cross_entropy - target_entropy
        ).detach().float().cpu().numpy(),
        # Kept separately in the schema because it is the most interpretable
        # optimization gap, even though CE-H(target) is algebraically the same
        # quantity as KL(target||model).
        "excess_cross_entropy_sum": (
            cross_entropy - target_entropy
        ).detach().float().cpu().numpy(),
        "model_top1_target_mass_sum": top1_mass.detach().float().cpu().numpy(),
        "model_top3_target_mass_sum": top3_mass.detach().float().cpu().numpy(),
    }


def _sum_policy_target_metric_rows(
    row_metrics: Mapping[str, np.ndarray],
    mask: np.ndarray | None = None,
    *,
    weights: np.ndarray | None = None,
) -> dict[str, float]:
    if not row_metrics:
        return _empty_policy_target_metric_parts()
    selected = np.asarray(
        row_metrics["eligible"], dtype=np.bool_
    ).copy()
    if mask is not None:
        selected &= np.asarray(mask, dtype=np.bool_)
    result = _empty_policy_target_metric_parts()
    selected_weights = None
    if weights is None:
        result["rows"] = float(np.count_nonzero(selected))
    else:
        all_weights = np.asarray(weights, dtype=np.float64)
        if all_weights.shape != selected.shape:
            raise ValueError("policy target metric weight shape drift")
        if not np.isfinite(all_weights).all() or np.any(all_weights < 0.0):
            raise ValueError("policy target metric weights must be finite and >= 0")
        selected_weights = all_weights[selected]
        result["rows"] = float(np.sum(selected_weights))
    for key in _POLICY_TARGET_METRIC_SUM_KEYS:
        values = np.asarray(row_metrics[key], dtype=np.float64)[selected]
        result[key] = float(
            values.sum()
            if selected_weights is None
            else np.dot(values, selected_weights)
        )
    return result


def _policy_target_distribution_stats(
    data: object,
    batch: np.ndarray,
    logits,
    soft_targets,
    has_soft,
    active,
    support,
    *,
    objective_weights: np.ndarray | None = None,
) -> dict[str, object]:
    row_metrics = _policy_target_metric_parts(
        logits, soft_targets, has_soft, active, support
    )
    result: dict[str, object] = {
        "schema_version": "policy-target-distribution-sufficient-stats-v1",
        "overall": _sum_policy_target_metric_rows(row_metrics),
        "objective_weighted_overall": _sum_policy_target_metric_rows(
            row_metrics, weights=objective_weights
        ),
        "phase": {},
        "opening_decision_index": {},
    }
    if not row_metrics:
        return result
    phases = (
        np.asarray(data["phase"][batch]).astype(str)
        if "phase" in data
        else np.full(len(batch), "unknown", dtype="<U7")
    )
    phase_stats = result["phase"]
    assert isinstance(phase_stats, dict)
    for phase in sorted(set(phases.tolist())):
        phase_stats[str(phase)] = _sum_policy_target_metric_rows(
            row_metrics, phases == phase
        )
    opening = phases == "BUILD_INITIAL_SETTLEMENT"
    if np.any(opening):
        decision_indices = np.asarray(
            _batch_array_or_fill(
                data,
                "decision_index",
                batch,
                -1,
                dtype=np.int64,
            ),
            dtype=np.int64,
        )
        opening_stats = result["opening_decision_index"]
        assert isinstance(opening_stats, dict)
        for decision_index in sorted(set(decision_indices[opening].tolist())):
            opening_stats[str(int(decision_index))] = (
                _sum_policy_target_metric_rows(
                    row_metrics,
                    opening & (decision_indices == decision_index),
                )
            )
    return result


def _merge_policy_target_distribution_stats(
    target: dict[str, object],
    source: Mapping[str, object],
) -> None:
    if not source:
        return
    if not target:
        target.update(
            {
                "schema_version": (
                    "policy-target-distribution-sufficient-stats-v1"
                ),
                "overall": _empty_policy_target_metric_parts(),
                "objective_weighted_overall": _empty_policy_target_metric_parts(),
                "phase": {},
                "opening_decision_index": {},
            }
        )
    for axis in (
        "overall",
        "objective_weighted_overall",
        "phase",
        "opening_decision_index",
    ):
        source_axis = source.get(axis)
        if axis in {"overall", "objective_weighted_overall"}:
            if not isinstance(source_axis, Mapping):
                continue
            target_axis = target.setdefault(
                axis, _empty_policy_target_metric_parts()
            )
            assert isinstance(target_axis, dict)
            for key in ("rows", *_POLICY_TARGET_METRIC_SUM_KEYS):
                target_axis[key] = float(target_axis.get(key, 0.0)) + float(
                    source_axis.get(key, 0.0)
                )
            continue
        if not isinstance(source_axis, Mapping):
            continue
        target_axis = target.setdefault(axis, {})
        assert isinstance(target_axis, dict)
        for label, parts in source_axis.items():
            if not isinstance(parts, Mapping):
                continue
            target_parts = target_axis.setdefault(
                str(label), _empty_policy_target_metric_parts()
            )
            for key in ("rows", *_POLICY_TARGET_METRIC_SUM_KEYS):
                target_parts[key] = float(target_parts.get(key, 0.0)) + float(
                    parts.get(key, 0.0)
                )


def _reduce_policy_target_distribution_stats(
    stats: dict[str, object],
    ddp: dict[str, int | bool],
) -> dict[str, object]:
    if not ddp["enabled"]:
        return stats
    import torch.distributed as dist

    gathered: list[dict[str, object] | None] = [None] * int(ddp["world_size"])
    dist.all_gather_object(gathered, stats)
    merged: dict[str, object] = {}
    for item in gathered:
        if item:
            _merge_policy_target_distribution_stats(merged, item)
    return merged


def _finalize_policy_target_metric_parts(
    parts: Mapping[str, object],
    *,
    rows_are_density: bool = False,
) -> dict[str, float | int]:
    rows = float(parts.get("rows", 0.0))
    denominator = rows if rows > 0.0 else 1.0
    result: dict[str, float | int] = {
        "teacher_argmax_top1_accuracy": float(
            parts.get("teacher_argmax_top1_correct", 0.0)
        )
        / denominator,
        "teacher_argmax_top3_accuracy": float(
            parts.get("teacher_argmax_top3_correct", 0.0)
        )
        / denominator,
        "soft_target_cross_entropy": float(
            parts.get("cross_entropy_sum", 0.0)
        )
        / denominator,
        "target_entropy": float(parts.get("target_entropy_sum", 0.0))
        / denominator,
        "kl_target_model": float(parts.get("kl_target_model_sum", 0.0))
        / denominator,
        "excess_cross_entropy_above_target_entropy": float(
            parts.get("excess_cross_entropy_sum", 0.0)
        )
        / denominator,
        "model_top1_target_mass": float(
            parts.get("model_top1_target_mass_sum", 0.0)
        )
        / denominator,
        "model_top3_target_mass": float(
            parts.get("model_top3_target_mass_sum", 0.0)
        )
        / denominator,
    }
    if rows_are_density:
        result["row_probability"] = rows
    else:
        result["rows"] = int(round(rows))
    return result


def _finalize_policy_target_distribution_stats(
    stats: Mapping[str, object],
    *,
    rows_are_density: bool = False,
) -> dict[str, object]:
    result: dict[str, object] = {
        "schema_version": "policy-target-distribution-metrics-v1",
        "weighting": "uniform_soft_target_policy_active_rows",
        "objective_weighted": False,
        "overall": _finalize_policy_target_metric_parts(
            stats.get("overall", {})
            if isinstance(stats.get("overall"), Mapping)
            else {},
            rows_are_density=rows_are_density,
        ),
        "objective_weighted_overall": {
            **_finalize_policy_target_metric_parts(
                stats.get("objective_weighted_overall", {})
                if isinstance(stats.get("objective_weighted_overall"), Mapping)
                else {},
                rows_are_density=True,
            ),
            "weighting": "actual_policy_objective_weight",
        },
    }
    for axis in ("phase", "opening_decision_index"):
        source = stats.get(axis)
        result[axis] = (
            {
                str(label): _finalize_policy_target_metric_parts(
                    parts, rows_are_density=rows_are_density
                )
                for label, parts in sorted(source.items())
                if isinstance(parts, Mapping)
            }
            if isinstance(source, Mapping)
            else {}
        )
    return result


def _field_stats(
    data: dict,
    batch: np.ndarray,
    predictions: np.ndarray,
    targets: np.ndarray,
    logits: np.ndarray,
    *,
    field: str,
) -> dict[str, dict[str, int]]:
    if field in data:
        values = np.asarray(data[field])[batch].astype(str)
    else:
        # The old ``dict.get`` default constructed a full-corpus Python string
        # list eagerly even when ``field`` existed.  Validation calls this for
        # every batch, turning a 12M-row corpus into minutes of CPU allocation
        # per batch.  Missing fields need only one constant per requested row.
        values = np.full(len(batch), "unknown", dtype="<U7")
    top3 = _numpy_topk_contains(logits, targets, k=3)
    stats = _empty_phase_stats()
    for value, pred, target, in_top3 in zip(values, predictions, targets, top3, strict=False):
        key = str(value or "unknown")
        row = stats.setdefault(key, {"count": 0, "top1": 0, "top3": 0})
        row["count"] += 1
        row["top1"] += int(int(pred) == int(target))
        row["top3"] += int(bool(in_top3))
    return stats


def _field_stats_unforced(
    data: dict,
    batch: np.ndarray,
    predictions: np.ndarray,
    targets: np.ndarray,
    logits: np.ndarray,
    *,
    field: str,
) -> dict[str, dict[str, int]]:
    legal_counts = np.sum(data["legal_action_ids"][batch] >= 0, axis=1)
    keep = legal_counts > 1
    if not np.any(keep):
        return {}
    return _field_stats(
        data,
        batch[keep],
        predictions[keep],
        targets[keep],
        logits[keep],
        field=field,
    )


def _numpy_topk_contains(logits: np.ndarray, targets: np.ndarray, *, k: int) -> np.ndarray:
    if logits.shape[1] == 0:
        return np.zeros(len(targets), dtype=bool)
    k = min(int(k), int(logits.shape[1]))
    topk = np.argpartition(-logits, kth=k - 1, axis=1)[:, :k]
    return np.any(topk == targets[:, None], axis=1)


def _empty_phase_stats() -> dict[str, dict[str, int]]:
    return {}


def _merge_phase_stats(
    total: dict[str, dict[str, int]],
    update: dict[str, dict[str, int]],
) -> None:
    for phase, row in update.items():
        target = total.setdefault(str(phase), {"count": 0, "top1": 0, "top3": 0})
        target["count"] += int(row.get("count", 0))
        target["top1"] += int(row.get("top1", 0))
        target["top3"] += int(row.get("top3", 0))


def _reduce_nested_count_stats(
    stats: dict[str, dict[str, int]],
    ddp: dict[str, int | bool],
) -> dict[str, dict[str, int]]:
    if not ddp["enabled"]:
        return stats
    import torch.distributed as dist

    gathered: list[dict[str, dict[str, int]] | None] = [None] * int(ddp["world_size"])
    dist.all_gather_object(gathered, stats)
    merged: dict[str, dict[str, int]] = {}
    for item in gathered:
        if item:
            _merge_phase_stats(merged, item)
    return merged


def _finalize_phase_stats(stats: dict[str, dict[str, int]]) -> dict[str, dict[str, float]]:
    result = {}
    for phase, row in sorted(stats.items()):
        count = int(row.get("count", 0))
        result[phase] = {
            "count": count,
            "top1_accuracy": float(row.get("top1", 0)) / max(count, 1),
            "top3_accuracy": float(row.get("top3", 0)) / max(count, 1),
        }
    return result


def _params(policy):
    yield from policy.model.parameters()


def _optimizer_observability_module_name(parameter_name: str) -> str:
    """Return a stable, compact top-level module label for optimizer telemetry."""
    name = str(parameter_name)
    for prefix in ("module.", "_fsdp_wrapped_module."):
        while name.startswith(prefix):
            name = name[len(prefix) :]
    return name.split(".", 1)[0] or "<root>"


def _objective_gradient_module_name(parameter_name: str) -> str:
    """Keep transformer block indices in objective-interference telemetry."""
    name = str(parameter_name)
    for prefix in ("module.", "_fsdp_wrapped_module."):
        while name.startswith(prefix):
            name = name[len(prefix) :]
    parts = name.split(".")
    if len(parts) >= 2 and parts[0] == "blocks" and parts[1].isdigit():
        return f"blocks.{parts[1]}"
    return parts[0] or "<root>"


def _shared_trunk_named_parameters(policy) -> list[tuple[str, object]]:
    """Select every representation parameter shared by policy and value.

    The legal-action-aware value residual consumes ``encoded_actions`` after
    the mature action encoder and each enabled action-local adapter. Those
    modules are therefore just as shared as the state-token trunk.
    """
    model = policy.model
    module = getattr(model, "module", model)
    action_value_shared = bool(
        getattr(module, "legal_action_value_residual_enabled", False)
    )
    shared_names = list(ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS["trunk"])
    if action_value_shared:
        shared_names.extend(
            (
                *ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS["action_encoder"],
                *ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS["target_gather"],
                *ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS["action_cross"],
                *ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS["static_action_residual"],
            )
        )
    shared_names = tuple(dict.fromkeys(shared_names))
    shared_prefixes = tuple(f"{name}." for name in shared_names)
    selected = []
    for name, parameter in module.named_parameters():
        normalized = str(name)
        while normalized.startswith("_fsdp_wrapped_module."):
            normalized = normalized[len("_fsdp_wrapped_module.") :]
        if parameter.requires_grad and (
            normalized in shared_names or normalized.startswith(shared_prefixes)
        ):
            selected.append((normalized, parameter))
    return selected


def _objective_gradient_interference_due(
    *,
    cadence_batches: int,
    batch_number: int,
    baseline_observed: bool,
    accum_do_step: bool,
) -> bool:
    """Schedule an independent probe and guarantee one short-dose baseline.

    The probe can only be retained on a micro-batch that closes an optimizer
    step. A positive cadence therefore observes the first such batch even when
    the requested interval is longer than the whole dose, then resumes the
    declared batch cadence. This keeps short commissioning runs observable
    without coupling the probe to the separate module-diagnostics cadence.
    """

    cadence = int(cadence_batches)
    if cadence <= 0 or not bool(accum_do_step):
        return False
    return not bool(baseline_observed) or int(batch_number) % cadence == 0


def _objective_gradient_observation_for_step(
    optimizer_observability: Mapping[str, object] | None,
    *,
    global_step: int,
    optimizer_step_applied: bool,
) -> dict[str, object] | None:
    """Bind a retained objective probe to its optimizer step independently."""

    if not isinstance(optimizer_observability, Mapping):
        return None
    observation = optimizer_observability.get("objective_gradient_interference")
    if not isinstance(observation, dict):
        return None
    return {
        **observation,
        "optimizer_step": int(global_step) + int(bool(optimizer_step_applied)),
    }


def _objective_gradient_interference(
    policy,
    *,
    policy_objective,
    value_objective,
    policy_aux_objective=None,
    additional_objectives: Mapping[str, object] | None = None,
    value_trunk_grad_scale: float = 1.0,
) -> dict[str, object]:
    """Measure weighted policy/value gradients in the shared representation.

    ``autograd.grad`` leaves ``Parameter.grad`` and the optimizer trajectory
    untouched. Objectives already include configured loss coefficients. This
    therefore measures what reaches both the state trunk and the shared
    legal-action representation, unlike ``--value-lr-mult``, which only
    changes named value-head parameter groups.

    ``autograd.grad`` does not trigger DDP's reducer, so DDP gradients are
    manually all-reduced and world-averaged before any norms or cosines are
    computed. This reconstructs the gradient that the optimizer actually applies.
    """
    import torch
    import torch.distributed as dist

    model = policy.model
    named = _shared_trunk_named_parameters(policy)
    if not named:
        return {"available": False, "reason": "no_trainable_shared_trunk_parameters"}
    if any(
        not getattr(objective, "requires_grad", False)
        for objective in (policy_objective, value_objective)
    ):
        return {"available": False, "reason": "inactive_policy_or_value_objective"}
    parameters = [parameter for _, parameter in named]
    aux_active = bool(
        policy_aux_objective is not None
        and getattr(policy_aux_objective, "requires_grad", False)
    )
    active_additional_objectives = {
        str(name): objective
        for name, objective in sorted((additional_objectives or {}).items())
        if getattr(objective, "requires_grad", False)
    }
    try:
        policy_grads = torch.autograd.grad(
            policy_objective, parameters, retain_graph=True, allow_unused=True
        )
        value_grads = torch.autograd.grad(
            value_objective, parameters, retain_graph=True, allow_unused=True
        )
        policy_aux_grads = (
            torch.autograd.grad(
                policy_aux_objective,
                parameters,
                retain_graph=True,
                allow_unused=True,
            )
            if aux_active
            else (None,) * len(parameters)
        )
        additional_gradients = {
            name: torch.autograd.grad(
                objective,
                parameters,
                retain_graph=True,
                allow_unused=True,
            )
            for name, objective in active_additional_objectives.items()
        }
    except RuntimeError as exc:
        return {
            "available": False,
            "reason": "autograd_probe_failed",
            "detail": str(exc)[:240],
        }

    distributed = (
        isinstance(model, torch.nn.parallel.DistributedDataParallel)
        and dist.is_available()
        and dist.is_initialized()
    )
    world_size = int(dist.get_world_size()) if distributed else 1

    def _ddp_average_gradients(gradients):
        if not distributed:
            return gradients
        averaged = []
        for parameter, gradient in zip(parameters, gradients, strict=True):
            materialized = (
                torch.zeros_like(parameter)
                if gradient is None
                else gradient.detach().clone()
            )
            dist.all_reduce(materialized, op=dist.ReduceOp.SUM)
            materialized.div_(world_size)
            averaged.append(materialized)
        return tuple(averaged)

    policy_grads = _ddp_average_gradients(policy_grads)
    value_grads = _ddp_average_gradients(value_grads)
    if aux_active:
        policy_aux_grads = _ddp_average_gradients(policy_aux_grads)
    additional_gradients = {
        name: _ddp_average_gradients(gradients)
        for name, gradients in additional_gradients.items()
    }

    def _objective_metric(objective):
        metric = objective.detach().double().clone()
        if distributed:
            dist.all_reduce(metric, op=dist.ReduceOp.SUM)
            metric.div_(world_size)
        return metric

    policy_objective_metric = _objective_metric(policy_objective)
    value_objective_metric = _objective_metric(value_objective)
    policy_aux_objective_metric = (
        _objective_metric(policy_aux_objective) if aux_active else None
    )

    zero = torch.zeros((), dtype=torch.float64, device=parameters[0].device)
    policy_sq = zero.clone()
    value_sq = zero.clone()
    dot = zero.clone()
    policy_base_sq = zero.clone()
    policy_aux_sq = zero.clone()
    policy_base_aux_dot = zero.clone()
    additional_squared_norms = {
        name: zero.clone() for name in active_additional_objectives
    }
    conflict_coordinates = zero.clone()
    joint_coordinates = zero.clone()
    by_module: dict[str, dict[str, object]] = {}
    for parameter_index, ((name, parameter), policy_grad, value_grad, policy_aux_grad) in enumerate(
        zip(named, policy_grads, value_grads, policy_aux_grads, strict=True)
    ):
        if policy_grad is None and value_grad is None and policy_aux_grad is None:
            if not any(
                gradients[parameter_index] is not None
                for gradients in additional_gradients.values()
            ):
                continue
        if policy_grad is None:
            policy_grad = torch.zeros_like(parameter)
        if value_grad is None:
            value_grad = torch.zeros_like(parameter)
        pg = policy_grad.detach().double()
        vg = value_grad.detach().double()
        ag = (
            torch.zeros_like(pg)
            if policy_aux_grad is None
            else policy_aux_grad.detach().double()
        )
        bg = pg - ag
        p_sq = pg.square().sum()
        v_sq = vg.square().sum()
        pv = (pg * vg).sum()
        b_sq = bg.square().sum()
        a_sq = ag.square().sum()
        ba = (bg * ag).sum()
        jointly_nonzero = (pg != 0) & (vg != 0)
        policy_sq += p_sq
        value_sq += v_sq
        dot += pv
        policy_base_sq += b_sq
        policy_aux_sq += a_sq
        policy_base_aux_dot += ba
        for objective_name, gradients in additional_gradients.items():
            objective_gradient = gradients[parameter_index]
            if objective_gradient is not None:
                additional_squared_norms[objective_name] += (
                    objective_gradient.detach().double().square().sum()
                )
        joint_coordinates += jointly_nonzero.sum(dtype=torch.float64)
        conflict_coordinates += (
            jointly_nonzero & ((pg * vg) < 0)
        ).sum(dtype=torch.float64)
        group = _objective_gradient_module_name(name)
        row = by_module.setdefault(
            group,
            {
                "policy_sq": zero.clone(),
                "value_sq": zero.clone(),
                "dot": zero.clone(),
                "policy_base_sq": zero.clone(),
                "policy_aux_sq": zero.clone(),
                "policy_base_aux_dot": zero.clone(),
                "additional_squared_norms": {
                    objective_name: zero.clone()
                    for objective_name in active_additional_objectives
                },
            },
        )
        row["policy_sq"] += p_sq
        row["value_sq"] += v_sq
        row["dot"] += pv
        row["policy_base_sq"] += b_sq
        row["policy_aux_sq"] += a_sq
        row["policy_base_aux_dot"] += ba
        for objective_name, gradients in additional_gradients.items():
            objective_gradient = gradients[parameter_index]
            if objective_gradient is not None:
                row["additional_squared_norms"][objective_name] += (
                    objective_gradient.detach().double().square().sum()
                )

    epsilon = torch.finfo(torch.float64).eps
    policy_norm = torch.sqrt(policy_sq)
    value_norm = torch.sqrt(value_sq)
    denominator = policy_norm * value_norm
    policy_base_norm = torch.sqrt(policy_base_sq)
    policy_aux_norm = torch.sqrt(policy_aux_sq)
    policy_base_aux_denominator = policy_base_norm * policy_aux_norm

    def _float(value) -> float:
        return float(value.detach().cpu().item())

    modules = {}
    for group, row in sorted(by_module.items()):
        p_norm = torch.sqrt(row["policy_sq"])
        v_norm = torch.sqrt(row["value_sq"])
        denom = p_norm * v_norm
        modules[group] = {
            "policy_grad_norm": _float(p_norm),
            "value_grad_norm": _float(v_norm),
            "cosine": _float(row["dot"] / denom.clamp_min(epsilon))
            if _float(denom) > 0.0
            else None,
            "additional_objective_grad_norms": {
                name: _float(torch.sqrt(squared_norm))
                for name, squared_norm in sorted(
                    row["additional_squared_norms"].items()
                )
            },
        }
        if aux_active:
            base_norm = torch.sqrt(row["policy_base_sq"])
            aux_norm = torch.sqrt(row["policy_aux_sq"])
            base_aux_denominator = base_norm * aux_norm
            modules[group].update(
                {
                    "policy_base_grad_norm": _float(base_norm),
                    "policy_aux_grad_norm": _float(aux_norm),
                    "policy_base_aux_cosine": (
                        _float(
                            row["policy_base_aux_dot"]
                            / base_aux_denominator.clamp_min(epsilon)
                        )
                        if _float(base_aux_denominator) > 0.0
                        else None
                    ),
                }
            )
    combined_sq = policy_sq + value_sq + 2.0 * dot
    objective_trunk_grad_l2 = {
        "policy": _float(policy_norm),
        "value": _float(value_norm),
        **(
            {
                "policy_base": _float(policy_base_norm),
                "active_policy": _float(policy_aux_norm),
            }
            if aux_active
            else {}
        ),
        **{
            name: _float(torch.sqrt(squared_norm))
            for name, squared_norm in sorted(additional_squared_norms.items())
        },
    }
    return {
        "available": True,
        "scope": (
            "global_ddp_microbatch"
            if distributed
            else "single_process_microbatch"
        ),
        "aggregation": (
            "manual_all_reduce_then_world_average_of_ddp_scaled_gradients"
            if distributed
            else "single_process_exact_gradient"
        ),
        "world_size": world_size,
        "value_lr_mult_scales_shared_trunk": False,
        "scalar_value_trunk_grad_scale": float(value_trunk_grad_scale),
        "policy_objective": _float(policy_objective_metric),
        "value_objective": _float(value_objective_metric),
        "policy_trunk_grad_norm": _float(policy_norm),
        "value_trunk_grad_norm": _float(value_norm),
        "value_to_policy_grad_norm_ratio": (
            _float(value_norm / policy_norm.clamp_min(epsilon))
            if _float(policy_norm) > 0.0
            else None
        ),
        "trunk_gradient_cosine": (
            _float(dot / denominator.clamp_min(epsilon))
            if _float(denominator) > 0.0
            else None
        ),
        "opposing_coordinate_fraction": (
            _float(conflict_coordinates / joint_coordinates)
            if _float(joint_coordinates) > 0.0
            else None
        ),
        "combined_trunk_grad_norm": _float(torch.sqrt(combined_sq.clamp_min(0.0))),
        "objective_trunk_grad_l2": objective_trunk_grad_l2,
        "feature_path_objective_contract": {
            "public_card": "input_feature_path_not_independent_loss_objective",
            "meaningful_history": "input_feature_path_not_independent_loss_objective",
        },
        "modules": modules,
        **(
            {
                "policy_aux_objective": _float(policy_aux_objective_metric),
                "policy_base_objective": _float(
                    policy_objective_metric - policy_aux_objective_metric
                ),
                "policy_base_trunk_grad_norm": _float(policy_base_norm),
                "policy_aux_trunk_grad_norm": _float(policy_aux_norm),
                "policy_aux_to_base_grad_norm_ratio": (
                    _float(
                        policy_aux_norm / policy_base_norm.clamp_min(epsilon)
                    )
                    if _float(policy_base_norm) > 0.0
                    else None
                ),
                "policy_base_aux_gradient_cosine": (
                    _float(
                        policy_base_aux_dot
                        / policy_base_aux_denominator.clamp_min(epsilon)
                    )
                    if _float(policy_base_aux_denominator) > 0.0
                    else None
                ),
            }
            if aux_active
            else {}
        ),
    }


def _aux_shared_trunk_gradient_geometry(
    policy,
    *,
    main_objective,
    unit_aux_objective,
) -> dict[str, object]:
    """Measure the exact global main/AUX gradient geometry without an update.

    Both objectives must come from one forward pass.  Unlike the historical
    policy-vs-value diagnostic, this routine manually all-reduces each logical
    trunk gradient because ``autograd.grad`` does not trigger DDP's reducer.
    The losses produced by :func:`_weighted_mean_from_parts` are already scaled
    by ``world_size / global_denominator``; averaging the rank gradients here
    therefore reconstructs the gradient of the global objective exactly.

    ``Parameter.grad`` must be empty on entry and remains empty.  This makes the
    result suitable for the commissioned five-batch, no-update AUX selector and
    prevents a probe from contaminating a subsequent optimizer step.
    """

    import torch
    import torch.distributed as dist

    named = _shared_trunk_named_parameters(policy)
    if not named:
        raise RuntimeError("AUX gradient geometry found no inherited trunk parameters")
    if any(parameter.grad is not None for _, parameter in named):
        raise RuntimeError("AUX gradient geometry requires empty Parameter.grad state")
    if any(
        not bool(getattr(objective, "requires_grad", False))
        for objective in (main_objective, unit_aux_objective)
    ):
        raise RuntimeError("AUX gradient geometry objectives are inactive")

    surface = [
        {
            "name": name,
            "shape": [int(value) for value in parameter.shape],
            "dtype": str(parameter.dtype),
        }
        for name, parameter in named
    ]
    parameters = [parameter for _, parameter in named]
    main_gradients = torch.autograd.grad(
        main_objective,
        parameters,
        retain_graph=True,
        allow_unused=True,
    )
    aux_gradients = torch.autograd.grad(
        unit_aux_objective,
        parameters,
        retain_graph=False,
        allow_unused=True,
    )
    distributed = dist.is_available() and dist.is_initialized()
    world_size = int(dist.get_world_size()) if distributed else 1
    main_objective_metric = main_objective.detach().double().clone()
    aux_objective_metric = unit_aux_objective.detach().double().clone()
    if distributed:
        # The DDP-correct weighted objectives are world-size-scaled local
        # numerator contributions. Their rank average is the global scalar,
        # matching the globally reconstructed gradients below.
        dist.all_reduce(main_objective_metric, op=dist.ReduceOp.SUM)
        dist.all_reduce(aux_objective_metric, op=dist.ReduceOp.SUM)
        main_objective_metric.div_(world_size)
        aux_objective_metric.div_(world_size)
    zero = torch.zeros((), dtype=torch.float64, device=parameters[0].device)
    main_sq = zero.clone()
    aux_sq = zero.clone()
    dot = zero.clone()
    opposing = zero.clone()
    jointly_nonzero = zero.clone()
    by_module: dict[str, dict[str, object]] = {}
    for (name, parameter), main_gradient, aux_gradient in zip(
        named, main_gradients, aux_gradients, strict=True
    ):
        main = (
            torch.zeros_like(parameter)
            if main_gradient is None
            else main_gradient.detach().clone()
        )
        aux = (
            torch.zeros_like(parameter)
            if aux_gradient is None
            else aux_gradient.detach().clone()
        )
        if distributed:
            dist.all_reduce(main, op=dist.ReduceOp.SUM)
            dist.all_reduce(aux, op=dist.ReduceOp.SUM)
            main.div_(world_size)
            aux.div_(world_size)
        main64 = main.double()
        aux64 = aux.double()
        parameter_main_sq = main64.square().sum()
        parameter_aux_sq = aux64.square().sum()
        parameter_dot = (main64 * aux64).sum()
        joint = (main64 != 0) & (aux64 != 0)
        main_sq += parameter_main_sq
        aux_sq += parameter_aux_sq
        dot += parameter_dot
        jointly_nonzero += joint.sum(dtype=torch.float64)
        opposing += (joint & ((main64 * aux64) < 0)).sum(dtype=torch.float64)
        module_name = _objective_gradient_module_name(name)
        row = by_module.setdefault(
            module_name,
            {"main_sq": zero.clone(), "aux_sq": zero.clone(), "dot": zero.clone()},
        )
        row["main_sq"] += parameter_main_sq
        row["aux_sq"] += parameter_aux_sq
        row["dot"] += parameter_dot

    if any(parameter.grad is not None for _, parameter in named):
        raise RuntimeError("AUX gradient geometry mutated Parameter.grad state")
    epsilon = torch.finfo(torch.float64).eps
    main_norm = torch.sqrt(main_sq)
    aux_norm = torch.sqrt(aux_sq)
    denominator = main_norm * aux_norm

    def _number(value) -> float:
        return float(value.detach().cpu().item())

    modules: dict[str, dict[str, float | None]] = {}
    for module_name, row in sorted(by_module.items()):
        module_main = torch.sqrt(row["main_sq"])
        module_aux = torch.sqrt(row["aux_sq"])
        module_denominator = module_main * module_aux
        modules[module_name] = {
            "main_gradient_norm": _number(module_main),
            "unit_aux_gradient_norm": _number(module_aux),
            "gradient_dot_product": _number(row["dot"]),
            "gradient_cosine": (
                _number(row["dot"] / module_denominator.clamp_min(epsilon))
                if _number(module_denominator) > 0.0
                else None
            ),
        }
    return {
        "schema_version": "a1-aux-global-gradient-geometry-batch-v1",
        "updates_weights": False,
        "same_forward": True,
        "aggregation": (
            "manual_all_reduce_then_world_average_of_ddp_scaled_gradients"
            if distributed
            else "single_process_exact_gradient"
        ),
        "world_size": world_size,
        "parameter_surface": surface,
        "parameter_surface_sha256": _canonical_json_sha256(surface),
        "main_objective": _number(main_objective_metric),
        "unit_aux_objective": _number(aux_objective_metric),
        # These additive sufficient statistics are the canonical cross-batch
        # evidence.  The commissioned selector concatenates five ordered probe
        # batches by summing them, then derives both norms and cosine itself.
        # Averaging per-batch cosines would answer a different question and can
        # hide cancellation.
        "main_gradient_sq_sum": _number(main_sq),
        "unit_aux_gradient_sq_sum": _number(aux_sq),
        "main_gradient_norm": _number(main_norm),
        "unit_aux_gradient_norm": _number(aux_norm),
        "gradient_dot_product": _number(dot),
        "gradient_cosine": (
            _number(dot / denominator.clamp_min(epsilon))
            if _number(denominator) > 0.0
            else None
        ),
        "opposing_coordinate_fraction": (
            _number(opposing / jointly_nonzero)
            if _number(jointly_nonzero) > 0.0
            else None
        ),
        "modules": modules,
    }


def _rng_json_value(value):
    """Project Python/NumPy RNG state into one canonical JSON value.

    NumPy bit generators do not all use the same state representation: PCG64
    uses Python integers while MT19937 includes ndarrays.  A geometry receipt
    must therefore hash the *actual* state without assuming one generator
    family.  This helper is intentionally private to the no-update probe; the
    normal checkpoint/resume format remains unchanged.
    """

    if value is None or isinstance(value, (bool, int, str)):
        return value
    if isinstance(value, float):
        if not math.isfinite(value):
            raise ValueError("RNG state contains a non-finite float")
        return value
    if isinstance(value, np.generic):
        return _rng_json_value(value.item())
    if isinstance(value, np.ndarray):
        return {
            "dtype": str(value.dtype),
            "shape": [int(size) for size in value.shape],
            "values": _rng_json_value(value.tolist()),
        }
    if isinstance(value, (list, tuple)):
        return [_rng_json_value(item) for item in value]
    if isinstance(value, dict):
        if any(not isinstance(key, str) for key in value):
            raise ValueError("RNG state mappings must use string keys")
        return {
            key: _rng_json_value(item) for key, item in sorted(value.items())
        }
    raise TypeError(f"unsupported RNG state value {type(value).__name__}")


def _torch_rng_state_sha256(state) -> str:
    """Hash an exact uint8 torch RNG state without tensor serialization noise."""

    import torch

    if not isinstance(state, torch.Tensor) or state.dtype != torch.uint8:
        raise TypeError("torch RNG state must be a uint8 Tensor")
    raw = state.detach().cpu().contiguous().numpy().tobytes(order="C")
    return f"sha256:{hashlib.sha256(raw).hexdigest()}"


def _capture_aux_geometry_rng_state(
    *,
    numpy_generators: dict[str, np.random.Generator],
    cuda_device: int | None = None,
) -> dict[str, object]:
    """Capture every process-local RNG stream used by the five-batch probe."""

    import torch

    if not isinstance(numpy_generators, dict) or any(
        not isinstance(name, str)
        or not name
        or not isinstance(generator, np.random.Generator)
        for name, generator in numpy_generators.items()
    ):
        raise TypeError("numpy_generators must map non-empty names to Generators")
    resolved_cuda_device: int | None = None
    cuda_state = None
    if cuda_device is not None:
        if not torch.cuda.is_available():
            raise RuntimeError("CUDA RNG capture requested without CUDA")
        resolved_cuda_device = int(cuda_device)
        cuda_state = torch.cuda.get_rng_state(resolved_cuda_device).clone()
    return {
        "python_random": copy.deepcopy(random.getstate()),
        "numpy": {
            name: copy.deepcopy(generator.bit_generator.state)
            for name, generator in sorted(numpy_generators.items())
        },
        "torch_cpu": torch.get_rng_state().clone(),
        "cuda_device": resolved_cuda_device,
        "torch_cuda": cuda_state,
    }


def _aux_geometry_rng_state_identity(snapshot: dict[str, object]) -> dict[str, object]:
    """Return a compact, portable identity for one opaque RNG snapshot."""

    python_state = _rng_json_value(snapshot["python_random"])
    numpy_states = {
        str(name): _rng_json_value(state)
        for name, state in sorted(dict(snapshot["numpy"]).items())
    }
    python_sha = _canonical_json_sha256(python_state)
    numpy_sha = {
        name: _canonical_json_sha256(state)
        for name, state in numpy_states.items()
    }
    torch_cpu_sha = _torch_rng_state_sha256(snapshot["torch_cpu"])
    torch_cuda = snapshot["torch_cuda"]
    torch_cuda_sha = (
        None if torch_cuda is None else _torch_rng_state_sha256(torch_cuda)
    )
    identity: dict[str, object] = {
        "schema_version": "a1-aux-geometry-rng-state-v1",
        "python_random_sha256": python_sha,
        "numpy_generator_sha256": numpy_sha,
        "torch_cpu_sha256": torch_cpu_sha,
        "cuda_device": snapshot["cuda_device"],
        "torch_cuda_sha256": torch_cuda_sha,
    }
    identity["state_sha256"] = _canonical_json_sha256(identity)
    return identity


def _restore_aux_geometry_rng_state(
    snapshot: dict[str, object],
    *,
    numpy_generators: dict[str, np.random.Generator],
) -> None:
    """Restore a process-local probe snapshot exactly."""

    import torch

    saved_numpy = dict(snapshot["numpy"])
    if set(saved_numpy) != set(numpy_generators):
        raise RuntimeError("AUX geometry NumPy generator set changed during probe")
    random.setstate(copy.deepcopy(snapshot["python_random"]))
    for name, generator in numpy_generators.items():
        generator.bit_generator.state = copy.deepcopy(saved_numpy[name])
    torch.set_rng_state(snapshot["torch_cpu"].clone())
    cuda_device = snapshot["cuda_device"]
    cuda_state = snapshot["torch_cuda"]
    if cuda_device is not None:
        if not torch.cuda.is_available() or cuda_state is None:
            raise RuntimeError("cannot restore captured CUDA RNG state")
        torch.cuda.set_rng_state(cuda_state.clone(), int(cuda_device))


@contextmanager
def _isolated_aux_geometry_rng_transaction(
    *,
    numpy_generators: dict[str, np.random.Generator],
    cuda_device: int | None = None,
):
    """Consume five probe batches without persistently advancing any RNG.

    The caller must wrap the *whole* ordered five-batch geometry pass in this
    transaction.  Restoring after each batch would replay one dropout mask five
    times and invalidate the selector.  The mutable evidence object is filled
    only after restoration, including on exceptional exit.
    """

    snapshot = _capture_aux_geometry_rng_state(
        numpy_generators=numpy_generators,
        cuda_device=cuda_device,
    )
    before = _aux_geometry_rng_state_identity(snapshot)
    evidence: dict[str, object] = {
        "schema_version": "a1-aux-geometry-rng-transaction-v1",
        "scope": "one_complete_ordered_five_batch_probe",
        "restore_frequency": "once_after_all_five_batches",
        "before": before,
        "after_probe": None,
        "after_restore": None,
        "restored_exactly": False,
    }
    try:
        yield evidence
    finally:
        after_probe_snapshot = _capture_aux_geometry_rng_state(
            numpy_generators=numpy_generators,
            cuda_device=cuda_device,
        )
        evidence["after_probe"] = _aux_geometry_rng_state_identity(
            after_probe_snapshot
        )
        _restore_aux_geometry_rng_state(
            snapshot,
            numpy_generators=numpy_generators,
        )
        restored = _capture_aux_geometry_rng_state(
            numpy_generators=numpy_generators,
            cuda_device=cuda_device,
        )
        after = _aux_geometry_rng_state_identity(restored)
        evidence["after_restore"] = after
        evidence["restored_exactly"] = (
            before["state_sha256"] == after["state_sha256"]
        )
        if evidence["restored_exactly"] is not True:
            raise RuntimeError("AUX geometry probe failed to restore RNG state exactly")


def _norms_from_squared_sums(squared_sums: dict[str, object]) -> dict[str, float]:
    import torch

    return {
        name: float(torch.sqrt(value).detach().cpu().item())
        for name, value in sorted(squared_sums.items())
    }


def _capture_optimizer_observability(policy) -> dict:
    """Capture pre-clip module gradient norms and pre-step parameter bytes.

    This helper is called only at the existing opt-in train-diagnostics cadence.
    The normal/default path therefore performs no parameter clones, device
    synchronizations, or extra reductions. Under DDP the gradients and parameters
    are already replicated and synchronized.
    """
    model = policy.model
    module = getattr(model, "module", model)
    named_parameters = [
        (name, parameter)
        for name, parameter in module.named_parameters()
        if parameter.requires_grad and parameter.grad is not None
    ]
    snapshots = [
        (
            _optimizer_observability_module_name(name),
            parameter,
            parameter.detach().clone(),
        )
        for name, parameter in named_parameters
    ]
    grad_squared_sums: dict[str, object] = {}
    parameter_squared_sums: dict[str, object] = {}
    parameter_counts: dict[str, int] = {}
    for name, parameter in named_parameters:
        group = _optimizer_observability_module_name(name)
        squared = parameter.grad.detach().float().square().sum()
        grad_squared_sums[group] = grad_squared_sums.get(group, 0.0) + squared
        parameter_squared = parameter.detach().float().square().sum()
        parameter_squared_sums[group] = (
            parameter_squared_sums.get(group, 0.0) + parameter_squared
        )
        parameter_counts[group] = parameter_counts.get(group, 0) + int(
            parameter.numel()
        )
    import torch

    is_fsdp = callable(getattr(model, "clip_grad_norm_", None)) and not isinstance(
        model, torch.nn.parallel.DistributedDataParallel
    )
    return {
        "snapshots": snapshots,
        "module_pre_clip_grad_norms": _norms_from_squared_sums(
            grad_squared_sums
        ),
        "module_parameter_l2_before": _norms_from_squared_sums(
            parameter_squared_sums
        ),
        "module_parameter_counts": parameter_counts,
        "module_norm_scope": "rank_local_shard" if is_fsdp else "global_replicated",
    }


def _finish_optimizer_observability(
    policy,
    state: dict,
    *,
    pre_clip_total_grad_norm,
    max_grad_norm: float,
) -> dict:
    """Measure the actual optimizer update after ``optimizer.step()``."""
    del policy  # The captured Parameter objects remain live across optimizer.step().
    delta_squared_sums: dict[str, object] = {}
    for group, parameter, before in state["snapshots"]:
        squared = (parameter.detach().float() - before.float()).square().sum()
        delta_squared_sums[group] = delta_squared_sums.get(group, 0.0) + squared
    if hasattr(pre_clip_total_grad_norm, "detach"):
        total_norm = float(pre_clip_total_grad_norm.detach().cpu().item())
    else:
        total_norm = float(pre_clip_total_grad_norm)
    delta_norms = _norms_from_squared_sums(delta_squared_sums)
    return {
        "pre_clip_total_grad_norm": total_norm,
        "max_grad_norm": float(max_grad_norm),
        "gradient_clipping_enabled": bool(max_grad_norm > 0.0),
        "clipped": bool(
            max_grad_norm > 0.0
            and (not math.isfinite(total_norm) or total_norm > max_grad_norm)
        ),
        "module_pre_clip_grad_norms": state["module_pre_clip_grad_norms"],
        "module_parameter_delta_norms": delta_norms,
        "module_parameter_update_rms": {
            group: (
                float(delta_norm)
                / math.sqrt(float(state["module_parameter_counts"][group]))
            )
            for group, delta_norm in delta_norms.items()
        },
        "module_relative_parameter_delta": {
            group: (
                float(delta_norm)
                / max(float(state["module_parameter_l2_before"][group]), 1.0e-30)
            )
            for group, delta_norm in delta_norms.items()
        },
        "module_parameter_counts": state["module_parameter_counts"],
        "module_norm_scope": state["module_norm_scope"],
    }


def _suppress_inactive_policy_only_gradients(
    policy,
    optimizer=None,
) -> tuple[str, ...]:
    """Stop momentum/AdamW drift after policy distillation is disabled."""

    module = getattr(policy.model, "module", policy.model)
    parameters: list[tuple[str, object]] = []
    for module_name in ("action_bias", "edge_policy_mlp"):
        submodule = getattr(module, module_name, None)
        if submodule is not None:
            parameters.extend(
                (f"{module_name}.{name}", parameter)
                for name, parameter in submodule.named_parameters()
            )
    logit_scale = getattr(module, "logit_scale", None)
    if logit_scale is not None:
        parameters.append(("logit_scale", logit_scale))
    if int(getattr(module, "value_tower_split_layers", 0) or 0) > 0:
        state_norm = getattr(module, "state_norm", None)
        if state_norm is not None:
            parameters.extend(
                (f"state_norm.{name}", parameter)
                for name, parameter in state_norm.named_parameters()
            )
    suppressed: list[str] = []
    for name, parameter in parameters:
        if parameter.grad is not None:
            parameter.grad = None
            suppressed.append(name)
        if optimizer is not None:
            optimizer.state.pop(parameter, None)
    return tuple(sorted(suppressed))


def _suppress_shared_policy_representation_gradients(
    policy,
    optimizer=None,
) -> tuple[str, ...]:
    """Freeze every non-value EntityGraph surface, including AdamW state."""

    model = policy.model
    module = getattr(model, "module", model)
    frozen_roots = {
        module_name
        for group_name in ENTITY_GRAPH_VALUE_ONLY_FREEZE_GROUPS
        for module_name in ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS[group_name]
    }
    parameters: list[tuple[str, object]] = []
    seen: set[int] = set()
    for name, parameter in module.named_parameters():
        normalized = str(name)
        for prefix in ("module.", "_fsdp_wrapped_module."):
            while normalized.startswith(prefix):
                normalized = normalized[len(prefix) :]
        if normalized.split(".", 1)[0] not in frozen_roots:
            continue
        identity = id(parameter)
        if identity in seen:
            continue
        seen.add(identity)
        parameters.append((normalized, parameter))
    suppressed: list[str] = []
    for name, parameter in parameters:
        if parameter.grad is not None:
            parameter.grad = None
            suppressed.append(name)
        if optimizer is not None:
            optimizer.state.pop(parameter, None)
    return tuple(sorted(suppressed))


def _validate_max_grad_norm(value: float) -> float:
    """Return the canonical clipping threshold or reject an unsafe value.

    Positive finite values enable clipping. Zero is the sole explicit no-clip
    representation; negative, NaN, and infinite values fail before data or GPU
    setup.
    """

    value = float(value)
    if not math.isfinite(value) or value < 0.0:
        raise SystemExit(
            "--max-grad-norm must be finite and non-negative; use 0 to disable "
            f"gradient clipping explicitly (got {value})"
        )
    return value


def _optimizer_clip_observability(
    pre_clip_total_grad_norm,
    *,
    max_grad_norm: float,
) -> dict[str, float | bool]:
    """Return cheap per-step clipping telemetry without parameter snapshots."""

    if hasattr(pre_clip_total_grad_norm, "detach"):
        total_norm = float(pre_clip_total_grad_norm.detach().cpu().item())
    else:
        total_norm = float(pre_clip_total_grad_norm)
    enabled = bool(max_grad_norm > 0.0)
    return {
        "pre_clip_total_grad_norm": total_norm,
        "max_grad_norm": float(max_grad_norm),
        "gradient_clipping_enabled": enabled,
        "clipped": bool(
            enabled
            and (not math.isfinite(total_norm) or total_norm > max_grad_norm)
        ),
    }




def _clip_grad_norm(policy, max_norm: float = 1.0):
    """Clip the EntityGraph gradient norm under single-GPU or DDP training."""
    import torch

    max_norm = _validate_max_grad_norm(max_norm)
    effective_max_norm = math.inf if max_norm == 0.0 else max_norm
    return torch.nn.utils.clip_grad_norm_(list(_params(policy)), effective_max_norm)


def _step_optimizer_fail_closed(
    policy,
    optimizer,
    *,
    loss,
    max_grad_norm: float,
):
    """Clip and apply one optimizer step without committing corrupt/no-op state.

    ``clip_grad_norm_`` defaults to ``error_if_nonfinite=False``. A NaN/Inf
    gradient can therefore survive a finite scalar-loss check and be committed
    to Adam's moments unless the returned global norm is checked explicitly.

    An exactly zero objective *and* global gradient is not a learning step:
    calling AdamW would decay parameters and advance old momentum even though
    the batch carried no configured signal. We do not skip merely because the
    gradient norm is zero; at a valid stationary point with nonzero loss,
    optimizer momentum/decay semantics still apply.
    """
    pre_clip_total_grad_norm = _clip_grad_norm(policy, max_grad_norm)
    grad_norm = (
        float(pre_clip_total_grad_norm.detach().cpu().item())
        if hasattr(pre_clip_total_grad_norm, "detach")
        else float(pre_clip_total_grad_norm)
    )
    if not math.isfinite(grad_norm):
        raise FloatingPointError(
            f"non-finite BC gradient norm before optimizer step: {grad_norm}"
        )
    loss_value = (
        float(loss.detach().cpu().item())
        if hasattr(loss, "detach")
        else float(loss)
    )
    any_nonzero_objective = loss_value != 0.0
    if grad_norm == 0.0:
        # DDP synchronizes gradients, not the rank-local scalar loss.  At a
        # stationary/sparse step every rank sees the same zero global gradient,
        # but one rank can have no eligible objective rows while another has a
        # nonzero loss.  Letting the empty rank skip while its peer calls
        # optimizer.step() diverges Adam moments (and AdamW parameters) even
        # though DDP was otherwise correct.  The zero gradient makes this branch
        # rare; use one collective only here to reach a rank-consistent decision.
        import torch
        import torch.distributed as dist

        if dist.is_available() and dist.is_initialized():
            objective_present = torch.tensor(
                int(any_nonzero_objective),
                dtype=torch.int32,
                device=(loss.device if hasattr(loss, "device") else None),
            )
            dist.all_reduce(objective_present, op=dist.ReduceOp.MAX)
            any_nonzero_objective = bool(objective_present.item())
    zero_objective_step_skipped = not any_nonzero_objective and grad_norm == 0.0
    optimizer_step_applied = not zero_objective_step_skipped
    if optimizer_step_applied:
        optimizer.step()
        from catan_zero.rl.optim_state import assert_finite_optimizer_generation

        assert_finite_optimizer_generation(policy.model, optimizer)
    return (
        pre_clip_total_grad_norm,
        optimizer_step_applied,
        zero_objective_step_skipped,
    )


def _torch_ppo_masked_logits(logits, valid_actions, action_size):
    from catan_zero.rl.torch_ppo import _masked_logits

    return _masked_logits(logits, valid_actions, action_size)


def target_reliability_policy_factors(
    data,
    *,
    enabled: bool,
    confidence_floor: float,
) -> np.ndarray:
    """Return neutral or explicitly contracted per-row policy multipliers."""

    n = int(len(data["action_taken"]))
    factors = np.ones(n, dtype=np.float32)
    if not bool(enabled):
        return factors
    floor = float(confidence_floor)
    if not math.isfinite(floor) or not 0.0 <= floor <= 1.0:
        raise SystemExit("--target-reliability-confidence-floor must be in [0, 1]")
    missing = [name for name in TARGET_RELIABILITY_COLUMNS if name not in data]
    if missing:
        raise SystemExit(
            "--target-reliability-confidence-weighting requires the complete "
            f"typed reliability row contract; missing={missing}"
        )

    version = np.asarray(data["target_reliability_version"], dtype=np.uint8)
    audited = np.asarray(data["target_reliability_audited"], dtype=np.bool_)
    js = np.asarray(data["target_reliability_js_divergence"], dtype=np.float32)
    policy_agreement = np.asarray(
        data["target_reliability_policy_top1_agreement"], dtype=np.bool_
    )
    q_agreement = np.asarray(
        data["target_reliability_q_top1_agreement"], dtype=np.bool_
    )
    primary_margin = np.asarray(
        data["target_reliability_q_margin_primary"], dtype=np.float32
    )
    duplicate_margin = np.asarray(
        data["target_reliability_q_margin_duplicate"], dtype=np.float32
    )
    confidence = np.asarray(
        data["target_reliability_confidence"], dtype=np.float32
    )
    columns = {
        "version": version,
        "audited": audited,
        "js": js,
        "policy_agreement": policy_agreement,
        "q_agreement": q_agreement,
        "primary_margin": primary_margin,
        "duplicate_margin": duplicate_margin,
        "confidence": confidence,
    }
    malformed_shapes = {
        name: value.shape for name, value in columns.items() if value.shape != (n,)
    }
    if malformed_shapes:
        raise SystemExit(
            "target reliability columns must be one-dimensional and row-aligned: "
            f"{malformed_shapes}"
        )
    unsupported = set(map(int, np.unique(version))) - {
        0,
        TARGET_RELIABILITY_VERSION,
    }
    if unsupported:
        raise SystemExit(
            f"unsupported target reliability versions: {sorted(unsupported)}"
        )
    contracted = version == TARGET_RELIABILITY_VERSION
    if not bool(np.any(contracted)):
        raise SystemExit(
            "--target-reliability-confidence-weighting found no version-1 rows"
        )
    if bool(np.any(audited & ~contracted)):
        raise SystemExit("audited reliability rows must carry version 1")
    if "target_information_regime" not in data:
        raise SystemExit(
            "target reliability weighting requires target_information_regime"
        )
    regimes = np.asarray(data["target_information_regime"]).astype(str)
    if regimes.shape != (n,) or bool(
        np.any(contracted & (regimes != TARGET_INFORMATION_REGIME_PUBLIC_COHERENT))
    ):
        raise SystemExit(
            "version-1 target reliability rows require coherent public-belief targets"
        )

    observed = contracted & audited
    if not bool(np.any(observed)):
        raise SystemExit(
            "--target-reliability-confidence-weighting found no audited version-1 rows"
        )
    if (
        bool(np.any(~np.isfinite(js[observed])))
        or bool(np.any((js[observed] < 0.0) | (js[observed] > math.log(2.0) + 1e-6)))
        or bool(np.any(~np.isfinite(primary_margin[observed])))
        or bool(np.any(~np.isfinite(duplicate_margin[observed])))
        or bool(np.any(primary_margin[observed] < 0.0))
        or bool(np.any(duplicate_margin[observed] < 0.0))
        or bool(np.any(~np.isfinite(confidence[observed])))
        or bool(np.any((confidence[observed] < 0.0) | (confidence[observed] > 1.0)))
    ):
        raise SystemExit("audited target reliability evidence is malformed")

    expected = np.asarray(
        [
            target_reliability_confidence(
                float(divergence), policy_top1_agreement=bool(agreement)
            )
            for divergence, agreement in zip(
                js[observed], policy_agreement[observed], strict=True
            )
        ],
        dtype=np.float32,
    )
    if not bool(np.allclose(confidence[observed], expected, rtol=0.0, atol=2e-6)):
        raise SystemExit(
            "stored target reliability confidence differs from its version-1 formula"
        )
    factors[observed] = np.maximum(floor, confidence[observed])
    return factors


def build_sample_weights(
    data: dict,
    *,
    teacher_weights: dict[str, float],
    phase_weights: dict[str, float],
    forced_action_weight: float,
    winner_sample_weight: float,
    loser_sample_weight: float,
    vp_margin_weight: float,
    vps_to_win: int,
    per_game_policy_weight: bool = False,
    per_game_policy_weight_mode: str = "equal",
    target_reliability_confidence_weighting: bool = False,
    target_reliability_confidence_floor: float = 0.25,
) -> np.ndarray:
    n = len(data["action_taken"])
    weights = np.ones(n, dtype=np.float32)
    if teacher_weights and "teacher_name" in data:
        teachers = np.asarray(data["teacher_name"]).astype(str)
        for teacher, weight in teacher_weights.items():
            weights[teachers == teacher] *= float(weight)
    if phase_weights and "phase" in data:
        phases = np.asarray(data["phase"]).astype(str)
        for phase, weight in phase_weights.items():
            weights[phases == phase] *= float(weight)
    if forced_action_weight != 1.0:
        legal_column = data["legal_action_ids"]
        legal_counts = (
            legal_column.row_counts()
            if isinstance(legal_column, _MemmapRaggedColumn)
            else np.sum(np.asarray(legal_column) >= 0, axis=1)
        )
        weights[legal_counts == 1] *= float(forced_action_weight)
    if (
        (float(winner_sample_weight) != 1.0 or float(loser_sample_weight) != 1.0)
        and "winner" in data
        and "player" in data
    ):
        winners = np.asarray(data["winner"]).astype(str)
        players = np.asarray(data["player"]).astype(str)
        truncated = np.asarray(
            data.get("truncated", np.zeros(n, dtype=np.bool_)),
            dtype=np.bool_,
        )
        has_winner = (winners != "") & ~truncated
        weights[has_winner & (winners == players)] *= float(winner_sample_weight)
        weights[has_winner & (winners != players)] *= float(loser_sample_weight)
    if float(vp_margin_weight) != 0.0 and "seat" in data and "final_actual_vps" in data:
        rows = np.arange(n)
        seats = np.asarray(data["seat"], dtype=np.int64)
        truncated = np.asarray(
            data.get("truncated", np.zeros(n, dtype=np.bool_)),
            dtype=np.bool_,
        )
        vps = np.zeros((n, 4), dtype=np.float32)
        has_final_vps = np.zeros(n, dtype=np.bool_)
        actual = np.asarray(data["final_actual_vps"], dtype=np.float32)
        if actual.ndim == 2 and actual.shape[0] == n:
            vps[:, : actual.shape[1]] = actual[:, : vps.shape[1]]
            has_actual = np.asarray(
                data.get("has_final_actual_vps", np.zeros(n, dtype=np.bool_)),
                dtype=np.bool_,
            )
            has_final_vps |= has_actual
        valid = (seats >= 0) & (seats < vps.shape[1]) & ~truncated & has_final_vps
        own = np.zeros(n, dtype=np.float32)
        own[valid] = vps[rows[valid], seats[valid]]
        masked = vps.copy()
        for idx, seat in enumerate(seats):
            if 0 <= int(seat) < masked.shape[1]:
                masked[idx, int(seat)] = -1.0
        best_opp = np.max(masked, axis=1)
        margin = (own - best_opp) / max(float(vps_to_win), 1.0)
        multiplier = np.ones(n, dtype=np.float32)
        multiplier[valid] = np.maximum(
            0.1,
            1.0 + float(vp_margin_weight) * margin[valid],
        )
        weights *= multiplier
    mean = float(np.mean(weights)) if len(weights) else 1.0
    if "policy_weight_multiplier" in data:
        weights *= np.asarray(data["policy_weight_multiplier"], dtype=np.float32)
        mean = float(np.mean(weights)) if len(weights) else 1.0
    if bool(target_reliability_confidence_weighting):
        weights *= target_reliability_policy_factors(
            data,
            enabled=True,
            confidence_floor=float(target_reliability_confidence_floor),
        )
        mean = float(np.mean(weights)) if len(weights) else 1.0
    if per_game_policy_weight and len(weights):
        # Only rows that already carry policy loss are redistributed. In
        # particular, fast/filtered rows with policy_weight_multiplier=0 stay
        # exactly zero and zero-active games acquire no synthetic policy mass.
        if per_game_policy_weight_mode not in {"equal", "sqrt"}:
            raise ValueError(
                f"unknown per_game_policy_weight_mode {per_game_policy_weight_mode!r}"
            )
        positive = np.where(weights > 0.0, weights, 0.0).astype(np.float32, copy=False)
        weights = _normalize_weights_per_game(
            data, positive, mode=per_game_policy_weight_mode
        )
        mean = float(np.mean(weights)) if len(weights) else 1.0
    if mean > 0:
        weights = weights / mean
    return weights.astype(np.float32, copy=False)


def _policy_distillation_scope_mask(
    data: object,
    rows: np.ndarray,
) -> np.ndarray | None:
    """Resolve the exact component mask used by policy CE and its admissions."""

    if isinstance(data, dict) and "_policy_distillation_eligible" in data:
        eligible = np.asarray(
            data["_policy_distillation_eligible"][rows], dtype=np.bool_
        )
        if eligible.shape != (len(rows),):
            raise ValueError("materialized policy distillation scope shape drift")
        return eligible
    if not bool(getattr(data, "policy_distillation_scope_authenticated", False)):
        return None
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    eligible = tuple(
        int(value)
        for value in getattr(data, "policy_distillation_component_indices", tuple())
    )
    component_lookup = getattr(data, "component_indices_for_rows", None)
    if (
        not component_ids
        or not eligible
        or not callable(component_lookup)
        or any(value < 0 or value >= len(component_ids) for value in eligible)
        or len(set(eligible)) != len(eligible)
    ):
        raise SystemExit("authenticated policy distillation component scope is invalid")
    components = np.asarray(component_lookup(rows), dtype=np.int64)
    if components.shape != (len(rows),):
        raise SystemExit("authenticated policy distillation row lookup shape drift")
    return np.isin(components, np.asarray(eligible, dtype=np.int64))


def _apply_authenticated_policy_distillation_scope(
    data, weights: np.ndarray
) -> np.ndarray:
    """Zero policy CE outside an authenticated composite component scope.

    Value weights are intentionally untouched. Stored-prior KL has its own
    independently authenticated component scope, so a replay component can
    rehearse outcomes and optionally anchor incumbent behavior without
    distilling an obsolete search teacher.
    """

    rows = np.arange(len(weights), dtype=np.int64)
    keep = _policy_distillation_scope_mask(data, rows)
    if keep is None:
        return weights
    scoped = np.asarray(weights, dtype=np.float32).copy()
    scoped[~keep] = 0.0
    if not np.any(scoped > 0.0):
        raise SystemExit("authenticated policy distillation scope has no positive policy rows")
    return scoped


def _policy_distillation_scope_report(data, weights: np.ndarray) -> dict[str, object] | None:
    if not bool(getattr(data, "policy_distillation_scope_authenticated", False)):
        return None
    component_ids = tuple(data.component_ids)
    eligible = set(data.policy_distillation_component_indices)
    offsets = np.asarray(data.component_offsets, dtype=np.int64)
    components = {}
    for index, component_id in enumerate(component_ids):
        part = np.asarray(weights[offsets[index] : offsets[index + 1]], dtype=np.float64)
        components[str(component_id)] = {
            "component_index": int(index),
            "policy_distillation_enabled": bool(index in eligible),
            "rows": int(part.size),
            "positive_policy_rows": int(np.count_nonzero(part > 0.0)),
            "policy_weight_sum": float(part.sum()),
        }
    return {
        "schema_version": "component-policy-distillation-scope-v1",
        "component_ids": [component_ids[index] for index in sorted(eligible)],
        "components": components,
    }


def _policy_target_identity_from_meta(meta: object) -> str | None:
    if not isinstance(meta, dict):
        return None
    candidates: list[object] = [
        meta.get("policy_target_identity_sha256"),
        meta.get("target_policy_target_identity_sha256"),
    ]
    overlay = meta.get("stage_c_policy_overlay")
    if isinstance(overlay, dict):
        candidates.append(overlay.get("target_policy_target_identity_sha256"))
    realized = {str(value) for value in candidates if value not in {None, ""}}
    if len(realized) > 1:
        raise SystemExit(
            "corpus metadata binds contradictory policy-target identities: "
            + ", ".join(sorted(realized))
        )
    identity = next(iter(realized), None)
    if identity is not None and not _is_sha256(identity):
        raise SystemExit("corpus policy-target identity is not a SHA-256 digest")
    return identity


def _validate_policy_target_identity_scope(
    data,
    weights: np.ndarray,
    *,
    accepted_identities: Sequence[str],
) -> dict[str, object]:
    """Fail closed when policy CE mixes missing or different target operators."""

    accepted = tuple(dict.fromkeys(str(value) for value in accepted_identities))
    if any(not _is_sha256(value) for value in accepted):
        raise SystemExit(
            "--accepted-policy-target-identity-sha256 requires SHA-256 digests"
        )
    values = np.asarray(weights, dtype=np.float64)
    if isinstance(data, ConcatMemmapCorpus):
        component_ids = tuple(str(value) for value in data.component_ids)
        corpora = tuple(data.corpora)
        offsets = np.asarray(data.component_offsets, dtype=np.int64)
    else:
        component_ids = ("corpus",)
        corpora = (data,)
        offsets = np.asarray([0, len(values)], dtype=np.int64)

    components: dict[str, dict[str, object]] = {}
    active_identities: set[str] = set()
    missing_active: list[str] = []
    rejected: list[str] = []
    for index, (component_id, corpus) in enumerate(
        zip(component_ids, corpora, strict=True)
    ):
        part = values[offsets[index] : offsets[index + 1]]
        active_rows = int(np.count_nonzero(part > 0.0))
        identity = _policy_target_identity_from_meta(getattr(corpus, "meta", None))
        if active_rows > 0:
            if identity is None:
                missing_active.append(component_id)
            else:
                active_identities.add(identity)
                if accepted and identity not in accepted:
                    rejected.append(component_id)
        components[component_id] = {
            "positive_policy_rows": active_rows,
            "policy_target_identity_sha256": identity,
            "accepted": bool(
                active_rows == 0
                or identity is not None
                and (not accepted or identity in accepted)
            ),
        }

    if accepted and missing_active:
        raise SystemExit(
            "policy-active component(s) lack exact target identity: "
            + ", ".join(missing_active)
        )
    if rejected:
        raise SystemExit(
            "policy-active component(s) bind an unaccepted target operator: "
            + ", ".join(rejected)
        )
    if active_identities and missing_active:
        raise SystemExit(
            "policy CE would mix exact-identity and legacy unbound targets: "
            + ", ".join(missing_active)
        )
    if len(active_identities) > 1 and not accepted:
        raise SystemExit(
            "policy CE would mix distinct target operators without an explicit "
            "accepted identity set"
        )
    return {
        "schema_version": "policy-target-identity-admission-v1",
        "mode": (
            "explicit_accepted_identity_set"
            if accepted
            else "automatic_uniform_identity"
            if active_identities
            else "legacy_unbound_diagnostic"
        ),
        "accepted_policy_target_identity_sha256": list(accepted),
        "realized_active_policy_target_identity_sha256": sorted(active_identities),
        "legacy_unbound_active_components": missing_active,
        "components": components,
    }


def _value_training_scope_mask(
    data: object,
    rows: np.ndarray,
) -> np.ndarray | None:
    """Resolve the component mask shared by value loss and its admissions."""

    if isinstance(data, dict) and "_value_training_eligible" in data:
        eligible = np.asarray(data["_value_training_eligible"][rows], dtype=np.bool_)
        if eligible.shape != (len(rows),):
            raise ValueError("materialized value training scope shape drift")
        return eligible
    if not bool(getattr(data, "value_training_scope_authenticated", False)):
        return None
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    eligible = tuple(
        int(value)
        for value in getattr(data, "value_training_component_indices", tuple())
    )
    component_lookup = getattr(data, "component_indices_for_rows", None)
    if (
        not component_ids
        or not eligible
        or not callable(component_lookup)
        or any(value < 0 or value >= len(component_ids) for value in eligible)
        or len(set(eligible)) != len(eligible)
    ):
        raise SystemExit("authenticated value training component scope is invalid")
    components = np.asarray(component_lookup(rows), dtype=np.int64)
    if components.shape != (len(rows),):
        raise SystemExit("authenticated value training row lookup shape drift")
    return np.isin(components, np.asarray(eligible, dtype=np.int64))


def _apply_authenticated_value_training_scope(
    data, weights: np.ndarray
) -> np.ndarray:
    """Zero value objectives outside an authenticated composite scope.

    A realised outcome is policy-conditional: replay ``z`` estimates the old
    self-play continuation, not the current checkpoint's continuation.  This
    scope lets replay remain available to its independently authenticated KL
    anchor without silently using old-policy returns as current value labels.
    Ordinary corpora and old descriptors retain all-component behavior.
    """

    rows = np.arange(len(weights), dtype=np.int64)
    keep = _value_training_scope_mask(data, rows)
    if keep is None:
        return weights
    scoped = np.asarray(weights, dtype=np.float32).copy()
    scoped[~keep] = 0.0
    if not np.any(scoped > 0.0):
        raise SystemExit("authenticated value training scope has no positive rows")
    return scoped


def _value_training_scope_report(
    data, weights: np.ndarray
) -> dict[str, object] | None:
    if not bool(getattr(data, "value_training_scope_authenticated", False)):
        return None
    component_ids = tuple(data.component_ids)
    eligible = set(data.value_training_component_indices)
    offsets = np.asarray(data.component_offsets, dtype=np.int64)
    components = {}
    for index, component_id in enumerate(component_ids):
        part = np.asarray(
            weights[offsets[index] : offsets[index + 1]], dtype=np.float64
        )
        components[str(component_id)] = {
            "component_index": int(index),
            "value_training_enabled": bool(index in eligible),
            "rows": int(part.size),
            "positive_value_rows": int(np.count_nonzero(part > 0.0)),
            "value_weight_sum": float(part.sum()),
        }
    return {
        "schema_version": "component-value-training-scope-v1",
        "component_ids": [component_ids[index] for index in sorted(eligible)],
        "components": components,
    }


def _source_global_rows_for_training_batch(
    batch_data: object, batch: np.ndarray
) -> np.ndarray:
    """Resolve full-corpus rows after optional threaded materialization."""

    rows = np.asarray(batch, dtype=np.int64)
    if isinstance(batch_data, dict) and "_source_global_row_indices" in batch_data:
        source = np.asarray(batch_data["_source_global_row_indices"], dtype=np.int64)
        if source.ndim != 1 or np.any(rows < 0) or np.any(rows >= len(source)):
            raise RuntimeError("materialized source-global row mapping is invalid")
        rows = source[rows]
    if rows.ndim != 1 or np.any(rows < 0):
        raise RuntimeError("training batch has invalid source-global rows")
    return rows


def _legal_width_bucket(width: int) -> str:
    value = int(width)
    if value <= 1:
        return "1"
    if value <= 3:
        return "2_3"
    if value <= 7:
        return "4_7"
    if value <= 19:
        return "8_19"
    if value <= 39:
        return "20_39"
    return "40_plus"


def _simulation_budget_bucket(simulations: int) -> str:
    value = int(simulations)
    if value <= 0:
        return "0_or_unrecorded"
    if value < 64:
        return "1_63"
    if value < 128:
        return "64_127"
    if value == 128:
        return "128"
    if value < 256:
        return "129_255"
    return "256_plus"


def _training_source_labels(data: object, rows: np.ndarray) -> np.ndarray:
    """Map sampled rows to the learner's fresh/replay source contract."""

    component_lookup = getattr(data, "component_indices_for_rows", None)
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    if not callable(component_lookup) or not component_ids:
        return np.full(len(rows), "single_corpus", dtype="<U16")
    indices = np.asarray(component_lookup(rows), dtype=np.int64)
    if indices.shape != rows.shape or np.any(indices < 0) or np.any(
        indices >= len(component_ids)
    ):
        raise RuntimeError("training source-component mapping is invalid")
    return np.asarray(
        [
            "replay" if component_ids[index] == HISTORICAL_REPLAY_CATEGORY else "fresh"
            for index in indices
        ],
        dtype="<U8",
    )


def _training_action_type_labels(data: object, rows: np.ndarray) -> np.ndarray:
    """Recover the selected action type from the serialized legal-action token.

    The current entity adapter stores an exact action-type one-hot in slots
    ``2:2+len(ACTION_TYPES)`` for every legal action.  Reading the selected
    legal row avoids reconstructing a player-count-specific flat ActionCatalog
    and makes rare-action dose evidence valid under both 2p and larger tracks.
    Legacy/non-entity corpora remain explicitly ``unrecorded``.
    """

    indices = np.asarray(rows, dtype=np.int64)
    fallback = np.full(len(indices), "unrecorded", dtype="<U32")
    if "legal_action_tokens" not in data or len(indices) == 0:
        return fallback
    legal_ids = np.asarray(data["legal_action_ids"][indices])
    action_ids = np.asarray(data["action_taken"][indices], dtype=np.int64)
    tokens = np.asarray(data["legal_action_tokens"][indices])
    expected_width = 2 + len(ACTION_TYPES)
    if (
        legal_ids.ndim != 2
        or tokens.ndim != 3
        or legal_ids.shape != tokens.shape[:2]
        or tokens.shape[2] < expected_width
    ):
        raise RuntimeError("training action-type attribution is malformed")
    selected_columns = _target_columns(legal_ids, action_ids)
    selected = np.asarray(
        tokens[np.arange(len(indices)), selected_columns, 2:expected_width],
        dtype=np.float32,
    )
    finite = np.isfinite(selected).all(axis=1)
    positive = selected > 0.5
    one_hot = finite & (positive.sum(axis=1) == 1)
    if np.any(one_hot):
        encoded = np.argmax(selected[one_hot], axis=1)
        fallback[one_hot] = np.asarray(ACTION_TYPES, dtype="<U32")[encoded]
    return fallback


def _training_strata_dose_for_batch(
    data: object,
    rows: np.ndarray,
    *,
    policy_weights: np.ndarray,
    value_weights: np.ndarray,
    value_active_mask: np.ndarray,
    draw_stream: str = "base",
    policy_objective_fraction: float = 1.0,
) -> dict[str, dict[str, dict[str, float]]]:
    """Attribute one realized training draw to science-relevant strata.

    This is draw accounting, not a corpus histogram: weighted sampling may
    revisit a row, and every revisit is counted because it contributes another
    optimizer exposure.  Policy activity is kept separate from total row dose;
    the old headline ``524288 samples`` hid that only ~10% of those rows could
    affect policy CE.
    """

    rows = np.asarray(rows, dtype=np.int64)
    policy = np.asarray(policy_weights, dtype=np.float64)
    value = np.asarray(value_weights, dtype=np.float64)
    value_active = np.asarray(value_active_mask, dtype=np.bool_)
    objective_fraction = float(policy_objective_fraction)
    expected = (len(rows),)
    if (
        rows.ndim != 1
        or policy.shape != expected
        or value.shape != expected
        or value_active.shape != expected
        or np.any(rows < 0)
        or not np.isfinite(policy).all()
        or not np.isfinite(value).all()
        or not math.isfinite(objective_fraction)
        or objective_fraction < 0.0
        or objective_fraction > 1.0
    ):
        raise RuntimeError("training stratum dose inputs are misaligned")

    legal = np.asarray(data["legal_action_ids"][rows])
    if legal.ndim != 2 or legal.shape[0] != len(rows):
        raise RuntimeError("training legal-width attribution is malformed")
    legal_widths = np.sum(legal >= 0, axis=1, dtype=np.int64)
    full_labels = (
        np.where(
            np.asarray(data["used_full_search"][rows], dtype=np.bool_),
            "full",
            "fast",
        )
        if "used_full_search" in data
        else np.full(len(rows), "unrecorded", dtype="<U10")
    )
    simulations = (
        np.asarray(data["simulations_used"][rows], dtype=np.int64)
        if "simulations_used" in data
        else np.zeros(len(rows), dtype=np.int64)
    )
    phases = np.asarray(data["phase"][rows]).astype(str, copy=False)
    decisions = (
        np.asarray(data["decision_class"][rows]).astype(str, copy=False)
        if "decision_class" in data
        else np.full(len(rows), "legacy_unknown", dtype="<U14")
    )
    sources = _training_source_labels(data, rows)
    action_types = _training_action_type_labels(data, rows)
    dimensions = {
        "draw_stream": np.full(len(rows), str(draw_stream)),
        "full_vs_fast": full_labels,
        "simulation_budget": np.asarray(
            [_simulation_budget_bucket(value) for value in simulations]
        ),
        "decision_class": decisions,
        "legal_width": np.asarray(
            [_legal_width_bucket(value) for value in legal_widths]
        ),
        "phase": phases,
        "fresh_vs_replay": sources,
        "action_type": action_types,
    }
    policy_active = policy > 0.0
    result: dict[str, dict[str, dict[str, float]]] = {}
    for dimension, labels in dimensions.items():
        groups: dict[str, dict[str, float]] = {}
        dimension_labels = (
            tuple(ACTION_TYPES) + ("unrecorded",)
            if dimension == "action_type"
            else tuple(str(label) for label in np.unique(labels))
        )
        for label in dimension_labels:
            mask = labels == label
            active_value = mask & value_active
            groups[str(label)] = {
                "sampled_rows": float(np.count_nonzero(mask)),
                "policy_active_rows": float(np.count_nonzero(mask & policy_active)),
                "policy_weight_sum": float(policy[mask].sum()),
                "policy_objective_active_rows": (
                    float(np.count_nonzero(mask & policy_active))
                    if objective_fraction > 0.0
                    else 0.0
                ),
                "policy_objective_equivalent_rows": (
                    float(np.count_nonzero(mask & policy_active))
                    * objective_fraction
                ),
                "policy_objective_equivalent_weight_sum": (
                    float(policy[mask].sum()) * objective_fraction
                ),
                "value_active_rows": float(np.count_nonzero(active_value)),
                "value_weight_sum": float(value[active_value].sum()),
            }
        result[dimension] = groups
    return result


def _flatten_training_strata_dose(
    report: dict[str, dict[str, dict[str, float]]]
) -> dict[str, float]:
    return {
        f"{dimension}\0{label}\0{metric}": float(value)
        for dimension, groups in report.items()
        for label, metrics in groups.items()
        for metric, value in metrics.items()
    }


def _nest_training_strata_dose(values: dict[str, float]) -> dict[str, object]:
    dimensions: dict[str, dict[str, dict[str, float | int]]] = {}
    for key, value in sorted(values.items()):
        dimension, label, metric = key.split("\0", 2)
        converted: float | int = (
            int(round(value))
            if metric.endswith("_rows") and "equivalent" not in metric
            else float(value)
        )
        dimensions.setdefault(dimension, {}).setdefault(label, {})[metric] = converted
    headline = dimensions.get("fresh_vs_replay", {})
    total_rows = sum(int(row.get("sampled_rows", 0)) for row in headline.values())
    policy_rows = sum(
        int(row.get("policy_active_rows", 0)) for row in headline.values()
    )
    policy_objective_rows = sum(
        int(row.get("policy_objective_active_rows", 0))
        for row in headline.values()
    )
    policy_objective_equivalent_rows = sum(
        float(row.get("policy_objective_equivalent_rows", 0.0))
        for row in headline.values()
    )
    value_rows = sum(
        int(row.get("value_active_rows", 0)) for row in headline.values()
    )
    streams = dimensions.get("draw_stream", {})
    base_rows = int(streams.get("base", {}).get("sampled_rows", 0))
    auxiliary_rows = int(streams.get("policy_aux", {}).get("sampled_rows", 0))
    return {
        "schema_version": "training-strata-dose-v1",
        "total_row_draws": total_rows,
        "base_row_draws": base_rows,
        "policy_aux_row_draws": auxiliary_rows,
        "policy_active_row_draws": policy_rows,
        "policy_active_fraction": policy_rows / max(total_rows, 1),
        "policy_objective_active_row_draws": policy_objective_rows,
        "policy_objective_equivalent_row_draws": (
            policy_objective_equivalent_rows
        ),
        "policy_objective_equivalent_fraction": (
            policy_objective_equivalent_rows / max(total_rows, 1)
        ),
        "value_active_row_draws": value_rows,
        "value_active_fraction": value_rows / max(total_rows, 1),
        "dimensions": dimensions,
    }


def _value_component_active_dose_for_batch(
    data, batch: np.ndarray, active_mask: np.ndarray | None
) -> dict[str, float] | None:
    """Measure source rows that actually entered the value loss by component."""

    if not bool(getattr(data, "value_training_scope_authenticated", False)):
        return None
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    eligible = set(
        int(value)
        for value in getattr(data, "value_training_component_indices", tuple())
    )
    mask = np.asarray(active_mask)
    if (
        not component_ids
        or not eligible
        or any(value < 0 or value >= len(component_ids) for value in eligible)
        or mask.dtype != np.bool_
        or mask.shape != (len(batch),)
    ):
        raise RuntimeError(
            "authenticated value scope lost its realized row exposure"
        )
    components = np.asarray(
        data.component_indices_for_rows(np.asarray(batch, dtype=np.int64)),
        dtype=np.int64,
    )
    if components.shape != mask.shape:
        raise RuntimeError("authenticated value component mapping shape drift")
    if np.any(mask & ~np.isin(components, np.asarray(sorted(eligible)))):
        raise RuntimeError("excluded value component received positive exposure")
    return {
        str(component_id): float(np.count_nonzero(mask & (components == index)))
        for index, component_id in enumerate(component_ids)
    }


def build_value_sample_weights(
    data: dict,
    *,
    phase_weights: dict[str, float] | None = None,
    forced_row_value_weight: float = 1.0,
    forced_row_value_action_type_weights: Mapping[str, float] | None = None,
    action_catalog: object | None = None,
    per_game_value_weight: bool = False,
    per_game_value_weight_mode: str = "equal",
    per_game_weight_diagnostics: dict[str, object] | None = None,
) -> np.ndarray:
    """Keep value targets unbiased by filtered-BC policy weighting.

    Winner/loser filtering is useful for action imitation because we prefer to
    copy decisions from stronger trajectories. The value head needs both sides
    of a completed game at full weight, otherwise PPO starts from an optimistic
    baseline and advantages become high-variance.

    FIX A5: ``phase_weights`` (e.g. ``robber=8.0,initial_build=5.0``) previously only reached
    the POLICY loss via ``build_sample_weights`` -- the value head had no way to be
    phase-weighted at all, so any "phase-repair" pass could never touch the value head by
    construction. This mirrors ``build_sample_weights``'s phase-weight application (per-phase
    multiplier, then renormalize to mean 1) so the value head can be repaired the same way.

    CAT-60: ``forced_row_value_weight`` and ``per_game_value_weight`` address
    repeated correlated labels and low-information forced-decision rows. For an
    ordinary uniform-row corpus, naive value MSE overweights long games. A v2
    composite already samples games uniformly, so its sampler-aware normalizer
    operates on mean rather than summed in-game weight. Combination rule,
    applied in this exact order, since every factor here is multiplicative and
    the final mean-renormalize makes the order of scalar factors irrelevant
    except for ``per_game_value_weight``, which must go LAST:

      1. ``phase_weights`` multiplier (this function, existing).
      2. ``value_weight_multiplier`` (CAT-45's per-row sampling-weight field, already stored on
         the corpus -- existing).
      3. ``forced_row_value_weight`` multiplier on rows with exactly one legal action.
      4. ``forced_row_value_action_type_weights`` multiplier selected from the
         stored ``action_taken`` through the active ``ActionCatalog``. Unlisted
         forced action types retain multiplier 1.0.
      5. ``per_game_value_weight`` normalization: divides by summed game weight
         for uniform-row corpora or mean game weight for game-uniform v2
         composites. It does not undo forced-row downweighting within a game.

    Finally the whole array is renormalized to global mean 1, as with every other weight
    builder in this module (a uniform scalar rescale, so it preserves the equal-per-game-mass
    property from step 4).
    """

    weights = np.ones(len(data["action_taken"]), dtype=np.float32)
    if phase_weights and "phase" in data:
        phases = np.asarray(data["phase"]).astype(str)
        for phase, weight in phase_weights.items():
            weights[phases == phase] *= float(weight)
    if "value_weight_multiplier" in data:
        weights *= np.asarray(data["value_weight_multiplier"], dtype=np.float32)
    type_weights = dict(forced_row_value_action_type_weights or {})
    legal_counts = None
    if (
        float(forced_row_value_weight) != 1.0 or type_weights
    ) and "legal_action_ids" in data:
        legal_counts = _legal_action_counts(data["legal_action_ids"])
    if float(forced_row_value_weight) != 1.0 and legal_counts is not None:
        weights[legal_counts == 1] *= float(forced_row_value_weight)
    if type_weights:
        if legal_counts is None:
            raise SystemExit(
                "--forced-row-value-action-type-weights requires legal_action_ids"
            )
        forced = legal_counts == 1
        multipliers, _action_types = _action_catalog_type_projection(
            action_catalog, type_weights
        )
        if np.any(forced):
            forced_actions = _validated_forced_action_ids(
                data, forced, action_catalog_size=len(multipliers)
            )
            weights[forced] *= multipliers[forced_actions]
    if per_game_value_weight and len(weights):
        weights = _normalize_weights_per_game(
            data,
            weights,
            mode=per_game_value_weight_mode,
            diagnostics=per_game_weight_diagnostics,
        )
    elif per_game_weight_diagnostics is not None:
        per_game_weight_diagnostics.update(
            {
                "requested": False,
                "mode": str(per_game_value_weight_mode),
                "effective": False,
                "game_count": 0,
                "denominator": {},
            }
        )
    mean = float(np.mean(weights)) if len(weights) else 1.0
    if mean > 0.0:
        weights = weights / mean
    return weights.astype(np.float32, copy=False)


def _encoded_identity_values(
    column: object,
    indices: np.ndarray,
    *,
    field: str,
) -> tuple[np.ndarray, tuple[str, ...]]:
    """Return compact identity codes without decoding a full categorical column."""

    if isinstance(column, _MemmapCategoricalColumn):
        categories = tuple(str(value) for value in column.categories.tolist())
        codes = np.asarray(column._codes[indices], dtype=np.int64)  # noqa: SLF001
        invalid = (codes < 0) | (codes >= len(categories))
        if bool(np.any(invalid)):
            examples = sorted(set(map(int, codes[invalid].tolist())))[:8]
            raise SystemExit(
                "sampler_balanced_v1 categorical identity code is out of range: "
                f"field={field!r} categories={len(categories)} examples={examples}"
            )
        return codes, categories
    values = np.asarray(column[indices]).astype(str)
    categories, codes = np.unique(values, return_inverse=True)
    return np.asarray(codes, dtype=np.int64), tuple(map(str, categories.tolist()))


def _paired_identity_codes(
    player_column: object,
    winner_column: object,
    indices: np.ndarray,
) -> tuple[np.ndarray, np.ndarray, tuple[str, ...]]:
    player_codes, player_categories = _encoded_identity_values(
        player_column, indices, field="player"
    )
    winner_codes, winner_categories = _encoded_identity_values(
        winner_column, indices, field="winner"
    )
    identities = tuple(sorted(set(player_categories) | set(winner_categories)))
    lookup = {name: index for index, name in enumerate(identities)}
    player_remap = np.asarray(
        [lookup[name] for name in player_categories], dtype=np.int64
    )
    winner_remap = np.asarray(
        [lookup[name] for name in winner_categories], dtype=np.int64
    )
    return (
        player_remap[player_codes],
        winner_remap[winner_codes],
        identities,
    )


def _value_balance_components(
    data: dict, row_indices: np.ndarray
) -> tuple[list[dict[str, object]], tuple[float, ...]]:
    """Resolve complete selected games and authenticated component provenance."""

    n = len(data["action_taken"])
    selected = np.asarray(row_indices, dtype=np.int64)
    if selected.ndim != 1 or np.any(selected < 0) or np.any(selected >= n):
        raise SystemExit("value player/outcome balance row selection is invalid")
    if selected.size > 1 and bool(np.any(selected[1:] < selected[:-1])):
        selected = np.sort(selected)
    if selected.size > 1 and bool(np.any(selected[1:] == selected[:-1])):
        raise SystemExit("value player/outcome balance row selection is invalid")
    offsets = _validated_component_offsets(data, n)
    ranges = _component_row_ranges(offsets, n)
    ratios = tuple(
        float(value)
        for value in getattr(data, "component_game_sampling_ratios", tuple())
    )
    component_ids = tuple(
        str(value) for value in getattr(data, "component_ids", tuple())
    )
    corpora = tuple(getattr(data, "corpora", tuple()))
    if offsets is not None:
        if (
            len(component_ids) != len(ranges)
            or len(ratios) != len(ranges)
            or len(corpora) != len(ranges)
            or any(not value for value in component_ids)
            or any(not math.isfinite(value) or value <= 0.0 for value in ratios)
            or not bool(getattr(data, "value_training_scope_authenticated", False))
        ):
            raise SystemExit(
                "sampler_balanced_v1 requires authenticated composite component "
                "identity, sampling ratios, corpora, and value-training scope"
            )
        eligible = tuple(
            int(value)
            for value in getattr(data, "value_training_component_indices", tuple())
        )
        if (
            not eligible
            or len(set(eligible)) != len(eligible)
            or any(value < 0 or value >= len(ranges) for value in eligible)
        ):
            raise SystemExit(
                "sampler_balanced_v1 received an invalid authenticated value scope"
            )
        eligible_set = set(eligible)
    else:
        if ratios or component_ids or corpora:
            raise SystemExit(
                "sampler_balanced_v1 received partial composite provenance"
            )
        component_ids = ("ordinary_corpus",)
        ratios = (1.0,)
        corpora = (data,)
        eligible_set = {0}

    required = {"game_seed", "player", "winner", "truncated"}
    resolved: list[dict[str, object]] = []
    for component_index, (start, stop) in enumerate(ranges):
        if component_index not in eligible_set:
            continue
        rows = selected[(selected >= start) & (selected < stop)]
        if rows.size == 0:
            if offsets is not None:
                raise SystemExit(
                    "sampler_balanced_v1 partition omits an authenticated "
                    "value-enabled component: "
                    f"component={component_ids[component_index]!r}"
                )
            continue
        corpus = corpora[component_index]
        missing = sorted(required - set(corpus.keys()))
        if missing:
            raise SystemExit(
                "sampler_balanced_v1 component lacks required outcome provenance: "
                f"component={component_ids[component_index]!r} missing={missing}"
            )
        local = rows - int(start)
        seeds = np.asarray(corpus["game_seed"][local], dtype=np.int64)
        truncated = np.asarray(corpus["truncated"][local], dtype=np.bool_)
        if seeds.shape != local.shape or truncated.shape != local.shape:
            raise SystemExit(
                "sampler_balanced_v1 outcome provenance is not row-aligned: "
                f"component={component_ids[component_index]!r}"
            )
        breaks = np.flatnonzero(
            (seeds[1:] != seeds[:-1]) | (local[1:] != local[:-1] + 1)
        ) + 1
        partition_game_starts = np.concatenate(
            (np.asarray([0], dtype=np.int64), breaks.astype(np.int64, copy=False))
        )
        partition_game_stops = np.concatenate(
            (breaks.astype(np.int64, copy=False), np.asarray([len(local)], dtype=np.int64))
        )
        partition_game_seeds = seeds[partition_game_starts]
        if len(np.unique(partition_game_seeds)) != len(partition_game_seeds):
            raise SystemExit(
                "sampler_balanced_v1 requires each selected game to be one "
                f"contiguous run: component={component_ids[component_index]!r}"
            )
        full_seed_column = corpus["game_seed"]
        begins_at_game_start = (local[partition_game_starts] == 0) | (
            np.asarray(
                full_seed_column[np.maximum(local[partition_game_starts] - 1, 0)],
                dtype=np.int64,
            )
            != partition_game_seeds
        )
        last_local = local[partition_game_stops - 1]
        ends_at_game_stop = (last_local == int(stop - start) - 1) | (
            np.asarray(
                full_seed_column[np.minimum(last_local + 1, int(stop - start) - 1)],
                dtype=np.int64,
            )
            != partition_game_seeds
        )
        if not bool(np.all(begins_at_game_start & ends_at_game_stop)):
            raise SystemExit(
                "sampler_balanced_v1 refuses a partial-game train/validation split: "
                f"component={component_ids[component_index]!r}"
            )
        partition_game_lengths = partition_game_stops - partition_game_starts
        truncated_counts = np.add.reduceat(
            truncated.astype(np.int64, copy=False), partition_game_starts
        )
        mixed_truncation = (truncated_counts > 0) & (
            truncated_counts < partition_game_lengths
        )
        if bool(np.any(mixed_truncation)):
            bad_seeds = partition_game_seeds[mixed_truncation][:8].tolist()
            raise SystemExit(
                "sampler_balanced_v1 found mixed truncation state within a game: "
                f"component={component_ids[component_index]!r} seeds={bad_seeds}"
            )
        completed_games = truncated_counts == 0
        if not bool(np.any(completed_games)):
            raise SystemExit(
                "sampler_balanced_v1 component has no completed outcome games: "
                f"component={component_ids[component_index]!r}"
            )
        completed_row_mask = np.repeat(completed_games, partition_game_lengths)
        completed_rows = rows[completed_row_mask]
        truncated_row_indices = rows[~completed_row_mask]
        completed_local = local[completed_row_mask]
        completed_game_lengths = partition_game_lengths[completed_games]
        game_stops = np.cumsum(completed_game_lengths, dtype=np.int64)
        game_starts = np.concatenate(
            (np.asarray([0], dtype=np.int64), game_stops[:-1])
        )
        game_seeds = partition_game_seeds[completed_games]
        player_ids, winner_ids, identity_names = _paired_identity_codes(
            corpus["player"], corpus["winner"], completed_local
        )
        empty_identity_ids = {
            index for index, name in enumerate(identity_names) if not str(name)
        }
        if (
            empty_identity_ids
            and (
                bool(np.any(np.isin(player_ids, list(empty_identity_ids))))
                or bool(np.any(np.isin(winner_ids, list(empty_identity_ids))))
            )
        ):
            raise SystemExit(
                "sampler_balanced_v1 found empty player/winner provenance: "
                f"component={component_ids[component_index]!r}"
            )
        resolved.append(
            {
                "component_index": int(component_index),
                "component_id": component_ids[component_index],
                "ratio": float(ratios[component_index]),
                "game_uniform_sampler": bool(offsets is not None),
                "partition_rows": int(len(rows)),
                "completed_non_truncated_rows": int(len(completed_rows)),
                "truncated_rows": int(len(rows) - len(completed_rows)),
                "partition_games": int(len(partition_game_starts)),
                "completed_non_truncated_games": int(len(game_starts)),
                "truncated_games": int(np.count_nonzero(~completed_games)),
                "rows": completed_rows,
                "truncated_row_indices": truncated_row_indices,
                "player_ids": player_ids,
                "winner_ids": winner_ids,
                "identity_names": identity_names,
                "game_starts": game_starts,
                "game_stops": game_stops,
                "game_seeds": game_seeds,
            }
        )
    if not resolved:
        raise SystemExit("sampler_balanced_v1 selection has no value-enabled games")
    return resolved, ratios


def apply_value_player_outcome_balance(
    data: dict,
    weights: np.ndarray,
    row_indices: np.ndarray,
    *,
    mode: str,
) -> np.ndarray:
    """Fit explicit value-label balancing on exactly one data partition."""

    if mode == "none":
        return np.asarray(weights, dtype=np.float32)
    if mode != "sampler_balanced_v1":
        raise ValueError(f"unknown value_player_outcome_balance_mode {mode!r}")
    balanced = np.asarray(weights, dtype=np.float32).copy()
    components, ratios = _value_balance_components(data, row_indices)
    completed_sampler_mass_before = _value_balance_completed_sampler_mass(
        components, ratios, balanced
    )
    active_rows: list[np.ndarray] = []
    has_truncated_games = False
    for component in components:
        rows = np.asarray(component["rows"], dtype=np.int64)
        player_ids = np.asarray(component["player_ids"], dtype=np.int64)
        winner_ids = np.asarray(component["winner_ids"], dtype=np.int64)
        game_starts = np.asarray(component["game_starts"], dtype=np.int64)
        game_stops = np.asarray(component["game_stops"], dtype=np.int64)
        outcome_positive = player_ids == winner_ids
        component_weights = np.asarray(balanced[rows], dtype=np.float64)
        if bool(np.any(~np.isfinite(component_weights))) or bool(
            np.any(component_weights < 0.0)
        ):
            raise SystemExit(
                "sampler_balanced_v1 received non-finite or negative value weights"
            )
        has_truncated_games |= int(component["truncated_games"]) > 0
        positive_game_mass = 0.0
        negative_game_mass = 0.0
        positive_one_sided: list[tuple[int, int]] = []
        negative_one_sided: list[tuple[int, int]] = []
        component_has_positive = False
        component_has_negative = False
        for game_start, game_stop in zip(game_starts, game_stops, strict=True):
            start, stop = int(game_start), int(game_stop)
            signs = outcome_positive[start:stop]
            game_weights = component_weights[start:stop]
            positive = bool(np.any(signs))
            negative = bool(np.any(~signs))
            component_has_positive |= positive
            component_has_negative |= negative
            if not positive and not negative:
                raise SystemExit("sampler_balanced_v1 found an outcome-free game")
            if positive and negative:
                positive_players = np.unique(player_ids[start:stop][signs])
                negative_players = np.unique(player_ids[start:stop][~signs])
                if (
                    len(positive_players) != 1
                    or len(negative_players) != 1
                    or int(positive_players[0]) == int(negative_players[0])
                    or len(np.unique(player_ids[start:stop])) != 2
                    or len(np.unique(winner_ids[start:stop])) != 1
                ):
                    raise SystemExit(
                        "sampler_balanced_v1 found malformed bilateral player/winner "
                        f"coverage in component {component['component_id']!r}"
                    )
                positive_mass = float(game_weights[signs].sum())
                negative_mass = float(game_weights[~signs].sum())
                total_mass = positive_mass + negative_mass
                if positive_mass <= 0.0 or negative_mass <= 0.0:
                    raise SystemExit(
                        "sampler_balanced_v1 bilateral game has zero effective "
                        "winner or loser mass"
                    )
                game_weights[signs] *= total_mass / (2.0 * positive_mass)
                game_weights[~signs] *= total_mass / (2.0 * negative_mass)
            else:
                if len(np.unique(player_ids[start:stop])) != 1 or len(
                    np.unique(winner_ids[start:stop])
                ) != 1:
                    raise SystemExit(
                        "sampler_balanced_v1 found malformed one-sided player/winner "
                        f"coverage in component {component['component_id']!r}"
                    )
                game_mass = float(
                    np.mean(game_weights)
                    if bool(component["game_uniform_sampler"])
                    else np.sum(game_weights)
                )
                if game_mass <= 0.0:
                    raise SystemExit(
                        "sampler_balanced_v1 one-sided game has zero effective mass"
                    )
                if positive:
                    positive_one_sided.append((start, stop))
                    positive_game_mass += game_mass
                else:
                    negative_one_sided.append((start, stop))
                    negative_game_mass += game_mass
        if not component_has_positive or not component_has_negative:
            raise SystemExit(
                "sampler_balanced_v1 requires both outcome signs in every enabled "
                f"component: component={component['component_id']!r}"
            )
        if positive_one_sided or negative_one_sided:
            if positive_game_mass <= 0.0 or negative_game_mass <= 0.0:
                raise SystemExit(
                    "sampler_balanced_v1 requires positive and negative one-sided "
                    f"games together in component {component['component_id']!r}"
                )
            total_one_sided_mass = positive_game_mass + negative_game_mass
            positive_scale = total_one_sided_mass / (2.0 * positive_game_mass)
            negative_scale = total_one_sided_mass / (2.0 * negative_game_mass)
            for start, stop in positive_one_sided:
                component_weights[start:stop] *= positive_scale
            for start, stop in negative_one_sided:
                component_weights[start:stop] *= negative_scale
        balanced[rows] = component_weights.astype(np.float32)
        active_rows.append(rows[component_weights > 0.0])
    active = np.concatenate(active_rows)
    balanced_active = np.asarray(balanced[active], dtype=np.float64)
    balanced_active_mass = float(balanced_active.sum())
    if (
        not math.isfinite(balanced_active_mass)
        or balanced_active_mass <= 0.0
    ):
        raise SystemExit("sampler_balanced_v1 produced zero/non-finite global mass")
    if not has_truncated_games:
        # Preserve the established completed-only production behavior exactly.
        balanced[active] /= balanced_active_mass / float(len(active))
    else:
        completed_sampler_mass_after = _value_balance_completed_sampler_mass(
            components, ratios, balanced
        )
        if (
            not math.isfinite(completed_sampler_mass_before)
            or completed_sampler_mass_before <= 0.0
            or not math.isfinite(completed_sampler_mass_after)
            or completed_sampler_mass_after <= 0.0
        ):
            raise SystemExit(
                "sampler_balanced_v1 produced zero/non-finite completed sampler mass"
            )
        # Preserve the actual completed contribution under the authenticated
        # partition sampler, whose denominator still includes truncated games
        # or rows. Truncated VP-margin weights remain byte-identical.
        balanced[active] *= (
            completed_sampler_mass_before / completed_sampler_mass_after
        )
    return balanced


def _value_balance_completed_sampler_mass(
    components: list[dict[str, object]],
    ratios: tuple[float, ...],
    weights: np.ndarray,
) -> float:
    total_ratio = float(sum(ratios))
    mass = 0.0
    for component in components:
        rows = np.asarray(component["rows"], dtype=np.int64)
        local_weights = np.asarray(weights[rows], dtype=np.float64)
        if bool(component["game_uniform_sampler"]):
            starts = np.asarray(component["game_starts"], dtype=np.int64)
            stops = np.asarray(component["game_stops"], dtype=np.int64)
            component_mass = sum(
                float(np.mean(local_weights[int(start) : int(stop)]))
                for start, stop in zip(starts, stops, strict=True)
            ) / float(component["partition_games"])
        else:
            component_mass = float(local_weights.sum()) / float(
                component["partition_rows"]
            )
        mass += (
            float(component["ratio"]) / total_ratio
        ) * component_mass
    return mass


def _value_balance_measure(
    components: list[dict[str, object]],
    ratios: tuple[float, ...],
    weights: np.ndarray,
) -> dict[str, object]:
    total_ratio = sum(ratios)
    positive_mass = 0.0
    negative_mass = 0.0
    game_masses: list[float] = []
    player_cells: dict[str, dict[str, float | int]] = {}
    component_reports: dict[str, dict[str, object]] = {}
    bilateral_games = 0
    positive_one_sided_games = 0
    negative_one_sided_games = 0
    truncated_weight_sum = 0.0
    for component in components:
        rows = np.asarray(component["rows"], dtype=np.int64)
        truncated_rows = np.asarray(
            component["truncated_row_indices"], dtype=np.int64
        )
        player_ids = np.asarray(component["player_ids"], dtype=np.int64)
        winner_ids = np.asarray(component["winner_ids"], dtype=np.int64)
        names = tuple(component["identity_names"])
        starts = np.asarray(component["game_starts"], dtype=np.int64)
        stops = np.asarray(component["game_stops"], dtype=np.int64)
        local_weights = np.asarray(weights[rows], dtype=np.float64)
        signs = player_ids == winner_ids
        game_uniform_sampler = bool(component["game_uniform_sampler"])
        ratio = float(component["ratio"]) / total_ratio
        game_probability = (
            ratio / float(component["partition_games"])
            if game_uniform_sampler
            else 0.0
        )
        ordinary_row_probability = (
            ratio / float(component["partition_rows"])
            if not game_uniform_sampler
            else 0.0
        )
        component_positive = 0.0
        component_negative = 0.0
        component_bilateral = 0
        component_positive_one_sided = 0
        component_negative_one_sided = 0
        for start, stop in zip(starts, stops, strict=True):
            start_i, stop_i = int(start), int(stop)
            row_probability = (
                game_probability / float(stop_i - start_i)
                if game_uniform_sampler
                else ordinary_row_probability
            )
            game_signs = signs[start_i:stop_i]
            game_weights = local_weights[start_i:stop_i]
            positive = float(game_weights[game_signs].sum() * row_probability)
            negative = float(game_weights[~game_signs].sum() * row_probability)
            component_positive += positive
            component_negative += negative
            game_masses.append(positive + negative)
            if positive > 0.0 and negative > 0.0:
                component_bilateral += 1
            elif positive > 0.0:
                component_positive_one_sided += 1
            elif negative > 0.0:
                component_negative_one_sided += 1
        for identity_id, identity in enumerate(names):
            player_mask = player_ids == identity_id
            for label, outcome_mask in (("win", signs), ("loss", ~signs)):
                mask = player_mask & outcome_mask
                if not bool(np.any(mask)):
                    continue
                # Rows have game-dependent probability. Accumulate by game to
                # preserve the authenticated game-uniform measure.
                mass = 0.0
                for start, stop in zip(starts, stops, strict=True):
                    start_i, stop_i = int(start), int(stop)
                    local_mask = mask[start_i:stop_i]
                    if bool(np.any(local_mask)):
                        mass += float(
                            local_weights[start_i:stop_i][local_mask].sum()
                            * (
                                game_probability / float(stop_i - start_i)
                                if game_uniform_sampler
                                else ordinary_row_probability
                            )
                        )
                key = f"{identity}|{label}"
                cell = player_cells.setdefault(
                    key, {"raw_rows": 0, "effective_mass": 0.0}
                )
                cell["raw_rows"] = int(cell["raw_rows"]) + int(np.count_nonzero(mask))
                cell["effective_mass"] = float(cell["effective_mass"]) + mass
        component_reports[str(component["component_id"])] = {
            "partition_rows": int(component["partition_rows"]),
            "completed_non_truncated_rows": int(
                component["completed_non_truncated_rows"]
            ),
            "truncated_rows": int(component["truncated_rows"]),
            "partition_games": int(component["partition_games"]),
            "completed_non_truncated_games": int(
                component["completed_non_truncated_games"]
            ),
            "truncated_games": int(component["truncated_games"]),
            "completed_non_truncated_weight_sum": float(local_weights.sum()),
            "truncated_weight_sum": float(
                np.asarray(weights[truncated_rows], dtype=np.float64).sum()
            ),
            "games": int(len(starts)),
            "bilateral_games": int(component_bilateral),
            "one_sided_positive_games": int(component_positive_one_sided),
            "one_sided_negative_games": int(component_negative_one_sided),
            "positive_effective_mass": component_positive,
            "negative_effective_mass": component_negative,
            "total_effective_mass": component_positive + component_negative,
            "sampler_adjusted_target_mean": (
                (component_positive - component_negative)
                / (component_positive + component_negative)
                if component_positive + component_negative > 0.0
                else 0.0
            ),
        }
        positive_mass += component_positive
        negative_mass += component_negative
        bilateral_games += component_bilateral
        positive_one_sided_games += component_positive_one_sided
        negative_one_sided_games += component_negative_one_sided
        truncated_weight_sum += float(
            np.asarray(weights[truncated_rows], dtype=np.float64).sum()
        )
    total_mass = positive_mass + negative_mass
    game_mass_array = np.asarray(game_masses, dtype=np.float64)
    game_ess_denom = float(np.sum(game_mass_array * game_mass_array))
    outcome_masses = np.asarray([positive_mass, negative_mass], dtype=np.float64)
    outcome_ess_denom = float(np.sum(outcome_masses * outcome_masses))
    return {
        "rows": int(sum(len(np.asarray(component["rows"])) for component in components)),
        "completed_non_truncated_weight_sum": float(
            sum(
                np.asarray(
                    weights[np.asarray(component["rows"], dtype=np.int64)],
                    dtype=np.float64,
                ).sum()
                for component in components
            )
        ),
        "truncated_weight_sum": truncated_weight_sum,
        "games": int(len(game_masses)),
        "bilateral_games": int(bilateral_games),
        "one_sided_positive_games": int(positive_one_sided_games),
        "one_sided_negative_games": int(negative_one_sided_games),
        "positive_effective_mass": positive_mass,
        "negative_effective_mass": negative_mass,
        "total_effective_mass": total_mass,
        "positive_effective_fraction": (
            positive_mass / total_mass if total_mass > 0.0 else 0.0
        ),
        "negative_effective_fraction": (
            negative_mass / total_mass if total_mass > 0.0 else 0.0
        ),
        "sampler_adjusted_target_mean": (
            (positive_mass - negative_mass) / total_mass if total_mass > 0.0 else 0.0
        ),
        "game_effective_sample_size": (
            float(game_mass_array.sum() ** 2 / game_ess_denom)
            if game_ess_denom > 0.0
            else 0.0
        ),
        "outcome_effective_sample_size": (
            float(outcome_masses.sum() ** 2 / outcome_ess_denom)
            if outcome_ess_denom > 0.0
            else 0.0
        ),
        "player_outcome_cells": dict(sorted(player_cells.items())),
        "components": component_reports,
    }


def value_player_outcome_balance_quality(
    data: dict,
    before_weights: np.ndarray,
    after_weights: np.ndarray,
    row_indices: np.ndarray,
    *,
    mode: str,
    per_game_weighting: dict[str, object] | None = None,
) -> dict[str, object]:
    if mode == "none":
        return {
            "schema_version": "value-player-outcome-balance-v1",
            "mode": "none",
            "enabled": False,
            "per_game_weighting": dict(per_game_weighting or {}),
        }
    components, ratios = _value_balance_components(data, row_indices)
    completed_rows = int(
        sum(len(np.asarray(component["rows"])) for component in components)
    )
    value_enabled_partition_rows = int(
        sum(int(component["partition_rows"]) for component in components)
    )
    truncated_rows = int(
        sum(int(component["truncated_rows"]) for component in components)
    )
    completed_games = int(
        sum(int(component["completed_non_truncated_games"]) for component in components)
    )
    truncated_games = int(
        sum(int(component["truncated_games"]) for component in components)
    )
    return {
        "schema_version": "value-player-outcome-balance-v1",
        "mode": str(mode),
        "enabled": True,
        "fit_partition_rows": int(len(row_indices)),
        "value_enabled_partition_rows": value_enabled_partition_rows,
        "completed_non_truncated_rows": completed_rows,
        "truncated_rows": truncated_rows,
        "completed_non_truncated_games": completed_games,
        "truncated_games": truncated_games,
        "normalization_policy": (
            "preserve_actual_completed_sampler_mass_when_truncated_else_legacy_mean_one"
        ),
        "per_game_weighting": dict(per_game_weighting or {}),
        "before": _value_balance_measure(components, ratios, before_weights),
        "after": _value_balance_measure(components, ratios, after_weights),
    }


def _legal_action_counts(
    legal_column: object,
    row_indices: np.ndarray | None = None,
) -> np.ndarray:
    compact_row_counts = getattr(legal_column, "row_counts", None)
    if callable(compact_row_counts):
        counts = compact_row_counts(row_indices)
    elif row_indices is None:
        counts = np.sum(np.asarray(legal_column) >= 0, axis=1)
    else:
        counts = np.sum(np.asarray(legal_column[row_indices]) >= 0, axis=1)
    return np.asarray(counts, dtype=np.int64)


def _action_catalog_type_projection(
    action_catalog: object | None,
    configured_weights: Mapping[str, float],
) -> tuple[np.ndarray, tuple[str, ...]]:
    """Build dense action-id multipliers from the authoritative catalog."""

    if action_catalog is None:
        raise SystemExit(
            "--forced-row-value-action-type-weights requires an ActionCatalog"
        )
    size = int(getattr(action_catalog, "size", -1))
    describe = getattr(action_catalog, "describe", None)
    if size <= 0 or not callable(describe):
        raise SystemExit("forced-row value weighting received an invalid ActionCatalog")
    action_types = tuple(
        str(describe(action_id)["action_type"]).upper()
        for action_id in range(size)
    )
    malformed = {
        str(name): value
        for name, value in configured_weights.items()
        if (
            str(name) != str(name).upper()
            or not _ACTION_TYPE_NAME_RE.fullmatch(str(name))
            or not math.isfinite(float(value))
            or float(value) < 0.0
        )
    }
    if malformed:
        raise SystemExit(
            "forced-row value action-type weights are malformed: "
            f"{malformed!r}"
        )
    known_types = set(action_types)
    unknown = set(configured_weights) - known_types
    if unknown:
        raise SystemExit(
            "--forced-row-value-action-type-weights names unknown ActionCatalog "
            f"types {sorted(unknown)}; known={sorted(known_types)}"
        )
    multipliers = np.fromiter(
        (float(configured_weights.get(name, 1.0)) for name in action_types),
        dtype=np.float32,
        count=size,
    )
    return multipliers, action_types


def _validated_forced_action_ids(
    data: dict,
    forced_mask: np.ndarray,
    *,
    action_catalog_size: int,
    row_indices: np.ndarray | None = None,
) -> np.ndarray:
    forced = np.asarray(forced_mask, dtype=np.bool_)
    if forced.ndim != 1:
        raise ValueError("forced-row mask must be one-dimensional")
    if row_indices is None:
        if forced.shape[0] != len(data["action_taken"]):
            raise ValueError("forced-row mask length does not match corpus rows")
        actions = np.asarray(data["action_taken"])[forced]
        forced_rows = np.flatnonzero(forced)
    else:
        source_rows = np.asarray(row_indices, dtype=np.int64)
        if source_rows.ndim != 1 or forced.shape[0] != source_rows.shape[0]:
            raise ValueError("forced-row scope does not match its row indices")
        actions = np.asarray(data["action_taken"][source_rows])[forced]
        forced_rows = source_rows[np.flatnonzero(forced)]
    action_ids = np.asarray(actions, dtype=np.int64)
    if (
        action_ids.shape != actions.shape
        or np.any(action_ids < 0)
        or np.any(action_ids >= action_catalog_size)
        or not np.array_equal(action_ids, actions)
    ):
        raise SystemExit(
            "forced-row action_taken contains an id outside the active ActionCatalog"
        )
    legal_column = data.get("legal_action_ids")
    if legal_column is None:
        raise SystemExit("forced-row action validation requires legal_action_ids")
    forced_legal = np.asarray(legal_column[forced_rows])
    if forced_legal.ndim != 2 or forced_legal.shape[0] != action_ids.shape[0]:
        raise SystemExit("forced-row legal action payload is malformed")
    sole_legal = np.where(forced_legal >= 0, forced_legal, -1).max(axis=1)
    if np.any(sole_legal < 0) or not np.array_equal(action_ids, sole_legal):
        mismatch = int(np.flatnonzero(action_ids != sole_legal)[0])
        raise SystemExit(
            "forced-row action_taken does not match its sole legal action: "
            f"row={int(forced_rows[mismatch])} "
            f"action_taken={int(action_ids[mismatch])} "
            f"sole_legal_action={int(sole_legal[mismatch])}"
        )
    return action_ids


def _forced_value_nominal_population_measure(
    training_value_sample_weights: np.ndarray,
    train_indices: np.ndarray,
    *,
    base_sampler: str,
    component_game_sampling: np.ndarray | None,
    objective_confidence: np.ndarray | None = None,
) -> tuple[np.ndarray, str]:
    """Materialize the intended scalar-value population objective measure."""

    indices = np.asarray(train_indices, dtype=np.int64)
    if indices.ndim != 1:
        raise ValueError("training value objective indices must be one-dimensional")
    source_weights = np.asarray(training_value_sample_weights)
    if (
        source_weights.ndim != 1
        or np.any(indices < 0)
        or np.any(indices >= source_weights.shape[0])
    ):
        raise ValueError("training value objective rows are not weight-aligned")
    weights = np.asarray(source_weights[indices], dtype=np.float64)
    if objective_confidence is not None:
        confidence = np.asarray(objective_confidence, dtype=np.float64)
        if (
            confidence.ndim != 1
            or confidence.shape != indices.shape
            or not np.isfinite(confidence).all()
            or np.any(confidence < 0.0)
        ):
            raise ValueError(
                "scalar value objective confidence must be non-negative, "
                "finite, and aligned to training rows"
            )
        weights *= confidence
    if base_sampler == BASE_SAMPLER_COVERAGE_IMPORTANCE_V1:
        # Coverage has already transferred authenticated p_i onto its uniform
        # traversal as N*p_i inside training_value_sample_weights. A fixed
        # normalizer is a scalar and therefore cannot change mass fractions.
        return weights, "coverage_importance_scalar_outcome_value_loss_v1"
    if base_sampler != BASE_SAMPLER_WEIGHTED_REPLACEMENT_V1:
        raise ValueError(f"unsupported base sampler {base_sampler!r}")
    if component_game_sampling is None:
        # Ordinary corpora use the uniform epoch path. The omitted 1/N factor
        # is common to every row and cancels from all reported fractions.
        return weights, "uniform_training_row_scalar_outcome_value_loss_v1"
    probabilities = np.asarray(component_game_sampling, dtype=np.float64)
    if (
        probabilities.ndim != 1
        or probabilities.shape != indices.shape
        or not np.isfinite(probabilities).all()
        or np.any(probabilities < 0.0)
        or not math.isclose(
            float(probabilities.sum()), 1.0, rel_tol=0.0, abs_tol=1.0e-9
        )
    ):
        raise ValueError(
            "authenticated weighted-replacement probabilities must be "
            "non-negative, normalized, and aligned to training rows"
        )
    # Weighted replacement visits row i with probability p_i. Its population
    # value objective therefore has mass p_i * loss_weight_i.
    weights *= probabilities
    return (
        weights,
        "authenticated_weighted_replacement_scalar_outcome_value_loss_v1",
    )


def forced_action_type_value_mass_quality(
    data: dict,
    weights: np.ndarray,
    *,
    row_indices: np.ndarray | None = None,
    weights_aligned_to_rows: bool = False,
    objective_measure: str = "supplied_value_loss_weights",
    objective_active: bool = True,
    action_catalog: object,
    configured_weights: Mapping[str, float],
) -> dict[str, object]:
    """Report forced-action mass under an explicit value objective measure.

    ``weights`` is full-corpus aligned. ``row_indices`` selects the unique
    population whose optimizer objective is being audited; callers using a
    non-uniform sampler must supply weights that already include its draw
    measure. This keeps validation rows and pre-sampler weights from silently
    contaminating the production training-signal report.
    """

    multipliers, action_types = _action_catalog_type_projection(
        action_catalog, configured_weights
    )
    if "legal_action_ids" not in data:
        raise SystemExit(
            "forced action-type value mass reporting requires legal_action_ids"
        )
    row_count = len(data["action_taken"])
    if not isinstance(objective_measure, str) or not objective_measure.strip():
        raise ValueError("forced action-type objective measure must be non-empty")
    if row_indices is None:
        scope_rows = None
        scope_row_count = row_count
        scope_name = "all_rows"
    else:
        scope_rows = np.asarray(row_indices)
        if scope_rows.ndim != 1:
            raise ValueError("forced action-type value scope must be one-dimensional")
        if not np.issubdtype(scope_rows.dtype, np.integer):
            raise ValueError("forced action-type value scope must contain row indices")
        scope_rows = scope_rows.astype(np.int64, copy=False)
        if np.any(scope_rows < 0) or np.any(scope_rows >= row_count):
            raise ValueError("forced action-type value scope row is out of range")
        if scope_rows.size > 1 and np.any(scope_rows[1:] <= scope_rows[:-1]):
            raise ValueError(
                "forced action-type value scope rows must be unique and "
                "strictly increasing"
            )
        scope_row_count = int(scope_rows.size)
        scope_name = "training_rows"
    final_weights = np.asarray(weights, dtype=np.float64)
    expected_weight_rows = (
        scope_row_count if bool(weights_aligned_to_rows) else row_count
    )
    if (
        final_weights.ndim != 1
        or final_weights.shape[0] != expected_weight_rows
        or not np.isfinite(final_weights).all()
        or np.any(final_weights < 0.0)
        or (bool(weights_aligned_to_rows) and scope_rows is None)
    ):
        alignment = (
            "selected scope rows"
            if bool(weights_aligned_to_rows)
            else "corpus rows"
        )
        raise ValueError(
            "forced action-type value objective weights must be finite, "
            f"non-negative, and aligned to {alignment}"
        )
    scoped_weights = (
        final_weights
        if bool(weights_aligned_to_rows) or scope_rows is None
        else final_weights[scope_rows]
    )
    forced = _legal_action_counts(
        data["legal_action_ids"], scope_rows
    ) == 1
    action_ids = _validated_forced_action_ids(
        data,
        forced,
        action_catalog_size=len(multipliers),
        row_indices=scope_rows,
    )
    counts_by_id = np.bincount(action_ids, minlength=len(multipliers))
    mass_by_id = np.bincount(
        action_ids,
        weights=scoped_weights[forced],
        minlength=len(multipliers),
    )
    rows_by_type: dict[str, int] = {}
    mass_by_type: dict[str, float] = {}
    for action_id, action_type in enumerate(action_types):
        rows_by_type[action_type] = rows_by_type.get(action_type, 0) + int(
            counts_by_id[action_id]
        )
        mass_by_type[action_type] = mass_by_type.get(action_type, 0.0) + float(
            mass_by_id[action_id]
        )
    forced_mass = float(np.sum(scoped_weights[forced]))
    total_mass = float(np.sum(scoped_weights))
    by_action_type = {
        action_type: {
            "rows": rows_by_type[action_type],
            "configured_multiplier": float(
                configured_weights.get(action_type, 1.0)
            ),
            "effective_value_mass": mass_by_type[action_type],
            "fraction_of_forced_value_mass": (
                mass_by_type[action_type] / forced_mass if forced_mass > 0.0 else 0.0
            ),
            "fraction_of_total_value_mass": (
                mass_by_type[action_type] / total_mass if total_mass > 0.0 else 0.0
            ),
        }
        for action_type in sorted(rows_by_type)
        if rows_by_type[action_type] > 0
    }
    return {
        "schema_version": "forced-action-type-value-mass-v2",
        "enabled": True,
        "scope": scope_name,
        "scope_rows": scope_row_count,
        "weights_alignment": (
            "scope_rows" if bool(weights_aligned_to_rows) else "corpus_rows"
        ),
        "objective_measure": str(objective_measure),
        "objective": "scalar_outcome_value_loss",
        "objective_active": bool(objective_active),
        "measure_semantics": "nominal_population_objective_v1",
        "mass_scale_semantics": (
            "raw_mass_units_are_objective_measure_specific;fractions_only_are_"
            "cross_sampler_comparable"
        ),
        "realized_optimizer_coefficient_semantics": (
            "coverage_fixed_denominator_is_unbiased;uniform_and_weighted_"
            "replacement_self_normalized_microbatches_are_not_exactly_"
            "represented"
        ),
        "configured_weights": {
            key: float(configured_weights[key]) for key in sorted(configured_weights)
        },
        "forced_rows": int(np.count_nonzero(forced)),
        "forced_row_fraction": (
            float(np.mean(forced)) if len(forced) else 0.0
        ),
        "effective_forced_value_mass": forced_mass,
        "effective_total_value_mass": total_mass,
        "effective_forced_value_mass_fraction": (
            forced_mass / total_mass if total_mass > 0.0 else 0.0
        ),
        "by_action_type": by_action_type,
    }


def forced_scalar_value_mass_admission(
    mass_report: Mapping[str, object] | None,
    *,
    maximum_fraction: float | None,
) -> dict[str, object]:
    """Build the fail-closed admission record for forced scalar-value mass."""

    enforced = maximum_fraction is not None
    if maximum_fraction is not None and (
        not math.isfinite(float(maximum_fraction))
        or not 0.0 <= float(maximum_fraction) <= 1.0
    ):
        raise ValueError(
            "forced scalar-value mass ceiling must be finite and in [0, 1]"
        )

    objective_active = bool(
        mass_report is not None and mass_report.get("objective_active") is True
    )
    total_mass = (
        None
        if mass_report is None
        else float(mass_report.get("effective_total_value_mass", 0.0))
    )
    observed = (
        None
        if mass_report is None or total_mass is None or total_mass <= 0.0
        else float(
            mass_report.get("effective_forced_value_mass_fraction", float("nan"))
        )
    )
    valid_observation = bool(
        objective_active
        and total_mass is not None
        and math.isfinite(total_mass)
        and total_mass > 0.0
        and observed is not None
        and math.isfinite(observed)
        and 0.0 <= observed <= 1.0
    )
    if not enforced:
        admitted = True
        reason = "ceiling_disabled"
    elif not objective_active:
        admitted = False
        reason = "scalar_outcome_value_objective_inactive_or_unauthenticated"
    elif not valid_observation:
        admitted = False
        reason = "nominal_scalar_value_mass_unavailable_or_zero"
    elif observed <= float(maximum_fraction):
        admitted = True
        reason = "observed_fraction_within_ceiling"
    else:
        admitted = False
        reason = "observed_fraction_exceeds_ceiling"

    return {
        "schema_version": "forced-scalar-value-mass-admission-v1",
        "objective": "scalar_outcome_value_loss",
        "objective_active": objective_active,
        "scope": (None if mass_report is None else mass_report.get("scope")),
        "measure_semantics": (
            None if mass_report is None else mass_report.get("measure_semantics")
        ),
        "objective_measure": (
            None if mass_report is None else mass_report.get("objective_measure")
        ),
        "observed_nominal_forced_mass_fraction": observed,
        "maximum_nominal_forced_scalar_value_mass_fraction": (
            None if maximum_fraction is None else float(maximum_fraction)
        ),
        "admission_enforced": enforced,
        "admitted": admitted,
        "reason": reason,
        "comparison": "observed <= maximum",
        "source_report_schema_version": (
            None if mass_report is None else mass_report.get("schema_version")
        ),
        "raw_mass_cross_sampler_comparable": False,
    }


def _validated_component_offsets(data: dict, n: int) -> np.ndarray | None:
    """Return trusted composite row offsets, or ``None`` for an ordinary corpus."""

    raw = getattr(data, "component_offsets", None)
    if raw is None:
        return None
    offsets = np.asarray(raw, dtype=np.int64)
    if (
        offsets.ndim != 1
        or offsets.size < 2
        or int(offsets[0]) != 0
        or int(offsets[-1]) != int(n)
        or np.any(offsets[1:] <= offsets[:-1])
    ):
        raise ValueError("composite component_offsets do not partition learner rows")
    return offsets


def _component_row_ranges(
    component_offsets: np.ndarray | None, n: int
) -> tuple[tuple[int, int], ...]:
    if component_offsets is None:
        return ((0, int(n)),)
    return tuple(
        (int(start), int(stop))
        for start, stop in zip(component_offsets[:-1], component_offsets[1:], strict=True)
    )


def _normalize_weights_per_game(
    data: dict,
    weights: np.ndarray,
    *,
    mode: str = "equal",
    diagnostics: dict[str, object] | None = None,
) -> np.ndarray:
    """Rescale weights under the corpus's actual row-sampling measure.

    Ordinary corpora are sampled uniformly by row, so ``equal`` divides by a
    game's summed weight and ``sqrt`` by its square root. Authenticated
    composite-v2 corpora already sample ``component -> game -> row``. Under
    that measure a game's contribution is its *mean* row weight, not its sum;
    dividing by the sum again biases the objective toward short games. For
    those corpora, ``equal`` therefore divides by mean weight and ``sqrt`` by
    its square root. This preserves the named game-mass semantics instead of
    double-correcting a sampler that is already game-uniform.

    A one-row-per-game fallback would silently collapse every row's weight to
    exactly 1.0, erasing phase/forced/CAT-45 weights. A missing ``game_seed``
    therefore fails closed whenever per-game weighting is explicitly enabled.
    """

    if "game_seed" not in data:
        raise SystemExit(
            "per-game weighting requires a populated game_seed column; refusing "
            "the historical silent no-op"
        )
    seeds = np.asarray(data["game_seed"], dtype=np.int64)
    weights64 = weights.astype(np.float64, copy=False)
    if mode not in {"equal", "sqrt"}:
        raise ValueError(f"unknown per_game_value_weight_mode {mode!r}")
    normalized = np.empty_like(weights64)
    denominators: list[np.ndarray] = []
    component_offsets = _validated_component_offsets(data, len(weights64))
    game_uniform_sampler = bool(
        tuple(getattr(data, "component_game_sampling_ratios", tuple()))
    )
    for start, stop in _component_row_ranges(component_offsets, len(weights64)):
        _unique_seeds, inverse, game_row_counts = np.unique(
            seeds[start:stop], return_inverse=True, return_counts=True
        )
        game_totals = np.zeros(len(_unique_seeds), dtype=np.float64)
        np.add.at(game_totals, inverse, weights64[start:stop])
        game_mass = (
            game_totals / game_row_counts.astype(np.float64)
            if game_uniform_sampler
            else game_totals
        )
        safe_mass = np.where(game_mass > 0.0, game_mass, 1.0)
        if mode == "sqrt":
            denominator = np.sqrt(safe_mass)
        else:
            denominator = safe_mass
        denominators.append(np.asarray(denominator, dtype=np.float64))
        normalized[start:stop] = weights64[start:stop] / denominator[inverse]
    if diagnostics is not None:
        combined = (
            np.concatenate(denominators)
            if denominators
            else np.asarray([], dtype=np.float64)
        )
        spread = float(combined.std()) if combined.size else 0.0
        scale = float(np.mean(np.abs(combined))) if combined.size else 1.0
        diagnostics.update(
            {
                "requested": True,
                "mode": str(mode),
                # A common denominator is erased by the final global mean
                # normalization. Only between-game denominator variation changes
                # the realized objective.
                "effective": bool(
                    combined.size > 1
                    and spread > max(1e-12, 1e-9 * max(scale, 1.0))
                ),
                "game_count": int(combined.size),
                "denominator": (
                    {
                        "min": float(combined.min()),
                        "max": float(combined.max()),
                        "mean": float(combined.mean()),
                        "std": spread,
                    }
                    if combined.size
                    else {}
                ),
            }
        )
    return normalized.astype(np.float32, copy=False)


def _parse_game_seed_ranges(raw: str) -> list[tuple[int, int]]:
    """Parse "start1:end1,start2:end2" (inclusive bounds) for
    --validation-game-seed-ranges. Matches a holdout.json's documented ranges
    (task #65 value-head-repair-v2 protocol)."""
    ranges: list[tuple[int, int]] = []
    for chunk in raw.split(","):
        chunk = chunk.strip()
        if not chunk:
            continue
        if ":" not in chunk:
            raise SystemExit(f"invalid --validation-game-seed-ranges entry {chunk!r}: expected start:end")
        start_str, end_str = chunk.split(":", 1)
        start, end = int(start_str), int(end_str)
        if end < start:
            raise SystemExit(f"invalid --validation-game-seed-ranges entry {chunk!r}: end < start")
        ranges.append((start, end))
    return ranges


def split_train_validation_indices(
    data: dict,
    *,
    validation_fraction: float,
    validation_seed: int,
    validation_max_samples: int,
    validation_game_seed_ranges: list[tuple[int, int]] | None = None,
    validation_game_seeds: np.ndarray | None = None,
    training_excluded_game_seeds: np.ndarray | None = None,
    allow_missing_game_seed: bool = False,
) -> dict[str, np.ndarray]:
    """Split into train/validation indices.

    CAT-52 AUDIT (2026-07-08, see AUDIT.md): every path below is REQUIRED to be
    game-level (grouping/filtering by ``data["game_seed"]``, one value per GAME,
    repeated across every decision row of that game), never row-level -- a
    row-level split is the exact mechanism that caused the round-11 val-leak
    incident (per-round random re-splits leaked ~95% of validation rows,
    because the "split" secretly operated per-ROW instead of per-GAME).

    Both branches below used to silently default a MISSING ``"game_seed"``
    column to ``np.arange(n)`` -- i.e. treat every row as its own distinct
    "game". That default defeats game-level grouping by construction (each
    row becomes a singleton group) and reproduces the round-11 mechanism
    exactly, with no warning. Refuse it by default; ``allow_missing_game_seed``
    is an explicit, loud opt-out for callers that genuinely have no game_seed
    column (documented as a row-level split when used).
    """
    n = int(len(data["action_taken"]))
    all_indices = np.arange(n, dtype=np.int64)
    if "game_seed" not in data and not allow_missing_game_seed:
        raise SystemExit(
            "split_train_validation_indices: data has no 'game_seed' column. "
            "Defaulting to a row-index-as-seed split would silently degrade to a "
            "ROW-LEVEL split (the exact round-11 val-leak mechanism -- see "
            "AUDIT.md), so this is refused by default. Pass "
            "allow_missing_game_seed=True (train_bc.py: "
            "--allow-missing-game-seed-validation-split) only if you have "
            "verified this corpus has no meaningful game grouping and a "
            "row-level split is acceptable for your use case."
        )
    if validation_game_seeds is not None:
        if validation_game_seed_ranges:
            raise SystemExit(
                "choose validation_game_seeds or validation_game_seed_ranges, not both"
            )
        if int(validation_max_samples) != 0:
            raise SystemExit(
                "an exact validation game-seed manifest requires "
                "validation_max_samples=0"
            )
        if "game_seed" not in data:
            raise SystemExit(
                "an exact validation game-seed manifest requires a game_seed column"
            )
        requested = np.asarray(validation_game_seeds, dtype=np.int64).reshape(-1)
        if requested.size == 0 or len(np.unique(requested)) != len(requested):
            raise SystemExit(
                "exact validation game seeds must be non-empty and unique"
            )
        seeds = np.asarray(data["game_seed"], dtype=np.int64)
        present = set(map(int, np.unique(seeds).tolist()))
        missing = set(map(int, requested.tolist())) - present
        if missing:
            raise SystemExit(
                "exact validation game-seed manifest references games absent from "
                f"the corpus: missing={len(missing)}"
            )
        excluded = (
            requested
            if training_excluded_game_seeds is None
            else np.asarray(training_excluded_game_seeds, dtype=np.int64).reshape(-1)
        )
        if excluded.size == 0 or len(np.unique(excluded)) != len(excluded):
            raise SystemExit("training-excluded game seeds must be non-empty and unique")
        excluded_set = set(map(int, excluded.tolist()))
        if not set(map(int, requested.tolist())).issubset(excluded_set):
            raise SystemExit("validation game seeds must be a subset of training exclusions")
        excluded_missing = excluded_set - present
        if excluded_missing:
            raise SystemExit(
                "training-excluded game seeds reference games absent from the corpus: "
                f"missing={len(excluded_missing)}"
            )
        validation_mask = np.isin(seeds, requested)
        validation = all_indices[validation_mask]
        train = all_indices[~np.isin(seeds, excluded)]
        if len(train) == 0:
            raise SystemExit(
                "exact validation game-seed manifest selects the entire corpus"
            )
        return {
            "train": train.astype(np.int64, copy=False),
            "validation": validation.astype(np.int64, copy=False),
        }
    if validation_game_seed_ranges:
        # Explicit, deterministic held-out set (task #65): overrides the random
        # game_seed permutation below entirely -- these EXACT games are what a
        # holdout.json documents for coordination with the separate calibration
        # probe (docs/catan_postrepair_revalidation_protocol_20260704.md Step 1).
        if int(validation_max_samples) != 0:
            raise SystemExit(
                "explicit validation game-seed ranges require "
                "validation_max_samples=0; a row cap would split held-out games"
            )
        seeds = np.asarray(data["game_seed"], dtype=np.int64)
        present_seeds = np.unique(seeds)
        for start, end in validation_game_seed_ranges:
            matched = present_seeds[
                (present_seeds >= int(start)) & (present_seeds <= int(end))
            ]
            expected_games = int(end) - int(start) + 1
            if matched.size != expected_games:
                missing_games = expected_games - int(matched.size)
                coverage = "absent" if matched.size == 0 else "partial"
                raise SystemExit(
                    "explicit validation game-seed range is "
                    f"{coverage} from the corpus: range=[{start}, {end}] "
                    f"expected_games={expected_games} "
                    f"present_games={int(matched.size)} "
                    f"missing_games={missing_games}"
                )
        validation_mask = np.zeros(n, dtype=bool)
        for start, end in validation_game_seed_ranges:
            validation_mask |= (seeds >= start) & (seeds <= end)
        validation = all_indices[validation_mask]
        train = all_indices[~validation_mask]
        if len(validation) == 0:
            raise SystemExit(
                "explicit validation game-seed ranges select no validation rows"
            )
        if len(train) == 0:
            raise SystemExit(
                "explicit validation game-seed ranges select the entire corpus"
            )
        return {
            "train": train.astype(np.int64, copy=False),
            "validation": validation.astype(np.int64, copy=False),
        }
    fraction = float(np.clip(validation_fraction, 0.0, 0.9))
    if n == 0 or fraction <= 0.0:
        return {
            "train": all_indices,
            "validation": np.asarray([], dtype=np.int64),
        }
    seeds = np.asarray(data.get("game_seed", np.arange(n, dtype=np.int64)), dtype=np.int64)
    component_offsets = _validated_component_offsets(data, n)
    component_ratios = tuple(
        getattr(data, "component_game_sampling_ratios", tuple())
    )
    if component_offsets is not None and component_ratios:
        if len(component_ratios) != len(component_offsets) - 1:
            raise SystemExit("composite validation component ratio count drift")
        train_parts: list[np.ndarray] = []
        validation_parts: list[np.ndarray] = []
        for component_index, (start, stop) in enumerate(
            _component_row_ranges(component_offsets, n)
        ):
            local_indices = np.arange(start, stop, dtype=np.int64)
            local_seeds = seeds[start:stop]
            unique_local, unique_local_counts = np.unique(
                local_seeds, return_counts=True
            )
            if unique_local.size <= 1:
                raise SystemExit(
                    "promotion-eligible composite validation requires at least two "
                    f"games per component; component={component_index}"
                )
            rng = np.random.default_rng(validation_seed + component_index)
            shuffled = rng.permutation(unique_local)
            target_rows = max(1, int(round(len(local_indices) * fraction)))
            selected: list[int] = []
            selected_rows = 0
            # ``unique_local`` is sorted, so one search maps the seeded
            # permutation back to the counts computed by the same O(rows)
            # pass.  The old dict comprehension rescanned every corpus row for
            # every game (O(games * rows)); on a production composite that made
            # validation preflight dominate or appear stalled before the first
            # optimizer step.
            shuffled_counts = unique_local_counts[
                np.searchsorted(unique_local, shuffled)
            ]
            for seed, game_rows in zip(shuffled, shuffled_counts, strict=True):
                selected.append(int(seed))
                selected_rows += int(game_rows)
                if selected_rows >= target_rows:
                    break
            validation_mask = np.isin(
                local_seeds, np.asarray(selected, dtype=np.int64)
            )
            validation_parts.append(local_indices[validation_mask])
            train_parts.append(local_indices[~validation_mask])
        train = np.concatenate(train_parts).astype(np.int64, copy=False)
        validation = np.concatenate(validation_parts).astype(np.int64, copy=False)
        # Composite training explicitly requires validation_max_samples=0;
        # retaining this assertion here prevents a future direct caller from
        # silently row-capping a whole-game split.
        if validation_max_samples != 0:
            raise SystemExit(
                "composite component-aware validation forbids row-level caps"
            )
        return {"train": train, "validation": validation}
    unique_seeds = np.unique(seeds)
    row_level_fallback = unique_seeds.size <= 1
    if row_level_fallback:
        if n >= 1000:
            raise SystemExit(
                "validation_fraction requires non-degenerate game_seed values for "
                "large teacher datasets; refusing row-level validation split because "
                "it can leak decisions from the same game into train and validation."
            )
        print(
            "WARNING: split_train_validation_indices is falling back to a ROW-LEVEL "
            f"random split ({n} rows, {unique_seeds.size} unique game_seed value(s)) -- "
            "this is the round-11 val-leak mechanism (see AUDIT.md). Only acceptable "
            "for tiny synthetic/smoke corpora where within-game correlation across "
            "train/validation is a non-issue; never for a real training corpus.",
            file=sys.stderr,
        )
        rng = np.random.default_rng(validation_seed)
        shuffled = rng.permutation(all_indices)
        validation_count = max(1, int(round(n * fraction)))
        validation = np.sort(shuffled[:validation_count])
        train = np.sort(shuffled[validation_count:])
    else:
        rng = np.random.default_rng(validation_seed)
        unique_seeds, unique_seed_counts = np.unique(seeds, return_counts=True)
        shuffled_seeds = rng.permutation(unique_seeds)
        target_rows = max(1, int(round(n * fraction)))
        if validation_max_samples > 0:
            target_rows = min(target_rows, int(validation_max_samples))
        selected: list[int] = []
        selected_rows = 0
        shuffled_counts = unique_seed_counts[
            np.searchsorted(unique_seeds, shuffled_seeds)
        ]
        for seed, game_rows in zip(
            shuffled_seeds, shuffled_counts, strict=True
        ):
            selected.append(int(seed))
            selected_rows += int(game_rows)
            if selected_rows >= target_rows:
                break
        validation_mask = np.isin(seeds, np.asarray(selected, dtype=np.int64))
        validation = all_indices[validation_mask]
        train = all_indices[~validation_mask]
    if (
        row_level_fallback
        and validation_max_samples > 0
        and len(validation) > validation_max_samples
    ):
        rng = np.random.default_rng(validation_seed + 1)
        validation = np.sort(rng.choice(validation, size=validation_max_samples, replace=False))
    if len(train) == 0:
        train = np.setdiff1d(all_indices, validation[: max(0, len(validation) - 1)], assume_unique=False)
        validation = np.setdiff1d(all_indices, train, assume_unique=False)
    return {
        "train": train.astype(np.int64, copy=False),
        "validation": validation.astype(np.int64, copy=False),
    }


def _distributed_index_slice(indices: np.ndarray, ddp: dict[str, int | bool]) -> np.ndarray:
    if not ddp["enabled"]:
        return indices
    world_size = int(ddp["world_size"])
    rank = int(ddp["rank"])
    return np.asarray(indices, dtype=np.int64)[rank::world_size]


def _set_policy_training(policy, training: bool) -> list[tuple[object, bool]]:
    seen: set[int] = set()
    modes: list[tuple[object, bool]] = []
    for name in ("model", "actor", "action_encoder", "action_id_embedding", "action_bias"):
        module = getattr(policy, name, None)
        if module is None or not hasattr(module, "train") or id(module) in seen:
            continue
        seen.add(id(module))
        modes.append((module, bool(getattr(module, "training", False))))
        module.train(bool(training))
    return modes


def _restore_policy_training(policy, modes: list[tuple[object, bool]]) -> None:
    del policy
    for module, was_training in modes:
        if hasattr(module, "train"):
            module.train(was_training)


def _parse_weight_map(raw: str) -> dict[str, float]:
    weights: dict[str, float] = {}
    for part in raw.split(","):
        item = part.strip()
        if not item:
            continue
        if "=" not in item:
            raise SystemExit(f"invalid --teacher-weights entry: {item}")
        name, value = item.split("=", 1)
        weights[name.strip()] = float(value)
    return weights


def _validate_loss_weight_map_realization(
    data: Mapping[str, object],
    weights: Mapping[str, float],
    *,
    column: str,
    option: str,
) -> dict[str, object]:
    """Prove that a configured loss-weight treatment changes real rows.

    Phase and teacher maps are science coefficients, not best-effort labels.
    Historically a spelling/case/schema drift (for example ``play_turn`` vs
    ``PLAY_TURN``) matched zero rows and silently reduced the requested
    treatment to the control objective.  Non-finite or negative multipliers
    were even worse: they could poison or reverse gradients before the generic
    finite-loss guard noticed.  Admit the treatment once, before derived-array
    construction or GPU work, and bind its exact realized row support.
    """

    configured = {str(name): float(value) for name, value in weights.items()}
    if not configured:
        return {
            "schema_version": "loss-weight-map-realization-v1",
            "option": str(option),
            "column": str(column),
            "configured": {},
            "realized_rows": {},
        }
    malformed = {
        name: value
        for name, value in configured.items()
        if not name or not math.isfinite(value) or value < 0.0
    }
    if malformed:
        raise SystemExit(
            f"{option} multipliers must use non-empty labels and finite values "
            f">= 0; malformed={malformed}"
        )
    if column not in data:
        raise SystemExit(
            f"{option} requires corpus column {column!r}; refusing a silent no-op"
        )
    rows = int(len(data["action_taken"]))
    values = data[column]
    present = _string_column_present_values(values, rows=rows)
    missing = sorted(set(configured).difference(present))
    if missing:
        preview = sorted(present)[:16]
        raise SystemExit(
            f"{option} configured label(s) absent from corpus {column!r}: "
            f"{missing}; present={preview}"
        )
    realized_rows: dict[str, int] = {}
    value_counts = getattr(values, "value_counts", None)
    if callable(value_counts):
        counts = {str(name): int(count) for name, count in value_counts().items()}
        realized_rows = {name: counts.get(name, 0) for name in configured}
    else:
        materialized = np.asarray(values).astype(str)
        if materialized.shape != (rows,):
            raise SystemExit(
                f"{option} corpus column {column!r} must have shape ({rows},), "
                f"got {materialized.shape}"
            )
        realized_rows = {
            name: int(np.count_nonzero(materialized == name))
            for name in configured
        }
    if any(count <= 0 for count in realized_rows.values()):
        raise RuntimeError(f"{option} realization count drift: {realized_rows}")
    return {
        "schema_version": "loss-weight-map-realization-v1",
        "option": str(option),
        "column": str(column),
        "configured": dict(sorted(configured.items())),
        "realized_rows": dict(sorted(realized_rows.items())),
    }


def _resolve_value_phase_weights(
    raw: str,
    *,
    policy_phase_weights: Mapping[str, float],
) -> tuple[dict[str, float], str]:
    """Resolve value-phase weighting without conflating omission with opt-out.

    Historical runs used an empty value map to inherit policy phase weights.
    Keep that replay behavior, while giving new recipes an explicit ``none``
    sentinel so a policy-only sampling repair cannot silently distort value
    calibration.
    """

    normalized = str(raw or "").strip()
    if normalized.lower() in {"", "inherit"}:
        return dict(policy_phase_weights), "policy_phase_weights"
    if normalized.lower() == "none":
        return {}, "explicit_none"
    return _parse_weight_map(normalized), "explicit_map"


def _resolved_training_entity_adapter(args: argparse.Namespace) -> str:
    requested = getattr(args, "entity_feature_adapter_version", None)
    if requested:
        resolved = require_known_entity_feature_adapter(requested)
    elif bool(getattr(args, "public_rule_state_features", False)):
        resolved = RUST_ENTITY_ADAPTER_V4
    else:
        resolved = CURRENT_RUST_ENTITY_ADAPTER_VERSION
    if resolved in {RUST_ENTITY_ADAPTER_V5, RUST_ENTITY_ADAPTER_V6}:
        if not bool(getattr(args, "public_rule_state_features", False)):
            raise SystemExit(
                "entity adapter v5/v6 requires --public-rule-state-features"
            )
        if not bool(getattr(args, "meaningful_public_history", False)):
            raise SystemExit(
                "entity adapter v5/v6 requires --meaningful-public-history"
            )
        if int(getattr(args, "event_history_limit", 0)) != 64:
            raise SystemExit("entity adapter v5/v6 requires --event-history-limit 64")
    return resolved


def _history_schema_for_entity_adapter(adapter_version: object) -> str:
    resolved = require_known_entity_feature_adapter(adapter_version)
    if resolved in {RUST_ENTITY_ADAPTER_V5, RUST_ENTITY_ADAPTER_V6}:
        return MEANINGFUL_PUBLIC_HISTORY_SCHEMA_V2
    return MEANINGFUL_PUBLIC_HISTORY_SCHEMA_VERSION


_ACTION_TYPE_NAME_RE = re.compile(r"[A-Z][A-Z0-9_]*\Z")


def _parse_forced_row_value_action_type_weights(raw: str) -> dict[str, float]:
    """Parse an opt-in ActionCatalog type -> forced-row value multiplier map."""

    weights: dict[str, float] = {}
    for part in str(raw or "").split(","):
        item = part.strip()
        if not item:
            continue
        if "=" not in item:
            raise SystemExit(
                "invalid --forced-row-value-action-type-weights entry: "
                f"{item!r}; expected ACTION_TYPE=WEIGHT"
            )
        raw_name, raw_value = item.split("=", 1)
        name = raw_name.strip().upper()
        if not _ACTION_TYPE_NAME_RE.fullmatch(name):
            raise SystemExit(
                "invalid --forced-row-value-action-type-weights action type: "
                f"{raw_name.strip()!r}"
            )
        if name in weights:
            raise SystemExit(
                "duplicate --forced-row-value-action-type-weights action type: "
                f"{name}"
            )
        try:
            value = float(raw_value)
        except ValueError as error:
            raise SystemExit(
                "invalid --forced-row-value-action-type-weights multiplier for "
                f"{name}: {raw_value!r}"
            ) from error
        if not math.isfinite(value) or value < 0.0:
            raise SystemExit(
                "--forced-row-value-action-type-weights multipliers must be "
                f"finite and >= 0: {name}={raw_value!r}"
            )
        weights[name] = value
    return weights


def _canonical_forced_row_value_action_type_weights(
    weights: Mapping[str, float],
) -> str:
    """Return the stable recipe/receipt representation of a parsed type map."""

    return ",".join(
        f"{name}={float(weights[name])!r}" for name in sorted(weights)
    )


def _parse_prefixes(raw: str) -> tuple[str, ...]:
    return tuple(part.strip() for part in raw.split(",") if part.strip())


def _teacher_name_has_prefix(values: np.ndarray, prefixes: tuple[str, ...]) -> np.ndarray:
    if not prefixes:
        return np.zeros(values.shape, dtype=bool)
    result = np.zeros(values.shape, dtype=bool)
    for prefix in prefixes:
        result |= np.char.startswith(values.astype(str), prefix)
    return result


def _q_skip_rows(data: dict, batch: np.ndarray, prefixes: tuple[str, ...]) -> np.ndarray:
    teacher_names = _batch_array_or_fill(data, "teacher_name", batch, "").astype(str)
    score_sources = _batch_array_or_fill(
        data,
        "target_score_source",
        batch,
        "",
    ).astype(str)
    return _q_skip_rows_for_arrays(teacher_names, score_sources, prefixes)


def _q_skip_rows_for_arrays(
    teacher_names: np.ndarray,
    score_sources: np.ndarray,
    prefixes: tuple[str, ...],
) -> np.ndarray:
    if not prefixes:
        return np.zeros(teacher_names.shape, dtype=bool)
    prefix_match = _teacher_name_has_prefix(teacher_names.astype(str), prefixes)
    # AB rows generated by the fixed teacher expose true root alpha-beta scores.
    # Older AB rows have no source or fallback value scores and stay excluded.
    return prefix_match & (score_sources.astype(str) != "ab_root")


def _prefer_policy_over_scores_for_teachers(
    teacher_names: np.ndarray,
    score_sources: np.ndarray | None = None,
) -> np.ndarray:
    """Keep AB rows anchored to the action actually chosen by alpha-beta.

    New AB shards expose root search scores, but the anchored policy target is
    still safer for older/fallback rows where scores may be missing or generated
    by a fallback teacher. Rows marked target_score_source=ab_root are handled
    by the prefer_scores path with an explicit score/policy blend.
    """

    ab_rows = _teacher_name_has_prefix(teacher_names, ("catanatron_ab",))
    if score_sources is None:
        return ab_rows
    return ab_rows & (np.asarray(score_sources).astype(str) != "ab_root")


def _ab_root_score_rows(teacher_names: np.ndarray, score_sources: np.ndarray) -> np.ndarray:
    return _teacher_name_has_prefix(teacher_names, ("catanatron_ab",)) & (
        np.asarray(score_sources).astype(str) == "ab_root"
    )


def _blend_soft_target_rows(
    policy: np.ndarray,
    score_target: np.ndarray,
    rows: np.ndarray,
    *,
    policy_weight: float,
) -> np.ndarray:
    alpha = float(np.clip(policy_weight, 0.0, 1.0))
    mixed = alpha * policy[rows] + (1.0 - alpha) * score_target[rows]
    sums = np.sum(mixed, axis=1, keepdims=True)
    valid = sums[:, 0] > 0.0
    if np.any(valid):
        mixed[valid] = mixed[valid] / sums[valid]
    return mixed.astype(np.float32, copy=False)


def _checkpoint_config_mismatches(
    *,
    policy_type: str | None,
    config,
    args: argparse.Namespace,
) -> list[str]:
    mismatches: list[str] = []
    if policy_type is not None and str(policy_type) != str(args.arch):
        mismatches.append(f"policy_type checkpoint={policy_type} cli={args.arch}")
    if config is None:
        return mismatches
    # Task #74: checkpoints may store the config as a name-keyed dict; the
    # getattr probes below need an attribute view over that form.
    from catan_zero.rl.config_serialization import config_attr_view

    config = config_attr_view(config)
    hidden_size = getattr(config, "hidden_size", None)
    if hidden_size is not None and int(hidden_size) != int(args.hidden_size):
        mismatches.append(f"hidden_size checkpoint={hidden_size} cli={args.hidden_size}")
    if args.arch == "entity_graph":
        state_trunk = str(getattr(config, "state_trunk", "transformer"))
        requested_state_trunk = str(
            getattr(args, "entity_state_trunk", "transformer")
        )
        if state_trunk != requested_state_trunk:
            mismatches.append(
                "entity_state_trunk "
                f"checkpoint={state_trunk} cli={requested_state_trunk}"
            )
        state_layers = getattr(config, "state_layers", None)
        if state_layers is not None and int(state_layers) != int(args.graph_layers):
            mismatches.append(f"graph_layers checkpoint={state_layers} cli={args.graph_layers}")
        attention_heads = getattr(config, "attention_heads", None)
        if attention_heads is not None and int(attention_heads) != int(args.attention_heads):
            mismatches.append(
                f"attention_heads checkpoint={attention_heads} cli={args.attention_heads}"
            )
        dropout = getattr(config, "dropout", None)
        if dropout is not None and abs(float(dropout) - float(args.graph_dropout)) > 1.0e-9:
            mismatches.append(f"graph_dropout checkpoint={dropout} cli={args.graph_dropout}")
        for config_name, cli_name, default in (
            (
                "action_cross_attention_layers",
                "action_cross_attention_layers",
                0,
            ),
            ("relational_block_pattern", "relational_block_pattern", ""),
            ("relational_ff_size", "relational_ff_size", 0),
            ("relational_bases", "relational_bases", 4),
            (
                "relational_action_cross_layers",
                "relational_action_cross_layers",
                1,
            ),
            (
                "relational_edge_policy_head",
                "relational_edge_policy_head",
                True,
            ),
            ("latent_deliberation_steps", "latent_deliberation_steps", 0),
            ("latent_deliberation_slots", "latent_deliberation_slots", 8),
            ("moe_routed_experts", "moe_routed_experts", 0),
            ("moe_top_k", "moe_top_k", 2),
            ("moe_expert_ff_size", "moe_expert_ff_size", 0),
        ):
            checkpoint_value = getattr(config, config_name, default)
            cli_value = getattr(args, cli_name, default)
            if cli_value is None:
                continue
            if checkpoint_value != cli_value:
                mismatches.append(
                    f"{cli_name} checkpoint={checkpoint_value} cli={cli_value}"
                )
        categorical_bins = int(getattr(config, "value_categorical_bins", 0) or 0)
        requested_bins = int(getattr(args, "value_categorical_bins", 0) or 0)
        if categorical_bins != requested_bins:
            mismatches.append(
                "value_categorical_bins "
                f"checkpoint={categorical_bins} cli={requested_bins}"
            )
        # Optional-head creation flags are normally one-way for warm starts:
        # an upgraded checkpoint can carry a head when the CLI default is off.
        # The inverse is unsafe here. A caller explicitly requesting the pointer
        # repair must never train the legacy topology-blind settlement head.
        if bool(getattr(args, "aux_settlement_pointer_head", False)) and not bool(
            getattr(config, "aux_settlement_pointer_head", False)
        ):
            mismatches.append(
                "aux_settlement_pointer_head checkpoint=False cli=True; upgrade "
                "the checkpoint with --flags aux_settlement_pointer"
            )
        checkpoint_card_counts = bool(
            getattr(config, "public_card_count_features", False)
        )
        requested_card_counts = bool(
            getattr(args, "public_card_count_features", False)
        )
        if checkpoint_card_counts != requested_card_counts:
            mismatches.append(
                "public_card_count_features "
                f"checkpoint={checkpoint_card_counts} cli={requested_card_counts}; "
                "use a function-preserving card_count checkpoint upgrade"
            )
        checkpoint_card_bias = bool(
            getattr(config, "public_card_count_residual_bias", True)
        )
        requested_card_bias_raw = getattr(
            args, "public_card_count_residual_bias", None
        )
        requested_card_bias = (
            checkpoint_card_bias
            if requested_card_bias_raw is None
            else bool(requested_card_bias_raw)
        )
        if checkpoint_card_bias != requested_card_bias:
            mismatches.append(
                "public_card_count_residual_bias "
                f"checkpoint={checkpoint_card_bias} cli={requested_card_bias}"
            )
        checkpoint_rule_state = bool(
            getattr(config, "public_rule_state_features", False)
        )
        requested_rule_state = bool(
            getattr(args, "public_rule_state_features", False)
        )
        if checkpoint_rule_state != requested_rule_state:
            mismatches.append(
                "public_rule_state_features "
                f"checkpoint={checkpoint_rule_state} cli={requested_rule_state}; "
                "use the function-preserving public_rule_state checkpoint upgrade"
            )
        checkpoint_target_gather = bool(
            getattr(config, "action_target_gather", False)
        )
        requested_target_gather = bool(
            getattr(args, "action_target_gather", False)
        )
        if checkpoint_target_gather != requested_target_gather:
            mismatches.append(
                "action_target_gather "
                f"checkpoint={checkpoint_target_gather} "
                f"cli={requested_target_gather}; use the action_target_gather "
                "checkpoint upgrade"
            )
        checkpoint_action_cross = int(
            getattr(config, "action_cross_attention_layers", 0) or 0
        )
        requested_action_cross = int(
            getattr(args, "action_cross_attention_layers", 0) or 0
        )
        if checkpoint_action_cross != requested_action_cross:
            mismatches.append(
                "action_cross_attention_layers "
                f"checkpoint={checkpoint_action_cross} "
                f"cli={requested_action_cross}; use the action cross-attention "
                "checkpoint upgrade"
            )
        checkpoint_topology_residual = bool(
            getattr(config, "topology_residual_adapter", False)
        )
        requested_topology_residual = bool(
            getattr(args, "topology_residual_adapter", False)
        )
        if checkpoint_topology_residual != requested_topology_residual:
            mismatches.append(
                "topology_residual_adapter "
                f"checkpoint={checkpoint_topology_residual} "
                f"cli={requested_topology_residual}; use the topology checkpoint "
                "upgrade or omit the flag to inherit it"
            )
        for field in (
            "static_action_residual",
            "legal_action_value_residual",
            "legal_action_value_set_statistics",
        ):
            checkpoint_enabled = bool(getattr(config, field, False))
            requested_enabled = bool(getattr(args, field, False))
            if checkpoint_enabled != requested_enabled:
                mismatches.append(
                    f"{field} checkpoint={checkpoint_enabled} "
                    f"cli={requested_enabled}; use the structured_action_value "
                    "checkpoint upgrade"
                )
        checkpoint_value_split = int(
            getattr(config, "value_tower_split_layers", 0) or 0
        )
        requested_value_split = int(
            getattr(args, "value_tower_split_layers", 0) or 0
        )
        if checkpoint_value_split != requested_value_split:
            mismatches.append(
                "value_tower_split_layers "
                f"checkpoint={checkpoint_value_split} "
                f"cli={requested_value_split}; use the value_split:N "
                "checkpoint upgrade"
            )
        checkpoint_history = bool(
            getattr(config, "meaningful_public_history", False)
        )
        requested_history_raw = getattr(args, "meaningful_public_history", None)
        requested_history = (
            checkpoint_history
            if requested_history_raw is None
            else bool(requested_history_raw)
        )
        checkpoint_history_limit = int(
            getattr(config, "event_history_limit", 64) or 0
        )
        requested_history_limit_raw = getattr(args, "event_history_limit", None)
        requested_history_limit = (
            checkpoint_history_limit
            if requested_history_limit_raw is None
            else int(requested_history_limit_raw)
        )
        if (
            checkpoint_history != requested_history
            or checkpoint_history_limit != requested_history_limit
        ):
            mismatches.append(
                "meaningful_public_history "
                f"checkpoint={checkpoint_history}/{checkpoint_history_limit} "
                f"cli={requested_history}/{requested_history_limit}; upgrade "
                "the checkpoint with --flags meaningful_history"
            )
        checkpoint_history_pooling = str(
            getattr(
                config,
                "meaningful_public_history_pooling",
                MASKED_MEAN_V1,
            )
            or MASKED_MEAN_V1
        )
        requested_history_pooling_raw = getattr(
            args, "meaningful_public_history_pooling", None
        )
        requested_history_pooling = (
            checkpoint_history_pooling
            if requested_history_pooling_raw is None
            else str(requested_history_pooling_raw)
        )
        if checkpoint_history_pooling != requested_history_pooling:
            mismatches.append(
                "meaningful_public_history_pooling "
                f"checkpoint={checkpoint_history_pooling} "
                f"cli={requested_history_pooling}; upgrade the checkpoint "
                "with --flags ordered_history"
            )
        checkpoint_history_target_gather = bool(
            getattr(config, "meaningful_public_history_target_gather", False)
        )
        requested_history_target_gather_raw = getattr(
            args, "meaningful_public_history_target_gather", None
        )
        requested_history_target_gather = (
            checkpoint_history_target_gather
            if requested_history_target_gather_raw is None
            else bool(requested_history_target_gather_raw)
        )
        if checkpoint_history_target_gather != requested_history_target_gather:
            mismatches.append(
                "meaningful_public_history_target_gather "
                f"checkpoint={checkpoint_history_target_gather} "
                f"cli={requested_history_target_gather}; upgrade the checkpoint "
                "with the history target-gather adapter"
            )
    return mismatches


def _preflight_init_checkpoint_architecture(args: argparse.Namespace, ddp: dict) -> None:
    if not args.init_checkpoint:
        return
    import torch

    checkpoint = torch.load(args.init_checkpoint, map_location="cpu", weights_only=False)
    if not isinstance(checkpoint, dict):
        return
    mismatches = _checkpoint_config_mismatches(
        policy_type=checkpoint.get("policy_type"),
        config=checkpoint.get("config"),
        args=args,
    )
    if mismatches:
        raise SystemExit(
            "init checkpoint architecture does not match requested run: "
            + "; ".join(mismatches)
        )
    _rank0_print(
        json.dumps(
            {
                "progress": "init_checkpoint_architecture_preflight",
                "checkpoint": args.init_checkpoint,
                "policy_type": checkpoint.get("policy_type"),
                "ok": True,
            },
            sort_keys=True,
        ),
        ddp,
    )


def _assert_init_config_matches(policy, args: argparse.Namespace) -> None:
    mismatches = _checkpoint_config_mismatches(
        policy_type=getattr(policy, "policy_type", None),
        config=getattr(policy, "config", None),
        args=args,
    )
    if mismatches:
        raise SystemExit(
            "init checkpoint architecture does not match requested run: "
            + "; ".join(mismatches)
        )


def _enforce_35m_model_size(policy, args: argparse.Namespace) -> None:
    """Enforce checkpoint-shape compatibility, not active learner capacity.

    Historical 35M checkpoints include optional heads even when a particular
    learner recipe freezes or omits their forward. Changing this guard to the
    trainable/live count would reject compatible warm starts and silently
    redefine the architecture contract. Reports expose those counts separately.
    """

    if not bool(getattr(args, "require_35m_model", False)):
        return
    count = int(_parameter_count(policy))
    lower = int(args.min_35m_params)
    upper = int(args.max_35m_params)
    if count < lower or count > upper:
        raise SystemExit(
            "entity_graph total checkpoint parameter count is outside the required "
            "35M range: "
            f"count={count} expected=[{lower}, {upper}]. Check --hidden-size, "
            "--graph-layers before launching a production BC run."
        )


def _set_entity_q_branch_trainable(model, trainable: bool) -> None:
    module = getattr(model, "module", model)
    for name in ("q_state", "q_action", "q_bias", "q_head"):
        layer = getattr(module, name, None)
        if layer is None:
            continue
        for param in layer.parameters():
            param.requires_grad = bool(trainable)


def _effective_symmetry_augment_events(args: argparse.Namespace) -> bool:
    """Return the event relabel setting that can affect learner outputs."""

    return bool(args.symmetry_augment and args.symmetry_augment_events)


def _freeze_authenticated_empty_event_encoder(model) -> dict[str, object]:
    """Freeze exactly the encoder bypassed by authenticated event0 cropping.

    Cropping a proven-empty event axis to width zero intentionally bypasses the
    event MLP.  Leaving that MLP trainable makes DDP fail on its second forward
    because the parameters do not participate in the first backward pass.
    Freezing is preferable to global unused-parameter discovery: it preserves
    checkpoint bytes, excludes only the mathematically disconnected tensors
    from the optimizer, and adds no per-step DDP graph traversal.
    """

    module = getattr(model, "module", model)
    event_encoder = getattr(module, "event_encoder", None)
    if event_encoder is None:
        raise SystemExit(
            "authenticated empty-event crop expected a named event_encoder"
        )
    before = {
        name: bool(parameter.requires_grad)
        for name, parameter in module.named_parameters()
    }
    parameters_by_name = dict(module.named_parameters())
    total_parameter_tensors = len(parameters_by_name)
    total_parameters = int(sum(p.numel() for p in parameters_by_name.values()))
    trainable_parameter_tensors_before = sum(before.values())
    trainable_parameters_before = int(
        sum(p.numel() for name, p in parameters_by_name.items() if before[name])
    )
    event_parameters = {
        f"event_encoder.{name}": parameter
        for name, parameter in event_encoder.named_parameters()
    }
    if not event_parameters:
        raise SystemExit(
            "authenticated empty-event crop found no event_encoder parameters"
        )
    already_frozen = sorted(
        name for name, parameter in event_parameters.items()
        if not parameter.requires_grad
    )
    if already_frozen:
        raise SystemExit(
            "authenticated empty-event crop expected a fully trainable event_encoder "
            f"before its operational freeze: {already_frozen}"
        )
    for parameter in event_parameters.values():
        parameter.requires_grad = False
    after = {
        name: bool(parameter.requires_grad)
        for name, parameter in module.named_parameters()
    }
    changed = sorted(
        name for name in before
        if before[name] != after.get(name)
    )
    expected = sorted(event_parameters)
    if changed != expected:
        raise SystemExit(
            "authenticated empty-event crop changed an unexpected trainability set: "
            f"expected={expected} observed={changed}"
        )
    return {
        "reason": "authenticated empty event axis is cropped to width zero",
        "frozen_parameter_names": expected,
        "frozen_parameter_tensors": len(expected),
        "frozen_parameters": int(
            sum(parameter.numel() for parameter in event_parameters.values())
        ),
        "unexpected_frozen_parameter_tensors": 0,
        "total_parameter_tensors": total_parameter_tensors,
        "total_parameters": total_parameters,
        "trainable_parameter_tensors_before": trainable_parameter_tensors_before,
        "trainable_parameter_tensors_after": int(sum(after.values())),
        "trainable_parameters_before": trainable_parameters_before,
        "trainable_parameters_after": int(
            sum(p.numel() for name, p in parameters_by_name.items() if after[name])
        ),
        "optimizer_excluded_parameter_tensors": len(expected),
        "optimizer_excluded_parameters": int(
            sum(parameter.numel() for parameter in event_parameters.values())
        ),
    }


def _set_scalar_value_head_trainable(model, trainable: bool) -> None:
    """Freeze the legacy scalar readout in categorical-primary runs.

    A zero coefficient alone is insufficient under AdamW: a zero gradient can
    still receive decoupled weight decay.  Freezing makes the reported scalar
    metric a genuinely fixed diagnostic unless the explicit HL scalar-aux
    weight is enabled.
    """

    module = getattr(model, "module", model)
    value_head = getattr(module, "value_head", None)
    if value_head is None:
        raise SystemExit(
            "categorical-primary training expected a named scalar value_head "
            "to freeze for diagnostic integrity"
        )
    for parameter in value_head.parameters():
        parameter.requires_grad = bool(trainable)


# Named groups of EntityGraphNet submodules that --freeze-modules / --train-value-only can
# freeze. ``value_heads`` is opt-in: value-repair runs leave it trainable, while the
# later action-local policy warmup can freeze every value-specific parameter cleanly
# instead of relying on a zero loss coefficient (which is not an AdamW freeze).
ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS: dict[str, tuple[str, ...]] = {
    "trunk": (
        "hex_encoder",
        "vertex_encoder",
        "edge_encoder",
        "player_encoder",
        "v6_exact_resource_residual",
        "public_card_count_residual",
        "public_rule_state_residual",
        "global_encoder",
        "event_encoder",
        "meaningful_history_residual_gate",
        "meaningful_history_ordered_gate",
        "meaningful_history_sequence",
        "meaningful_history_target_proj",
        "type_embedding",
        "cls_token",
        "blocks",
        "state_norm",
        "deliberation_slots",
        "deliberation_block",
        "deliberation_fusion_norm",
        "deliberation_fusion",
        "deliberation_halt_head",
        "topology_residual_adapter",
    ),
    "action_encoder": ("action_encoder",),
    # Granular explicit isolation controls for function-preserving input
    # adapters. They also belong to ``trunk`` for legacy all-trunk freezes, but
    # ordinary feature-bearing training leaves them trainable so their zero
    # initialization can commission from the learner objective.
    "public_card_residual": ("public_card_count_residual",),
    "meaningful_history_gate": (
        "meaningful_history_residual_gate",
        "meaningful_history_ordered_gate",
        "meaningful_history_sequence",
        "meaningful_history_target_proj",
    ),
    "v7_resource_residual": ("v6_exact_resource_residual",),
    "policy_head": ("action_bias", "logit_scale"),
    # Keep optional action-local adapters independently freezable.  Grouping
    # them together would make a gather+edge ablation silently update the
    # already-trained gather branch while claiming to isolate the edge head.
    "target_gather": ("target_gather_proj",),
    "edge_policy": ("edge_policy_mlp",),
    "action_cross": ("action_cross_blocks",),
    "static_action_residual": ("static_action_residual_proj",),
    "v7_initial_road_residual": ("v6_initial_road_residual",),
    "value_heads": (
        "value_blocks",
        "value_state_norm",
        "value_head",
        "legal_action_value_residual_proj",
        "legal_action_value_static_proj",
        "legal_action_value_max_proj",
        "legal_action_value_count_proj",
        "legal_action_value_static_max_proj",
        "value_categorical_head",
        "final_vp_head",
        "value_uncertainty_head",
        "value_probe",
        "value_probe_norm_q",
        "value_probe_norm_kv",
        "value_probe_attn",
        "value_pool_head",
    ),
}

# The complete policy-producing surface for a value-only repair. Keep this as
# named freeze groups rather than raw parameter prefixes so new optional action
# adapters cannot silently remain optimizer-visible. In particular, a zero
# policy coefficient is not enough under AdamW: graph-reachable policy tensors
# can receive exact-zero gradients and still undergo decoupled weight decay.
ENTITY_GRAPH_VALUE_ONLY_FREEZE_GROUPS: frozenset[str] = frozenset(
    {
        "trunk",
        "action_encoder",
        "policy_head",
        "target_gather",
        "edge_policy",
        "action_cross",
        "static_action_residual",
        "v7_initial_road_residual",
    }
)


def _resolve_entity_graph_freeze_groups(
    *, freeze_modules: str, train_value_only: bool
) -> set[str]:
    """Resolve only caller-visible optimizer freezes.

    Corpus metadata may authenticate labels, scopes, and sampling measures, but
    it must not silently change which model parameters receive gradients.
    """

    groups = set(_parse_prefixes(freeze_modules))
    if train_value_only:
        groups |= ENTITY_GRAPH_VALUE_ONLY_FREEZE_GROUPS
    return groups


def _effective_entity_graph_architecture_report(
    policy,
    *,
    requested_edge_policy_head: bool = False,
    requested_aux_subgoal_heads: bool = False,
    requested_aux_settlement_pointer_head: bool = False,
    requested_belief_resource_head: bool = False,
) -> dict[str, object]:
    """Bind learner reports to the architecture that actually ran.

    Entity-graph warm-start experiments normally flip optional architecture
    fields in an upgraded checkpoint.  ``--init-checkpoint`` then reconstructs
    the model from that checkpoint's config, so CLI defaults are not evidence
    that an optional path was disabled.  In particular, reporting
    ``args.edge_policy_head`` mislabeled an upgraded edge-head model as OFF,
    while gather and cross-attention were omitted from the report entirely.

    Keep the requested CLI values separately for diagnosis, but make the
    historical top-level feature fields describe the effective loaded model.
    """

    config = getattr(policy, "config", None)
    if config is None or getattr(policy, "policy_type", "") != "entity_graph":
        return {
            "action_target_gather": False,
            "action_cross_attention_layers": 0,
            "edge_policy_head": bool(requested_edge_policy_head),
            "aux_subgoal_heads": bool(requested_aux_subgoal_heads),
            "aux_settlement_pointer_head": bool(
                requested_aux_settlement_pointer_head
            ),
            "topology_residual_adapter": False,
            "static_action_residual": False,
            "legal_action_value_residual": False,
            "legal_action_value_set_statistics": False,
            "v6_compatibility_preserving_inputs": False,
            "value_tower_split_layers": 0,
            "public_card_count_features": False,
            "public_card_count_residual_bias": False,
            "public_rule_state_features": False,
            "public_rule_state_feature_schema": (
                PUBLIC_RULE_STATE_FEATURE_SCHEMA_VERSION
            ),
            "meaningful_public_history": False,
            "meaningful_public_history_schema": (
                MEANINGFUL_PUBLIC_HISTORY_SCHEMA_VERSION
            ),
            "event_history_limit": 64,
            "meaningful_public_history_pooling": MASKED_MEAN_V1,
            "meaningful_public_history_target_gather": False,
            "requested_edge_policy_head": bool(requested_edge_policy_head),
            "requested_aux_subgoal_heads": bool(requested_aux_subgoal_heads),
            "requested_aux_settlement_pointer_head": bool(
                requested_aux_settlement_pointer_head
            ),
            "belief_resource_head": bool(requested_belief_resource_head),
            "requested_belief_resource_head": bool(
                requested_belief_resource_head
            ),
        }
    state_trunk = str(getattr(config, "state_trunk", "transformer"))
    configured_relational_action_cross_layers = int(
        getattr(config, "relational_action_cross_layers", 1) or 0
    )
    return {
        "action_target_gather": bool(
            getattr(config, "action_target_gather", False)
        ),
        "action_cross_attention_layers": int(
            getattr(config, "action_cross_attention_layers", 0) or 0
        ),
        "edge_policy_head": bool(getattr(config, "edge_policy_head", False)),
        "aux_subgoal_heads": bool(getattr(config, "aux_subgoal_heads", False)),
        "aux_settlement_pointer_head": bool(
            getattr(config, "aux_settlement_pointer_head", False)
        ),
        "topology_residual_adapter": bool(
            getattr(config, "topology_residual_adapter", False)
        ),
        "static_action_residual": bool(
            getattr(config, "static_action_residual", False)
        ),
        "legal_action_value_residual": bool(
            getattr(config, "legal_action_value_residual", False)
        ),
        "legal_action_value_set_statistics": bool(
            getattr(config, "legal_action_value_set_statistics", False)
        ),
        "v6_compatibility_preserving_inputs": bool(
            getattr(config, "v6_compatibility_preserving_inputs", False)
        ),
        "value_tower_split_layers": int(
            getattr(config, "value_tower_split_layers", 0) or 0
        ),
        "public_card_count_features": bool(
            getattr(config, "public_card_count_features", False)
        ),
        "public_rule_state_features": bool(
            getattr(config, "public_rule_state_features", False)
        ),
        "public_rule_state_feature_schema": str(
            getattr(
                config,
                "public_rule_state_feature_schema",
                PUBLIC_RULE_STATE_FEATURE_SCHEMA_VERSION,
            )
            or PUBLIC_RULE_STATE_FEATURE_SCHEMA_VERSION
        ),
        "public_card_count_residual_bias": (
            bool(getattr(config, "public_card_count_residual_bias", True))
            if bool(getattr(config, "public_card_count_features", False))
            else False
        ),
        "meaningful_public_history": bool(
            getattr(config, "meaningful_public_history", False)
        ),
        "meaningful_public_history_schema": str(
            getattr(
                config,
                "meaningful_public_history_schema",
                MEANINGFUL_PUBLIC_HISTORY_SCHEMA_VERSION,
            )
            or MEANINGFUL_PUBLIC_HISTORY_SCHEMA_VERSION
        ),
        "event_history_limit": int(
            getattr(config, "event_history_limit", 64) or 0
        ),
        "meaningful_public_history_pooling": str(
            getattr(
                config,
                "meaningful_public_history_pooling",
                MASKED_MEAN_V1,
            )
            or MASKED_MEAN_V1
        ),
        "meaningful_public_history_target_gather": bool(
            getattr(config, "meaningful_public_history_target_gather", False)
        ),
        "belief_resource_head": bool(
            getattr(config, "belief_resource_head", False)
        ),
        "state_trunk": state_trunk,
        "relational_block_pattern": str(
            getattr(config, "relational_block_pattern", "") or ""
        ),
        # This report describes the architecture that actually ran. The legacy
        # config default is 1 even on Transformer checkpoints, but the model
        # constructor consumes it only for relational trunks. Preserve the raw
        # knob separately so old recipes remain diagnosable without claiming a
        # decoder layer that does not exist.
        "relational_action_cross_layers": (
            configured_relational_action_cross_layers
            if state_trunk != "transformer"
            else 0
        ),
        "configured_relational_action_cross_layers": (
            configured_relational_action_cross_layers
        ),
        "relational_edge_policy_head": bool(
            getattr(config, "relational_edge_policy_head", True)
        ),
        "requested_edge_policy_head": bool(requested_edge_policy_head),
        "requested_aux_subgoal_heads": bool(requested_aux_subgoal_heads),
        "requested_aux_settlement_pointer_head": bool(
            requested_aux_settlement_pointer_head
        ),
        "requested_belief_resource_head": bool(requested_belief_resource_head),
    }


def _set_entity_graph_modules_trainable(
    model, group_names, *, trainable: bool
) -> list[str]:
    """Freeze/unfreeze named EntityGraphNet module groups.

    Recognized group names are the keys of ``ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS``.
    Raises SystemExit on an unrecognized name. Returns the list of attribute names
    actually touched, for logging.
    """
    module = getattr(model, "module", model)
    group_names = list(group_names)
    unknown = sorted(set(group_names) - set(ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS))
    if unknown:
        raise SystemExit(
            "unknown --freeze-modules group(s): "
            f"{unknown}; valid groups are {sorted(ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS)}"
        )
    touched: list[str] = []
    for group_name in group_names:
        for attr_name in ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS[group_name]:
            attr = getattr(module, attr_name, None)
            if attr is None:
                continue
            touched.append(attr_name)
            parameters = attr.parameters() if hasattr(attr, "parameters") else (attr,)
            for param in parameters:
                param.requires_grad = bool(trainable)
    return touched


def _require_only_trainable_prefixes(model, prefixes) -> dict[str, object]:
    """Prove the optimizer surface is exactly inside reviewed module prefixes."""

    module = getattr(model, "module", model)
    normalized_prefixes = tuple(str(prefix).strip().rstrip(".") for prefix in prefixes)
    if not normalized_prefixes or any(not prefix for prefix in normalized_prefixes):
        raise SystemExit("--require-only-trainable-prefixes contains an empty prefix")
    trainable: list[tuple[str, object]] = []
    for raw_name, parameter in module.named_parameters():
        if not parameter.requires_grad:
            continue
        name = str(raw_name)
        while name.startswith("_fsdp_wrapped_module."):
            name = name[len("_fsdp_wrapped_module.") :]
        trainable.append((name, parameter))
    unexpected = [
        name
        for name, _ in trainable
        if not any(name == prefix or name.startswith(prefix + ".") for prefix in normalized_prefixes)
    ]
    counts = {
        prefix: sum(
            int(parameter.numel())
            for name, parameter in trainable
            if name == prefix or name.startswith(prefix + ".")
        )
        for prefix in normalized_prefixes
    }
    if unexpected:
        raise SystemExit(
            "trainable parameter escaped --require-only-trainable-prefixes: "
            + ", ".join(unexpected[:16])
        )
    missing = [prefix for prefix, count in counts.items() if count <= 0]
    if missing or not trainable:
        raise SystemExit(
            "required trainable prefix has no parameters: " + ", ".join(missing)
        )
    return {
        "prefixes": list(normalized_prefixes),
        "parameter_tensors": len(trainable),
        "parameters": sum(int(parameter.numel()) for _, parameter in trainable),
        "parameters_by_prefix": counts,
    }


def _lr_warmup_multiplier(step: int, warmup_steps: int) -> float:
    """Linear ramp from 0 at step 0 to 1.0 at (and past) ``warmup_steps``. ``step`` is
    0-indexed (the step about to run); a ``warmup_steps <= 0`` disables the ramp (always 1.0).
    """
    if warmup_steps <= 0:
        return 1.0
    return min(1.0, float(step + 1) / float(warmup_steps))


def _effective_training_epoch_limit(
    *, configured_epochs: int, max_steps: int, exact_max_steps: bool
) -> int:
    """Return the epoch ceiling while preserving legacy max-step semantics.

    A non-empty corpus can apply at least one optimizer update per epoch. An
    exact step dose therefore needs at most ``max_steps`` epoch passes. The
    post-loop assertion remains authoritative because an empty or all-zero
    objective can apply no updates and must fail closed instead of spinning.
    """
    if not exact_max_steps:
        return int(configured_epochs)
    if int(max_steps) <= 0:
        raise SystemExit("--exact-max-steps requires --max-steps > 0")
    return max(int(configured_epochs), int(max_steps))


def _validate_exact_optimizer_step_dose(
    *, exact_max_steps: bool, max_steps: int, applied_steps: int, epoch_limit: int
) -> None:
    if exact_max_steps and int(applied_steps) != int(max_steps):
        raise RuntimeError(
            "exact optimizer-step dose was not reached: "
            f"requested={int(max_steps)} applied={int(applied_steps)} "
            f"effective_epoch_limit={int(epoch_limit)}"
        )


def _require_optimizer_resume_sidecars(
    *, optimizer_path: Path, progress_path: Path
) -> None:
    """Require the complete durable state promised by --resume-optimizer."""

    missing = [
        label
        for label, path in (
            ("optimizer", optimizer_path),
            ("training-progress", progress_path),
        )
        if not path.is_file()
    ]
    if missing:
        raise SystemExit(
            "incomplete resumable checkpoint set: model, optimizer, and "
            "training-progress sidecars must all belong to one atomic commit; "
            f"missing={missing}; use --no-resume-optimizer for an explicit "
            "fresh-optimizer start"
        )


def _validate_optimizer_resume_request(
    *, requested: bool, init_checkpoint: str, optimizer_available: bool
) -> None:
    """Reject a resume flag that cannot possibly restore optimizer state."""

    if not requested:
        return
    if not str(init_checkpoint).strip():
        raise SystemExit("--resume-optimizer requires --init-checkpoint")
    if not optimizer_available:
        raise SystemExit("--resume-optimizer requires a live training optimizer")


def _validate_resumed_epoch_boundary(
    *, resumed: bool, completed_epochs: int, epoch_limit: int
) -> None:
    """Refuse an exact continuation whose configured epoch dose is complete."""

    if not resumed:
        return
    completed = int(completed_epochs)
    limit = int(epoch_limit)
    if completed >= limit:
        raise SystemExit(
            "resumed completed_epochs already reaches --epochs: "
            f"completed={completed} epochs={limit}; the requested dose is "
            "complete, so no optimizer update or checkpoint save will be performed"
        )


def _validate_resumed_max_step_boundary(
    *, resumed: bool, global_step: int, max_steps: int
) -> None:
    """Refuse a capped resume that has no legal optimizer step remaining.

    This check belongs immediately after progress restoration and before any
    epoch order is constructed. The weighted sampler otherwise turns an
    already-complete dose into an empty draw and reaches checkpoint saving,
    while the uniform sampler ignores the weighted-only draw cap and can apply
    an extra optimizer update. One sampler-independent boundary keeps both
    paths exact and prevents a completed checkpoint from being rewritten.
    """

    if not resumed or int(max_steps) <= 0:
        return
    restored_step = int(global_step)
    requested_cap = int(max_steps)
    if restored_step > requested_cap:
        raise SystemExit(
            "resumed optimizer_step exceeds --max-steps: "
            f"restored={restored_step} max_steps={requested_cap}; "
            "refusing to sample, update, or save"
        )
    if restored_step == requested_cap:
        raise SystemExit(
            "resumed optimizer_step already equals --max-steps: "
            f"restored={restored_step} max_steps={requested_cap}; "
            "the requested dose is complete, so no optimizer update or "
            "checkpoint save will be performed"
        )


def _apply_lr_warmup(optimizer, *, base_lr: float, step: int, warmup_steps: int) -> float:
    """Set every optimizer param group's lr to ``group_base_lr * warmup multiplier`` for
    this step, where ``group_base_lr`` is the group's own ``"base_lr"`` key when present
    (see ``_build_optimizer_param_groups``'s --value-lr-mult split) and ``base_lr``
    otherwise -- so a single-group optimizer (no "base_lr" key, e.g. every call site
    before --value-lr-mult existed) is unaffected. Returns the multiplier actually
    applied, for logging."""
    multiplier = _lr_warmup_multiplier(step, warmup_steps)
    for group in optimizer.param_groups:
        group["lr"] = float(group.get("base_lr", base_lr)) * multiplier
    return multiplier


def _lr_schedule_multiplier(
    step: int, *, warmup_steps: int, total_steps: int, schedule: str
) -> float:
    """AUDIT FIX (LR decay): combine the existing linear warmup ramp with an optional
    post-warmup decay curve. ``step`` is 0-indexed (the step about to run).

    ``schedule="flat"`` returns exactly ``_lr_warmup_multiplier(step, warmup_steps)`` --
    i.e. warmup-then-hold, bit-identical to every training recipe run before this flag
    existed. ``"cosine"``/``"linear"`` only change behavior once the caller opts in via
    --lr-schedule.
    """
    warmup_multiplier = _lr_warmup_multiplier(step, warmup_steps)
    if schedule == "flat":
        return warmup_multiplier
    if step < warmup_steps:
        return warmup_multiplier
    decay_span = max(1, int(total_steps) - int(warmup_steps))
    progress = min(1.0, max(0.0, float(step - warmup_steps) / float(decay_span)))
    if schedule == "cosine":
        return 0.5 * (1.0 + math.cos(math.pi * progress))
    if schedule == "linear":
        return max(0.0, 1.0 - progress)
    raise SystemExit(f"unknown --lr-schedule {schedule!r}; expected flat, cosine, or linear")


def _apply_lr_schedule(
    optimizer,
    *,
    base_lr: float,
    step: int,
    warmup_steps: int,
    total_steps: int,
    schedule: str,
) -> float:
    """Set every optimizer param group's lr to ``group_base_lr * schedule multiplier``
    for this step, where ``group_base_lr`` is the group's own ``"base_lr"`` key when
    present (see ``_build_optimizer_param_groups``'s --value-lr-mult split) and
    ``base_lr`` otherwise -- so a single-group optimizer (no "base_lr" key, e.g. every
    call site before --value-lr-mult existed) is unaffected. Returns the multiplier
    actually applied, for logging."""
    multiplier = _lr_schedule_multiplier(
        step, warmup_steps=warmup_steps, total_steps=total_steps, schedule=schedule
    )
    for group in optimizer.param_groups:
        group["lr"] = float(group.get("base_lr", base_lr)) * multiplier
    return multiplier


# Submodule attribute names treated as "value head" parameters for --value-lr-mult.
# This must cover the complete value-only readout path, including the optional
# attention pool. Otherwise ``--value-lr-mult`` misleadingly slows the final
# linear head while its fresh value probe/attention layers train at trunk LR.
# Missing optional EntityGraph attributes are harmless.
VALUE_HEAD_MODULE_ATTRS: tuple[str, ...] = (
    "value_blocks",
    "value_state_norm",
    "value_head",
    "legal_action_value_residual_proj",
    "legal_action_value_static_proj",
    "legal_action_value_max_proj",
    "legal_action_value_count_proj",
    "legal_action_value_static_max_proj",
    "value_categorical_head",
    "final_vp_head",
    "value_uncertainty_head",
    "value_probe",
    "value_probe_norm_q",
    "value_probe_norm_kv",
    "value_probe_attn",
    "value_pool_head",
)

# Opt-in action-local modules introduced by the gather/cross-attention upgrade.
# They are freshly initialized when upgrading a scalar/global-policy checkpoint,
# so the later architecture A/B needs an independent LR from both the mature
# trunk and the value heads.
ACTION_LOCAL_MODULE_ATTRS: tuple[str, ...] = (
    "target_gather_proj",
    "action_cross_blocks",
    "edge_policy_mlp",
    "static_action_residual_proj",
    "v6_initial_road_residual",
)

# Mature action-side representation shared by every legal action scored by the
# EntityGraph policy.  It is intentionally separate from the new action-local
# adapters above: warm-start experiments often need to commission new adapters
# quickly while protecting this already-trained encoder from a full base-LR
# update.
SHARED_ACTION_MODULE_ATTRS: tuple[str, ...] = ("action_encoder",)


def _optimizer_param_group_report(params, *, base_lr: float) -> list[dict[str, object]]:
    """Describe optimizer groups without mutating the objects passed to torch.

    ``_group_name`` is private construction metadata and is stripped by
    ``_make_optimizer`` before optimizer/checkpoint state is created.
    """
    param_groups = list(params)
    if not param_groups or not isinstance(param_groups[0], dict):
        tensors = [p for p in param_groups if p.requires_grad]
        return [
            {
                "group": "historical_flat",
                "lr": float(base_lr),
                "parameter_tensors": len(tensors),
                "parameters": sum(int(p.numel()) for p in tensors),
            }
        ]
    return [
        {
            "group": str(group.get("_group_name", "unnamed")),
            "lr": float(group["lr"]),
            "parameter_tensors": len(group["params"]),
            "parameters": sum(int(p.numel()) for p in group["params"]),
        }
        for group in param_groups
    ]


def _split_adamw_weight_decay_groups(
    param_groups: list[dict[str, object]],
    *,
    weight_decay: float,
) -> list[dict[str, object]]:
    """Apply AdamW decay only to matrix-or-higher trainable parameters.

    Biases, normalization scales, and scalar gates (including ``logit_scale``)
    are all tensors with fewer than two dimensions. Decaying those parameters
    moves calibration and normalization even when their objective is inactive,
    while adding no useful capacity regularization. Preserve every source
    group's LR metadata and split only its decay topology.
    """
    result: list[dict[str, object]] = []
    assigned: list[int] = []
    expected: list[int] = []
    for group in param_groups:
        source_params = [
            parameter
            for parameter in group["params"]
            if parameter.requires_grad
        ]
        expected.extend(id(parameter) for parameter in source_params)
        decay_params = [
            parameter
            for parameter in source_params
            if int(
                getattr(
                    parameter,
                    "_optimizer_original_ndim",
                    parameter.ndim,
                )
            )
            >= 2
        ]
        no_decay_params = [
            parameter
            for parameter in source_params
            if int(
                getattr(
                    parameter,
                    "_optimizer_original_ndim",
                    parameter.ndim,
                )
            )
            < 2
        ]
        metadata = {
            key: value
            for key, value in group.items()
            if key not in {"params", "weight_decay"}
        }
        if decay_params:
            result.append(
                {
                    **metadata,
                    "params": decay_params,
                    "weight_decay": float(weight_decay),
                }
            )
            assigned.extend(id(parameter) for parameter in decay_params)
        if no_decay_params:
            result.append(
                {
                    **metadata,
                    "params": no_decay_params,
                    "weight_decay": 0.0,
                }
            )
            assigned.extend(id(parameter) for parameter in no_decay_params)
    if len(assigned) != len(set(assigned)) or set(assigned) != set(expected):
        raise RuntimeError(
            "AdamW decay grouping did not assign every trainable parameter exactly once"
        )
    return result


def _build_optimizer_param_groups(
    model,
    *,
    base_lr: float,
    value_lr_mult: float,
    action_module_lr_mult: float = 1.0,
    shared_action_lr_mult: float = 1.0,
    public_card_lr_mult: float = 1.0,
    trunk_lr_mult: float = 1.0,
    architecture: str | None = None,
):
    """Return the optimizer's ``params`` argument for ``model``'s trainable parameters.

    All multipliers at 1.0 return a FLAT list of parameters -- exactly the
    historical single-implicit-group optimizer. Non-unit multipliers split the
    corresponding named modules into independent groups; every other trainable
    parameter stays in a base group at ``base_lr``. Each group dict carries its
    own ``"base_lr"`` key so
    ``_apply_lr_schedule``/``_apply_lr_warmup`` scale the right rate per group instead
    of overwriting every group with the same absolute rate.
    """
    module = getattr(model, "module", model)
    trainable = [p for p in module.parameters() if p.requires_grad]
    multipliers = {
        "value-lr-mult": float(value_lr_mult),
        "action-module-lr-mult": float(action_module_lr_mult),
        "shared-action-lr-mult": float(shared_action_lr_mult),
        "public-card-lr-mult": float(public_card_lr_mult),
        "trunk-lr-mult": float(trunk_lr_mult),
    }
    if any(not math.isfinite(value) or value <= 0.0 for value in multipliers.values()):
        raise SystemExit(
            "--value-lr-mult, --action-module-lr-mult, "
            "--shared-action-lr-mult, --public-card-lr-mult, and "
            "--trunk-lr-mult "
            "must all be > 0; "
            "freeze modules explicitly instead of encoding a freeze as LR 0"
        )
    if all(value == 1.0 for value in multipliers.values()):
        return trainable
    if (
        float(trunk_lr_mult) != 1.0
        or float(shared_action_lr_mult) != 1.0
    ) and architecture != "entity_graph":
        raise SystemExit(
            "--trunk-lr-mult and --shared-action-lr-mult are supported only "
            "for --arch entity_graph; "
            f"received architecture={architecture!r}"
        )

    def _params_under(attrs: tuple[str, ...]) -> list:
        params: list = []
        for attr_name in attrs:
            submodule = getattr(module, attr_name, None)
            if submodule is None:
                continue
            parameters = (
                submodule.parameters()
                if hasattr(submodule, "parameters")
                else (submodule,)
            )
            params.extend(p for p in parameters if p.requires_grad)
        return params

    value_params = (
        _params_under(VALUE_HEAD_MODULE_ATTRS)
        if float(value_lr_mult) != 1.0
        else []
    )
    action_params = (
        _params_under(ACTION_LOCAL_MODULE_ATTRS)
        if float(action_module_lr_mult) != 1.0
        else []
    )
    shared_action_params = (
        _params_under(SHARED_ACTION_MODULE_ATTRS)
        if float(shared_action_lr_mult) != 1.0
        else []
    )
    public_card_params = (
        _params_under(("public_card_count_residual",))
        if float(public_card_lr_mult) != 1.0
        else []
    )
    if float(public_card_lr_mult) != 1.0:
        public_card_residual = getattr(module, "public_card_count_residual", None)
        if (
            public_card_residual is not None
            and getattr(public_card_residual, "bias", None) is not None
        ):
            raise SystemExit(
                "--public-card-lr-mult != 1.0 requires the bias-free public-card "
                "residual topology. Legacy v1 adapters contain a trainable "
                "intercept that changes every player token even when the public-card "
                "evidence row is all zero; replay them only at multiplier 1.0 or "
                "upgrade with the v2/v3 bias-free receipt."
            )
    public_card_param_ids = {id(p) for p in public_card_params}
    # V7's exact-resource adapter belongs to the trunk *freeze* surface because
    # it changes the shared representation consumed by policy and value.  It is
    # nevertheless a fresh, zero-output residual and must commission at base LR
    # while --trunk-lr-mult protects the inherited trunk.  Keep it in the base
    # group just as the dedicated public-card group overrides the mature-trunk
    # multiplier below.
    commissioning_adapter_param_ids = {
        id(parameter)
        for parameter in _params_under(("v6_exact_resource_residual",))
    }
    trunk_params = (
        [
            parameter
            for parameter in _params_under(
                ENTITY_GRAPH_FREEZABLE_MODULE_GROUPS["trunk"]
            )
            # The public-card adapter is part of the complete trunk freeze
            # surface, but its dedicated LR control is explicitly independent
            # from the mature trunk. When both controls are active, the
            # narrower public-card group owns these parameters.
            if id(parameter)
            not in public_card_param_ids | commissioning_adapter_param_ids
        ]
        if float(trunk_lr_mult) != 1.0
        else []
    )
    if float(value_lr_mult) != 1.0 and not value_params:
        raise SystemExit(
            "--value-lr-mult != 1.0 but the model has no trainable parameters under "
            f"any of {VALUE_HEAD_MODULE_ATTRS} -- nothing to apply the multiplier to."
        )
    if float(action_module_lr_mult) != 1.0 and not action_params:
        raise SystemExit(
            "--action-module-lr-mult != 1.0 but the model has no trainable "
            f"parameters under any of {ACTION_LOCAL_MODULE_ATTRS}"
        )
    if float(shared_action_lr_mult) != 1.0 and not shared_action_params:
        raise SystemExit(
            "--shared-action-lr-mult != 1.0 but the model has no trainable "
            f"parameters under any of {SHARED_ACTION_MODULE_ATTRS}"
        )
    if float(public_card_lr_mult) != 1.0 and not public_card_params:
        raise SystemExit(
            "--public-card-lr-mult != 1.0 but the model has no trainable "
            "public_card_count_residual parameters"
        )
    if float(trunk_lr_mult) != 1.0 and not trunk_params:
        raise SystemExit(
            "--trunk-lr-mult != 1.0 but the entity-graph model has no trainable "
            "parameters under the canonical trunk module group"
        )
    value_param_ids = {id(p) for p in value_params}
    action_param_ids = {id(p) for p in action_params}
    shared_action_param_ids = {id(p) for p in shared_action_params}
    trunk_param_ids = {id(p) for p in trunk_params}
    pairwise_overlaps = {
        "value/action": value_param_ids & action_param_ids,
        "value/shared_action": value_param_ids & shared_action_param_ids,
        "value/public_card": value_param_ids & public_card_param_ids,
        "value/trunk": value_param_ids & trunk_param_ids,
        "action/shared_action": action_param_ids & shared_action_param_ids,
        "action/public_card": action_param_ids & public_card_param_ids,
        "action/trunk": action_param_ids & trunk_param_ids,
        "shared_action/public_card": (
            shared_action_param_ids & public_card_param_ids
        ),
        "shared_action/trunk": shared_action_param_ids & trunk_param_ids,
        "public_card/trunk": public_card_param_ids & trunk_param_ids,
    }
    overlapping = {name: ids for name, ids in pairwise_overlaps.items() if ids}
    if overlapping:
        raise RuntimeError(
            "optimizer parameter groups overlap: "
            + ", ".join(f"{name}={len(ids)}" for name, ids in overlapping.items())
        )
    grouped_ids = (
        value_param_ids
        | action_param_ids
        | shared_action_param_ids
        | public_card_param_ids
        | trunk_param_ids
    )
    base_params = [p for p in trainable if id(p) not in grouped_ids]
    groups = [
        {
            "params": base_params,
            "lr": float(base_lr),
            "base_lr": float(base_lr),
            "_group_name": "base",
        }
    ]
    if value_params:
        value_lr = float(base_lr) * float(value_lr_mult)
        groups.append(
            {
                "params": value_params,
                "lr": value_lr,
                "base_lr": value_lr,
                "_group_name": "value",
            }
        )
    if action_params:
        action_lr = float(base_lr) * float(action_module_lr_mult)
        groups.append(
            {
                "params": action_params,
                "lr": action_lr,
                "base_lr": action_lr,
                "_group_name": "action_local",
            }
        )
    if shared_action_params:
        shared_action_lr = float(base_lr) * float(shared_action_lr_mult)
        groups.append(
            {
                "params": shared_action_params,
                "lr": shared_action_lr,
                "base_lr": shared_action_lr,
                "_group_name": "shared_action",
            }
        )
    if public_card_params:
        public_card_lr = float(base_lr) * float(public_card_lr_mult)
        groups.append(
            {
                "params": public_card_params,
                "lr": public_card_lr,
                "base_lr": public_card_lr,
                "_group_name": "public_card",
            }
        )
    if trunk_params:
        trunk_lr = float(base_lr) * float(trunk_lr_mult)
        groups.append(
            {
                "params": trunk_params,
                "lr": trunk_lr,
                "base_lr": trunk_lr,
                "_group_name": "trunk",
            }
        )
    assigned = [id(p) for group in groups for p in group["params"]]
    trainable_ids = [id(p) for p in trainable]
    if len(assigned) != len(set(assigned)) or set(assigned) != set(trainable_ids):
        raise RuntimeError(
            "optimizer parameter grouping did not assign every trainable parameter "
            "exactly once"
        )
    return groups


def _make_optimizer(params, args, device):
    import torch

    param_groups = list(params)
    grouped_input = bool(param_groups and isinstance(param_groups[0], dict))
    if grouped_input:
        # --value-lr-mult path: `params` is already a list of param-group dicts (see
        # `_build_optimizer_param_groups`), each carrying its own "lr". Drop any
        # non-trainable stragglers per group (mirrors the flat-list branch below).
        trainable_params = [
            {
                **{key: value for key, value in group.items() if key != "_group_name"},
                "params": [p for p in group["params"] if p.requires_grad],
            }
            for group in param_groups
        ]
        if not any(group["params"] for group in trainable_params):
            raise SystemExit("no trainable parameters found for BC optimizer")
    else:
        trainable_params = [parameter for parameter in param_groups if parameter.requires_grad]
        if not trainable_params:
            raise SystemExit("no trainable parameters found for BC optimizer")
    optimizer_name = str(args.optimizer).lower()
    weight_decay = float(args.weight_decay)
    # AUDIT FIX (weight-decay silent no-op): plain torch.optim.Adam's weight_decay
    # is L2-regularization added to the gradient BEFORE the Adam moment estimates,
    # not AdamW's decoupled decay -- they are not interchangeable, and this
    # function used to only ever forward --weight-decay when --optimizer adamw was
    # also passed, silently dropping it under the default "adam" optimizer. Fail
    # loud instead: a nonzero --weight-decay with --optimizer adam is always a
    # config mistake here (this repo's only two choices are "adam"/"adamw"), so
    # refuse rather than guess which regularization the caller meant.
    if weight_decay != 0.0 and optimizer_name != "adamw":
        raise SystemExit(
            f"--weight-decay {weight_decay} has no effect with --optimizer "
            f"{optimizer_name!r}: this trainer only forwards weight_decay to "
            "torch.optim.AdamW's decoupled decay. Pass --optimizer adamw to "
            "apply it, or --weight-decay 0.0 to train without decay."
        )
    cls = torch.optim.AdamW if optimizer_name == "adamw" else torch.optim.Adam
    kwargs = {"lr": float(args.lr)}
    if optimizer_name == "adamw":
        kwargs["weight_decay"] = weight_decay
        if weight_decay != 0.0:
            normalized_groups = (
                trainable_params
                if grouped_input
                else [{"params": trainable_params}]
            )
            trainable_params = _split_adamw_weight_decay_groups(
                normalized_groups,
                weight_decay=weight_decay,
            )
    if bool(args.fused_optimizer) and str(device).startswith("cuda"):
        kwargs["fused"] = True
    try:
        return cls(trainable_params, **kwargs)
    except TypeError:
        if "fused" not in kwargs:
            raise
        kwargs.pop("fused", None)
        return cls(trainable_params, **kwargs)


def _amp_context(device, amp: str):
    from contextlib import nullcontext

    if str(amp).lower() != "bf16":
        return nullcontext()
    if not str(device).startswith("cuda"):
        return nullcontext()
    import torch

    if not torch.cuda.is_available():
        return nullcontext()
    return torch.autocast(device_type="cuda", dtype=torch.bfloat16)


def _ensure_policy_action_mask_version(
    policy,
    env_config,
    *,
    allow_legacy_upgrade: bool,
    checkpoint_path: str,
) -> None:
    config = getattr(policy, "config", None)
    if config is None:
        return
    current = str(getattr(config, "action_mask_version", "") or "")
    if current:
        return
    expected = _expected_action_mask_version(env_config)
    if not expected:
        return
    if not allow_legacy_upgrade:
        source = f" {checkpoint_path}" if checkpoint_path else ""
        raise SystemExit(
            f"init checkpoint{source} is missing action_mask_version; refusing "
            "to stamp it with the current action catalog automatically. Regenerate "
            "from a versioned checkpoint or pass --allow-legacy-action-mask-upgrade "
            "only after an action-ID replay smoke test passes."
        )
    object.__setattr__(config, "action_mask_version", expected)


def _batch_profile(policy, data: dict, batch: np.ndarray) -> dict:
    config = getattr(policy, "config", None)
    policy_type = str(getattr(policy, "policy_type", ""))
    action_size = int(getattr(policy, "action_size", getattr(config, "action_size", 0)))
    context_size = int(
        getattr(
            policy,
            "context_action_feature_size",
            getattr(config, "context_action_feature_size", 0),
        )
    )
    valid = data["legal_action_ids"][batch]
    legal_counts = np.sum(valid >= 0, axis=1)
    profile = {
        "batch_size": int(len(batch)),
        "input_representation": (
            "entity_tokens" if policy_type == "entity_graph" else "dense_obs"
        ),
        "obs_shape": (
            list(data["obs"][batch].shape) if "obs" in data else None
        ),
        "legal_action_ids_shape": list(valid.shape),
        "legal_action_context_shape": list(data["legal_action_context"][batch].shape),
        "dense_action_context_materialized": policy_type != "entity_graph",
        "dense_action_context_shape": (
            None
            if policy_type == "entity_graph"
            else [int(len(batch)), action_size, context_size]
        ),
        "legal_actions_mean": float(np.mean(legal_counts)) if len(legal_counts) else 0.0,
        "legal_actions_p90": int(np.percentile(legal_counts, 90)) if len(legal_counts) else 0,
        "legal_actions_max": int(np.max(legal_counts)) if len(legal_counts) else 0,
        "parameter_count": int(_parameter_count(policy)),
        "cuda": _cuda_memory(policy),
    }
    if policy_type != "entity_graph" and profile["obs_shape"] is None:
        raise RuntimeError(
            "dense batch profiling requires obs; only entity_graph batches may "
            "omit the unused legacy dense observation"
        )
    if policy_type == "entity_graph":
        for key in (
            "hex_tokens",
            "vertex_tokens",
            "edge_tokens",
            "player_tokens",
            "global_tokens",
            "legal_action_tokens",
            "event_tokens",
        ):
            if key in data:
                profile[f"{key}_shape"] = list(data[key][batch].shape)
    return profile


def _parameter_count(policy) -> int:
    return int(sum(parameter.numel() for parameter in _params(policy)))


def _parameter_accounting(policy) -> dict[str, object]:
    """Separate serialized size, optimizer surface, and live training forward.

    ``requires_grad`` answers whether a parameter may be optimized, not whether
    its module executes. Conversely, a zero-objective head can be present in a
    checkpoint yet intentionally skipped by the learner. The trainer records
    those exact top-level model attributes in
    ``_forward_inactive_parameter_modules`` before distributed wrapping.
    """

    parameters = list(_params(policy))
    total = int(sum(parameter.numel() for parameter in parameters))
    trainable = int(
        sum(parameter.numel() for parameter in parameters if parameter.requires_grad)
    )

    wrapped_model = getattr(policy, "model", None)
    model = getattr(wrapped_model, "module", wrapped_model)
    inactive_names = tuple(
        sorted(getattr(model, "_forward_inactive_parameter_modules", ()))
    )
    inactive_parameter_ids: set[int] = set()
    observed_names: list[str] = []
    if model is not None:
        for name in inactive_names:
            submodule = getattr(model, name, None)
            if submodule is None or not hasattr(submodule, "parameters"):
                continue
            observed_names.append(name)
            inactive_parameter_ids.update(id(parameter) for parameter in submodule.parameters())
    forward_inactive = int(
        sum(
            parameter.numel()
            for parameter in parameters
            if id(parameter) in inactive_parameter_ids
        )
    )
    return {
        "schema_version": "model-parameter-accounting-v1",
        "total_parameters": total,
        "trainable_parameters": trainable,
        "forward_active_parameters": int(total - forward_inactive),
        "forward_inactive_parameters": forward_inactive,
        "forward_inactive_submodules": observed_names,
        "total_parameter_contract": (
            "serialized_checkpoint_structure_including_frozen_or_skipped_heads"
        ),
    }


def _cuda_memory(policy) -> dict:
    try:
        import torch
    except ImportError:
        return {}
    device = getattr(policy, "device", None)
    if not torch.cuda.is_available() or device is None or str(device).startswith("cpu"):
        return {}
    return {
        "allocated_mib": float(torch.cuda.memory_allocated(device) / 1024 / 1024),
        "reserved_mib": float(torch.cuda.memory_reserved(device) / 1024 / 1024),
        "max_allocated_mib": float(torch.cuda.max_memory_allocated(device) / 1024 / 1024),
        "max_reserved_mib": float(torch.cuda.max_memory_reserved(device) / 1024 / 1024),
    }


def _epoch_checkpoint_path(checkpoint: str, epoch: int) -> Path:
    path = Path(checkpoint)
    suffix = "".join(path.suffixes) or ".pt"
    stem = path.name[: -len(suffix)] if path.name.endswith(suffix) else path.stem
    return path.with_name(f"{stem}_epoch{epoch:04d}{suffix}")


def _step_checkpoint_path(checkpoint: str | Path, step: int) -> Path:
    """Return the model-only checkpoint path for one optimizer-step snapshot."""

    path = Path(checkpoint)
    suffix = "".join(path.suffixes) or ".pt"
    stem = path.name[: -len(suffix)] if path.name.endswith(suffix) else path.stem
    return path.with_name(f"{stem}_step{int(step):04d}{suffix}")


INTERMEDIATE_CHECKPOINT_SCHEMA = "train-bc-intermediate-checkpoint-v1"
INTERMEDIATE_CHECKPOINT_TRAJECTORY_SCHEMA = (
    "train-bc-intermediate-checkpoint-trajectory-v1"
)


def _prepare_checkpoint_frontier_start(
    checkpoint: str | Path,
    *,
    checkpoint_steps: Sequence[int],
    init_checkpoint: str,
    resume_optimizer: bool,
) -> Path | None:
    """Reserve immutable snapshot paths for a fresh or model-only start.

    Exact optimizer resume cannot classify requested steps until its authenticated
    progress marker supplies the restored optimizer step.  It therefore creates
    no step-zero reference and defers both past/future path checks to
    :func:`_verify_resumed_checkpoint_frontier`.
    """

    steps = tuple(int(step) for step in checkpoint_steps)
    if bool(resume_optimizer):
        return None
    for step in steps:
        snapshot_path = _step_checkpoint_path(checkpoint, step)
        if snapshot_path.exists() or snapshot_path.is_symlink():
            raise SystemExit(
                f"intermediate checkpoint path already exists: {snapshot_path}"
            )
    initialization_reference_path = (
        _step_checkpoint_path(checkpoint, 0)
        if steps and str(init_checkpoint).strip()
        else None
    )
    if initialization_reference_path is not None and (
        initialization_reference_path.exists()
        or initialization_reference_path.is_symlink()
    ):
        raise SystemExit(
            "effective initialization reference path already exists: "
            f"{initialization_reference_path}"
        )
    return initialization_reference_path


def _intermediate_checkpoint_trajectory_binding(
    *, optimizer_step: int, resume_recipe_identity: Mapping[str, object]
) -> dict[str, object]:
    """Bind one model-only snapshot to its exact resumable optimizer trajectory."""

    return {
        "schema_version": INTERMEDIATE_CHECKPOINT_TRAJECTORY_SCHEMA,
        "optimizer_step": int(optimizer_step),
        "training_resume_recipe_identity_sha256": _canonical_json_sha256(
            dict(resume_recipe_identity)
        ),
    }


def _verify_resumed_checkpoint_frontier(
    checkpoint: str | Path,
    *,
    checkpoint_steps: Sequence[int],
    restored_global_step: int,
    resume_recipe_identity: Mapping[str, object],
) -> set[int]:
    """Authenticate passed snapshots and reserve future paths on exact resume.

    A path alone is not evidence that the snapshot belongs to this optimizer
    trajectory.  Passed steps must be regular model-only checkpoint files whose
    embedded step and recipe identity match the validated training-progress
    marker.  Future paths must be absent so resuming never overwrites evidence.
    """

    import torch

    restored = int(restored_global_step)
    expected_identity_sha256 = _canonical_json_sha256(
        dict(resume_recipe_identity)
    )
    verified: set[int] = set()
    from catan_zero.rl.optim_state import (
        optimizer_sidecar_path,
        training_progress_sidecar_path,
    )

    for raw_step in checkpoint_steps:
        step = int(raw_step)
        snapshot_path = _step_checkpoint_path(checkpoint, step)
        optimizer_path = optimizer_sidecar_path(snapshot_path)
        progress_path = training_progress_sidecar_path(snapshot_path)
        occupied_paths = tuple(
            path
            for path in (snapshot_path, optimizer_path, progress_path)
            if path.exists() or path.is_symlink()
        )
        if step > restored:
            if occupied_paths:
                raise SystemExit(
                    "future intermediate checkpoint path already exists during "
                    f"optimizer resume: step={step} paths="
                    f"{[str(path) for path in occupied_paths]}"
                )
            continue
        if not snapshot_path.is_file() or snapshot_path.is_symlink():
            raise SystemExit(
                "optimizer resume is missing an immutable past intermediate "
                f"checkpoint: step={step} path={snapshot_path}"
            )
        if (
            optimizer_path.exists()
            or optimizer_path.is_symlink()
            or progress_path.exists()
            or progress_path.is_symlink()
        ):
            raise SystemExit(
                "past intermediate checkpoint is not model-only: "
                f"step={step} path={snapshot_path}"
            )
        try:
            payload = torch.load(snapshot_path, map_location="cpu", weights_only=False)
        except Exception as error:
            raise SystemExit(
                "cannot authenticate past intermediate checkpoint "
                f"step={step} path={snapshot_path}: {error}"
            ) from error
        value_training = (
            payload.get("value_training") if isinstance(payload, dict) else None
        )
        intermediate = (
            value_training.get("intermediate_checkpoint")
            if isinstance(value_training, dict)
            else None
        )
        trajectory = (
            value_training.get("intermediate_checkpoint_trajectory")
            if isinstance(value_training, dict)
            else None
        )
        if (
            not isinstance(payload, dict)
            or not isinstance(payload.get("model"), dict)
            or not payload.get("model")
            or not isinstance(value_training, dict)
            or type(value_training.get("optimizer_steps")) is not int
            or value_training.get("optimizer_steps") != step
            or not isinstance(intermediate, dict)
            or type(intermediate.get("optimizer_step")) is not int
            or intermediate
            != {
                "schema_version": INTERMEDIATE_CHECKPOINT_SCHEMA,
                "optimizer_step": step,
                "same_training_trajectory": True,
                "optimizer_sidecar_intentionally_omitted": True,
            }
            or not isinstance(trajectory, dict)
            or type(trajectory.get("optimizer_step")) is not int
            or trajectory
            != {
                "schema_version": INTERMEDIATE_CHECKPOINT_TRAJECTORY_SCHEMA,
                "optimizer_step": step,
                "training_resume_recipe_identity_sha256": (
                    expected_identity_sha256
                ),
            }
        ):
            raise SystemExit(
                "past intermediate checkpoint step/trajectory metadata mismatch: "
                f"step={step} path={snapshot_path}"
            )
        verified.add(step)
    return verified


def _parse_checkpoint_steps(raw: str, *, max_steps: int) -> tuple[int, ...]:
    """Parse a canonical, strictly increasing set of intermediate steps."""

    value = str(raw or "").strip()
    if not value:
        return ()
    try:
        steps = tuple(int(part.strip()) for part in value.split(","))
    except ValueError as error:
        raise SystemExit("--checkpoint-steps must be comma-separated integers") from error
    if (
        not steps
        or any(step <= 0 for step in steps)
        or tuple(sorted(set(steps))) != steps
    ):
        raise SystemExit(
            "--checkpoint-steps must be unique positive integers in increasing order"
        )
    if int(max_steps) > 0 and any(step >= int(max_steps) for step in steps):
        raise SystemExit(
            "--checkpoint-steps must be strictly below --max-steps; the terminal "
            "checkpoint already represents --max-steps"
        )
    return steps


def _acquire_host_train_lock(lock_file: str, ddp: dict[str, int | bool]):
    """Prevent accidental same-host BC job stacking.

    Only local rank 0 owns the lock for DDP jobs. If a second DDP launcher starts,
    its rank 0 exits quickly and torchrun tears down the sibling ranks.
    """

    if bool(ddp["enabled"]) and int(ddp["local_rank"]) != 0:
        return None
    path = Path(lock_file)
    path.parent.mkdir(parents=True, exist_ok=True)
    handle = path.open("w", encoding="utf-8")
    try:
        import fcntl

        fcntl.flock(handle.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
    except BlockingIOError as error:
        raise SystemExit(
            f"another train_bc.py job is already running on this host; "
            f"lock_file={path}. Pass --allow-concurrent-bc only if the GPUs "
            "are intentionally partitioned."
        ) from error
    handle.seek(0)
    handle.truncate()
    handle.write(
        json.dumps(
            {
                "pid": os.getpid(),
                "rank": int(ddp["rank"]),
                "local_rank": int(ddp["local_rank"]),
                "started_unix": time.time(),
            },
            sort_keys=True,
        )
        + "\n"
    )
    handle.flush()
    return handle


def _iter_with_last(iterable):
    """Yield ``(item, is_last)`` for every item, with ``is_last=True`` only on the
    final item. Uses one-step lookahead so it works on single-pass generators
    (the streaming memmap/prefetch batch iterator) without materialising them.
    An empty iterable yields nothing.
    """
    iterator = iter(iterable)
    try:
        previous = next(iterator)
    except StopIteration:
        return
    for current in iterator:
        yield previous, False
        previous = current
    yield previous, True


def _gradient_sync_context(model, *, accum_do_step: bool):
    """Suppress DDP gradient sync around a complete micro-batch.

    PyTorch requires ``no_sync`` to cover the forward pass that creates reducer
    hooks, not merely ``backward``.  The caller therefore enters this context
    before invoking the batch trainer.  Plain modules retain a strict no-op.
    """
    import contextlib

    if not bool(accum_do_step) and hasattr(model, "no_sync"):
        return model.no_sync()
    return contextlib.nullcontext()


def _accumulation_group_size(
    *, configured_size: int, batch_number: int, total_batches: int
) -> int:
    """Return the actual divisor for the group beginning at ``batch_number``."""
    configured = int(configured_size)
    batch = int(batch_number)
    total = int(total_batches)
    if configured < 1 or batch < 1 or total < batch:
        raise ValueError("invalid gradient accumulation group bounds")
    return min(configured, total - batch + 1)


def _advance_global_step(
    global_step: int,
    *,
    accum_do_step: bool,
    optimizer_step_applied: bool,
) -> int:
    """Advance the LR/max-step clock only for an applied optimizer update."""
    if optimizer_step_applied and not accum_do_step:
        raise ValueError("an optimizer step cannot occur on a non-stepping microbatch")
    return int(global_step) + int(bool(accum_do_step and optimizer_step_applied))


def _warm_start_grow(policy, checkpoint_path: str, *, device: str) -> dict:
    """C1 warm-start-GROW: copy every parameter/buffer whose NAME and SHAPE
    match from ``checkpoint_path`` into the already-constructed (fresh, typically
    bigger) ``policy.model``; leave every other tensor at its fresh init.

    This is the "load matching keys, init the rest, log the fraction loaded"
    contract from the C1 spec. It deliberately does NOT require an architecture
    match (that is what --init-checkpoint is for): a same-width/deeper config
    warm-starts the shared trunk blocks + token encoders + heads cleanly (only
    the extra blocks.<i> stay fresh), while a width change matches little and the
    run is effectively from-scratch -- either way the fraction loaded is logged
    so the caller sees exactly how much signal was transferred.

    Returns a JSON-safe report: parameter/tensor counts, the loaded fraction (by
    parameter element count -- the number that matters for "how warm is this
    start"), and the sizes of the mismatched/missing/unexpected buckets.
    """
    import torch

    ckpt = torch.load(checkpoint_path, map_location="cpu", weights_only=False)
    if not isinstance(ckpt, dict) or "model" not in ckpt:
        raise SystemExit(
            f"--grow-from-checkpoint {checkpoint_path} is not a policy checkpoint "
            "(no 'model' state_dict)"
        )
    source = ckpt["model"]
    target_model = policy.model
    target_sd = target_model.state_dict()

    to_copy: dict = {}
    shape_mismatch: list[str] = []
    unexpected: list[str] = []
    for name, src_tensor in source.items():
        if name not in target_sd:
            unexpected.append(name)
            continue
        if tuple(src_tensor.shape) == tuple(target_sd[name].shape):
            to_copy[name] = src_tensor
        else:
            shape_mismatch.append(name)
    missing = [name for name in target_sd if name not in source]

    # strict=False so the fresh-init tensors for missing/mismatched keys are
    # left untouched; assign=False keeps the target's dtype/device.
    target_model.load_state_dict(to_copy, strict=False)

    def _param_elems(names) -> int:
        return int(sum(int(target_sd[n].numel()) for n in names if n in target_sd))

    total_target_params = int(sum(p.numel() for p in target_model.parameters()))
    # Restrict the "loaded" accounting to trainable parameters (buffers such as
    # the non-persistent value_categorical_support never appear in state_dict
    # persistently, but any registered buffers that do should not inflate the
    # "fraction of the MODEL warm-started" number the operator reads).
    param_names = {name for name, _ in target_model.named_parameters()}
    loaded_param_elems = _param_elems(n for n in to_copy if n in param_names)
    loaded_fraction = (
        float(loaded_param_elems) / float(total_target_params)
        if total_target_params > 0
        else 0.0
    )
    return {
        "checkpoint": checkpoint_path,
        "source_tensors": int(len(source)),
        "target_tensors": int(len(target_sd)),
        "copied_tensors": int(len(to_copy)),
        "shape_mismatch_tensors": int(len(shape_mismatch)),
        "missing_in_source_tensors": int(len(missing)),
        "unexpected_in_source_tensors": int(len(unexpected)),
        "target_total_params": total_target_params,
        "loaded_params": loaded_param_elems,
        "loaded_fraction": round(loaded_fraction, 6),
        "shape_mismatch_examples": sorted(shape_mismatch)[:8],
        "missing_examples": sorted(missing)[:8],
    }


def _distributed_state() -> dict[str, int | bool]:
    world_size = int(os.environ.get("WORLD_SIZE", "1"))
    return {
        "enabled": world_size > 1,
        "world_size": world_size,
        "rank": int(os.environ.get("RANK", "0")),
        "local_rank": int(os.environ.get("LOCAL_RANK", "0")),
    }


def _resolved_sampler_seed(args: argparse.Namespace) -> int:
    """Return the independent data-trajectory seed with a legacy exact default."""

    value = getattr(args, "sampler_seed", None)
    return int(args.seed if value is None else value)


def _draw_global_rank_strided_symmetry_ids(
    rng: np.random.Generator,
    *,
    n_symmetries: int,
    local_rows: int,
    rank: int,
    world_size: int,
) -> np.ndarray:
    """Draw one topology-correct D6 id per rank-local row.

    DDP obtains its local data as ``global_order[rank::world_size]``. Mirror
    that exact mapping for augmentation: every rank advances an identical copy
    of the generator through the complete logical global batch and keeps only
    its rank-strided positions. This has three important properties:

    * concatenating the rank slices by global position exactly reproduces one
      single-process generator draw;
    * every rank's underlying generator finishes in the same state, so the
      existing one-state resumable checkpoint contract remains exact; and
    * ``world_size == 1`` executes the historical ``integers(..., size=b)``
      call unchanged.

    The caller must preserve the learner's equal local-batch-size invariant.
    Both non-sharded and sharded DDP epoch-order builders pad to provide it.
    """

    count = int(local_rows)
    size = int(world_size)
    position = int(rank)
    choices = int(n_symmetries)
    if count < 0:
        raise ValueError("local symmetry row count must be non-negative")
    if choices <= 0:
        raise ValueError("symmetry count must be positive")
    if size <= 0 or position < 0 or position >= size:
        raise ValueError(
            f"invalid symmetry DDP topology rank={position} world_size={size}"
        )
    if size == 1:
        return np.asarray(rng.integers(choices, size=count), dtype=np.int64)
    global_draws = np.asarray(
        rng.integers(choices, size=count * size), dtype=np.int64
    )
    local = global_draws[position::size]
    if local.shape != (count,):
        raise RuntimeError(
            "rank-strided symmetry draw shape drift: "
            f"local={local.shape} expected={(count,)}"
        )
    return local


def _initialize_training_rng(
    args: argparse.Namespace,
    ddp: dict[str, int | bool],
    *,
    checkpoint_loaded: bool = False,
) -> dict[str, object]:
    """Bind the PyTorch training RNG after model construction/loading.

    Model construction/loading must happen first: all ranks need identical initial
    parameters for DDP. NumPy is deliberately untouched because ``_epoch_order`` and
    ``_policy_aux_epoch_order`` draw one deterministic global order and then slice it
    by rank. Historical fresh-start runs are an exact no-op when the rank-offset flag
    is false.

    A checkpoint load is different: policy loaders construct a model before applying
    the serialized state and that constructor historically calls ``torch.manual_seed``
    with its default seed. Without an explicit post-load reset, dropout and every
    other training-time torch draw therefore used the loader's implementation detail
    (usually seed 0), not ``--seed``. Always rebind a loaded model to the configured
    base seed; opt-in distributed runs retain their existing ``base_seed + rank``
    trajectory exactly.
    """

    enabled = bool(getattr(args, "training_rng_rank_offset", False))
    rank = int(ddp.get("rank", 0))
    base_seed = int(args.seed)
    effective_seed: int | None = None
    if enabled or checkpoint_loaded:
        effective_seed = base_seed + rank if enabled else base_seed
        import torch

        torch.manual_seed(effective_seed)
    return {
        "schema_version": "train-bc-rank-offset-rng-v1",
        "rank_offset_enabled": enabled,
        "base_seed": base_seed,
        "rank": rank,
        "effective_torch_seed": effective_seed,
        "checkpoint_loaded": bool(checkpoint_loaded),
        "post_load_reseeded": bool(checkpoint_loaded),
        "sampler_seed": _resolved_sampler_seed(args),
        "sampler_seed_explicit": getattr(args, "sampler_seed", None) is not None,
        "numpy_data_trajectory_scope": [
            "epoch_order",
            "policy_aux_order",
            "symmetry_and_data_transforms",
        ],
        "numpy_epoch_order_rng_unchanged": True,
        "initial_parameters_unchanged": True,
    }


def _rank0_authoritative_call(
    ddp: dict[str, int | bool],
    label: str,
    operation,
):
    """Run one deterministic read-only startup check per local DDP job.

    DDP ranks on this learner map the same authenticated immutable memmap.  A
    check that only returns JSON/pickle-safe metadata therefore has exactly the
    same result on every rank, while independently scanning tens of millions
    of rows multiplies startup I/O and host memory pressure by world size.

    Rank 0 broadcasts both success and ordinary refusal as data.  This detail
    is essential: raising on rank 0 before peers reach a collective leaves the
    remaining ranks hung rather than failing the job coherently.
    """

    # On multi-node jobs each host may have its own corpus staging/filesystem.
    # A global rank-0 result cannot attest those independent local mappings, so
    # retain the historical per-rank check outside a single-node torchrun.
    if not _single_node_ddp_shared_storage_enabled(ddp):
        return operation()

    rank = int(ddp.get("rank", 0))
    payload: list[dict[str, object] | None] = [None]
    if rank == 0:
        try:
            payload[0] = {"ok": True, "value": operation()}
        except (Exception, SystemExit) as error:
            payload[0] = {
                "ok": False,
                "error_type": type(error).__name__,
                "error": str(error),
            }
    import torch.distributed as dist

    dist.broadcast_object_list(payload, src=0)
    result = payload[0]
    if not isinstance(result, dict) or result.get("ok") not in {True, False}:
        raise SystemExit(f"{label} rank-0 authority returned malformed status")
    if result["ok"] is not True:
        raise SystemExit(
            f"{label} refused on rank 0 "
            f"({result.get('error_type', 'error')}): {result.get('error', '')}"
        )
    return result.get("value")


_TRAINING_PRECOMPUTE_CACHE_SCHEMA = "train-bc-derived-arrays-v1"


def _array_content_sha256(array: np.ndarray) -> str:
    """Hash an array's exact C-order bytes without materialising a second copy."""

    contiguous = np.ascontiguousarray(array)
    digest = hashlib.sha256()
    view = memoryview(contiguous).cast("B")
    block = 8 * 1024 * 1024
    for offset in range(0, len(view), block):
        digest.update(view[offset : offset + block])
    return f"sha256:{digest.hexdigest()}"


def _derived_array_cache_key(payload: dict[str, object]) -> tuple[str, dict[str, object]]:
    """Return a content key and the canonical, versioned cache identity.

    The caller must bind every corpus and recipe input that can affect an array.
    The implementation file and NumPy version are bound here centrally, so a
    code or numerical-runtime change cannot silently reuse an older result.
    """

    raw_identity = {
        "schema_version": _TRAINING_PRECOMPUTE_CACHE_SCHEMA,
        "implementation_sha256": _sha256_existing_file(__file__),
        "numpy_version": str(np.__version__),
        "inputs": payload,
    }
    # The manifest is JSON, so its decoded identity contains lists even when a
    # caller supplied tuples (notably explicit validation seed ranges). Keep
    # the in-memory comparison object in that same canonical JSON domain;
    # otherwise a valid freshly-written cache immediately refuses itself as
    # "identity drift".
    identity = json.loads(
        json.dumps(
            raw_identity,
            sort_keys=True,
            separators=(",", ":"),
            ensure_ascii=True,
        )
    )
    digest = _canonical_json_sha256(identity).removeprefix("sha256:")
    return digest, identity


def _write_derived_array_cache(
    cache_root: Path,
    identity: dict[str, object],
    arrays: dict[str, np.ndarray],
) -> Path:
    """Atomically publish immutable, checksummed ``.npy`` derived arrays."""

    key = _canonical_json_sha256(identity).removeprefix("sha256:")
    destination = cache_root / key
    cache_root.mkdir(parents=True, exist_ok=True)
    if destination.exists():
        # Never overwrite an existing content-addressed entry. Validation is
        # deliberately delegated to the loader, which fails closed on damage.
        return destination
    temporary = Path(tempfile.mkdtemp(prefix=f".{key}.", dir=cache_root))
    try:
        inventory: dict[str, dict[str, object]] = {}
        for name, value in sorted(arrays.items()):
            if not re.fullmatch(r"[a-z][a-z0-9_]*", name):
                raise ValueError(f"unsafe derived-array cache name {name!r}")
            array = np.ascontiguousarray(value)
            path = temporary / f"{name}.npy"
            with open(path, "wb") as handle:
                np.save(handle, array, allow_pickle=False)
                handle.flush()
                os.fsync(handle.fileno())
            path.chmod(0o444)
            inventory[name] = {
                "file": path.name,
                "dtype": array.dtype.str,
                "shape": [int(item) for item in array.shape],
                "content_sha256": _array_content_sha256(array),
                "file_sha256": _sha256_existing_file(path),
            }
        manifest = {
            "schema_version": _TRAINING_PRECOMPUTE_CACHE_SCHEMA,
            "identity": identity,
            "identity_sha256": f"sha256:{key}",
            "arrays": inventory,
        }
        manifest_path = temporary / "manifest.json"
        with open(manifest_path, "w", encoding="utf-8") as handle:
            json.dump(manifest, handle, sort_keys=True, separators=(",", ":"))
            handle.write("\n")
            handle.flush()
            os.fsync(handle.fileno())
        manifest_path.chmod(0o444)
        try:
            os.replace(temporary, destination)
        except FileExistsError:
            # A concurrent run with the same authenticated identity won the
            # publish race. Its atomic rename guarantees a complete entry;
            # the caller still authenticates every byte before use.
            import shutil

            shutil.rmtree(temporary)
        directory_fd = os.open(cache_root, os.O_RDONLY)
        try:
            os.fsync(directory_fd)
        finally:
            os.close(directory_fd)
    except BaseException:
        if temporary.exists():
            import shutil

            shutil.rmtree(temporary)
        raise
    return destination


def _load_derived_array_cache(
    cache_root: Path,
    identity: dict[str, object],
    *,
    verify_digests: bool = True,
) -> dict[str, np.ndarray]:
    """Authenticate a cache entry before exposing read-only memory maps.

    Both the ``.npy`` file bytes and decoded C-order array bytes are checked.
    This is intentionally fail-closed: an existing but partial/tampered entry
    aborts training instead of being silently regenerated or reused.
    """

    key = _canonical_json_sha256(identity).removeprefix("sha256:")
    directory = cache_root / key
    manifest_path = directory / "manifest.json"
    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"derived-array cache manifest is unreadable: {manifest_path}") from error
    if manifest.get("schema_version") != _TRAINING_PRECOMPUTE_CACHE_SCHEMA:
        raise SystemExit("derived-array cache schema drift")
    if manifest.get("identity") != identity or manifest.get("identity_sha256") != f"sha256:{key}":
        raise SystemExit("derived-array cache identity drift")
    inventory = manifest.get("arrays")
    if not isinstance(inventory, dict) or not inventory:
        raise SystemExit("derived-array cache has no array inventory")
    loaded: dict[str, np.ndarray] = {}
    for name, record in sorted(inventory.items()):
        if not isinstance(record, dict) or record.get("file") != f"{name}.npy":
            raise SystemExit(f"derived-array cache inventory is invalid for {name!r}")
        path = directory / f"{name}.npy"
        if verify_digests and _sha256_existing_file(path) != record.get("file_sha256"):
            raise SystemExit(f"derived-array cache file digest mismatch: {name}")
        try:
            array = np.load(path, mmap_mode="r", allow_pickle=False)
        except (OSError, ValueError) as error:
            raise SystemExit(f"derived-array cache cannot decode {name}") from error
        if array.dtype.str != record.get("dtype") or list(array.shape) != record.get("shape"):
            raise SystemExit(f"derived-array cache shape/dtype drift: {name}")
        if verify_digests and _array_content_sha256(array) != record.get("content_sha256"):
            raise SystemExit(f"derived-array cache content digest mismatch: {name}")
        loaded[name] = array
    return loaded


def _coverage_objective_active_training_scope(
    data,
    train_indices: np.ndarray,
    *,
    policy_loss_weight: float,
    scalar_value_loss_weight: float,
    final_vp_loss_weight: float,
    categorical_value_loss_weight: float = 0.0,
    q_loss_weight: float = 0.0,
    policy_kl_anchor_weight: float = 0.0,
    value_uncertainty_loss_weight: float = 0.0,
    aux_subgoal_loss_weight: float = 0.0,
    belief_resource_loss_weight: float = 0.0,
    moe_balance_loss_weight: float = 0.0,
) -> tuple[np.ndarray, dict[str, np.ndarray]]:
    """Remove composite components that feed no enabled coverage objective.

    ``coverage_importance_v1`` traverses every admitted row exactly once.  A
    component outside both authenticated policy and value scopes therefore
    consumes a full forward/backward slot while contributing exactly zero to
    every supported loss.  Condition the authenticated component-game measure
    on the union of scopes for objectives that are actually enabled.

    Ordinary and weighted-replacement samplers never call this helper and
    preserve their historical row set exactly.
    """

    ratios = np.asarray(
        getattr(data, "component_game_sampling_ratios", tuple()),
        dtype=np.float64,
    )
    component_count = len(getattr(data, "corpora", tuple()))
    if (
        ratios.ndim != 1
        or ratios.size == 0
        or ratios.size != component_count
        or not np.isfinite(ratios).all()
        or np.any(ratios <= 0.0)
        or not math.isclose(
            float(ratios.sum()), 1.0, rel_tol=0.0, abs_tol=1.0e-9
        )
    ):
        raise SystemExit(
            "coverage objective scope requires authenticated component ratios"
        )
    all_components = set(range(component_count))
    active_components: set[int] = set()
    objective_weights = (
        float(policy_loss_weight),
        float(scalar_value_loss_weight),
        float(final_vp_loss_weight),
        float(categorical_value_loss_weight),
        float(q_loss_weight),
        float(policy_kl_anchor_weight),
        float(value_uncertainty_loss_weight),
        float(aux_subgoal_loss_weight),
        float(belief_resource_loss_weight),
        float(moe_balance_loss_weight),
    )
    if any(
        not math.isfinite(weight) or weight < 0.0
        for weight in objective_weights
    ):
        raise SystemExit("coverage objective weights must be finite and non-negative")
    enabled_flags = np.asarray(
        [int(weight > 0.0) for weight in objective_weights], dtype=np.uint8
    )
    if float(policy_loss_weight) > 0.0:
        active_components.update(
            (
                int(value)
                for value in getattr(
                    data, "policy_distillation_component_indices", tuple()
                )
            )
            if bool(
                getattr(data, "policy_distillation_scope_authenticated", False)
            )
            else all_components
        )
    if any(
        weight > 0.0
        for weight in (
            scalar_value_loss_weight,
            final_vp_loss_weight,
            categorical_value_loss_weight,
            value_uncertainty_loss_weight,
        )
    ):
        active_components.update(
            (
                int(value)
                for value in getattr(
                    data, "value_training_component_indices", tuple()
                )
            )
            if bool(getattr(data, "value_training_scope_authenticated", False))
            else all_components
        )
    if float(policy_kl_anchor_weight) > 0.0:
        active_components.update(
            (
                int(value)
                for value in getattr(
                    data, "policy_kl_anchor_component_indices", tuple()
                )
            )
            if bool(getattr(data, "policy_kl_anchor_scope_authenticated", False))
            else all_components
        )
    if float(aux_subgoal_loss_weight) > 0.0:
        active_components.update(
            (
                int(value)
                for value in getattr(
                    data, "aux_subgoal_component_indices", tuple()
                )
            )
            if bool(getattr(data, "aux_subgoal_scope_authenticated", False))
            else all_components
        )
    # Q, public-belief, and MoE balance objectives have no narrower
    # authenticated component namespace. Preserve every admitted component
    # whenever one is enabled rather than deleting valid supervision.
    if any(
        weight > 0.0
        for weight in (
            q_loss_weight,
            belief_resource_loss_weight,
            moe_balance_loss_weight,
        )
    ):
        active_components.update(all_components)
    if not np.any(enabled_flags):
        raise SystemExit(
            "coverage_importance_v1 has no enabled supported training objective"
        )
    if (
        not active_components
        or any(
            component < 0 or component >= component_count
            for component in active_components
        )
    ):
        raise SystemExit(
            "coverage_importance_v1 objective-active component scope is invalid"
        )

    indices = np.asarray(train_indices, dtype=np.int64)
    components = np.asarray(
        data.component_indices_for_rows(indices), dtype=np.int64
    )
    if components.shape != indices.shape:
        raise SystemExit("coverage objective component row lookup shape drift")
    active = np.asarray(sorted(active_components), dtype=np.int64)
    keep = np.isin(components, active)
    filtered = indices[keep]
    if filtered.size == 0:
        raise SystemExit(
            "coverage_importance_v1 objective-active training split is empty"
        )
    before_counts = np.bincount(components, minlength=component_count).astype(
        np.int64, copy=False
    )
    after_counts = np.bincount(
        components[keep], minlength=component_count
    ).astype(np.int64, copy=False)
    if np.any(after_counts[active] <= 0):
        missing = active[after_counts[active] <= 0]
        raise SystemExit(
            "coverage objective-active component(s) have no training rows: "
            + ",".join(str(int(value)) for value in missing)
        )
    active_mass = float(ratios[active].sum())
    if not math.isfinite(active_mass) or active_mass <= 0.0:
        raise SystemExit("coverage objective-active component mass is invalid")
    conditional_ratios = np.zeros(component_count, dtype=np.float64)
    conditional_ratios[active] = ratios[active] / active_mass
    if not math.isclose(
        float(conditional_ratios.sum()),
        1.0,
        rel_tol=0.0,
        abs_tol=1.0e-9,
    ):
        raise SystemExit("coverage objective-active conditional ratio drift")
    return filtered, {
        "coverage_objective_component_indices": active,
        "coverage_objective_component_rows_before": before_counts,
        "coverage_objective_component_rows_after": after_counts,
        "coverage_objective_conditional_ratios": conditional_ratios,
        "coverage_objective_enabled_flags": enabled_flags,
        "coverage_objective_scope_summary": np.asarray(
            [
                int(indices.size),
                int(filtered.size),
                int(indices.size - filtered.size),
                active_mass,
                int(enabled_flags[0]),
                int(np.any(enabled_flags[[1, 2, 3, 6]])),
            ],
            dtype=np.float64,
        ),
    }


def _coverage_objective_active_scope_report(
    data, derived: Mapping[str, np.ndarray]
) -> dict[str, object]:
    """Decode and bind the cached objective-active coverage scope."""

    required = {
        "coverage_objective_component_indices",
        "coverage_objective_component_rows_before",
        "coverage_objective_component_rows_after",
        "coverage_objective_conditional_ratios",
        "coverage_objective_enabled_flags",
        "coverage_objective_scope_summary",
    }
    missing = sorted(required.difference(derived))
    if missing:
        raise SystemExit(
            "coverage objective-active derived arrays are missing: "
            + ",".join(missing)
        )
    component_ids = tuple(
        str(value)
        for value in getattr(
            data,
            "component_ids",
            tuple(str(index) for index in range(len(data.corpora))),
        )
    )
    active = np.asarray(
        derived["coverage_objective_component_indices"], dtype=np.int64
    )
    before = np.asarray(
        derived["coverage_objective_component_rows_before"], dtype=np.int64
    )
    after = np.asarray(
        derived["coverage_objective_component_rows_after"], dtype=np.int64
    )
    conditional = np.asarray(
        derived["coverage_objective_conditional_ratios"], dtype=np.float64
    )
    summary = np.asarray(
        derived["coverage_objective_scope_summary"], dtype=np.float64
    )
    enabled_flags = np.asarray(
        derived["coverage_objective_enabled_flags"], dtype=np.uint8
    )
    objective_names = (
        "policy",
        "scalar_value_loss",
        "final_vp_loss",
        "categorical_value_loss",
        "q_loss",
        "policy_kl_anchor",
        "value_uncertainty_loss",
        "aux_subgoal_loss",
        "belief_resource_loss",
        "moe_balance_loss",
    )
    component_count = len(component_ids)
    if (
        before.shape != (component_count,)
        or after.shape != (component_count,)
        or conditional.shape != (component_count,)
        or summary.shape != (6,)
        or enabled_flags.shape != (len(objective_names),)
        or np.any((enabled_flags != 0) & (enabled_flags != 1))
        or np.any(active < 0)
        or np.any(active >= component_count)
        or len(np.unique(active)) != len(active)
    ):
        raise SystemExit("coverage objective-active report shape drift")
    active_set = {int(value) for value in active}
    components = {
        component_id: {
            "component_index": int(index),
            "objective_active": bool(index in active_set),
            "authenticated_training_rows": int(before[index]),
            "objective_active_training_rows": int(after[index]),
            "excluded_training_rows": int(before[index] - after[index]),
            "conditional_component_game_sampling_ratio": float(
                conditional[index]
            ),
        }
        for index, component_id in enumerate(component_ids)
    }
    report: dict[str, object] = {
        "schema_version": "coverage-objective-active-scope-v2",
        "enabled_objectives": [
            name
            for enabled, name in zip(enabled_flags, objective_names, strict=True)
            if enabled
        ],
        "authenticated_training_split_row_count": int(summary[0]),
        "objective_active_training_row_count": int(summary[1]),
        "excluded_zero_objective_training_row_count": int(summary[2]),
        "objective_active_target_mass_before_conditioning": float(summary[3]),
        "active_component_ids": [
            component_ids[index] for index in sorted(active_set)
        ],
        "excluded_component_ids": [
            component_ids[index]
            for index in range(component_count)
            if index not in active_set
        ],
        "conditional_component_game_sampling_ratios": {
            component_ids[index]: float(conditional[index])
            for index in sorted(active_set)
        },
        "components": components,
        "schedule_row_count_semantics": (
            "optimizer_schedule_and_epoch_updates_use_objective_active_training_rows"
        ),
    }
    report["scope_sha256"] = _canonical_json_sha256(report)
    return report


def _coverage_objective_schedule_accounting(
    scope_report: Mapping[str, object],
    *,
    local_batch_size: int,
    world_size: int,
    grad_accum_steps: int,
    epochs: int,
    max_steps: int,
) -> dict[str, object]:
    """Bind the optimizer horizon to rows that can produce an enabled loss."""

    local = int(local_batch_size)
    world = int(world_size)
    accumulation = int(grad_accum_steps)
    epoch_count = int(epochs)
    step_cap = int(max_steps)
    if min(local, world, accumulation, epoch_count) <= 0 or step_cap < 0:
        raise ValueError("coverage objective-active schedule inputs are invalid")
    authenticated_rows = int(
        scope_report["authenticated_training_split_row_count"]
    )
    active_rows = int(scope_report["objective_active_training_row_count"])
    if authenticated_rows <= 0 or not 0 < active_rows <= authenticated_rows:
        raise ValueError("coverage objective-active row accounting is invalid")
    global_batch = local * world * accumulation
    authenticated_steps = math.ceil(authenticated_rows / global_batch)
    active_steps = math.ceil(active_rows / global_batch)
    schedule_steps = step_cap if step_cap > 0 else epoch_count * active_steps
    return {
        "schema_version": "coverage-objective-active-schedule-v1",
        "local_batch_size": local,
        "world_size": world,
        "grad_accum_steps": accumulation,
        "effective_global_batch_size": global_batch,
        "epochs": epoch_count,
        "max_steps": step_cap,
        "authenticated_optimizer_steps_per_epoch": authenticated_steps,
        "objective_active_optimizer_steps_per_epoch": active_steps,
        "excluded_zero_objective_optimizer_slots_per_epoch": (
            authenticated_steps - active_steps
        ),
        "lr_schedule_total_steps": schedule_steps,
        "lr_schedule_total_steps_semantics": (
            "max_steps_if_positive_else_epochs_x_objective_active_steps_per_epoch"
        ),
    }


def _composite_game_sampling_weights(
    data,
    train_indices: np.ndarray,
    *,
    component_indices: Sequence[int] | None = None,
) -> np.ndarray | None:
    """Return authenticated component->game->row sampling probabilities.

    For a v2 composite, a draw first selects a component by its bound ratio,
    then a training game uniformly within that component, then a row uniformly
    within that game. ``component_indices`` optionally conditions those ratios
    on an authenticated objective-active component subset. Returning weights
    aligned to ``train_indices`` lets the existing seeded weighted epoch sampler
    perform that hierarchy without copying any corpus payload. V1 and ordinary
    corpora return ``None`` and therefore retain the historical permutation
    path exactly.
    """
    ratios = tuple(getattr(data, "component_game_sampling_ratios", tuple()))
    if not ratios:
        return None
    if len(ratios) != len(getattr(data, "corpora", tuple())):
        raise SystemExit("authenticated component sampling ratio count drift")
    if component_indices is None:
        selected_components = tuple(range(len(ratios)))
    else:
        selected_components = tuple(
            sorted({int(value) for value in component_indices})
        )
        if (
            not selected_components
            or any(
                value < 0 or value >= len(ratios)
                for value in selected_components
            )
        ):
            raise SystemExit(
                "authenticated component sampling selection is invalid"
            )
    selected_mass = float(
        sum(float(ratios[index]) for index in selected_components)
    )
    if not math.isfinite(selected_mass) or selected_mass <= 0.0:
        raise SystemExit("authenticated selected component mass is invalid")
    conditional_ratios = {
        component: float(ratios[component]) / selected_mass
        for component in selected_components
    }
    indices = np.asarray(train_indices, dtype=np.int64)
    components = np.asarray(data.component_indices_for_rows(indices), dtype=np.int64)
    unexpected = sorted(
        set(int(value) for value in np.unique(components)).difference(
            selected_components
        )
    )
    if unexpected:
        raise SystemExit(
            "authenticated component sampling rows include excluded component(s): "
            + ",".join(str(value) for value in unexpected)
        )
    seeds = np.asarray(data["game_seed"][indices], dtype=np.int64)
    weights = np.zeros(indices.shape[0], dtype=np.float64)
    for component in selected_components:
        ratio = conditional_ratios[component]
        positions = np.flatnonzero(components == component)
        if positions.size == 0:
            raise SystemExit(
                f"authenticated component {component} has no training rows"
            )
        component_seeds = seeds[positions]
        _games, inverse, counts = np.unique(
            component_seeds, return_inverse=True, return_counts=True
        )
        if counts.size == 0:
            raise SystemExit(
                f"authenticated component {component} has no training games"
            )
        weights[positions] = float(ratio) / (
            float(counts.size) * counts[inverse].astype(np.float64)
        )
    if not np.isfinite(weights).all() or np.any(weights <= 0.0):
        raise SystemExit("authenticated component game sampling produced invalid weights")
    if not math.isclose(float(weights.sum()), 1.0, rel_tol=0.0, abs_tol=1e-9):
        raise SystemExit("authenticated component game sampling mass drift")
    return weights


def _coverage_importance_weights(
    sampling_probabilities: np.ndarray,
) -> np.ndarray:
    """Transfer a target row measure onto a uniform full-coverage traversal.

    If the authenticated sampler assigns row ``i`` probability ``p_i`` and a
    permutation visits every row with probability ``q_i = 1/N``, the exact
    full-epoch weighted aggregate recovers the population objective with factor
    ``p_i / q_i = N*p_i``. The trainer reports its existing self-normalized
    minibatch estimator explicitly rather than calling each minibatch exact.
    """

    probabilities = np.asarray(sampling_probabilities, dtype=np.float64)
    if (
        probabilities.ndim != 1
        or probabilities.size == 0
        or not np.isfinite(probabilities).all()
        or np.any(probabilities <= 0.0)
        or not math.isclose(
            float(probabilities.sum()), 1.0, rel_tol=0.0, abs_tol=1.0e-9
        )
    ):
        raise ValueError(
            "coverage importance requires a positive normalized row measure"
        )
    factors = probabilities * float(probabilities.size)
    if not math.isclose(
        float(factors.mean()), 1.0, rel_tol=0.0, abs_tol=1.0e-9
    ):
        raise RuntimeError("coverage importance mean drift")
    return factors


def _effective_moe_balance_loss_weight(
    *, routed_experts: int, configured_weight: float
) -> float:
    """Return the MoE balance coefficient that can produce a gradient.

    The balance coefficient intentionally defaults to ``0.01`` while sparse
    MoE itself defaults off. With no routed experts the model emits an
    exact-zero balance term, so coverage admission and objective-scope
    filtering must not mistake that inert coefficient for an active loss.
    """

    weight = float(configured_weight)
    return weight if int(routed_experts) > 0 else 0.0


def _coverage_unsupported_objectives(
    args, *, categorical_value_loss_weight: float
) -> tuple[str, ...]:
    """List active objectives not yet normalized by coverage importance."""

    unsupported = {
        "advantage_policy_weighting": str(args.advantage_policy_weighting)
        != "none",
        "q_loss_weight": float(args.q_loss_weight) != 0.0,
        "policy_kl_anchor_weight": float(args.policy_kl_anchor_weight) != 0.0,
        "policy_kl_target": args.policy_kl_target is not None,
        "value_uncertainty_loss_weight": float(
            args.value_uncertainty_loss_weight
        )
        != 0.0,
        "aux_subgoal_loss_weight": float(args.aux_subgoal_loss_weight) != 0.0,
        "belief_resource_loss_weight": float(args.belief_resource_loss_weight)
        != 0.0,
        "value_categorical_loss_weight": float(categorical_value_loss_weight)
        != 0.0,
        "moe_balance_loss_weight": _effective_moe_balance_loss_weight(
            routed_experts=int(args.moe_routed_experts),
            configured_weight=float(args.moe_balance_loss_weight),
        )
        != 0.0,
    }
    return tuple(sorted(key for key, enabled in unsupported.items() if enabled))


def _validate_coverage_sampler_configuration(
    args, *, categorical_value_loss_weight: float
) -> None:
    """Reject unsupported coverage recipes before any derived cache is written."""

    policy_signal_floor = float(
        getattr(args, "minimum_policy_effective_rows_per_global_batch", 0.0)
    )
    if not math.isfinite(policy_signal_floor) or policy_signal_floor < 0.0:
        raise SystemExit(
            "--minimum-policy-effective-rows-per-global-batch must be finite "
            "and non-negative"
        )
    if str(args.base_sampler) != BASE_SAMPLER_COVERAGE_IMPORTANCE_V1:
        if policy_signal_floor > 0.0:
            raise SystemExit(
                "--minimum-policy-effective-rows-per-global-batch requires "
                "--base-sampler coverage_importance_v1"
            )
        return
    if (
        policy_signal_floor > 0.0
        and float(getattr(args, "policy_loss_weight", 0.0)) <= 0.0
    ):
        raise SystemExit(
            "--minimum-policy-effective-rows-per-global-batch requires a "
            "positive --policy-loss-weight"
        )
    if int(args.policy_aux_active_batch_size) > 0:
        raise SystemExit(
            "coverage_importance_v1 is currently sealed for the direct base "
            "learner only; policy AUX sampling needs a separate coverage contract"
        )
    enabled_unsupported = _coverage_unsupported_objectives(
        args,
        categorical_value_loss_weight=float(categorical_value_loss_weight),
    )
    if enabled_unsupported:
        raise SystemExit(
            "coverage_importance_v1 fixed-measure normalization does not yet "
            "bind these objectives: " + ",".join(enabled_unsupported)
        )


def _derived_training_scope_cache_fields(
    args,
    *,
    resolved_scalar_value_loss_weight: float,
    resolved_categorical_value_loss_weight: float,
) -> dict[str, object]:
    """Bind every objective that can change cached coverage component scope."""

    return {
        "base_sampler": str(args.base_sampler),
        "policy_loss_weight": float(args.policy_loss_weight),
        "resolved_scalar_value_loss_weight": float(
            resolved_scalar_value_loss_weight
        ),
        "final_vp_loss_weight": float(args.final_vp_loss_weight),
        "resolved_categorical_value_loss_weight": float(
            resolved_categorical_value_loss_weight
        ),
        "q_loss_weight": float(args.q_loss_weight),
        "policy_kl_anchor_weight": float(args.policy_kl_anchor_weight),
        "value_uncertainty_loss_weight": float(
            args.value_uncertainty_loss_weight
        ),
        "aux_subgoal_loss_weight": float(args.aux_subgoal_loss_weight),
        "belief_resource_loss_weight": float(args.belief_resource_loss_weight),
        "effective_moe_balance_loss_weight": (
            _effective_moe_balance_loss_weight(
                routed_experts=int(args.moe_routed_experts),
                configured_weight=float(args.moe_balance_loss_weight),
            )
        ),
    }


def _coverage_fixed_loss_normalizers(
    data,
    train_indices: np.ndarray,
    *,
    policy_sample_weights: np.ndarray,
    value_sample_weights: np.ndarray,
    truncated_vp_margin_value_weight: float,
    vps_to_win: int,
    public_information_only: bool,
    chunk_rows: int = 262_144,
) -> dict[str, float]:
    """Compute fixed proposal-measure denominators for coverage importance.

    A uniform full-coverage permutation with importance factor ``N*p_i`` has
    an unbiased minibatch gradient only when the random minibatch weight sum is
    not used as its own denominator.  These population means make every batch
    use ``batch_rows * E_q[effective_weight]`` while preserving the exact
    policy/value masks used by the learner.
    """

    rows = np.asarray(train_indices, dtype=np.int64)
    if rows.ndim != 1 or rows.size == 0:
        raise ValueError("coverage loss normalization requires training rows")
    policy_weights = np.asarray(policy_sample_weights, dtype=np.float64)
    value_weights = np.asarray(value_sample_weights, dtype=np.float64)
    if (
        policy_weights.shape != (len(data["action_taken"]),)
        or value_weights.shape != policy_weights.shape
    ):
        raise ValueError("coverage loss weight arrays are not corpus-aligned")

    policy_total = float(np.sum(policy_weights[rows], dtype=np.float64))
    value_total = 0.0
    final_vp_total = 0.0
    for start in range(0, rows.size, max(1, int(chunk_rows))):
        batch = rows[start : start + max(1, int(chunk_rows))]
        weights = value_weights[batch]
        if "winner" in data and "player" in data:
            winners = np.asarray(data["winner"][batch]).astype(str)
            truncated = _batch_array_or_fill(
                data, "truncated", batch, False, dtype=np.bool_
            )
            has_outcome = (winners != "") & ~truncated
            confidence = has_outcome.astype(np.float64)
            if (
                float(truncated_vp_margin_value_weight) > 0.0
                and np.any(truncated)
            ):
                soft_mask, _soft_outcome = _truncated_vp_margin_outcome(
                    data,
                    batch,
                    truncated,
                    int(vps_to_win),
                    public_information_only=bool(public_information_only),
                )
                fill = soft_mask & ~has_outcome
                confidence[fill] = float(truncated_vp_margin_value_weight)
            value_total += float(np.sum(weights * confidence, dtype=np.float64))

        if "seat" in data:
            seats = np.asarray(data["seat"][batch], dtype=np.int64)
            valid_vp = np.zeros(batch.size, dtype=np.bool_)
            truncated = _batch_array_or_fill(
                data, "truncated", batch, False, dtype=np.bool_
            )
            for value_key, present_key in (
                ("final_actual_vps", "has_final_actual_vps"),
                ("final_public_vps", "has_final_public_vps"),
            ):
                if value_key not in data:
                    continue
                values = np.asarray(data[value_key][batch])
                present = _batch_array_or_fill(
                    data, present_key, batch, False, dtype=np.bool_
                )
                valid_vp |= (
                    ~valid_vp
                    & ~truncated
                    & present
                    & (seats >= 0)
                    & (seats < values.shape[1])
                )
            final_vp_total += float(
                np.sum(weights * valid_vp.astype(np.float64), dtype=np.float64)
            )

    normalizers = {
        "policy_effective_weight_mean": policy_total / float(rows.size),
        "value_effective_weight_mean": value_total / float(rows.size),
        "final_vp_effective_weight_mean": final_vp_total / float(rows.size),
    }
    for name, value in normalizers.items():
        if not math.isfinite(value) or value < 0.0:
            raise ValueError(f"coverage {name} is invalid")
    if normalizers["policy_effective_weight_mean"] <= 0.0:
        raise SystemExit("coverage policy objective has zero population weight")
    return normalizers


def _coverage_policy_signal_admission(
    train_indices: np.ndarray,
    *,
    policy_sample_weights: np.ndarray,
    global_batch_size: int,
    minimum_effective_rows_per_global_batch: float,
    chunk_rows: int = 262_144,
) -> dict[str, object]:
    """Measure corpus-level policy dose before a coverage run can optimize.

    Counting only nonzero policy rows misses the failure mode where importance
    weighting concentrates nearly all policy mass onto a still smaller set.
    Kish effective sample size, ``sum(w)^2 / sum(w^2)``, captures both sparsity
    and concentration. Scaling its corpus fraction by the synchronous global
    batch size gives the expected effective policy rows in one optimizer
    update. This is an admission statistic, not a claim that every shuffled
    batch realizes exactly that count.

    The canonical floor is deliberately recipe-bound. It rejects the audited
    failed corpus (0.85% active and roughly 0.71% ESS: about 4.36 active and
    3.65 effective rows at global batch 512) while leaving legacy/diagnostic
    recipes unchanged unless they explicitly commission a positive floor.
    """

    rows = np.asarray(train_indices, dtype=np.int64)
    weights = np.asarray(policy_sample_weights)
    batch_size = int(global_batch_size)
    minimum = float(minimum_effective_rows_per_global_batch)
    if rows.ndim != 1 or rows.size == 0:
        raise ValueError("coverage policy admission requires training rows")
    if (
        weights.ndim != 1
        or np.any(rows < 0)
        or np.any(rows >= weights.size)
    ):
        raise ValueError("coverage policy admission weight alignment drift")
    if batch_size <= 0:
        raise ValueError("coverage policy admission requires positive global batch")
    if (
        not math.isfinite(minimum)
        or minimum < 0.0
        or minimum > float(batch_size)
    ):
        raise ValueError(
            "minimum policy effective rows must be finite and within the "
            "global batch"
        )

    active_rows = 0
    weight_sum = 0.0
    weight_square_sum = 0.0
    block_rows = max(1, int(chunk_rows))
    for start in range(0, rows.size, block_rows):
        scoped = np.asarray(
            weights[rows[start : start + block_rows]], dtype=np.float64
        )
        if not np.isfinite(scoped).all() or np.any(scoped < 0.0):
            raise ValueError(
                "coverage policy admission weights must be finite and non-negative"
            )
        active_rows += int(np.count_nonzero(scoped > 0.0))
        weight_sum += float(np.sum(scoped, dtype=np.float64))
        weight_square_sum += float(np.dot(scoped, scoped))
    if active_rows <= 0 or weight_sum <= 0.0 or weight_square_sum <= 0.0:
        if minimum > 0.0:
            raise SystemExit("coverage policy objective has zero population weight")
        return {
            "schema_version": "coverage-policy-signal-admission-v1",
            "training_row_count": int(rows.size),
            "policy_active_row_count": 0,
            "policy_active_row_fraction": 0.0,
            "policy_effective_sample_size_rows": 0.0,
            "policy_effective_sample_fraction": 0.0,
            "policy_effective_weight_sum": 0.0,
            "policy_effective_weight_square_sum": 0.0,
            "effective_global_batch_size": batch_size,
            "expected_policy_active_rows_per_global_batch": 0.0,
            "expected_policy_effective_rows_per_global_batch": 0.0,
            "minimum_policy_effective_rows_per_global_batch": minimum,
            "admission_enforced": False,
            "admitted": True,
            "signal_present": False,
            "estimator": "kish_ess_fraction_x_synchronous_global_batch_v1",
        }

    effective_rows = (weight_sum * weight_sum) / weight_square_sum
    row_count = int(rows.size)
    active_fraction = float(active_rows) / float(row_count)
    effective_fraction = float(effective_rows) / float(row_count)
    expected_active = float(batch_size) * active_fraction
    expected_effective = float(batch_size) * effective_fraction
    report: dict[str, object] = {
        "schema_version": "coverage-policy-signal-admission-v1",
        "training_row_count": row_count,
        "policy_active_row_count": active_rows,
        "policy_active_row_fraction": active_fraction,
        "policy_effective_sample_size_rows": float(effective_rows),
        "policy_effective_sample_fraction": effective_fraction,
        "policy_effective_weight_sum": weight_sum,
        "policy_effective_weight_square_sum": weight_square_sum,
        "effective_global_batch_size": batch_size,
        "expected_policy_active_rows_per_global_batch": expected_active,
        "expected_policy_effective_rows_per_global_batch": expected_effective,
        "minimum_policy_effective_rows_per_global_batch": minimum,
        "admission_enforced": minimum > 0.0,
        "admitted": expected_effective >= minimum,
        "signal_present": True,
        "estimator": "kish_ess_fraction_x_synchronous_global_batch_v1",
    }
    if minimum > 0.0 and expected_effective < minimum:
        raise SystemExit(
            "coverage policy signal admission refused sparse/concentrated "
            "supervision before the first optimizer step: "
            f"active_rows={active_rows}/{row_count} "
            f"expected_active_per_global_batch={expected_active:.6g} "
            f"effective_sample_size={effective_rows:.6g} "
            f"expected_effective_per_global_batch={expected_effective:.6g} "
            f"required={minimum:.6g} global_batch={batch_size}"
        )
    return report


def _hard_decision_policy_mass_minima(args) -> dict[str, float] | None:
    """Return the complete reviewed hard-decision contract or unset sentinel.

    A partial contract would leave a strategic decision silently unprotected.
    Zero is not a meaningful production floor: callers that have not
    commissioned values must leave every field unset and remain fail-closed at
    the production launcher.
    """

    raw = {
        "BUILD_INITIAL_SETTLEMENT": getattr(
            args, "minimum_initial_settlement_policy_mass_fraction", None
        ),
        "BUILD_INITIAL_ROAD": getattr(
            args, "minimum_initial_road_policy_mass_fraction", None
        ),
        "DISCARD": getattr(args, "minimum_discard_policy_mass_fraction", None),
        "MOVE_ROBBER": getattr(
            args, "minimum_move_robber_policy_mass_fraction", None
        ),
    }
    present = {phase: value is not None for phase, value in raw.items()}
    if not any(present.values()):
        return None
    if not all(present.values()):
        raise SystemExit(
            "hard-decision policy-mass admission requires reviewed minima for "
            "BUILD_INITIAL_SETTLEMENT, BUILD_INITIAL_ROAD, DISCARD, and MOVE_ROBBER"
        )
    minima = {phase: float(value) for phase, value in raw.items()}
    if any(
        not math.isfinite(value) or not 0.0 < value <= 1.0
        for value in minima.values()
    ):
        raise SystemExit(
            "hard-decision policy-mass minima must be finite fractions in (0, 1]"
        )
    if sum(minima.values()) > 1.0:
        raise SystemExit("hard-decision policy-mass minima cannot sum above one")
    return minima


def _policy_phase_objective_mass_admission(
    data,
    train_indices: np.ndarray,
    *,
    policy_sample_weights: np.ndarray,
    sampling_weights: np.ndarray | None,
    minimum_phase_mass_fractions: Mapping[str, float] | None,
    objective_measure: str,
    chunk_rows: int = 262_144,
) -> dict[str, object]:
    """Measure the exact expected policy-loss mass by phase before training.

    ``policy_sample_weights`` is the final loss multiplier after forced-row,
    phase, per-game, reliability, and (for coverage traversal) importance
    weighting. For weighted replacement, ``sampling_weights`` contributes the
    row draw probability as well. Consequently the reported fractions describe
    the objective the optimizer is expected to see, rather than raw row counts
    or nominal phase multipliers.
    """

    rows = np.asarray(train_indices, dtype=np.int64)
    weights = np.asarray(policy_sample_weights)
    if rows.ndim != 1 or rows.size == 0:
        raise ValueError("policy phase-mass admission requires training rows")
    if (
        weights.ndim != 1
        or np.any(rows < 0)
        or np.any(rows >= weights.size)
    ):
        raise ValueError("policy phase-mass weight alignment drift")
    if "phase" not in data:
        if minimum_phase_mass_fractions is not None:
            raise SystemExit(
                "hard-decision policy-mass admission requires a row-aligned phase column"
            )
        report: dict[str, object] = {
            "schema_version": "policy-phase-objective-mass-admission-v2",
            "available": False,
            "admission_enforced": False,
            "admitted": None,
            "reason": "phase_column_unavailable",
            "objective_measure": str(objective_measure),
            "required_phases": list(HARD_DECISION_POLICY_MASS_PHASES),
            "minimum_phase_mass_fractions": None,
            "per_phase": {},
        }
        report["identity_sha256"] = _canonical_json_sha256(report)
        return report

    draw_weights = None
    if sampling_weights is not None:
        draw_weights = np.asarray(sampling_weights, dtype=np.float64)
        if (
            draw_weights.shape != rows.shape
            or not np.isfinite(draw_weights).all()
            or np.any(draw_weights < 0.0)
            or float(draw_weights.sum()) <= 0.0
        ):
            raise ValueError("policy phase-mass sampling measure is invalid")
        draw_weights = draw_weights / float(draw_weights.sum())

    row_counts: Counter[str] = Counter()
    active_counts: Counter[str] = Counter()
    phase_mass: Counter[str] = Counter()
    block_rows = max(1, int(chunk_rows))
    for start in range(0, rows.size, block_rows):
        stop = start + block_rows
        block = rows[start:stop]
        phases = np.asarray(data["phase"][block]).astype(str)
        scoped = np.asarray(weights[block], dtype=np.float64)
        if phases.shape != block.shape:
            raise ValueError("policy phase column is not row-aligned")
        if not np.isfinite(scoped).all() or np.any(scoped < 0.0):
            raise ValueError(
                "policy phase-mass weights must be finite and non-negative"
            )
        if draw_weights is not None:
            scoped = scoped * draw_weights[start:stop]
        for phase in np.unique(phases):
            selected = phases == phase
            name = str(phase)
            row_counts[name] += int(np.count_nonzero(selected))
            active_counts[name] += int(np.count_nonzero(scoped[selected] > 0.0))
            phase_mass[name] += float(
                np.sum(scoped[selected], dtype=np.float64)
            )

    total_mass = float(sum(phase_mass.values()))
    if not math.isfinite(total_mass) or total_mass <= 0.0:
        if minimum_phase_mass_fractions is not None:
            raise SystemExit(
                "hard-decision policy-mass admission found zero policy objective mass"
            )
        total_mass = 0.0
    minima = (
        None
        if minimum_phase_mass_fractions is None
        else {
            phase: float(minimum_phase_mass_fractions[phase])
            for phase in HARD_DECISION_POLICY_MASS_PHASES
        }
    )
    per_phase: dict[str, dict[str, object]] = {}
    for phase in sorted(set(row_counts) | set(HARD_DECISION_POLICY_MASS_PHASES)):
        mass = float(phase_mass.get(phase, 0.0))
        fraction = mass / total_mass if total_mass > 0.0 else 0.0
        minimum = None if minima is None else minima.get(phase)
        per_phase[phase] = {
            "training_row_count": int(row_counts.get(phase, 0)),
            "policy_active_row_count": int(active_counts.get(phase, 0)),
            "policy_objective_mass": mass,
            "policy_objective_mass_fraction": fraction,
            "minimum_policy_objective_mass_fraction": minimum,
            "admitted": None if minimum is None else fraction >= minimum,
        }
    admitted = None
    if minima is not None:
        admitted = all(
            bool(per_phase[phase]["admitted"])
            for phase in HARD_DECISION_POLICY_MASS_PHASES
        )
    report = {
        "schema_version": "policy-phase-objective-mass-admission-v2",
        "available": True,
        "admission_enforced": minima is not None,
        "admitted": admitted,
        "reason": (
            "reviewed_minima_satisfied"
            if admitted is True
            else "reviewed_minima_not_commissioned"
            if admitted is None
            else "hard_decision_policy_objective_mass_below_reviewed_minimum"
        ),
        "objective_measure": str(objective_measure),
        "training_row_count": int(rows.size),
        "total_policy_objective_mass": total_mass,
        "required_phases": list(HARD_DECISION_POLICY_MASS_PHASES),
        "minimum_phase_mass_fractions": minima,
        "per_phase": per_phase,
    }
    report["identity_sha256"] = _canonical_json_sha256(report)
    if admitted is False:
        details = ", ".join(
            f"{phase}={per_phase[phase]['policy_objective_mass_fraction']:.6g}"
            f"<{minima[phase]:.6g}"
            for phase in HARD_DECISION_POLICY_MASS_PHASES
            if not bool(per_phase[phase]["admitted"])
        )
        raise SystemExit(
            "hard-decision policy-mass admission refused before the first optimizer "
            f"step: {details}"
        )
    return report


def _compose_per_game_policy_surprise_sampling_weights(
    data,
    train_indices: np.ndarray,
    surprise_factors: np.ndarray,
    base_sampling_weights: np.ndarray | None,
) -> np.ndarray:
    """Apply within-game surprise after the established source measure.

    ``surprise_factors`` is aligned to ``train_indices`` and has total factor
    mass equal to the row count of every game.  With no authenticated composite,
    it directly defines the weighted epoch order.  With a composite base measure,
    multiplication redistributes rows only *inside* each game; this helper also
    verifies that every authenticated component retains its exact bound mass.
    """

    indices = np.asarray(train_indices, dtype=np.int64)
    factors = np.asarray(surprise_factors, dtype=np.float64)
    if factors.shape != indices.shape:
        raise ValueError("per-game policy-surprise factor alignment drift")
    if not np.isfinite(factors).all() or np.any(factors <= 0.0):
        raise ValueError("per-game policy-surprise factors must be finite and positive")
    if base_sampling_weights is None:
        return factors

    base = np.asarray(base_sampling_weights, dtype=np.float64)
    if base.shape != indices.shape:
        raise ValueError("component and policy-surprise sampling alignment drift")
    if not np.isfinite(base).all() or np.any(base <= 0.0):
        raise ValueError("authenticated component sampling measure is invalid")
    combined = base * factors

    components = np.asarray(data.component_indices_for_rows(indices), dtype=np.int64)
    component_count = len(getattr(data, "component_game_sampling_ratios", tuple()))
    if component_count <= 0:
        raise ValueError("component sampling metadata disappeared during composition")
    before = np.bincount(components, weights=base, minlength=component_count)
    after = np.bincount(components, weights=combined, minlength=component_count)
    if not np.allclose(after, before, rtol=0.0, atol=1.0e-9):
        raise RuntimeError(
            "per-game policy-surprise changed authenticated component proportions"
        )
    total = float(combined.sum())
    if not math.isfinite(total) or total <= 0.0:
        raise ValueError("composed policy-surprise sampling measure has no mass")
    combined *= float(base.sum()) / total
    return combined


def _conditioned_policy_aux_sampling_weights(
    base_sampling_weights: np.ndarray,
    policy_weight_multiplier: np.ndarray,
) -> np.ndarray:
    """Condition an authenticated base row measure on policy-active rows."""
    base = np.asarray(base_sampling_weights, dtype=np.float64)
    multiplier = np.asarray(policy_weight_multiplier)
    if base.ndim != 1 or multiplier.ndim != 1 or base.shape != multiplier.shape:
        raise ValueError("policy auxiliary base/multiplier shape drift")
    if not np.isfinite(base).all() or np.any(base < 0.0):
        raise ValueError("policy auxiliary base measure is invalid")
    # Admission only: phase/winner/loser weights remain loss weights and must
    # not silently become a second sampling-frequency correction.
    conditioned = np.where(multiplier > 0.0, base, 0.0)
    total = float(conditioned.sum())
    if not math.isfinite(total) or total <= 0.0:
        raise ValueError("policy auxiliary measure has no active mass")
    conditioned /= total
    return conditioned


def _compose_stage_c_policy_surprise_sampling_weights(
    data,
    indices: np.ndarray,
    surprise_factors: np.ndarray,
    stage_c_sampling_weights: np.ndarray,
) -> np.ndarray:
    """Apply surprise inside the authenticated Stage-C selected-root measure.

    Stage-C weights are zero outside the reanalysed selected roots, so the
    ordinary component composer cannot accept them.  Preserve the Stage-C mass
    of every represented game exactly, and use surprise only to redistribute
    that mass among selected roots from the same game.  This prevents enabling
    ``--per-game-policy-surprise-weighting`` from silently replacing the
    strategic/production Stage-C arm with a different global sampler.
    """

    rows = np.asarray(indices, dtype=np.int64)
    factors = np.asarray(surprise_factors, dtype=np.float64)
    base = np.asarray(stage_c_sampling_weights, dtype=np.float64)
    if factors.shape != rows.shape or base.shape != rows.shape:
        raise ValueError("Stage-C policy-surprise sampling alignment drift")
    if (
        not np.isfinite(factors).all()
        or np.any(factors <= 0.0)
        or not np.isfinite(base).all()
        or np.any(base < 0.0)
    ):
        raise ValueError("Stage-C policy-surprise inputs are invalid")
    if not np.any(base > 0.0):
        raise ValueError("Stage-C policy-surprise base has no selected-root mass")

    game_identities = _component_game_identities(data, rows)
    _games, inverse = np.unique(game_identities, return_inverse=True)
    game_count = int(inverse.max()) + 1 if inverse.size else 0
    before = np.bincount(inverse, weights=base, minlength=game_count)
    combined = base * factors
    after = np.bincount(inverse, weights=combined, minlength=game_count)
    represented = before > 0.0
    if np.any(after[represented] <= 0.0):
        raise RuntimeError("Stage-C policy-surprise erased a represented game")
    scales = np.ones(game_count, dtype=np.float64)
    scales[represented] = before[represented] / after[represented]
    combined *= scales[inverse]
    restored = np.bincount(inverse, weights=combined, minlength=game_count)
    if not np.allclose(restored, before, rtol=0.0, atol=1.0e-9):
        raise RuntimeError("Stage-C policy-surprise changed per-game sampling mass")
    return combined


def _stage_c_policy_aux_base_measure(
    data,
    train_indices: np.ndarray,
) -> tuple[np.ndarray, str] | None:
    """Load the authenticated Stage-C selected-root sampling distribution."""

    meta = getattr(data, "meta", None)
    overlay = meta.get("stage_c_policy_overlay") if isinstance(meta, dict) else None
    sampling = overlay.get("sampling_distribution") if isinstance(overlay, dict) else None
    if sampling is None:
        return None
    if (
        not isinstance(sampling, dict)
        or sampling.get("schema_version")
        not in {
            "a1-stage-c-policy-sampling-distribution-v1",
            "a1-stage-c-policy-sampling-distribution-v2",
        }
        or sampling.get("column") != "stage_c_policy_sampling_weight"
        or sampling.get("arm")
        not in {"PRODUCTION_WEIGHTED", "STRATEGIC_BALANCED"}
        or "stage_c_policy_sampling_weight" not in data
    ):
        raise SystemExit("Stage-C policy sampling contract is malformed")
    indices = np.asarray(train_indices, dtype=np.int64)
    weights = np.asarray(
        data["stage_c_policy_sampling_weight"][indices], dtype=np.float64
    )
    active = np.asarray(data["policy_weight_multiplier"][indices], dtype=np.float64) > 0.0
    if (
        weights.shape != indices.shape
        or not np.isfinite(weights).all()
        or np.any(weights < 0.0)
        or np.any(weights[~active] != 0.0)
        or np.any(weights[active] <= 0.0)
    ):
        raise SystemExit("Stage-C policy sampling weights violate active-row scope")
    active_mean = float(np.mean(weights[active])) if np.any(active) else 0.0
    if not math.isclose(active_mean, 1.0, rel_tol=0.0, abs_tol=2.0e-6):
        raise SystemExit(
            "Stage-C policy sampling weights lost unit selected-training mean: "
            f"{active_mean}"
        )
    return weights, f"stage_c_{str(sampling['arm']).lower()}"


def _apply_authenticated_policy_aux_phase_allocation(
    active_sampling_weights: np.ndarray,
    phase_values: np.ndarray,
    phase_sampling_weights: dict[str, float],
    component_values: np.ndarray | None = None,
) -> np.ndarray:
    """Allocate exact AUX draw mass across authenticated, explicit phases.

    ``active_sampling_weights`` is already the authenticated composite base
    measure conditioned on the policy-distillation scope and positive policy
    loss. Within each component and requested phase we preserve that measure
    exactly. Each component keeps its original total AUX mass, preventing a
    phase arm from becoming a hidden n128:n256 mixture arm. Unlisted phases
    receive no auxiliary draws. This never changes the base sampler/value loss.
    """

    base = np.asarray(active_sampling_weights, dtype=np.float64)
    phases = np.asarray(phase_values).astype(str, copy=False)
    if base.ndim != 1 or phases.ndim != 1 or base.shape != phases.shape:
        raise ValueError("policy auxiliary phase allocation shape drift")
    components = (
        np.zeros(base.size, dtype=np.int16)
        if component_values is None
        else np.asarray(component_values)
    )
    if components.ndim != 1 or components.shape != base.shape:
        raise ValueError("policy auxiliary phase component alignment drift")
    if not isinstance(phase_sampling_weights, dict) or not phase_sampling_weights:
        raise ValueError("policy auxiliary phase allocation is empty")
    if not np.isfinite(base).all() or np.any(base < 0.0):
        raise ValueError("policy auxiliary active measure is invalid")
    configured_total = float(sum(phase_sampling_weights.values()))
    if not math.isclose(configured_total, 1.0, rel_tol=0.0, abs_tol=1e-9):
        raise ValueError("policy auxiliary phase allocation must sum to 1")

    allocated = np.zeros_like(base)
    for component in np.unique(components[base > 0.0]):
        component_mask = components == component
        component_mass = float(base[component_mask].sum())
        for phase, raw_share in phase_sampling_weights.items():
            share = float(raw_share)
            if not phase or not math.isfinite(share) or share <= 0.0:
                raise ValueError(
                    f"policy auxiliary phase allocation is invalid for {phase!r}"
                )
            mask = component_mask & (phases == phase)
            stratum_mass = float(base[mask].sum())
            if not math.isfinite(stratum_mass) or stratum_mass <= 0.0:
                raise ValueError(
                    "policy auxiliary requested phase has no policy-active mass "
                    f"in component {component!r}: {phase!r}"
                )
            allocated[mask] = base[mask] * (
                component_mass * share / stratum_mass
            )
    total = float(allocated.sum())
    if not math.isclose(total, 1.0, rel_tol=0.0, abs_tol=1e-9):
        raise ValueError("policy auxiliary phase allocation mass drift")
    return allocated


def _authenticated_policy_aux_phase_sampling_weights(
    data,
    train_indices: np.ndarray,
    active_sampling_weights: np.ndarray,
    phase_sampling_weights: dict[str, float],
    *,
    chunk_rows: int = 1_000_000,
) -> np.ndarray:
    """Chunk-decode corpus phases, then apply an authenticated allocation.

    Memmap string columns decode to NumPy Unicode.  Keeping only an int16
    stratum id avoids a multi-gigabyte full-corpus Unicode temporary on large
    composites while preserving exact row probabilities.
    """

    rows = np.asarray(train_indices, dtype=np.int64)
    base = np.asarray(active_sampling_weights, dtype=np.float64)
    if rows.ndim != 1 or base.shape != rows.shape:
        raise ValueError("policy auxiliary phase corpus alignment drift")
    if "phase" not in data:
        raise ValueError("policy auxiliary phase allocation requires a phase column")
    phase_names = tuple(phase_sampling_weights)
    if len(phase_names) > np.iinfo(np.int16).max:
        raise ValueError("policy auxiliary phase allocation has too many strata")
    labels = np.full(rows.size, -1, dtype=np.int16)
    components = np.asarray(
        data.component_indices_for_rows(rows), dtype=np.int16
    )
    chunk = max(1, int(chunk_rows))
    for start in range(0, rows.size, chunk):
        stop = min(start + chunk, rows.size)
        decoded = np.asarray(data["phase"][rows[start:stop]]).astype(
            str, copy=False
        )
        for label, phase in enumerate(phase_names):
            labels[start:stop][decoded == phase] = label

    shares = np.asarray(
        [float(phase_sampling_weights[phase]) for phase in phase_names],
        dtype=np.float64,
    )
    if not np.isfinite(shares).all() or np.any(shares <= 0.0) or not math.isclose(
        float(shares.sum()), 1.0, rel_tol=0.0, abs_tol=1e-9
    ):
        raise ValueError("policy auxiliary phase allocation is invalid")
    allocated = np.zeros_like(base)
    for component in np.unique(components[base > 0.0]):
        component_mask = components == component
        component_mass = float(base[component_mask].sum())
        for label, phase in enumerate(phase_names):
            mask = component_mask & (labels == label)
            stratum_mass = float(base[mask].sum())
            if not math.isfinite(stratum_mass) or stratum_mass <= 0.0:
                raise ValueError(
                    "policy auxiliary requested phase has no policy-active mass "
                    f"in component {int(component)}: {phase!r}"
                )
            allocated[mask] = base[mask] * (
                component_mass * shares[label] / stratum_mass
            )
    if not math.isclose(float(allocated.sum()), 1.0, rel_tol=0.0, abs_tol=1e-9):
        raise ValueError("policy auxiliary phase allocation mass drift")
    return allocated


def _policy_component_phase_dose(
    data,
    rows: np.ndarray,
    phase_names: tuple[str, ...],
    *,
    suffix: str,
    chunk_rows: int = 1_000_000,
) -> dict[str, float]:
    """Count realized rows by authenticated component and configured phase."""

    indices = np.asarray(rows, dtype=np.int64)
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    result = {
        f"{component_id}\0{phase}\0{suffix}": 0.0
        for component_id in component_ids
        for phase in phase_names
    }
    if indices.size == 0:
        return result
    chunk = max(1, int(chunk_rows))
    for start in range(0, indices.size, chunk):
        part = indices[start : start + chunk]
        components = np.asarray(
            data.component_indices_for_rows(part), dtype=np.int64
        )
        phases = np.asarray(data["phase"][part]).astype(str, copy=False)
        for component, component_id in enumerate(component_ids):
            component_mask = components == component
            for phase in phase_names:
                result[f"{component_id}\0{phase}\0{suffix}"] += float(
                    np.count_nonzero(component_mask & (phases == phase))
                )
    return result


def _policy_component_dose_for_batch(
    data,
    rows: np.ndarray,
    *,
    suffix: str,
    phase_names: tuple[str, ...] = (),
) -> tuple[dict[str, float], dict[str, float]]:
    """Attribute realized policy-objective rows to component and phase."""

    indices = np.asarray(rows, dtype=np.int64)
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    component_dose = {
        f"{component_id}.{suffix}": 0.0 for component_id in component_ids
    }
    phase_dose = {
        f"{component_id}\0{phase}\0{suffix}": 0.0
        for component_id in component_ids
        for phase in phase_names
    }
    if indices.size == 0:
        return component_dose, phase_dose
    components = np.asarray(
        data.component_indices_for_rows(indices), dtype=np.int64
    )
    if components.shape != indices.shape:
        raise RuntimeError("policy component mapping shape drift")
    for component, component_id in enumerate(component_ids):
        component_dose[f"{component_id}.{suffix}"] = float(
            np.count_nonzero(components == component)
        )
    if phase_names:
        phase_dose = _policy_component_phase_dose(
            data, indices, phase_names, suffix=suffix
        )
    return component_dose, phase_dose


def _policy_aux_epoch_order(
    rng: np.random.Generator,
    n: int,
    sample_weights: np.ndarray,
    *,
    local_draws: int,
    ddp: dict[str, int | bool],
    mode: str = POLICY_AUX_SAMPLING_LEGACY_REPLACEMENT_V1,
    global_draw_offset: int = 0,
) -> np.ndarray:
    """Draw an exact per-rank dose from one deterministic global stream."""
    if int(local_draws) < 0:
        raise ValueError("policy auxiliary local_draws must be non-negative")
    weights = np.asarray(sample_weights, dtype=np.float64)
    if weights.shape != (int(n),):
        raise ValueError("policy auxiliary sampling weight length drift")
    total = float(weights.sum())
    if not math.isfinite(total) or total <= 0.0:
        raise ValueError("policy auxiliary sampling weights have no mass")
    if np.any(~np.isfinite(weights)) or np.any(weights < 0.0):
        raise ValueError(
            "policy auxiliary sampling weights must be finite and non-negative"
        )
    world = int(ddp["world_size"]) if ddp.get("enabled", False) else 1
    rank = int(ddp["rank"]) if ddp.get("enabled", False) else 0
    global_draws = int(local_draws) * world
    offset = int(global_draw_offset)
    if offset < 0:
        raise ValueError("policy auxiliary global_draw_offset must be non-negative")
    if mode == POLICY_AUX_SAMPLING_LEGACY_REPLACEMENT_V1:
        if offset != 0:
            raise ValueError(
                "legacy policy auxiliary sampling does not accept a global offset"
            )
        global_order = rng.choice(
            int(n), size=global_draws, replace=True, p=weights / total
        )
    elif mode == POLICY_AUX_SAMPLING_WEIGHTED_CYCLES_V1:
        eligible = np.flatnonzero(weights > 0.0).astype(np.int64, copy=False)
        eligible_weights = weights[eligible]
        global_order = np.empty(global_draws, dtype=np.int64)
        cycle_size = int(eligible.size)
        first_cycle = offset // cycle_size
        last_exclusive = offset + global_draws
        final_cycle = (
            (last_exclusive - 1) // cycle_size
            if global_draws > 0
            else first_cycle - 1
        )
        output_offset = 0
        for cycle in range(final_cycle + 1):
            # Gumbel-top-k generates a Plackett-Luce weighted permutation:
            # higher-mass rows tend to occur earlier, but every positive-mass
            # row appears exactly once before the next cycle begins.  Using
            # log(weight)+Gumbel avoids the reciprocal overflow of an
            # exponential race when an authenticated row has tiny positive
            # mass.
            priority = np.log(eligible_weights) + rng.gumbel(
                size=eligible_weights.size
            )
            if cycle < first_cycle:
                continue
            cycle_start = cycle * cycle_size
            slice_start = max(offset, cycle_start) - cycle_start
            slice_stop = min(last_exclusive, cycle_start + cycle_size) - cycle_start
            needed = int(slice_stop)
            if needed == cycle_size:
                selected = np.argsort(-priority, kind="stable")
            else:
                selected = np.argpartition(-priority, needed - 1)[:needed]
                selected = selected[
                    np.argsort(-priority[selected], kind="stable")
                ]
            part = eligible[selected[int(slice_start) : int(slice_stop)]]
            global_order[output_offset : output_offset + part.size] = part
            output_offset += int(part.size)
        if output_offset != global_draws:
            raise RuntimeError("weighted policy auxiliary cycle length drift")
    else:
        raise ValueError(f"unknown policy auxiliary sampling mode: {mode!r}")
    return np.asarray(global_order[rank::world], dtype=np.int64)


def _policy_aux_sampling_cycle_report(
    sample_weights: np.ndarray,
    *,
    local_draws: int,
    ddp: Mapping[str, int | bool],
    mode: str,
    global_draw_offset: int = 0,
) -> dict[str, object]:
    """Describe exact global coverage/reuse guarantees for one epoch stream."""

    weights = np.asarray(sample_weights, dtype=np.float64)
    positive = weights > 0.0
    eligible_rows = int(np.count_nonzero(positive))
    mass = float(weights[positive].sum())
    squared_mass = float(np.square(weights[positive]).sum())
    world = int(ddp["world_size"]) if ddp.get("enabled", False) else 1
    global_draws = int(local_draws) * world
    offset = int(global_draw_offset)
    end = offset + global_draws
    start_cycle = offset // eligible_rows if eligible_rows else 0
    end_cycle = (end - 1) // eligible_rows if eligible_rows and global_draws else -1
    cycle_boundaries_crossed = (
        end // eligible_rows - offset // eligible_rows if eligible_rows else 0
    )
    partial_cycle_draws_at_end = end % eligible_rows if eligible_rows else 0
    weighted_cycles = mode == POLICY_AUX_SAMPLING_WEIGHTED_CYCLES_V1
    return {
        "schema_version": "policy-aux-sampling-cycle-v1",
        "mode": str(mode),
        "global_draws": global_draws,
        "global_draw_offset": offset,
        "global_draw_end": end,
        "local_draws_per_rank": int(local_draws),
        "world_size": world,
        "eligible_positive_mass_rows": eligible_rows,
        "sampling_weight_effective_sample_size": (
            mass * mass / squared_mass if squared_mass > 0.0 else 0.0
        ),
        "start_cycle_index": int(start_cycle) if weighted_cycles else None,
        "end_cycle_index": int(end_cycle) if weighted_cycles else None,
        "complete_cycles_before_slice": (
            int(offset // eligible_rows)
            if weighted_cycles and eligible_rows
            else None
        ),
        "complete_cycles_after_slice": (
            int(end // eligible_rows)
            if weighted_cycles and eligible_rows
            else None
        ),
        "cycle_boundaries_crossed": (
            int(cycle_boundaries_crossed) if weighted_cycles else None
        ),
        "partial_cycle_draws_at_end": (
            int(partial_cycle_draws_at_end) if weighted_cycles else None
        ),
        "duplicates_before_cycle_exhaustion": (
            False if weighted_cycles else "unconstrained"
        ),
        "maximum_source_row_reuse_by_construction": (
            int(math.ceil(end / eligible_rows))
            if weighted_cycles
            else None
        ),
        "reuse_cap_semantics": (
            "cumulative_ceil(global_draw_end/eligible_positive_mass_rows)"
            if weighted_cycles
            else "none_weighted_draws_with_replacement"
        ),
        "global_stream_rank_partition": "rank_stride",
    }


def _policy_aux_loss_weights_without_phase_multiplication(
    data,
    batch: np.ndarray,
    sample_weights: np.ndarray,
    phase_loss_weights: Mapping[str, float] | None,
) -> np.ndarray:
    """Undo policy phase loss weights after phase-stratified AUX sampling.

    An authenticated AUX phase allocation already defines the Monte-Carlo
    measure over phases. Applying ``--phase-weights`` again inside the loss
    squares that treatment (for example 2/3 PLAY_TURN sampled at 4x becomes
    8/9 of gradient mass). Base-policy training retains the phase repair; only
    the separately stratified AUX stream removes the duplicate multiplier.
    """

    rows = np.asarray(batch, dtype=np.int64)
    weights = np.asarray(sample_weights[rows], dtype=np.float32).copy()
    if not phase_loss_weights:
        return weights
    if "phase" not in data:
        raise ValueError("phase-stratified AUX loss requires a phase column")
    phases = np.asarray(data["phase"][rows]).astype(str, copy=False)
    for phase, raw_multiplier in phase_loss_weights.items():
        multiplier = float(raw_multiplier)
        if not math.isfinite(multiplier) or multiplier <= 0.0:
            raise ValueError(
                "phase-stratified AUX loss can only undo finite positive phase "
                f"multipliers; got {phase}={raw_multiplier}"
            )
        weights[phases == str(phase)] /= multiplier
    return weights


def _policy_aux_source_reuse_summary(
    row_counts: Mapping[int, int],
    *,
    game_identities: set[tuple[int, int]],
    ddp: Mapping[str, int | bool],
    data_sharded: bool,
) -> dict[str, object]:
    """Return exact cumulative AUX source reuse across every learner rank."""

    local = {
        "rank": int(ddp.get("rank", 0)),
        "row_counts": {int(row): int(count) for row, count in row_counts.items()},
        "game_identities": sorted(
            (int(component), int(seed))
            for component, seed in game_identities
        ),
    }
    gathered = [local]
    if bool(ddp.get("enabled", False)):
        import torch.distributed as dist

        gathered = [None for _ in range(int(ddp["world_size"]))]
        dist.all_gather_object(gathered, local)
    merged: Counter[object] = Counter()
    merged_games: set[tuple[int, int]] = set()
    for record in gathered:
        if not isinstance(record, dict):
            raise RuntimeError("policy AUX reuse gather returned malformed rank data")
        rank = int(record["rank"])
        for row, count in dict(record["row_counts"]).items():
            identity: object = (rank, int(row)) if data_sharded else int(row)
            merged[identity] += int(count)
        merged_games.update(
            (int(component), int(seed))
            for component, seed in record["game_identities"]
        )
    counts = np.asarray(tuple(merged.values()), dtype=np.int64)
    draws = int(counts.sum()) if counts.size else 0
    unique_rows = int(counts.size)
    return {
        "schema_version": "policy-aux-source-reuse-v1",
        "draws": draws,
        "unique_source_rows": unique_rows,
        "unique_source_games": len(merged_games),
        "game_identity_namespace": "component_id+game_seed",
        "draws_per_unique_row": (
            float(draws / unique_rows) if unique_rows else 0.0
        ),
        "max_source_row_reuse": int(counts.max()) if counts.size else 0,
        "source_row_reuse_p50": (
            float(np.percentile(counts, 50)) if counts.size else 0.0
        ),
        "source_row_reuse_p95": (
            float(np.percentile(counts, 95)) if counts.size else 0.0
        ),
        "source_row_reuse_p99": (
            float(np.percentile(counts, 99)) if counts.size else 0.0
        ),
        "data_sharded_identity": bool(data_sharded),
    }


def _a1_canonical_sample_row_identity(
    *,
    payload_member_sha256: str,
    row_offset: int,
    component_id: str,
    prior_policy_present: bool,
    legal_action_count: int,
) -> str:
    """Reproduce the scientific producer's physical-row identity exactly."""

    return _canonical_json_sha256(
        {
            "schema_version": "a1-p1-kl-row-identity-v1",
            "payload_member_sha256": payload_member_sha256,
            "row_offset": int(row_offset),
            "component_id": component_id,
            "prior_policy_present": bool(prior_policy_present),
            "legal_action_count": int(legal_action_count),
        }
    )


def _a1_order_digest_update(
    digest, *, index: int, row_identity_sha256: str
) -> None:
    digest.update(str(int(index)).encode("ascii"))
    digest.update(b"\0")
    digest.update(row_identity_sha256.encode("ascii"))
    digest.update(b"\n")


def _a1_row_set_sha256(row_identities) -> str:
    digest = hashlib.sha256()
    for identity in sorted(set(row_identities)):
        digest.update(str(identity).encode("ascii"))
        digest.update(b"\n")
    return "sha256:" + digest.hexdigest()


def _a1_central_sample_order_evidence(
    data,
    *,
    train_indices: np.ndarray,
    validation_indices: np.ndarray,
    global_order_positions: np.ndarray,
    composite_meta: dict[str, object],
    expected_sample_dose: int,
    chunk_rows: int = 16_384,
) -> dict[str, object]:
    """Bind the *physical* rows actually drawn by the central learner.

    ``_epoch_order`` samples positions in ``train_indices``.  Hashing those
    positions would be ambiguous across split changes, so this projection first
    maps them to physical composite rows and then recreates the authenticated
    component/payload/local-offset identity used by the independent producer.
    It runs on rank 0 before the first optimizer step.
    """

    positions = np.asarray(global_order_positions, dtype=np.int64)
    train = np.asarray(train_indices, dtype=np.int64)
    validation = np.asarray(validation_indices, dtype=np.int64)
    if positions.ndim != 1 or positions.size != int(expected_sample_dose):
        raise RuntimeError(
            "central learner global sample dose drift: "
            f"expected={expected_sample_dose} actual={positions.size}"
        )
    if train.ndim != 1 or train.size < int(expected_sample_dose):
        raise RuntimeError(
            "central learner training split is smaller than the sealed dose"
        )
    if positions.size and (
        int(positions.min()) < 0 or int(positions.max()) >= int(train.size)
    ):
        raise RuntimeError("central learner order contains a non-training position")
    physical_rows = train[positions]
    if validation.size and np.isin(physical_rows, validation).any():
        raise RuntimeError("central learner sampled a validation-excluded physical row")
    component_ids = tuple(getattr(data, "component_ids", tuple()))
    component_offsets = np.asarray(
        getattr(data, "component_offsets", tuple()), dtype=np.int64
    )
    raw_components = composite_meta.get("components")
    if (
        len(component_ids) != 4
        or component_offsets.shape != (len(component_ids) + 1,)
        or not isinstance(raw_components, list)
        or len(raw_components) != len(component_ids)
    ):
        raise RuntimeError("central learner composite identity surface drift")
    inventory = {}
    for expected_id, raw in zip(component_ids, raw_components, strict=True):
        if (
            not isinstance(raw, dict)
            or raw.get("component_id") != expected_id
            or not _is_sha256(raw.get("payload_inventory_sha256"))
        ):
            raise RuntimeError("central learner component inventory drift")
        inventory[expected_id] = str(raw["payload_inventory_sha256"])
    component_indices = np.asarray(
        data.component_indices_for_rows(physical_rows), dtype=np.int64
    )
    if component_indices.shape != positions.shape or (
        component_indices.size
        and (
            int(component_indices.min()) < 0
            or int(component_indices.max()) >= len(component_ids)
        )
    ):
        raise RuntimeError("central learner physical-row component routing drift")
    order_digest = hashlib.sha256()
    eligible_digest = hashlib.sha256()
    evidence_digest = hashlib.sha256()
    identities: list[str] = []
    eligible = 0
    for start in range(0, int(positions.size), max(1, int(chunk_rows))):
        stop = min(int(positions.size), start + max(1, int(chunk_rows)))
        rows = physical_rows[start:stop]
        components = component_indices[start:stop]
        legal = np.asarray(data["legal_action_ids"][rows])
        prior = np.asarray(data["prior_policy"][rows], dtype=np.float32)
        valid = legal >= 0
        legal_counts = valid.sum(axis=1)
        has_prior = (prior * valid).sum(axis=1) > 1.0e-6
        for local_index in range(stop - start):
            draw_index = start + local_index
            component_index = int(components[local_index])
            component_id = component_ids[component_index]
            row_offset = int(rows[local_index] - component_offsets[component_index])
            identity = _a1_canonical_sample_row_identity(
                payload_member_sha256=inventory[component_id],
                row_offset=row_offset,
                component_id=component_id,
                prior_policy_present=bool(has_prior[local_index]),
                legal_action_count=int(legal_counts[local_index]),
            )
            identities.append(identity)
            _a1_order_digest_update(
                order_digest,
                index=draw_index,
                row_identity_sha256=identity,
            )
            row_evidence = {
                "draw_index": draw_index,
                "row_identity_sha256": identity,
                "payload_member_sha256": inventory[component_id],
                "row_offset": row_offset,
                "component_id": component_id,
                "prior_policy_present": bool(has_prior[local_index]),
                "legal_action_count": int(legal_counts[local_index]),
            }
            encoded = json.dumps(
                row_evidence,
                sort_keys=True,
                separators=(",", ":"),
                allow_nan=False,
            ).encode("utf-8") + b"\n"
            evidence_digest.update(encoded)
            if (
                component_id == "historical_replay"
                and bool(has_prior[local_index])
                and int(legal_counts[local_index]) > 1
            ):
                eligible += 1
                eligible_digest.update(encoded)
    return {
        "schema_version": "a1-realized-central-sample-order-v1",
        "sample_dose": int(positions.size),
        "sample_order_sha256": "sha256:" + order_digest.hexdigest(),
        "row_set_sha256": _a1_row_set_sha256(identities),
        "unique_row_count": len(set(identities)),
        "kl_eligible_rows": int(eligible),
        "kl_eligible_mass_decimal": format(
            eligible / max(1, int(positions.size)), ".12f"
        ).rstrip("0").rstrip("."),
        "kl_ordered_evidence_sha256": "sha256:" + evidence_digest.hexdigest(),
        "kl_eligible_evidence_sha256": "sha256:" + eligible_digest.hexdigest(),
        "physical_row_identity": True,
        "validation_rows_excluded": True,
    }


def _a1_reinterleave_rank_stride_orders(
    rank_orders: list[np.ndarray], *, expected_global_size: int
) -> np.ndarray:
    """Invert ``order[rank::world_size]`` and reject padding/shape drift."""

    if not rank_orders:
        raise RuntimeError("central learner has no DDP rank orders")
    arrays = [np.asarray(value, dtype=np.int64) for value in rank_orders]
    if any(value.ndim != 1 for value in arrays):
        raise RuntimeError("central learner rank order is not one-dimensional")
    lengths = {int(value.size) for value in arrays}
    if len(lengths) != 1:
        raise RuntimeError("central learner rank-stride orders have unequal lengths")
    reconstructed = np.stack(arrays, axis=1).reshape(-1)
    if reconstructed.size != int(expected_global_size):
        raise RuntimeError(
            "central learner DDP order required padding or changed dose: "
            f"expected={expected_global_size} actual={reconstructed.size}"
        )
    return reconstructed


def _a1_verify_realized_central_sample_order(
    realized: dict[str, object], sample_binding: dict[str, object]
) -> dict[str, object]:
    """Reject metadata echo: compare measurements from physical optimizer rows."""

    comparisons = {
        "sample_dose": "sample_dose",
        "sample_order_sha256": "sample_order_sha256",
        "row_set_sha256": "row_set_sha256",
        "unique_row_count": "unique_row_count",
        "kl_eligible_rows": "kl_eligible_rows",
        "kl_eligible_mass_decimal": "kl_eligible_mass_decimal",
        "kl_ordered_evidence_sha256": "kl_ordered_evidence_sha256",
        "kl_eligible_evidence_sha256": "kl_eligible_evidence_sha256",
    }
    drift = {
        field: {
            "authority": sample_binding.get(binding_field),
            "realized": realized.get(field),
        }
        for field, binding_field in comparisons.items()
        if realized.get(field) != sample_binding.get(binding_field)
    }
    if (
        realized.get("schema_version")
        != "a1-realized-central-sample-order-v1"
        or realized.get("physical_row_identity") is not True
        or realized.get("validation_rows_excluded") is not True
        or drift
    ):
        raise RuntimeError(f"central learner realized sample order drift: {drift}")
    return dict(realized)


def _a1_load_aux_geometry_manifest(
    binding: Mapping[str, object],
    *,
    rule: Mapping[str, object],
    data,
    train_indices: np.ndarray,
    validation_indices: np.ndarray,
    composite_meta: Mapping[str, object],
) -> tuple[dict[str, object], np.ndarray]:
    """Stable-read and physically replay the preregistered five-batch probe."""

    ref = binding.get("probe_manifest")
    if not isinstance(ref, dict) or set(ref) != {"path", "file_sha256"}:
        raise SystemExit("A1 AUX GEOMETRY probe-manifest reference drift")
    path, file_sha, payload = _stable_canonical_regular_file(
        str(ref["path"]), where="A1 AUX GEOMETRY probe manifest"
    )
    if file_sha != ref["file_sha256"] or file_sha != rule.get("probe_manifest_sha256"):
        raise SystemExit("A1 AUX GEOMETRY probe-manifest file digest drift")
    try:
        manifest = json.loads(payload.decode("utf-8"))
    except (UnicodeError, json.JSONDecodeError) as error:
        raise SystemExit(f"cannot parse A1 AUX GEOMETRY probe manifest: {error}") from error
    expected_fields = {
        "schema_version",
        "descriptor_sha256",
        "payload_inventory_sha256",
        "sampler_seed",
        "world_size",
        "local_batch_size",
        "probe_batches",
        "global_train_positions",
        "probe_row_order_sha256",
    }
    if not isinstance(manifest, dict) or set(manifest) != expected_fields:
        raise SystemExit("A1 AUX GEOMETRY probe-manifest shape drift")
    positions = np.asarray(manifest["global_train_positions"], dtype=np.int64)
    expected_rows = (
        int(rule["probe_batches"])
        * int(rule["probe_batch_size"])
        * int(manifest["world_size"])
    )
    if (
        manifest["schema_version"] != "a1-aux-gradient-probe-manifest-v1"
        or manifest["descriptor_sha256"] != composite_meta.get("descriptor_file_sha256")
        or manifest["payload_inventory_sha256"]
        != composite_meta.get("payload_inventory_sha256")
        or manifest["sampler_seed"] != rule.get("probe_sampler_seed")
        or manifest["world_size"] != 8
        or manifest["local_batch_size"] != rule.get("probe_batch_size")
        or manifest["probe_batches"] != rule.get("probe_batches")
        or positions.ndim != 1
        or positions.size != expected_rows
        or np.any(positions < 0)
        or np.any(positions >= len(train_indices))
    ):
        raise SystemExit("A1 AUX GEOMETRY probe-manifest recipe/order drift")
    realized = _a1_central_sample_order_evidence(
        data,
        train_indices=np.asarray(train_indices, dtype=np.int64),
        validation_indices=np.asarray(validation_indices, dtype=np.int64),
        global_order_positions=positions,
        composite_meta=dict(composite_meta),
        expected_sample_dose=expected_rows,
    )
    if (
        manifest["probe_row_order_sha256"] != realized["sample_order_sha256"]
        or manifest["probe_row_order_sha256"] != rule.get("probe_row_order_sha256")
    ):
        raise SystemExit("A1 AUX GEOMETRY physical probe row order drift")
    return manifest, positions


def _tensor_state_mapping_sha256(state: Mapping[str, object]) -> str:
    """Digest exact tensor bytes, names, shapes, and dtypes."""

    digest = hashlib.sha256()
    for name, tensor in sorted(state.items()):
        if not hasattr(tensor, "detach"):
            raise ValueError(f"checkpoint model state contains a non-tensor: {name}")
        value = tensor.detach().cpu().contiguous()
        metadata = json.dumps(
            {
                "name": name,
                "dtype": str(value.dtype),
                "shape": [int(item) for item in value.shape],
            },
            sort_keys=True,
            separators=(",", ":"),
        ).encode("utf-8")
        digest.update(metadata)
        digest.update(b"\0")
        digest.update(value.numpy().tobytes())
        digest.update(b"\0")
    return "sha256:" + digest.hexdigest()


def _a1_model_tensor_state_sha256(model) -> str:
    """Digest exact in-memory model state for validation/no-mutation proof."""

    unwrapped = getattr(model, "module", model)
    return _tensor_state_mapping_sha256(unwrapped.state_dict())


def _checkpoint_model_tensor_state_sha256(path: str | Path) -> str:
    """Recover the exact model-state identity from a durable entity checkpoint."""

    import torch

    resolved = Path(path).expanduser().resolve(strict=True)
    payload = torch.load(resolved, map_location="cpu", weights_only=False)
    state = payload.get("model") if isinstance(payload, dict) else None
    if not isinstance(state, Mapping) or not state:
        raise ValueError("checkpoint does not contain a model tensor mapping")
    return _tensor_state_mapping_sha256(state)


def _epoch_order(
    rng: np.random.Generator,
    n: int,
    batch_size: int,
    ddp: dict[str, int | bool],
    *,
    data_sharded: bool = False,
    sample_weights: np.ndarray | None = None,
    max_samples: int | None = None,
    global_order_observer=None,
) -> np.ndarray:
    """Per-epoch traversal order over ``train_indices`` positions ``0..n-1``.

    Default (``sample_weights=None``): a uniform ``rng.permutation`` -- every
    row visited exactly once per epoch, byte-identical to pre-CAT-45 behaviour.
    This is NOT merely "uniform weights passed through the weighted path" --
    ``rng.choice`` and ``rng.permutation`` consume a NumPy bit generator's
    stream differently even when the distribution is uniform, so taking that
    shortcut would silently change existing seeded runs' reproducibility.
    Callers MUST pass ``sample_weights=None`` (not an all-ones array) to get
    today's exact behaviour.

    CAT-45 weighted path (``sample_weights`` given, length ``n``, aligned to
    ``train_indices`` positions): draws ``n`` positions WITH replacement,
    probability proportional to ``sample_weights`` -- a KataGo-style weighted
    sampler (oversampling), matching torch's ``WeightedRandomSampler``
    convention. This changes SAMPLING FREQUENCY (how often a row is drawn per
    epoch), which is orthogonal to -- and composes multiplicatively in effect
    with -- ``policy_sample_weights``/``value_sample_weights`` (which scale the
    LOSS magnitude of whichever row was drawn); see the CAT-45 call site for the
    explicit non-combination-rule with those. If a future ticket also wants to
    change epoch sampling frequency (not loss weight), it must combine its
    weights with these explicitly (e.g. multiply then renormalize) rather than
    overwriting this argument.

    ``max_samples`` only bounds the weighted-with-replacement path. Its result
    is byte-identical to the same-length prefix of the historical ``size=n``
    draw for the same RNG state. ``None`` and values >= ``n`` retain the exact
    historical call. The permutation path intentionally ignores the bound.
    """
    if sample_weights is None:
        order = rng.permutation(n)
    else:
        weights = np.asarray(sample_weights, dtype=np.float64)
        if weights.shape[0] != n:
            raise ValueError(
                f"sample_weights length {weights.shape[0]} != train_indices length {n}"
            )
        total = float(weights.sum())
        if total <= 0.0:
            raise ValueError("sample_weights must sum to a positive value")
        draw_count = n
        if max_samples is not None:
            if int(max_samples) < 0:
                raise ValueError("max_samples must be non-negative")
            draw_count = min(n, int(max_samples))
        order = rng.choice(n, size=draw_count, replace=True, p=weights / total)
    if global_order_observer is not None:
        global_order_observer(np.asarray(order, dtype=np.int64))
    if not ddp["enabled"]:
        return order
    if data_sharded:
        local_order_size = len(order) if max_samples is not None else n
        total_size = int(
            np.ceil(
                _distributed_scalar_max(float(local_order_size), ddp)
                / max(1, int(batch_size))
            )
            * max(1, int(batch_size))
        )
        if total_size > len(order):
            pad = np.resize(order, total_size - len(order))
            order = np.concatenate((order, pad), axis=0)
        return order
    world_size = int(ddp["world_size"])
    rank = int(ddp["rank"])
    global_batch = max(1, int(batch_size)) * world_size
    total_size = int(np.ceil(len(order) / global_batch) * global_batch)
    if total_size > len(order):
        pad = np.resize(order, total_size - len(order))
        order = np.concatenate((order, pad), axis=0)
    return order[rank:total_size:world_size]


def _reduce_epoch_metrics(
    loss_sum: float,
    acc_sum: float,
    top3_sum: float,
    count: float,
    ddp: dict[str, int | bool],
) -> tuple[float, float, float, float]:
    if not ddp["enabled"]:
        return loss_sum, acc_sum, top3_sum, count
    import torch
    import torch.distributed as dist

    values = torch.tensor(
        [loss_sum, acc_sum, top3_sum, count],
        dtype=torch.float64,
        device=f"cuda:{int(ddp['local_rank'])}",
    )
    dist.all_reduce(values, op=dist.ReduceOp.SUM)
    return (
        float(values[0].item()),
        float(values[1].item()),
        float(values[2].item()),
        float(values[3].item()),
    )


def _training_draw_accounting(metrics: list[dict]) -> dict[str, int | str | None]:
    """Report optimizer row draw events without calling them unique examples.

    ``metrics[*].samples`` is the DDP-reduced base sampler dose. Composite
    sampling is with replacement (and DDP padding can also repeat positions),
    so this is not a unique-row count. Policy-auxiliary batches are additional
    row draws consumed by the same optimizer steps and were historically absent
    from ``training_row_draws``. Keep that field's established base-dose meaning
    for contract compatibility while exposing the complete accounting.
    """
    base = sum(int(metric.get("samples", 0)) for metric in metrics)
    policy_aux = sum(
        int(metric.get("policy_aux_active_rows", 0)) for metric in metrics
    )
    policy_base = sum(
        int(metric.get("policy_base_active_rows", 0)) for metric in metrics
    )
    value_active = sum(
        int(metric.get("value_active_rows", 0)) for metric in metrics
    )
    return {
        "training_row_draws": int(base),
        "training_row_draws_semantics": (
            "base_sampler_draw_events; may repeat rows; excludes_policy_aux"
        ),
        "base_training_row_draws": int(base),
        "policy_aux_training_row_draws": int(policy_aux),
        "policy_base_active_training_row_draws": int(policy_base),
        "policy_active_training_row_draws": int(policy_base + policy_aux),
        "value_active_training_row_draws": int(value_active),
        "total_training_row_draws": int(base + policy_aux),
        "unique_training_rows_drawn": None,
    }


def _value_independent_evidence_report(
    data: object,
    train_indices: np.ndarray,
    value_sample_weights: np.ndarray,
) -> dict[str, object]:
    """Separate value-row exposure from independent terminal outcomes.

    Every state in one completed game inherits the same terminal result. Row
    counts therefore exaggerate the amount of independent value supervision by
    roughly the number of recorded decisions per game. Report both the raw
    state labels and their game-level effective sample size.
    """

    rows = np.asarray(train_indices, dtype=np.int64)
    weights = np.asarray(value_sample_weights, dtype=np.float64)
    if rows.ndim != 1 or weights.ndim != 1 or np.any(rows < 0):
        raise ValueError("value evidence accounting inputs are malformed")
    if len(rows) == 0:
        return {
            "schema_version": "value-independent-evidence-v2",
            "status": "empty_training_partition",
        }
    if "game_seed" not in data or "winner" not in data:
        return {
            "schema_version": "value-independent-evidence-v2",
            "status": "unavailable_missing_game_seed_or_winner",
            "training_rows": int(len(rows)),
        }
    if np.any(rows >= len(weights)):
        raise ValueError("value evidence rows exceed the weight array")

    game_identities = _component_game_identities(data, rows)
    winners = np.asarray(data["winner"][rows]).astype(str, copy=False).reshape(-1)
    truncated = _batch_array_or_fill(
        data, "truncated", rows, False, dtype=np.bool_
    )
    row_weights = weights[rows]
    if (
        game_identities.shape != rows.shape
        or winners.shape != rows.shape
        or truncated.shape != rows.shape
        or row_weights.shape != rows.shape
        or not np.isfinite(row_weights).all()
        or np.any(row_weights < 0.0)
    ):
        raise ValueError("value evidence columns are not row-aligned")

    clean = (row_weights > 0.0) & (winners != "") & ~truncated
    if not np.any(clean):
        return {
            "schema_version": "value-independent-evidence-v2",
            "status": "no_clean_terminal_value_rows",
            "training_rows": int(len(rows)),
            "positive_value_weight_rows": int(np.count_nonzero(row_weights > 0.0)),
        }

    clean_identities = game_identities[clean]
    clean_winners = winners[clean]
    clean_weights = row_weights[clean]
    unique_games, first, inverse = np.unique(
        clean_identities, return_index=True, return_inverse=True
    )
    game_rows = np.bincount(inverse, minlength=len(unique_games)).astype(np.int64)
    game_mass = np.bincount(
        inverse, weights=clean_weights, minlength=len(unique_games)
    ).astype(np.float64)
    winner_mismatch = clean_winners != clean_winners[first[inverse]]
    contradictory_games = int(
        np.count_nonzero(
            np.bincount(
                inverse,
                weights=winner_mismatch.astype(np.int64),
                minlength=len(unique_games),
            )
            > 0
        )
    )
    mass_sum = float(game_mass.sum())
    mass_square_sum = float(np.square(game_mass).sum())
    game_ess = (
        mass_sum * mass_sum / mass_square_sum
        if mass_square_sum > 0.0
        else 0.0
    )
    clean_rows = int(np.count_nonzero(clean))
    games = int(len(unique_games))
    return {
        "schema_version": "value-independent-evidence-v2",
        "status": "ok" if contradictory_games == 0 else "contradictory_game_outcomes",
        "training_rows": int(len(rows)),
        "positive_value_weight_rows": int(np.count_nonzero(row_weights > 0.0)),
        "clean_terminal_value_rows": clean_rows,
        "independent_terminal_games": games,
        "game_identity_namespace": (
            "component_id+game_seed"
            if callable(getattr(data, "component_indices_for_rows", None))
            else "game_seed"
        ),
        "row_labels_per_independent_outcome": clean_rows / max(games, 1),
        "repeated_label_fraction": 1.0 - games / max(clean_rows, 1),
        "game_weight_effective_sample_size": float(game_ess),
        "game_weight_ess_fraction": float(game_ess / max(games, 1)),
        "rows_per_game": {
            "mean": float(np.mean(game_rows)),
            "p50": float(np.percentile(game_rows, 50)),
            "p90": float(np.percentile(game_rows, 90)),
            "max": int(np.max(game_rows)),
        },
        "value_weight_mass_per_game": {
            "mean": float(np.mean(game_mass)),
            "p50": float(np.percentile(game_mass, 50)),
            "p90": float(np.percentile(game_mass, 90)),
            "max": float(np.max(game_mass)),
        },
        "contradictory_terminal_outcome_games": contradictory_games,
    }


def _module_optimizer_observability_from_accumulators(
    *,
    observations: int,
    cadence_batches: int,
    norm_scope: str | None,
    grad_norm_sums: dict[str, float],
    grad_norm_max: dict[str, float],
    delta_norm_sums: dict[str, float],
    update_rms_sums: dict[str, float],
    relative_delta_sums: dict[str, float],
    parameter_counts: dict[str, int],
) -> dict[str, object] | None:
    """Materialize one bounded diagnostic prefix from running accumulators."""

    if int(observations) <= 0:
        return None
    count = int(observations)
    return {
        "schema_version": "module-optimizer-observability-v1",
        "observed_steps": count,
        "cadence_batches": int(cadence_batches),
        "norm_scope": norm_scope,
        "modules": {
            module: {
                "mean_pre_clip_grad_norm": grad_norm_sums[module] / count,
                "max_pre_clip_grad_norm": grad_norm_max[module],
                "mean_parameter_delta_norm": (
                    delta_norm_sums.get(module, 0.0) / count
                ),
                "mean_parameter_update_rms": (
                    update_rms_sums.get(module, 0.0) / count
                ),
                "mean_relative_parameter_delta": (
                    relative_delta_sums.get(module, 0.0) / count
                ),
                "parameter_count": int(parameter_counts[module]),
            }
            for module in sorted(grad_norm_sums)
        },
    }


def _aggregate_module_optimizer_observability(
    metrics: list[dict], *, cadence_batches: int
) -> dict[str, object] | None:
    """Merge per-epoch module diagnostics without changing their cadence."""

    observation_count = sum(
        int(
            (metric.get("module_optimizer_observability") or {}).get(
                "observed_steps", 0
            )
        )
        for metric in metrics
    )
    if observation_count <= 0:
        return None
    modules = sorted(
        {
            module
            for metric in metrics
            for module in (
                (metric.get("module_optimizer_observability") or {}).get(
                    "modules", {}
                )
            )
        }
    )
    aggregate: dict[str, object] = {
        "schema_version": "module-optimizer-observability-v1",
        "observed_steps": int(observation_count),
        "cadence_batches": int(cadence_batches),
        "norm_scope": next(
            (
                (metric.get("module_optimizer_observability") or {}).get(
                    "norm_scope"
                )
                for metric in metrics
                if metric.get("module_optimizer_observability")
            ),
            None,
        ),
        "modules": {},
    }
    aggregate_modules = aggregate["modules"]
    assert isinstance(aggregate_modules, dict)
    for module in modules:
        weighted_grad = 0.0
        weighted_delta = 0.0
        weighted_update_rms = 0.0
        weighted_relative_delta = 0.0
        maximum = 0.0
        parameter_count: int | None = None
        for metric in metrics:
            observation = metric.get("module_optimizer_observability") or {}
            count = int(observation.get("observed_steps", 0))
            row = observation.get("modules", {}).get(module)
            if not isinstance(row, dict) or count <= 0:
                continue
            weighted_grad += float(row["mean_pre_clip_grad_norm"]) * count
            weighted_delta += float(row["mean_parameter_delta_norm"]) * count
            weighted_update_rms += float(row["mean_parameter_update_rms"]) * count
            weighted_relative_delta += (
                float(row["mean_relative_parameter_delta"]) * count
            )
            maximum = max(maximum, float(row["max_pre_clip_grad_norm"]))
            observed_parameter_count = int(row["parameter_count"])
            if parameter_count not in {None, observed_parameter_count}:
                raise RuntimeError(
                    "optimizer module parameter count changed across epochs"
                )
            parameter_count = observed_parameter_count
        aggregate_modules[module] = {
            "mean_pre_clip_grad_norm": weighted_grad / observation_count,
            "max_pre_clip_grad_norm": maximum,
            "mean_parameter_delta_norm": weighted_delta / observation_count,
            "mean_parameter_update_rms": weighted_update_rms / observation_count,
            "mean_relative_parameter_delta": (
                weighted_relative_delta / observation_count
            ),
            "parameter_count": parameter_count,
        }
    return aggregate


def _checkpoint_dose_telemetry(
    metrics: list[dict],
    *,
    optimizer_step: int,
    optimizer_observed_steps: int,
    optimizer_clipped_steps: int,
    optimizer_zero_objective_steps: int,
    optimizer_pre_clip_grad_norm_sum: float,
    optimizer_pre_clip_grad_norm_max: float,
    objective_gradient_cadence_batches: int,
    train_diagnostic_cadence_batches: int,
    public_card_enabled: bool,
    meaningful_history_enabled: bool,
    v7_compatibility_inputs_enabled: bool = False,
) -> dict[str, object]:
    """Build the exact cumulative learning dose at one saved checkpoint.

    This consumes telemetry already collected by the learner.  It performs no
    forward/backward pass and is reached only by explicit checkpoint-dose runs.
    """

    denominators: dict[str, float] = {}
    observations: list[dict[str, object]] = []
    policy_aux_coefficients: list[float] = []
    for metric in metrics:
        for name, value in (metric.get("loss_denominators") or {}).items():
            denominators[str(name)] = denominators.get(str(name), 0.0) + float(
                value
            )
        if "policy_aux_loss_coefficient" in metric:
            coefficient = float(metric["policy_aux_loss_coefficient"])
            if not math.isfinite(coefficient) or coefficient < 0.0:
                raise RuntimeError(
                    "checkpoint dose has an invalid policy AUX coefficient"
                )
            policy_aux_coefficients.append(coefficient)
        observations.extend(
            observation
            for observation in (
                (metric.get("objective_gradient_interference") or {}).get(
                    "observations", []
                )
            )
            if isinstance(observation, dict)
        )

    active_rows = {
        "policy_base": int(
            sum(int(metric.get("policy_base_active_rows", 0)) for metric in metrics)
        ),
        "policy_aux": int(
            sum(int(metric.get("policy_aux_active_rows", 0)) for metric in metrics)
        ),
        "value": int(
            sum(int(metric.get("value_active_rows", 0)) for metric in metrics)
        ),
        "policy_kl_anchor": int(
            sum(
                int(metric.get("policy_kl_anchor_eligible_rows", 0))
                for metric in metrics
            )
        ),
    }
    policy_aux_unique_source_rows = max(
        (
            int(metric.get("policy_aux_unique_source_rows", 0))
            for metric in metrics
        ),
        default=0,
    )
    active_rows["policy_total"] = (
        active_rows["policy_base"] + active_rows["policy_aux"]
    )
    active_rows["policy_aux_unique_source_rows"] = (
        policy_aux_unique_source_rows
    )
    active_rows["policy_aux_reuse_factor"] = (
        active_rows["policy_aux"] / policy_aux_unique_source_rows
        if policy_aux_unique_source_rows > 0
        else None
    )
    policy_effective = {
        "base": float(
            sum(
                float(metric.get("policy_base_effective_weight_sum", 0.0))
                for metric in metrics
            )
        ),
        "aux": float(
            sum(
                float(metric.get("policy_aux_effective_weight_sum", 0.0))
                for metric in metrics
            )
        ),
    }
    policy_effective["total"] = policy_effective["base"] + policy_effective["aux"]
    for key, expected in (
        ("policy_base_loss", policy_effective["base"]),
        ("policy_aux_loss", policy_effective["aux"]),
    ):
        observed = denominators.get(key)
        if observed is not None and not math.isclose(
            float(observed), expected, rel_tol=1.0e-6, abs_tol=1.0e-6
        ):
            raise RuntimeError(
                "checkpoint dose policy-stream denominator drift: "
                f"{key}={observed}, effective_weight_sum={expected}"
            )
        denominators[key] = expected if observed is None else float(observed)
    denominators["active_policy_loss"] = policy_effective["aux"]
    aux_enabled = bool(
        active_rows["policy_aux"] > 0
        or denominators["policy_aux_loss"] > 0.0
    )
    if aux_enabled:
        if len(policy_aux_coefficients) != len(metrics):
            raise RuntimeError(
                "checkpoint dose policy AUX coefficient is missing from one or "
                "more cumulative metrics"
            )
        first_coefficient = policy_aux_coefficients[0]
        if first_coefficient <= 0.0 or any(
            not math.isclose(
                coefficient,
                first_coefficient,
                rel_tol=0.0,
                abs_tol=0.0,
            )
            for coefficient in policy_aux_coefficients[1:]
        ):
            raise RuntimeError(
                "checkpoint dose policy AUX coefficient changed within one "
                "training trajectory"
            )
        if denominators["policy_aux_loss"] <= 0.0:
            raise RuntimeError(
                "checkpoint dose has AUX draws but no positive AUX objective mass"
            )
        aux_coefficient = first_coefficient
    else:
        if policy_aux_coefficients and any(
            not math.isclose(
                coefficient,
                policy_aux_coefficients[0],
                rel_tol=0.0,
                abs_tol=0.0,
            )
            for coefficient in policy_aux_coefficients[1:]
        ):
            raise RuntimeError(
                "checkpoint dose policy AUX coefficient changed within one "
                "training trajectory"
            )
        aux_coefficient = 0.0
    policy_stream_objective = {
        "schema_version": "train-policy-stream-objective-v1",
        "formula": "base_mean + aux_coefficient * aux_mean",
        "normalization": "independent_weighted_means",
        "base_coefficient": 1.0,
        "aux_enabled": aux_enabled,
        "aux_coefficient": aux_coefficient,
        "base_denominator": float(denominators["policy_base_loss"]),
        "aux_denominator": float(denominators["policy_aux_loss"]),
    }
    for metric in metrics:
        for name, parts in (metric.get("aux_subgoal_loss_parts") or {}).items():
            if isinstance(parts, dict):
                key = f"aux_subgoal.{name}"
                denominators[key] = denominators.get(key, 0.0) + float(
                    parts.get("weight_sum", 0.0)
                )
    module_observability = _aggregate_module_optimizer_observability(
        metrics, cadence_batches=train_diagnostic_cadence_batches
    )
    module_rows = (
        {}
        if module_observability is None
        else module_observability.get("modules", {})
    )
    assert isinstance(module_rows, dict)

    def _feature_path(
        enabled: bool, module_names: tuple[str, ...]
    ) -> dict[str, object]:
        selected = {
            name: module_rows[name] for name in module_names if name in module_rows
        }
        signal_fields = (
            "max_pre_clip_grad_norm",
            "mean_parameter_delta_norm",
            "mean_parameter_update_rms",
        )

        def _has_nonzero_signal(row: object) -> bool:
            if not isinstance(row, dict):
                return False
            for field in signal_fields:
                try:
                    value = float(row.get(field, 0.0))
                except (TypeError, ValueError):
                    continue
                if math.isfinite(value) and value > 0.0:
                    return True
            return False

        nonzero_signal_modules = sorted(
            name
            for name, row in selected.items()
            if _has_nonzero_signal(row)
        )
        zero_signal_modules = sorted(
            name for name in selected if name not in nonzero_signal_modules
        )
        return {
            "enabled": bool(enabled),
            "independent_loss_objective": False,
            "measurement": "total_objective_parameter_path_gradient",
            "status": (
                (
                    "observed_nonzero"
                    if nonzero_signal_modules and not zero_signal_modules
                    else "observed_partial"
                    if nonzero_signal_modules
                    else "observed_zero"
                )
                if selected
                else (
                    "awaiting_diagnostic_cadence"
                    if enabled
                    else "not_configured"
                )
            ),
            "nonzero_signal_modules": nonzero_signal_modules,
            "zero_signal_modules": zero_signal_modules,
            "modules": selected,
        }

    observed_steps = int(optimizer_observed_steps)
    draws = _training_draw_accounting(metrics)
    policy_objective_dose = {
        "active_rows": int(
            sum(
                int(metric.get("policy_objective_active_rows", 0))
                for metric in metrics
            )
        ),
        "equivalent_active_rows": float(
            sum(
                float(
                    metric.get(
                        "policy_objective_equivalent_active_rows",
                        0.0,
                    )
                )
                for metric in metrics
            )
        ),
        "coefficient_weighted_effective_weight_sum": float(
            sum(
                float(
                    metric.get(
                        "policy_objective_effective_weight_sum",
                        0.0,
                    )
                )
                for metric in metrics
            )
        ),
        "equivalent_effective_weight_sum": float(
            sum(
                float(
                    metric.get(
                        "policy_objective_equivalent_effective_weight_sum",
                        0.0,
                    )
                )
                for metric in metrics
            )
        ),
        "optimizer_updates": int(
            sum(
                int(metric.get("policy_objective_optimizer_updates", 0))
                for metric in metrics
            )
        ),
        "equivalent_optimizer_updates": float(
            sum(
                float(
                    metric.get(
                        "policy_objective_equivalent_optimizer_updates",
                        0.0,
                    )
                )
                for metric in metrics
            )
        ),
    }
    return {
        "schema_version": CHECKPOINT_DOSE_TELEMETRY_SCHEMA,
        "optimizer_step": int(optimizer_step),
        "training_row_draws": {
            key: draws[key]
            for key in (
                "base_training_row_draws",
                "policy_aux_training_row_draws",
                "policy_active_training_row_draws",
                "value_active_training_row_draws",
                "total_training_row_draws",
            )
        },
        "active_rows": active_rows,
        "policy_objective_dose": policy_objective_dose,
        "policy_effective_weight_sums": policy_effective,
        "policy_stream_objective": policy_stream_objective,
        "objective_effective_weight_sums": denominators,
        "optimizer": {
            "observed_steps": observed_steps,
            "clipped_steps": int(optimizer_clipped_steps),
            "clipped_fraction": (
                float(optimizer_clipped_steps) / observed_steps
                if observed_steps > 0
                else None
            ),
            "zero_objective_steps_skipped": int(optimizer_zero_objective_steps),
            "mean_pre_clip_total_grad_norm": (
                float(optimizer_pre_clip_grad_norm_sum) / observed_steps
                if observed_steps > 0
                else None
            ),
            "max_pre_clip_total_grad_norm": float(
                optimizer_pre_clip_grad_norm_max
            ),
        },
        "shared_trunk_objective_gradients": {
            "schema_version": "objective-gradient-dose-observations-v2",
            "cadence_batches": int(objective_gradient_cadence_batches),
            "observed_steps": len(observations),
            "observations": observations,
        },
        "module_optimizer_observability": module_observability,
        "feature_path_gradients": {
            "public_card": _feature_path(
                public_card_enabled, ("public_card_count_residual",)
            ),
            "meaningful_history": _feature_path(
                meaningful_history_enabled,
                (
                    "event_encoder",
                    "meaningful_history_residual_gate",
                    "meaningful_history_ordered_gate",
                    "meaningful_history_sequence",
                    "meaningful_history_target_proj",
                ),
            ),
            "v7_compatibility_inputs": _feature_path(
                v7_compatibility_inputs_enabled,
                (
                    "v6_exact_resource_residual",
                    "v6_initial_road_residual",
                ),
            ),
        },
    }


def _reduce_named_sums(
    values_by_name: dict[str, float],
    ddp: dict[str, int | bool],
) -> dict[str, float]:
    if not ddp["enabled"] or not values_by_name:
        return dict(values_by_name)
    import torch
    import torch.distributed as dist

    names = sorted(values_by_name)
    values = torch.tensor(
        [float(values_by_name[name]) for name in names],
        dtype=torch.float64,
        device=f"cuda:{int(ddp['local_rank'])}",
    )
    dist.all_reduce(values, op=dist.ReduceOp.SUM)
    return {name: float(values[index].item()) for index, name in enumerate(names)}


def _reduce_unique_row_count(
    rows: set[int],
    *,
    total_rows: int,
    ddp: dict[str, int | bool],
) -> int:
    """Return the exact global union size for a small sampled row set."""

    if total_rows < 0 or any(row < 0 or row >= total_rows for row in rows):
        raise ValueError("sampled source row lies outside the corpus")
    if not ddp["enabled"]:
        return len(rows)
    import torch
    import torch.distributed as dist

    observed = torch.zeros(
        int(total_rows),
        dtype=torch.uint8,
        device=f"cuda:{int(ddp['local_rank'])}",
    )
    if rows:
        indices = torch.as_tensor(
            sorted(rows),
            dtype=torch.int64,
            device=observed.device,
        )
        observed[indices] = 1
    dist.all_reduce(observed, op=dist.ReduceOp.MAX)
    return int(observed.sum().item())


def _reduce_sparse_named_sums(
    values_by_name: dict[str, float],
    ddp: dict[str, int | bool],
) -> dict[str, float]:
    """Reduce a small sparse map whose observed labels may differ by rank.

    Dynamic phase/decision strata are not guaranteed to appear on every rank's
    finite sample prefix. A dense NCCL vector keyed from each rank's local map
    would therefore misalign or hang. Gather the small telemetry maps as
    objects and merge their union; this path never carries tensor payloads.
    """

    if not ddp["enabled"]:
        return dict(values_by_name)
    import torch.distributed as dist

    gathered: list[dict[str, float] | None] = [None] * int(ddp["world_size"])
    dist.all_gather_object(gathered, dict(values_by_name))
    merged: dict[str, float] = {}
    for record in gathered:
        if not record:
            continue
        for name, value in record.items():
            merged[str(name)] = merged.get(str(name), 0.0) + float(value)
    return merged


def _reduce_scalar_sum(value: float, ddp: dict[str, int | bool]) -> float:
    if not ddp["enabled"]:
        return float(value)
    import torch
    import torch.distributed as dist

    values = torch.tensor(
        [float(value)],
        dtype=torch.float64,
        device=f"cuda:{int(ddp['local_rank'])}",
    )
    dist.all_reduce(values, op=dist.ReduceOp.SUM)
    return float(values[0].item())


POLICY_KL_CONTROLLER_SCHEMA = "adaptive-policy-kl-controller-v2"
POLICY_KL_CONTROLLER_METRIC_SCOPE = (
    "ddp_global_training_sampler_authenticated_stored_prior_multi_action_rows"
)
FUNCTIONAL_PARENT_KL_SELECTION_SCOPE = (
    "frozen_validation_policy_active_multi_action_rows"
)


class AdaptivePolicyKLController:
    """Projected-dual controller for the authenticated stored-prior objective.

    The observed constraint is the exact eligible-row mean used by the
    existing forward-KL loss.  Callers reduce numerator and denominator over
    every DDP rank and every microbatch in one optimizer-step group before
    invoking :meth:`update`, so every rank advances an identical coefficient.

    This is deliberately *not* called a functional parent-KL controller.  Its
    probability measure is the live training sampler, whereas checkpoint
    selection measures parent→candidate KL on one frozen validation anchor.
    Even when the stored-prior checkpoint is the exact causal parent, the two
    means are not interchangeable.
    """

    def __init__(
        self,
        *,
        target_kl: float,
        dual_lr: float,
        max_weight: float,
        coefficient: float,
    ) -> None:
        self.target_kl = float(target_kl)
        self.dual_lr = float(dual_lr)
        self.max_weight = float(max_weight)
        self.coefficient = float(coefficient)
        self.updates = 0
        self.skipped_empty_updates = 0
        self.eligible_rows = 0
        self.observed_kl_sum = 0.0
        self.last_observed_kl: float | None = None
        self.min_coefficient = float(coefficient)
        self.max_coefficient_observed = float(coefficient)
        scalars = {
            "target_kl": self.target_kl,
            "dual_lr": self.dual_lr,
            "max_weight": self.max_weight,
            "coefficient": self.coefficient,
        }
        if any(not math.isfinite(float(value)) for value in scalars.values()):
            raise ValueError(f"policy-KL controller values must be finite: {scalars}")
        if self.target_kl < 0.0:
            raise ValueError("policy-KL target must be >= 0")
        if self.dual_lr <= 0.0:
            raise ValueError("policy-KL dual LR must be > 0")
        if self.max_weight <= 0.0:
            raise ValueError("policy-KL max weight must be > 0")
        if not 0.0 <= self.coefficient <= self.max_weight:
            raise ValueError(
                "initial policy-KL anchor weight must be in [0, max_weight]"
            )

    def update(self, *, global_kl_sum: float, global_eligible_rows: float) -> dict:
        numerator = float(global_kl_sum)
        denominator = float(global_eligible_rows)
        if not math.isfinite(numerator) or not math.isfinite(denominator):
            raise RuntimeError("policy-KL controller received non-finite global parts")
        if numerator < -1.0e-8 or denominator < 0.0:
            raise RuntimeError("policy-KL controller received negative global parts")
        before = float(self.coefficient)
        if denominator <= 0.0:
            self.skipped_empty_updates += 1
            return {
                "updated": False,
                "global_eligible_rows": 0,
                "observed_kl": None,
                "coefficient_before": before,
                "coefficient_after": before,
            }
        observed = max(0.0, numerator) / denominator
        after = min(
            float(self.max_weight),
            max(0.0, before + float(self.dual_lr) * (observed - self.target_kl)),
        )
        self.coefficient = after
        self.updates += 1
        rows = int(round(denominator))
        self.eligible_rows += rows
        self.observed_kl_sum += max(0.0, numerator)
        self.last_observed_kl = observed
        self.min_coefficient = min(float(self.min_coefficient), after)
        self.max_coefficient_observed = max(
            float(self.max_coefficient_observed), after
        )
        return {
            "updated": True,
            "global_eligible_rows": rows,
            "observed_kl": observed,
            "target_kl": float(self.target_kl),
            "coefficient_before": before,
            "coefficient_after": after,
        }

    def state_dict(self) -> dict[str, object]:
        return {
            "schema_version": POLICY_KL_CONTROLLER_SCHEMA,
            "direction": "forward",
            "update_rule": (
                "clip(lambda+dual_lr*(global_eligible_mean_kl-target_kl),"
                "0,max_weight)"
            ),
            "metric_scope": POLICY_KL_CONTROLLER_METRIC_SCOPE,
            "functional_parent_kl_authority": "none_measure_mismatch",
            "promotion_claim_authority": False,
            "target_kl": float(self.target_kl),
            "dual_lr": float(self.dual_lr),
            "max_weight": float(self.max_weight),
            "coefficient": float(self.coefficient),
            "updates": int(self.updates),
            "skipped_empty_updates": int(self.skipped_empty_updates),
            "eligible_rows": int(self.eligible_rows),
            "observed_kl_sum": float(self.observed_kl_sum),
            "observed_kl_mean": (
                float(self.observed_kl_sum) / int(self.eligible_rows)
                if self.eligible_rows > 0
                else None
            ),
            "last_observed_kl": self.last_observed_kl,
            "min_coefficient": float(self.min_coefficient),
            "max_coefficient_observed": float(self.max_coefficient_observed),
        }

    def restore(self, raw: object) -> None:
        if not isinstance(raw, dict):
            raise SystemExit(
                "adaptive policy-KL optimizer resume lacks controller state"
            )
        immutable = {
            "schema_version": POLICY_KL_CONTROLLER_SCHEMA,
            "direction": "forward",
            "update_rule": (
                "clip(lambda+dual_lr*(global_eligible_mean_kl-target_kl),"
                "0,max_weight)"
            ),
            "metric_scope": POLICY_KL_CONTROLLER_METRIC_SCOPE,
            "target_kl": float(self.target_kl),
            "dual_lr": float(self.dual_lr),
            "max_weight": float(self.max_weight),
        }
        if any(raw.get(key) != value for key, value in immutable.items()):
            raise SystemExit(
                "resumed adaptive policy-KL controller config differs from command"
            )
        try:
            integer_fields = {
                name: raw[name]
                for name in (
                    "updates",
                    "skipped_empty_updates",
                    "eligible_rows",
                )
            }
            if any(
                isinstance(value, bool) or not isinstance(value, int)
                for value in integer_fields.values()
            ):
                raise TypeError("controller counters must be exact integers")
            coefficient = float(raw["coefficient"])
            updates = int(integer_fields["updates"])
            skipped = int(integer_fields["skipped_empty_updates"])
            eligible_rows = int(integer_fields["eligible_rows"])
            observed_sum = float(raw["observed_kl_sum"])
            last = raw.get("last_observed_kl")
            last_observed = None if last is None else float(last)
            minimum = float(raw["min_coefficient"])
            maximum = float(raw["max_coefficient_observed"])
        except (KeyError, TypeError, ValueError) as error:
            raise SystemExit(
                "resumed adaptive policy-KL controller state is malformed"
            ) from error
        numeric = (coefficient, observed_sum, minimum, maximum)
        if last_observed is not None:
            numeric = (*numeric, last_observed)
        if (
            any(not math.isfinite(value) for value in numeric)
            or not 0.0 <= coefficient <= self.max_weight
            or updates < 0
            or skipped < 0
            or eligible_rows < 0
            or observed_sum < 0.0
            or not 0.0 <= minimum <= maximum <= self.max_weight
            or not minimum <= coefficient <= maximum
            or (last_observed is not None and last_observed < 0.0)
            or (updates == 0 and eligible_rows != 0)
            or (updates == 0 and observed_sum != 0.0)
            or (updates == 0 and last_observed is not None)
            or (updates > 0 and eligible_rows < updates)
            or (updates > 0 and last_observed is None)
        ):
            raise SystemExit(
                "resumed adaptive policy-KL controller state is out of bounds"
            )
        self.coefficient = coefficient
        self.updates = updates
        self.skipped_empty_updates = skipped
        self.eligible_rows = eligible_rows
        self.observed_kl_sum = observed_sum
        self.last_observed_kl = last_observed
        self.min_coefficient = minimum
        self.max_coefficient_observed = maximum


def _adaptive_policy_kl_controller(
    args: argparse.Namespace,
    *,
    resume_progress: dict[str, object] | None,
) -> AdaptivePolicyKLController | None:
    target = getattr(args, "policy_kl_target", None)
    if target is None:
        if resume_progress is not None and resume_progress.get(
            "policy_kl_controller_state"
        ) is not None:
            raise SystemExit(
                "resumed checkpoint carries adaptive policy-KL state but the "
                "current command omits --policy-kl-target"
            )
        return None
    controller = AdaptivePolicyKLController(
        target_kl=float(target),
        dual_lr=float(args.policy_kl_dual_lr),
        max_weight=float(args.policy_kl_max_weight),
        coefficient=float(args.policy_kl_anchor_weight),
    )
    if resume_progress is not None:
        controller.restore(resume_progress.get("policy_kl_controller_state"))
    return controller


def _validate_adaptive_policy_kl_args(args: argparse.Namespace) -> None:
    target = getattr(args, "policy_kl_target", None)
    if target is None:
        return
    if str(args.policy_kl_anchor_direction) != "forward":
        raise SystemExit(
            "--policy-kl-target requires --policy-kl-anchor-direction forward"
        )
    try:
        AdaptivePolicyKLController(
            target_kl=float(target),
            dual_lr=float(args.policy_kl_dual_lr),
            max_weight=float(args.policy_kl_max_weight),
            coefficient=float(args.policy_kl_anchor_weight),
        )
    except (TypeError, ValueError) as error:
        raise SystemExit(f"invalid adaptive policy-KL controller: {error}") from error


def _global_policy_kl_controller_parts(
    local_sum: float,
    local_eligible_rows: float,
    ddp: dict[str, int | bool],
) -> tuple[float, float]:
    reduced = _reduce_named_sums(
        {
            "kl_sum": float(local_sum),
            "eligible_rows": float(local_eligible_rows),
        },
        ddp,
    )
    return float(reduced["kl_sum"]), float(reduced["eligible_rows"])


def _policy_kl_controller_surface(
    surface: dict[str, object] | None,
    controller: AdaptivePolicyKLController | None,
) -> dict[str, object] | None:
    if controller is None:
        return surface
    return {
        **(surface or {}),
        "adaptive_stored_prior_policy_kl": controller.state_dict(),
    }


def _apply_adaptive_policy_kl_promotion_guard(
    report: dict[str, object],
    controller: AdaptivePolicyKLController | None,
) -> None:
    """Prevent a training-sampler KL controller from certifying promotion.

    The functional dose selector evaluates the exact parent and candidate on a
    frozen validation anchor.  The online controller instead observes
    authenticated stored-prior probabilities under the live training sampler.
    Those distributions can differ sharply under active/surprise sampling, so
    a numerically satisfied controller target is not evidence that the frozen
    functional parent-KL cap was satisfied.

    Until the online controller is driven by the exact same immutable anchor
    identity and weighting measure as selection, any run that enables it is an
    ablation: useful for learning whether adaptive regularization helps, but
    never directly promotion eligible.
    """

    if controller is None:
        return
    report["diagnostic_only"] = True
    report["promotion_eligible"] = False
    report["adaptive_policy_kl_claim_authority"] = {
        "schema_version": "adaptive-policy-kl-claim-authority-v1",
        "status": "diagnostic_only_measure_mismatch",
        "controller_metric_scope": POLICY_KL_CONTROLLER_METRIC_SCOPE,
        "selection_metric_scope": FUNCTIONAL_PARENT_KL_SELECTION_SCOPE,
        "controller_target_does_not_certify_functional_parent_kl": True,
        "promotion_eligible": False,
        "required_implementation_before_promotion": [
            "bind_one_immutable_balanced_anchor_identity_into_the_training_contract",
            "evaluate_exact_parent_and_live_candidate_logits_on_that_anchor",
            "update_the_dual_controller_from_anchor_parent_to_candidate_forward_kl",
            "bind_checkpoint_selection_to_the_same_anchor_identity_and_weights",
        ],
    }


def _distributed_scalar_max(value: float, ddp: dict[str, int | bool]) -> float:
    if not ddp["enabled"]:
        return float(value)
    import torch
    import torch.distributed as dist

    values = torch.tensor(
        [float(value)],
        dtype=torch.float64,
        device=f"cuda:{int(ddp['local_rank'])}",
    )
    dist.all_reduce(values, op=dist.ReduceOp.MAX)
    return float(values[0].item())


def _rank0_print(message: str, ddp: dict[str, int | bool]) -> None:
    if int(ddp["rank"]) == 0:
        print(message, flush=True)




def _training_resume_recipe_identity(
    train_config: TrainConfig,
    args: argparse.Namespace,
    ddp: dict[str, int | bool],
) -> dict[str, object]:
    """Stable identity of the trajectory whose Adam/schedule state may continue.

    ``init_checkpoint`` necessarily changes from the original parent to the checkpoint
    being resumed, so it is normalized out. ``grow_from_checkpoint`` is normalized for
    the same reason: after the first grown checkpoint is saved, continuation must use
    the mutually-exclusive ``--init-checkpoint`` path rather than grow the architecture
    a second time. Everything else in the typed science config remains bound, augmented
    with optimizer-step topology and live science/admission fields that have not yet
    migrated into ``TrainConfig``. This intentionally rejects changing max_steps,
    warmup/decay, loss recipe, corpus, batch geometry, optimizer parameter-group rates,
    sampling, architecture inputs, or terminal admission while reusing moments.
    """
    normalized = dataclasses.replace(
        train_config,
        init_checkpoint="",
        init_checkpoint_sha256="",
        grow_from_checkpoint="",
        grow_from_checkpoint_sha256="",
        resume_optimizer=True,
    )
    arch = str(getattr(args, "arch", getattr(train_config, "arch", "")) or "")
    requested_adapter = getattr(args, "entity_feature_adapter_version", None)
    init_checkpoint = str(
        getattr(args, "init_checkpoint", "")
        or getattr(train_config, "init_checkpoint", "")
        or ""
    )
    if arch != "entity_graph":
        resume_entity_adapter = ""
    elif requested_adapter is not None:
        resume_entity_adapter = require_known_entity_feature_adapter(
            requested_adapter
        )
    elif init_checkpoint and Path(init_checkpoint).is_file():
        # Init resumes inherit the checkpoint's append-only adapter contract.
        # Do not infer v2/v3 from the same false public-feature flags.
        resume_entity_adapter = _checkpoint_entity_feature_adapter_version(
            str(
                getattr(
                    args,
                    "authenticated_init_checkpoint_load_path",
                    init_checkpoint,
                )
            )
        )
    elif (
        bool(getattr(args, "public_rule_state_features", False))
        and bool(getattr(args, "meaningful_public_history", False))
        and int(getattr(args, "event_history_limit", 0) or 0) == 64
    ):
        # Resolved checkpoint-owned v5 semantics remain identifiable even when
        # the continuation command inherits the adapter rather than spelling it.
        resume_entity_adapter = RUST_ENTITY_ADAPTER_V5
    elif bool(getattr(args, "public_rule_state_features", False)):
        resume_entity_adapter = RUST_ENTITY_ADAPTER_V4
    else:
        resume_entity_adapter = CURRENT_RUST_ENTITY_ADAPTER_VERSION
    resume_history_schema = (
        _history_schema_for_entity_adapter(resume_entity_adapter)
        if resume_entity_adapter
        else ""
    )
    runtime_binding = getattr(args, "checkout_runtime_binding", None)
    runtime_modules = (
        runtime_binding.get("modules")
        if isinstance(runtime_binding, dict)
        else None
    )
    runtime_code_identity = {
        "schema_version": CHECKOUT_RUNTIME_BINDING_SCHEMA,
        "trainer_sha256": (
            str(runtime_binding.get("trainer_sha256", ""))
            if isinstance(runtime_binding, dict)
            else ""
        ),
        "modules": {
            str(name): str(record.get("sha256", ""))
            for name, record in sorted(
                runtime_modules.items() if isinstance(runtime_modules, dict) else ()
            )
            if isinstance(record, dict)
        },
    }
    runtime_code_sha256 = "sha256:" + hashlib.sha256(
        json.dumps(
            runtime_code_identity, sort_keys=True, separators=(",", ":")
        ).encode("utf-8")
    ).hexdigest()
    requested_matmul_precision = getattr(
        args, "float32_matmul_precision", None
    )
    if requested_matmul_precision is not None:
        effective_matmul_precision = str(requested_matmul_precision)
    elif str(getattr(args, "amp", "none")) == "bf16":
        effective_matmul_precision = "high"
    else:
        import torch

        effective_matmul_precision = str(
            torch.get_float32_matmul_precision()
        )
    identity: dict[str, object] = {
        "schema_version": "train-bc-resume-recipe-v1",
        "normalized_train_config_sha256": normalized.full_config_hash(),
        "checkout_runtime_code_sha256": runtime_code_sha256,
        "float32_matmul_precision": effective_matmul_precision,
        "grad_accum_steps": int(args.grad_accum_steps),
        "world_size": int(ddp["world_size"]),
        "ddp_shard_data": bool(args.ddp_shard_data),
        "policy_aux_active_batch_size": int(args.policy_aux_active_batch_size),
        "policy_dose_lr_area": float(
            getattr(args, "policy_dose_lr_area", 0.0)
        ),
        "policy_dose_reference_global_batch_size": int(
            getattr(args, "policy_dose_reference_global_batch_size", 0)
        ),
        # These live CLI fields alter the optimizer trajectory, model input, or
        # terminal checkpoint admission but are not yet represented by TrainConfig.
        # Keep them explicit here so progress saved under one interpretation cannot
        # restore Adam/RNG/LR state under another.
        "public_card_lr_mult": float(
            getattr(args, "public_card_lr_mult", 1.0)
        ),
        "scalar_value_objective": str(
            getattr(args, "scalar_value_objective", "mse")
        ),
        "scalar_value_loss_readout": str(
            getattr(args, "scalar_value_loss_readout", "raw")
        ),
        "scalar_value_loss_scale": float(
            getattr(args, "scalar_value_loss_scale", 1.0)
        ),
        "value_player_outcome_balance_mode": str(
            getattr(args, "value_player_outcome_balance_mode", "none")
        ),
        "base_sampler": str(
            getattr(args, "base_sampler", BASE_SAMPLER_WEIGHTED_REPLACEMENT_V1)
        ),
        "minimum_policy_effective_rows_per_global_batch": float(
            getattr(args, "minimum_policy_effective_rows_per_global_batch", 0.0)
        ),
        "minimum_initial_settlement_policy_mass_fraction": getattr(
            args, "minimum_initial_settlement_policy_mass_fraction", None
        ),
        "minimum_initial_road_policy_mass_fraction": getattr(
            args, "minimum_initial_road_policy_mass_fraction", None
        ),
        "minimum_discard_policy_mass_fraction": getattr(
            args, "minimum_discard_policy_mass_fraction", None
        ),
        "minimum_move_robber_policy_mass_fraction": getattr(
            args, "minimum_move_robber_policy_mass_fraction", None
        ),
        "entity_feature_adapter_version": resume_entity_adapter,
        "public_rule_state_features": bool(
            getattr(args, "public_rule_state_features", False)
        ),
        "topology_residual_adapter": bool(
            getattr(args, "topology_residual_adapter", False)
        ),
        "action_cross_attention_layers": int(
            getattr(args, "action_cross_attention_layers", 0) or 0
        ),
        "value_tower_split_layers": int(
            getattr(args, "value_tower_split_layers", 0) or 0
        ),
        "meaningful_public_history": bool(
            getattr(args, "meaningful_public_history", False)
        ),
        "meaningful_public_history_schema": str(resume_history_schema),
        "event_history_limit": int(
            getattr(args, "event_history_limit", 64) or 0
        ),
        "meaningful_public_history_pooling": str(
            getattr(args, "meaningful_public_history_pooling", MASKED_MEAN_V1)
            or MASKED_MEAN_V1
        ),
        "meaningful_public_history_target_gather": bool(
            getattr(args, "meaningful_public_history_target_gather", False)
        ),
        "require_feature_learning_signal_modules": ",".join(
            sorted(
                {
                    token.strip()
                    for token in str(
                        getattr(
                            args, "require_feature_learning_signal_modules", ""
                        )
                        or ""
                    ).split(",")
                    if token.strip()
                }
            )
        ),
        "minimum_feature_learning_signal_observations": int(
            getattr(args, "minimum_feature_learning_signal_observations", 0)
        ),
        "train_diagnostics_every_batches": int(
            getattr(args, "train_diagnostics_every_batches", 0)
        ),
        "objective_gradient_interference_every_batches": int(
            getattr(args, "objective_gradient_interference_every_batches", 0)
        ),
        "require_only_trainable_prefixes": ",".join(
            sorted(
                {
                    token.strip()
                    for token in str(
                        getattr(args, "require_only_trainable_prefixes", "") or ""
                    ).split(",")
                    if token.strip()
                }
            )
        ),
        "accepted_policy_target_identity_sha256": sorted(
            {
                str(value)
                for value in (
                    getattr(args, "accepted_policy_target_identity_sha256", [])
                    or []
                )
            }
        ),
    }
    if getattr(args, "sampler_seed", None) is not None:
        # Omitted is the historical identity: the typed TrainConfig already
        # binds --seed, and the sampler inherited it. Only the new decoupled
        # trajectory needs additive identity fields, preserving old resumes.
        identity.update(
            {
                "model_and_torch_seed": int(args.seed),
                "sampler_seed": _resolved_sampler_seed(args),
                "sampler_seed_explicit": True,
            }
        )
    return identity


def _restore_training_progress_state(
    progress: dict[str, object] | None,
    *,
    epochs: int,
    rng,
    symmetry_rng,
    ddp: dict[str, int | bool],
    require_policy_objective_lr_area: bool = False,
) -> tuple[int, int, float, float, float]:
    """Restore schedule/dose counters and sampler RNG from validated progress."""
    if progress is None:
        return 0, 0, 0.0, 0.0, 0.0
    global_step = int(progress["optimizer_step"])
    completed_epochs = int(progress["completed_epochs"])
    if completed_epochs > int(epochs):
        raise SystemExit(
            f"resumed completed_epochs={completed_epochs} exceeds --epochs={epochs}"
        )
    rank_numpy_rng_states = progress.get("rank_numpy_rng_states")
    if isinstance(rank_numpy_rng_states, list):
        if len(rank_numpy_rng_states) != int(ddp["world_size"]):
            raise SystemExit(
                "resumed checkpoint lacks matching per-rank numpy RNG state"
            )
        rng.bit_generator.state = rank_numpy_rng_states[int(ddp["rank"])]
    else:
        # Legacy progress stored only rank 0's sampler state. That is exact when
        # every rank traverses the same global corpus/order, but not when each
        # rank owns a different shard and can advance NumPy by a different
        # amount. Fail closed instead of silently changing the resumed order.
        recipe_identity = progress.get("recipe_identity", {})
        sharded = bool(
            recipe_identity.get("ddp_shard_data", False)
            if isinstance(recipe_identity, dict)
            else False
        )
        if sharded and int(ddp["world_size"]) > 1:
            raise SystemExit(
                "legacy sharded-DDP checkpoint lacks per-rank numpy RNG state"
            )
        rng.bit_generator.state = progress["rng_state"]
    saved_symmetry_state = progress.get("symmetry_rng_state")
    if symmetry_rng is not None:
        if not isinstance(saved_symmetry_state, dict):
            raise SystemExit(
                "resumed symmetry-augmentation recipe lacks symmetry RNG state"
            )
        symmetry_rng.bit_generator.state = saved_symmetry_state
    elif saved_symmetry_state is not None:
        raise SystemExit(
            "training progress has symmetry RNG state but current recipe disables it"
        )
    if require_policy_objective_lr_area and "policy_objective_lr_area" not in progress:
        raise SystemExit(
            "resumed policy-dose run lacks consumed policy LR-area progress"
        )
    policy_objective_lr_area = float(
        progress.get("policy_objective_lr_area", 0.0)
    )
    if (
        not math.isfinite(policy_objective_lr_area)
        or policy_objective_lr_area < 0.0
    ):
        raise SystemExit("resumed checkpoint has invalid policy LR-area progress")
    rank_rng_states = progress.get("rank_torch_rng_states")
    if not isinstance(rank_rng_states, list) or len(rank_rng_states) != int(
        ddp["world_size"]
    ):
        raise SystemExit("resumed checkpoint lacks matching per-rank torch RNG state")
    rank_rng = rank_rng_states[int(ddp["rank"])]
    import torch

    torch.set_rng_state(torch.tensor(rank_rng["cpu"], dtype=torch.uint8))
    if rank_rng.get("cuda") is not None:
        if not torch.cuda.is_available():
            raise SystemExit("resumed checkpoint requires CUDA RNG state on a CPU run")
        torch.cuda.set_rng_state(
            torch.tensor(rank_rng["cuda"], dtype=torch.uint8),
            device=int(ddp["local_rank"]),
        )
    return (
        global_step,
        completed_epochs,
        float(progress["scalar_training_weight_sum"]),
        float(progress["categorical_training_weight_sum"]),
        policy_objective_lr_area,
    )


def _restore_policy_aux_global_draw_offset(
    progress: dict[str, object] | None,
    *,
    required: bool,
) -> int:
    """Restore the exact position in the weighted AUX global draw stream.

    Epoch numbers cannot reconstruct this position because a capped final epoch
    can consume fewer draws than earlier epochs. Weighted-cycle resumes therefore
    require the cumulative draw offset committed with the optimizer checkpoint.
    """

    if progress is None:
        return 0
    if required and "policy_aux_global_draw_offset" not in progress:
        raise SystemExit(
            "resumed weighted-cycle policy AUX run lacks cumulative global draw "
            "offset"
        )
    value = progress.get("policy_aux_global_draw_offset", 0)
    if isinstance(value, bool) or not isinstance(value, int) or value < 0:
        raise SystemExit(
            "resumed checkpoint has invalid policy AUX global draw offset"
        )
    return int(value)


def _advance_policy_aux_global_draw_offset(
    offset: int,
    *,
    local_draws: int,
    ddp: Mapping[str, int | bool],
) -> int:
    """Advance one rank-strided AUX stream by draws consumed on every rank."""

    start = int(offset)
    draws = int(local_draws)
    if start < 0 or draws < 0:
        raise ValueError("policy AUX global draw offset/count must be non-negative")
    world = int(ddp["world_size"]) if ddp.get("enabled", False) else 1
    if world <= 0:
        raise ValueError("policy AUX world size must be positive")
    return start + draws * world


def _policy_aux_stream_slice_contract(
    *,
    global_draw_offset: int,
    global_draws: int,
    eligible_rows: int,
) -> dict[str, int | bool]:
    """Coverage/reuse bounds for one possibly resumed weighted-cycle slice."""

    start = int(global_draw_offset)
    draws = int(global_draws)
    cycle_size = int(eligible_rows)
    if start < 0 or draws < 0 or cycle_size <= 0:
        raise ValueError("invalid weighted policy AUX stream slice")
    end = start + draws
    maximum_reuse = (
        0
        if draws == 0
        else int(math.ceil(((start % cycle_size) + draws) / cycle_size))
    )
    first_complete_cycle_start = (
        (start + cycle_size - 1) // cycle_size
    ) * cycle_size
    return {
        "global_draw_start": start,
        "global_draw_end": end,
        "maximum_source_row_reuse": maximum_reuse,
        "contains_complete_cycle": (
            first_complete_cycle_start + cycle_size <= end
        ),
    }


def _save_optimizer_sidecar(checkpoint_path: str, policy, optimizer, ddp: dict):
    """CAT-128 patch #8 wrapper: persist optimizer (Adam) state as
    ``<checkpoint_path>.optimizer.pt`` via the shared DDP-safe util. The util
    rank-guards the write and is fail-soft (a save error logs and does not crash
    the run)."""
    from catan_zero.rl.optim_state import save_optimizer_state

    return save_optimizer_state(checkpoint_path, policy.model, optimizer, ddp)


def _require_shared_symmetry_rng_state(
    states: list[object],
) -> dict[str, object] | None:
    """Prove every DDP rank consumed the shared symmetry stream equally."""

    if not states:
        raise RuntimeError("symmetry RNG state gather returned no ranks")
    if all(state is None for state in states):
        return None
    if any(not isinstance(state, dict) for state in states):
        raise RuntimeError(
            "distributed symmetry RNG state is enabled on only part of the ranks"
        )
    identities = [
        _canonical_json_sha256(_rng_json_value(state)) for state in states
    ]
    if len(set(identities)) != 1:
        raise RuntimeError(
            "distributed symmetry RNG streams diverged across ranks; refusing "
            "a falsely resumable checkpoint"
        )
    return copy.deepcopy(states[0])


def _save_training_progress_sidecar(
    checkpoint_path: str,
    *,
    optimizer_saved,
    checkpoint_role: str,
    optimizer_step: int,
    completed_epochs: int,
    recipe_identity: dict[str, object],
    rng,
    symmetry_rng,
    scalar_training_weight_sum: float,
    categorical_training_weight_sum: float,
    policy_objective_lr_area: float,
    policy_aux_global_draw_offset: int,
    policy_kl_controller_state: dict[str, object] | None = None,
    ddp: dict,
) -> None:
    """Write the checkpoint-set commit marker on rank 0 after optimizer save."""
    from catan_zero.rl.optim_state import (
        RESUMABLE_EPOCH_CHECKPOINT_ROLE,
        TERMINAL_ADMITTED_CHECKPOINT_ROLE,
        TrainingProgressError,
        save_training_progress,
    )

    import torch

    local_rng = {
        "rank": int(ddp["rank"]),
        "cpu": torch.get_rng_state().tolist(),
        "cuda": (
            torch.cuda.get_rng_state(int(ddp["local_rank"])).tolist()
            if torch.cuda.is_available()
            else None
        ),
    }
    local_numpy_rng_state = rng.bit_generator.state
    local_symmetry_rng_state = (
        None if symmetry_rng is None else symmetry_rng.bit_generator.state
    )
    if bool(ddp["enabled"]):
        import torch.distributed as dist

        rank_rng_states: list[dict[str, object] | None] = [
            None for _ in range(int(ddp["world_size"]))
        ]
        dist.all_gather_object(rank_rng_states, local_rng)
        gathered_rng_states = [row for row in rank_rng_states if row is not None]
        rank_numpy_rng_states: list[dict[str, object] | None] = [
            None for _ in range(int(ddp["world_size"]))
        ]
        dist.all_gather_object(rank_numpy_rng_states, local_numpy_rng_state)
        gathered_numpy_rng_states = [
            row for row in rank_numpy_rng_states if row is not None
        ]
        rank_symmetry_rng_states: list[dict[str, object] | None] = [
            None for _ in range(int(ddp["world_size"]))
        ]
        dist.all_gather_object(
            rank_symmetry_rng_states,
            local_symmetry_rng_state,
        )
        gathered_symmetry_rng_states: list[object] = list(
            rank_symmetry_rng_states
        )
    else:
        gathered_rng_states = [local_rng]
        gathered_numpy_rng_states = [local_numpy_rng_state]
        gathered_symmetry_rng_states = [local_symmetry_rng_state]

    shared_symmetry_rng_state = _require_shared_symmetry_rng_state(
        gathered_symmetry_rng_states
    )
    # Non-zero DDP ranks participate in optimizer/RNG collectives and the
    # shared-symmetry invariant, but never write.
    if int(ddp["rank"]) != 0:
        return
    if checkpoint_role not in {
        RESUMABLE_EPOCH_CHECKPOINT_ROLE,
        TERMINAL_ADMITTED_CHECKPOINT_ROLE,
    }:
        raise RuntimeError(
            f"unknown training-progress checkpoint role {checkpoint_role!r}"
        )
    if optimizer_saved is None:
        raise RuntimeError(
            "model checkpoint saved but optimizer sidecar failed; refusing to emit "
            "a falsely resumable training checkpoint"
        )
    try:
        save_training_progress(
            checkpoint_path,
            optimizer_step=int(optimizer_step),
            completed_epochs=int(completed_epochs),
            checkpoint_role=checkpoint_role,
            recipe_identity=recipe_identity,
            rng_state=rng.bit_generator.state,
            rank_numpy_rng_states=gathered_numpy_rng_states,
            symmetry_rng_state=shared_symmetry_rng_state,
            rank_torch_rng_states=gathered_rng_states,
            scalar_training_weight_sum=float(scalar_training_weight_sum),
            categorical_training_weight_sum=float(
                categorical_training_weight_sum
            ),
            policy_objective_lr_area=float(policy_objective_lr_area),
            policy_aux_global_draw_offset=int(
                policy_aux_global_draw_offset
            ),
            policy_kl_controller_state=policy_kl_controller_state,
            ddp=ddp,
        )
    except TrainingProgressError as error:
        raise RuntimeError(
            f"could not commit resumable checkpoint set: {error}"
        ) from error


def _save_policy(
    policy,
    path: str,
    ddp: dict[str, int | bool],
    *,
    mask_hidden_info: bool = False,
    soft_target_source: str | None = None,
    value_training: dict[str, object] | None = None,
    training_information_surface: dict[str, object] | None = None,
) -> None:
    """Write an EntityGraph checkpoint under single-GPU or DDP training."""
    is_rank0 = int(ddp["rank"]) == 0

    output = Path(path)
    output.parent.mkdir(parents=True, exist_ok=True)
    tmp = output.with_name(f".{output.name}.tmp.{os.getpid()}")
    if not ddp["enabled"]:
        try:
            policy.save(
                tmp,
                mask_hidden_info=bool(mask_hidden_info),
                soft_target_source=soft_target_source,
                value_training=value_training,
                training_information_surface=training_information_surface,
            )
            if not tmp.exists() or tmp.stat().st_size <= 0:
                raise RuntimeError(f"checkpoint temp file was not written: {tmp}")
            os.replace(tmp, output)
        finally:
            if tmp.exists():
                tmp.unlink()
        return

    # DDP: only rank 0 writes; other ranks return (state_dict() here is a local
    # non-collective call, so this guard is safe even when every rank calls in).
    if not is_rank0:
        return
    _write_entity_checkpoint(
        policy,
        path,
        policy.model.module.state_dict(),
        mask_hidden_info,
        soft_target_source=soft_target_source,
        value_training=value_training,
        training_information_surface=training_information_surface,
    )


def _write_entity_checkpoint(
    policy,
    path: str,
    model_state: dict,
    mask_hidden_info: bool,
    *,
    soft_target_source: str | None = None,
    value_training: dict[str, object] | None = None,
    training_information_surface: dict[str, object] | None = None,
) -> None:
    """Atomically write the durable DDP checkpoint (mirrors EntityGraphPolicy.save)."""
    import torch

    from catan_zero.rl.config_serialization import config_to_dict
    from catan_zero.rl.checkpoint_runtime_semantics import (
        ENTITY_GRAPH_FORWARD_SEMANTICS_KEY,
        current_entity_graph_forward_semantics,
    )
    from catan_zero.rl.entity_token_policy import (
        _validate_public_award_feature_contract,
    )
    import catan_zero.rl.entity_token_policy as entity_token_policy_module

    award_contract = _validate_public_award_feature_contract(
        getattr(policy, "public_award_feature_contract", "legacy_zero_v0")
    )

    output = Path(path)
    output.parent.mkdir(parents=True, exist_ok=True)
    tmp = output.with_name(f".{output.name}.tmp.{os.getpid()}")
    try:
        payload = {
                "policy_type": "entity_graph",
                "config": config_to_dict(policy.config),
                "action_mask_version": str(getattr(policy.config, "action_mask_version", "")),
                "mask_hidden_info": bool(mask_hidden_info),
                "entity_feature_adapter": (
                    checkpoint_entity_feature_adapter_metadata(
                        policy_entity_feature_adapter_version(policy)
                    )
                ),
                "public_award_feature_contract": award_contract,
                # OPT-8 provenance (mirrors EntityGraphPolicy.save).
                "soft_target_source": str(soft_target_source) if soft_target_source is not None else "",
                "static_action_features_sha256": _array_sha256(
                    policy.static_action_features.detach().cpu().numpy()
                ),
                "static_action_features": policy.static_action_features.detach().cpu(),
                # DDP checkpoints must carry the same executable-forward
                # identity as EntityGraphPolicy.save().  Omitting this field
                # made every distributedly trained checkpoint fail closed at
                # evaluation even though its commissioned initializer was
                # accepted and its tensors were complete.
                ENTITY_GRAPH_FORWARD_SEMANTICS_KEY: (
                    current_entity_graph_forward_semantics(
                        Path(entity_token_policy_module.__file__)
                    )
                ),
                "model": model_state,
            }
        if value_training is not None:
            durable_value_training = dict(value_training)
            payload["value_training"] = durable_value_training
            payload["trained_value_readouts"] = [
                str(readout)
                for readout in durable_value_training.get(
                    "trained_value_readouts", ()
                )
                if str(readout) in {"scalar", "categorical"}
            ]
        if training_information_surface is not None:
            payload["training_information_surface"] = dict(
                training_information_surface
            )
        torch.save(payload, tmp)
        if not tmp.exists() or tmp.stat().st_size <= 0:
            raise RuntimeError(f"checkpoint temp file was not written: {tmp}")
        os.replace(tmp, output)
    finally:
        if tmp.exists():
            tmp.unlink()


if __name__ == "__main__":
    # Sealed historical receipts and the authenticated A1 scratch/one-dose
    # executors bind this exact script path and invoke it as a subprocess.
    # Keep that compatibility boundary executable until those receipts have an
    # explicit replay adapter.  New human-authored launches still belong on
    # tools/train.py; that is a support-policy boundary, not permission to
    # invalidate already-issued execution authorities.
    main()
